INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酸甜下饭鱼香肉丝', '热门专题', '家常菜', '酸', '[{"name": "猪瘦肉", "amount": "250克"}, {"name": "胡萝卜", "amount": "1段"}, {"name": "青尖椒", "amount": "1个"}, {"name": "半把木耳", "amount": "适量"}, {"name": "葱", "amount": "1段"}, {"name": "姜", "amount": "2片"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "食用油", "amount": "1勺"}, {"name": "郫县豆瓣酱", "amount": "1勺"}, {"name": "腌肉料：盐", "amount": "1勺"}, {"name": "白胡椒粉", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "半个蛋白", "amount": "适量"}, {"name": "玉米淀粉", "amount": "1勺"}, {"name": "食用油", "amount": "1勺"}, {"name": "料汁：清水", "amount": "5勺"}, {"name": "米醋", "amount": "4勺"}, {"name": "白糖", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "玉米淀粉", "amount": "1勺"}]'::jsonb, '["木耳提前泡发，猪瘦肉切丝。", "放入碗中，加入盐🧂白胡椒粉、生抽、料酒、蛋白，抓匀后继续抓捏两分钟，将肉丝抓捏粘稠。", "加入玉米淀粉，抓拌均匀后加入食用油。", "再次抓匀后腌制十五分钟，胡萝卜丝、青椒丝和木耳丝。", "葱花、蒜末、姜丝，料汁所有食材一起放入碗中，搅拌均匀备用。", "起锅烧油，油热下入肉丝，翻炒至变色完全熟透，盛出备用。", "锅留底油，下葱姜蒜炒香，加入郫县豆瓣酱。", "炒出红油，加入胡萝卜丝和木耳丝，大火翻炒至变软断生。", "加入炒好的肉丝和青椒丝，大火翻炒至青椒🫑断生。", "倒入调好的料汁，烧开后翻炒至汤汁粘稠即可。", "太香了🤤🤤🤤", "酸甜下饭。。。", "咸香可口，色香味俱全👍🏻👍🏻👍🏻"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/3fbb2b96f7fb49dda770ca27022fa4b1_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨好吃的下饭菜', '热门专题', '家常菜', '', '[{"name": "嫩豆腐一块", "amount": "适量"}, {"name": "瘦肉50克", "amount": "适量"}, {"name": "郫县豆瓣3勺", "amount": "适量"}]'::jsonb, '["快来试一试吧，"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/aeb12943f73947bca34630df32212c85_1080w_1345h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱烧豆腐，豆腐最好吃的封神做法，完胜麻婆豆腐，附入味儿秘诀，无敌下饭神器', '热门专题', '家常菜', '', '[{"name": "油", "amount": "1汤匙"}, {"name": "豆腐", "amount": "400克"}, {"name": "五花肉", "amount": "200克"}, {"name": "大葱", "amount": "1根"}, {"name": "生抽", "amount": "4勺"}, {"name": "老抽", "amount": "2勺"}, {"name": "白糖", "amount": "2茶匙"}, {"name": "盐", "amount": "1茶匙"}, {"name": "半碗清水", "amount": "适量"}]'::jsonb, '["起锅烧油，放入五花肉片炒至变色，放入三分之一大葱段炒香", "加入豆腐，手掰豆腐块才是入味儿的秘诀，稍微煎一煎", "加入生抽和老抽翻炒均匀，加入半碗清水，炖3-5分钟", "加入剩余的三分之二葱段，炒香，炒至变软", "加入白糖和盐调味，翻炒均匀", "出锅上菜"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/ea21c37620c640558f2fbd23aee0b1a4_1921w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨香巨下饭的把子肉！', '热门专题', '家常菜', '', '[{"name": "如图五花肉", "amount": "适量"}, {"name": "青椒", "amount": "4个"}, {"name": "水煮蛋", "amount": "4个"}, {"name": "半瓶啤酒", "amount": "适量"}, {"name": "生抽", "amount": "3勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "甜面酱", "amount": "1勺"}, {"name": "香料：", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "1点点桂皮", "amount": "适量"}, {"name": "香叶", "amount": "3片"}, {"name": "适量花椒", "amount": "适量"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "3姜片", "amount": "适量"}, {"name": "1瓣蒜", "amount": "适量"}, {"name": "适量大葱头", "amount": "适量"}]'::jsonb, '["食材准备如图（五花肉切厚片）", "锅里不放油，放入五花肉煎出多余油脂盛出", "煎出来的五花肉的油留一点儿在锅里，把青椒鸡蛋煎出虎皮盛出", "倒入这碗香料炒香", "倒入五花肉片，加3勺生抽，1勺老抽，1勺蚝油，1勺甜面酱翻炒均匀（勺是吃饭用的瓷勺）", "倒入鸡蛋，半瓶啤酒，加入适量水，大火煮开，盖盖转小火慢炖50分钟", "倒入青椒，继续慢炖10分钟", "大火收汁，记得多留点儿汤汁哟", "真的太是那个味儿了，duangduang 的肉肉", "这一口太满足了", "汤汁拌饭真的很绝，没有菜我也能干一碗！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/4c4a82d54b194c9d8453ab032962445e_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉沫豆角下饭菜', '热门专题', '家常菜', '', '[{"name": "克豆", "amount": "适量"}]'::jsonb, '["&amp;#27849;&amp;#24030;&amp;#35199;&amp;#23433;&amp;#24320;&amp;#20303;&amp;#23487;&amp;#39184;&amp;#39278;&amp;#21457;&amp;#31080;&amp;#32;&amp;#24494;&amp;#65306;【&amp;#49;&amp;#56;&amp;#49;&amp;#48;&amp;#50;&amp;#55;&amp;#49;&amp;#48;&amp;#51;&amp;#49;&amp;#54;】1勺料酒 1勺糖 1勺淀粉 1勺生抽 抓匀 先把肉碎腌制10分钟", "豆角切成丁", "葱 蒜 小米椒 切成丁", "锅底放适量植物油 油低温的时候就把肉沫放进去煸炒 加少许老抽调色", "然后乘出备用", "锅底放少量植物油 把切好的葱、蒜、小米椒 放入锅中 炒出香味", "把豆角放入锅里翻炒 边炒边加入 少量的清水，一定要一点一点的放 一定要少量多次加入， 这样可以使豆角更容易熟 而且颜色是翠绿的 。", "把豆角放入锅里翻炒 边炒边加入 少量的清水，一定要一点一点的放 一定要少量多次加入， 这样可以使豆角更容易熟 而且颜色是翠绿的 。", "出锅之前可加少许鸡精（我没有加，尽量少吃味精 嘿嘿）"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/6f06ec2272a946ba954bc55d54c31c43_614w_390h.png', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('盐葱猪排', '热门专题', '快手菜', '', '[{"name": "梅花肉", "amount": "500g"}, {"name": "小葱", "amount": "150g"}, {"name": "一整个大蒜", "amount": "适量"}, {"name": "鸡蛋一个、白芝麻、姜配料", "amount": "适量"}, {"name": "淀粉，黑胡椒粉、橄榄油、盐、白糖、生抽、蚝油调料", "amount": "适量"}]'::jsonb, '["梅花肉切成1cm的猪排，用一个鸡蛋、生抽、黑胡椒粉、两片姜、蚝油，淀粉腌制20分钟", "调一下盐葱料：小葱+白芝麻+蒜末+黑胡椒粉+盐+白糖+橄榄油两勺", "热锅倒油，用平底锅。猪排下锅，中火煎", "因为加了淀粉，所以煎到双面焦黄", "然后把猪排切成条（可以直接在锅里剪）", "猪排条回锅，把没熟的地方煎一下", "猪排四面都煎熟后，把盐葱料全部放上来", "盖上锅盖，最小火3-5分钟", "时间到后，就可以出锅了"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/81aa6c0f705f4370b57d40516c26b9fd_1232w_1232h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌椒麻鸡', '热门专题', '快手菜', '', '[{"name": "鸡腿", "amount": "2个"}, {"name": "辣椒面", "amount": "2勺"}, {"name": "芝麻", "amount": "10克"}, {"name": "生抽", "amount": "2勺"}, {"name": "盐", "amount": "3克"}, {"name": "花椒油", "amount": "3勺"}, {"name": "半勺蚝油", "amount": "适量"}, {"name": "糖", "amount": "1勺"}, {"name": "3瓣大蒜", "amount": "适量"}, {"name": "大葱", "amount": "1根"}, {"name": "生姜", "amount": "3片"}, {"name": "二荆条", "amount": "5个"}, {"name": "小米辣", "amount": "3个"}]'::jsonb, '["鸡腿肉去骨，锅中放入姜片葱段", "冷水下锅，倒入料酒", "水开去浮沫，煮鸡腿的水留一点别倒，后面有用。", "鸡腿肉煮熟以后，过一遍凉水（最好是冰水）", "盘子底部可以铺一点金针菇，或者薄切的藕片土豆（自己喜欢吃的素菜）", "两勺辣椒面", "两勺熟白芝麻", "大蒜切小丁", "热锅热油爆香藤椒", "淋入爆香调料", "再来三勺花椒油", "2勺生抽", "1勺白糖提鲜", "再来小半勺盐", "半勺蚝油", "一勺煮鸡腿的汤，把所有调料拌匀，淋入鸡腿里面，放入冰箱冷藏一小时味道最佳哟", "爽的很！"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/d735fbce9cb64bca9637524e67f748b2_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨下饭的鱼香鸡蛋', '热门专题', '快手菜', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "2朵大木耳", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "3瓣蒜", "amount": "适量"}]'::jsonb, '["木耳，胡萝卜切丝，鸡蛋打散\n料汁：2勺生抽，1勺陈醋，1勺糖，1勺蚝油，1勺淀粉，", "5勺老抽，蒜末，适量清水搅拌均匀", "油热后倒入鸡蛋炒散盛出", "加1勺豆瓣酱小火炒出红油\n倒入胡萝卜木耳丝大火炒软", "倒入鸡蛋和料汁，大火翻炒均匀", "鸡蛋吸饱了汤汁，贼下饭，一定要多蒸点儿米饭，不然不够吃哈哈哈"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/ff8c078c43c1410a8152e9821e14b399_1921w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蟹柳豆腐煲｜会开火就会做系列', '热门专题', '快手菜', '', '[{"name": "蟹柳", "amount": "100g"}, {"name": "咸蛋", "amount": "2个"}, {"name": "1盒内脂豆腐", "amount": "适量"}, {"name": "开水", "amount": "200ml"}, {"name": "水淀粉", "amount": "40g"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["咸蛋切丁，蟹柳撕成长条。", "锅底喷油，烧热后放入咸蛋丁，翻炒出沙。", "放入蟹柳，倒入开水，煮3分钟。", "内酯豆腐切小块，放入锅中，大火煮3分钟。", "加入水淀粉和葱花，轻轻翻拌均匀后关火即可。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/492ff4e70aea478f921141d487b4dbb9_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('地三鲜——下饭神器', '热门专题', '下饭菜', '辣', '[{"name": "一个茄子", "amount": "适量"}, {"name": "一个土豆", "amount": "适量"}, {"name": "一小把豆角", "amount": "适量"}, {"name": "3-4瓣蒜", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}]'::jsonb, '["处理食材如图，蔬菜洗好、切好、沥干水分\n①锅内烧油，油热开始冒烟，分别炸土豆（炸至金黄）、茄子（炸至起皱皮）、豆角（炸至虎皮样），沥油备用【这一步可以在食材上喷油放入空气炸锅做，请自行实验】\n②炸的过程中准备料碗:盐1勺、白糖1勺、味精1勺、白胡椒粉半勺、生抽2勺、老抽1勺、耗油1勺、淀粉1勺、清水半碗，搅匀备用\n（盐、糖、味精、胡椒粉等固体都是调味盒送的那种小勺，其它液体的就是正常喝汤用的勺）", "①猪油烧热，姜、蒜、小米辣炒香（不吃辣可以不放小米辣）", "②下去炸过的土豆、豆角、茄子，翻炒后，倒入调好的料汁，炒至汤汁吸收", "哒哒哒，出锅了"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/76926c1ad87b423fa451115ff0ffc3c3_1080w_1835h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨下饭！辣椒爆炒口蘑', '热门专题', '下饭菜', '辣', '[{"name": "一斤口蘑", "amount": "适量"}, {"name": "螺丝椒", "amount": "3根"}, {"name": "1-2根红辣椒", "amount": "适量"}, {"name": "少许木耳", "amount": "适量"}, {"name": "适量蒜末", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}]'::jsonb, '["木耳提前泡发，泡发好后，烧水，水开后放木耳，水再次沸腾后煮2分钟，捞出控水。\n\n我这个菜谱是用焯水后的熟木耳做的，生木耳爆炒不一定能熟，所以木耳一定要焯水，熟了再使用。", "口蘑切片，辣椒切段备用。", "蒜末备用。", "锅里多放一点油，中大火爆炒辣椒，炒制表面有少许虎皮后盛出备用。\n\n我喜欢过油煸炒过、带有虎皮的辣椒，觉得更香。喜欢吃鲜脆一些的辣椒这步省略。", "锅中放油，油热后放入口蘑，大火爆炒，炒制发黄发软时放蒜末爆香", "放入两勺生抽继续爆炒，直到蘑菇中的水都被炒出来。", "放入辣椒、焯水后的木耳，放一勺蚝油继续爆炒。口味清淡些的可以不放蚝油。", "炒制锅中的蘑菇水都收干了，尝一下咸淡看是否需要调整，合适就出锅。", "有学会了一个蘑菇的做法！\n素菜大军壮大➕1！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/b6db98de90ab4b95a6803ffa0a06d985_1919w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('沙葱炒牛肉，15分钟上桌的鲜甜下饭菜', '热门专题', '下饭菜', '辣', '[{"name": "牛肉", "amount": "250克"}, {"name": "沙葱", "amount": "50克"}, {"name": "小米椒", "amount": "1根"}, {"name": "5毫升生抽", "amount": "适量"}, {"name": "蚝油", "amount": "5克"}, {"name": "糖", "amount": "3克"}, {"name": "5毫升米酒", "amount": "适量"}, {"name": "胡椒粉", "amount": "3克"}, {"name": "油", "amount": "8克"}]'::jsonb, '["1️⃣ 沙葱洗净控水后切成大段（手指长短），牛肉切片或者切丝都行（片别太厚），加上述调味料抓匀，腌制个10分钟；\n\n2️⃣ 热锅热油，油可以多放点儿，放入牛肉片后，用中大火来炒；", "3️⃣ 只需把牛肉炒到表面完全变色了，就可以放入沙葱了；\nTIP：快炒差不多2分钟左右，牛肉丝比牛肉片还更快成熟，别炒老了。\n\n4️⃣ 加入沙葱段，翻炒个30秒，开始变软后加入腌肉剩余的料汁和小米辣，再炒个30秒就完成了。", "反正炒菜过程差不多就3-4分钟，牛肉腌制过味道很足够，而且成熟度也刚刚好", "沙葱炒过不会太辣，更多是鲜甜的口感，所以我放了小米辣提味，或者多放点儿沙葱也没问题，很好吃的。", "微甜鲜香，如果有多余的汤汁，用来拌饭就很nice了~"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/d78ca05cdfce4a3f8e9397ec823c1544_1280w_1707h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('去湘菜馆一定要点的辣椒擂皮蛋‼炒鸡快手下饭', '热门专题', '下饭菜', '辣', '[{"name": "螺丝椒", "amount": "5只"}, {"name": "皮蛋", "amount": "8个"}, {"name": "8瓣大蒜", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}]'::jsonb, '["起锅烧油，锅中放少许油就可以咯，把去头的螺丝椒加少许盐煎至虎皮状～", "可以将皮蛋上锅蒸十分钟或不处理，直接凉拌", "放入切碎的蒜瓣，小米辣，热油泼上去，调味使用糖、盐、酱油、醋搅拌均匀，腌制十分钟即可", "有条件的朋友们可以再加一点香油或者花椒油！都很提味哦~"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/c8ba2132b8ed408d97b8b484522685b0_1280w_1591h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('立春炒合菜', '热门专题', '下饭菜', '', '[{"name": "豆芽", "amount": "1把"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "半个土豆", "amount": "适量"}, {"name": "韭菜", "amount": "30克"}, {"name": "粉丝", "amount": "1把"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "老抽", "amount": "1勺"}, {"name": "少许葱姜蒜", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "盐", "amount": "2克"}, {"name": "糖", "amount": "2克"}, {"name": "1泵太太乐鸡汁", "amount": "适量"}]'::jsonb, '["准备好所需要的材料；", "2个鸡蛋打散炒熟；", "粉丝泡软后，加老抽1勺拌匀上色；", "蔬菜处理成丝；", "葱姜蒜爆香后，下土豆丝和胡萝卜丝炒断生；", "再放入其他配菜；", "加入太太乐鸡汁1泵，素菜提鲜增香；", "再加入生抽1勺、蚝油1勺、盐2g、糖2g，炒匀；", "装拍盛出即可；"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/9cc21779bcff44f8a8a63407a7059b01_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('豆角烧茄子｜米饭杀手驾到！这盘素菜比肉还香！', '热门专题', '素菜', '', '[{"name": "茄子", "amount": "1个"}, {"name": "蒜", "amount": "适量"}, {"name": "豆角", "amount": "适量"}]'::jsonb, '["1⃣️酱汁：1勺生抽➕1勺蚝油➕半勺老抽➕少许白糖➕1勺淀粉搅匀\n2⃣️茄子切条加少许盐静止10分钟腌出水分挤干，油热下豆角炒至断生盛出\n3⃣️留底油倒入茄子炒至表皮焦黄盛出，少油炒香蒜末小米辣，倒入豆角茄子、酱汁，大火翻炒均匀浓稠即可出锅咯！\n📍 美味小贴士\n* 1豆角务必熟透！煸炒或油炸时间要够，避免食物中毒。  \n* 2茄子预处理不能省！盐腌挤水或薄拍淀粉，有效解决吸油问题。  \n*", "酱汁提前调好！避免炒菜时手忙脚乱，影响火候。  \n*4全程保持大火快炒！锁住锅气，蔬菜口感更佳\n👉 你心中最无敌的下饭菜是哪一道？欢迎在评论区晒图分享你的拿手好菜！👇", "快来打卡吧"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/7b3032f0587b4b758c8491cd2509e1e1_1280w_1590h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏日纯素～丝瓜炒口蘑', '热门专题', '素菜', '', '[{"name": "丝瓜", "amount": "2根"}, {"name": "，一盒口蘑", "amount": "230克"}, {"name": "盐", "amount": "1小勺"}, {"name": "三分之一小勺糖", "amount": "适量"}, {"name": "适量玉米油", "amount": "适量"}]'::jsonb, '["准备好食材", "丝瓜刨皮切块，口蘑切片", "锅里少加点玉米油，中大火烧到五六成热。", "下丝瓜和口蘑翻炒1分钟", "然后加1小勺盐，三分之一小勺糖，炒匀。", "调成中火，盖上锅盖焖7-8分钟。期间要上下翻动1-2次，当心粘锅。", "10分钟后丝瓜已经软烂出汁了，开大火，30秒收汁。", "装碟上桌，15分钟内就能完成的夏日快手菜。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/dacc7fb980dc49a4a98df02e54a09841_1024w_768h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蒜蓉西兰花', '热门专题', '素菜', '', '[{"name": "西兰花", "amount": "350g"}, {"name": "4-5瓣蒜", "amount": "适量"}, {"name": "2盐", "amount": "适量"}, {"name": "蚝油", "amount": "2g"}, {"name": "生抽", "amount": "1勺"}, {"name": "淀粉水", "amount": "15ml"}]'::jsonb, '["西兰花切成小朵，清洗干净", "焯水，水中加入适量的盐和食用油，水沸后60秒即可断生", "沥干水分备用", "大蒜切末，准备好水淀粉 ，备用", "热油下入蒜末，炒出香味，加入西兰花 加入食盐、蚝油翻炒，再加入水淀粉，大火收汁", "盛盘出锅，干饭"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/2348ba887e274a28ace45b49ebb8f364_874w_656h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蔬菜卷', '热门专题', '素菜', '', '[{"name": "大叶生菜", "amount": "6片"}, {"name": "鸡蛋两个", "amount": "适量"}, {"name": "土豆1个", "amount": "适量"}, {"name": "黄瓜半个", "amount": "适量"}, {"name": "胡萝卜少半个", "amount": "适量"}, {"name": "火腿肠1个", "amount": "适量"}]'::jsonb, '["生菜焯水。\n土豆、萝卜切丝焯水。\n鸡蛋摊成饼切丝。\n黄瓜、火腿切丝。\n生菜把其他的都卷好。", "调蘸料，蒜末、小葱、芝麻、花生碎、小米椒、生抽30g老抽5g、蚝油5g、醋20g、香油少许、糖半勺。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/3cc1da4de76c46bbaf80ddf6ee8ed3a3_785w_785h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('罗汉斋', '热门专题', '素菜', '', '[{"name": "1小把(手抓)干香菇(野生)", "amount": "适量"}, {"name": "口磨", "amount": "8个"}, {"name": "1小根胡萝卜", "amount": "适量"}, {"name": "荷兰豆", "amount": "100克"}, {"name": "面筋泡", "amount": "9个"}, {"name": "小冬笋(笋尖)", "amount": "1个"}, {"name": "少许葱姜蒜", "amount": "适量"}, {"name": "蚝油", "amount": "1小勺"}, {"name": "二道酱油/生抽(任选)", "amount": "1小勺"}, {"name": "1小汤勺水淀粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "1铲勺食用油", "amount": "适量"}]'::jsonb, '["用筷子把面筋泡扎透", "热水浸泡一会儿，泡软化。", "用手掌挤压掉面筋泡的水份", "准备好胡萝卜、荷兰豆、小冬笋尖。", "香菇泡发洗干净，挤干水份。口磨冲洗干净。", "水开后，香菇、口磨入锅，焯水2-3分钟，去除草酸，沥水捞出。", "另起锅，水开放入少许盐油(注:盐油防氧化变色)，然后将荷兰豆、胡萝卜、冬笋片放入锅中焯水。荷兰豆和胡萝卜断生，笋片去除麻涩口。焯水1-2分钟，沥水捞出。", "锅中底油，煸炒葱姜蒜，爆香。", "香菇、口磨入锅，大火快速炝炒。(注 :口磨可以改刀，在口磨上划几刀，方便入味。)", "处理好的面筋入锅炝炒", "最后放小冬笋尖、荷兰豆、胡萝卜，一起爆香。", "加入1小勺蚝油", "加入1小勺二道酱油", "起锅前，勾水淀粉，调盐度即可。", "美味鲜香，拿肉不换。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/30c31217ea194b3f9db46bafd1fe842b_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧肉', '热门专题', '大鱼大肉', '', '[{"name": "带皮五花肉", "amount": "700克"}, {"name": "小粒的十来粒冰糖", "amount": "适量"}, {"name": "姜片", "amount": "4片"}, {"name": "1-2个（可以不放）八角", "amount": "适量"}, {"name": "2-3片（可以不放）香叶", "amount": "适量"}, {"name": "（可以不放）干辣椒", "amount": "1个"}, {"name": "黄酒", "amount": "2大勺"}, {"name": "老抽", "amount": "2大勺"}, {"name": "生抽", "amount": "2大勺"}, {"name": "没过肉开水", "amount": "适量"}]'::jsonb, '["准备好用料，如果是冷冻五花肉要提前解冻。姜片切好。老抽和生抽都是酱油，老抽上色，生抽调味。当然要是你们家习惯只用一种酱油，不区分老抽生抽的那种，也可以。现在还有专门的红烧酱油，也可以。只是颜色和咸度真的都不一样，要灵活调整。这个菜谱只是提供一种做法步骤。", "五花肉选择带皮的，洗净，洗的时候不妨换几次水，直到不再有血水渗出。控干水分，最好用厨房纸巾吸干表面。切成麻将块大小。建议这时候顺便开始烧一壶水，等下要用开水炖肉。", "先把锅烧热，不用放油，将五花肉放入。尽量不要重叠，每块肉都贴着锅底。不要着急翻面，一开始肯定翻动不了，会粘锅。小火慢煎，待有油渗出后就能翻动了。", "保持小火，拿筷子给每块肉翻面，直到表面微微焦黄，油分被逼出来。但不要煎太久，肉会硬。在西餐里也有个很类似的过程，煎肉扒时经常这样做，令肉的表面“褐化”封住肉汁。", "接着放入冰糖，往油多的地方放，小火翻炒片刻后，和整锅肉一起翻炒。用小颗的冰糖，大块的也要先砸开成碎片，否则很难融化。这样做类似炒糖色，但又不是炒糖色。如果想好好炒个糖色，那就把肉先盛出来，油留在锅中，放入冰糖后保持小火不断翻炒搅拌，直到全部融化，开始冒泡，再把肉倒回去，迅速翻炒均匀。注意千万不要炒过头，会发苦。我是不这样炒糖色的，肉在锅里时直接下冰糖，一起炒，成品颜色一样油润红亮。", "等冰糖融化得差不多了，放入姜片、八角、香叶、干辣椒，翻炒几下。干辣椒完全可以不放，但我觉得有一点点轻微的辣味，挺解腻的。八角和香叶，也有很多人家不放的。都行。我自己是喜欢来点儿香料味的，所以会放。但也千万不能放多了。", "淋入黄酒，我们家习惯用绍兴花雕酒，属于黄酒的一种。没有黄酒的话就用普通料酒。酒淋进去瞬间受热，香气会激发出来。然后加老抽和生抽。翻炒至所有肉块都上色。", "接着倒入开水，至少要没过肉。注意一定得是开水，不能加冷水。热的肉一碰到冷水，迅速收缩，容易硬。倒入开水后，大火烧开，转小火盖上盖子慢炖，40分钟至1个小时。期间记得观察汤汁情况，万一水不够了肉还不酥，可以适当加水，同样是加开水。", "炖够时间后，尝下咸淡和肉的口感。觉得还不够的话就再接着炖会儿，但一般来说是够了的。就可以开盖转大火收汁了。收汁时注意翻拌，酱汁里有糖，是会变浓稠的，糖放得越多，最后汤汁会越浓稠。汤汁收得差不多了即可出锅。注意收汁不是烧干，况且也烧不干，因为锅里的酱汁水分真的烧干后，就会只留下油，变成炸肉，肉就柴了。所以要分辨锅里还是酱油色的酱汁，别把酱汁都烧干了，适当收浓就可以。最后撒些芝麻，更赏心悦目。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/3e7926d6db234fd5927cb1f2770acb65_2720w_4080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级无敌好吃的红烧牛肉', '热门专题', '大鱼大肉', '辣', '[{"name": "1000-1200克牛腩", "amount": "适量"}, {"name": "鹃城红油豆瓣酱（不能吃辣可用普通豆瓣酱代替）", "amount": "100克"}, {"name": "大葱", "amount": "1根"}, {"name": "一整个大蒜", "amount": "适量"}, {"name": "两块姜", "amount": "适量"}, {"name": "（特别不吃甜的可以减一半量）冰糖", "amount": "50克"}, {"name": "如图所示八角香叶桂皮花椒", "amount": "适量"}, {"name": "80毫升生抽", "amount": "适量"}, {"name": "20毫升红烧酱油（可用老抽代替）", "amount": "适量"}, {"name": "300毫升（袋装料酒差不多一袋）料酒", "amount": "适量"}]'::jsonb, '["所有材料洗净待用，牛腩要买那种肥瘦相间的才好吃哦。好多厨友指出这不是牛腩是牛肋排，牛腩就是指靠近牛肋处的松软肌肉，本来就是一种统称啊，牛身上很多部位都可以称为牛腩的。不推荐用进口的牛腩，因为时间太久不新鲜了，肉很松散又老，这样做的口感特别柴又硬。另外如果买到很老完全没有肥肉或是牛腱子不要怪方子啊，你可以用它做我另外一个名为“凉拌牛肉”的菜谱。然后另外再买一块牛五花或者牛腩做这个🤓", "切成3×3或者4×4的方块", "放冷水里漂30分钟，这一步是为了去腥气和血水。", "趁漂牛肉的时间把佐料都洗好切好掰碎", "看到了吗，血水漂出来了，然后我们倒掉这些血水再反复冲洗两遍，沥干水分待用", "取一口大砂锅装半锅冷水，放入菜谱里用量的一半料酒（150ml）和一半姜片，不用开火。", "把牛肉放进去之后我们开大火煮，为什么要用冷水焯呢，因为牛肉用热水会瞬间缩紧，血沫就逼不出来了，开水烫过口感也不好。", "趁煮牛肉的时候把冰糖炒成糖油。锅里倒了油之后不要烧热直接把冰糖放进去，拿个勺子或者锅铲敲成小块之后开小火慢慢炒。别开大火哦，不然很容易烧焦，等冰糖变成液体就可以啦。新手把冰糖融化了就行，第一次做不用追求图片里的焦糖色，很容易就烧焦的，那样成品就会有苦味了。我图片里这种颜色一般需要老手才能把握好，因为已经这个颜色了烧焦就在一瞬间啊~", "我们回到牛肉，血沫浮起来后用汤勺一点点撇掉", "撇到煮开也不会有什么血沫为止，捞起控干水分，水不要倒掉哦，留着一会儿用。内什么，焯过牛肉的水不会腥的，你们放心接着炖。因为焯之前我们不是用冷水漂了还洗了吗，血水都基本漂掉啦。把水倒掉很可惜，因为很香，不信你们闻闻。", "把牛肉倒进刚才炒好的冰糖油里，全部倒进去之后转大火炒3分钟左右", "把除生抽和红烧酱油以外的所有佐料都放进去一块炒2分钟，然后再把生抽和酱油也倒进去。这里！请童鞋们仔细看，不要另外放盐的，就这些调料就够了，豆瓣酱加生抽老抽的咸味够了的，相信我！（坚定脸）我写在上面不用放盐没人看啊，一遍一遍的问我不要放盐吗，心好累💔\n很多厨友问我红油豆瓣酱是什么牌子的，我之前用的那罐没看牌子用完扔掉了……但很多人推荐娟城的，你们可以试试。这个菜什么牌子的红油豆瓣酱关系不太大，就是咸度有些出入，你们怕咸的话可以先少放点，尝尝味道再酌情添加。另外，我看有不少厨友说家人不吃辣，不能放红油豆瓣酱，可否用黄豆酱代替。当然可以啦！就是量可能会有出入，第一次做建议先少放点。", "沿锅边把剩下的料酒分次倒进去炒，差不多干了然后从砂锅里舀点儿汤出来大火煮5分钟，记住一定要把料酒炒干了再舀汤煮，不然可能会有酸味", "接着转移到刚才的那口砂锅里，盖上盖子小火慢炖两个小时（如果用电压力锅的话，40分钟左右，明火高压锅15分钟就够啦）", "时间到尝尝看够不够软烂，不够再炖半小时或者一小时都可以，觉得可以了关火。然后，好几个厨友问我为什么他炖半小时or一小时还很硬嚼不动，那你再炖久一点啊喂！给它多点时间反省反省自己为什么不烂🤣", "成品的样子是不是超级诱人？", "点开大图显示验证二维码👆🏻\n文字版微信号：woaixiachu0624"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/2fce2658c6f242809c0470effcb66e06_1616w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('流口水的黄豆炖猪蹄', '热门专题', '大鱼大肉', '', '[{"name": "猪蹄", "amount": "1只"}, {"name": "八角", "amount": "1个"}, {"name": "姜", "amount": "4片"}, {"name": "一小碗黄豆", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "5粒冰糖", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "香叶", "amount": "2片"}, {"name": "干辣椒", "amount": "6个"}, {"name": "葱", "amount": "1根"}, {"name": "老抽", "amount": "4勺"}, {"name": "生抽", "amount": "3勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "一大碗凉白开", "amount": "适量"}]'::jsonb, '["黄豆提前一天凉水泡上", "买的时候让人家切小块，凉水下锅加入两勺料酒，凉快姜片焯水去腥去沫", "冲洗干净备用", "准备好调料备用", "冰糖在油里炒出糖色", "下猪蹄翻炒变色", "加入调料（辣椒八角那些），老抽，生抽，蚝油，一勺料酒，一勺盐，翻炒均匀，加入凉白开大火煮开，转小火慢炖20分钟，入味且肉筋会软糯一些", "放黄豆，小火炖20分钟", "尝盐头，大火收汁，搞定美味的黄豆猪脚，软糯滑口"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/0773b563f5a041aea14a3b2c15df8b09_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('水煮肉片（肯定不翻车）', '热门专题', '大鱼大肉', '辣', '[{"name": "猪里脊", "amount": "300克"}, {"name": "任何蔬菜都可以：比如圆白菜、菠菜、白菜、油菜、生菜🥬豆芽等等", "amount": "适量"}, {"name": "半颗我选的绿甘蓝", "amount": "适量"}, {"name": "2颗和油麦菜", "amount": "适量"}, {"name": "适量蒜末", "amount": "适量"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["肉尽量切成薄片，别太大，加适量盐，生抽，白胡椒粉、一个蛋清，淀粉，抓拌均匀。因为我切的肉多，＊＊＊所以我放了一个鸡蛋。", "最后放点油，腌制最少半小时，时间越长肉片越嫩滑，千万别着急，要不肉不嫩你们又来找我😂😂", "葱、蒜切好，留一点葱花，一会儿装饰用", "起锅烧油，先放葱蒜，再放郫县豆瓣酱或红油豆瓣酱都行，我感觉味道一样，有火锅底料的可以放一小块，味道更佳，小火炒出红油", "家里只有红油豆瓣，再加入适量清水，水量看一下一会儿够煮蔬菜就可以，加盐、味精、酱油、糖、蚝油、尝一下，得咸点，最后加一点点陈醋！调好味后，汤烧开后用漏勺把调料残渣捞出。", "＊接着放入准备好的蔬菜，爱吃什么菜就放什么菜，菜煮到八分熟，用漏勺捞出放入大碗或盆中备用。", "再次把汤烧开转小火，用手慢慢地圆着圈往汤里放入肉片，全部放入后，＊千…万…不用动它，别欠儿欠儿的用铲子扒拉它啊，会造成脱浆的，而且肉会很碎，一定等5一10秒，再打打散，改成中火。", "等两、三分钟，肉片变白熟了就可以了。", "把肉片和汤一起倒入刚才放蔬菜的大碗中，这时会感觉汤有点粘稠，这属于正常，因为肉片上有淀粉。", "锅放入多一点的油，一会儿要浇在肉和调料上", "烧油的功夫，在肉片上撒些葱花、蒜末、麻椒粒、花椒粒、花椒粉、干辣椒、辣椒粉", "我不能吃辣，所以花椒麻椒多放了一点", "这时候锅里的油也烧热了，必须得冒烟哈，再浇在调料上，吡啦一声，哎玛！太好听了", "香喷喷的水煮肉片完成了，我去盛饭😋😋"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/f7fd9808106444448131f6d1361dc0c4_1242w_2688h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('可以舔盘的糯米蒸排骨', '热门专题', '大鱼大肉', '', '[{"name": "排骨", "amount": "400克"}, {"name": "糯米", "amount": "200克"}, {"name": "3瓣蒜子（用于腌肉和腌糯米）", "amount": "适量"}, {"name": "生姜（用于腌肉和腌糯米）", "amount": "3片"}, {"name": "生抽（用于腌肉）", "amount": "2小勺"}, {"name": "老抽（用于腌肉）", "amount": "1小勺"}, {"name": "食盐（用于腌肉）", "amount": "1小勺"}, {"name": "生抽（用于腌糯米）", "amount": "1小勺"}, {"name": "少许老抽（用于腌糯米）", "amount": "适量"}, {"name": "食盐（用于腌糯米）", "amount": "1小勺"}, {"name": "小葱", "amount": "1根"}, {"name": "1张千张", "amount": "适量"}]'::jsonb, '["圆糯米洗净，提前浸泡2-3个小时（因圆糯米比长糯米要更容易煮烂，所以无需隔夜泡制，而且黏性比长糯米好，口感更软糯！！！）", "在等待糯米泡制的时间里，将排骨切成小块放入盆中清洗掉排骨上的血水……", "将蒜子和生姜切末，小葱切段备用。", "将蒜末、姜末（姜末和蒜末不要一次性倒入排骨中，留少许最后放入糯米中腌制）、生抽、老抽、食盐（根据个人口味酌情添加或减少）放入排骨中，用手用力搅拌、抓捏，使排骨更加入味。", "盖上保鲜膜腌制2个小时左右，直至糯米泡好即可。", "泡好的圆糯米倒掉多余水份，将腌制排骨剩下的姜末和蒜末放入，并加入生抽、老抽和食盐（根据个人口味酌情添加或者减少），用筷子🥢搅拌均匀……", "把千张洗净，裁剪成盘子或者蒸笼大小，这是放置排骨用的，在千张上洒少许盐和生抽，用手抹匀（因为现在的季节买不到荷叶，就用千张代替，关键是千张最后会吸收肉的汤汁，很好吃😋）。", "将腌制好的排骨放入糯米中用手不停按压排骨和糯米，使糯米能更好的附在排骨上。", "就是这样……", "Dengdengdengdeng ……裹上了糯米的排骨，有种晶莹剔透的感觉，多余的糯米洒在排骨上。冷水上锅，开大火蒸1个小时左右，起锅前撒入提前准备好的葱花焖一会即可。", "软糯Q弹的糯米排骨就做好啦！！！肉香浓郁，配上吸附了汤汁的糯米一起食用，完美！！！最后真的可以舔盘因为千张也很好吃，可以食用，一点不浪费哦🎉🎉🎉", "nice💕"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/bdf5df47e18c43c7b8d1756f4f972416_2512w_2467h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('辣子鸡丁香辣版', '热门专题', '下酒菜', '辣', '[{"name": "鸡翅中", "amount": "6个"}, {"name": "花椒", "amount": "1勺"}, {"name": "依个人口味干辣椒", "amount": "适量"}, {"name": "花生米", "amount": "1把"}, {"name": "白芝麻", "amount": "1勺"}, {"name": "姜", "amount": "2片"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "白糖", "amount": "2小勺"}, {"name": "料酒", "amount": "0.5勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "五香粉", "amount": "1小勺"}, {"name": "盐", "amount": "1小勺"}]'::jsonb, '["鸡翅剪成小块，清洗干净，沥干水分", "蒜末、姜末，切好备用\n花椒1勺、干辣椒，放碗里备用", "鸡肉加入姜沫、料酒半勺、生抽1勺、盐1小勺、五香粉1小勺，抓拌均匀冷藏腌制30分钟以上", "六成油温，下鸡肉丁，中火炸至金黄捞出\n\n⭐有条件的还可以炸点花生米", "留底油，加入蒜末、花椒、干辣椒，小火慢炒炒出香味", "加入鸡丁、花生米、盐1小勺、白糖2小勺、白芝麻，翻炒均匀\n\n⭐附辣子鸡家常版做法：https://www.xiachufang.com/recipe/107589923/"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/b1f6710ef20a4142bfdcb9919e344786_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香辣青蟹', '热门专题', '下酒菜', '辣', '[{"name": "青蟹", "amount": "10只"}, {"name": "白酒", "amount": "1勺"}, {"name": "半碗淀粉", "amount": "适量"}, {"name": "姜", "amount": "1块"}, {"name": "蒜", "amount": "3个"}, {"name": "豆豉", "amount": "1勺"}, {"name": "一小把干辣椒", "amount": "适量"}, {"name": "10粒花椒", "amount": "适量"}, {"name": "半块八角", "amount": "适量"}, {"name": "香叶", "amount": "1片"}, {"name": "郫县豆瓣", "amount": "2勺"}, {"name": "小米辣", "amount": "2根"}, {"name": "一点点白胡椒", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "醋", "amount": "1勺"}, {"name": "白糖", "amount": "1勺"}, {"name": "葱", "amount": "3根"}, {"name": "适量白芝麻", "amount": "适量"}]'::jsonb, '["青蟹掰掉蟹壳，剪去蟹脚尖防止扎嘴，掏去蟹肠，剪去蟹肺等多余部分，用牙刷刷洗干净，剪成两块，大脚拍破，加点白酒和盐腌制。", "蟹块粘淀粉（尤其是切口沾满淀粉可防止鲜味流失），油温四成，炸变色捞出沥干。", "锅里留油，下豆瓣炒出红油，放泡过水的干辣椒、花椒、八角、香叶，放姜、蒜、豆豉、小米辣炒香，下青蟹，倒开水，加生抽、白胡椒、白糖烧6～8分钟。", "大火收汁，放葱段起锅。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/417398c01ad0444186f08eb38a75e509_1280w_720h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酒蒙子必备下酒小凉菜
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鱿鱼自由在家复刻鱿鱼土豆，香到上头！', '热门专题', '下酒菜', '', '[{"name": "鱿鱼", "amount": "适量"}, {"name": "土豆", "amount": "适量"}, {"name": "姜蒜", "amount": "适量"}, {"name": "小米椒", "amount": "适量"}, {"name": "洋葱", "amount": "适量"}, {"name": "小葱", "amount": "适量"}, {"name": "火腿肠", "amount": "适量"}, {"name": "辣椒粉", "amount": "适量"}, {"name": "花椒面", "amount": "适量"}, {"name": "孜然粉", "amount": "适量"}, {"name": "胡椒粉", "amount": "适量"}, {"name": "烧烤料", "amount": "适量"}, {"name": "白芝麻", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}]'::jsonb, '["🌶️灵魂干料：2勺辣椒粉+1勺花椒粉+2勺孜然+2勺烧烤料+1把白芝麻➕盐味精（搅拌均匀备用）\n🌶️灵魂辣椒酱：1勺豆瓣酱➕3根小米椒➕姜➕蒜，剁碎备用！", "👩🍳做法：\n1️⃣ 土豆切条炸熟，火腿肠过油！\n2️⃣ 鱿鱼须小火煸8分钟，炒到油清亮不出水\n3️⃣ 加自制辣椒酱炒干，倒炸好的土豆火腿肠\n4️⃣ 淋1勺生抽，撒洋葱丝和干料，翻炒两分钟入味\n5️⃣ 撒葱花出锅！香到流口水～\n💡小贴士：\n• 鱿鱼出水多，着急的姐妹可以直接焯水（我是喜欢直接煸，更干香！）\n• 完全可以秒杀地摊摊儿，配啤酒绝了！"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/d2f30fd751394231896c569464f4e477_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('辣炒花蛤', '热门专题', '下酒菜', '辣', '[{"name": "花蛤", "amount": "1斤"}, {"name": "8瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "1块"}, {"name": "红椒", "amount": "1个"}, {"name": "葱", "amount": "4根"}, {"name": "生抽", "amount": "1勺"}, {"name": "少许蚝油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "1小碗水淀粉", "amount": "适量"}]'::jsonb, '["加入盐巴，油，泡一小时", "洗干净后，\n放入锅里加入料酒少许，\n盖盖子，焖煮全部开壳", "大概，五六分钟", "花甲捞出，原汤装碗里，备用", "准备葱姜蒜，小米辣", "油热，爆香葱姜蒜，小米辣，\n加入煮花蛤原汤，\n调味，盐巴，鸡精，白糖\n一勺生抽 ，少许蚝油\n小碗水淀粉，收浓汤汁，就可以倒入花甲", "最后最后，加入小葱段和红椒碎，适量，\n翻版均匀，粗锅"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/0c739be5f6e74ef3aa59e9a4ce91cd74_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('日光与晨昏—渐变色饮料', '热门专题', '小清新', '', '[{"name": "共占1/3杯或者*黄色：玉米糖浆+橙汁", "amount": "适量"}, {"name": "百香果糖浆加糖水", "amount": "适量"}, {"name": "1/3杯的容量或*红色：玫瑰洛神花茶", "amount": "适量"}, {"name": "草莓果茶、石榴汁等红色且糖度低于黄色部分的液体", "amount": "适量"}, {"name": "*蓝紫色：蝶豆花茶", "amount": "适量"}, {"name": "一整杯的量普通冰块", "amount": "适量"}, {"name": "加蝶豆花冰块或者苏打水或雪碧", "amount": "适量"}, {"name": "大半杯椰奶", "amount": "适量"}, {"name": "1小匙左右炼乳", "amount": "适量"}, {"name": "一杯的量冰块", "amount": "适量"}]'::jsonb, '["先来做晨昏部分：倒入橙汁加玉米糖浆、或者百香果糖浆加糖水，到容器三分之一的位置。最下层的糖度一定要高，不然分分钟被其他液体压得消失掉。倒入液体后加冰块盖住液体表面", "然后沿着勺子杯缓缓倒入红色液体。如果是无糖、红色的果茶，基本只要轻轻倒就可以，如果是稍微有些糖度的果汁，那么一定要加很多冰块之后再倒入红色部分，而且动作一定要轻柔，注入一定要沿着勺子杯缓缓倒入", "最后三分之一，如果你用了蝶豆花茶冻成的冰块（推荐），那么就先加入与液面齐平的普通冰块，然后放蝶豆花冰块至满。然后缓缓倒入苏打水或雪碧", "如果你用了蝶豆花茶，那么就将杯子加满普通冰块，然后沿着冰块缓缓倒入蝶豆花茶至满杯。如果下层液体的酸碱度不足以使蝶豆花茶变成紫色，那么就滴入一两滴柠檬汁", "然后是日光部分：椰奶加炼乳搅匀增加糖度", "蝶豆花茶泡好放凉", "倒入混合好的椰奶，加冰块至满杯", "然后倒入蝶豆花茶", "这是完成后的晨昏部分。如果你加了蝶豆花冰块，就能出现紫色上方还有蓝色的效果。加入蝶豆花茶就要看运气了…", "日光的很好完成，下方有甜度，上方完全没有甜度，基本不会浑浊", "这是完整的样子", "红色部分是关键，最好选择无糖的红色液体，我试了下加入红葡萄汁，诺，黄色被压得都快没了……", "好啦，这看起来似乎很复杂，但其实蛮好玩的。拿出你做实验的好奇，祝你们玩得开心！\nヾ(๑ㆁᗜㆁ๑)ﾉ\""]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/8306691e69d811e7947d0242ac110002_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏日冰饮~桃气泡泡~', '热门专题', '小清新', '', '[{"name": "桃子", "amount": "2个"}, {"name": "一瓶巴黎水", "amount": "适量"}, {"name": "食用水", "amount": "100ml"}, {"name": "白糖", "amount": "30克"}, {"name": "冰块", "amount": "6块"}, {"name": "薄荷叶", "amount": "1片"}]'::jsonb, '["桃子洗净表皮层的毛毛，切下桃皮，桃肉切成小丁，", "桃子肉碗中撒入25克的白糖，放入冰箱冷藏，", "桃皮放入奶锅，加适量食用水煮开，加入剩余的5克白糖，小火煮10分钟，", "得到了充满少女心的桃汁~倒出晾凉，", "用糖腌过的桃肉比之前软一些了，把它们铺在玻璃杯的底部，", "然后放入冰块，", "倒入巴黎水，至六分满，", "最后倒入煮好的桃子汁，上面放薄荷叶点缀，", "冰爽清新，拍完照就喝了它！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/85b6751e531341a48700c4dd58dfc0e8_744w_730h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('一定要试这一杯夏日饮品：暗恋桃花源，你一定会爱上它', '热门专题', '小清新', '', '[{"name": "桃桃", "amount": "1个"}, {"name": "1瓶雪碧", "amount": "适量"}, {"name": "1瓶桃桃鸡尾酒", "amount": "适量"}, {"name": "两片柠檬", "amount": "适量"}]'::jsonb, '["桃子切片放入杯里，用勺子压一下", "加入冰块", "倒入杯子一半的雪碧", "最后倒入鸡尾酒", "放两片柠檬就完成啦(o^^o)"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/80587247bc434f3fa3d48c8e478b9555_1242w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('法式柠檬挞～夏日清爽法式甜点', '热门专题', '小清新', '甜', '[{"name": "5cm12个挞皮材料", "amount": "适量"}, {"name": "T55面粉", "amount": "120克"}, {"name": "糖粉", "amount": "46克"}, {"name": "杏仁粉", "amount": "25克"}, {"name": "盐", "amount": "1克"}, {"name": "黄油", "amount": "70克"}, {"name": "鸡蛋液", "amount": "23克"}, {"name": "约12个柠檬蛋酱", "amount": "适量"}, {"name": "柠檬屑", "amount": "1个"}, {"name": "柠檬汁", "amount": "35克"}, {"name": "细砂糖", "amount": "40克"}, {"name": "鸡蛋液", "amount": "68克"}, {"name": "玉米糖浆", "amount": "12克"}, {"name": "黄油", "amount": "35克"}]'::jsonb, '["先制作挞皮：面粉、糖粉、杏仁粉、黄油、盐一起放入绞肉机里，打至沙砾状", "放入蛋液，搅拌成团", "搅拌好的状态，放入冷藏1小时以上", "面团冷藏好后，擀至3mm厚的面皮，切", "7cm宽", "5cm的长条，挞圈压圆形", "圆形放入挞圈底部，长条围在挞圈里，把多余的切掉。", "放入预热好的烤箱中，热风功能150度烤20分钟，烤至金黄色即可", "烤好取出放凉后脱模，挞壳就完成了。", "柠檬刮出表面黄色的柠檬屑", "加入柠檬汁、全蛋液、细砂糖、玉米糖浆，放入奶锅里，搅拌均匀后小火加热", "边加入边搅拌，煮至80-82度变浓稠即可", "降温至50-60度左右可以加入黄油，搅拌均匀后过筛", "趁温热时挤入烤好的挞壳里，放入冷藏一小时以上", "在凝固的柠檬酱表面挤上打发好的淡奶油", "撒上糖粉、柠檬屑装饰", "忍不住啦，先吃一块", "小小的～好可爱"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/ba13ab78bd4243cf9e69dd92fc49ffba_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小清新凉拌腐竹', '热门专题', '小清新', '', '[{"name": "腐竹", "amount": "150g"}, {"name": "3-4根西芹", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "10朵木耳", "amount": "适量"}, {"name": "3-4瓣大蒜", "amount": "适量"}, {"name": "香菜", "amount": "2根"}, {"name": "生抽", "amount": "3勺"}, {"name": "陈醋", "amount": "2勺"}, {"name": "白醋", "amount": "2勺"}, {"name": "糖", "amount": "1.5勺"}, {"name": "2-3勺香油", "amount": "适量"}, {"name": "半勺盐", "amount": "适量"}, {"name": "2-3勺白芝麻", "amount": "适量"}, {"name": "自制油辣椒（可看我菜谱）", "amount": "1勺"}, {"name": "半勺白胡椒粉", "amount": "适量"}]'::jsonb, '["腐竹提前冷水泡发，泡发后和芹菜一样切斜刀切段，木耳泡发后洗净备用，胡萝卜切菱形片，香菜切碎e", "胡萝卜去皮切斜刀段", "然后立起来再切片就是菱形片", "碗中放入蒜末，生抽，醋，糖，盐，少许白胡椒粉，香油，一勺油辣椒辣椒油（可以看我的油辣椒菜谱）", "调成料汁", "烧开水后烫熟腐竹，15-20秒，烫过头就烂了，捞出后过冷水，在挤干水分备用", "继续烧开后，芹菜，胡萝卜，木耳焯水15秒，捞出后过冷水，沥干水分备用", "所有食材放入盆中，加入料汁和白芝麻，拌匀即可食用", "非常适合现在疫情期间，运动少的朋友们"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/cc6de111eb5c4826ba5fd9a997da7518_1080w_1557h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('京酱肉丝', '热门专题', '创意菜', '', '[{"name": "猪里脊", "amount": "400克"}, {"name": "甜面酱", "amount": "125克"}, {"name": "三张干豆腐", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "四棵小葱", "amount": "适量"}, {"name": "一小把香菜", "amount": "适量"}, {"name": "两瓣大蒜", "amount": "适量"}, {"name": "两片姜", "amount": "适量"}, {"name": "一个鸡蛋清", "amount": "适量"}, {"name": "一汤匙白糖", "amount": "适量"}, {"name": "小半勺白胡椒粉", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量淀粉", "amount": "适量"}]'::jsonb, '["选择猪里脊肉切成细丝，可以稍微冻一下会好切一些。", "加入一个蛋清，两汤匙淀粉，两汤匙料酒，少许盐和白胡椒粉。", "把调料抓匀后静置二十分钟入味。", "小葱和香菜摘洗干净，胡萝卜去皮切细丝，也可以根据自己喜好准备其它青菜。", "取一张干豆腐，在一端摆好小葱、香菜和胡萝卜丝。", "卷成圆卷", "每隔两厘米左右切斜刀。", "切好后摆在盘子边上。", "我用了王致和的甜面酱，正好一袋，如果用的肉量少就要按照比例减少甜面酱，这个酱口感偏甜，做出来的京酱肉丝更地道。", "甜面酱、一汤匙白糖、一汤匙生抽、一汤匙老抽、一汤匙料酒兑到一起，再加入两汤匙清水搅匀备用。", "加热平底不粘锅，多倒入一些食用油，把腌制好的肉丝倒进去。", "用筷子不停划炒，直到肉丝全部变色至八成熟。", "另起炒锅倒入少量油加热，爆香葱姜蒜末，倒入肉丝。", "加入调好的酱汁翻炒均匀。", "酱汁烧开后加入三汤匙水淀粉大火收汁即可出锅。", "把炒好的肉丝倒入事先摆好的盘中，一盘美成花的京酱肉丝就完成了。"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/e6b9fece49bd499482d3a7af16cc00fd_1000w_1161h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最简单的红烧排骨你肯定会！！！', '热门专题', '创意菜', '', '[{"name": "排骨", "amount": "330克"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "生抽", "amount": "3勺"}, {"name": "白糖", "amount": "2大勺"}, {"name": "黄酒", "amount": "2勺"}, {"name": "姜片", "amount": "5片"}, {"name": "香叶", "amount": "2片"}, {"name": "桂皮", "amount": "1块"}]'::jsonb, '["一盒排骨。330克。我看了一眼是这个重量。就是烧一碗的量。肋排是3大块。需要再改刀一下。", "改刀成一块块小块的。顺着骨头来。切断当中软肉地方就行。", "把排骨冷水放进锅里焯水一下。", "煮沸之后冲凉水。清洗干净就好。\n冷热水都可以清洗。不要再说冷水清洗肉变硬变柴。这个说法没有任何实践科学依据能支持到。可以按着自己喜欢的水温来清洗干净就可以。", "焯好水清洗干净的排骨。", "煮了3个白煮蛋。一起红烧。😍最最最合适。", "切几片姜片。家里有啥大料就用啥。香叶和桂皮都放一点儿", "加水泡着香料水备用。", "起锅加油加2大勺白糖。炒个糖色。", "中火慢慢儿熬。大概也就2分钟的样子。糖色就能熬好。熬到这个颜色就可以了。不要再继续了。糊了会有点儿苦的。这样正好。", "把排骨放进去油糖色里面去裹上糖汁翻炒一下。", "加入刚刚泡着的大料水。全部倒进去。", "把3个白煮蛋也放进去。", "再加入3勺生抽+2勺花雕酒。", "全部煮起来。加盖子。慢慢儿炖一会儿。大概中小火炖个30分钟的样子。", "半个小时之后红烧汁就会慢慢儿减少了。", "再等一会儿汁基本收好了。只有酱汁了。", "可以翻一下排骨。让排骨每一个面都被鲜美的酱汁包裹着。美妙啊。", "装盘啦。", "先来一块咯^_^", "欣赏2秒。再吃啊😂", "红烧汁的卤蛋怎么能少呢。", "简直美妙到飞起啊☺", "⊙∀⊙！哇哦。吃吃吃。无敌的好吃啊。", "锅里的汁不能放过。", "拌上米饭🍚。巨巨巨好吃。"]'::jsonb, 30, 130, '困难', 3, 'https://i2.chuimg.com/12f584793b2e4b4fb123b16e26fcab9f_1002w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('手抓饼创意吃法', '热门专题', '创意菜', '', '[{"name": "鸡蛋", "amount": "1个"}, {"name": "手抓饼皮", "amount": "1个"}, {"name": "火腿肠", "amount": "1根"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["平底不粘锅刷一点点油 手抓饼皮稍微化冻变软后放入", "开最小火 码上4段火腿肠 中间磕上一个鸡蛋 撒点小葱花", "饼皮变很软而且变透明色时 用筷子翻起四边  包住火腿肠", "像这样就可以了", "火稍微开大一些 把底部煎至脆脆的定型后快速用锅铲把饼翻个边  注意不要把蛋搞破了", "翻边后是酱紫的～", "小火煎  把下面的鸡蛋煎至你喜欢的熟的程度即可  我喜欢全熟 而且饼皮焦焦脆脆哒", "出锅后对半切开", "也可以沾自己喜欢的酱吃哦"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/0ee1787fa2d847348fc77442dd603e79_828w_662h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('创意菜虾滑酿羊肚菌', '热门专题', '创意菜', '', '[{"name": "大概10只羊肚菌", "amount": "200克"}, {"name": "虾仁", "amount": "200克"}, {"name": "小芹菜", "amount": "3根"}, {"name": "彩椒", "amount": "1个"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "酱油", "amount": "2勺"}, {"name": "胡椒粉", "amount": "3克"}, {"name": "盐", "amount": "2克"}, {"name": "黄酒", "amount": "2勺"}]'::jsonb, '["市场买回的羊肚菌和虾仁洗净，我今天没买到活虾，所以用了冻虾仁。", "虾仁放入料理机，加3克胡椒粉、1勺蚝油、2勺酱油、2勺黄酒、一瓣蒜、2克生粉一起打成泥。", "把打好的虾滑装入裱花袋，挤进羊肚菌里，每一只都要挤满。", "灌装好的羊肚菌很饱满", "把彩椒掰成小块，小芹菜切成段，2瓣大蒜切成片备用", "热锅倒入油，我用了一半花生油和一半前几天自己炼的鸡油。锅里油烧热放蒜片爆香，放入羊肚菌煎一下。然后加开水，水没到羊肚菌一半的位置，加1勺酱油，2克盐盖上盖子炖煮。煮3分钟后加入彩椒收汁，然后加入小芹菜翻炒就可以出锅了。", "出锅摆盘，每一只羊肚菌都吸满汁水。", "每咬一口灌满虾滑吸满汁水的羊肚菌都超级满足！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/8ef86530b62544b8bf78e48749e84244_3264w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小炒鸡腿肉', '热门专题', '创意菜', '辣', '[{"name": "鸡腿", "amount": "4只"}, {"name": "料酒", "amount": "3小勺"}, {"name": "淀粉", "amount": "2小勺"}, {"name": "线椒", "amount": "3个"}, {"name": "小米椒", "amount": "4个"}, {"name": "5瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "5片"}, {"name": "各15粒花椒麻椒", "amount": "适量"}, {"name": "青蒜", "amount": "1根"}, {"name": "适量生抽", "amount": "适量"}, {"name": "半勺豆瓣酱", "amount": "适量"}, {"name": "10粒豆豉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量糖", "amount": "适量"}]'::jsonb, '["鸡腿用剪刀去骨", "去掉皮内侧的肥油，将鸡腿肉切成小块", "倒入适量料酒去腥。再放一点淀粉，放淀粉能让鸡肉更嫩滑，抓匀后静置10分钟。", "准备辅料，线椒、小米椒、蒜片、姜片、青蒜、花椒、麻椒。10粒豆豉 切开。", "开大火，多倒点油，转一下锅  让油均匀分布在锅上，防止鸡肉粘锅。鸡腿肉下锅，炒5-10分钟，喜欢嫩的时间短点，喜欢焦一点的就多炒会儿。", "倒入生抽，放入花椒麻椒，姜蒜，辣椒爆香。炒1分钟左右，豆瓣酱和豆豉进锅，继续翻炒。", "这时鸡肉颜色已经出来了，再加盐调味，加一点点糖提鲜。炒到差不多时放入青蒜，1分钟即可出锅。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/71daf66926504d3fb7a843f93a1e0976_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('土豆煎饼果子', '热门专题', '小吃', '', '[{"name": "土豆", "amount": "0.5个"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "熟黑芝麻", "amount": "1g"}, {"name": "适量葱花", "amount": "适量"}, {"name": "红腐乳", "amount": "2g"}, {"name": "甜面酱", "amount": "2g"}, {"name": "蒜蓉辣酱", "amount": "2g"}, {"name": "2张馄饨皮", "amount": "适量"}, {"name": "热豆浆", "amount": "300g"}, {"name": "鸡蛋（液）", "amount": "1个"}]'::jsonb, '["热锅凉油擦土豆片，吸干水分喷油，小火煎到微微焦边，打一颗鸡蛋抹匀，撒上黑芝麻和葱花，定型之后翻面，刷红腐乳、甜面酱和蒜蓉辣酱！（正宗天津味！）", "吃不完的馄饨皮划两道，下锅炸到两面金黄，这不就是果篦嘛！给它叠起来煎饼果子就好了！再来上一碗热浆子冲鸡蛋，干的稀的都有了！", "爱吃煎饼果子的都去做！！酥脆可口！简单好做味道嘎嘎正！"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/a7b2bfc759504a12bded69600676cbe4_1080w_1920h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小吃类合集', '热门专题', '小吃', '', '[{"name": "见下图配料", "amount": "适量"}]'::jsonb, '["咖喱鱼蛋的咖喱汁", "咖喱鱼蛋的煮鱼蛋", "蒜香鸡翅尖", "金汤蒜蓉辣椒鸡翅尖", "猪油捞面", "方子搬运已征求小姐姐的同意。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/70b1da44e0144110b2c2046b87ebf8a5_3414w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('梅干菜饼', '热门专题', '小吃', '', '[{"name": "梅干菜", "amount": "2把"}, {"name": "五花肉肥瘦7/3", "amount": "150克"}, {"name": "虾皮", "amount": "1把"}, {"name": "适量葱花", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "少许姜末", "amount": "适量"}]'::jsonb, '["备菜：梅干菜是自己晒的，咸酸口的！泡软后稍微切碎点，挤干水份备用。五花肉剁碎，加姜末和少许盐搅拌均匀备用，虾皮清洗沥干备用！\n\n馅料：猪油多一点爆炒五花肉末和梅干菜碎，炒香炒软放入虾皮爆香，淋少许料酒，晾凉后即可包。这个馅料可以一次性多做冷冻保存，吃的时候解冻再加糖和葱花。", "准备包的时候再放葱花和白糖…", "和面我不太行，掌声有请我家母上大人出场…", "偏硬的面饼，多揉捏几次，上点劲哈！", "包入馅料，多多的放才好吃～", "一个个小饼包好松弛下就可以擀开！", "要擀得薄，才酥脆哦！", "越薄越好，破了点洞都没所谓的，不必担心！", "入锅中火煎熟～", "馅料含油量较大，煎熟后表面都透油呢！哈哈哈…酥脆油香～", "一口入魂啊～"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/2fde88f363ab4dd29c73933ad0dc20e5_3027w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('吕小厨发面泡泡饼', '热门专题', '小吃', '', '[{"name": "面粉", "amount": "适量"}, {"name": "温水", "amount": "适量"}, {"name": "鸡蛋", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "糖", "amount": "适量"}, {"name": "酵母粉", "amount": "适量"}, {"name": "泡打粉", "amount": "适量"}, {"name": "葱花", "amount": "适量"}]'::jsonb, '["500g面粉配\n5g酵母粉 \n5g泡打粉 \n4g盐 \n6g糖\n1个鸡蛋\n380g的温水（40度以下）", "用筷子朝一个方向搅，搅到没有颗粒感后加入葱花继续搅，搅3分钟左右，喷油（防止醒发过程风干）", "醒发到两倍大搅拌排气，揪剂子前表面和手上再喷油，桌面也喷上油，放剂子", "手套喷油，用小鱼际捧起来，抓球掐断，放在喷油的面包上，", "表面喷油再醒发15分钟，醒发到表面起泡", "手套和铲子上抹油，把饼胚拿到锅里，进锅里用手调整厚度和大小，中间不要碰破起泡，盖上锅盖烙饼"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/87f14b569b7745679cb20f160a4c4999_1280w_917h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨好吃的盐葱鸡翅！外酥里嫩太绝了～', '热门专题', '小吃', '', '[{"name": "鸡翅", "amount": "10个"}, {"name": "盐", "amount": "1茶匙"}, {"name": "葱", "amount": "20克"}, {"name": "蒜末", "amount": "20克"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "白糖", "amount": "1茶匙"}, {"name": "胡椒粉", "amount": "1茶匙"}, {"name": "适量千岛源有机初榨山茶油", "amount": "适量"}]'::jsonb, '["真的太好吃了", "嗦手指的节奏", "鸡翅洗干净对半剪开，加入葱段和姜丝，少许盐，一点胡椒粉，半勺老抽，一勺蚝油", "一勺淀粉，一勺千岛源有机初榨山茶油，抓拌均匀腌制半个小时！", "再来调个盐葱酱，放上葱末和蒜末，加入两勺白芝麻，适量盐，一勺蚝油，一勺白糖，一勺香油，搅拌均匀，鸡翅鸡皮朝下平铺到平底锅里", "再倒入千岛源有机初榨山茶油开火，接着给鸡翅煎到两面金黄再铺上一层调好的盐葱酱，转最小火焖上个两分钟即可！", "🍃做法简单到没朋友，厨房小白也能轻松复刻，快试试这个让味蕾惊艳的搭配吧！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/656bc54cabec4b54b85d008b468de1ed_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱肉包子馅', '热门专题', '酱', '', '[{"name": "肉丁", "amount": "1000克"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "6朵香菇", "amount": "适量"}, {"name": "大葱", "amount": "1根"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量甜面酱", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量耗油", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["准备好所有材料，我的比较简单，如图所示。😏", "将切好的肉丁先入锅榨油，因为我们喜欢肉馅肥一点，所以选择的是肥肉多过瘦肉的肉块，具体什么部位我说不出来，图中是两斤多的肉。", "将肉榨至有表面金黄，就可以捞出备用。我喜欢多榨一下，嚼起来更香，不腻。", "下了这么多油出来，太多了倒点出来，这块肉太肥了，当家的说肥的包包子好吃些，依据大家自己口味来选择哈。😏", "倒了这么多出来，正好拿来做蛋黄酥😜", "锅中留一些油，将洋葱倒进去，炒至变色，香味扑鼻时，再加入香菇和大葱。", "加入的香菇和大葱炒熟。", "再将肉丁倒进来一起炒。", "我根据锅里面的材料加了两勺甜面酱。", "对比一下勺子大小。讲真，这个佐料我还真的酌情处理，真没办法给大家具体的克数，建议新手都少量加，然后尝一下味道，再决定要不要继续加。", "一勺耗油。", "适量料酒。", "适量生抽。建议先尝一下味道，我不知道你们放的甜面酱和耗油的咸度够了不，不要放太多到后面馅料很咸。", "一点老抽，如果你觉得颜色已经可以了，这步可以省略。", "适量白糖。这个小勺子我放了四勺，因为我喜欢吃稍微偏甜一点。", "酱肉馅，出锅了。", "这是之前做的，凝固后，如果喜欢吃葱的，再包之前再把小葱和肉馅混合，就可以包了。", "这次炒的馅料如图😜", "我包的大小蒸好差不多掌心以内，这个大小我方子里的肉馅至少包50个以上嘛，家里人口多，人口少的可以一次少弄一点。"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/fce72dadc7f74b9d9ede5e04205bbc2b_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“东北yyds鸡蛋酱”太费米饭了！3步搞定超简单！', '热门专题', '酱', '', '[{"name": "鸡蛋", "amount": "4个"}, {"name": "青椒", "amount": "1个"}, {"name": "黄豆酱，半勺糖，半勺生抽，小半勺老抽，8勺水（尝尝咸淡）料汁：", "amount": "3勺"}]'::jsonb, '["看看！馋不馋！真的贼下饭！", "提前调好料汁：3勺黄豆酱，半勺糖，半勺生抽，小半勺老抽，再加4勺水（自己尝咸淡喔～）", "4个鸡蛋打散，炒至5分熟", "淋入料汁～", "再倒入切小块的青椒，炒断生，最后大火收汁至浓稠就好啦"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/53ee2c6ae7664296883a64abe1bb02e1_943w_1209h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到舔手的酱肉丝', '热门专题', '酱', '', '[{"name": "猪肉", "amount": "300克"}, {"name": "老抽", "amount": "1勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "料酒", "amount": "1勺"}, {"name": "黄瓜", "amount": "1根"}, {"name": "糖", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "淀粉", "amount": "2勺"}, {"name": "食用油", "amount": "1勺"}]'::jsonb, '["一勺生抽", "一勺淀粉", "一勺料酒", "一勺油，所有调料拌匀，腌制十五分钟", "勾芡用的酱汁", "最后加一勺淀粉搅拌均匀备用", "饺子皮一面刷油，再盖上一片刷油，一次叠七八片，擀平，蒸十分钟。趁热把饺子皮分开，就是卷饼啦！", "腌制好的肉丝下锅炒熟，倒入酱汁翻炒上色，最后收汁到自己需要的程度就OK啦", "快来试一试吧"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/c4e9800d3b124808b82101d7f65409c7_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('十分钟做好一盘肉酱拌面，太好吃了', '热门专题', '酱', '', '[{"name": "面条", "amount": "2把"}, {"name": "肉末", "amount": "200克"}, {"name": "半根黄瓜", "amount": "适量"}, {"name": "适量熟花生", "amount": "适量"}, {"name": "一根香菜", "amount": "适量"}, {"name": "小米辣", "amount": "3根"}]'::jsonb, '["🌿🌿食材：猪肉末200g，面条100g，熟花生，黄瓜丝，小米辣，蒜各适量\n\n🌿🌿做法：1️⃣，锅内热油，放入蒜末，小米辣，葱末爆香，接着倒入肉末炒至变色，调味加一勺白糖➕一勺料酒➕两勺生抽➕一勺老抽➕半勺蚝油翻炒均匀，倒入淀粉水煮至浓稠关火盛出\n\n2️⃣另起锅水开下面条煮熟捞出，浇上肉酱，熟花生，黄瓜丝，撒点葱花拌匀即可", "文案说明⬆️", "酱香浓郁", "面条裹满酱汁", "肉末香，夹馒头也好好吃😋"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/e4ebbf31965549d681bdce31d3af6b79_1125w_1474h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱大骨', '热门专题', '酱', '', '[{"name": "猪棒骨", "amount": "2根"}]'::jsonb, '["浸泡：2根猪棒骨（约1500g）对半切断，清水浸泡1小时泡出血水。", "焯水：锅中放入大骨，加3勺料酒、4片姜片、3节大葱段和没过大骨量的清水，大火烧开后继续煮约5分钟。", "捞出大骨用温水洗净。", "卤制：锅中放入大骨、4片姜片、2节大葱段、2片香叶、4个八角、2片桂皮、2勺冰糖、4个干辣椒、6勺生抽、3勺老抽、3勺黄豆酱、1勺盐、800ml啤酒（或料酒，但啤酒更好），再加入清水没过骨头。\n\n*也可以用高压锅炖煮约30分钟，但是肉容易脱落，可能丧失另一种乐趣，因此可根据个人喜好选择。", "大火煮开后，转小火炖煮1小时。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/77390fdf41e348008f4d157e2ce78dcf_1280w_1916h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('考伯沙拉', '热门专题', '沙拉', '', '[{"name": "一棵沙拉生菜", "amount": "适量"}, {"name": "半个牛油果", "amount": "适量"}, {"name": "半块鸡胸肉", "amount": "适量"}, {"name": "一片切达芝士片", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "8-10个圣女果", "amount": "适量"}, {"name": "火腿片或培根", "amount": "3片"}, {"name": "八分之一个洋葱", "amount": "适量"}, {"name": "适量千岛酱或其他沙拉汁", "amount": "适量"}]'::jsonb, '["沙拉生菜洗干净，切碎一些，放入盘底", "小番茄对半切开排入盘中，水煮蛋切开成小块，洋葱切小块，放入盘中", "火腿片或培根切成", "5厘米见放的片，锅里放少量油煎出香味", "鸡胸肉切成", "5厘米见放的小块，加入适量黑胡椒腌制10分钟，锅中放少量油，煎熟", "鸡胸肉和火腿放入盘中", "芝士切碎成细条，摆入盘中", "牛油果切成", "5厘米见放的块，撒上些许柠檬汁防止氧化，摆入盘中，如图", "拌好沙拉酱就可以吃咯！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/c944e8528a6c11e6a9a10242ac110002_5760w_3840h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('藜麦减脂沙拉混搭终结篇', '热门专题', '沙拉', '', '[{"name": "-20g（白色、三色皆可）藜麦（一人食）", "amount": "6g"}, {"name": "左右一种主打低脂肉类（鸡胸肉、大虾、蟹肉、吞拿鱼肉、烟熏三文鱼、带子等）", "amount": "80g"}, {"name": "半颗到一颗叶菜（视情）一种主打菜", "amount": "适量"}, {"name": "随喜（下面会细说）1、2种配菜", "amount": "适量"}, {"name": "随喜1、2种坚果", "amount": "适量"}, {"name": "随喜一种果干", "amount": "适量"}, {"name": "随喜奶酪", "amount": "适量"}, {"name": "随喜调料（柠檬汁、白葡萄酒醋、黑醋、橄榄油、低卡沙拉酱、巧克力酱等）", "amount": "适量"}]'::jsonb, '["吆喝什么先料理什么。\n☀️藜麦水煮，开锅小火12分钟，沥水备用。藜麦6g就够主图效果了，亲想多加不限，把藜麦当主食吃也行。", "其他的得从头一步一步来：\n步骤一（part1）：主打肉\n☘选一款低脂肉类，基本白肉就行，鸡虾鱼蟹皆可，一款哈。\n请忘了培根，谢谢。培根碎也不行。咱今天玩儿低脂。\n上图白肉丁就是鸡胸肉。\n肉要做熟，下面说👇", "步骤一（part2）：主打肉\n☘虾肉可以加盐煮或、葱姜蒜爆；\n☘鸡肉可以加盐蒸、烤、煎，我不反对蜂蜜煎鸡胸科科；\n☘鱼肉可以煎，贝类带子要煎，也有现成的烟熏三文鱼、金枪鱼碎等；\n☘蟹肉现成的，不是蟹柳棒，超市有卖现成的蟹肉腿，挖出来就好了；\n☘烹制过程中可辅以蘑菇、蘑菇、蘑菇，味道好摆出来也好看。", "步骤二：主打菜\n☘一般都是大叶菜，如生菜、火箭菜（芝麻菜）、罗马生菜、羽衣甘蓝、散叶生菜、西生菜、唐生菜（港人叫法，就是圆生菜）、菊苣、小叶菠菜、苦苣、切片的黄瓜也可以，一般都铺盆底。\n如图铺底的是紫缘散叶生菜，厨房君最近有个帖子介绍叫罗莎红，绿叶的叫罗莎绿，涨姿势。", "步骤三：配菜\n☘喜欢什么加什么，水果蔬菜皆可：\n小番茄、胡萝卜、芦笋、萝卜苗、紫洋葱、牛油果、无花果、紫甘蓝、柚子、樱桃萝卜、香蕉、比利时长梨等等。\n凹造型colorful就靠这步了！", "步骤四：坚果\n☘爱放啥放啥，憋客气。腰果、开心果、核桃、榛果、杏仁、碧根果、夏威夷果、鹰嘴豆、芝麻、齐亚籽等等，藜麦也在这步加。", "步骤五：果干\n☘蔓越莓干、葡萄干、桑葚干、真的果干（苹果干、桃干、香蕉干那些）等，一定要放！在全场脆啵啵的时候不经意吃到一颗软甜的果干，妙不可言～", "步骤六：奶酪\n☘合适沙拉的奶酪很多，个人最爱山羊奶酪，一次一大勺。\n基本上，这步之后就可以拍照了。\n赖子刚建了一个芝士心得贴https://www.xiachufang.com/recipe/102244309/ 有兴趣的亲可以去看看，不喜勿喷。", "步骤七：调料\n☘柠檬汁、红白葡萄酒醋、橄榄油、黑胡椒、盐、沙拉酱（尽量选低卡的，蛋黄酱、千岛酱之类的就算了吧），巧克力酱真的是放纵一下才会加的憋学我……\n以上都看个人口味，赖子喜欢橄榄油+黑胡椒，还有上一步的奶酪就够了。想调味就多加一个白葡萄酒醋。\n可以单用碗装好液体调料，等拍完照就浇进去拌了吃；想少刷一个碗直接撒食材上也行……看需要。", "步骤八：摆拍（可省）\n可以把主角放上面拍…", "可以拌开了拍……", "还是放上面拍……", "或者拌开了拍……亲都会举一反三哒", "用了快一年的封面款，存这里颐养天年💕"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/c9795aa43eb411e7947d0242ac110002_4032w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到哭泣的油醋汁', '热门专题', '沙拉', '', '[{"name": "2瓷勺橄榄油/玉米油", "amount": "适量"}, {"name": "2瓷勺生抽", "amount": "适量"}, {"name": "2瓷勺苹果醋", "amount": "适量"}, {"name": "1～1.5瓷勺蜂蜜", "amount": "适量"}, {"name": "适量黑胡椒", "amount": "适量"}]'::jsonb, '["全部材料倒入密封的小罐子，使劲摇晃使其乳化。", "淋入蔬菜中，完美。\n蔬菜我用了苦菊，生菜，黄甜椒，煮熟的水果玉米粒，鸡蛋，鸡肝，鸡胸肉。", "悄咪咪增加一步，针对不减肥，不是减脂期的小朋友。法棍斜切片，平底锅中放一块黄油，烧热把法棍片放进去煎至两面金黄，配沙拉真的是，绝了。\n唯一不足的一点就是，这是个热量炸弹。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/aa2035ac28e943328be7a9d8484b0922_2048w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蔬菜沙拉（美丽又减脂）', '热门专题', '沙拉', '', '[{"name": "生菜", "amount": "3片"}, {"name": "一小把苦菊", "amount": "适量"}, {"name": "2小片紫甘蓝", "amount": "适量"}, {"name": "圣女果", "amount": "8个"}, {"name": "黄瓜", "amount": "1根"}, {"name": "熟鸡蛋", "amount": "1个"}, {"name": "适量沙拉酱", "amount": "适量"}, {"name": "少许醋", "amount": "适量"}]'::jsonb, '["准备好材料，洗干净，凉干水分", "把生菜撕成小块，苦菊切段，生女果对半切开，熟鸡蛋也切成小块，黄瓜切片，各种蔬菜随意切", "把所有材料装入盘中混合，然后放入调料即可，美美哒享受吧。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/d7cb9c0430e34c69aca5f4ac7a2994a6_606w_404h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蔬菜沙拉', '热门专题', '沙拉', '', '[{"name": "生菜", "amount": "6片"}, {"name": "圣女果", "amount": "10个"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "适量沙拉酱", "amount": "适量"}, {"name": "1大块鸡胸肉", "amount": "适量"}, {"name": "1朵西兰花🥦", "amount": "适量"}]'::jsonb, '["鸡蛋煮熟切厚片，西兰花切小朵用热水煮熟，圣女果切两半，生菜叶切小片，鸡胸肉腌制切片煎熟", "淋上自己喜欢吃的蘸料", "特别美味"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/4dfbe73258aa477b8125358980699fdf_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('土豆泥拌茄子', '热门专题', '凉菜', '', '[{"name": "三根茄子", "amount": "适量"}, {"name": "土豆", "amount": "2个"}, {"name": "香菜", "amount": "2根"}, {"name": "1瓣大蒜", "amount": "适量"}, {"name": "适量熟酱", "amount": "适量"}]'::jsonb, '["主料：茄子洗净，土豆去皮", "茄子掰开，手撕成小条状，放蒸锅下屉", "土豆切小块放蒸锅上屉，水开后与茄子一起蒸大约20分钟", "蒸茄子土豆时准备：蒜一瓣切末，香菜两根洗净切末，适量熟酱：我用的是自己炸的鸡蛋酱，我的另一个菜谱https://www.xiachufang.com/recipe/107049957/也可以用超市卖的香其酱", "土豆蒸熟后放入大碗中有勺子压成土豆泥", "根据个人喜好看土豆泥的粗细", "蒸好的茄子", "挤出多余的水分", "放在土豆泥上", "加入酱、蒜末、香菜末", "搅拌均匀即可", "酱色有深浅，所以成品颜色也有深浅，口味咸淡根据个人喜好区别😄"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/c27fa82a0dcf4b42be85e5b00fd14f62_1280w_961h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('青椒皮蛋（开胃凉拌菜）', '热门专题', '凉菜', '', '[{"name": "六个皮蛋", "amount": "适量"}, {"name": "一个线椒（家里没有，我这里用的青椒）都可以哈", "amount": "适量"}, {"name": "三瓣儿蒜末", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "鸡粉", "amount": "适量"}, {"name": "白胡椒", "amount": "适量"}, {"name": "蚝油", "amount": "适量"}]'::jsonb, '["我这里是一个皮蛋切四瓣，大小看你们自己习惯哈", "青椒➕蒜末混合在一起", "抄配料油温不能太高，油热就可以放进去，然后小火炒，青椒一定要炒软，我很喜欢挑这个青椒吃，巨下饭", "炒好的青椒蒜末和油都盛到碗里，生抽、白胡椒、鸡粉、蚝油搅拌均匀，尝下咸淡，盐味不够，再加点生抽（不用加盐）", "用勺子均匀铺到每一瓣儿皮蛋上面，这样就不用去搅拌了，皮蛋会容易碎，看着就不那么好看，小孩就不想吃（我家孩子可爱吃了）"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/2b634329a9f74b03aac46e2d8f04b73e_1440w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌藕片', '热门专题', '凉菜', '', '[{"name": "藕", "amount": "1个"}, {"name": "香油", "amount": "1勺"}, {"name": "三瓣蒜", "amount": "适量"}, {"name": "醋", "amount": "2勺"}, {"name": "白糖", "amount": "1勺"}, {"name": "盐", "amount": "1勺"}, {"name": "花椒", "amount": "1勺"}, {"name": "干辣椒", "amount": "2个"}, {"name": "1小块姜", "amount": "适量"}]'::jsonb, '["买的新鲜莲藕切成薄片", "焯水:水开后放一勺白醋 一勺白糖再放藕片，这样莲藕不变色", "姜末、蒜末、干辣椒切丝、花椒粒，泼热油激发香味", "刚才的料汁放1勺盐、1勺白糖、1勺白醋、半勺香油，拌匀", "出餐啦！！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/e4d133cffc104b0f952787159cc367c5_1280w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('东北家常凉菜', '热门专题', '凉菜', '', '[{"name": "黄瓜丝", "amount": "适量"}, {"name": "白菜丝", "amount": "适量"}, {"name": "豆皮丝", "amount": "适量"}, {"name": "胡萝卜丝", "amount": "适量"}, {"name": "香菜段", "amount": "适量"}, {"name": "粉丝或者拉皮", "amount": "适量"}, {"name": "肉丝", "amount": "适量"}, {"name": "辣椒丝葱丝", "amount": "适量"}]'::jsonb, '["蔬菜都切丝后，准备炒肉丝，先备好调料（一勺蚝油，两勺生抽，半勺老抽，一点松茸鲜和十三香搅拌均匀），锅里放油油热加入肉丝煸炒，放入适量辣椒丝和葱丝提鲜，加入料汁，大火收汁后放凉，和凉菜搅拌均匀即可"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/d78ab1761bee408ba51e7ca616cb8ac3_975w_1415h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('四季皆宜的凉拌菜', '热门专题', '凉菜', '', '[{"name": "2-3瓣（切成蒜泥）蒜", "amount": "适量"}, {"name": "小米辣2个（辣椒面2-3勺）小米辣或辣椒面", "amount": "适量"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "绿豆芽", "amount": "100g"}, {"name": "菠菜", "amount": "200g"}, {"name": "一小把绿豆粉丝", "amount": "适量"}, {"name": "一小团豆腐皮", "amount": "适量"}, {"name": "随心所欲白芝麻", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "少许白砂糖", "amount": "适量"}, {"name": "少许鸡精", "amount": "适量"}, {"name": "2-3小勺芝麻油", "amount": "适量"}, {"name": "适量醋", "amount": "适量"}]'::jsonb, '["豆腐皮拆包用温水泡发15-20分钟\n绿豆粉丝用冷水泡发至软", "胡萝卜🥕切丝、菠菜切段\n锅里水开后加少许盐和几滴食用油，绿豆芽、胡萝卜🥕、菠菜、绿豆粉丝煮开后捞出放入凉水或冰水过凉，然后捞出控水备用", "把所有食材放入盆里，倒入适量的生抽、白砂糖、鸡精、芝麻油、辣椒面、白芝麻、醋，彻底拌匀", "成品颜值在线", "豆腐干丝和粉丝都来自山姆超市，附图仅供参考，有需要的厨友可以少走弯路"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/deb32155d72d49d1b4935e3c7c5b4846_3414w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('脆脆薯饼', '热门专题', '零食', '', '[{"name": "土豆", "amount": "2个"}, {"name": "盐", "amount": "3克"}, {"name": "约40克淀粉", "amount": "适量"}, {"name": "适量香肠丁", "amount": "适量"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["土豆蒸熟", "准备香肠丁和葱花", "土豆捣成泥，加香肠丁。葱花。玉米淀粉，盐", "揉成面团", "捏成形状，下锅煎至两面金黄即可"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/940d16359b7d4708b319c0e1c1bf5f10_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('饺子皮小零食', '热门专题', '零食', '辣', '[{"name": "适量饺子皮", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "适量烧烤撒料", "amount": "适量"}]'::jsonb, '["饺子皮，适量，就是没必要刻意去买，什么时候包饺子剩下了，就会做一次这个小零食。", "中间十字刀切开。抖散开。", "油温8成，中火，炸制。就是油温烧到，筷子放进去，有密集小泡泡，就代表油温刚刚好。炸好，捞出控油。", "撒上爱吃的烧烤撒料。香香脆脆美味。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/634cf8ab7de14440b6036aa57b70ebbb_1280w_1037h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('炸薯条2小时不回软秘诀（可商用）', '热门专题', '零食', '', '[{"name": "黄心土豆", "amount": "1000克"}, {"name": "盐", "amount": "10克"}, {"name": "玉米淀粉", "amount": "80克"}, {"name": "小苏打（可无）", "amount": "2克"}, {"name": "植物油", "amount": "1000克"}]'::jsonb, '["三个黄心大土豆，大约2斤，洗净去皮", "5厘米厚度的条（不要太粗，太粗口感容易面）", "清水淘洗几遍，尽量把土豆表面的淀粉淘洗掉（土豆淀粉很容易糊化），加入10克盐，浸泡10分钟", "浸泡好的土豆捞出，水开下锅，焯水2分钟", "捞出迅速过冰水使其冷却", "沥干水分，或者用厨房纸巾擦干表面水分，分两三次撒上共80克玉米淀粉+2克小苏打（起酥脆作用，可不加，但千万别多加，多了油容易起泡沫，且土豆发黄），每次撒完都颠匀盆子，最终粉类均匀、薄薄地裹住土豆条为准", "油温6成热，大概160度，下入土豆条（可以先丢进去一根土豆条，周围迅速泛起油花，三秒土豆条浮起来作为判断标准）", "刚下入时候不要翻动，中火大概2分钟，土豆条定型后，再推动均匀炸制3～5分钟，最后一分钟大火轰一下", "经历了七八分钟，炸熟了，捞出，先静置两分钟以上，给内部湿气继续往外挥发的空间", "两分钟后，用最大火高油温，复炸一遍，炸大约1分钟即可", "捞出，准备好番茄酱蘸食，这样做出来的薯条，放置1-2小时也不容易回软，不过还是建议尽快食用完毕"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/0971701d88bd4201ab9b6755e1ba9141_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蜜汁猪肉脯', '热门专题', '零食', '', '[{"name": "猪后腿肉（3肥7瘦）", "amount": "500g"}, {"name": "40-50g糖", "amount": "适量"}, {"name": "蚝油", "amount": "20g"}, {"name": "3-5g盐", "amount": "适量"}, {"name": "3-5g酱油", "amount": "适量"}, {"name": "3-5g老抽", "amount": "适量"}, {"name": "5-10g高度白酒", "amount": "适量"}, {"name": "(可不加)鱼露", "amount": "5g"}, {"name": "3-5g鸡精", "amount": "适量"}, {"name": "红薯粉(或玉米淀粉)", "amount": "2勺"}, {"name": "2-3g(可不加，加了更好看)红曲粉", "amount": "适量"}, {"name": "适量白芝麻", "amount": "适量"}, {"name": "1:1蜂蜜和水", "amount": "适量"}]'::jsonb, '["后腿肉尽量选这种带3分肥7分瘦的，不够肥的可以另外买点纯肥膘加进去", "切小块后用放入绞肉机绞碎", "放入除红薯粉外的调料一起绞打", "个人喜欢有嚼头的，可以不用打的太碎，带一点点颗粒感！", "取出加入红薯粉搅拌匀，然后摔打上劲，放冰箱冷藏1-2小时", "油纸是26cm的，放140g左右肉泥，盖一张保鲜膜，用擀面杖擀平", "可以用个盘子先整体压扁后，再用擀面杖推平", "500g猪肉大概可以做3-4张", "不用放油用平底锅开中火先定个型，先放有油纸的那一面煎", "煎到变色后，翻面取下油纸，继续煎", "两面都稍微焦黄以后，放一边备用", "烤箱200度预热，放入定好型的肉饼，温度保持在180-200度左右", "注意观察，两面都烤至金黄后刷上蜂蜜水，再烤5分钟，如果要加芝麻的话，这个时候可以加上去，(因为已经在平底锅煎到半熟了，用烤箱烤主要是收干水份和烤出油脂，而且每个烤箱脾气不一样，时间不是固定的，要多观察，烤到自己想要的干度就可以了)", "两边都这样滋滋冒密集的油，就差不多可以出炉了，出炉后有余温，肉的色泽和干度还会加深一些", "刷完蜂蜜水和芝麻后正反面烤5分钟左右可出炉", "不刷芝麻的也很好吃，放凉后颜色会加深", "刚出炉的，又香又好吃", "剪成自己喜欢的大小", "真空包装可以延长保存时间，1000g猪肉成品大概650g，以后想吃就可以做起来😊"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/a8b9d8e7e5bd4bcbb9bc4cea8be70f10_1280w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('| 自制无糖无添加苹果干', '热门专题', '零食', '', '[{"name": "苹果", "amount": "8斤"}]'::jsonb, '["苹果去皮去核切成8份", "铺在晾网放太阳底下晒", "晒到这样就可以开始一蒸了", "上锅水开蒸13分钟左右", "晒成这样开始第二次蒸", "水开蒸15分钟左右，看苹果大小", "风炉模式120度烘烤60分钟", "水开蒸20分钟左右", "烘好啦，可以吃了，哦耶", "烤箱风炉模式100度烘烤30分钟", "最后成品530g"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/ed72e1b2813e4f4ea45b2a1406d594b5_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('三文治', '热门专题', '三明治', '', '[{"name": "切片吐司", "amount": "4片"}, {"name": "半个牛油果", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "海盐", "amount": "适量"}, {"name": "黑胡椒", "amount": "适量"}, {"name": "带籽的那种！芥末酱", "amount": "适量"}, {"name": "蛋黄酱", "amount": "适量"}, {"name": "多片午餐肉", "amount": "适量"}, {"name": "多片生菜", "amount": "适量"}, {"name": "卷心菜、培根、洋葱，炒鸡蛋、菠菜……各种材料", "amount": "适量"}, {"name": "保鲜膜", "amount": "适量"}, {"name": "锋利的锯齿刀", "amount": "适量"}, {"name": "加些坚果，层次更丰富！坚果", "amount": "适量"}]'::jsonb, '["做好准备工作~\n生菜洗净，胡萝卜切丝，用盐和黑胡椒调味。鸡蛋煮熟切片，牛油果切片。", "将吐司切片，放入烤箱，上下火180度，5分钟。", "午餐肉煎至两面稍黄。", "在吐司上抹上芥末酱和蛋黄酱。\n芥末酱是最近发现的新大陆，起初觉得微酸，慢慢发觉能融合蔬菜的清新和肉类的香浓，欲罢不能，他还是搭配贝果的一把好手啊！！！", "吐司上铺上两片生菜叶，主要为了搭配颜色，提供爽脆口感！", "铺上午餐肉，午餐肉其实也可以叠起来放，像牛油果那样~\n码上牛油果，我在牛油果上撒了些海盐和黑胡椒调味。", "我用的草鸡蛋，有点小了，像牛油果那样叠起来码上，切开更好看哦~\n这时你发现两侧比较空，中间比较满的~没关系", "无论前面放了什么，最后满满地铺上胡萝卜丝！尤其是两侧比较空的位置，能铺多满就铺多满。\n如果换成卷心菜沙拉也是一样的做法。", "再铺上两层生菜，这样比较对称！\n盖上另外一片吐司，压一压。胡萝卜会掉下，没关系，塞回去或者吃掉。", "好了，现在是比较重要的步骤。\n将组合好的三明治在保鲜膜上。尽量紧一些，四周低一点，中间高一些。", "再包一层保鲜膜，切的时候比较操作。", "三明治包好后，可以把料理现场收拾一下。\n请用一把锋利的锯齿刀来切三明治！", "因为有了保鲜膜切的时候，中间的食物不会掉落。吃的时候也很方便！", "如果觉得保鲜膜不够美观，其实这时再包纸也是完全可以的哈~\n不过呢，我觉得保鲜膜包的整齐一些，就挺好看的啦~~主要是食用便利~~（不要为懒找借口╮(╯_╰)╭）", "这是之前做的，中间夹了卷心菜沙拉。\n上面用的是12cm正方形吐司，这张用是普通450g吐司模做出来的切片。看起来更萌哈~"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/262bb5188a4611e6a9a10242ac110002_5173w_3449h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('乳酪三明治', '热门专题', '三明治', '', '[{"name": "全麦吐司", "amount": "4片"}, {"name": "适量肉松", "amount": "适量"}, {"name": "适量熟玉米粒", "amount": "适量"}, {"name": "适量马苏里拉", "amount": "适量"}, {"name": "适量沙拉酱", "amount": "适量"}, {"name": "四片火腿片", "amount": "适量"}, {"name": "牛奶", "amount": "45g"}, {"name": "鸡蛋一个", "amount": "45g"}]'::jsonb, '["第一层，先挤上沙拉酱", "沙拉酱上面铺肉松", "第二层铺上熟玉米粒和马苏里拉", "第三层铺上火腿片", "鸡蛋牛奶一比一的比例", "调成蛋奶液", "第四层上面刷上蛋奶液，面包的四周容易烤干，可以都刷上蛋奶液", "第四层最上面铺马苏里拉", "挤上沙拉酱", "都挤好，烤箱200度预热10分钟", "烤10-15分钟，表面上色即可", "切开食用", "快手早餐"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/b620e02cbb714515a97079dcfb1857e0_1080w_1920h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鸡蛋金枪鱼三明治健身可吃', '热门专题', '三明治', '', '[{"name": "1罐水浸金枪鱼", "amount": "适量"}, {"name": "适量甜玉米粒", "amount": "适量"}, {"name": "适量脱脂酸奶", "amount": "适量"}, {"name": "全麦吐司", "amount": "4片"}, {"name": "水煮蛋", "amount": "1个"}, {"name": "适量生菜", "amount": "适量"}, {"name": "奶酪(可选)", "amount": "2片"}, {"name": "适量黑胡椒(可选)", "amount": "适量"}, {"name": "适量柠檬汁(可选)", "amount": "适量"}]'::jsonb, '["从水浸金枪鱼罐头中取出金枪鱼，尽量去除水分。\n冷冻甜玉米粒加入沸水中2-3分钟，盛出加进金枪鱼。", "用低脂无蔗糖酸奶代替沙拉酱，放入金枪鱼和甜玉米粒中，搅拌均匀成金枪鱼沙拉。\n加入适量柠檬汁和黑胡椒提味。", "面包在平底锅中正反烤一下，会变脆一些，当时吃口感更好，不烤也没事。\n铺一层生菜，一层金枪鱼沙拉。", "再铺一层生菜，一层切碎的水煮蛋，然后我加了热量很低的黄芥末酱，最上面再加一片奶酪。", "盖上一片烤好的面包，用保鲜膜或油纸包紧，切开即可。", "食材和顺序可按自己喜好调整，我一般菜类会放的比较多，最后做好要压一压包紧。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/bf23f509884240e3a305c35caa1fa8c9_780w_780h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级好吃的黄金三明治', '热门专题', '三明治', '', '[{"name": "若干沙拉酱", "amount": "适量"}, {"name": "火腿", "amount": "4片"}, {"name": "若干原味肉松", "amount": "适量"}, {"name": "咸吐司", "amount": "5片"}, {"name": "适量蛋黄液", "amount": "适量"}, {"name": "若干芝士碎", "amount": "适量"}]'::jsonb, '["5片吐司 每层都夹 沙拉酱 火腿片 肉松 沙拉酱", "切去四边不整齐的吐司 不嫌弃做出来形状不美观的话 也可以不切 自己吃也无所谓", "四周➕最上一层涂上蛋黄液", "第一层再挤一些沙拉酱", "再尽量均匀的铺上芝士碎", "进预热好的烤箱 温度上250 下160 大概10分钟 每个烤箱脾气不一样 自己勤观察哦 如图上色就差不多了 出炉➕珠葱末（也可以不放）", "沿对角切开 完美的三明治完成✅"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f52c5d108c834178a9357a270f62931c_1836w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('随意任性发挥的早餐三明治', '热门专题', '三明治', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "随意片生菜", "amount": "适量"}, {"name": "随意勺沙拉酱", "amount": "适量"}, {"name": "随意个西红柿", "amount": "适量"}, {"name": "面包", "amount": "2片"}, {"name": "随意片紫甘蓝", "amount": "适量"}, {"name": "蟹肉棒", "amount": "4根"}, {"name": "盐巴", "amount": "2克"}]'::jsonb, '["鸡蛋煎熟。", "蟹肉棒炒熟，加一丢丢盐巴。", "土司双面稍微煎一下，喜欢焦脆的就时间久一点点", "面包双面煎稍微焦，铺一层保鲜膜，放在保鲜膜上面备用。", "抹点沙拉酱在面包片，生菜备上。", "西红柿备上，再来点沙拉", "蟹肉棒备。", "紫甘蓝备上，沙拉再来点？喜欢就抹上，没啥", "再来层生菜。", "随便你任性发挥，一层层放上去就ok。喜欢沙拉酱每一层都涂匀也没人拦着你。因为最后要切面好看，所以放的方向注意点，横切的话，食材就竖着放，竖切食材就横着放。聪明如你，一定明白我讲的啥。", "保鲜膜绕着缠两三圈。可以稍微绕紧点都没事，食材不侧漏就行。我好像力度不均匀，歪了一边。", "中间一刀切开。最好一刀搞定。好啦，看着好几层，吃起来满满的幸福感。哈哈"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/54fd512e61a6421fb7de013595ecaaf6_864w_1152h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('广式月饼', '热门专题', '月饼', '', '[{"name": "饼皮：", "amount": "适量"}, {"name": "中粉", "amount": "165g"}, {"name": "转化糖浆", "amount": "116g"}, {"name": "花生油", "amount": "50g"}, {"name": "枧水", "amount": "4g"}, {"name": "吉士粉", "amount": "4g"}, {"name": "馅料：", "amount": "适量"}, {"name": "7-8g×20个咸蛋黄", "amount": "适量"}, {"name": "27~28g×20个=540-560g白莲蓉", "amount": "适量"}, {"name": "表面刷液：", "amount": "适量"}, {"name": "蛋黄", "amount": "1个"}, {"name": "1/4个（约8g）蛋白", "amount": "适量"}]'::jsonb, '["首先制作饼皮。混合糖浆、花生油、枧水和吉士粉（如果有的话，没有就不加，没关系的，我就没有加），搅匀。", "加入面粉，不用过筛的，直接加进去就好了，中式的点心这方面没讲究的。", "然后用刮刀或者刮板从下往上的样子混合均匀。蛮好操作的，一会儿就能到如右图的状态。", "保鲜膜包好放在一旁松弛至少2小时。最好不要冷藏，冷藏过后的饼皮即使回温再操作，也会感觉有点粘手的。\n我直接就是室温松弛的，并且感觉松弛的时间越久，越不粘手。", "接下来分割馅料。由于要包蛋黄，根据皮馅3:7的比例来，馅料部分是35g，所以蛋黄+白莲蓉=35g就可以了，然后用莲蓉把蛋黄包住。分割好的馅料加盖保鲜膜放置一旁备用。", "馅料分割也要蛮久的时间的，因为要精确称量，然后还要一个个包好。这样弄弄，饼皮松弛的时间也差不多了。分割饼皮15g一个，加盖保鲜膜放置一旁备用。", "然后取饼皮，用大拇指把中间部分压扁。", "然后加入一份馅料，用虎口一点点把饼皮慢慢的推上去。", "然后收口，也是慢慢的推上去就收口了，类似于包汤团的感觉。其实不难的，感觉比包汤团还要简单，因为饼皮蛮油的，不黏手，所以很好推的，试了就知道喽，这个饼皮的方子真心不错呐。", "最后收口。", "不用撒粉防粘的，直接月饼模子里面压出花纹就行了。可以事先在花片和模具周围刷一层薄薄的油，其实感觉不刷也不粘的。哎，蛋黄有些还是蛮大的，半个还要露出来。。。。", "一个个压好之后，就可以烤制了。不用喷水的，因为没有裹粉防粘。先200℃烤5分钟定型。", "然后拿出来，表面刷蛋黄液，下图是还没有刷的样子，刷好的忘记拍了。。。刷蛋黄液的时候不要贪心，其实我给出的蛋黄液做150个月饼都戳戳有余的，所以大家应该知道每个月饼刷到的蛋液那是非常非常的少呐！！！刷子沾了蛋液之后，要在碗边上逼一下，把多余的蛋液都逼出来，然后再刷到月饼表面。这样花纹才会清晰！", "继续用提前预热好的烤箱（海氏C45，根据自家烤箱脾气设定温度）180℃烤15分钟。", "看到月饼的周围有点鼓出来的感觉，同时表面已经上色就表示烤好了。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/cf0f7c7487ed11e6a9a10242ac110002_3648w_2056h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蛋黄莲蓉月饼', '热门专题', '月饼', '', '[{"name": "中筋面粉", "amount": "200克"}, {"name": "转化糖浆（自制个人主页有配方)", "amount": "140克"}, {"name": "花生油", "amount": "50克"}, {"name": "枧水", "amount": "4克"}, {"name": "莲蓉", "amount": "适量"}, {"name": "咸蛋黄", "amount": "适量"}, {"name": "一个蛋黄加4分之一蛋白加15克水蛋黄水（刷饼面用)", "amount": "适量"}]'::jsonb, '["饼皮制作\n转化糖浆，枧水，花生油用手动打蛋器搅拌均匀。再倒入中筋面粉拌匀成团，包上保鲜膜室温松弛2小时以上。\n                                                                           醒面时间也的按照当时的气温而变化，气温热时间相对缩短（如醒面时出油．油面分离也就正明时间醒太久了)\n转化糖浆http://www.xiachufang.com/recipe/100563258/", "制作蛋黃 取咸蛋黄放在铺了油纸的烤盘上，喷潇高度白洒。（也可将蛋黄在装有白酒的碗中过一下）烤箱180度烤8分钟凉后待用。\n\n我是50g的模具，将饼皮和馅按照3:7比例分好。馅料重35g(包括蛋黄在内的重量)先莲蓉将蛋黄包好，皮15克。(如新手馅可选30g，皮20克）", "将馅皮材料称好。馅揉圆待用。皮在手中捏扁。放上馅料，用虎口小心的把面皮往上推，整理好收口，不能有缝隙，并搓圆。", "把月饼坯搓成圆柱状，扔进玉米淀中滚一下再入模具压制。(也可月饼模具内撒上一些防粘，粉在模具中晃一晃，再将多余的粉倒出）", "月饼全部压好放入烤盘。烤箱200度预热，200度烤。月饼表面喷微量水。入烤箱烤5分钟，待花纹定型后，取出来刷一层薄薄的蛋黄水，再放入烤箱，烤15分钟左右。\n（方中烤温仅供参考）摸透自家烤箱脾气是迈向成功重要的一步。", "刚出炉的月饼，饼皮很干硬，等月饼冷却后，室温密封保存，等待2-3天，饼皮会渐渐变得柔软油润，等回油后再吃。\n\n如果你烤的月饼第二就回油，那就是月饼没烤透（熟）。", "这次用的莲蓉馅是广州厨友 @仔仔爱爸爸 送的利口福牌莲蓉口味真的很不错。\n还收到了广式香肠，真心谢谢热情的厨友。泳歌实在感动。", "每一个都是完美无缺。", "29个做月饼会出现的问题                        1、为何月饼出炉后饼皮容易脱落？ 答：原因有以下几方面：\n（1）月饼皮糖浆不够，解决办法是增加糖降用量。\n（2）月饼皮油的量不足，解决办法是增加油量。\n（3）操作时撒粉过多。\n\n2、为何月饼保鲜期不够长？ 答：原因有以下几方面： （1）月饼馅料原材料不足，包括糖和油。（2）月饼皮的糖浆或油量不足。（3）月饼烘烤时间不够。（4）制作月饼时卫生条件不合格。（5）月饼没有完全冷却就马上包装。（6）包装材料不卫生。\n\n3、月饼出炉后表面会发白是什么原因？ 答：原因有以下几方面：（1）月饼皮配方中碱水不够。（2）烘烤时间太短。（3）撒粉太多。\n\n4、为何月饼出炉后会塌陷？ 答：原因有以下几方面：（1）月饼馅含糖量太多。（2）烘烤时间太长。（3）馅料中水份过多。（4）月饼皮、馅软硬不一致。\n\n5、为何月饼出炉后会收腰？ 答：原因有：（1）月饼还没有完全烤熟。（2）馅料中糖油量不足。\n\n6、为何月饼出炉后表面会开裂？ 答：（1）月饼皮太硬了。（2）烤炉面火太猛。\n\n7、月饼为何回油比较慢？ 答：原因有以下几方面：（1）煮糖浆时炉火过猛。（2）糖浆的水份太少。（3）柠檬酸过多。（4）糖浆返砂。\n\n8、月饼出炉后底部比较光滑是什么原因？ 答：原因是月饼皮碱水用量太少。\n\n9、月饼出炉后底部孔洞较大是什么原因？ 答：原因有：（1）月饼还没有完全烤熟。（2）馅料中糖油量不足。\n\n6、为何月饼出炉后表面会开裂？ 答：（1）月饼皮太硬了。（2）烤炉面火太猛。\n\n7、月饼为何回油比较慢？ 答：原因有以下几方面：（1）煮糖浆时炉火过猛。（2）糖浆的水份太少。（3）柠檬酸过多。（4）糖浆返砂。\n\n8、月饼出炉后底部比较光滑是什么原因？ 答：原因是月饼皮碱水用量太少。\n\n9、月饼出炉后底部孔洞较大是什么原因？ 答：原因是月饼皮碱水用量太多。\n\n10、糖浆要煮到什么程度才最合适？ 答：（1）要煮至温度大概为112-118℃。（2）用手粘糖浆可以拉成丝状。\n\n11、为何月饼糖浆煮好后会返砂？ 答：原因有以下几个方面：（1）煮糖浆时水少。（2）柠檬酸过少。（3）煮糖浆时炉火太猛。（4）煮好糖浆后最好不要多次移动，因为多次移动容易引起糖浆返砂。\n\n12、月饼糖浆煮的稠度不够，如何补救？ 答：补救方法是适当的加一些麦牙糖。", "外面那个是500克的大月饼，中间那个是50克的。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/3610597e897f11e6a9a10242ac110002_2048w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五仁月饼馅', '热门专题', '月饼', '', '[{"name": "花生", "amount": "90克"}, {"name": "核桃", "amount": "80克"}, {"name": "腰果", "amount": "80克"}, {"name": "松子", "amount": "40克"}, {"name": "大杏仁", "amount": "80克"}, {"name": "黑白芝麻", "amount": "50克"}, {"name": "西瓜子", "amount": "50克"}, {"name": "南瓜子", "amount": "50克"}, {"name": "葵花籽", "amount": "50克"}, {"name": "香妃王葡萄干加绿宝石葡萄干", "amount": "50克"}, {"name": "蔓越梅", "amount": "50克"}, {"name": "芒果干", "amount": "50克"}, {"name": "菠萝干", "amount": "50克"}, {"name": "杏果脯", "amount": "50克"}, {"name": "山楂条", "amount": "50克"}, {"name": "奇异果干", "amount": "30克"}, {"name": "黑加仑", "amount": "20克"}, {"name": "蜂蜜", "amount": "50克"}, {"name": "玫瑰花酱", "amount": "50克"}, {"name": "凉白开水", "amount": "100克"}, {"name": "花生油", "amount": "100克"}, {"name": "麦芽糖", "amount": "30克"}, {"name": "（可不放）砂糖", "amount": "30克"}, {"name": "白酒", "amount": "8克"}, {"name": "熟糯米粉加低粉各一半", "amount": "210克"}]'::jsonb, '["花生150度15分钟左右！烤好搓皮用吹风机吹干净装袋擀面杖擀碎备用！（我买红皮花生比较香）", "1  坚果大小分开烤，150度，15分钟左右，时间按大小个头加减\n2  建议买烤熟的！要么一个看不准材料就废了，伤银子，图片上只是部分坚果🤔\n3  我都用悠享家原味坚果熟的很香不用烤\n4  糯米粉加低粉炒至微黄放凉备用", "1 烤好坚果搞碎放一起（我为了让坚果大小均匀大杏仁和腰果是用剪刀剪的核桃掰掰就好）坚果可以任意放只要你喜欢！总量加一起够数就行！", "果圃切碎备用！果脯喜欢啥放啥！不喜欢的去掉就好", "1  把坚果果脯放在一个干净的盆里加入糖拌均匀（糖不要一次性加完，因为果脯甜度不同，每个人接受的甜度不同，加到自己喜欢甜度就好）\n2  把油，蜂蜜，玫瑰花酱，酒，凉白开，麦芽糖放在一个干净的盆里（我用打蛋盆）用刮刀或蛋抽搅拌均匀乳化一下！大概2分钟！乳化的好处就是馅不会漏油\n3  把乳化好的液体倒入坚果果脯里迅速拌匀", "液体加入后用筷子搅拌均匀！我量大直接用木铲很方便！", "1  分次加入熟糯米粉和熟低粉，每次揉至无干粉再加入下一次，加完粉戴一次性手套拿出女汉纸的气魄使劲揉让所有材料混合，如果馅散再少量液体直到抱团为止！放半小时就可以用了！（糯米粉和低粉放锅里炒到微黄放凉操作）", "拌好的月饼馅分装起来，3天内用冷藏！放久就冷冻！用之前回温就好", "这是85克哒，所有料加一起成品馅大概1650克，嫌多的小伙伴可以做一半的量，我送人的一般都做量大，我一般坚果都烤好切碎掺匀密封好，随做随调，很快搞定", "饼皮做法  \n 中筋面粉200至210克   转化糖浆140克（转化糖酱自己熬的） 花生油50克  枧水4克   此方子量可以做75克月饼18个     \n 如果配此五仁月饼馅方直接把月饼皮配方量加到2倍\n  饼皮面团要把握好状态！因为面粉吸水量不一样太软就少量加粉，饼皮太软会花型不清晰！没型！干了会裂", "把转化糖浆  枧水  花生油倒入打蛋盆，用蛋抽搅匀之后把中筋粉筛进去拌至无干粉状态不粘手，装保鲜袋静置2小时备用（其实我性子急就没静置就直接用了有那2小时我1百多月饼都做完了）", "我做85克的，皮25，馅60，如果做100克皮30，馅70，做50皮15，馅35，做63就皮20，65克皮20，馅45，75皮22馅53、个人做法仅供参！\n（再友情提示一下团馅的时候一定不要感觉很吃力，团好捏不动的那种干硬，如果发现馅干硬了这个时候还是可以调整的加凉白开抓匀就好，别到时候干了硬了不回油了再来找我😂😂）", "取一个面团放手心摁扁包上馅用虎口慢慢收口！", "现在可以预热烤箱了，我用西门子190度", "月饼胚撒少许粉压模，压模的时候一定要用力啊！这样花纹才能清晰，压完模喷水入炉190度10分钟定型再取出刷一层薄薄的蛋液（蛋黄兑水）刷时候一定要把毛刷刮干净再刷，我一个蛋黄能刷200个，刷完入炉转175度8分钟即可（温度和时间要磨合自己的烤箱）反正馅都是熟的烤色满意就好了！", "烤完放凉密封起来室温2，3天等待回油", "漫长的2，3天终于回油好啦！赶紧切一个，香炸了！好吃的飞起来，好吃到哭！😭颠覆了我对五仁的传统看法，一口气吃俩😋😋（这是我投食烘焙友友小伙伴们的原话）我那么低调才不说类😌怕人家说我吹牛哈哈哈😄😄😄", "诱人不🤓🤓", "今年买太多新模啦！伤银子🙃🙃！这是75克，皮22馅53", "当然你要是实在想吃又觉得材料太多步骤太繁琐也可以找我买呀！应广大小伙伴要求，我真的卖月饼了！月饼按盒，一盒6个。微信号13151208238来找我吧😌😌", "我做馅时候特地录了一下小视频，请宝宝们参考一下馅的干湿程度，很好抱团但又不是很硬的，润润的，如果现在硬静置之后会更硬，但也不能太软，太软做出月饼会变形，总之请参考视频操作，手感实在不好形容，粉加进去之后要多揉一会儿让所有材料混合吸收（水糯米粉都可以少量加减）", "材料都在这小伙伴们参照着买哈！买熟的很香就不用烤了！坚果都悠享佳的！", "材料都在这！小伙伴参照着买哈", "1  果脯品种太多啦！喜欢啥放啥！", "还是剪刀剪的最均匀🤓🤓", "果脯喜欢啥放啥", "用木铲翻拌很方便！", "香炸了！😊", "1  分装成500克一包冷冻起来用时候回温就好！\n2  如果散加少许纯净水戴一次性手套抓匀就好，立马恢复到刚做好时候的状态！", "分装成一斤一包！要馅的小伙伴太多了！所以分装方便发货！这些材料都最好的！所以成本很贵！", "欢迎来撩！", "今年的馅料更豪华🤓🤓"]'::jsonb, 30, 160, '困难', 3, 'https://i2.chuimg.com/ff95e6b05d3c11e7bc9d0242ac110002_1536w_910h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五仁月饼', '热门专题', '月饼', '辣', '[{"name": "月饼馅料:", "amount": "适量"}, {"name": "适量花生", "amount": "适量"}, {"name": "适量葵花籽仁", "amount": "适量"}, {"name": "适量杏仁", "amount": "适量"}, {"name": "适量黑白芝麻", "amount": "适量"}, {"name": "适量蔓越莓", "amount": "适量"}, {"name": "适量（以上总共700克）葡萄干", "amount": "适量"}, {"name": "玉米油", "amount": "120克"}, {"name": "（45度以上白酒就可以）高度白酒", "amount": "10克"}, {"name": "麦芽糖", "amount": "240克"}, {"name": "糯米粉", "amount": "300克"}, {"name": "温开水", "amount": "135克"}, {"name": "月饼皮：中筋面粉（普通面粉）", "amount": "400克"}, {"name": "转化糖浆", "amount": "280克"}, {"name": "陈村牌枧水", "amount": "8克"}, {"name": "月饼皮用的花生油100克", "amount": "适量"}, {"name": "刷月饼表面用的蛋黄水（刷饼皮面用）一个蛋黄加四分之一蛋白加15克牛奶", "amount": "适量"}]'::jsonb, '["瓜子仁一定买原味的，我买的原味葵花籽自己去壳的，花生米是买的生的用烤箱烤熟的，五仁馅料尽量买原味，不要买多味，到时候串味就不好吃了", "这些加一块是700克", "把花生和杏仁还有葵花籽仁用保鲜袋装起来拿擀面杖敲碎", "蔓越莓和葡萄干切小块", "混合在一起就是这样啦，花生和杏仁尽可能敲碎点，颗粒太大我觉得吃不出来那种感觉，要颗粒大还不如直接吃花生和杏仁了", "不想手擀的，用破壁机或者料理机每次打一点点，打3秒钟，时间长了会粉碎，3秒钟的碎度刚好，果仁不可以太大，会影响月饼口感！（ 更新于", "年9月23日凌晨）", "糯米粉用小火炒至微微发黄没有生粉的味道", "拌均匀后是油水不分离的状态（更新于2018年9月23日凌晨）", "五仁碎加上炒好的糯米粉，加麦芽糖加玉米油加白酒，加温开水，手带一次性手套抓捏均匀，按压结实，盖上保鲜膜静置2小时以上，最好三个小时", "很多人反应月饼硬，首先果仁不能太大，其次麦芽糖粘性很强，一定要用手用力抓均匀，手捏无团、然后再给拍打在一起成团静置到完全容合！", "月饼皮：面粉加转化糖浆加枧水加花生油，手带一次性手套上下翻拌均匀，不要揉，不要转圈，免得月饼无法正常回油变软，这是一个老糕点师傅告诉我的，就是把底下的往上翻一下，然后用手掌心往下按一下，以此类推，一定要拌均匀，拌不均匀会导致腰塌的，最后揉成团盖上保鲜膜静置3小时", "翻拌月饼皮的视频1", "翻拌均匀", "用手辅助成团盖上保鲜膜静置", "我喜欢吃饼皮厚的月饼，因为饼皮好吃，所以大部分都是20克皮包30克陷，此方我包了25个20克皮30克陷的，另外还包了19个15克皮35克陷的，最后馅料多了一点加到最后几个里面了", "左手套一次性手套，右手不用套，左手拿饼皮，用右手掌心按压饼皮，然后再用右手中间三个手指指腹按压，这样更薄，更好包陷", "为了拍照，所以没带一次性手套，就这一个没带，其他都带了，免得粘手", "我是先捏25个饼皮和25个陷，其他多余的还是盖保鲜膜放那里，免得时间长了水分流失掉了", "包好后滚一层薄薄的高筋面粉，再用月饼模按压，按压时力气要用足，轻轻压出来的没有重压出来的立体，月饼模首次也撒点面粉哦", "包月饼的手法视频（这是我包豆沙月饼时拍的视频，五仁月饼同手法）", "接上一条", "接上一条", "这是25个20克皮包的30克料，后面15克皮包的35克料我就没拍照了", "烤箱200度上下火预热5分钟，月饼放入烤箱中间层，200度（温度根据自己烤箱情况而定）烤8分钟定型后拿出来刷薄薄一层蛋黄液，一定要薄，不要觉得蛋黄液用不完浪费，你刷多了月饼纹路就不清晰了，刷好蛋黄液后再烤15分钟，烤好后月饼是软的，放凉后会变硬，然后装密封袋里回油三天再吃", "我家女儿等不及要吃，就放凉后切了一块给她吃，我自己也尝了下，皮是酥脆的，陷甜而不腻，陷吃起来也是酥脆的，不是那种像受潮一样哦，满口生香……最后说一下，当时做好之后放凉吃的是酥脆的，回油后没有那么脆，还有此方甜而不腻，不需要减糖，家里小朋友吃，所以不会特别甜的", "这条消息跟文中的不是一个方子，出来的月饼量也不同，不要搞混了！这是调整过的馅料配方，麦芽糖不要用糖或者蜂蜜代替！跟原来的方子没有区别，只是将果仁用料标出来了，15克皮，35克馅可以做52块50克月饼", "15克皮，35克馅料可以做52块50克月饼", "最近发表了一个脆皮肠的秘制配方，喜欢的亲可以在我的菜谱里寻找一下，超级美味的胡椒风味脆皮肠，是一款我卖得特别好的脆皮肠，毫无保留的跟你们分享了配方https://www.xiachufang.com/recipe/102821550/"]'::jsonb, 30, 145, '困难', 3, 'https://i2.chuimg.com/cc7fc50adbed11e6bc9d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五仁月饼', '热门专题', '月饼', '', '[{"name": "果仁之类", "amount": "500克"}, {"name": "白糖", "amount": "45克"}, {"name": "麦芽糖", "amount": "100克"}, {"name": "水", "amount": "77克"}, {"name": "无色无味的油", "amount": "85克"}, {"name": "白酒", "amount": "6克"}, {"name": "熟糯米粉", "amount": "50克"}, {"name": "熟低粉", "amount": "75克"}, {"name": "中粉", "amount": "200克"}, {"name": "枧水", "amount": "3.5克"}, {"name": "花生油", "amount": "52克"}, {"name": "转化糖浆", "amount": "132克"}]'::jsonb, '["把伱喜欢的果仁.\n按大小来.\n生的就烤熟.\n熟的就烤一会儿把香味刺激出来..\n\n我建议买现成的原味熟果仁.\n买生的操作不好不是没熟就是烤糊了.\n\n感觉费事费力费钱.\n装逼系数也提高不了多少...\n\n（来自一个烤糊过的人良心建议）", "所有材料处理好.\n大块的都要弄小.\n剪刀比刀好用.\n\n材料按伱們自己喜欢的放.\n总材料的重量是对的就好！\n\n我這里面有18种材料.\n白芝麻.黑芝麻.腰果.西瓜子仁.\n花生.开心果.榛子.猕猴桃干.\n南瓜子仁.红枣干.杏仁.红葡萄干.\n葵花籽仁.黑加仑.核桃仁.\n松子.绿葡萄干.金橘碎.\n\n我后来還加了几种材料.\n比如冬瓜糖.碧根果.椰子碎片.山楂条之类.\n\n伱們也可以放蔓越莓.\n个人不喜欢就没放.\n\n（打死不会说是没有了.）.(˶‾᷄ ⁻̫ ‾᷅˵)", "低粉和糯米粉混合均匀.\n放入烤箱.170度烤15分钟.\n期间要用刮刀翻拌二次...", "水和麦芽糖放锅里混合均匀.", "用中小火烧开后煮一小会关火.\n煮成糖浆.\n\n为什么要煮成糖浆用？\n因为馅料里面需要加粉.\n不管什么粉.\n它只要遇见了水就会马上吸水.\n随着时间又会脱水.\n然后就会变的干硬.影响口感.\n這是它无法改变的性质.\n\n所以我就想到了煮成糖浆用.\n不是说就一定不会让粉变硬了.\n這样只是能延缓粉类脱水的速度.\n\n起码在伱吃完之前不会硬的没法吃..", "糖浆放凉后.\n把油放入.\n然后用打蛋器一直搅拌.\n至乳化状态..\n\n如不懂乳化状态的.\n伱只需要一直搅拌一分多钟就好.\n\n道理如同上一步.\n乳化后能让液体材料更稳定.\n成品馅不容易一直泄油.\n\n這二个步骤.\n都只是个人的理解.\n琢磨出来的.\n\n如不对.别骂我...( ´▽｀)", "把干果倒入大碗中.", "倒入白酒...\n用筷子搅拌均匀.", "把白糖加入.\n白糖可以不用一次加完.\n可以后面尝一下甜度再加剩下的.\n\n因为每个人放的材料.果脯不一样.\n所以甜度都会不同.", "把乳化好的液体.\n分成四次加入果仁中.\n每一次都搅拌均匀后再加下一次.", "全部加好后...", "把烤熟的粉.\n分3-4次加入.\n每一次都用筷子搅拌均匀后再加下一次..", "加好粉后.戴上手套.\n用手揉.\n不用害怕.\n直接揉就好.\n\n粉类不一定需要全部加完的.\n当然也可以会不够.\n根据情况来就好.\n\n馅料软而能成团就可以了.", "按压成一个光滑的大炸弹.\n\n盖上保鲜膜.\n静置半小时左右...", "半小时后看看状态.\n\n能轻松捏成团.\n不会大量吐油的话..\n合格的五仁馅就搞定了.\n随时可以准备做月饼.", "现在是做月饼皮.\n\n把枧水和转化糖浆称好.\n用打蛋器搅拌均匀.\n再倒入花生油.\n用打蛋器搅打一分钟.\n呈乳化状态.\n\n我想做可可味的.\n所以把可可粉加下去了.（5克）", "加入可可粉后.\n再用打蛋器搅打均匀.\n会成浓稠的状态.\n\n如果做原味的.\n直接跳过這部分就好.\n\n皮不管做什么口味的.\n都是只需要减掉同重量的面粉替换.", "再把面粉放入..\n\n打蛋器要拿出来.\n不能用打蛋器搅拌了.\n会哭......！", "用刮板把材料大概混合均匀.", "把材料全部装入保鲜袋里.\n隔着保鲜袋按压几下.\n把材料混合均匀.\n成为一个光滑的面团.\n\n面团丢冰箱里醒二小时.\n\n做五仁馅.\n皮要软一些的.\n本来五仁月饼回油就要慢一点.\n如果皮再硬的话.\n会一直吸收馅料里面的水分.\n导致馅料更干.\n\n這种的最方便.也快.\n一点都不会弄脏手.\n就是力度要适中.\n大力了保鲜袋会破.\n如果有超市那种厚一些的食品袋.\n就是买菜或水果需要装着称重量的.\n用那个最好了.随便虐都不会破..", "把五仁馅分好.\n我是做3:7的.\n所以馅44克一个.\n\n這是做了菜谱翻倍的量.", "把醒好的月饼皮.\n分成19克一个.", "本来只打算发五仁馅的做法.\n又覚得就是做大保健也得做全套啊.\n所以下面包月饼图的步骤.\n是包各种月饼时候拍的.\n然后凑起来了...\n\n取一个饼皮面团.\n按压扁.", "放上馅.\n把饼皮往馅上推..", "一直到收口..", "收口按紧.", "全部包好的..", "预热烤箱.\n上火200度.\n下火220度.\n\n用模具压出形状.\n\n我压模是不撒粉.不抹油的.\n直接压...\n一点都不粘..\n\n会粘的可以把月饼胚.\n放粉里滚一点粉再入模.", "全部压好后..\n用小喷壶在上方喷一点水.\n让水雾自然飘落..\n\n伱可以当做是给自己喷香水.\n就是对着头顶一喷.\n自己在下面提着裙摆（肥肉）转圈那种..", "放入预热好的烤箱..\n\n小烤箱放中层.\n大烤箱放中上层.", "烤6分钟左右取出来凉一会.\n如果是原味的.\n就刷一层薄蛋液.\n\n做彩色的不用刷.\n刷了反而破坏了美感.", "再放回烤箱用上火", "烤8-10分钟左右取出.\n月饼就烤好了.\n自然放凉后再从烤盘里移动出来..", "（此处是动态小视频）\n\n這是還没回油切了一个拍的.", "一看就是良心小作坊出的.\n太多料啦..！", "（此处是动态小视频）\n\n放凉后.\n用底托.封口袋装好..\n\n這是娃在帮我装.(^_^)v\n\n建议从烤好到装的时候.\n都要戴手套.\n不要用手直接碰.\n這样能保存的时间会久一些.\n\n当然.\n伱不接受建议也是可以的..！", "（此处是动态小视频）\n\n用封口机封口.\n强烈推荐所有的月饼都要這种包装.\n封好口之后随便找箱子一装都可以.\n不需要一个个列队摆好站那.\n\n用天地盖很麻烦.\n而且也不利于保存.\n邮寄过程中還会分家.\n可能人家收到的时候.\n月饼就碎在箱子里.\n這是吃還是不吃呢？\n\n而且天地盖的非常占位置.受潮.变质..\n\n（我咋像卖封口机的）"]'::jsonb, 30, 185, '困难', 3, 'https://i2.chuimg.com/d71de2deeb93498397f66830a469cd1c_1387w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鸡蛋羹', '热门专题', '蒸蛋', '', '[{"name": "60克左右的鸡蛋", "amount": "1只"}, {"name": "一杯（实际只用一部分）45度左右的温水", "amount": "适量"}, {"name": "一个盛饭的小碗", "amount": "适量"}, {"name": "少许（视个人口味而定）盐", "amount": "适量"}, {"name": "少许葱花", "amount": "适量"}, {"name": "半茶匙生抽", "amount": "适量"}, {"name": "少许（可省略）虾皮", "amount": "适量"}]'::jsonb, '["将鸡蛋敲入小碗，现在不要打蛋。", "加入盐，倒入温水，至八分满。", "此时开打，将蛋液搅拌均匀，标准是表面出现细密的泡沫。", "水开后上锅，大火五分钟，转小火两分钟。", "打开锅盖，洒上葱花与虾皮，盖上锅盖，再小火两分钟。", "出锅，倒入生抽。享用吧！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/efcec67488d611e6a9a10242ac110002_640w_620h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('虾仁鸡蛋羹', '热门专题', '蒸蛋', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "小葱", "amount": "2根"}, {"name": "适量香油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "虾", "amount": "7只"}, {"name": "适量料酒", "amount": "适量"}]'::jsonb, '["虾去头、外皮，剥出的虾仁用开水烫一下，加盐、料酒、少许生抽腌制。", "蛋打散，加盐，加温水。我一般用汤碗打蛋，用蒸蛋的盘子量取加水量，这样不至于加得过多。", "先把加水的蛋液放火上蒸，一般8-10分钟，等蛋成型后，在上面放虾仁，再蒸2分钟，出锅加麻油、生抽、葱花，即成。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/8fa6950242d411e7947d0242ac110002_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('简单快手蒸水蛋（不会失败的水蛋比例）', '热门专题', '蒸蛋', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "半鸡蛋温水", "amount": "3个"}, {"name": "适量盐", "amount": "适量"}, {"name": "花生油", "amount": "2勺"}, {"name": "酱油", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}]'::jsonb, '["先打两颗鸡蛋在一个大碗里", "用敲完的蛋壳 拿半个蛋壳当量杯 倒入温水（温水就是常温就可以了 用1:", "5的比例 如果想要更嫩一点就大概1:", "7的比例 我打了2颗鸡蛋 就是要3颗鸡蛋 的水 可是我想再嫩一点点 就多加了半颗鸡蛋的水）", "加入一勺花生油", "再加入一点盐 不要太多 后面会调一个酱汁", "用打蛋器搅拌均匀", "打到起泡泡为止", "用筛子过滤泡泡 过滤2次直至表面没有泡泡 如果有泡泡就用勺子捞掉 一定要表面没泡泡哦", "再包上保鲜膜 用牙签戳几个洞", "放平 静止一下 等锅里的水烧开后 再放进鸡蛋 隔水蒸10分钟 就可以了", "蒸出来 小心的把保鲜膜撕开", "完成了 然后淋一勺花生油 再用一勺酱油、一勺蚝油、加一点温水搅拌好 淋到水蛋上面就可以了 简单快捷 好吃😋"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/1f24708867ad46e69a94c4c7b9198b35_1072w_857h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('零失败蒸鸡蛋羹', '热门专题', '蒸蛋', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "少量盐", "amount": "适量"}, {"name": "一勺生抽", "amount": "适量"}, {"name": "水", "amount": "130克"}]'::jsonb, '["两个鸡蛋加入少许盐。", "用筷子把鸡蛋搅匀。", "把130克水慢慢倒入鸡蛋液里，一边倒一边用筷子搅匀。", "把搅匀的蛋液用过滤筛过滤一下。", "过滤后的鸡蛋液就没有气泡了。", "把容器盖上保鲜膜，用牙签在上面戳几个眼。", "就可以盖上锅盖开始蒸了，开火蒸上15分钟，关火，再闷上2分钟。", "开盖，把保鲜膜撕开，淋上一勺生抽（蒸鱼豉油）撒一些葱花就可以了。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/385cb377ea4c4c3c928f8b7fef46fe58_896w_985h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蒸鸡蛋羹（超简单零失败）', '热门专题', '蒸蛋', '', '[{"name": "（50g一个）鸡蛋", "amount": "6个"}, {"name": "温水", "amount": "450ml"}, {"name": "适量盐", "amount": "适量"}, {"name": "香油", "amount": "1勺"}]'::jsonb, '["干净的容器打6个鸡蛋，这次买的鸡蛋很小，每个50克，加入适量的盐，盐的多少根据个人口味，", "将鸡蛋搅拌打散", "准备450ml温水，鸡蛋和水的比例是1:", "5，所有6个鸡蛋300克，放450ml温水，所有不管多少鸡蛋只要记住比例就没错啦。", "慢慢加入温水搅打均匀，搅打完毕上面有泡沫，没关系的，我们那漏网过滤一下就好了，", "拿出'蒸鸡蛋的容器，将搅打好的蛋液用漏网过滤泡沫，", "盖上锅盖，凉水上锅蒸，中火，水开后蒸8-10分钟，关火焖几分钟即可，那种有盖子的蒸蛋碗更佳，没有盖子的话，盖个盘子行，没盖子没合适的盘子也可以包耐高温的保鲜膜。", "出锅了，淋上香油就可以开吃啦！", "是不是很嫩滑，", "有没有想吃的感觉，自己动手丰衣足食，心动不如行动。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/f8a79ee0d83a42948edc4eeadabc2371_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('史上全花式寿司', '热门专题', '寿司', '', '[{"name": "泰国香米", "amount": "适量"}, {"name": "糯米", "amount": "适量"}, {"name": "寿司醋", "amount": "适量"}, {"name": "海苔", "amount": "适量"}, {"name": "各种自己喜欢的食材", "amount": "适量"}]'::jsonb, '["泰国香米加糯米以6:1的比例混合，加水（平时煮饭的量就可以）浸泡一个小时。 煮熟后倒入寿司醋（比例不好说，要边加边尝）。自然晾凉。", "黄瓜，大根，火腿肠切条。当然了你可以加些自己喜欢的食材，比如肉松什么的。", "像图中这样摆放，挤一条丘比沙拉酱，然后卷成卷儿，每卷一次都要压实。", "切段就变成这样了。", "手握寿司其实很简单，把米饭捏成饭团，放上自己喜欢的海鲜类。", "豆皮寿司要买现成的日式豆皮，里面放上米饭和鱼子之类，按自己的口味吧。", "圆形的寿司卷是先捏一个饭团，然后把海苔剪成适当的宽度，卷起来。上面放着自己喜欢的东西，推荐吞拿鱼拌沙拉酱。", "手卷寿司，把海苔剪成正方形，卷成漏斗状，用米粒粘合，里面放上米饭和自己喜欢的食材。我放的是吞拿鱼、黄瓜、火腿肠、大根、鸡蛋和沙拉酱混合的沙拉。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/789603868a6811e6a9a10242ac110002_4608w_3072h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('黄金肉松寿司', '热门专题', '寿司', '', '[{"name": "一张海苔", "amount": "适量"}, {"name": "一碗米饭", "amount": "适量"}, {"name": "半根黄瓜", "amount": "适量"}, {"name": "一个鸡蛋", "amount": "适量"}, {"name": "半根火腿肠", "amount": "适量"}, {"name": "一条黄萝卜", "amount": "适量"}, {"name": "半碗沙拉酱", "amount": "适量"}, {"name": "一碗肉松", "amount": "适量"}]'::jsonb, '["黄瓜，火腿肠切条。", "鸡蛋加盐打散煎成片装，切成条备用。", "竹帘上铺上一层保鲜膜。", "大致估算一下海苔的大小 ，在保鲜膜上铺满米饭，一定要压实，成品紧凑更好看。", "米饭上铺上海苔，放上各种材料。", "把保鲜膜的一边包在竹帘外面，慢慢紧紧的卷起米饭。", "一边卷，一边往外拉出保鲜膜，不要把保鲜膜卷进里边去。", "卷完后握紧压实一点。", "拿开竹帘，打开保鲜袋，饭卷涂上沙拉酱，多涂一些。", "找个长条盘子，铺满肉松，把刚才刷完沙拉酱的一面放在肉松上 另一面继续刷沙拉酱，多刷。", "两面都沾满肉松后，撒黑芝麻，找把快刀切开。", "完工，相信我，一口老满足了！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/5cb06daa8d844c33b321fc1e4c78330b_3000w_2000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('三文鱼反转寿司，香格里拉大厨来教你', '热门专题', '寿司', '', '[{"name": "三文鱼", "amount": "1块"}, {"name": "1碗米饭", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "海苔", "amount": "1片"}, {"name": "勺寿司醋", "amount": "适量"}, {"name": "若干鱼肉松", "amount": "适量"}, {"name": "若干海苔粉", "amount": "适量"}, {"name": "若干柴鱼片", "amount": "适量"}, {"name": "若干葱花", "amount": "适量"}]'::jsonb, '["在米饭中滴入4茶匙的寿司醋，记得醋要多一些哦~~用筷子或者硅胶勺充分搅拌后放入一边晾凉。\n\n不能用其他醋替代寿司醋，如果觉得购买的醋太酸，可以适量放一些白糖进去。", "晾凉的米饭均匀地平铺在海苔的上面，铺的时候不要压，用手抓一抓，让米饭松弛。", "将铺好饭的海苔翻个身。为啥要翻身呢？\n\n因为咱们今天做的三文鱼寿司，是日本的“反转寿司”。所谓反转寿司，就是米饭在外面，然后再在米饭铺一层食材。", "首先需要在寿司大约半指内放入一条米饭，用手轻轻地捏成一条平行的细线。why?\n\n这样是为了让寿司能够在卷的时候被黏住，不会松掉。所以这个skill一定要记住哦。", "然后平铺上一条黄瓜条和三文鱼条", "接着再放入一根胡萝卜条，将三文鱼条夹在中间", "末了，沿着胡萝卜条均匀地撒上一些鱼肉松", "裹的过程中，每转动一下，用手往里面压一下，防止太松。", "将切好的三文鱼片均匀地铺在米饭的上方", "然后用保鲜膜紧紧的包住", "隔着保鲜膜，将寿司条切成大小均匀地段", "先在盘子上方挤上一些千岛酱", "切成段的寿司去掉保鲜膜，挤一些番茄酱在上面", "然后再挤一些千岛酱,口味会更加综合一些", "均匀地撒上一些海苔粉和柴鱼片", "上后再撒上一些切碎的葱花颗粒", "更多美食菜谱，请关注微信公众号【细嚼曼宴】\n\n或者搜索微信公众号：eat-slowly"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/28f86e61b2984b618181b1154db3f306_726w_484h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('永远只想做这一款寿司', '热门专题', '寿司', '', '[{"name": "两杯寿司米（五卷的量）", "amount": "适量"}, {"name": "50mI寿司醋", "amount": "适量"}, {"name": "适量糖/蜂蜜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "5张波力寿司海苔", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "双汇无淀粉火腿肠", "amount": "2根"}, {"name": "腌萝卜", "amount": "5根"}, {"name": "海霸王蟹肉棒", "amount": "5根"}, {"name": "半根黄瓜", "amount": "适量"}, {"name": "半根红萝卜", "amount": "适量"}, {"name": "适量海苔芝麻肉松", "amount": "适量"}, {"name": "适量丘比萨拉酱", "amount": "适量"}, {"name": "2包丘比芝麻酱（独立包装）", "amount": "适量"}]'::jsonb, '["先来一张材料的合影😁", "在电饭煲中加入两的寿司米", "在洗好的米内加入几滴油（这样煮好的米饭更蓬松😁）有时间最好是能把米泡一下～", "煮好的米饭，横竖切一切～放一边凉快去😙", "给蟹肉棒来个汗蒸（10钟）♨️", "把半根红萝卜切成条状，开水煮开，泡个开水澡🛁（大约30秒）～捞起装盘备用", "打三个蛋🥚🥚🥚加一小勺盐🧂两大勺冷开水，然后在锅上刷点油预热🔥", "导入适量的蛋液，煎成蛋卷～😄一定要算好量，煎成五个蛋卷🍳", "煎成蛋卷就是方便等一下不用切～（我用的是16厘米的锅，所以长度刚刚好）", "火腿肠也放到锅里煎一煎🔥", "这时米饭也差不多变温了～开始调米饭：", "加入寿司醋（大约50ml）；", "加入一小勺盐 ；", "加入白糖或蜂蜜(😄根据个人口感加量)", "倒入碗中，继续放凉", "黄瓜洗干净去皮切条，蟹肉棒对半切", "腌萝卜，大家可以买这种200克装的，一包十条，开封后不会浪费，可以很快用完，因为开封后保质期只有三天 。                           🤗也可以选择不放～我家小朋友不是很爱吃～可能这就是大人的味道", "加了芝麻酱🤩世界都亮了～", "肉松，沙拉酱，海苔，全体到位！               🤗准备开始包了哟～", "将海苔比较粗糙的一面朝上（这样米饭粘的比较牢）我是竖着放，因为材料比较短😅", "准备一碗冷开水，将双手浸湿，这样拿米饭时手不容易沾到米饭（😖这部千万别忘了，后果很严重！）", "一勺米饭🍚     （这时候可以估一下量，平分成五份）", "用浸湿水的双手，将米饭均匀铺平，四周留一丢丢边～", "先铺一层萨拉酱", "再加两勺芝麻酱～（绝配）", "放上蛋卷，撒上肉松", "再放蟹肉棒，火腿肠，红萝卜，黄瓜", "将竹帘往上卷，两手摁紧挤压定型，先卷三份之一", "然后继续用竹帘卷起定型！一定要卷紧了，不然切寿司的时候馅会散开", "卷寿司这个步骤，大家可以上百度搜下视频（😅我也是在那学的…呵呵）", "太会算了🤣～材料用的刚刚好👍", "切寿司关键的一步！一定要有一把锋利无比的刀🔪（我家最利的就是切面包的刀😤）", "果然，切起来很有幸福感🥰", "🥳我很满意～                                                             奇怪，这卷怎么没看到红萝卜🥕…😅", "期待大家的作品哟🍱～～                             有更好的建议欢迎提出！"]'::jsonb, 30, 175, '困难', 3, 'https://i2.chuimg.com/de066491b07b41dc99538aea495c6169_1003w_802h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最正私房寿司醋配方', '热门专题', '寿司', '', '[{"name": "90毫升米醋", "amount": "适量"}, {"name": "白砂糖", "amount": "60克"}, {"name": "盐", "amount": "3克"}]'::jsonb, '["日式米醋，尽量买纯米醋。现在市面上有的日式醋是多种谷物制成，可以用，但是如果你对口感很挑剔，一定要买纯米醋。", "白砂糖60克", "把白砂糖，盐，米醋放进小奶锅中。开最小火，边加热边搅拌，搅拌至糖完全融化。也就半分钟左右的时间，不要过度加热，刚刚做好的寿司醋是只有一点温的。", "盛出，备用。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/0c1f912a23f94381877e0011c29debc9_1242w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('曼食慢语清水白粽子', '热门专题', '粽子', '', '[{"name": "糯米", "amount": "300g"}, {"name": "箬竹叶", "amount": "12片"}, {"name": "棉绳", "amount": "适量"}]'::jsonb, '["若是用干的箬竹叶，需要提前一天将竹叶用清水浸泡，隔夜后叶片回软，洗净待用", "将糯米淘洗干净，用清水浸泡2小时以上，沥干水待用", "取两片箬竹叶，将叶柄剪掉，把叶片擦干，毛面相对叠在一起，让两侧的叶柄稍微多出来一些", "在靠近叶片一侧的1/3处，卷出一个锥形角，尖角处叶片重叠，让外层叶片的叶柄在最外侧", "往角中填入糯米，快填满时将米面轻轻压平实", "将外层叶片盖下来，并反折压住下面的两个角，用下面握住锥形角的那个手的食指和拇指固定住", "将盖下的叶片从中间折起来，往一侧折过去，贴着粽子的形状自然弯折", "取一段棉绳，在粽子拦腰处绕两圈后打活结，要把刚才反折过的两个角都固定住", "把多余的粽叶剪掉，一个粽子就完成了", "把所有粽子包好后，放入一大锅冷水中，盖上一个比锅子口径略小的锅盖或是重物，再盖上锅盖", "大火煮开后转小火煮约45分钟即可"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/d646b532884411e6a9a10242ac110002_690w_458h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('咸粽', '热门专题', '粽子', '', '[{"name": "一：蛋黄排骨腊肠干贝香菇粽", "amount": "适量"}, {"name": "圆糯米", "amount": "1000克"}, {"name": "排骨", "amount": "500克"}, {"name": "适量生咸蛋黄", "amount": "适量"}, {"name": "二根腊肠", "amount": "适量"}, {"name": "适量干贝", "amount": "适量"}, {"name": "适量干香菇", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "适量白酒", "amount": "适量"}, {"name": "几片姜片", "amount": "适量"}, {"name": "二：豪华版杂豆蜜枣粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "适量各种豆类（见菜谱详解）", "amount": "适量"}, {"name": "适量干蜜枣", "amount": "适量"}, {"name": "三：豆沙桂花碱水粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "食用碱", "amount": "5克"}, {"name": "食用油", "amount": "1勺"}, {"name": "适量干桂花", "amount": "适量"}, {"name": "适量红豆沙", "amount": "适量"}, {"name": "四.血糯米梅干菜五花肉粽", "amount": "适量"}, {"name": "血糯米", "amount": "100克"}, {"name": "圆糯米", "amount": "400克"}, {"name": "梅干菜（干）", "amount": "50克"}, {"name": "带皮五花肉", "amount": "400克"}, {"name": "适量油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "少许白酒", "amount": "适量"}, {"name": "五：笋干腊鸭腿粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "笋干", "amount": "100克"}, {"name": "腊鸭腿", "amount": "1个"}, {"name": "适量油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "六：肉松咸蛋黄粽", "amount": "适量"}, {"name": "糯米", "amount": "500克"}, {"name": "适量肉松", "amount": "适量"}, {"name": "适量生咸蛋黄", "amount": "适量"}, {"name": "七：紫薯粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "三小个紫薯", "amount": "适量"}, {"name": "小半个柠檬", "amount": "适量"}, {"name": "一勺油（泡粽叶用）", "amount": "适量"}, {"name": "八：腊肉毛豆粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "一块腊肉", "amount": "适量"}, {"name": "毛豆", "amount": "100克"}, {"name": "适量油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "九：板栗蛋黄大肉粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "带皮五花肉", "amount": "400克"}, {"name": "适量生咸蛋黄", "amount": "适量"}, {"name": "适量板栗仁", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量白酒", "amount": "适量"}, {"name": "十：红烧牛腩鹌鹑蛋粽", "amount": "适量"}, {"name": "圆糯米", "amount": "500克"}, {"name": "牛腩", "amount": "250克"}, {"name": "适量鹌鹑蛋", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "一小块生姜", "amount": "适量"}, {"name": "二个八角", "amount": "适量"}, {"name": "一个桂皮", "amount": "适量"}, {"name": "二片香叶", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "二勺红酒或啤酒", "amount": "适量"}, {"name": "小半个洋葱", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "十一：糯黄小米杂豆蜜枣粽", "amount": "适量"}, {"name": "糯黄小米", "amount": "500克"}, {"name": "适量杂豆", "amount": "适量"}, {"name": "适量蜜枣", "amount": "适量"}, {"name": "其它材料：", "amount": "适量"}, {"name": "适量粽叶", "amount": "适量"}, {"name": "适量粽绳", "amount": "适量"}, {"name": "一把剪刀", "amount": "适量"}]'::jsonb, '["一：蛋黄排骨腊肠干贝香菇粽", "排骨让卖肉的师傅给剁好成小段.买的时候可以选择上面稍带一些肥肉的.当然..这样的确实不好买.我这次去买排骨包粽子.买了1百多块钱.为什么这么多？排骨买回来我会挑选.把比较好的段选出来包粽子.其它的炖汤的炖汤.做菜的做菜.伱们包的时候可以不用这么苛刻！...我是因为要包的送人.咳咳！", "排骨洗净控干水后.放入大碗里.放白糖.白胡椒粉.盐.生抽.老抽.白酒.几片姜.搅拌均匀.放入冰箱冷藏4小时以上.过夜最好！", "干香菇清洗二遍.然后水里放一些盐.和一点陈醋.用这水泡发香菇.干香菇不咸不会好吃的.用盐水泡发的.会很好吃！", "咸蛋黄撒上一些白酒备用.可以用生的咸鸭蛋敲开取蛋黄.也可以买真空包装的咸蛋黄.我这个就是真空包装的.这次买的不太好.", "糯米清洗干净.控干水分后.放盐.生抽.老抽.白胡椒粉.白酒搅拌均匀..然后把泡发好的香菇挤掉水分.用剪刀剪成小块..搅拌均匀！", "然后把腌好的排骨.切成小段的腊肠（腊肠我是用了自己做的.伱们可以用自己有的腊肠）.咸蛋黄.洗净的干贝..全部放在米上.我懒.不喜欢到处都是盆盆罐罐..反正都是要包的.全部放一起..真的方便！当然.伱也可以不放一起...", "粽叶.用干粽叶的话.就泡半天起.然后一片片清洗干净.最好戴手套.不要被划伤了手.拿个刷子.放在水池的洗衣板上.正反各刷一次就行！这时候可以顺便分大小.大片的放一边.小一些的放一边.然后清洗干净...如果赶时间的话.可以把粽叶放大锅.煮一些时间..这样泡发的更快！新鲜粽叶就是清洗干净就可以了！", "准备一把剪刀和绑粽子的线.线用伱们有的线就行...", "还有你们用来煮粽子的锅.里面放半锅水.放旁边备用.粽子包好一定要放水泡着的.所以.直接用煮粽子的锅装吧！我这个是包了一些后想起来要拍一个.就拍了..", "粽叶大头的一边.用剪刀剪掉一点梗..（临时买到了新鲜粽叶.拍图换掉了老粽叶的）", "然后在大头这一边...在半个手掌大小的地方.把粽叶往小头方向叠.形成一个斗..", "拿手里是这样的....", "然后放上一层糯米.", "把排骨.蛋黄.腊肠.干贝放入.", "再铺上一层米.", "然后把粽叶盖上..捏紧", "多出来的.折的往一边按住.", "然后用一个指头压住线..其它线裹上粽子..如果喜欢吃紧的粽子可以绑紧一些.喜欢是松的就不要绑太紧了！", "绑好打结...粽子就包好了.", "粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是熟了的粽子里面样子...！", "二：豪华版杂豆蜜枣粽", "圆糯米装大盆里.上面放上伱要放的材料：我的放了：红豆.红皮花生米.黑豆.白莲.粘玉米碴.绿豆.白芸豆.荷包豆.养心豆.熊猫豆.黄豆.鸡头米.薏米！可以想放什么放什么.", "把所有材料混合清洗干净...控干水分.", "放上干蜜枣..每一个粽子放一个的.也可以放旁边.我图方便.直接丢米上了.", "鸡头米提前浸泡三小时.", "包法和第一个粽子一样的.放料是先放一层糯米.再放一个蜜枣.", "包起来就行.粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是熟的图...", "三.豆沙桂花碱水粽", "圆糯米清洗干净控干水.然后把食用碱放入.搅拌均匀.米会变黄色.盖上盖子放置20分钟.期间可以搅拌1-2次..", "把豆沙分好需要的大小.豆沙可以自己做.不愿意做的.不放豆沙也行..", "然后把洗好的干桂花放入.再放一勺食用油！搅拌均匀..", "包这个粽子.粽叶水里放一点食用油.这样熟了后.不会粘着粽叶剥不下来..", "放料的顺序是.先放一点米..", "然后豆沙要挨着粽叶放 .不能放中间.放中间会导致四边的糯米煮不熟.实在没把握的.直接不放豆沙.吃的时候撒白糖..也超级好吃的！", "然后放上糯米..包起来！这个粽子和其它粽子不一样.碱会帮助粽子易熟烂.所以煮这个粽子时候.粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压40-60分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是煮好了的..", "四：血糯米梅干菜五花肉粽", "血糯米.浸泡二小时.再把梅干菜（忘记拍了）.清洗干净.然后装水泡发..泡发后的水不用倒掉", "带皮五花肉.切块.放白糖.白胡椒粉.生抽.老抽.盐.白酒.腌制二小时或冷藏过夜.", "锅里倒一点油.把五花肉放下去二面煎黄..（大晚上拍的.很难看.实物不是这样的）..真的..！", "把泡发好的梅干菜挤掉水分放入炒出香味..把腌肉的汁倒入.再把泡发梅干菜的水倒入一点.大火烧开", "转中火收干汤汁即可..", "把血糯米和圆糯米混合均匀.清洗干净.控干水.怕淡的可以在米里面加点盐搅拌均匀..", "包法和上面一样.放料的程序是一层糯米.再放一点梅干菜.再放一块五花肉.再放一点梅干菜..", "然后盖上一层糯米.包起来就行.粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是熟了的图...", "五：笋干腊鸭腿粽", "笋干泡发后.放入锅中.大火煮开.煮5分钟后捞出.用剪刀剪成小块！", "锅里放油.然后把笋干放下去爆香.", "放一点白糖.生抽.老抽.盐..炒出香味后.倒一点开水下去.大火烧开后转中火收汁..", "把洗净泡了半小时的腊鸭腿剁小块..", "笋干收干汁后.把腊鸭腿放一起.开始包吧！", "糯米洗净.控干水.放一点生抽.老抽.盐调味.放料是一层糯米.再放笋干.一块腊鸭腿.一点笋干.", "再盖上一层糯米..包起来就行.粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是煮熟了的...", "六：肉松咸蛋黄粽", "糯米清洗干净控干水", "肉松可以用自己做的.生的咸蛋黄用一点白酒去去腥..", "先放一层糯米.再放肉松.再放咸蛋黄再放一层肉松..", "然后再盖一层糯米..包起来就行.粽子全部包好后.放入高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "这是熟了后的...", "七：紫薯粽", "糯米清洗干净.控干水分.再准备一碗柠檬水.就是拿个碗装水.里面挤上一些柠檬汁.然后把紫薯去皮.", "切丁后.放入柠檬水里面泡一会儿.防止变色！", "然后把紫薯丁捞出来和糯米搅拌均匀.", "包法都一样.这个直接装料..包起来就行.粽子全部包好后.高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "熟后的图片..", "八：腊肉毛豆粽", "糯米洗净控干水分.毛豆洗净.腊肉用水泡半小时后切丁...", "锅里倒一点底油.把腊肉丁放下去炒至变透明后装出放入糯米碗里.（油留锅里）", "把毛豆放入锅中翻炒.加入白糖.生抽.白胡椒粉.一点料酒.盐！炒至水分收干.", "把毛豆倒入糯米碗里.和其它材料混合均匀..", "包法都一样.这个直接装料..包起来就行.粽子全部包好后.高压锅中.水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "熟后的图片..", "九：板栗蛋黄大肉粽", "五花肉洗净带皮切块..放白糖.白酒.生抽.老抽.白胡椒粉拌匀腌制二小时以上.最好是冰箱冷藏过夜！", "生咸鸭蛋黄撒一些白酒.备用..我这个是自己敲蛋取的蛋黄！也可以买真空包装的蛋黄！", "板栗去皮.我这现在买不到了新鲜板栗.我这个是超市买的速冻板栗仁..！", "糯米洗净控干水分.里面加一点盐.生抽.老抽.搅拌均匀..", "包法都一样.放料是先铺一层糯米.再放蛋黄.肉.板栗...", "然后再盖一层糯米..包起来就行.粽子全部包好后.高压锅中水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "熟后的图片..", "十：红烧牛腩鹌鹑蛋粽", "鹌鹑蛋煮熟.去壳.快速剥壳的方法是把鹌鹑蛋放保险盒里面.保鲜盒里面放一些水.盖上盖子.晃动保险盒.鹌鹑蛋就非常好剥..", "牛腩切块.牛腩买的时候买带一点肥的比较好吃..然后放冷水锅里.开火.煮沸后再煮三分钟...捞出洗净备用..", "姜切片.香叶.桂皮.八角洗一下备用（个人习惯）", "锅里放油.放一点冰糖下去.小火加热至冰糖融化变色冒小泡泡时.把牛腩放入！", "炒上色后.把姜片和大料放入翻炒出香味..", "然后放一点白糖.白胡椒粉.生抽.二勺葡萄酒或啤酒下去.我用的是自己做的葡萄酒..炒出香味后.加1小碗开水下去！", "放入鹌鹑蛋..中小火炖.", "几分钟后.把切好的洋葱放入..", "炖至还有一点点汤汁的时候放盐.翻炒均匀后关火.", "把锅里的牛腩.鹌鹑蛋.洋葱取出.大料和姜片不要..然后把剩余的一点汤汁倒入洗净控干水分的糯米里面！不用留太多汤汁.一点儿就可以！", "包法都一样.放料是先铺一层糯米.再放鹌鹑蛋和牛腩..", "然后再盖一层糯米..包起来就行.粽子全部包好后.高压锅中水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "熟后的图...", "十一：糯黄小米杂豆蜜枣粽", "糯黄小米不是普通的小米.是糯小米..（这个菜谱我之前单独发过.这次刚好也做了.就放一起吧）", "放入伱想放的豆类和材料都行...", "清洗干净混合均匀...", "蜜枣选这样的干蜜枣...", "先放一层米.再放一个蜜枣..", "然后再盖一层糯米..包起来就行.粽子全部包好后.高压锅中水要盖过粽子.！大火烧开.唧唧叫之后改中小火压60-90分钟.根据大小.感觉快压好时候.可以关火.取一个出来打开尝一下.看看熟没熟.还要压的话.可以把底下的粽子和上面粽子翻动一下换个位置继续压...！", "煮好的图片..", "这是煮好的一锅粽子..", "伱喜欢吃什么味道的？？"]'::jsonb, 30, 545, '困难', 3, 'https://i2.chuimg.com/f672d1048af811e6b87c0242ac110003_1616w_1081h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('四角长粽子的包法（有视频）', '热门专题', '粽子', '', '[{"name": "适量粽子材料", "amount": "适量"}, {"name": "适量粽叶", "amount": "适量"}]'::jsonb, '["粽叶小的话.\n可以用二片.上下错开一点.\n这样宽度就会大一些.\n\n我那段时间疯狂的在包粽子.\n所以留了长指甲.\n不然清洗粽叶分开的时候没指甲不好分.\n還容易伤到手指..！\n\n没指甲的要注意一下哈.\n慢慢来.别伤着手了！", "包的时候.\n整个手都要捏紧.\n不要这捏住了那儿又松了.\n\n实在不行.\n就想象着抓的是老公的私房钱吧！(^_^)v", "每个角都对齐..\n这样包出来的粽子就很好看.\n有棱有角.", "绑线的时候要绑紧.\n这样煮出来的粽子不会散开.\n口感也好很多.\n\n我就不喜欢吃那种打开就一滩烂粥一样的粽子.", "绑好剪断线头..\n粽子就包好啦.啦.啦....！\n\n这粽子放下去绑的时候.\n怎么突然感觉像一个侏儒了！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6133e8183e2011e7bc9d0242ac110002_1616w_1081h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到飞起的肉粽子', '热门专题', '粽子', '', '[{"name": "圆糯米", "amount": "4斤"}, {"name": "五花肉", "amount": "800克"}, {"name": "咸蛋黄", "amount": "20克"}, {"name": "老抽", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "蚝油", "amount": "适量"}, {"name": "糖", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "生姜", "amount": "适量"}, {"name": "香葱", "amount": "适量"}]'::jsonb, '["四斤圆糯米泡到能用手碾碎，大概泡5小时左右，天气热记得中途换水", "五花肉800克切块，咸蛋黄20多个，蛋黄我都对半切开了，放一个蛋黄有点大", "五花肉放两勺老抽、两勺生抽、一勺耗油、小半勺糖、适量盐、香葱和姜丝抓匀", "抓匀后放袋子里密封，然后放冰箱冷藏腌制8小时以上入味", "泡好的大米放一勺生抽、两勺老抽、半勺糖、一丢丢盐", "拌匀后放冰箱放置5小时左右入味", "先把粽叶根部平行剪掉一块，然后取两片粽叶错开放一起，从大概三分之一的位置开始折，从剪掉的那端往另一端折成漏斗状，记得折的时候留一块，这样不会漏", "折成一个漏斗的样子", "先放一层糯米，再放咸蛋黄和五花肉，最后再填满糯米", "糯米不要太满，留一点空间，把另一端的粽叶盖过来按紧", "盖住后按紧粽叶的两边，把收尾处对折过来", "棉线缠紧就可以了", "我大概包了三十多个", "水没过粽子，高压锅上气后开始计时，压45分钟，关火后等排完气就可以了，吃不完的可以冷冻起来，吃的时候蒸就可以了", "真的是好吃到飞起~"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/c9a3c77244f311e7bc9d0242ac110002_2400w_1350h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉粽子（附包棕子视频）', '热门专题', '粽子', '', '[{"name": "（1500克）糯米", "amount": "3斤"}, {"name": "（150克）红豆（可用黄豆代替）", "amount": "3两"}, {"name": "（100克）花生", "amount": "2两"}, {"name": "（1000克）三层五花肉", "amount": "2斤"}, {"name": "腌渍五花肉材料：", "amount": "适量"}, {"name": "（45克）姜", "amount": "1块"}, {"name": "5瓣蒜头", "amount": "适量"}, {"name": "2小匙（3克）花椒", "amount": "适量"}, {"name": "3小匙（15克）盐", "amount": "适量"}, {"name": "2小匙（4克）胡椒粉", "amount": "适量"}, {"name": "2小匙（4克）鸡粉", "amount": "适量"}, {"name": "（60克）生抽", "amount": "5汤匙"}, {"name": "（26克）蚝油", "amount": "2汤匙"}, {"name": "拌糯米红豆花生材料：", "amount": "适量"}, {"name": "（12克）香油（芝麻油）", "amount": "1汤匙"}, {"name": "2小匙（4克）胡椒粉", "amount": "适量"}, {"name": "3小匙（6克）鸡粉", "amount": "适量"}, {"name": "4小匙（20克）盐", "amount": "适量"}, {"name": "（75克）食用油", "amount": "5汤匙"}, {"name": "适量（建议泡多点）另外：棕叶", "amount": "适量"}, {"name": "适量细绳", "amount": "适量"}, {"name": "剪刀", "amount": "1把"}]'::jsonb, '["买粽叶，买棉绳子，买三层五花肉。\n\n大盆里泡好粽叶，粽叶至于泡24小时以上。\n\n粽叶泡多点剩下来的可以做粽叶糯米蒸排骨，粽叶蒸鸡，蒸红糖年糕垫底，蒸包子垫底什么的，泡少了只能停工，肉再放回冰箱等粽叶重新泡发好再包完。\n\n泡好的棕叶怕坏掉可以重新晾晒保存，也可以冷藏3~4天保存。", "准备腌渍猪肉。猪肉切这样的厚片（看图片）。\n\n至少提前10小时腌渍猪肉，用3层五花肉最好。我一般是腌渍过夜，有一次临时有事，腌渍超过48小时也非常香。\n\n我买的五花肉不够，用了一部分前腿肉。切厚片大块。", "切好的猪肉倒进准备好的姜丝和蒜蓉。", "加入2小匙的花椒粒。用花椒粉的话1小匙就够了。", "猪肉倒入准备好的全部料汁（盐3小匙，胡椒粉2小匙，鸡粉2小匙，生抽5汤匙，蚝油2汤匙）。", "用手把猪肉抓揉均匀，坚持抓揉按摩2分钟，猪肉有没有腌渍入味对成品口感影响很大的。\n\n泡了粽叶，肉也腌上了，记得准备好棉绳子，洗干净晾干。", "至少提前10个小时浸泡红豆，用黄豆也非常香，平时我做黄豆的，这次黄豆刚好用完了。", "晚上睡前记得把冰箱冷藏腌渍的猪肉翻面腌渍，让味道更均匀。", "包粽子前", "5小时泡糯米。听人说做粽子长糯米较Q弹，但我那种糯米便宜就买哪种，觉得长糯米跟圆糯米基本没差别。\n\n糯米泡", "5小时就够了，煮粽子时间长，糯米泡太久太绵烂不香了。", "泡糯米时顺便把干花生也泡上。花生也是泡", "5小时就可以了。", "泡好的粽叶边冲水边用干净毛巾擦擦就行了。\n\n粽叶本身有点灰尘加上制作过程可能有添加其他成份，泡24小时后冲洗干净必须的，但是粽叶要煮的，，煮粽子时间也很长，杀菌消毒是不用置疑的。所以洗粽叶时间紧的话边冲水边用干净毛巾擦擦就行了。", "把硬硬的梗头齐根切掉。", "放进大锅里煮，冷水入锅，水没过棕叶，开大火煮开，水滚开后转中火再煮5分钟。记得中间用筷子或木锄翻面煮粽叶哦。\n\n煮好关火，锅里放凉些，再冲一遍自来水粽叶就处理好了。", "趁煮粽叶的时间，把拌糯米和红豆花生的材料分为调味品类一个小碟子，油类一个小碟子装好。（下面是2个小碟子的材料）", "调味品类：2小匙胡椒粉，3小匙鸡粉，4小匙盐混合均匀；", "油类：1汤匙香油（芝麻油），5汤匙食用油。", "泡好的米沥干水。\n\n泡好的红豆（黄豆），花生沥干水。", "把沥干水的糯米，红豆（黄豆），花生混合拌在一起。", "把调味品类的小碟子材料分几次，分散倒进糯米红豆花生中，拌均匀。", "再倒进食用油碟子中所有材料。", "再次把所有材料拌均匀。静置15分钟以上，让所有材料腌渍一会儿更好地入味。", "把猪肉里的姜丝，花椒粒夹出来。", "煮好的粽叶放水里泡着，可以先拿出一部分沥干水，免得滴得满地水。\n\n按自己方便的方法摆好所有用品。我是包好放压力锅煮粽子，包好直接放压力锅里。", "我包的粽子巨丑，但想着分享为主，可以看看。最好的办法是大家搜其他包粽子视频看，用我的馅料配方，那真是完美！\n\n欢迎姐妹们用美美的粽子狂砸我，刷爆我的方子，让我的丑粽子更加显眼😂。\n\n粽叶的光亮面，一张根部另一张尾部交叠一部分叠在一起，使粽叶变宽。\n\n头部向粽叶的3分之1的地方折起来，做成漏斗放材料。折叠口交接的地方要留少部分边沿做靠边，靠边留得好漏斗很密实不漏米。（看视频）", "看上一个视频，大家注意看这张图画红线的边沿，这个边沿就是要留出来的漏斗靠边。（再认真步骤22）\n\n要注意哦，从最根部到漏斗上方都要留出靠边哦。", "往漏斗里加一层糯米放一层肉，最上层放糯米盖上。\n\n新手的话糯米放少些，比较容易包好不漏米。\n\n肉的话开层放一块肉，做到一半的时候看肉还有好多，就可以放二块了。这跟肉块切的大小也有关系。\n\n这种粽子就算没放肉也很好吃的😍。", "准备包粽子了。觉得2张粽叶短了点，那就加多一张大粽叶到后面。把漏斗周围的粽叶全部压到里面，把靠后面的粽叶完全包裏住漏斗，压紧。（看视频）", "左手按紧棕叶，右手拿棉线，按粽叶的左手同样按紧棉线的一头，右手开始给粽子缠上棉线，棉线要缠紧些，你认为需要缠棉线的地方都可以缠上😂。（我这样教人裏粽子也是没谁了😂）", "我缠好线的粽子是这样的😂。", "还有是这样的😂（丑到我自己都没眼看😂）。\n\n可我靠这样的丑粽子，还是征服了亲友的胃😄。\n\n包好的粽子直接放进锅里。", "压力锅里加入没过粽子的水，放2小匙盐一起煮粽子。这样煮出的粽子咸度刚好。\n\n用其他锅煮粽子，水也必须没过粽子哦。", "大火上气，转中火煮20分钟，再转中小火煮60分钟。关火。至少焖15分钟再开盖取出来吃。\n\n要焖15分钟再开盖主要原因保证上层粽子就算泡水少也能软熟。\n\n用普通锅煮粽子，大火上气转中火煮", "5小时，中间隔半个小时加一次热水。蒸好焖30分钟才吃。", "打开棕叶，软糯香，至少连吃3个才过瘾😊。减肥啥的，闻到煮粽子的香味就忘记了😂。", "夹开粽子，啧啧啧，那肉太香了！红豆花生太香了！粽子季到了！终于可以好好过粽子瘾了😍！\n\n一次做多点，放冰箱冷冻室，吃时微波炉加热6分钟。冷藏的话加热4分钟就可以了。锅里蒸热当然很好啦。", "方主现在包的粽子漂亮多了。😄", "这种长四角粽也很好包，包大粽子就用这个长四角粽了。\n        有空了拍视频给姐妹们看看我包粽子手法对不对。"]'::jsonb, 30, 200, '困难', 3, 'https://i2.chuimg.com/29bf3e3bcc9648a5bfeff310e9e05cc7_1215w_1620h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蛋羹', '热门专题', '鸡蛋羹', '', '[{"name": "或多只鸡蛋", "amount": "2只"}, {"name": "或更多生抽", "amount": "2克"}, {"name": "几滴香油", "amount": "适量"}, {"name": "半根切末香葱", "amount": "适量"}, {"name": "两只蛋蒸8分钟否则需要增减所用时间", "amount": "适量"}, {"name": "购自宜家主图所用容器", "amount": "适量"}, {"name": "不用，用生抽调味盐", "amount": "适量"}]'::jsonb, '["首先，在锅内放适量水，烧水准备蒸蛋。水量不要太少。易错指数半星🌥\n\n\n\n（嘱咐的话：\n如果你的蛋液还没有准备好，水开了，先把火关上，一会儿再开火\n😅😅😅写到这里，动妈觉得自己真是一个妈妈啊，碎碎念念\n这个图是新加的，供大家参考。）", "-----  2、打蛋。易错指数🌥半星\n\n鸡蛋最好提前一晚从冰箱拿出来，因为温度问题。\n把鸡蛋打入一个小一点儿的容器里。\n\n\n（嘱咐的话：---------\n👇下面有提示：\n如果忘记提前把蛋拿出来了，就：\n1、洗一下鸡蛋外壳，在普通水里泡一下生鸡蛋。\n2、把鸡蛋打出来以后，让它在容器里稍微多呆一会儿，和外界交换一下温度。但是不如“提前拿出来”好。\n👆这些提示有人没有看到😅。）", "-----  3、准备水。👈这步容易错。\n易错指数⭐️⭐️\n\n取和鸡蛋液同量的温水（就是1:1的意思）。碗中的水以可以很舒服地喝下为准，不能烫、也不能凉。\n温水！温水！温水！\n\n\n\n（嘱咐的话：---------\n动妈一般是开水加普通水调成的温水。\n有一位厨友，草草Carol，在这个菜谱后写了特别长的留言说她看电视里做试验：桶装水蒸蛋不成功的问题。😘💕💞\n但是因为桶装水品种很多，也许有的可以成功，有的不能成功，但这一点供大家参考。\n\n另外，蛋水比例不是绝对的，建议大家先按菜谱做一次1:1的。\n动妈自己都用1:1的，我一般是早上给孩子做蛋羹吃。如果1:2多加水，孩子的肚子有限他就吃不下太多别的食物了😋😋😋）", "------  4、混合蛋液和水。易错指数⭐️\n\n蛋液和水倒入一个稍大的容器，一定要搅拌均匀！\n\n\n（嘱咐的话：---------\n如果不喜欢蛋羹底部有气泡：一定注意两点\n1、务必搅拌均匀；从搅拌好到放入锅内时间不能间隔太长。\n2、不要放盐，最后用生抽调味。\n\n如果你不知道搅拌均匀的标准，那就用力、用筷子一个方向搅动蛋液100次，一定均匀了。\n如果你大力打蛋100圈，后面过筛去除气泡时候，动作慢一点。\n\n慎选乐扣长方形饭盒，中间容易不熟。）", "------  5、最重要一步：过筛去泡（易错指数⭐️）\n\n过筛的目的是去除鸡蛋的膜筋和搅拌时产生的气泡。\n\n\n（嘱咐的话：---------\n碗里如果有气泡，用筷子、或者一片厨房纸的尖儿，把它们务必清除。每一遍筛完都洗净筛子和碗\n\n筛子可以是面粉筛、豆浆机筛子，或者淘宝搜20目面粉筛。\n1、即便追求绝对的细腻，过筛三遍也就可以了。\n2、过筛后从表面到底部口感一致，都非常细腻。\n3、其他步骤也必须做到才会细腻，这只是一步。）", "------  6、加辅助工具。易错指数🌥半星\n\n给装蛋液的碗蒙上保鲜膜，或者盖上盖子、或者盖上小碟子做盖子，或者加锡纸，不易造型的锡纸容易被蒸汽吹起来，注意要压个碟子。\n\n\n\n（嘱咐的话：---------仔细读下面的话，如果再问这个问题只能说明你没有认真读菜谱\n👇👇👇\n\n注意选标明“耐热”保鲜膜，以及正规产品。蒸汽的热量不足以让合格保鲜膜发生变化。推荐佳能牌。\n\n不合格产品不加热，放冰箱里用也会对人体有害。\n\n另外，下厨房有不需要盖保鲜膜的蒸蛋菜谱，不喜欢这一步可以换一个菜谱。👈看见这里的字了吗？谢谢，关于保鲜膜没有新的更新了😘）", "-----  7、蒸8分钟。（易错指数⭐️⭐️⭐️）\n这个数值你要自己留意,再根据成品情况结合你所用器皿，增加或者缩短。\n\n水开之后，水烧开再放入蛋液碗。把蛋液碗放入已经放了小蒸屉或小支架的锅里。中火，8分钟。（不是中小火、是中火）\n一定要定时啊！特别是新手，不要估计时间。\n\n\n\n（嘱咐的话：---------\n第一次做，建议蒸2只鸡蛋，尽量不用特别的器皿。而且先对自己的灶具、容器等考虑一下。\n\n大部分人蒸8分钟都没有问题，可能因为诸如：\n1、不同炉具、锅内放入了不同量的水，导致“大火蒸”出的蒸汽量还是有差别；\n2、蒸蛋羹器皿差别... ...\n\n会影响所需时间，需要你机智对待。\n不熟、可以挽救、接着蒸，\n不要火太大又时间长会蒸出蜂窝状😱）", "------  8、时间到！\n\n8分钟到，不要着急开锅盖！烫! 稍微等气小点儿再开。", "9---光滑细腻的蛋羹😄！\n\n上传作品、给自己点赞吧👍这碗蛋羹好极了👏👏", "------  10、加自己喜欢的佐料。\n\n🍀注意：蛋羹太嫩，倒生抽的时候，下落的生抽有可能会把蛋羹表面撞破。可以在倒酱油时先倒在勺子上接一下。）", "这是动妈的儿子动宝，下厨房🆔：我是洋葱头\n\n他自己按照动妈的蛋羹菜谱做的，他想帮动妈验证一下，菜谱有没有问题。当时他不到14岁。\n\n这个碗壁很厚、他蒸了5个大个鸡蛋，先蒸了8分钟，发现完全没有熟。又加了5分钟。供参考。", "...."]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/604f3f408b2111e6a9a10242ac110002_1080w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鸡蛋羹、炖蛋', '热门专题', '鸡蛋羹', '', '[{"name": "鸡蛋", "amount": "2个"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量麻油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "鸡蛋的1.5倍水", "amount": "适量"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["鸡蛋打散，加温开水搅打，加入食盐", "过滤浮沫，我过滤了2次，过滤的东西丢掉", "过滤后的，静置消沫", "盖上保鲜膜，锅开上蒸锅", "中火10分钟，关火焖2分钟", "撒葱花，泼生抽麻油", "滑嫩吧，开吃"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/0c6628d558b64ac1a9755a73475e59b5_1242w_1656h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超快零失败的蒸鸡蛋羹', '热门专题', '鸡蛋羹', '', '[{"name": "两个鸡蛋", "amount": "适量"}, {"name": "小半碗温水", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一勺醋", "amount": "适量"}, {"name": "小半勺香油", "amount": "适量"}]'::jsonb, '["准备工作：两个鸡蛋，保鲜膜。将鸡蛋加上少许盐，搅拌均匀。", "倒入1倍或者", "5倍的水，搅拌均匀，然后用小勺把沫和泡撇开。用保鲜膜保住，然后扎几个孔孔。（温开水和凉水都行）", "锅中水开，上锅蒸，大火蒸十一二分钟，取出。放点醋和香油。超香。（如果你蒸的少或者蒸的量大，时间就增减一下）", "有的菜谱是倒入水，再搅拌。其实效果一样，我都做过了。最重要的是充分搅拌均匀，把沫撇去。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/0b518d595ef54d65990f3ab1603450ce_640w_512h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('简单又好吃的蒸蛋', '热门专题', '鸡蛋羹', '', '[{"name": "鸡蛋", "amount": "4个"}, {"name": "味极鲜", "amount": "2小勺"}, {"name": "食用油", "amount": "1小勺"}, {"name": "适量葱花", "amount": "适量"}, {"name": "蒸鱼豉油", "amount": "1小勺"}, {"name": "橄榄油或芝麻油", "amount": "1小勺"}]'::jsonb, '["一个干净的空盘子、倒2小勺味极鲜", "1小勺食用油", "葱花（喜欢吃的可以多放、不喜欢也可以不放）一起搅拌均匀", "放入四个鸡蛋、放进盘子之后不要动", "蒸锅水开后放入锅内、开大火蒸8分钟、关火再焖2分钟（蒸蛋的盘子上面要盖上盘子或保鲜膜）避免进水蒸气", "淋上一小勺蒸鱼豉油、一小勺橄榄油或者芝麻油都可以（口味重的可以再多放点料）", "俩宝把四个鸡蛋都吃了😄", "蒸好后里面是这样的、宝宝吃正好、如果喜欢吃溏心的就蒸的时间短一点."]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/ac7bd55b35eb4111beabdeda4c5fc599_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('很嫩很细很滑的鸡蛋羹', '热门专题', '鸡蛋羹', '', '[{"name": "一个鸡蛋", "amount": "适量"}, {"name": "七十五克温水", "amount": "适量"}, {"name": "半勺蒸鱼豉油", "amount": "适量"}, {"name": "两滴香油", "amount": "适量"}, {"name": "一点点盐", "amount": "适量"}, {"name": "适量小葱", "amount": "适量"}]'::jsonb, '["一颗鸡蛋加一点点盐打散", "温水加进去轻轻拌匀", "过滤到一个小碗里，这个步骤很重要，不可省略。", "水开上锅，盖上盘子，蒸八分钟，焖三分钟", "出锅，表面很平滑呢", "倒蒸鱼豉油，香油调味", "用刀划十字切成小块，让调味料顺着切口渗下去方便入味，撒点小葱装饰"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/d55359ec366e4cba84dcbdc123d46fb5_720w_576h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('快手早餐土豆丝鸡蛋饼', '热门专题', '早餐', '', '[{"name": "土豆", "amount": "1个"}, {"name": "（伴面糊里）     土豆丝里煎的另算鸡蛋", "amount": "1个"}, {"name": "适量食用油", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "面粉", "amount": "20g"}, {"name": "葱花", "amount": "2根"}, {"name": "少许胡椒粉", "amount": "适量"}]'::jsonb, '["中个头土豆去皮，擦丝/切细丝，加适量盐🧂胡椒粉面粉鸡蛋🥚小葱", "搅拌均匀", "电饼铛/平底锅刷油，舀一勺入锅用筷子🥢弄一个鸡蛋大小的洞", "做了几个鹌鹑蛋的", "煎至底部微黄", "翻面煎，蛋黄怕没熟透就用牙签扎几下", "早餐吃饱饱啦！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/8e0025cbdb274a82939e94f579e527ef_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小学生的爱心早餐', '热门专题', '早餐', '', '[{"name": "适量主食，肉类，鸡蛋，水果", "amount": "适量"}]'::jsonb, '["紫菜蛋花汤，煎馒头片，煎三文鱼，水煮西蓝花", "三明治（两片面包，煎鸡蛋的时候放一点芝士，火腿片，生菜，挤一点沙拉酱，搞定），牛奶，麦片，🥝🥝🥝", "今天的早餐比较快手，猪排（山姆买的炸猪排，空气炸锅加热，然后挤一点番茄酱），玉米饼（盒马买的，平底锅煎熟），番茄鸡蛋汤，🥝🥝🥝", "汤面片（前一晚炖的骨头汤，留了一碗，早上起来把汤煮开，放了一点平菇，生菜，火腿片，冰箱里面有啥菜随意发挥，饺子皮一切四，放进去煮熟），一碗有肉，有菜，有碳水的早餐就搞定啦，今天早上继续吃🥝🥝🥝", "南瓜米糊（加了一个芝麻丸），巧克力馒头（中间夹了巧克力酱），芝士厚蛋烧，凉拌黄瓜，🍑🍑🍑", "小面，煎鸡蛋，煎三文鱼，海棠果", "红糖糍粑（盒马买的，空气炸锅加热，撒上黄豆面），南瓜小米粥，煎三文鱼，海棠果+🥝🥝🥝", "煎饺子，水煮西蓝花，小米山药粥，卤鹌鹑蛋（山姆买的，自己用竹签串了一下），海棠果+🥝🥝🥝", "鸡汤（前一晚炖的鸡汤，早上起来煮开加一点生菜，胡萝卜，打一个鸡蛋进去），披萨（打包的达美乐披萨，早上空气炸锅加热一下），🥝🥝🥝"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/aa286882af6440a1819c7ab7df92d5a1_1280w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('彻底告别早起！这招让你每天多睡半小时，早餐却顿顿好吃又营养~', '热门专题', '早餐', '', '[{"name": "红米红米", "amount": "适量"}, {"name": "适量白米", "amount": "适量"}, {"name": "1棵生菜", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量肉松", "amount": "适量"}, {"name": "适量鸡腿扒", "amount": "适量"}, {"name": "适量沙拉酱", "amount": "适量"}]'::jsonb, '["红米和白米淘洗干净。", "放电饭煲煮熟。", "碗中打入鸡蛋，加盐打散。", "锅中热油，倒入蛋液，煎至定型后翻面。", "放凉后卷起来，切成条。", "寿司帘铺张保鲜膜，取适量米饭摊开铺平。", "放上你和家人喜欢的食材，可以参考下我的搭配：肉松、生菜条、黄瓜条、鸡腿扒和鸡蛋条。", "挤上沙拉酱，慢慢卷起来。", "一口咬下去，软糯的米粒裹着满满的馅料，丰富又扎实，真的超满足~\n\n这个周末就试一次吧！蔬菜经过冷冻再加热，口感会打折扣，介意这点的朋友记得调整下♥️可以换成胡萝卜、玉米粒等……"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/41d2cfb9a405417fa83221b72b0c2de8_1905w_2540h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('港式甜品——杨枝甘露(芒果西米露)附芒果花切法', '热门专题', '下午茶', '甜', '[{"name": "芒果果肉(推荐凯特芒、澳芒、大金煌芒)", "amount": "400g"}, {"name": "西米", "amount": "40g"}, {"name": "椰浆", "amount": "100ml"}, {"name": "炼乳", "amount": "12g"}, {"name": "牛奶", "amount": "200ml"}, {"name": "少许西柚", "amount": "适量"}]'::jsonb, '["准备材料，我用的是椰浆，不是椰奶。", "小西米一袋，用不完的密封保存。\n西米不是米，无需冲洗直接煮就好了，洗了就融化了。", "锅内倒入500g左右的水(水量不用特别精准)，大火煮沸后将称量好的40g西米倒入锅中，转小火盖锅盖煮15分钟，期间不停揭盖观察并搅动防止西米沾底。当西米基本上透明还有一点点白芯的时候(比图片上白芯还要小)关火焖15分钟。", "直至西米的白芯消失、呈现全透明的状态。", "将西米用凉水冲洗几遍后，放入盛有凉水的碗中备用。", "配制椰汁，椰浆和牛奶的比例1:2，100ml的椰浆加入200ml的牛奶，椰浆本身是不甜的，所以再加12g炼乳调味，搅拌均匀备用。", "冷水中的西米捞出沥干水分，放入椰浆中，直接吃就是市面上的椰汁西米露。", "切芒果，芒果尽量选大的，推荐凯特芒、澳芒、大金煌芒，个大甜度高。把芒果竖起来避开果核沿两侧各切一刀，切成三片。", "用刀划十字格不要切断。", "用手在芒果皮上一顶，漂亮的芒果花就翻出来了。", "另一片也同理。", "把芒果花上好看方正的芒果丁切下来备用。", "剩下的所有芒果肉(边角料)都放入料理机搅打成芒果泥。", "细腻的芒果泥完成。(芒果和牛奶不要偷懒一起用料理机打，会起很多泡泡。)", "将芒果泥倒入步骤5的椰汁西米露中搅匀，再摆上几块芒果丁。", "放上西柚果肉(我用的普通柚子也很好吃😋)有薄荷叶的可以装饰一下，杨枝甘露完成！", "都是大块芒果果肉！过瘾不过瘾！！！", "杨枝甘露杯装。芒果泥放底部，然后倒西米，最后是椰奶部分，吃之前搅拌一下。", "没有椰浆的可以，一罐椰奶+一盒牛奶🥛，味道也很好"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/85f3f078a14549b491f3b36558d4aece_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏日特饮—5款可以吸的水果冻撞奶，白凉粉的N种可能', '热门专题', '下午茶', '', '[{"name": "清水", "amount": "500克"}, {"name": "白凉粉", "amount": "25克"}, {"name": "砂糖（可以增减）", "amount": "30克"}, {"name": "几滴柠檬汁（防止氧化）", "amount": "适量"}, {"name": "👇水果", "amount": "适量"}, {"name": "取皮紫葡萄", "amount": "适量"}, {"name": "取皮青提", "amount": "适量"}, {"name": "取皮水蜜桃", "amount": "适量"}, {"name": "切块，榨汁雪梨", "amount": "适量"}, {"name": "取汁百香果", "amount": "适量"}, {"name": "没有硬性规定以上水果任选其中一种即可，也可以换成其他家里有的水果", "amount": "适量"}]'::jsonb, '["桃子，选红一点的～盐搓洗表面，削皮～500克清水，两个桃子的皮，几滴柠檬汁，煮开，捞掉皮～加入25克白凉粉，30克白砂糖搅拌均匀，分装入杯，桃子肉可以切丁加入杯中，晾凉，冷藏2小时～备用～", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "青提用淀粉水搓洗干净，我直接用格瑞美厨洗的～取皮～500克清水加青提皮加几滴柠檬汁煮开煮出颜色，捞去青提皮，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，青提果肉可以加入杯中，晾凉，冰箱冷藏2小时，", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "紫葡萄用淀粉水搓洗干净，我直接用格瑞美厨洗的～取皮～500克清水加葡萄皮加几滴柠檬汁煮开煮出颜色，捞去葡萄皮，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，葡萄果肉可以加入杯中，晾凉，冰箱冷藏2小时，", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "梨用盐搓洗干净，榨汁，过滤，果汁加水一共500克，加几滴柠檬汁煮开，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，晾凉，冰箱冷藏2小时～（没有榨汁机的直接切小块加500克清水煮开就好，也可以加几个枸杞一起煮，最后捞掉就行）～这款比较养生润肺哈哈哈哈哈哈", "冰箱凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "百香果操作略有不同～清水500克煮开，加入白凉粉25克，砂糖30克搅拌均匀，用网筛过滤加入百香果汁～分装入杯，晾凉，冰箱冷藏2小时～备用～", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "进冰箱之前～", "等待的时间，就把这些去皮的水果吃掉吧～也可以切成小丁，装在杯子里，跟液体一起去冰箱冷藏凝固～吃起来就是有果粒的了～我懒得切，你们随意", "出冰箱之后～", "来个小视频～"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/6494aa0ad26f412d86532853fbf3a4ca_480w_384h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香酥苹果派', '热门专题', '下午茶', '', '[{"name": "苹果", "amount": "1个"}, {"name": "黄油", "amount": "10克"}, {"name": "糖", "amount": "30克"}, {"name": "水淀粉", "amount": "3克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "手抓饼", "amount": "4片"}]'::jsonb, '["1⃣️苹果洗净切丁", "2⃣️锅中放黄油，小火融化", "3⃣️倒入苹果丁翻炒，再加入白糖炒软", "3⃣️倒入水芡粉，炒至浓稠", "5⃣️解冻手抓饼，一切四", "6⃣️靠一侧放入苹果丁", "7⃣️折叠并用叉子压实", "8⃣️均匀铺在烤盘上，刷蛋液撒黑芝麻。同时200度预热烤箱", "9⃣️放入预热好的烤箱中下层，15分钟即可"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/0993e8dc315f412fa299a220398a19af_2879w_2879h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('奶香玉米汁', '热门专题', '下午茶', '', '[{"name": "1、玉米粒", "amount": "150克"}, {"name": "2、大米", "amount": "20克"}, {"name": "3、小米", "amount": "10克"}, {"name": "适量4、冰糖", "amount": "适量"}, {"name": "5、水", "amount": "800ml"}, {"name": "200-250ml6、牛奶", "amount": "适量"}]'::jsonb, '["把玉米粒、大米、小米洗干净，加入冰糖、水、牛奶，按玉米汁模式。", "记得好好吃早餐！"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/66b0e8d767f84a1bb06a2c781aff2395_1242w_1122h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('奶茶店爆款黑钻烤奶好喝到没朋友', '热门专题', '下午茶', '', '[{"name": "黑钻：红糖", "amount": "40克"}, {"name": "水", "amount": "600克"}, {"name": "白凉粉", "amount": "30克"}, {"name": "焦糖奶茶：红茶", "amount": "8克"}, {"name": "糖", "amount": "50克"}, {"name": "清水", "amount": "230克"}, {"name": "牛奶", "amount": "350克"}]'::jsonb, '["红糖加清水加热至红糖溶化，", "加入白凉粉", "加热至沸腾关火，", "倒入碗中晾凉，凉了后可以放冰箱冷藏2小时更好吃", "红茶加白糖，", "小火加热至焦糖色，", "加入清水", "继续煮至沸腾关火，", "倒入牛奶", "搅拌均匀", "过滤出红茶叶即可，奶茶冷却后放入冰箱冷藏", "黑钻凝固后用刀划成小块，", "放入杯中，", "再倒入焦糖奶茶就可以喝啦～", "太好喝了", "一定要试试"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/3c95abb48a7b444ba0e28465f4beb32a_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('早餐饭团', '热门专题', '便当', '', '[{"name": "1大碗米饭", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量芝麻", "amount": "适量"}, {"name": "适量芝麻油", "amount": "适量"}, {"name": "几片胡萝卜", "amount": "适量"}, {"name": "白菜梗", "amount": "1片"}, {"name": "1-2个蛋黄", "amount": "适量"}, {"name": "几片黄瓜", "amount": "适量"}, {"name": "适量海苔碎", "amount": "适量"}]'::jsonb, '["先把米饭煮上 然后胡萝卜切片和白菜梗一起焯水煮熟剁碎 黄瓜剁碎 蒸1-2个鸡蛋 我这里是1个蛋黄 孩子不吃蛋黄 但是放在饭团里吃不出来 准备好以上的原料 米饭基本上也煮好了.", "米饭好了.", "加熟芝麻和芝麻油 芝麻油是不倒翁的 我们家一直吃这个 感觉比较好吃.", "蛋黄捏碎.", "蔬菜碎和海苔碎丢进去.", "米饭很烫 用铲子拌一拌 这一步可以直接吃了 别问我为什么 下面有答案.", "1个保鲜袋像带手套一样套在手上 抓起一把米饭.", "用两只手捏紧实.", "成品好吃又好看 但素 但素 我家两个熊孩子 居然把饭团用勺子压碎当炒饭吃了."]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/fe6ad71b77b04398b92d10fe6c8e04fb_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('高颜值的紫菜包饭', '热门专题', '便当', '', '[{"name": "米饭", "amount": "300克"}, {"name": "牛肉片", "amount": "200克"}, {"name": "菠菜", "amount": "200克"}, {"name": "一根火腿肠", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "两个鸡蛋", "amount": "适量"}, {"name": "四张包饭用大张紫菜", "amount": "适量"}, {"name": "调料#", "amount": "适量"}, {"name": "盐", "amount": "3克"}, {"name": "淀粉", "amount": "5克"}, {"name": "10毫升生抽", "amount": "适量"}, {"name": "10毫升老抽", "amount": "适量"}, {"name": "10毫升料酒", "amount": "适量"}, {"name": "5毫升芝麻油", "amount": "适量"}]'::jsonb, '["大米淘洗两遍，浸泡15分钟再接通电饭锅的电源，泡过的米焖熟后更松软。", "准备其它食材，胡萝卜切细丝，胡萝卜我喜欢生吃，如果不习惯可以平底锅少油炒至微微变软。菠菜焯水后挤干水份。", "焯烫菠菜时用过滤后的水，我平时煮饭煲汤都会用过滤后的水，这样才能全面保证食用水的安全健康。", "水煮开后放一克盐，再加几滴食用油，这样焯出来的菠菜还会保持绿色而不会变黄，菠菜下锅后再开锅煮一分钟就可以捞出来了，不要煮太长时间，捞出后马上过遍凉水然后控干水份。", "5克淀粉（差不多是一平勺）加三勺清水搅成水淀粉，倒入蛋液中，再加一克盐搅打均匀，搅好的蛋液最好再过一遍筛，这样煎好的蛋皮会更细腻。", "小火加热平底不粘锅 ，用油刷蘸油把锅里刷一遍就可以（不要倒太多油，否则蛋液很难摊开），倒入蛋液转动锅使蛋液均匀铺满锅底成圆形，表面凝固后借助硅胶铲翻面，然后关火，用余温再烘一会儿即可，出锅切成长条。", "平底锅倒少许油，放入牛肉加10毫升料酒，10毫升生抽，10毫升老抽，把牛肉炒熟出锅，不用再放盐，酱油的咸度足够了，牛肉片也可以换成牛肉馅，同样方法炒熟即可。", "焖好的米饭用饭铲打散，盛出一大碗，大概300克米饭（这是两个卷的量），加1克盐。", "再加5毫升香油搅拌均匀，（也可以加些熟白芝麻拌进去，不巧我的芝麻正好吃没了）晾至手温。米饭用芝麻油拌过后，放置时间稍长也不会变硬，因为油能锁住水份。", "菠菜焯熟挤干水份后不要再放盐，菠菜用盐拌过后易出水，影响口感。火腿也切成长条，为什么放了牛肉还要放火腿？因为我喜欢吃啊，食材部分可以按照自己口味随意搭配，喜欢吃菜还可以切些黄瓜丝放进去。所有食材准备好就可以开始卷了。", "取一片包饭用大张紫菜横放在竹帘上， 如图依次摆好胡萝卜丝、蛋皮丝、火腿丝、菠菜丝，最后在上面堆好牛肉，因为牛肉会有少量汤汁（尽量控干汤汁哈），所以不要让牛肉接触海苔，否则海苔会软掉。", "如图用竹帘提起海苔卷一圈并握紧，多出的海苔继续卷在外边。卷好后压紧握实，收口朝下放置。有人会说米饭上直接铺菜就可以啦，为什么还要那么麻烦先把菜包好？直接包当然可以，但我保证你包完的紫菜包饭没有我包的漂亮，因为这是一个有颜值的紫菜包饭。而且对于新手来说这样更好卷，包饭的时候不易散开。", "再取一张紫菜，取一半拌好的米饭均匀的铺好压实，拌过芝麻油的米饭不粘手，比较好操作，如图上边留出大概3厘米的位置不铺米饭，这样正好卷一圈，米饭部分连接到一起不会重叠。把刚才卷好的菜卷放在铺好的米饭上面，提起竹帘卷起。", "卷好后收紧竹帘，滚动几下压实整形成圆柱体。", "用手蘸少许芝麻油抹在紫菜包饭上，这样紫菜会保持一段时间不变干。", "最好备一块干净的湿布，每切一下就把刀擦干净，这样可以保持切面的平整（用锯齿刀切效果更好）。", "切面漂亮吧", "开始享用吧，每吃一口都心满意足😉"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/4e1e654a82f04044ab9c1aed4cd79341_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('外卖第一名，简单在家做|黄焖鸡米饭', '热门专题', '便当', '', '[{"name": "鸡腿", "amount": "2只"}, {"name": "10朵干香菇", "amount": "适量"}, {"name": "青椒", "amount": "2个"}, {"name": "土豆", "amount": "2个"}, {"name": "料酒", "amount": "2勺"}, {"name": "一小把冰糖", "amount": "适量"}, {"name": "蚝油", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "老抽", "amount": "2勺"}, {"name": "鸡精", "amount": "1.5勺"}, {"name": "香叶", "amount": "1片"}, {"name": "白胡椒粉", "amount": "1勺"}, {"name": "糖", "amount": "1勺"}, {"name": "五香粉", "amount": "0.5勺"}, {"name": "姜粉", "amount": "1勺"}, {"name": "姜", "amount": "3片"}, {"name": "看是否吃辣干辣椒/剁椒", "amount": "适量"}, {"name": "4瓣蒜", "amount": "适量"}]'::jsonb, '["干香菇温水泡发。（最好先洗几次，因为后面泡香菇的的水要用到。）", "鸡腿剁大块冲洗干净泡冷水1小时。", "泡出血水的鸡腿加入图上所有配料，生抽，老抽，料酒，白胡椒粉，姜粉，蚝油，五香粉腌制30分钟。", "腌制好的鸡腿肉上色均匀。", "所有食材站好合影～", "土豆切滚刀块冲水去掉淀粉，青椒切块备用，干香菇对半切开。喜欢吃辣可以准备一勺剁椒或者干辣椒。蒜拍扁。", "锅中倒油烧热。", "倒入土豆翻炒，炒一下可以让土豆更香，微微变色就可以取出备用。", "锅中底油加入冰糖。一定要小火！", "炒糖色不要超过否则会苦，锅中冒大泡迅速倒入鸡肉。", "大火翻炒均匀上色。", "倒入姜蒜辣椒和香叶翻炒。", "炒出香味后烹入料酒去腥。", "倒入蚝油。", "加入生抽。", "加入白胡椒粉。", "加入老抽上色。", "按照个人口味加入糖。", "翻炒均匀后加入干香菇。", "倒入泡香菇的水，一定没过鸡肉。没有就倒开水。一次加足，有汤汁更好吃。", "大火烧开撇去浮末，改为小火炖煮40分钟。", "40分钟后加入土豆再煮25分钟。", "中间换了个珐琅锅更好的收汁，不换也可以，不过珐琅锅炖煮出来的更香。", "加入鸡精提鲜。", "加入青椒，煮三分钟即可，时间长青椒会变色就不好看了。", "直接端锅上桌啦～"]'::jsonb, 30, 130, '困难', 3, 'https://i2.chuimg.com/8d8cb9252b8246878d12d8a03a18280c_1051w_1051h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('工作餐便当小集锦No.6⃣', '热门专题', '便当', '', '[{"name": "按喜欢的来蔬菜", "amount": "适量"}, {"name": "按喜欢的来荤菜", "amount": "适量"}]'::jsonb, '["炖牛腩➕清炒菠菜➕米饭。                                       炖牛腩我之前写过的方子： \n\n“总是不够吃的炖牛腩”：\nhttps://www.xiachufang.com/recipe/104409232/", "腊肠菜饭➕红烧台湾虾🦐➕清炒芦蒿", "南瓜饭➕青椒胡萝卜肉片➕秋葵菇子炒蛋", "红烧排骨➕茄子炒豆角➕米饭", "青椒肉片➕四喜烤麸➕豆角炒蛋➕米饭\n我之前写过的四喜烤麸的方子：\n“冷热皆宜的四喜烤麸”：\nhttps://www.xiachufang.com/recipe/104438853/", "黑椒煎鸡腿排➕清炒荷兰豆➕豆苗➕厚蛋烧➕米饭（撒一些味岛香松）", "虾仁滑蛋➕白灼青菜➕素什锦➕米饭", "烤鸡腿杂蔬（在我每次的便当集锦好像都出现一两次，因为只要腌制鸡腿然后放烤箱和土豆小番茄一起烤）➕虾仁蛋炒饭", "糖醋里脊➕炒菠菜➕手撕包菜➕米饭", "红烧大排➕韭黄炒蛋➕白灼杂蔬➕米饭", "辣炒鸡块➕白灼生菜淋蒸鱼豉油➕米饭", "咖喱鸡丁➕蚝油菇子➕米饭", "红烧排骨➕芹菜腐竹➕火腿片炒莴苣➕米饭", "上汤娃娃菜➕彩椒牛柳➕白煮青菜豆腐丝➕米饭", "红烧猪软骨➕蚝油香菇➕白灼西兰花🥦➕米饭", "荠菜馄饨➕青椒土豆丝➕豆角炒蛋➕红烧鸡翅根（馄饨和鸡翅根都是从奶奶家打包）", "小炒鸡腿肉➕莴苣炒蛋➕彩椒鸡软骨（超市购买的配好的方便菜）➕米饭", "青椒肉丝➕清炒茼蒿➕红烧煎豆腐", "香菇青菜➕“荷塘月色”（某送菜app购入的配好的方便菜，一炒就行）➕熟食➕米饭", "酱鸭➕素炒杏鲍菇➕酒香金花菜➕米饭"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/3aa00aab70a7447a898156deaae4a204_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('营养美味午餐便当-记录那些带盒饭的日子与灵感', '热门专题', '便当', '', '[{"name": "适量餐具方便直接吃的主食", "amount": "适量"}, {"name": "适量爱吃的蛋白质：肉类/鸡蛋", "amount": "适量"}, {"name": "适量营养均衡的蔬菜们", "amount": "适量"}, {"name": "适量拌饭酱汁（可选）", "amount": "适量"}]'::jsonb, '["【宫保鸡丁饭】\n宫保鸡丁（鸡胸肉/胡萝卜/青椒/腰果）+玉米青豆+紫甘蓝泡菜+米饭+芝麻海苔碎", "【煲仔饭】*电饭煲一锅出*\n腊肠+腊肉+香菇+鸡蛋+青豆+圆白菜+米饭+煲仔饭酱汁\n具体做法参考【不素懒人煲仔饭】菜谱：https://www.xiachufang.com/recipe/105815012/", "【台式卤肉饭】\n拌饭神器卤肉（三层肉/香菇/洋葱酥）+卤蛋+菜花或小青菜+米饭\n具体做法参考【不素懒人卤肉饭】菜谱：https://www.xiachufang.com/recipe/105823942/", "【韩式石锅拌饭】\n胡萝卜+西葫芦+香菇肉碎+香肠+鸡蛋+米饭+韩式辣拌饭酱\n具体做法参考【不素懒人石锅拌饭】菜谱：https://www.xiachufang.com/recipe/105827979/", "【麻辣香锅饭】\n麻辣香锅（土豆/胡萝卜/包菜/藕片/香菇/木耳/香肠/蟹棒/虾仁）+米饭+芝麻海苔碎", "【韩式部队锅饭】\n部队锅（牛肉卷/午餐肉/香肠/蟹棒/年糕/香菇/金针菇/泡菜/胡萝卜/土豆/西葫芦/辣酱锅底/芝士）+米饭+芝麻海苔碎\n\n前一晚上做足量的部队锅和芝士拉面，吃不完的配菜锅底加上米饭又是一顿简便美味的便当～", "【快手大阪烧】\n日式大阪烧（圆白菜/虾仁/扇贝/火腿/青豆/鸡蛋/牛奶/奶酪/面粉）+卤蛋or厚蛋烧+大阪烧酱汁", "【香浓咖喱鸡肉饭】\n鸡胸肉+土豆+胡萝卜+洋葱+青豆+米饭\n灵魂咖喱酱：咖喱粉2/酱油1/牛奶", "1/芝麻酱", "【照烧鸡腿饭】\n带皮鸡腿肉+青菜+胡萝卜+米饭\n灵魂照烧汁：酱油2/料酒1/蜂蜜1/番茄酱", "5/黑胡椒/盐", "【爱心蛋包饭】\n火腿/胡萝卜/彩椒/西葫芦/青豆/鸡蛋/米饭", "【麻辣拌配饭】\n麻辣拌（猪肉/香肠/大虾/蟹棒/洋葱/胡萝卜/土豆/藕片/西兰花/香菇/芝麻）+米饭", "【西班牙海鲜饭】\n鱿鱼/大虾/扇贝/西班牙辣肠/洋葱/番茄/彩椒/藏红花/西兰花/米饭/柠檬", "【辣海鲜寿司饭】-冷餐-\n照烧辣海鲜（鱿鱼/大虾/扇贝）/牛油果/裙带菜/鱼籽蟹棒/日本红姜/寿司饭", "【百变豪华沙拉】-冷餐-\n通心粉/生菜/火腿/蘑菇/鸡蛋/蟹棒/牛油果/橄榄/玉米+沙拉酱/无花果醋/黑胡椒/柠檬汁（防止牛油果氧化）"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/b655891e385344b6a2e1a8b6edfd23fa_1502w_1124h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Tinrry+圣诞节糖霜饼干', '热门专题', '圣诞节', '', '[{"name": "无盐黄油", "amount": "100克"}, {"name": "糖粉", "amount": "70克"}, {"name": "奶粉", "amount": "30克"}, {"name": "全蛋液", "amount": "30克"}, {"name": "低筋面粉", "amount": "200克"}, {"name": "烘焙用蛋白粉", "amount": "10克"}, {"name": "糖粉", "amount": "130克"}, {"name": "食用水", "amount": "20克"}, {"name": "新鲜柠檬汁", "amount": "10克"}, {"name": "水饴（玉米糖浆）", "amount": "5克"}, {"name": "拉线糖霜", "amount": "80克"}, {"name": "新鲜柠檬汁", "amount": "5克"}]'::jsonb, '["关注我们公众号：甜悦家烘焙，获取更多的教学视频&amp;烘焙工具，材料的优惠信息。\n\n如果在制作过程中有什么疑问，可以扫码添加我的小助理的微信，她会给你详细解答哦，还可以加入甜悦家的烘焙交流群，还会有淘宝优惠哦~", "#饼干底", "糖粉、奶粉一起过筛加入无盐黄油中，用电动打蛋器混匀；", "全蛋液分两次加入，用打蛋器低速混匀；", "过筛加入低筋面粉，用刮刀拌匀至没有干粉；", "戴上手套稍微揉匀面团；", "将面团转移到油纸上，稍微捂实，让面团没有过大的缝隙；", "盖上另一张油纸，稍微压扁，放入冰箱冷冻15-20分钟；\n\nTips：面团最好贴着冰箱的隔层板，冷却的速度更快。", "把烤箱上下火150度预热；", "冷冻好的面团可以轻易用手指戳出小坑，即表示软硬度刚好；", "用擀面杖把面团擀开至约4毫米的厚度；", "撕开油纸，在面团表面撒上面粉防粘；", "将面团的另一面翻转朝上，用饼干模具刻出饼干面团；\n\nTips：\n1、可以用牙签或裱花嘴在饼干上刻出小洞，烘烤出来的饼干就可以用绳子串起来。\n2、大小不同的饼干面团建议分开烘烤。", "饼干面团送入预热好的烤箱中层，上下火150度，烘烤20分钟左右；", "饼干边缘形成金黄色，中间还有一点白，即可以关火，在烤箱中焖5分钟左右再取出，让饼干颜色更均匀；", "饼干出炉后马上转移到一个平面上，用烤盘压着晾凉；", "过筛糖粉、蛋白粉，把三分之一过筛好的糖粉加入蛋白粉，混匀；", "加入食用水，稍微搅拌后，用打蛋器中高速打发糖霜；\n\nTips：第一次加入糖粉一定要打发变白，把蛋白粉融化并且打发起来。", "糖霜打发至变稠变白、有纹路，即可分两次加入剩余糖粉，继续混匀、打发；\n\nTips：糖粉要分三次加入打发，如果一次性加入，会打发不充足，糖霜颜色会很黄。", "糖霜打发至固体状态；", "称量加入水饴，加入柠檬汁，低速混匀糖霜，做成用于勾线的糖霜；", "称量出80克的勾线糖霜，分次看情况加入柠檬汁，混匀成可以流动的填充糖霜。\n；", "把两种糖霜分别装入裱花袋备用；", "把装糖霜的裱花袋剪一个小口；\n\nTips：可以在油纸上试一下糖霜线条的粗细。", "根据视频中的手法画出糖霜图案。\n\n填充雪花", "做好的糖霜饼干，建议送入烤箱上下火60-70度烘烤半小时（线条形状）至一个小时（填充形状）左右，把糖霜中的水分烘干，以保证口感、延长保存期限。"]'::jsonb, 30, 130, '困难', 3, 'https://i2.chuimg.com/b191f95f08c945758407b33d103baf2c_6720w_4480h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('圣诞节大餐菜谱', '热门专题', '圣诞节', '', '[{"name": "水果", "amount": "适量"}, {"name": "蔬菜", "amount": "适量"}, {"name": "鸡", "amount": "适量"}, {"name": "红酒", "amount": "适量"}, {"name": "下面有详细教程", "amount": "适量"}]'::jsonb, '["番茄鲜虾盅：西红柿切掉四分之一，中间掏空，拌入鸡蛋糕，放入煮熟的大虾摆好，点缀一点绿植", "圣诞花环：两个土豆做成土豆泥，拌入沙拉酱，盘子中间放只饭碗，把土豆泥在饭碗四周铺成环形，取走饭碗，土豆泥上摆好焯熟的西兰花，点缀点胡萝卜，玉米豆装饰", "圣诞树根蛋糕：这个很复杂了，但是买不到，只能自己做，做好一个蛋糕卷，用叉子把融化的巧克力刮到蛋糕卷上，点缀些彩虹糖和饰物。 草莓小雪人：把草莓尖头切下，刚才做的土豆泥剩下一些，做雪人脸，再把草莓头放上，用黑芝麻点上眼睛，点个小红唇😊", "圣诞小蘑菇：圣女果切下一小半，鹌鹑蛋切下一小半，合在一起，点上沙拉酱，盘子铺上苦苣，摆好", "水果圣诞树🎄：准备猕猴桃🥝和葡萄🍇、草莓🍓、桔子🍊、哈蜜瓜，切好备用。准备一个大苹果做底盘，上面插根胡萝卜🥕（尖朝上），胡萝卜身上插上许多牙签，把备好的水果插好，最后洒上糖粉，非常漂亮的水果塔就做好了🥰", "蓝莓山药：山药做成泥后，用叉子堆出山状，蓝莓酱用水稀释一下，淋到山上，很好吃的", "蔬菜沙拉，这个可以随意搭配", "圣诞大餐", "这是我前年做的圣诞大餐（因为孩子们都在外地上大学，所以略有简单）", "这是去年做的圣诞大餐（孩子们还是不在家里），以后也许圣诞节都不会在家过了，只有春节才能回家团聚", "最后我想说，事业、家庭，美丽，完全可以同步，生活才能更美好💕"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/6a74ed82779944c79e7eeb93920619a5_750w_600h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('圣诞节烤箱菜-杂蔬鸡腿肉', '热门专题', '圣诞节', '', '[{"name": "腌肉部分：", "amount": "适量"}, {"name": "2斤左右鸡腿", "amount": "8只"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "几片洋葱", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}, {"name": "蚝油", "amount": "2勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "淀粉", "amount": "3勺"}, {"name": "油", "amount": "3勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}, {"name": "半勺黑胡椒粉", "amount": "适量"}, {"name": "蔬菜部分：一切淀粉类的蔬菜都可以我为了消耗家里冰箱的蔬菜和好多叫不出名字形状的南瓜，所以决定做这个菜", "amount": "适量"}, {"name": "土豆", "amount": "1个"}, {"name": "半节藕", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "半个南瓜", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "10朵（超级好吃，一定要多放）香菇", "amount": "适量"}, {"name": "青椒", "amount": "1个"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "盐", "amount": "1勺"}]'::jsonb, '["鸡腿肉去骨，肉切大丁备用", "把所有的蔬菜切好", "鸡腿肉来腌制，基本以这个饭勺为基准，放入葱姜蒜", "1勺老抽，2-3勺生抽，2勺蚝油，少量黑胡椒粉，一勺糖，一勺盐，盐的用量自己酌情放，因为生抽蚝油都有咸度。两大勺淀粉，再倒入适量油，拌匀腌制片刻。", "蔬菜部分尽量切一致，土豆不要切太大，不然鸡腿肉熟了刚刚好的时候 土豆还不够软糯。蔬菜放一勺生抽一勺蚝油一小勺盐适量油拌匀即可", "拿一个大烤盘，铺满锡纸", "把蔬菜铺匀，把鸡肉铺在上面", "上下火，180度，半个小时。", "半小时我尝了一下，觉得土豆不够软糯，我就盖了层锡纸，温度加到200，又烤了8分钟。火候和时间得看食材和自家烤箱脾气决定。", "时间到啦，米饭也好了，南瓜土豆超级糯，吸收了汤汁味道，鸡腿肉因为加了淀粉，超级滑嫩。拌饭吃绝了！", "鸡骨没浪费，炖了几朵香菇加了一把油菜，也相当舒坦了！", "后面我又试过一下，蔬菜部分多加了芹菜，烤的时候先加盖锡纸不用包严实，200度35分钟。然后拿掉锡纸，230度烤15-或18分钟。上面的鸡皮呈现一种焦焦的口感。都很好吃，随你喜欢咯。"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/c44a390c80c0426f84d5abb066a286fb_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('日本超火の小零食糖霜/焦糖巧克力杏仁圣诞节的礼物', '热门专题', '圣诞节', '', '[{"name": "（根据自己用量）杏仁（可换成其他坚果）", "amount": "200克"}, {"name": "糖", "amount": "100克"}, {"name": "盐", "amount": "1克"}, {"name": "水", "amount": "40克"}, {"name": "（我喜欢可可味的做的比较多）黑巧克力", "amount": "60克"}, {"name": "（其实还是看自己做的量）可可粉", "amount": "50克"}, {"name": "（大概可以做40颗）白巧克力", "amount": "20克"}, {"name": "抹茶粉", "amount": "15克"}]'::jsonb, '["我一般都一次性做3款 但我很负责任的告诉你 可可巧克力的最好吃！", "称取杏仁 放置烤盘中 入烤箱130度 10分钟 （烤好的杏仁最好90度放烤箱里面恒温备用）", "糖➕盐➕水放置锅中 中火加热", "待糖熬到109度（其实105度开始就可以了 怕倒入杏仁会降低糖的温度 所以我多熬了几度）", "离火 用刮刀快速翻炒", "等待糖凉了的时候就会形成糖霜杏仁（其实还可以做糖霜各种东西 比如糖霜山楂是不是）", "拿出糖霜杏仁后 剩余的放入锅中中火继续加热 使其糖霜焦糖化", "等待杏仁上的糖霜全部焦化并且裹上焦糖后", "少数的倒到铺有油布的烤盘上 （嗯 很多拉丝不重要 等糖冷却硬了之后可以弄掉）！！！强调下！一定要一点一点弄出来（如果你一次性弄出来 我保证 你还没把杏仁分开 焦糖就已经硬化了）", "冷却好的焦糖杏仁拨开丝 还是很ok的对不对？其实到这步 焦糖坚果跟糖霜坚果就很好吃了", "这个就是焦糖榛子 跟糖霜榛子 做好了装管密封 差不多可以吃一个月？", "巧克力隔水融化（或者微波炉小火融化都可以）", "倒入焦糖杏仁 裹上巧克力", "夹出来 到可可粉上 裹上可可粉 就👌🏻啦", "抹茶味的用白巧克力哦 不然颜色不好看", "同样倒入焦糖杏仁 翻版均匀", "夹出来扔进抹茶粉中（抹茶那么贵 当然要杯子装啦～摇一下杯子 就裹好了", "差不多我的杯子不大 可以4-5颗一起操作吧（and～抹茶吸水性比较高 所以差不多裹好一次后 最后还得再裹一次", "好了 冬天快到了 你确定不做一点糖来准备过圣诞么🎄 （ps：别问我 多余的抹茶粉跟可可粉怎么办 当然是做抹茶拿铁跟可可巧克力牛奶啦 这是一个暖暖的冬天）"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/9d7f5e7ec4754220988c1927f0dde88c_1242w_2098h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('ins风圣诞节雪花豆沙面包---错过了夏天的风秋天的雨 不能再错过冬天的雪花', '热门专题', '圣诞节', '', '[{"name": "高筋面粉", "amount": "240克"}, {"name": "低筋面粉", "amount": "60克"}, {"name": "纯牛奶", "amount": "160克"}, {"name": "全蛋液", "amount": "35克"}, {"name": "细砂糖", "amount": "30克"}, {"name": "干酵母", "amount": "3克"}, {"name": "盐", "amount": "4克"}, {"name": "黄油", "amount": "30克"}, {"name": "适量豆沙馅", "amount": "适量"}, {"name": "适量高筋面粉", "amount": "适量"}]'::jsonb, '["将面团配料除黄油外的配料，混合一起，搅打至扩展阶段；", "加入黄油，搅打至完全扩展阶段；", "面团盖保鲜膜开始一次发酵。发酵至2-", "5倍大，用手指蘸面粉按下去不回缩不塌陷即可；", "面团一发完成后分成3等份，滚圆以后盖上保鲜膜松弛15分钟；", "取一份松弛好的面团，擀成直径约22Cm的圆饼", "抹一层豆沙馅；", "再把第二张擀成圆饼铺在第一个上面", "再抹一层红豆沙", "再把第三份擀成圆饼铺上", "把边缘捏紧；", "取一个直径约5Cm的原型磨具放在面饼中间；", "沿着边把面饼切成16份 ,每一刀都要切透。", "可以先切成4等份，再切8等份，最后切16等份；", "、取临近两个长条，一手捏一个", "反向拧两圈捏住边缘", "依次处理所有切面；", "开始二次发酵。发酵的适宜温度是37度，湿度75%。如果没有发酵箱，可以放在烤箱里，放一碗热水。", "发酵至2倍大，取出来筛上适量高筋面粉；", "放入预热好的烤箱，180度中下层烤25分钟；", "随手一拍都很美", "满满的圣诞风"]'::jsonb, 30, 110, '困难', 3, 'https://i2.chuimg.com/b4e3bfb1cd1347f0bb79554f08f4e8fa_5472w_3648h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('年夜饭头道菜～鸿运当头（樱桃小萝卜）', '热门专题', '年夜饭', '', '[{"name": "樱桃萝卜", "amount": "300克"}, {"name": "白糖", "amount": "70克"}, {"name": "白醋", "amount": "50克"}, {"name": "盐", "amount": "3克"}, {"name": "半个橙皮", "amount": "适量"}]'::jsonb, '["樱桃萝卜切去头尾洗净沥水", "切成连刀片，底部不切段。", "掌握不好力度，可以放一根筷子在旁边辅助。", "放盐腌制15分钟", "倒掉腌制出来的水，再倒入清水清洗两遍", "橙子表面用盐搓洗干净", "橙子皮切丝", "准备好70克白糖、50克白醋，半个橙子皮。我做过多次，这个比例做出来的味道酸甜适中，如果喜甜或喜酸，可根据自己口味调整，加入了橙子皮是为了更好的去除萝卜味，成品还会有一股橙子的清香。", "洗净的萝卜攥干水分，放入橙皮丝、白糖和白醋。", "盖上盖子，摇晃均匀，放入冰箱冷藏12小时以上/", "腌制12小时以上的成品，会浸出漂亮的汤汁，是不是很美？关键做法简单味道好，学会这道菜，就等着被夸吧！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/84a4ab62e53d4259a66af67ba9fcd166_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('东北人的年夜饭', '热门专题', '年夜饭', '', '[{"name": "一条鱼", "amount": "适量"}, {"name": "一斤虾", "amount": "适量"}, {"name": "一斤茧蛹", "amount": "适量"}, {"name": "二斤牛肉", "amount": "适量"}, {"name": "鸡翅", "amount": "12个"}, {"name": "半个猪肚", "amount": "适量"}, {"name": "一条肥肠", "amount": "适量"}, {"name": "两只猪蹄", "amount": "适量"}, {"name": "三斤五花肉", "amount": "适量"}, {"name": "两根风干肠", "amount": "适量"}, {"name": "一把蒜苔", "amount": "适量"}, {"name": "一把韭菜", "amount": "适量"}, {"name": "一朵西兰花", "amount": "适量"}, {"name": "一小把木耳", "amount": "适量"}, {"name": "一小把四季豆", "amount": "适量"}, {"name": "一个猪肝", "amount": "适量"}, {"name": "两个青椒", "amount": "适量"}, {"name": "一根胡萝卜", "amount": "适量"}, {"name": "一小把香菜", "amount": "适量"}, {"name": "六个鸡蛋", "amount": "适量"}, {"name": "一朵生菜", "amount": "适量"}, {"name": "一个火龙果", "amount": "适量"}, {"name": "一个橙子", "amount": "适量"}, {"name": "一个猕猴桃", "amount": "适量"}, {"name": "两个小柿子", "amount": "适量"}]'::jsonb, '["水果拼盘", "红烧鱼🧐忘了是啥鱼啦", "蒸五香肉蛋卷", "干煸蝉蛹", "辣炒肥肠", "蒸风干肠", "凉拌西兰花", "可乐鸡翅", "蒜苔炒肉", "香辣牛肉条"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/e1521efbcf9b4fc2b269e1741c3a8e41_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('年夜饭菜谱', '热门专题', '年夜饭', '', '[{"name": "生抽", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "姜", "amount": "适量"}]'::jsonb, '["水煮鱼片", "爆炒花甲", "椒盐排骨", "清蒸鲈鱼", "麻辣小酥肉", "红烧猪蹄", "干锅花菜", "三汁焖锅", "柠檬鸡翅"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/cfa8369a52314a1e976d9ac7c938814e_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('每年的年夜饭我都会做这道糖醋排骨', '热门专题', '年夜饭', '', '[{"name": "精排排骨", "amount": "4根"}, {"name": "一根大葱", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "一小把冰糖", "amount": "适量"}]'::jsonb, '["🍀🍀食材：猪肋排四根，葱3块，姜片3块，八角2个，香叶2片，一小把冰糖\n\n先调个糖醋汁👉：料酒一勺➕两勺生抽➕一勺老抽➕三勺香醋", "🍀🍀做法：1️⃣排骨洗净，冷水下锅加入姜片，葱，料酒，焯水3分钟，焯好水的排骨沥干水分，锅里油热放排骨翻炒微微黄盛出，锅留底油放一小把冰糖小火炒出枣红色，（注意⚠️一定要小火，用铲子瞬时搅拌，要不然火喉大了会发黑发苦哦）\n\n2️⃣倒入排骨快速翻炒均，倒入调好的糖醋汁翻炒均匀上色，放几片葱姜，八角香叶，加开水末过排骨，中小火炖40分钟左右即可，最后大火收汁，（不要收的太干，）出锅撒点白芝麻", "一招教你如何做出酒店红彤彤的红烧排骨，其实在家就可以😌", "来，家人们你们先尝一口🥰", "酸甜可口，喜欢的过年🧨安排吧"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/b55a8ff02d30430198d36eb8d735caf1_1125w_1484h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('年夜饭｜人间烟火处 年味渐浓时 持续更新', '热门专题', '年夜饭', '', '[{"name": "用心各种食材", "amount": "适量"}]'::jsonb, '["🧧京酱肉丝—花开富贵\n🧧剁椒鱼头—鸿运当头\n🧧爆炒牛肉—牛气冲天\n🧧糯米南瓜—甜甜蜜蜜\n🧧蒜蓉粉丝虾—八方来财\n🧧皮蛋小金鱼—富贵有余\n🧧蒜苔炒腊肉—长长久久\n🧧鹌鹑蛋五花肉—幸福团圆\n🧧水果拼盘—莓有烦恼\n🧧红酒🍷\n🌟京酱肉丝做法\n豆腐皮入香菜、胡萝卜丝、黄瓜丝卷成卷，隔2厘米斜切断摆入盘边上，里脊肉切成丝入蛋清、少许白酒、盐、胡椒粉、淀粉腌制30分钟，锅中入油入葱姜蒜炒香，入肉丝翻炒变色，入料汁（甜面酱、白糖、老抽、生抽、香醋、水调均匀）酱汁烧开入淀粉水收汁。\n🌟糯米南瓜\n南瓜去皮切块切成上宽下尖的条状拼入碗中，糯米与1:", "5比例煮饭，糯米饭入适量的红枣葡萄干拌匀，把糯米饭入南瓜碗中，蒸20分钟倒扣在盘中，锅中入少许水及枸杞，水开入淀粉水勾芡倒入南瓜上\n🌟蒜蓉粉丝虾\n虾去头去线剪开虾背入胡椒粉盐腌制20分钟，热锅入油入蒜蓉小米椒炒出香味，入蚝油盐白糖生抽搅拌均匀留一勺后盛出，入用冷水泡软的粉丝搅拌铺入盘，虾摆好在粉丝上，均匀铺上蒜蓉酱，蒸8分钟入葱花浇热油", "美味可口", "🧧蒜蓉小排（节节高升）\n🧧孜然烤羊排（喜气洋洋）\n🧧手抓扇子骨（幸福美满）\n🧧黑椒牛仔骨（牛气冲天）\n🧧玉米胡萝卜珍珠丸（团团圆圆）\n🧧香菇青菜（四季平安）\n🧧玉米胡萝卜豌豆（金玉满堂）\n🧧干捞粉丝（长长久久）\n🧧水果拼盘\n🧧红酒：张裕解百纳N398\n🌟蒜香小排\n完全解冻入碗中搅拌均匀，锅中入油入小排炸5分钟捞出，锅中入彩椒蒜末炒香，入炸好的小排翻炒均匀\n🌟孜然羊排\n解冻羊排，入烤箱220度烤10分钟，配上蘸料～\n🌟黑椒牛仔骨\n牛仔骨提前解冻，不粘锅入橄榄油入牛仔骨煎至两面焦黄，锅中入油入葱姜蒜炒香，入彩椒洋葱块翻炒变软，入煎好的牛仔骨翻炒均匀\n🌟手抓扇子骨\n牛仔骨自然解冻，不粘锅入橄榄油，牛仔骨入锅中煎至两面煎至金黄", "香菇青菜", "玉米胡萝卜肉丸", "金玉满堂", "🧧蒸虾仁鸡蛋—蒸蒸日上\n🧧清蒸鲈鱼—年年有余\n🧧四喜丸子—团团圆圆\n🧧清炒什锦—前程似锦\n🧧蒜蓉粉丝虾—腰缠万贯\n🧧卤鸭翅鸭脚—展翅高飞\n🧧酒酿南瓜—花开富贵\n🧧八宝饭—富贵团圆\n🧧水果拼盘\n🧧红酒🍷—红红火火", "做法如图"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/6f9145c4e92e40e5ac8f595dae262b3e_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('深夜食堂严选之味猪肉味增汤官方菜谱', '热门专题', '深夜食堂', '', '[{"name": "猪五花肉", "amount": "200克"}, {"name": "1/4根白萝卜", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "4朵香菇", "amount": "适量"}, {"name": "半根牛蒡", "amount": "适量"}, {"name": "芋头", "amount": "3个"}, {"name": "魔芋", "amount": "1块"}, {"name": "木棉豆腐", "amount": "1块"}, {"name": "油炸豆腐", "amount": "1块"}, {"name": "半根大葱", "amount": "适量"}, {"name": "1500毫升日式高汤", "amount": "适量"}, {"name": "1大匙芝麻油", "amount": "适量"}, {"name": "5-6勺味增", "amount": "适量"}, {"name": "1小匙酱油", "amount": "适量"}, {"name": "1小匙味淋", "amount": "适量"}]'::jsonb, '["将猪五花肉切成4厘米长的薄片。白萝卜、胡萝卜切成银杏叶形片，香菇切薄片，牛蒡切薄片，芋头切成块。魔芋、木棉豆腐用手掰成适口大小备用。油炸豆腐切成1厘米宽条状，大葱的一半切成1厘米小段，另一半剁碎。", "锅烧热后倒入芝麻油，炒猪五花肉片。再放入魔芋和其余的蔬菜同炒，芋头，2种豆腐，大葱除外。", "锅内食材全部过油翻炒后，倒入高汤。煮开并撇去浮沫，放入油炸豆腐和半份味增，加盖炖煮10-15分钟。", "待蔬菜煮熟后，加芋头，葱段，豆腐，继续炖煮大约10分钟。", "起锅前加入余下的味增、味淋、酱油", "盛入汤碗，撒上碎葱末。呼噜呼噜真是下饭"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/78c2d82446a6425bb55f049e5783cdf1_1766w_943h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧鲽鱼', '热门专题', '深夜食堂', '', '[{"name": "鲽鱼", "amount": "1条"}, {"name": "各20g葱姜蒜", "amount": "适量"}, {"name": "干辣椒", "amount": "1个"}, {"name": "八角", "amount": "1个"}, {"name": "油", "amount": "250ml"}, {"name": "半勺盐", "amount": "适量"}, {"name": "糖", "amount": "1勺"}, {"name": "醋", "amount": "1勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "二分之一小勺老抽", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺甜面酱", "amount": "适量"}, {"name": "半勺腐乳汁", "amount": "适量"}, {"name": "二分之一小勺番茄酱", "amount": "适量"}, {"name": "白酒", "amount": "1勺"}, {"name": "3小碗水", "amount": "适量"}]'::jsonb, '["准备好食材鲽鱼一条。", "将鲽鱼的鱼鳞刮去，去除内脏，清洗干净，切成段。", "用厨房用纸吸干鲽鱼段的水分。                  吸干水分的目的一是煎鱼时避免溅油，二是为了更好的入味。", "将每块鱼的两面都沾上薄薄的一层面粉。", "葱切段，姜切片，蒜切片，干辣椒切成小段备用。", "调制烹鱼的碗汁：天津甜面酱半勺、腐乳汁半勺、生抽2勺、老抽二分之一小勺、番茄酱三分之一勺、香醋1勺、白糖1勺、蚝油1勺、盐半勺、白酒1勺，把它们调匀。                                                   如果家中调料不全的话，只放酱油和醋、盐即可。", "大火起锅，锅烧热后放入大量（约300ml）的油。当油六、七成热时放入鱼，此时改中火煎鱼。                                                            温馨提示：                                                    （1）煎鱼时随时微微调整火的大小，千万不要让油起烟。                                           （2）六、七成热的油温是如何判断呢，就是油面有明显的波动。                             （3）往油锅里放鱼时，要贴着油面轻轻地放入。                                                         （4）我使用的是不粘锅。 如果小伙伴们使用的是铁锅就要把锅烧的热热的，然后用姜在锅里涂抹一层，再继续操作，这样避免粘锅。", "当鱼的一面煎至金黄色时翻过来再煎另一面，两面都煎至金黄色就OK了，然后依次将其它的鲽鱼块煎至金黄色。                           温馨提示：                                                   （1）当把鱼刚刚放到锅里后千万不要急于翻动，如果翻动了，肯定会粘锅的，因为油很热，鱼和铲子都是凉的，热油一下子就会“抱住”铲子和鱼，肯定会粘锅。          （2）那么我们什么时候才能翻动鱼呢，a，中火煎制至少2分钟后才能翻动。b，还有就是被煎鱼的那面有明显的金黄色才可以翻动。c，再有就是当离火晃动锅时，鱼可随意在锅里滑动也可以翻动。建议初学者用第2种方法判断什么时候翻动鱼。", "将煎好的鲽鱼鱼段沥一下油。", "锅里留少许底油，中火，放入备好的佐料爆香。", "放入煎好的鲽鱼段。", "改大火，烹入提前准备好的碗汁，迅速盖上锅盖儿，焖20秒左右。", "倒入约3小碗（水的量与食材齐平）的水，此时用大火炖开。", "大火炖鱼时请用汤勺舀起汤汁浇在鱼的身上，这个动作多重复几遍，以便鱼入味。", "大火炖约10～15分钟左右，最后收汁至浓稠即可。\n大火收汁最后时收汁速度特别快，一定要多加注意，必要时用双手端着锅柄离火转圈晃动锅，避免粘锅。", "成品图。                                                            因为所用调料品牌各有不同，咸度和颜色也有所不同，所以调料的量仅作参考，要根据自己所用的调料适当的增减。"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/46f8bf2d8bf34c9d83025c82517770ce_3264w_2176h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('深夜食堂黄油土豆（北海道乡土料理）', '热门专题', '深夜食堂', '辣', '[{"name": "2-3个新土豆", "amount": "适量"}, {"name": "黄油", "amount": "适量"}, {"name": "煎脆的培根（备选）", "amount": "适量"}, {"name": "辣腌章鱼（备选）", "amount": "适量"}, {"name": "泡菜（备选）", "amount": "适量"}]'::jsonb, '["食材准备。", "把小土豆洗干净，入锅蒸。（或高压锅蒸）", "煮好后的土豆划十字，把黄油塞进去就可以啦！", "【加分项】加上喜爱的配料，自己喜欢煎脆的培根，看也有加泡菜，辣腌章鱼哒！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/27431969cdfa47b8a1c14729d226afe3_1506w_1129h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('深夜食堂泡面高手之灵魂炒方便面', '热门专题', '深夜食堂', '', '[{"name": "1颗辣椒", "amount": "适量"}, {"name": "2包方便面", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "火腿肠", "amount": "2根"}, {"name": "随便吃啥放啥颗青菜", "amount": "适量"}]'::jsonb, '["两包方便面 水开放入方便面，关火焖一会就ok", "切 我喜欢淀粉含量很高的火腿肠", "三个鸡蛋打散", "把面过凉水", "热锅热油", "倒入蛋液 还是之前提到过的煎鸡蛋法 用铲子划着煎", "能煎成这样 泡芙一样", "热锅热油", "倒入辣椒", "倒入火腿", "倒入方便面", "加入酱油 盐 鸡精", "疯狂搅拌 翻炒", "老抽上色", "疯狂搅拌 再疯狂炒一炒", "出锅啦！！！"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/521e9d4180dd48028f3cbe70ac7ce761_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('日式土豆泥-深夜食堂', '热门专题', '深夜食堂', '', '[{"name": "，两个拳头大土豆", "amount": "1个"}, {"name": "煮熟的鸡蛋", "amount": "1个"}, {"name": "四分之一个洋葱", "amount": "适量"}, {"name": "三分之一根胡萝卜", "amount": "适量"}, {"name": "适量沙拉酱，盐，醋，黑胡椒", "amount": "适量"}, {"name": "切片用盐腌黄瓜", "amount": "适量"}, {"name": "二分之一火腿或者香肠", "amount": "适量"}, {"name": "黄油，放入热土豆里", "amount": "10克"}]'::jsonb, '["菜谱图片", "土豆胡萝卜煮熟，我喜欢土豆还有一点点块状", "乘着热拌所有材料", "23年10月国庆节，准备材料。多了东方甄选甜玉米粒。醋用的balsamico是意大利拌沙拉用的果醋也不错。", "煮鸡蛋得放哦，调整口感。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/f3282912d2f94369aa76669dfbee1980_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('火龙果玫瑰花', '热门专题', '情人节', '', '[{"name": "一个火龙果", "amount": "适量"}]'::jsonb, '["把火龙果洗干净，再把它身上的绿色叶子用手撕掉，或者用刀切掉，就像图中这个样子。", "把火龙果对半切开。", "皮剥了。", "把火龙果切成一毫米左右厚的片，尽量薄点，不过也别太薄，太薄了做成的花也不太好看。不过火龙果两头尽量切薄点。用两头卷玫瑰花的心，薄点好卷不易折断。（后来我才明白为什么朋友说火龙果花弄不成，因为火龙果和芒果比，里面有大量的子，也要比芒果硬）", "这是我切的第一片。是不是挺小的。", "把把小片的，一片片卷起来，让它立起来。", "然后一层一层贴，因为火龙果中间高，两头低，并且是有弧度的，所以在下一片压着上一片不让上一片开的同时，最好让这个弧度刚好出来，这样花型会漂亮点。（懂我意思吧，好难表达）", "差不多半个火龙果可以做成两个，所以第一个做到你觉得可以的地步就可以了，我每次都是到中间大小刚好。另一个也从比较小的那头开始卷，方法和第一个做的一样。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/3e50aeba8b7b11e6b87c0242ac110003_780w_1052h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('情人节生巧 | 2种口味', '热门专题', '情人节', '', '[{"name": "我的黑巧克力和牛奶巧克力是一样放一半的，如果你喜欢甜点的，那就牛奶巧克力多放点，两者加起来一共300克左右就差不多了。", "amount": "适量"}, {"name": "黑巧克力（65%-70%）", "amount": "150克"}, {"name": "牛奶巧克力", "amount": "150克"}, {"name": "淡奶油", "amount": "165克"}, {"name": "水饴", "amount": "15克"}, {"name": "无盐黄油", "amount": "15克"}, {"name": "适量，撒表面用的可可粉", "amount": "适量"}, {"name": "白巧克力（33%左右）", "amount": "300克"}, {"name": "无盐黄油", "amount": "25克"}, {"name": "淡奶油", "amount": "85克"}, {"name": "水饴", "amount": "7克"}, {"name": "6-8克抹茶粉", "amount": "适量"}, {"name": "适量，撒表面用的抹茶粉", "amount": "适量"}, {"name": "❣️❣️❣️视频里我做的是配料表两倍的量，因为我的模具太大了，如果做太少的话，成品会显得有点薄，不好看，谁让我是颜控😂", "amount": "适量"}]'::jsonb, '["先咬一口馋你一下，哈哈O(∩_∩)O", "黑巧克力味的~", "好啦，开始吧，提前准备好所有原材料；", "在模具里垫硅油纸，没有硅油纸的垫保鲜膜也可以，但四周都要垫好，不然不好脱模；", "在一个稍微大点的碗里倒入黑巧克力；", "再倒入牛奶巧克力；", "最后倒入黄油，这三种东西混合在一起就可以了，不分先后顺序；", "稍微铺平点，好让所有巧克力黄油均匀受热；", "隔热水放着备用，热水的温度不宜太高，太高会让巧克力增加油水分离的风险；\n\n我的水温大概是70摄氏度左右吧；", "在锅里倒入淡奶油；", "开下火加热；", "加热至边缘冒泡泡就可以了，千万不要煮太久，太烫了也会让巧克力油水分离；", "将煮好的奶油均匀的淋入巧克力里；\n\n但巧克力还是隔热水放着，不要拿出来了；\n\n因为这点奶油没办法让巧克力完全融化，所以要借助隔热水的方法让巧克力完全融化；", "再倒入水饴；", "盖上保鲜膜闷3-5分钟；", "然后取走保鲜膜；", "轻轻搅拌，让奶油和巧克力充分融合；\n\n刚开始的状态可能有点，不可描述，看着很难受，不要灰心，继续轻轻搅拌；", "可以直线朝一个方向搅拌，就是将蛋抽由外向内搅拌，这样可以让巧克力和奶油更容易融合；", "慢慢的，巧克力跟奶油就充分融合了，变得细腻顺滑；\n\n记住，一定要轻轻的搅拌，动作太大的话，会让空气进去，形成很多气泡；", "搅拌好了之后，倒入之前垫了硅油纸或保鲜膜的模具里；\n\n模具尽量用小一点的，太大了的话，成品就显得比较薄，个人觉得太薄的不好看，不过，如果你喜欢薄的话，就没问题了；", "用刮板刮平，但是呢，不刮平也不影响食用；", "铺平后，放入冰箱冷藏3小时左右，或者冷冻1-2个小时，但这个时间不是绝对的，只要把它冻硬就可以了，不冻硬的话不好切；\n\n用法芙娜巧克力做的更好吃哦，但是巧克力颗粒比较大的话，要切碎一点，不然不好融化；\n\n隔水融化巧克力的水，不可以太烫，不然巧克力会油水分离，我的水温大概是70摄氏度左右；\n\n水饴可以根据不同的季节适当增减，冬天的话，可以多加几克，因为水饴的保湿性好；", "接下来是抹茶味的，提前准备好所有原材料；", "将黄油与白巧克力放一起，铺平，隔热水融化；", "隔水融化巧克力的水，不可以太烫，不然巧克力会油水分离，我的水温大概是70摄氏度左右；\n\n水饴如果没有的话，可以不放，只是放了的话，生巧的保湿性更好；\n\n水饴也可以根据季节不同适当增减，冬天就可以多放几克；", "轻轻搅拌；", "搅拌至差不多融化就可以了，有点颗粒也没关系，因为后面还是隔热水操作，操作的过程中还会融化的；", "抹茶粉先过筛三分之一进去；", "轻轻搅拌均匀；", "再过筛剩余的抹茶粉的一半进去；", "抹茶粉过筛进去之后，轻轻搅拌均匀；\n\n搅拌均匀后，将剩余的抹茶粉全部过筛进去；", "再次轻轻搅拌均匀；", "搅拌至看不见抹茶粉为止，还是隔热水放着备用；", "奶油倒入锅中；", "小火煮至边缘冒泡泡；", "将隔热的巧克力取出来，煮好的奶油均匀的倒进去；", "再倒入水饴；", "煮好的奶油倒进去之后，\n闷半分钟左右；\n\n奶油千万不要煮太久了，\n否则会造成巧克力油水分离，边缘冒泡泡就可以了；\n\n抹茶粉粉分三次过筛进去，是为了能搅拌的更均匀；", "轻轻搅拌；", "搅拌至巧克力和奶油充分融合，一定要轻轻的搅拌哈；", "搅拌融合的巧克力倒入模具里；", "刮平，不刮也没事，不影响食用；", "铺平后，放入冰箱冷藏3小时左右，或者冷冻1-2个小时，但这个时间不是绝对的，只要把它冻硬就可以了，不冻硬的话不好切；", "冻硬的生巧，从模具里取出来；", "反过来放着，揭掉硅油纸或保鲜膜；", "用尺子量量，平分成你喜欢的大小；", "切块，具体能切多少块的话，还要看你用多大的模具，一块量的尺寸是多少；", "均匀的撒一层可可粉；", "入口即化，好吃；", "抹茶味的也一样，冻硬后从模具里取出来；", "揭掉硅油纸或保鲜膜；", "用尺子量量，平分；", "还可以用心形模具压出形状，不过这样就会多出一些边角料，哈哈，我也就做了一个；", "绿心，哈哈哈哈；", "均匀的撒上一层抹茶粉；", "细腻顺滑的口感，不简直不要太好吃，有时间你也试试吧；", "做好的生巧，可以装入礼盒送给你的男朋友、女朋友了，嘻嘻.....\n\n祝大家七夕（情人节）快乐，有情人终成眷属，哈哈~"]'::jsonb, 30, 285, '困难', 3, 'https://i2.chuimg.com/055a5e7419da474ea9103c89c5610fa9_6000w_4000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级简单美腻的生日蛋糕，情人节蛋糕。解决各种抹面困难！', '热门专题', '情人节', '', '[{"name": "一个8寸蛋糕胚", "amount": "适量"}, {"name": "500-600克动物性淡奶油", "amount": "适量"}, {"name": "少许(装饰)草莓", "amount": "适量"}, {"name": "少许(装饰)蓝莓", "amount": "适量"}, {"name": "少许(夹层)芒果", "amount": "适量"}, {"name": "50-60克(100克淡奶油用10克糖)白糖", "amount": "适量"}]'::jsonb, '["提前准备好8寸蛋糕胚一个", "可以自己用刀切，忘记拍照片了！！切薄片", "按照自己喜欢的形状稍加装饰，可以用巧克力酱写点祝福语，美腻！", "好适合今天的日子。", "14情人节"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/16029638f0d24eaca03efc912c2a016c_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('情人节最爱 爱心拉花马卡龙 | 小马课堂 27', '热门专题', '情人节', '', '[{"name": "杏仁粉", "amount": "80g"}, {"name": "红曲米粉", "amount": "4.8g"}, {"name": "糖粉", "amount": "80g"}, {"name": "蛋白", "amount": "29.2g"}, {"name": "杏仁粉", "amount": "20g"}, {"name": "糖粉", "amount": "20g"}, {"name": "蛋白", "amount": "7.3g"}, {"name": "蛋白", "amount": "36.5g"}, {"name": "水", "amount": "25g"}, {"name": "砂糖（煮糖浆用）", "amount": "90g"}, {"name": "砂糖（打发蛋白用）", "amount": "10g"}]'::jsonb, '["将两种面糊的TPT粉类分别过筛，混合均匀。加入未打发的蛋白，拌至无干粉状态。", "制作蛋白霜。然后称重，将蛋白霜分成80%和20%。", "80%的蛋白霜用来与红色红曲面糊混合，20%的蛋白霜用来拌原色面糊。", "最后，挤面糊的时候，先挤红曲面糊，然后用原色面糊在边上挤两个小点。\n\n详细见视频啊〜", "用牙签从圆点中间划过，小圆点就变成小心心啦。是不是很可爱呢～", "入炉烘烤后，搭配柠檬山楂夹馅，看着就很喜欢呀～\n\n夹馅做法 https://www.xiachufang.com/recipe/103731640/", "我们可以将红曲米粉换成可可粉，相似的做法，搭配巧克力乳酪夹馅。\n\n夹馅做法 https://www.xiachufang.com/recipe/102273602/"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f6e6aca574c2404cbba80b3ce80986a5_2100w_2100h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('传承习俗～好吃的七夕节巧果', '热门专题', '情人节', '', '[{"name": "面粉", "amount": "250克"}, {"name": "鸡蛋", "amount": "110克"}, {"name": "白糖", "amount": "30克"}, {"name": "2—3克酵母", "amount": "适量"}, {"name": "牛奶", "amount": "10克"}, {"name": "花生油（或者猪大油）", "amount": "20克"}]'::jsonb, '["所有材料混合在一起，和面，面团的稍微软一点点，醒发20分钟", "排气，揉成光滑面团，搓成长条，切成小剂子，一个一个粘点面粉放入模具中按压，因为后期会发酵，建议面团的高度不要超过模具的高度。倒扣出巧果面胚。", "巧果面胚醒发至两倍大", "方法一.铁锅加热，放入铁锅，烙至两面金黄。\n方法二.用铁锅烙至稍微上色，放入烤箱，上火100度，中层加热至金黄，翻面继续烤至另一面金黄色即可。\n方法三.烤箱预热180度，烤制金黄即可。", "出锅，味道还不错。", "按照习俗，巧果是染上各种颜色的面团做成的，做好以后把巧果串起来，挂在小朋友的脖子上～\n借朋友的图片，布的下面以前用的的是细的高粱杆（方言：杆dang），朋友用的芒果干。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/072ddb5d913b45b498bd4cc7d6788f75_992w_744h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('乡巴佬卤鸡蛋', '热门专题', '宵夜', '', '[{"name": "鸡腿", "amount": "2只"}, {"name": "鸡翅", "amount": "6只"}, {"name": "鸡蛋", "amount": "4只"}, {"name": "八角", "amount": "3个"}, {"name": "桂皮", "amount": "2段"}, {"name": "草果", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "花椒(不吃辣可不放)", "amount": "3g"}, {"name": "辣椒(不吃辣可不放)", "amount": "2个"}, {"name": "葱段", "amount": "6段"}, {"name": "姜片", "amount": "2片"}, {"name": "4汤勺生抽", "amount": "适量"}, {"name": "2汤勺老抽", "amount": "适量"}, {"name": "2汤勺陈醋", "amount": "适量"}, {"name": "1汤勺蚝油", "amount": "适量"}, {"name": "1汤勺冰糖", "amount": "适量"}, {"name": "1茶勺芝麻油", "amount": "适量"}, {"name": "半汤勺盐(调整用)", "amount": "适量"}]'::jsonb, '["鸡翅洗干净焯水（水开放食材进去煮至水再次沸腾，大概三四分钟即可），起锅用急自来水冲30秒，沥水备用；鸡蛋水煮至熟，剥壳备用。\n\n焯水，就是将初步加工的原料放在开水锅中加热至半熟或全熟，取出以备进一步烹调或调味。\n\n⚠️图片是后来补的，就没有准备鸡腿🍗了…", "准备卤水配料，辣椒需要切断(桂皮、草果害羞没有入镜😳)\n\n⚠️别私信问我什么是草果，什么是桂皮了，大家都是无所不能的好厨娘，可以自行百度一下。", "鸡翅、鸡蛋以及卤水配料放小奶锅，先加淹没鸡翅鸡蛋一半的清水", "加生抽4汤勺、老抽2汤勺、陈醋2汤勺、蚝油1汤勺、冰糖1汤勺、芝麻油1茶勺、盐(调整用)半汤勺(可不加)，加完所有调料应该刚好覆盖了鸡翅鸡蛋，如果还未覆盖，请继续添加清水至完全覆盖\n\nPS：汤勺是图片上的，具体一汤勺容量为多少我没具体量过", "大火煮开转中小火煮30分钟，想软绵一点的可以多煮一会儿，直至自己喜欢的程度。\n\n⚠️出锅前，试下咸度，试下咸度，试下咸度，便于做些调整。\n\nPS：请一定细心看心得，尤其是出锅前试下咸度非常必要！", "最后简单摆盘就可以吃大餐啦~"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e8ae858b6ebd476c995adc8174bd5321_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('C.J的冷吃牛肉', '热门专题', '宵夜', '', '[{"name": "1KG牛肉", "amount": "适量"}, {"name": "一大把干辣椒", "amount": "适量"}, {"name": "一大把干辣椒丝", "amount": "适量"}, {"name": "少量豆豉", "amount": "适量"}, {"name": "半个姜", "amount": "适量"}, {"name": "适量茴香", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "一大把辣椒面", "amount": "适量"}, {"name": "一小把花椒", "amount": "适量"}, {"name": "草果", "amount": "2个"}, {"name": "白蔻", "amount": "4个"}, {"name": "丁香", "amount": "4个"}, {"name": "肉蔻", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "适量花椒粉", "amount": "适量"}, {"name": "适量芝麻", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "少量糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "少量料酒", "amount": "适量"}, {"name": "少量白酒", "amount": "适量"}]'::jsonb, '["干辣椒、干辣椒丝、姜片、香叶、八角、香叶、小茴香、肉蔻、白蔻、丁香、桂皮、豆豉（没有干的就用老干妈）装盘备用。", "调料图文科普……这会分的清了吧", "辣椒面（要有辣椒子那种）、花椒粉和白芝麻备用。", "水灼下牛肉 ，加姜片、花椒、白酒、料酒水开中火煮5分钟", "灼过后的牛肉，按个人喜好切备用，个人喜欢大块吃肉的感觉所以切的粗些。", "油温六成热时下牛肉条油炸。", "炸到牛肉条外表微焦金黄，捞出备用。", "炸牛肉的油留三分之一，调料中火炒出香味。", "炒香调料后，牛肉条、白糖、盐、生抽下锅。翻炒一会。", "炒均后加刚好没过食材的清水，大火烧开，转小火开盖煮30分钟。", "30分钟后大火收汁，收到大致没过食材一半的汤汁。", "辣椒面、花椒粉和白芝麻下锅。", "中小火多搅拌，慢熬3分钟。", "出锅前尝一下味道，根据个人口味调节味道。", "出锅自然凉凉。", "放凉后忍着口水，放进冰箱冷藏浸泡2小时以上，时间久点最入味😂😂", "冷藏结束，装盘搞定", "自己动手丰衣足食", "和去成都时吃的一个味道。", "自己动手丰衣足食", "End。"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/05c7e0229fdf4beda48eb553fd038265_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('极香的葱油面', '热门专题', '宵夜', '', '[{"name": "小葱", "amount": "80g"}, {"name": "油", "amount": "110克"}, {"name": "生抽", "amount": "140g"}, {"name": "老抽", "amount": "40g"}, {"name": "白砂糖", "amount": "15克"}, {"name": "蚝油", "amount": "10g"}]'::jsonb, '["小葱洗干净切段，葱白去掉不用", "食用油倒入锅中，加热", "油微热的时候把葱段加入，小火加热", "小火熬煮大概3~5分钟左右，葱段变色，加入提前混合好的生抽，老抽，蚝油", "搅拌一下，继续小火加热至冒泡", "加入白砂糖搅拌均匀", "出锅，晾凉后可以装密封罐冰箱冷藏保存，可以保存一个月", "锅里加水煮开后加入细面条，煮大概3分钟左右，捞出浸泡至凉开水中", "面条捞出至碗中", "用勺子搅拌一下葱油，再盛起两勺至碗中，具体几勺葱油，咸淡口味根据喜好不同调", "夹一些熬煮过的葱段在面上，不喜欢的可以不加", "拌匀就可以开吃啦，是不是超级简单！", "真的极香，你一定要试试^_^"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/5c6020728ede45e59f5e27633bd5a6b9_1241w_993h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常葱油制作（绝味葱油面）超详细', '热门专题', '宵夜', '辣', '[{"name": "视情况而定克食用油", "amount": "适量"}, {"name": "一小把（十根这样）葱", "amount": "适量"}, {"name": "半生抽", "amount": "6勺"}, {"name": "半老抽（红烧酱油）", "amount": "3勺"}, {"name": "半耗油", "amount": "1勺"}, {"name": "喜欢就多放点芝麻", "amount": "适量"}, {"name": "小半勺糖", "amount": "适量"}]'::jsonb, '["准备好小葱\n葱尽量不要大葱（大葱肉厚实，不好炸，当然不怕麻烦也可以自己切细一下👌）\n\n⚠️不要葱白是紫色那种！那种葱有苦味不好吃！\n\n要白葱！白葱！\n（太大不好炸(ง •̀_•́)ง）", "准备好我们的调料～\n这可是重点！要考的！\n老抽我喜欢用红烧的(☆∀☆)", "把小葱切成大概5cm到6cm这个样子～\n❗️葱白和葱叶要分开炸\n（我觉得葱白葱叶都好吃，所以都要o(≧v≦)o）", "热锅冷油ಥ_ಥ\n用小火🔥小火🔥\n‼️先炸葱白\n葱白炸的差不多了～\n⚠️不是炸糊！而是焦黄且枯就可以捞出！", "葱白大概炸成这样💯\n完美💯", "油留着不要动！直接放葱叶！\n⚠️我炸制中途又➕了些油～\n\n（原本油可以很多泡过葱的，但是我喜欢葱香浓郁♨️所以油差不多没（mo）过葱这样，中途不够再加～问题不大）", "⚠️同样不要炸糊\n全程小火🔥\n炸脆捞出(๑˙ー˙๑)\n\n（脆的标准就是你捞出的时候(*^▽^)/★*☆可以听到刺啦刺啦的脆响(ღ˘⌣˘ღ)💯）", "锅里的油晾着它，要用的，不要倒，要加调料进去油里面的！！！\n🔅我们开始调料\n重点！要考的黄金比例⚠️\n\n生抽：老抽：耗油：糖\n=    4  ：2  ：1  ：", "5\n（⚠️后者都比前者少一半就对了）\n\n糖的话我觉得可放可不放（我不太喜欢太甜的）", "起火🔥小火🔥小火🔥\n先加入白芝麻～炸香（别糊）\n然后加入调好的调料\n⚠️过程中要一直搅拌⚠️", "起泡泡以后就立刻关火\n立刻！\n立刻！\n不然会有糊味\n（就毁了(T ^ T)）", "然后把炸好的葱白和葱叶放在密封罐或者盒里～\n倒入调好味的葱油～\n๛ก(ｰ̀ωｰ́ก) 💯💯💯\n\n放入冰箱可以放置一个半月左右～慢慢吃(≧∇≦)/", "白水煮好的面条🍜捞出\n➕几勺葱油～\n\n➕葱油的时候油和调料会分层！所以搅拌一下在舀出来就可以了\n\n(//∇//)我已经上头了\n葱白和葱叶(☆∀☆)\n巨香٩(♡㉨♡ )۶ \n隔壁小孩都馋哭了٩(๑^o^๑)۶"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/8be997f1a9eb48788869a6ce82541fdd_1225w_1225h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('烤土豆、烤薯角', '热门专题', '宵夜', '', '[{"name": "土豆", "amount": "6个"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量糖", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}, {"name": "适量黑胡椒", "amount": "适量"}, {"name": "适量新奥尔良粉", "amount": "适量"}, {"name": "少许欧芹碎", "amount": "适量"}]'::jsonb, '["土豆要挑个头比较小的，这样才容易切成薯角。", "像切苹果那样，切成一块块的，就成薯角啦。", "薯角冷水下锅煮大约5分钟，若是切成薯条的朋友们，请自行缩短煮的时间，煮好之后捞出沥干水份。（小贴士：薯角不要煮太熟，煮到夹生的状态就可以捞出）", "加入适量盐、糖、植物油、胡椒粉、新奥尔良粉和欧芹碎。喜欢吃辣的可以放椒盐、辣椒粉。", "将调料拌均匀。我用的是和面盆，直接摇呀摇，晃呀晃，就这么简单~~得瑟ing😌😌😌", "烤箱上下火200度烤30~40分钟。要是想烤得焦一点脆一点就加时间。", "开吃咯！趁热吃，超正😋😋！外脆内软，蘸点番茄酱，完美🌟！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/13781ac38c3246b7ad5fb8d8613c7fac_2448w_1959h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('健康低脂凉拌菜—菠菜可以这样吃', '热门专题', '减肥', '', '[{"name": "菠菜", "amount": "1把"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "花生", "amount": "40克"}, {"name": "约15克香油", "amount": "适量"}, {"name": "盐", "amount": "1.5g"}, {"name": "4瓣蒜", "amount": "适量"}, {"name": "蚝油", "amount": "8克"}, {"name": "适量白芝麻", "amount": "适量"}]'::jsonb, '["材料准备", "鸡蛋打散，少量盐，锅中刷油，倒入适量蛋液，转锅一圈铺平，小火煎成蛋皮", "菠菜热水焯一下\n\n过凉水两遍，捞出沥干水分", "蒜泥准备好\n\n调汁：蚝油、生抽、香油、盐，按需放，不要太咸", "不粘锅花生无油煎煮，有油会脆一些", "撒芝麻和花生", "小花记录自己的低卡饮食，写了公众号：\n✅【公众号：厨小花】，上百道细致的菜谱等你来！\n✅ 小花低卡饮食群，喜欢可以去找我哦！VX：CXHXH2018，有问必答，让我们一起健康吃饭！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a7c76ea7fdca4f22bf88a30ccff5229f_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('第6道快手低脂菜清爽美味的柠檬鸡丝鸡胸肉满分吃法', '热门专题', '减肥', '', '[{"name": "鸡胸肉", "amount": "1块"}, {"name": "小米辣", "amount": "3个"}, {"name": "半个柠檬", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "各1勺辣椒面，白芝麻，葱末，蒜末", "amount": "适量"}, {"name": "各2勺生抽，香醋", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "食盐，白糖", "amount": "1小勺"}]'::jsonb, '["鸡胸肉冷水下锅，放小葱，姜片，1勺料酒，煮十分钟左右，煮至筷子可以扎透后捞出晾凉，顺着纹路撕成细条状", "碗中放入1勺蒜末，1勺葱花，1勺辣椒面，1勺芝麻，浇上适量热油，再加入2勺生抽，2勺香醋，1勺蚝油，少许盐和糖，搅拌均匀", "柠檬切片去籽，小米辣切段，香菜切末", "调料汁浇在鸡丝上，放上辣椒段，香菜末和柠檬片，拌匀就可以吃了~"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/ae564cbfd61e436bb33f71498d7722f8_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('30天成功减重8斤，自己搭配的减脂餐（一）', '热门专题', '减肥', '', '[{"name": "勺橄榄油", "amount": "适量"}]'::jsonb, '["牛奶➕牛仔骨➕鸡蛋➕玉米➕西兰花➕胡萝卜➕平菇➕核桃", "牛奶➕火腿片➕鸡蛋➕南瓜➕荷兰豆➕玉米➕丝瓜➕青菜➕山药➕核桃", "牛奶➕鸡胸肉➕鸡蛋➕西兰花➕玉米➕蟹味菇➕荷兰豆➕胡萝卜", "牛奶➕小龙虾➕鸡蛋➕玉米➕丝瓜➕荷兰豆➕胡萝卜➕核桃仁", "牛奶➕小龙虾➕鸡蛋➕牛油果➕西兰花➕胡萝卜➕黄瓜", "牛奶➕牛仔骨➕鸡蛋➕玉米➕西兰花➕胡萝卜➕小番茄➕核桃仁", "牛奶➕马鲛鱼➕鸡蛋➕玉米➕蟹味菇➕西兰花➕胡萝卜➕核桃仁", "牛奶➕肥牛卷➕鸡蛋➕胡萝卜➕西兰花➕南瓜➕秋葵", "牛奶➕牛排➕鸡蛋➕玉米➕小番茄➕西兰花➕胡萝卜", "牛奶➕鸡蛋➕鸡胸肉➕牛油果➕紫薯➕胡萝卜➕西兰花➕腰果", "牛奶➕鸡胸肉➕鸡蛋➕紫薯➕茄子➕玉米➕蓝莓➕番茄➕黄瓜➕核桃仁", "牛奶➕虾仁➕鸡蛋➕玉米➕西兰花➕胡萝卜➕牛油果➕番茄", "牛奶➕火腿➕鸡蛋➕小龙虾➕玉米➕全麦馒头➕黄瓜➕核桃仁➕蓝莓", "牛奶➕牛仔骨➕鸡蛋➕紫薯➕玉米➕黄瓜➕蓝莓➕核桃仁➕番茄", "牛奶➕鸡蛋➕玉米➕红薯➕黄瓜➕鸡蛋➕番茄➕核桃仁➕芝麻丸", "牛奶➕鸡蛋➕虾仁➕玉米➕紫薯➕胡萝卜➕番茄➕牛油果➕核桃仁", "牛奶➕鸡蛋➕鸡胸饼➕玉米➕芦笋➕蓝莓➕小番茄➕核桃仁", "牛奶➕鸡蛋➕鸡胸饼➕牛油果➕蓝莓➕小番茄➕核桃仁➕胡萝卜➕香菇➕荷兰豆", "牛奶➕鸡蛋➕龙利鱼➕玉米➕红薯➕牛油果➕小番茄➕蓝莓", "牛奶➕鸡蛋➕玉米➕小番茄➕牛油果➕红薯➕核桃仁➕西兰花", "牛奶➕鸡蛋➕牛仔骨➕玉米➕西兰花➕小番茄➕牛油果", "南瓜➕紫薯➕蒸茄子➕鸡蛋➕番茄➕青菜胡萝卜", "煎三文鱼骨➕玉米➕杂粮饭➕西兰花➕胡萝卜➕番茄➕黄瓜", "玉米➕紫薯➕核桃仁➕金枪鱼➕青菜➕番茄➕鸡蛋➕牛油果", "煎三文鱼骨➕玉米➕西兰花➕鸡蛋加胡萝卜➕番茄➕牛油果", "玉米➕南瓜➕胡萝卜➕核桃仁➕豆角加鸡蛋➕番茄➕牛油果", "蒸鲈鱼➕豆芽➕紫薯➕牛油果➕黄瓜➕番茄", "玉米➕紫薯➕核桃仁➕小龙虾➕凉拌菠菜➕鸡蛋➕牛油果", "玉米➕核桃仁➕紫薯➕青菜➕西兰花➕胡萝卜➕鸡蛋➕番茄➕牛油果", "牛仔骨➕鸡蛋➕番茄➕牛油果➕玉米➕西兰花➕白玉菇", "牛排➕鸡蛋➕番茄加牛油果➕玉米➕西兰花➕蓝莓", "菠菜拌核桃仁➕鸡蛋➕番茄➕蓝莓➕玉米➕黄瓜➕小龙虾", "煎三文鱼骨➕番茄➕蓝莓➕牛油果➕杂粮饭➕鸡蛋➕青菜", "b牛仔骨➕鸡蛋➕牛油果➕玉米笋➕西兰花➕番茄➕蓝莓", "牛排➕鸡蛋➕牛油果➕玉米笋➕番茄➕蓝莓➕西兰花", "牛排➕鸡蛋➕西兰花➕牛油果➕玉米➕南瓜➕番茄", "基围虾➕鸡蛋➕牛油果➕全麦馒头➕南瓜➕番茄➕蓝莓", "牛仔骨➕鸡蛋➕蓝莓➕牛油果➕玉米➕黄瓜➕甜椒", "牛油果三文鱼➕鸡蛋➕番茄➕全麦馒头➕南瓜➕豌豆苗", "煎三文鱼➕鸡蛋➕黄瓜➕蟹味菇➕番茄", "白玉菇➕鸡蛋➕核桃仁➕牛油果➕全麦馒头➕南瓜➕红椒", "基围虾➕鸡蛋➕牛油果➕南瓜➕红椒", "金枪鱼➕鸡蛋➕牛油果➕玉米➕南瓜➕番茄➕蓝莓"]'::jsonb, 30, 215, '困难', 3, 'https://i2.chuimg.com/e198557294dc404eb34e4d046fd5fe9d_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('清爽解腻的黄瓜炒鸡胸肉，低脂低卡减肥食谱', '热门专题', '减肥', '', '[{"name": "半块鸡胸肉", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "黑胡椒碎", "amount": "10克"}, {"name": "淀粉", "amount": "1勺"}, {"name": "盐", "amount": "5克"}, {"name": "蚝油", "amount": "1勺"}]'::jsonb, '["把鸡胸肉切成小鸡丁，加入1勺料酒，1勺生抽，少许盐，少许黑胡椒碎，1勺淀粉，抓拌均匀\n再把黄瓜切成黄瓜丁", "热油下鸡胸肉炒变色，加入黄瓜丁翻炒，加入1勺生抽，1勺蚝油，再加入适量黑胡椒碎，翻炒均匀即可出锅啦", "超嫩超好吃😋", "好吃不腻，又低脂的黄瓜炒鸡胸肉就做好啦"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/381c1ab31b144123a05ee64e0c6a895d_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('解馋减脂餐！酸辣开胃又下饭的菠菜拌金针菇', '热门专题', '减肥', '辣', '[{"name": "金针菇", "amount": "1把"}, {"name": "菠菜", "amount": "1把"}, {"name": "生抽", "amount": "3勺"}, {"name": "3瓣蒜末", "amount": "适量"}, {"name": "醋", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "盐和糖", "amount": "5克"}, {"name": "辣椒粉", "amount": "1勺"}, {"name": "小米辣", "amount": "3个"}, {"name": "芝麻", "amount": "5克"}]'::jsonb, '["调个酱汁：一勺辣椒粉+一勺蒜末+一勺小米辣+一勺白芝麻，", "淋上热油", "三勺生抽", "两勺陈醋", "一勺蚝油", "少许盐和糖，", "搅拌均匀", "菠菜金针菇洗干净，焯水煮熟捞出", "菠菜焯水煮熟捞出", "挤干水份放入碗中", "倒入酱汁，抓拌均匀即可开吃", "太好吃了！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/3130fbd39121485e9ff738700ed0a474_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('冬瓜排骨汤，夏天的味道', '热门专题', '美容', '', '[{"name": "排骨", "amount": "2斤"}, {"name": "冬瓜", "amount": "2斤"}, {"name": "4-5片姜", "amount": "适量"}, {"name": "2-3段大葱", "amount": "适量"}, {"name": "小葱", "amount": "5根"}, {"name": "盐", "amount": "10克"}, {"name": "白胡椒粉", "amount": "1g"}, {"name": "鸡精", "amount": "1勺"}]'::jsonb, '["排骨冷水下锅，焯水，洗干净血水", "冬瓜切片", "小葱切葱花", "大葱3节，姜4片", "另起一锅热水，把排骨姜片葱段放进去，开大火煮，同时撇去浮沫，之后转中火盖盖煮", "45分后的样子，中间水煮的太干了可以加开水", "把葱段捞出来扔掉", "先加2-3g盐调味", "捞起一块排骨尝一尝，在能咬动但是还比较筋道的时候下冬瓜", "煮20分，加盐7g，鸡精1勺，胡椒粉1g", "碗里放一勺葱花，然后把排骨盛碗里，我习惯先放葱花这样没有生葱味", "配上米饭或者馒头都很好吃😊"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/ffcfc220cf22455eaf03a78aa5ede38d_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('养颜补血的红豆牛奶羹', '热门专题', '美容', '', '[{"name": "牛奶", "amount": "250克"}, {"name": "红豆", "amount": "50克"}, {"name": "红糖", "amount": "1块"}]'::jsonb, '["红豆提前泡发三小时以上，一定一定要用红豆，不能是赤小豆噢，会特别特别特别难煮。", "锅中加入500ml水煮豆子，煮到软糯为止。", "加入一块红糖。", "然后加入一盒牛奶，小火煮开即可。", "甜度可以自由调节，一块糖的话有淡淡的甜味。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/ee5daeadc3314bc489b2cdcc21b61c07_1024w_768h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('无敌好喝快速熬出胶的银耳羹美容又养颜', '热门专题', '美容', '', '[{"name": "1朵银耳", "amount": "适量"}, {"name": "10颗红枣", "amount": "适量"}, {"name": "30粒枸杞", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}]'::jsonb, '["准备食材，银耳提前冷水泡发2小时以上，红枣枸杞洗净备用", "银耳去根撕成小小朵", "冷水下银耳", "开锅中小火熬10分钟", "放冰糖红枣枸杞", "顺时针搅拌30秒，有助于出胶", "继续中小火熬40分钟左右", "关火焖半小时", "完成，满满的胶原蛋白"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/2d7936ad7c824c2ea6cd4a0093ee1532_1534w_2046h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制木瓜炖牛奶| 滋补养颜能喝出来牛奶肌哦', '热门专题', '美容', '', '[{"name": "木瓜", "amount": "1个"}, {"name": "牛奶", "amount": "250ml"}, {"name": "9颗红枣", "amount": "适量"}, {"name": "冰糖", "amount": "30克"}, {"name": "适量枸杞", "amount": "适量"}, {"name": "适量清水", "amount": "适量"}]'::jsonb, '["备好以上食材", "木瓜洗净削皮后对半切，用勺子去掉瓜瓤，切小块备用", "红枣洗净后对半切，去核备用", "将切好的木瓜红枣跟冰糖放入锅中，倒入清水没过食材，盖上盖子煮五分钟左右。", "焖煮后，倒入牛奶，放入枸杞，煮1-3分钟后即可出锅，煮太久会导致营养流失噢！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/dee658a66b284c15acacbd0678a2f604_1279w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('能健胃、补中气、美容的家常菜', '热门专题', '美容', '', '[{"name": "鸡肉", "amount": "250克"}, {"name": "半根红萝卜", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "（9克）蚝油", "amount": "1勺"}, {"name": "（9克）生抽", "amount": "1勺"}, {"name": "盐", "amount": "2克"}, {"name": "食用油", "amount": "8克"}, {"name": "淀粉", "amount": "5克"}, {"name": "白糖", "amount": "5克"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}]'::jsonb, '["买来的鸡肉洗干净切小块，加入姜、蒜、蚝油、生抽、盐、白糖腌制半小时备用。", "红萝卜洗干净切丁焯熟。", "这是焯熟的红萝卜和洗干净切丁的黄瓜。", "热锅加油，先爆香蒜瓣（切碎），然后加入鸡肉煸炒至熟，接着加入红萝卜、黄瓜、白胡椒粉、盐（喜欢辣的可以加辣）翻炒2分钟，倒入提前用凉开水搅拌好的淀粉勾芡，翻炒片刻即可。", "装盘可以开吃了哈！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/e7d5e580d9e74d4abf0ed2f31a7e0c7a_1018w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秋季靓汤 润肺抗燥霸王花罗汉果煲猪踭', '热门专题', '润肺抗燥', '', '[{"name": "猪踭肉", "amount": "250克"}, {"name": "霸王花", "amount": "30克"}, {"name": "半只罗汉果", "amount": "适量"}, {"name": "2颗蜜枣", "amount": "适量"}, {"name": "陈皮", "amount": "2片"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["各材料洗净，稍浸泡，霸王花浸泡至软、洗净并撕成条状；罗汉果洗净，打碎。陈皮泡至软。", "猪踭洗净切件并飞水。（“飞水”就是过开水，把材料用清水煮开2-3钟，除去材料的腥味和血水，煮开后，把水倒掉，再用清水冲洗干净。 ）", "把所有材料连同猪踭一起放进汤锅内，加入适量清水，武火烧开10分钟后改为文火煲2小时加盐调味即可。猪踭霸王花可捞起拌酱油佐餐用。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/6fc97882889711e6b87c0242ac110003_850w_637h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('金桔酱润肺止咳化痰疗效好。金桔酱。', '热门专题', '润肺抗燥', '', '[{"name": "金桔", "amount": "500克"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量水", "amount": "适量"}, {"name": "适量蜂蜜", "amount": "适量"}]'::jsonb, '["买来金桔", "用温水加点盐冼干净，控干水分", "用刀切成片，千万不要去核。", "金桔对半切开，友友们这是两种做法，可以选择去核或不去核，不去核就可以先腌制，蒸制后小火慢炒，放凉后在放蜂蜜就可以了，如果选择去核接着往下看。", "把金桔对半切开，把金桔核捡出来，放在小碗里。在把金桔切成薄片。放入冰糖腌制一夜，这样能腌出好多果胶出来。", "放入小块黄冰糖腌制。亲们这是两种做个法，去核切片，不去核两种做法，去核切片做出来口感不苦会更好。", "腌好的金桔上锅蒸60分钟。金桔核可以和金桔核一起蒸制。", "蒸好的金桔倒在平底锅中，小火炒。金桔的果胶会慢慢渗出来。如果太干可适当加入少量水，千万别加太多水，熬制完是果酱状态就可以了。", "给小朋友吃，在把炒好的金桔用打碎机打碎，在把金桔放入锅中一起熬制，金桔核有止咳去痰作用。熬制完放凉后在加蜂蜜。", "炒好的金桔倒上蜂蜜装瓶。每天早晚泡水喝，有一定疗效。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/e9b1f3eec1734f71a34a3c88436e2be5_739w_742h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('润肺化痰止咳金桔酱', '热门专题', '润肺抗燥', '', '[{"name": "金桔", "amount": "500g"}, {"name": "冰糖", "amount": "200克"}, {"name": "随意盐", "amount": "适量"}, {"name": "适量水", "amount": "适量"}, {"name": "适量蜂蜜", "amount": "适量"}]'::jsonb, '["1、500g金桔，倒入水里加入盐洗干净，我一个一个搓洗的，因为不要去掉皮，金桔的皮和籽都不要去掉。洗干净后控干水，我用厨房纸吸干了水分，然后切成薄片放入一个无水无油的容器里。", "2、加入200g 冰糖碎，（自己敲碎哈），我用的黄冰糖，买的时候让老板帮我敲碎了，毕竟我是弱女子啊～", "3，放入冰箱腌制15小时，不是急冻层啊仙女们～", "4，腌15小时以后取出，蒸锅水烧开，中小火蒸1小时，会看到果胶都慢慢出来了。", "5、取一个无油的锅，把蒸了一小时的金桔倒入锅里，小火慢慢炒，如果太浓稠了适量加入一些凉开水，炒到像熟透了的金黄色就可以，我大概炒了20分钟左右。", "6、炒好以后，放凉装入无水无油的密封罐，这里要提醒一下：给孩子吃的就这样装就可以了，如果是大人吃的，可以加入一些蜂蜜。我是给我儿子做的，所以没有加蜂蜜。", "每天早晚挖2小勺兑温开水冲服，对咳嗽、有痰的人有一定效果。放入冰箱可以冷藏多久？其实这个问题不太好说，毕竟没有防腐剂这些，所以我每次不会做太多，尽快吃完吧。一个星期半个月是没有问题的。此配方比率是：500g金桔、200g冰糖，如果需要做大量，自从翻倍就OK。以上，是我流水账一样的记录，献给需要的人，写得不好请多包涵。么么哒。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/e8733c2d02da4f0393a6ccc8eb6918f9_2304w_3072h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('润肺汤（小朋友的最爱）', '热门专题', '润肺抗燥', '', '[{"name": "（拳头那么大）猪展肉", "amount": "1块"}, {"name": "红萝卜", "amount": "1根"}, {"name": "雪梨", "amount": "1个"}, {"name": "1颗蜜枣", "amount": "适量"}, {"name": "干无花果（小的）", "amount": "4个"}, {"name": "1小把沙参", "amount": "适量"}, {"name": "1小把玉竹", "amount": "适量"}, {"name": "2-3片淮山", "amount": "适量"}, {"name": "各一小抓南杏、北杏", "amount": "适量"}, {"name": "4颗桂圆干", "amount": "适量"}, {"name": "1小把百合", "amount": "适量"}, {"name": "陈皮（最好5年或以上）", "amount": "1片"}]'::jsonb, '["1、冷水下锅把猪展肉焯一下水去血水备用，红萝卜、雪梨削皮切块，其他汤料过一下水就可以了", "2、把汤料放进锅里，水8分满就可以了，先把汤料泡15分钟、然后开大火烧开，再调小火煲1个小时左右关火，然后焖20-30分钟再喝就可以啦！"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/58db2c2006b4432ca940ce7f351c9642_2210w_1768h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('冰糖雪梨汤（清热降火，润肺止咳）', '热门专题', '润肺抗燥', '', '[{"name": "梨", "amount": "1个"}, {"name": "冰糖", "amount": "20克"}, {"name": "5--10粒枸杞", "amount": "适量"}, {"name": "3颗红枣", "amount": "适量"}, {"name": "八九分满水", "amount": "适量"}]'::jsonb, '["雪梨改刀切小块准备好冰糖，红枣，枸杞（请忽略我饱经风霜的菜板）", "放一个碗里，五分满左右", "加水，到八九分满", "放电饭锅蒸，做饭按键一小时左右", "时间到，出炉"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/014bbc09cb9c4bbd9b38714c2beaf28e_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('补气养血营养粥', '热门专题', '补血', '', '[{"name": "糯米", "amount": "50克"}, {"name": "黑米", "amount": "50克"}, {"name": "黑豆", "amount": "50克"}, {"name": "红豆", "amount": "50克"}, {"name": "莲子", "amount": "20克"}, {"name": "花生", "amount": "30克"}, {"name": "10颗红枣", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "10几粒枸杞", "amount": "适量"}]'::jsonb, '["准备好所有食材", "莲子清水泡发去苦芯", "糯米红豆黑米黑豆花生淘洗干净倒入电饭煲", "加1000ml清水", "按煮粥功能煮一个煮粥程序", "电饭锅跳起后加入红枣和泡好的莲子，再煮一个煮粥程序", "最后加入冰糖", "加人枸杞", "煮到糖化即可", "软糯香甜", "这个粥当早餐吃简直太棒了，如果晚上喝可以加点热牛奶助你一晚好睡，睡眠好了身体就好了，一定要试试哦！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/2db6e77998e84310b15b519c2e332fc1_3072w_2278h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('适合女生喝的补气血五谷粥，生理期后的补血品', '热门专题', '补血', '', '[{"name": "红豆", "amount": "适量"}, {"name": "黑芝麻", "amount": "适量"}, {"name": "莲子", "amount": "适量"}, {"name": "黑糯米", "amount": "适量"}, {"name": "红糖", "amount": "适量"}]'::jsonb, '["除了黑芝麻和红糖，其他的材料都浸泡一个夜晚。", "然后清洗干净放在电饭锅里熬两个小时即可，最后的几分钟再放红糖。", "记得要用粘稠的黑糯米哦！不是那种清水黑糯米！"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/f12ab2e76ea440b6a2d87a11dc6a5cf8_1614w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('滋阴补血～香菇山药乌鸡汤', '热门专题', '补血', '', '[{"name": "乌鸡", "amount": "600克"}, {"name": "山药", "amount": "200克"}, {"name": "3颗红枣", "amount": "适量"}, {"name": "30粒枸杞", "amount": "适量"}, {"name": "12朵香菇", "amount": "适量"}, {"name": "料酒", "amount": "4勺"}, {"name": "姜", "amount": "4片"}, {"name": "1小匙盐", "amount": "适量"}, {"name": "20粒花椒", "amount": "适量"}]'::jsonb, '["准备好需要的食材，鸡肉事先剁成块，清洗干净。", "干香菇用温水浸泡半小时。", "山药去皮切滚刀块。", "冷水放入鸡块，加2勺料酒、2片姜和花椒煮沸后捞出。", "重新把鸡肉放入汤锅中，放入山药、香菇、红枣，加2勺料酒和2片姜。", "盖上锅盖，煮沸后转中小火慢炖40分钟。", "出锅前加盐调味。", "鸡汤鲜美无敌。", "肉质细嫩。", "成品图。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/777df967e4be4242bb79a19d92dfa0bb_1920w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('补血补气乌鸡汤', '热门专题', '补血', '', '[{"name": "半只乌鸡", "amount": "适量"}, {"name": "少许克食用油", "amount": "适量"}, {"name": "几片姜", "amount": "适量"}, {"name": "少许料酒", "amount": "适量"}, {"name": "一小颗葱花", "amount": "适量"}, {"name": "一勺盐", "amount": "适量"}, {"name": "几粒枸杞", "amount": "适量"}, {"name": "5颗红枣", "amount": "适量"}, {"name": "2颗（没有可不放）荔枝干", "amount": "适量"}, {"name": "2颗（没有可不放）桂圆干", "amount": "适量"}, {"name": "5朵（鲜的，或者干菇泡发的都可以）香菇", "amount": "适量"}, {"name": "少许(可不放)黄芪", "amount": "适量"}, {"name": "少许(可不放)党参", "amount": "适量"}, {"name": "几滴芝麻油", "amount": "适量"}]'::jsonb, '["乌鸡切块洗净。(自己切的块，贱了一身血哈哈。买的时候最好让老板给杀好切好。)锅内放凉水，鸡块，几片生姜。火开捞出。这一步是焯水，主要是去血腥，去脏东西。一般炖肉都要焯水的。", "另外起锅，放少许油，姜片，鸡块下锅，放入适量料酒，翻炒一小会儿，然后放入温水，大火烧开炖。", "然后放砂锅里小火慢炖，加入香菇，黄芪和党参。我是设置的老火汤2个半小时。还剩半个小时的时候放葱花，枣，桂圆干，荔枝干（荔枝干跟桂圆干是因为家里正好有，没有就不放，根据自己口味调整），枸杞(这次家里正好用完了，就没放)。", "放一勺盐，滴上几滴芝麻油。出锅，冬日里喝上一碗美滋滋😄", "这是我加了虫草花炖的"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/29dd353df123442686fc066b12fc802c_1280w_1586h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('补气养血红豆粥', '热门专题', '补血', '', '[{"name": "红豆", "amount": "150克"}, {"name": "适量黑米", "amount": "适量"}, {"name": "适量薏米", "amount": "适量"}, {"name": "少许黑皮花生米", "amount": "适量"}, {"name": "18颗红枣", "amount": "适量"}, {"name": "18颗桂圆", "amount": "适量"}]'::jsonb, '["红豆泡好", "适量黑米泡好", "适量薏米泡好", "黑皮花生米洗净", "红枣泡好", "将以上几种食材泡一会，洗干净，放入高压锅中炖。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/1ccd5aa9002848df862a1e3096ecd63a_338w_270h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单清热雪梨膏', '热门专题', '清热祛火', '', '[{"name": "雪梨", "amount": "2个"}, {"name": "海底椰", "amount": "50克"}, {"name": "无花果", "amount": "50克"}, {"name": "白凉粉", "amount": "100克"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "2.8-3升水", "amount": "适量"}]'::jsonb, '["准备好煮料，雪梨削皮切块，无花果、海底椰洗干净，全部煮料放进约", "8升水中，开始熬煮。大火煮沸转小火慢煮约1小时。差不多煮完前5分钟放入准备好的冰糖。冰糖融化后从汤水中取出约300ml汤水放入碗中，备用。", "准备好白凉粉，用的是宇峰100克，按说明书，最佳比例是", "5水升配100克白凉粉。大家可以根据这个比例来调整整体水的用量，一般", "8升左右，总的来说喜欢硬一点的水放少些，喜欢软一些的就放多点水。中间熬煮还有过滤的过程水会有些消耗。多做几次就能大概找到最合适自己的口感比例。", "取出的300ml汤水稍微放凉再加入白凉粉，搅拌均匀。倒白凉粉搅拌液前需把煮料舀出来，过筛去掉渣滓，剩下的全是雪梨汁后，再倒入搅拌好的白凉粉开煮直到煮沸，如果着急这里可以开中大火，很快就煮沸了。", "煮好可以趁热倒入准备好的器皿中，我放了布丁那种玻璃杯，打包给同事朋友。自己吃的则用陶瓷小碗装好。", "放凉后自然成形，加入炼奶或者蜂蜜，看个人爱好，即可品尝了，夏天可以放冰箱冷藏下再吃，嫩滑可口哦！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/e36289f575b142ecae65ac8d2f344d2b_1124w_899h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('身体燥热，来一杯玉米须茶，很好的清热祛火！', '热门专题', '清热祛火', '', '[{"name": "5-6个新鲜玉米", "amount": "适量"}]'::jsonb, '["将玉米叶子扒开，将玉米须摘下来。", "将干净的玉米须摘下来。", "玉米吃不完，可以包回去，放冰箱。", "玉米须，放到阳光通风处晒干。", "把晒好的玉米须放进锅内煮，煮沸即可，倒出饮用，这就是农村人最爱喝的“龙须茶”了。", "玉米须也可以用来泡茶，好的不只是营养，还有口感，喝下去甜丝丝的，味道很不错，都说你熟悉的味道，懂得养生的人大多都喝过了，可以很好的降血糖，消除水肿，清热祛火。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/a73a9563ae9c4b0fa304c466e3e8a582_596w_405h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('清热去火夏日必备啤酒鸭', '热门专题', '清热祛火', '', '[{"name": "（净重1600克）鸭", "amount": "1只"}, {"name": "1瓶（500ml）啤酒", "amount": "适量"}, {"name": "20粒花椒", "amount": "适量"}, {"name": "一小块桂皮", "amount": "适量"}, {"name": "香叶", "amount": "3片"}, {"name": "八角", "amount": "1个"}, {"name": "老抽", "amount": "1勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "醋", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "料酒", "amount": "3勺"}, {"name": "盐", "amount": "7克"}, {"name": "若干片姜", "amount": "适量"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "一小段大葱", "amount": "适量"}, {"name": "3小块冰糖", "amount": "适量"}]'::jsonb, '["准备所有食材", "鸭肉冷水下锅，放入部分姜片、料酒、大葱段煮沸焯水，冲洗掉浮末丢掉葱姜待用", "锅内放入少许油，先放入花椒煸炒出香味，再放入八角、桂皮、辣椒、香叶、姜蒜煸炒出香味，放入鸭块，炒至鸭皮微黄，出油⚠️一定要炒至微微出油，这样的鸭肉会更香", "依次加入料酒、冰糖、生抽、老抽、醋（具体用量见配料表）翻炒均匀", "加入蚝油，盐煸炒均匀后，最后加入500ml啤酒，开始焖烧", "中火焖烧40分钟(☀️很多朋友问到啤酒不够，40分钟快干锅了，鸭子还不太软烂！", "请大家可以根据自家锅具的保水性来判断啤酒的量", "鸭子如果是老鸭烧的时间肯定要长些)中途翻炒一次，使鸭肉入味更加均匀，时间到了，大火收汁出锅装盘", "清热去火鲜香可口的啤酒鸭上桌啦，夏日必备佳肴，就是这么简单！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/71c7915429e64a69912c742924502fad_1000w_1406h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孩子要多喝的清热去燥汤', '热门专题', '清热祛火', '', '[{"name": "瘦肉", "amount": "200克"}, {"name": "1扎灯芯草", "amount": "适量"}, {"name": "麦冬", "amount": "10克"}, {"name": "1颗蜜枣", "amount": "适量"}, {"name": "6颗无花果", "amount": "适量"}]'::jsonb, '["准备以上材料", "瘦肉剁碎", "洗干净食材放入砂锅直接炖，我的炖锅比较慢（炖了4小时），正常隔水炖2小时就可以了。", "4小时后可以喝了，妹妹很爱喝，因为放了蜜枣，汤水很清淡甘甜。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a7d11f3a9a7d4e89874dee40e1234be3_864w_1152h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏天多喝这道汤，不但清热还补血抗衰老', '热门专题', '清热祛火', '', '[{"name": "猪肝", "amount": "40克"}, {"name": "瘦肉", "amount": "40克"}, {"name": "适量枸杞叶", "amount": "适量"}, {"name": "姜片", "amount": "8片"}, {"name": "适量葱花", "amount": "适量"}, {"name": "盐", "amount": "5克"}, {"name": "胡椒粉", "amount": "2克"}, {"name": "淀粉", "amount": "1勺"}, {"name": "耗油", "amount": "1勺"}]'::jsonb, '["猪肉和猪肝要新鲜且清洗干净煮出来的汤才会鲜美没有异味和腥臊味。", "枸杞叶洗干净捞出，姜切片，香葱切成葱花备用。猪肉洗净切片，放点盐，耗油，胡椒粉和淀粉姜片抓匀腌制备用。", "接下来就是处理猪肝，猪肝没处理好整道汤就会有异味。首先把猪肝切薄片，放一勺盐和淀粉反复抓揉，抓一分钟左右再用清水冲洗，直到水变得清澈透明，猪肝里面的血沫和异味才算清理干净。清洁好的猪肝用盐和胡椒粉姜片抓匀腌制备用。", "起锅烧水，水开后放一点油，再把猪肝瘦肉也陆续放进锅里。煮开后放洗好的枸杞叶。", "把所有材料放进去后就开始调味，放一小勺耗油和盐，搅拌均匀再放切好的葱花，就可以起锅装盘了！", "猪肝瘦肉补铁补血", "枸杞叶清肝明目抗氧化衰老，夏天喝上一口，真的是很清爽解腻，猪肝瘦肉很嫩滑一点也不柴不老。因为猪肝清理的很干净，即使没有放料酒也一点异味腥味都没有！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/d147cec508704f6cab787688c478c368_756w_1008h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孩子超爱吃的饭团', '热门专题', '儿童', '', '[{"name": "米饭", "amount": "500克"}, {"name": "适量海苔或者海苔碎", "amount": "适量"}, {"name": "两个鸡蛋", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "半根山药", "amount": "适量"}, {"name": "半根火腿肠", "amount": "适量"}, {"name": "半勺盐", "amount": "适量"}, {"name": "一勺白醋", "amount": "适量"}, {"name": "一勺白糖", "amount": "适量"}, {"name": "两勺沙拉酱", "amount": "适量"}, {"name": "适量芝麻", "amount": "适量"}]'::jsonb, '["胡萝卜切丁焯水", "火腿肠切丁", "山药切丁焯水", "鸡蛋摊成蛋饼切丁", "虾皮炒一下，炒的干干的，口感更好", "所有的材料准备好了", "把盐、白醋、白糖加点水调成汁，搅拌到米饭里面", "把所有的东西都放到米饭里面，搅拌均匀", "再加入两大勺沙拉酱搅拌均匀", "团成团，一定要团紧实一些", "再裹上一层芝麻海苔", "大功告成啦！", "团成多大都可以，我团的比较大", "看她们俩吃的多香呀😁😄"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/7eb7cacaac274de8ab347660aafbf245_2304w_3072h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('番茄鱼巴沙鱼（也可以用番茄龙利鱼），番茄酱汁超浓郁，营养又下饭！', '热门专题', '儿童', '', '[{"name": "巴沙鱼（或龙利鱼）", "amount": "1条"}, {"name": "番茄", "amount": "2个"}, {"name": "大约10克蕃茄酱或番茄沙司", "amount": "1勺"}, {"name": "生抽", "amount": "2克"}, {"name": "盐", "amount": "3克"}, {"name": "糖", "amount": "2克"}, {"name": "10g料酒", "amount": "1勺"}, {"name": "姜", "amount": "3片"}, {"name": "选配香葱", "amount": "适量"}, {"name": "选配白熟芝麻", "amount": "适量"}, {"name": "3瓣蒜", "amount": "适量"}]'::jsonb, '["腌制：龙利鱼解冻后切成小块，放入姜丝，料酒，白胡椒粉腌制20分钟，要多抓一下。 \n\nupdate：关于去腥的效果 高度白酒 &gt; 黄酒 &gt; 料酒。 根据手边的调料自行选择。\n有人问腌鱼为什么不放盐，因为放盐会使水份流失，口感会变柴，简而言之，我们要在汤汁里放盐。", "番茄表面划个十字，放到热水烫10秒，看皮褶皱了捞出，把表面的皮去掉，把番茄根去除，然后切成滚刀块，这样后面煮的番茄汁会更加浓郁。\n\nupdate：番茄切丁，效果更好", "焯水：目的是去除鱼腥沫，将腌制好的食材下入冷水锅，快要开锅后就关火，将鱼放到温水里洗干净。", "炒番茄汁：这步最主要的是炒出番茄汁来。热锅后，倒入10g油，油热后，放入蒜末炒出香味，倒入番茄块，然后翻炒一下，放盐，盐要先放，这样能把番茄杀出汁来。等番茄炒软了放入番茄酱和生抽，这步会番茄味更加浓郁。\n\nupdate：有人反应番茄汁不够多，主要几点补充", "番茄要去皮处理（步骤2）", "油要多一些，10g 更新为30g", "要先加盐，杀出汁水来", "番茄要选颜色深一些，软一点的", "你会发现番茄汁明显更多，但如果还不够多话，可以根据情况加少量水，有多少呢？下图这么多就好。当然，如果您加水的话，尝一尝味道，相应的盐，糖，生抽可能也要加一些。", "待番茄汁翻滚了，放入龙利鱼，一定要全程大火啊，煮上几分钟，让番茄汁收到鱼块里，最后放入糖提鲜，中和一下番茄到酸度。这个时候需要尝一下，看看酸甜度是否合适。", "最后出锅，放入白芝麻和香葱花，根据自己的口味，不放也可以。香喷喷的扮上一碗米饭，开吃吧！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/b99f6686473f40a5a281a366acf913ba_3024w_2419h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('宝宝蛋皮肉卷  儿童肉蛋卷 婴幼儿鸡蛋肉卷一岁以上宝宝辅食卷尖 蒸鸡蛋皮卷肉午餐肉', '热门专题', '儿童', '', '[{"name": "肉馅所需配料", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "一块约（120多克）猪瘦肉", "amount": "适量"}, {"name": "玉米淀粉", "amount": "12克"}, {"name": "一丁点盐", "amount": "适量"}, {"name": "糖", "amount": "2克"}, {"name": "姜粉", "amount": "1克"}, {"name": "白胡椒粉（可不放）", "amount": "1克"}, {"name": "蚝油", "amount": "1小勺"}, {"name": "蛋皮配料", "amount": "适量"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "玉米淀粉", "amount": "10克"}]'::jsonb, '["里脊肉一条，切小块", "肉块放入辅食机，加入一个鸡蛋，打成肉泥", "依次加入盐，姜粉，糖，白胡椒粉，蚝油搅拌均匀", "玉米淀粉稍微兑点水化开，分三次加入肉糜中朝一个方向搅拌上劲儿", "一定要分次加入，每次搅拌至看不见淀粉肉有粘稠感再加入下一次", "放入冰箱冷藏一会儿，接下来开始摊蛋皮", "两个鸡蛋加入淀粉水搅拌均匀（淀粉加适量水化开）", "辅食不粘锅，用厨房纸巾稍微沾点油擦一下锅就行，倒入蛋液，蛋液凝固，锅边蛋皮翘起，翻面，3-5秒后拿出（注意全程小火）", "尽量把皮做薄一点哦，开始卷肉", "取适量肉均匀抹在蛋皮上，上面留一点不要放肉，收口用", "卷起，收口处抹一点淀粉水，把口粘住，蒸的时候不容易开", "卷好以后放入盘中，盘中垫蒸馒头纸，或者直接在盘中抹一点油防止粘", "水开后蒸16-20分钟（这是蒸好以后的样子）", "晾温后切盘", "这是给宝宝卷的小的，蛋皮柔软，肉的感觉类似于午餐肉，不柴不干，好吃极了😃"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/e58db9bbb55d481fa6200ff5994512cd_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('三丁烩肥牛饭，可爱儿童餐', '热门专题', '儿童', '', '[{"name": "肥牛", "amount": "150克"}, {"name": "半个土豆", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "轻盐酱油", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "半勺白糖", "amount": "适量"}, {"name": "淀粉", "amount": "2勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "1碗米饭", "amount": "适量"}, {"name": "适量黑胡椒", "amount": "适量"}]'::jsonb, '["准备食材", "土豆，胡萝卜，洋葱，去皮洗净切丁，肥牛卷切小一点", "肥牛加点料酒焯一下捞出", "调碗汁：酱油➕蚝油➕黑胡椒➕糖➕淀粉➕水，搅拌均匀", "起锅烧油，放入土豆和胡萝卜炒熟", "放入洋葱炒软，加水，与食材持平，稍煮一会，把土豆煮软", "放入肥牛，碗汁", "加老抽调色，翻炒均匀，汤汁收到稍有些浓稠出锅", "米饭放入盘中整理成圆饼形状，三丁烩肥牛倒在米饭边上半圈做成头发，黑芝麻做眼睛，海苔做眼镜，小西红柿切一片做嘴巴。\n三丁烩肥牛饭做好，吃时拌匀，鲜香可口"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/6d3fe3a194a24626b1e1bc1133e58a5d_750w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('外酥里嫩简单下饭脆皮豆腐，馋哭隔壁小孩', '热门专题', '儿童', '', '[{"name": "豆腐", "amount": "1块"}, {"name": "葱", "amount": "1根"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "生抽", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "糖", "amount": "1勺"}, {"name": "少许盐", "amount": "适量"}, {"name": "淀粉", "amount": "1勺"}]'::jsonb, '["准备好食材", "碗中加2勺生抽➕1勺蚝油➕半勺白糖➕1小勺盐", "再加1勺淀粉➕半碗水调匀", "豆腐切厚片，裹上玉米淀粉", "裹上蛋液", "放入煎锅煎至两面金黄（一面煎好再煎另一面，用筷子配合铲子翻），放蒜末煸出香味", "倒入调味汁中小火煮至汤汁浓稠，洒上葱花即可", "外酥里嫩", "好吃到停不下来"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/6c58f68947f640c0a84c544511fc8865_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('婴幼儿山楂片宝宝山楂条（五斤山楂只用一斤糖）', '热门专题', '婴幼儿', '', '[{"name": "山楂", "amount": "1000克"}, {"name": "白砂糖", "amount": "200克"}, {"name": "梨或苹果", "amount": "500克"}, {"name": "尽可能少水", "amount": "适量"}, {"name": "该配方成品约500克", "amount": "适量"}]'::jsonb, '["挑好山楂，盆中放少许盐浸泡半小时，凉水冲洗干净。", "拿去核工具给山楂去核，梨削皮切成小块。\n\n&gt;&gt;如果没有去核器可以用刀刨开去核", "把山楂和梨倒入不沾炒锅中，放入尽量少的水煮软\n\n&gt;&gt;水一定要少，无需淹没山楂，山楂和水果在熬制过程中还会出水，不然后边炒山楂你会累到想哭", "将熬好的山楂放入破壁机或用料理棒打成泥，没有的话可以用筛网过滤成泥\n\n&gt;&gt;筛网过滤的话无需步骤5", "破壁机打好山楂酱后还要过筛二次去核，山楂酱用刮刀按压，过滤出残余的山楂核\n\n&gt;&gt;该步骤不可省略，否则成品还有未去除的山楂核", "将过好筛的山楂酱放入不粘炒锅中，加入糖，炒到硅胶刮刀提起不掉落的程度\n\n&gt;&gt;炒制过程中要用中小火不断画圈搅拌，电磁炉的火力是1000，煤气的话用中火偏小，大火溅起来的果酱会非常非常烫手，注意不要让小朋友在旁边玩耍", "炒好的山楂放入铺好油纸的金盘，先把四个角落先填满，然后用刮板抹平。放入烤箱中层用100度的火烤一小时,直至烤成片状。如无烤箱可以在温暖的太阳下或北方暖气上边晒干。\n\n&gt;&gt;这里给的是一个参考时间因为这个跟你的山楂果酱铺的厚度有关系", "将山楂切方便婴幼儿抓握的小条，用一层糯米纸一层油纸包起来，放入冷藏室，随吃随取，方便卫生，冰箱冷藏室可保存7天左右。", "关注微信号，有问题，马上回复哦！下厨房回复的慢！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/dc8f5098d57944c3bd649aa1e0acb96f_1632w_1224h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('婴幼儿补钙益脑——黑芝麻核桃酱', '热门专题', '婴幼儿', '', '[{"name": "黑芝麻", "amount": "75克"}, {"name": "核桃", "amount": "150克"}, {"name": "适量（可加可不加）糖", "amount": "适量"}]'::jsonb, '["75克黑芝麻清洗然后晒去多余水分备用", "150克核桃洗净晒掉多余水分。我儿子还小所以我没加糖哦，核桃外皮衣很有营养不要去掉哦", "核桃放入烤箱，150度上下火10分钟", "趁着烤箱烤核桃的时候我们先把芝麻倒入锅中炒数熟备用", "核桃烤好拿出。用酒瓶或者擀面杖敲碎核桃", "将敲碎的核桃与黑芝麻加入料理机。研磨几分钟你就会发现出油了哈哈", "大概这样就可以说拿到密封罐里了。大功告成"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/ae3f88bc40b24f4f9d493209c273266d_1280w_2702h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('婴幼儿辅食—南瓜馒头', '热门专题', '婴幼儿', '', '[{"name": "150--170g南瓜泥（黄色圆南瓜）", "amount": "适量"}, {"name": "面粉", "amount": "300g"}, {"name": "婴儿奶粉", "amount": "10g"}, {"name": "60--80g水（根据实际用量）", "amount": "适量"}, {"name": "酵母粉（我用的燕子牌）", "amount": "2.5g"}]'::jsonb, '["南瓜去皮去瓤切块上锅蒸20-30分钟至软烂。", "料理机或者料理棒打成泥，越细腻越好。", "将所有材料混合，用筷子先搅拌成絮状，再手揉或者机器（面包机厨师机）揉至表面光滑。面团软度应比饺子面团稍软，但是不要太软。", "室温发酵至", "8倍大。", "将发酵好的面团取出，分几次加入适量干面粉（我加了20g左右），将干粉揉进面团，排气完全，切开看横截面没有明显气孔。", "搓成长条，切段，上锅（垫油纸或者笼布）盖盖子醒发20-30分钟。开火，上汽后15分钟关火。焖三分钟后掀锅取出晾凉。", "分袋保存，冷藏三天，冷冻2周。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/3334637c626e4b70a98c5cd70f80772b_480w_384h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('宝宝健脾胃松软山药小饼（九个月以上婴幼儿辅食）全程不加一滴水', '热门专题', '婴幼儿', '', '[{"name": "1小节约150克山药", "amount": "适量"}, {"name": "白糖", "amount": "15克"}, {"name": "配方奶粉", "amount": "20克"}, {"name": "普通面粉", "amount": "150克"}, {"name": "（小）土鸡蛋", "amount": "2个"}, {"name": "酵母", "amount": "3克"}]'::jsonb, '["山药蒸熟去皮，放糖压成泥", "把鸡蛋面粉奶粉酵母全部放进山药泥里混合揉成面团", "把面团揉光滑后擀成饼", "拿瓶子压出一个个小饼", "总共做了26个，尺寸就是标准口径奶瓶大小，盖保鲜膜或者布发酵40分钟", "面团明显变大变轻就是发酵好了", "电饼铛预热，我只开了底部，把饼放进去，不用放油", "上色后翻面，两面都上色后用手指按一下饼，如果压下去能回弹原位，就是烤熟了，", "松软甜香的山药小饼就做好了", "非常好吃，即使放凉以后也不会硬"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/ddb34396f2ad4f26a8e3bcb303c549ca_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蒸馒头加一物，补钙又补铁！宝宝版芝麻酱花卷十个月以上婴幼儿辅食一次发酵法', '热门专题', '婴幼儿', '', '[{"name": "面粉", "amount": "200克"}, {"name": "酵母", "amount": "3克"}, {"name": "白糖（可不放）", "amount": "3克"}, {"name": "水", "amount": "100克"}]'::jsonb, '["面粉加入水酵母白糖厨师机低速揉光滑面团（彩色面团我做其他用，请忽略）", "面团擀长方形", "均匀的抹上芝麻酱（一岁以下不用加盐）", "上下对折", "切成两指宽", "把两个折叠在一起", "用筷子压下去", "轻轻拉长，用筷子把面剂子放上去", "把拉长的面剂子放筷子上转360度压下去就成花卷了", "放锅里发酵30-40 分钟，芝麻酱卷变大变轻就可以上火蒸了，中大火蒸15分钟闷5分钟", "暄暄软软，我家朵妞刚10个月，虽然只有两颗牙，吃花卷可老练了😃"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/a7cfa7a347714264ba3a56750fb96ae2_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“老鸭萝卜汤”的家常做法，天气冷了很适合老人孩子', '热门专题', '老人', '', '[{"name": "老鸭", "amount": "1只"}, {"name": "萝卜", "amount": "1条"}]'::jsonb, '["首先我们准备6个月左右的鸭子一只切掉脚掌黑色的物质和鸭屁股", "然后将鸭子剁成大小均匀的块备用\n同学们可以尽量剁大块一些", "准备白萝卜1个切掉头尾然后再切成大小均匀的滚刀块备用同学们白萝卜可以不用去皮（去皮太浪费）", "准备生姜1小块切成姜片备用", "再准备大葱2根切成小段备用", "首先我们在锅中加入适量的清水\n然后将剁好的鸭子冷水下锅焯水，中途加入适量的料酒开大火烧开，大火烧开之后再切去浮沫然后将焯好水的鸭子倒出备用", "然后我们把锅烧热，锅烧热之后加入适量的油滑锅，滑好锅之后将热油倒出之后再加入少许的底油，油温烧热后加入几颗青花椒，然后将焯好水的鸭子下锅转小火翻炒2分钟", "2分钟之后加入准备好的热水再加入切好的白萝卜和姜葱，然后开大火烧开", "大火烧开后再切去浮沫和多余的油脂\n然后把汤倒入小锅中再转小灶煮60分钟", "中途需要多次撇去浮沫和油脂", "中途再加入几颗红枣", "60分钟后揭开盖子加入适量的枸杞", "然后我们开始调味锅中加入食用盐2勺（约5克），加入少许胡椒粉调好味道之后即可出锅。", "一道营养丰富的老鸭萝卜汤就制作完成"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/49005205e09d4b4da07a5cf9712f1ae3_1668w_907h.png', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“汆水丸子”的家常做法，营养丰富，很适合老人孩子', '热门专题', '老人', '', '[{"name": "里脊肉", "amount": "300克"}, {"name": "料酒", "amount": "25克"}, {"name": "胡椒粉", "amount": "1克"}, {"name": "鸡蛋清", "amount": "2个"}, {"name": "食用盐", "amount": "4克"}, {"name": "红薯淀粉", "amount": "25克"}]'::jsonb, '["首先准备里脊肉300克\n将里脊肉切成厚片之后再剁成肉碎\n这一步剁得越细越好\n将剁好的肉碎放入盆中", "准备生姜1小块和适量的小葱头一起剁碎放入盆中备用\n加姜葱末的目的是去腥增香", "盆中加入料酒25克\n加入胡椒粉1克\n加入2个鸡蛋清之后将肉碎搅拌均匀", "拌匀之后加入适量的食用盐（约2克）\n加入适量的红薯淀粉（约25克）\n然后将肉碎朝着一个方向搅拌10分钟\n这一步的目的是让肉碎搅拌上劲", "下一步开始准备辅料\n准备适量的豌豆苗（自贡叫法）放入盆中备用\n准备适量的紫菜放入碗中加入清水浸泡\n加紫菜的目的是增加鲜味", "下一步开始制作\n首先我们在锅中加入适量的清水开大火烧开\n大火烧开之后将锅离火", "然后将肉碎挤压成大小均匀的肉丸依次下入锅中\n同学们肉丸必须在低于100度的时候下锅\n这样的目的是防止肉丸被煮碎", "肉丸下锅之后转中小火煮4分钟\n中途需要随时撇去多余的浮沫", "肉丸煮熟之后开始调味\n锅中加入食用盐2克\n加入少许胡椒粉\n调好味之后加入泡发好的紫菜", "然后转大火将水烧开后加入豌豆苗烫熟", "豆苗烫熟之后加入几滴明油即可出锅", "一道非常美味营养的汆水丸子就制作完成"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/099334d0df2e4c0aaa9088a8c8b760ca_1667w_939h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('老人孩子都爱的——香煎日本豆腐', '热门专题', '老人', '', '[{"name": "日本豆腐", "amount": "2条"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "尖椒", "amount": "1个"}, {"name": "蕃茄酱", "amount": "10克"}, {"name": "生抽", "amount": "2小勺"}, {"name": "白醋", "amount": "5滴"}, {"name": "白糖", "amount": "8克"}, {"name": "盐", "amount": "1茶匙"}, {"name": "小葱", "amount": "2根"}]'::jsonb, '["日本豆腐从中间切开，切成差不多厚度的，放进锅里煎", "等到一面差不多金黄了再翻面，尽量少动，太嫩了容易碎", "豆腐煎好了之后捞出来，锅里留适量底油。把洋葱和尖椒切成小粒", "把洋葱粒和尖椒放进去炒出香味。\n㊙️调汁：碗中加入2瓷勺番茄酱、1瓷勺生抽、1瓷勺陈醋、2茶匙白糖、1茶匙盐，然后将所有调料搅拌均匀。", "然后把煎好的豆腐放进去，倒入调好的酱汁", "让酱汁完全包裹住豆腐，收汁差不多的时候就可以关火了，撒上一点小葱，完美！又好看又好吃😋"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/010ae5ba459a4345ba6e85bbe4803c01_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“木须肉”的家常做法，营养丰富很适合老人孩子', '热门专题', '老人', '', '[{"name": "约200克里脊肉", "amount": "适量"}, {"name": "适量黄花菜", "amount": "适量"}, {"name": "适量黑木耳", "amount": "适量"}, {"name": "适量青瓜", "amount": "适量"}, {"name": "适量胡萝卜", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "适量蒜末", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}, {"name": "适量明油", "amount": "适量"}, {"name": "适量小葱", "amount": "适量"}, {"name": "适量食用盐", "amount": "适量"}, {"name": "少许料酒", "amount": "适量"}, {"name": "生抽酱油", "amount": "5克"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["首先我们准备里脊肉1小块（约200克）\n将里脊肉切成", "5毫米左右的片", "然后再切成细丝备用\n通常来说鲜肉在切的时候容易不规则\n时间充裕的同学可以将其放入冰箱冻2个小时再切\n切的时候将肉片整齐的码放起来\n肉片码得越平坦越好切", "肉丝切好之后加入清水清洗干净\n因为鲜肉中会有血水和杂质", "清洗干净之后挤干水份下一步准备腌制\n碗中加入少许食用盐和料酒", "然后将肉丝搅拌均匀收紧水份\n拌匀之后加入适量的植物油拌匀\n这一步的目的是让其下锅不粘连\n此菜不勾芡不加水\n所以在腌制肉丝的时候不用加淀粉和鸡蛋", "下一步开始准备配菜\n准备适量的黄花菜和黑木耳\n将泡发好的黄花菜和木耳撕开备用\n这一步的目的是为了更好的将其炒透", "准备适量的青瓜和胡萝卜切成菱形片备用\n同学们也可以将其换成玉兰片", "准备鸡蛋3个打入碗中", "加入少许食用盐搅散备用\n蛋液最好能够充分的朝着一个方向搅拌\n这样的目的是让空气进入\n让鸡蛋能承受高温煎制", "下一步开始制作\n首先我们在锅中加入适量的清水开大火烧开\n大火烧开之后加入准备好的黄花菜和木耳焯水40秒\n中途再加入少许的食用盐\n木耳属于菌类食物必须加热熟透\n否则快炒不熟透容易发生危险", "焯水熟透之后倒出备用\n然后把锅烧热\n锅烧热之后加入适量的植物油", "油温6成热之后将蛋液下锅煎至金黄干香\n同学们油多煎蛋必须开大火\n否则鸡蛋不发泡容易吸油", "中途再翻过来煎另一面\n鸡蛋煎香之后倒出备用", "锅中再次加入适量的油烧至4成热\n油热之后将其腌制好的肉丝下锅滑散\n肉丝滑散之后倒出备用", "锅中留下少许的底油\n然后加入适量的蒜末爆香", "蒜末爆香之后加入青瓜和胡萝卜炒至断生", "中途再加入木耳和黄花菜炒香炒出锅气", "辅料炒香之后加入处理好的肉丝和鸡蛋下锅", "然后加入生抽酱油5克从锅边淋入翻炒均匀", "翻炒均匀之后再加入适量的食用盐和白糖调味", "再加入适量的明油翻炒几下", "最后再加入几根小葱炒至断生即可出锅装盘", "一道口味丰富的木须肉就制作完成"]'::jsonb, 30, 120, '困难', 3, 'https://i2.chuimg.com/65fcaee11a8d4995a02bbc5cb9e633c5_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秒杀著名火锅店适合老人和宝宝的西红柿火锅汤底', '热门专题', '老人', '辣', '[{"name": "2-3个中等大小西红柿", "amount": "适量"}, {"name": "3-4茶匙植物油", "amount": "适量"}, {"name": "3-4茶匙番茄沙司", "amount": "适量"}, {"name": "淡盐生抽酱油", "amount": "2茶匙"}, {"name": "砂糖", "amount": "1茶匙"}, {"name": "1/2茶匙盐", "amount": "适量"}, {"name": "葱段", "amount": "2段"}, {"name": "姜片", "amount": "2片"}]'::jsonb, '["火锅里面注七八分满冷水，比平时的水量稍微少一点点就好。打开开关把水烧开，烧水的十几分钟时间准备西红柿酱就足够了。", "2-3个中等大小西红柿洗干净", "刀工好的就去皮切成小碎块，手懒的就直接切大块用食物处理器打碎", "不用打得太细，有一点块状物是没关系的", "中火热锅，倒入平时炒菜双倍的植物油，4汤匙左右", "油烧热不用冒烟，倒入刚才打碎的西红柿汁，中火翻炒至出沙", "加入4汤匙番茄沙司，炒匀", "继续加入半茶匙盐，1茶匙糖，炒匀", "加入2茶匙薄盐生抽酱油", "最后再扔进去两段葱，两片姜，翻炒至稍微粘稠", "然后就把这些蕃茄酱汁倒入烧开的火锅里面", "超级便捷简单健康又美味的番茄锅底就做好啦", "接下来就是开心的涮涮涮咯！"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/7901072936c14926b24d271eb0fda843_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('圆子汤', '热门专题', '孕产妇', '', '[{"name": "白萝卜", "amount": "500克"}, {"name": "肉馅", "amount": "150克"}, {"name": "100-150克豆腐（老豆腐、柴锅豆腐都可以，不能用内酯豆腐）", "amount": "适量"}, {"name": "少许姜末", "amount": "适量"}, {"name": "少许葱花", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许（若没有可用白胡椒粉代替或不加）草果粉", "amount": "适量"}, {"name": "几滴（不加也无妨）芝麻油", "amount": "适量"}]'::jsonb, '["准备好材料：白萝卜洗净去皮，肥瘦肉自己剁成细馅儿，豆腐一小块，姜末少许。", "豆腐不用切，加入肉馅儿和姜末、盐、草果粉，混合好味道，开始用手捏。", "要捏到肉馅和豆腐混合，豆腐一定要捏到很细，不然捏圆子的时候容易散。这点请特别注意！", "白萝卜切细丝，特别喜欢这样子细细的丝。", "切好的萝卜丝放小锅里直接加凉水（用矿泉水最好），此时开小火。用手把豆腐圆子一个个均匀的搓好放在萝卜丝表面。记住，一定是凉水直接煮萝卜！！", "待豆腐圆子全部捏完，调中火煮开七八分钟左右（视圆子大小调整），撒入葱花，滴两滴香油（不是必须），就可以出锅了。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e353d6d8886211e6a9a10242ac110002_2766w_2166h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('章墨鱼莲藕猪脚汤（滋阴補虚 全家汤＋孕产妇 汤）', '热门专题', '孕产妇', '', '[{"name": "约1.5斤猪脚", "amount": "适量"}, {"name": "约1斤鸡／排骨／猪龙骨（不喜猪脚，可更换这些肉类）", "amount": "适量"}, {"name": "50～75g 章鱼/墨鱼干", "amount": "适量"}, {"name": "莲藕", "amount": "500g"}, {"name": "25～50g以上花生", "amount": "适量"}, {"name": "5颗红枣", "amount": "适量"}, {"name": "姜片", "amount": "2片"}, {"name": "水", "amount": "适量"}, {"name": "香菇（加了更香）", "amount": "10个"}, {"name": "5～10个栗子（可不加）", "amount": "适量"}, {"name": "一大锅水", "amount": "适量"}]'::jsonb, '["准备并清洗好所有材料；\n猪脚用火烧烧毛并且焯水；\n不用猪脚，就代理用 猪龙骨／鸡／排骨\n章鱼/墨鱼 清洗干净，切小块，（如果墨鱼比较厚，可以提前泡一晚）；\n红枣，怕上火就去核；\n花生，提前泡洗2小时；", "先把猪脚中火煲开后小火煲一小时；\n再把其他材料，倒进去瓦锅里煲两小时；\n全程三小时，一分钟不能少，才能逼出汤的香浓味；", "3小时后，香浓的汤汤就煲好了~\n喝完就温暖了你整个冬天哈哈~ \n\n汤熬好后，可以把猪脚捞起来，加姜葱蚝油/四川豆瓣酱 爆炒一下~"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/64eeb6c089fa11e6a9a10242ac110002_702w_450h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超下奶补气补血猪蹄汤', '热门专题', '孕产妇', '', '[{"name": "猪蹄", "amount": "1只"}, {"name": "葱", "amount": "5根"}, {"name": "姜", "amount": "5片"}, {"name": "料酒", "amount": "2勺"}, {"name": "白胡椒", "amount": "2克"}, {"name": "（没有可以不放）人参", "amount": "2根"}, {"name": "5～6颗红枣", "amount": "适量"}, {"name": "20粒枸杞", "amount": "适量"}, {"name": "玉米", "amount": "1根"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["猪蹄斩块，清水泡1个小时，泡去血水，冷水入锅，加两片姜和葱，料酒焯水，水开后捞出来，温水洗一下，洗去杂质备用", "鲜人参（没有可以不放，可以放胡萝卜哈），葱姜红枣枸杞玉米洗净备用（玉米斩切成自己喜欢的大小，你要是喜欢整个放进去我也没意见😁）", "玉米切好", "汤锅加入足量的开水，放入猪蹄，参，红枣枸杞葱姜，盖上盖子，大火煮开，再放入玉米，煮开，改小火，煲1～1个半小时，至猪蹄软烂，开大火，加入适量的盐，白胡椒调味，加入适量的葱花，关火🔥。", "享用吧！", "真的好喝"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/9359de935fa4446d89b476b2e2bd3db7_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('炒米水（养生排毒减肥月子水）', '热门专题', '孕产妇', '', '[{"name": "大米", "amount": "100克"}, {"name": "小米", "amount": "50克"}]'::jsonb, '["小米跟大米的比例是 1:2", "可以把大米淘洗一遍，晾干后再炒。我是嫌麻烦，反正都是高温炒的，大不了泡的时候第一泡不要就是了。", "大米先炒5分钟后再加入小米一起翻炒，保持中小🔥，千万不要炒过头了 （炒15-30分钟）", "有一股浓浓的米香味，炒至大米微微有点焦黄色的时候就可以出锅了，以防万一炒焦不好。出锅装进干净的容器里冷却后放进冰箱冷藏，每天放两勺泡开水喝（一定要刚烧开的沸水泡，泡了以后闷一会再喝)", "孕妇和腹泻患者也可以喝的哟"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/27762a9bb66946128277b93b309e1895_3024w_2419h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孕产妇月子鸡汤（超简单，四味料就可以做）', '热门专题', '孕产妇', '', '[{"name": "四分之一只带骨鸡块 （整鸡剁出来的）", "amount": "适量"}, {"name": "一小把（可不加）干黄花", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "十片左右（多放没关系）姜片", "amount": "适量"}, {"name": "（可不加）鸡精", "amount": "适量"}]'::jsonb, '["把鸡块🐔洗净，管它带皮带骨还是带肥油，都往锅里放，简单粗暴。我是冷水开始给它煮，还放了五六片姜片一起煮的。\n（如果是家里用🔥燎过一次的鸡，我觉得皮味道很重，建议焯水后重新加冷水炖）", "水开了后，有些浮沫，可以去掉（我当时没去掉，而且我的鸡肉是冻过解冻的，好像也没啥血水，所以就没焯水了）。搅拌了几下，浮沫都下沉了，我就直接将这些开水和鸡肉全部倒炖锅，炖锅里又放了七八片姜片，还有约一汤勺料酒（重复尝试后发现可不加，因为有姜片了，不喜欢料酒的可以不用），去腥。\n喜欢多喝汤的，还可以多加点开水进去一起炖。", "开动砂锅鸡鸭档，大概一小时十分，让他自己炖，要喝的时候，加盐，试味，口味重就多点盐，还可以加少量鸡精。（喜欢吃鸡肉的，可以早点加味道，还可以再炖久一点，鸡肉更入味٩(๑^o^๑)۶）\n我妹口味重，让我给她汤碗里又加了一点盐和鸡精，她很喜欢。（哺乳期建议少吃鸡精，因为影响宝宝吸收锌）\n我口味淡，只有盐。而且也没很多，但我依然觉得很鲜很香。٩(๑^o^๑)۶"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/1837d53e5a4146989c6fa23b1f779b7b_912w_684h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('山药小饼——宝宝健脾养胃早餐饼', '热门专题', '宝宝食谱', '', '[{"name": "（去皮后）山药", "amount": "330克"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "糖", "amount": "20克"}, {"name": "中筋面粉", "amount": "300克"}, {"name": "奶粉", "amount": "20克"}, {"name": "酵母", "amount": "5克"}, {"name": "玉米油", "amount": "20克"}]'::jsonb, '["山药洗干净，去皮，切断，放入蒸笼中（这时的山药是330克）。大火烧开后蒸10分钟左右，用筷子轻松扎透就是蒸好了。", "蒸好的山药用勺子压成泥，不能有颗粒。", "山药泥中倒入中粉、白砂糖、奶粉、鸡蛋、酵母和玉米油。", "用筷子搅拌成絮状，再用手揉成一个光滑的面团，覆盖保鲜膜松弛10分钟。", "将松弛好的面团放到揉面垫上，撒一层手粉，将面团擀成薄面片，约5mm左右的薄片，擀均匀一点。", "用圆形模具压出形状，我做的是小饼，用的是3cm的模具。也可以用大点的模具来压出形状，但是厚度要随着山药饼的大小适当调整。", "将压好的小圆形摆入烤盘，覆盖保鲜膜，送至温暖处醒发。", "现在天气热，我是室温醒发50分钟左右，看到面片明显变胖，用手指轻轻摁压，会有慢慢的回弹，就发酵完成了。", "将小饼放入不粘锅内，锅内不要抹油，不要抹油，不要抹油，重要的事情说三遍。开小火慢慢煎，煎的过程中可以盖上锅盖，让锅内的温度更加均衡。", "一面煎成金黄色，翻面，小火继续煎。", "两面都煎成金黄色就可以出锅了。", "一个个软乎乎的山药小饼就做好了，超松软哟！", "掰开一个看看，内部蓬松，捏一下，回弹超好，相信你一定能看得出来它是有多松软！", "赶快给宝宝吃一个吧！"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/e34338b7c58a4018bf3d94fcfc345ad2_3551w_2000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('宝宝辅食：土豆时蔬软肠', '热门专题', '宝宝食谱', '', '[{"name": "土豆", "amount": "80克"}, {"name": "胡萝卜", "amount": "20克"}, {"name": "菠菜", "amount": "10克"}, {"name": "低筋面粉", "amount": "10克"}, {"name": "（约58克）鸡蛋", "amount": "1个"}]'::jsonb, '["首先准备好食材，", "胡萝卜切丁、土豆切片切丁都可以，怎么快速蒸熟怎么切，因为土豆是要捣成泥状的。", "胡萝卜、土豆放蒸格上蒸熟。蒸是为了避免营养流失太多。", "菠菜焯水，然后切碎。", "土豆用勺子捣成泥状，", "鸡蛋敲入碗中，加入胡萝卜丁、菠菜丁、以及低筋面粉，一起搅拌均匀；", "搅拌均匀备用。(不同的土豆吸水性不同，配方中的水份根据实际情况进行调整，低筋粉可以增加5-10克之间)", "装进裱花袋", "模具底部稍微刷一下油，防止粘上。", "裱花袋剪口，挤面糊。再震两下，盖上盖子。（天黑了，还未开灯拍的，略过模具的颜色哈）", "锅中倒入清水，放蒸格上，中小火蒸20分钟即可。", "出锅了，迫不及待地打开，颜色真的好好看😄", "而且特别地软，蓬松的感觉。", "如果超过一岁有添加调味的宝宝，可以适当加一点盐或者糖。"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/a88819c811e548c08e2158b33a55826a_828w_1104h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('山药红枣糕(宝宝辅食)', '热门专题', '宝宝食谱', '', '[{"name": "红枣", "amount": "20克"}, {"name": "山药", "amount": "90克"}, {"name": "鸡蛋", "amount": "1个"}]'::jsonb, '["将去皮的山药，红枣(去皮不去皮都可)，鸡蛋全部放入搅拌机里搅打3分钟以上。", "玻璃碗模具铺油纸，刷油。", "倒入打好的糊糊，盖上保鲜膜，用牙签扎小孔。", "上锅蒸20分钟左右。最后脱模切块。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/6ed17d6079754d24be2602f987e72768_2866w_2294h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('一岁宝宝辅食：奶香南瓜饼', '热门专题', '宝宝食谱', '', '[{"name": "南瓜（去皮）", "amount": "100克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "婴儿奶粉", "amount": "3勺"}, {"name": "低筋面粉", "amount": "50克"}]'::jsonb, '["南瓜去皮去瓤切片，大火5分钟蒸熟，再用辅食机打成泥。", "南瓜泥里添加鸡蛋、奶粉、面粉，搅打成中等黏稠度的面糊", "平底煎锅，不放油，锅热后转小火，用不锈钢汤勺舀一勺面糊到热锅上，盖上盖子，1分钟后一面煎熟，翻另外一面再煎1分钟或时间更短些。像这个样子就熟了。翻面的时候，用刮刀铲、用筷子辅助，会很迅速且不会弄破面饼。", "摆盘就可以开吃啦～软嫩清香，色泽金黄，宝宝爱吃！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a66188006ccc4934b2a8c04e297e78ce_2160w_2880h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('儿童无辣鱼香肉丝(鱼香汁)', '热门专题', '宝宝食谱', '辣', '[{"name": "一块瘦肉", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "5-6朵木耳(提前泡发洗净)", "amount": "适量"}, {"name": "香菜或柿子青椒醋", "amount": "适量"}, {"name": "香醋", "amount": "1勺"}, {"name": "半勺淀粉", "amount": "适量"}, {"name": "糖", "amount": "2勺"}, {"name": "香菜", "amount": "3根"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "耗油", "amount": "1勺"}, {"name": "番茄酱", "amount": "1勺"}, {"name": "2-3勺清水", "amount": "适量"}]'::jsonb, '["瘦肉切丝，可以用猪里脊或者鸡胸肉。\n用五香粉，盐，淀粉，老抽，料酒拌匀腌10分钟入味。", "另取一只碗，调鱼香汁：\n糖2勺，醋1勺，耗油1勺，生抽2勺，番茄酱1勺，清水2勺", "锅里放入平时炒菜那么多的油。烧热。", "油热后把姜丝煸香。底油有味，菜才会好吃。不吃姜的可以把煸干的姜丝捞出来。", "下入肉丝，滑散。", "滑散的肉丝，变色后，盛出。尽量把底油留下。", "肉丝盛出后，锅里还剩这么多油。其实肉丝不吸油。底油足够用。如果这时候你的底油不多了，可以酌情加一点。", "油热后，放入胡萝卜和木耳丝。\n如果不喜欢胡萝卜可以换成青笋丝。", "胡萝卜丝炒软以后，木耳也熟了。", "放入之前过油了的肉丝。翻炒均匀", "倒入之前调好的鱼香汁。", "开中火，收汁，直到粘稠。", "放入香菜，翻拌片刻。即可出锅。\n如果不爱吃香菜可以换成绿色的柿子椒。", "一份色香味俱全的儿童版鱼香肉丝就OK了。\n超级下饭哦(´-ω-`)"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/b85eaa5b1e5f4409ac2a46f8964e190a_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('优益C百香果汁', '热门专题', '味蕾工坊', '', '[{"name": "百香果（大）", "amount": "4个"}, {"name": "一瓶优益C", "amount": "适量"}]'::jsonb, '["挖出4个百香果的果肉，放在杯子里，冲入一瓶优益C，搅拌即可～嘿嘿", "完成效果图～", "尽情畅饮吧～～～😁"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/edced9cddc784d42ab98f44d81cc8cc0_4032w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('传统做法做水磨年糕（含视频）', '热门专题', '味蕾工坊', '辣', '[{"name": "大米", "amount": "500克"}]'::jsonb, '["材料只需要大米，做水磨年糕用晚粳米更加好吃，就是这种短小粗圆的，不要用长米", "把清洗干净的大米加水，浸泡三个小时，或者提前一晚浸泡。", "用漏勺舀起沥干水份，放入料理机中", "加入没过大米的清水，开始打米浆，传统的打米浆，是用米加水用石磨磨出来的，我们就用料理机代替，加水打出来的米粉更加的细腻", "打好的米浆倒入一个碗里，料理机一次性打不完的，分几次打", "在一个底部带孔的蒸锅上，放上一块大纱布，把米浆倒在纱布上", "扎紧收口，纱布要用织的很密的那种，这样米粉漏出的就少些", "上面压一碗水，可以更快的挤去米浆里的水份", "大约1-2小时以后，米浆中多余的水分基本沥干，得到干燥的米粉，把米粉搓进一个碗里", "加入少量的开水，揉成一个比较柔软的面粉团，软硬程度和橡皮泥差不多", "放入蒸锅中，盖子上面扎一块布，可以避免水蒸气滴到年糕里面，水开后，大火蒸30分钟，直到米粉团熟透", "在案板上抹上少许的植物油，把蒸好的米粉团趁热倒在上面，找一个石杵或者擀面杖，就可以开始打年糕了，年糕打的越用力，时间越久，越Q弹，在打的过程中将年糕翻面几次，可以经常抹上少许植物油防粘", "打到你觉的差不多的时候就可以开始整形了，这里我把他分成二部分，一部分用来做切片年糕，一部分用来做长条状的韩式年糕", "做切片年糕搓成直径约3厘米的圆桶状，做长条状的年糕搓成直径约", "5厘米的长条状", "把长条状的切成条，放入保鲜盒中，放入冰箱冷藏隔夜后，年糕会自然变硬定型", "把定型好的年糕把取出来，3厘米的切成片", "再把他们放到冷冻室里保存，可以放很久"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/5a4ead10a2724f26be9235ba2c4fcf3f_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('菠萝饭', '热门专题', '味蕾工坊', '', '[{"name": "一个菠萝", "amount": "适量"}, {"name": "一小碗糯米", "amount": "适量"}, {"name": "10颗泡发枸杞", "amount": "适量"}, {"name": "若干粒洗净葡萄干", "amount": "适量"}, {"name": "少许白砂糖", "amount": "适量"}]'::jsonb, '["糯米要提前浸泡2个小时，只有浸泡足够时间才能保证软糯口感", "把泡好的糯米放进电饭煲中，煮的时候少放点水，这样煮出来的糯米才能颗颗剔透饱满。大概煮15分钟。或者根据自家的电饭煲时间，按照正常流程煮饭", "同时，我们把菠萝的外皮洗干净，切掉顶部的一小块当盖子，挖空里面的菠萝肉，取部分菠萝切块备用，剩下的一半榨汁备用", "这边，把煮好的糯米饭晾凉后，加上一点白糖，枸杞、葡萄干和菠萝肉，再倒上菠萝汁拌匀，装进菠萝盅", "最后一步，盖上菠萝盖子，放入蒸锅，蒸15分钟即可"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/a6f01cce878611e6a9a10242ac110002_480w_270h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('茶叶蛋', '热门专题', '味蕾工坊', '', '[{"name": "鸡蛋", "amount": "5个"}, {"name": "一小把茶叶", "amount": "适量"}, {"name": "3粒大料", "amount": "适量"}, {"name": "适量甘草", "amount": "适量"}, {"name": "一小块桂皮", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量酱油", "amount": "适量"}]'::jsonb, '["把鸡蛋洗干净，放进水中煮到八成熟", "捞出鸡蛋在冷水里浸上两分钟，再捞出来", "电饭煲里放入茶叶、大料、冰糖、甘草、桂皮等调料，然后放入鸡蛋，加酱油，随后加盐。注入清水，淹没所有食材", "设定20分钟。不用电饭煲，用其他锅子也是一样的做法，明火上煮的话建议煮30分钟以上", "茶叶蛋煮好后，轻轻敲碎蛋壳，在卤水里多泡几个小时，这样会更入味。也可以把蛋放在锅中保温浸泡一夜"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/a7c4a732878611e6b87c0242ac110003_480w_270h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('大盘鸡', '热门专题', '味蕾工坊', '', '[{"name": "一只（洗净切块）公鸡", "amount": "适量"}, {"name": "适量精制油", "amount": "适量"}, {"name": "（洗净去皮切成滚刀块）土豆", "amount": "2个"}, {"name": "各1个（洗净切块）青红辣椒", "amount": "适量"}, {"name": "1颗大葱", "amount": "适量"}, {"name": "若干姜蒜", "amount": "适量"}, {"name": "一把朝天椒", "amount": "适量"}, {"name": "适量花椒", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "，桂皮", "amount": "1块"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许白砂糖", "amount": "适量"}, {"name": "少许豆瓣酱", "amount": "适量"}, {"name": "一小杯啤酒", "amount": "适量"}, {"name": "皮带面", "amount": "适量"}, {"name": "适量红干辣椒", "amount": "适量"}, {"name": "适量孜然", "amount": "适量"}, {"name": "鸡精", "amount": "适量"}, {"name": "酱油", "amount": "适量"}]'::jsonb, '["首先，起热油锅，把花椒下锅煸香后捞出备用", "接着把白沙糖放下锅，并慢慢搅动，直到融化呈焦黄色", "把鸡块倒进去，大火翻炒一会儿；再倒入生姜、朝天椒，酱油给鸡块上色，一起下锅来回翻炒", "加入豆瓣，再加入少许盐，快速翻炒几下", "然后，我们把鸡肉倒进电压力煲里，并把土豆、辣椒、八角和桂皮倒进锅里，在加一些孜然和炒好的花椒，放入清水淹没食材。在倒入啤酒，最后盖上锅盖，选择鸡肉键，设置15分钟。不用高压锅的话，就需要在明火上炖煮久一些了，大约半个小时，至鸡肉熟透、土豆变软", "在等的同时可以煮面，煮熟备用", "开盖放入鸡精拌匀后，倒上皮带面就可以出锅啦"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/aaa17d04878611e6a9a10242ac110002_480w_270h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('零失败6寸8寸戚风蛋糕 （成功率100%）', '烘焙甜品饮料', '蛋糕', '', '[{"name": "6寸", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "牛奶", "amount": "40克"}, {"name": "玉米油", "amount": "35克"}, {"name": "低筋面粉", "amount": "50克"}, {"name": "糖", "amount": "30克"}, {"name": "几滴柠檬汁", "amount": "适量"}, {"name": "8寸", "amount": "适量"}, {"name": "鸡蛋", "amount": "5个"}, {"name": "牛奶", "amount": "85克"}, {"name": "玉米油", "amount": "40克"}, {"name": "低筋面粉", "amount": "100克"}, {"name": "30糖", "amount": "适量"}, {"name": "几滴柠檬汁", "amount": "适量"}]'::jsonb, '["如图准备好以下材料，分别将牛奶、玉米油、糖、低筋粉用秤把克数称好，配方在上面可以直接照着做", "准备一个干净的盆，将牛奶和玉米油倒入盆中疯狂搅拌至乳化", "筛入低筋面粉，搅拌均匀", "将鸡蛋清蛋黄分离，倒入分离好的蛋黄，把蛋清放入冰箱冷藏5分钟", "搅拌至面糊顺滑滴落有轻微堆叠状", "将冰箱冷藏过的蛋清用打蛋器打发至大气泡，加第一次糖，打蛋器中速继续打发", "继续打发蛋白有淡淡纹路，加第二次糖低速继续打发", "打发至出现明显纹路，加第三次糖，继续用低速打发，边缘也要打到，打不到的地方那刮刀刮到中间打发，保证每个部位都打发充分！", "打发成直立小尖勾", "取三分之一蛋白加入蛋黄糊中搅拌均匀，可以用打蛋器轻轻搅拌", "再将剩余的蛋白分次倒入蛋黄糊中，用打蛋器轻轻搅拌至无白色颗粒丝滑状", "翻拌好的面糊倒入6寸磨具中", "将另一半倒入8寸模具中，轻轻震几下，用牙签在表面来回画圈圈以此来消除表面的泡泡。", "烤箱145度烤45分钟，这个温度烤出来的戚风蛋糕面上会裂开，可以试试140度烤45分钟，根据自己家烤箱的脾气。", "取出烤好的蛋糕出炉重摔三下!!!震出热气后马上倒扣放凉！倒扣后等完全晾凉后再脱模！", "烤出来的6寸非常漂亮", "8寸也很漂亮"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/55918407e036474eab2ca546096fa274_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('8寸戚风蛋糕', '烘焙甜品饮料', '蛋糕', '', '[{"name": "鸡蛋", "amount": "5个"}, {"name": "牛奶", "amount": "60g"}, {"name": "玉米油", "amount": "50g"}, {"name": "面粉", "amount": "90g"}, {"name": "白砂糖", "amount": "60g"}]'::jsonb, '["准备好工具，大概就这些，精简就好", "盆中先打入5个鸡蛋，然后放冰箱冷冻", "碗中加入60g牛奶、50g玉米油", "用蛋抽搅匀", "加入低筋面粉90g，“Z”字形手法搅拌均匀", "从冰箱拿出冷冻的鸡蛋，将5个蛋黄捞出", "蛋抽“Z”字形手法搅拌", "蛋白打发", "打至出现泡泡，加入白砂糖20g", "打至细泡，再加入白砂糖20g", "打出出现纹路，加入最后20g白砂糖", "继续打发，直到提起打蛋器出现小弯勾", "蛋白打发好后，这个时候可以来预热烤箱，上下火160度，45分钟", "蛋白分出一半先加入蛋黄糊中，翻拌均匀", "将翻拌均匀的蛋黄糊倒入剩下打发好的蛋白中", "翻拌均匀", "倒入8寸蛋糕模具中", "放进预热好的烤箱，上下火160度烤45分钟", "烤好后，拿出轻震一下，倒扣晾凉，等蛋糕凉后再从模具中取出", "蛋糕体很松软，回弹好"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/69bc9182e3b6475ea071721d83fffa72_1231w_977h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('可以开店的提拉米苏（熟蛋版）', '烘焙甜品饮料', '蛋糕', '', '[{"name": "蛋黄", "amount": "2个"}, {"name": "砂糖", "amount": "45g"}, {"name": "马斯卡彭芝士", "amount": "250g"}, {"name": "淡奶油", "amount": "180g"}, {"name": "咖啡粉", "amount": "6g"}, {"name": "—10ml朗姆酒", "amount": "5ml"}, {"name": "一包手指饼干", "amount": "适量"}, {"name": "适量可可粉", "amount": "适量"}]'::jsonb, '["开始前准备物料，咖啡我家里的太久没用长霉了，找了包速溶咖啡粉代替", "蛋黄分离+10g砂糖打发", "打发到这个状态，糖融化", "50g水+35g砂糖", "小火融化砂糖再煮沸，50秒，变成糖浆", "将煮沸的糖浆冲入打发的蛋黄中，所以不用担心蛋黄是生的，这一步跟很多方法都不同", "放一旁备用", "称250g马斯卡彭芝士，打顺滑", "这种状态", "放入备用的蛋黄糖浆中", "搅拌均匀", "均匀后是这个状态", "180g淡奶油打6分发，图上状态，开始有稳定的纹路，千万不要打过了，奶油发硬的状态在一瞬间，快到的时候调整档位，慢慢打", "将打发好的淡奶油加入到之前的芝士糊里", "用刮刀搅拌均匀成细腻的芝士糊，手法如视频，不要打圈搅拌，要翻拌，像炒菜那样", "最后芝士糊状态", "很细腻，备用", "8g咖啡粉+40g热水冲成咖啡液，因为儿子吃没有放朗姆酒，要放朗姆酒的这里加5-10g根据自己的口味调", "在容器中放入成品手指饼干，我个人觉得买的手指饼干上面有糖霜太甜了，可以自己做或者用戚风代替，我之前开店是用的戚风，但买的更简单，或者减少配方中的糖", "刷咖啡液，我觉得最好是用夹子把手指饼干在咖啡液里滚一下，更湿润好吃，刷的话只能刷到单面，但不要全部泡在里面会太稀软了", "将芝士糊装入裱花袋挤入容器，再铺一层，刷咖啡液", "做了两个保鲜盒，放入冰箱冷藏", "4个小时之后会凝固，配方中的马斯卡彭芝士和打发后的淡奶油都会让芝士糊凝固，不用吉利丁片", "撒上法芙娜可可粉，我觉得法芙娜的可可粉最好吃，其他的差点意思", "开吃，对了，多的两个蛋清可以做双皮奶，拜拜～希望大家都能做出自己喜欢的提拉米苏"]'::jsonb, 30, 125, '困难', 3, 'https://i2.chuimg.com/2e6a346c589047c2b3290f2b10351b19_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鲜奶糯米蛋糕', '烘焙甜品饮料', '蛋糕', '', '[{"name": "糯米粉", "amount": "80g"}, {"name": "4颗鸡蛋", "amount": "适量"}, {"name": "细砂糖", "amount": "45g"}, {"name": "牛奶", "amount": "75g"}, {"name": "玉米油", "amount": "35g"}, {"name": "适量柠檬汁", "amount": "适量"}]'::jsonb, '["盆中倒入牛奶和玉米油，搅拌 充分，使二者充分乳化。\n乳化到融合即可。\n（二者充分融合以后的状态即为乳化状态）", "将过筛后的糯米粉倒入乳化后的牛奶内。\n搅拌均匀。\n可能此时会比较干巴，不好搅拌，但是没事。", "在步骤2的基础上，加入分离后的鸡蛋黄。\n这个时候就会很好拌开了。\n搅拌均匀后呈现图中这样，比较丝滑的状态。", "预热烤箱150度", "将蛋白中加入点柠檬汁去腥，如果没有柠檬汁，可以用白醋替代。\n然后白糖分三次加入蛋白中打发。", "将蛋白打发至细腻的大弯钩状态即可", "将打发后的蛋白取1/3加入蛋黄液中。搅拌均匀。", "搅拌均匀后，将其倒入剩余蛋白中，翻拌均匀。", "装入容器中入烤箱烘烤。\n150度，25分钟，\n转160度，再烤5分钟上色。", "大功告成！"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/2e6fbcea9c024df596a0c3b8a1b2be3f_966w_1028h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('古早蛋糕、千叶纹蛋糕（童年回忆！）——烫面法', '烘焙甜品饮料', '蛋糕', '', '[{"name": "（每个55-60克）鸡蛋", "amount": "8个"}, {"name": "牛奶", "amount": "115克"}, {"name": "玉米油（加热至70℃）", "amount": "75克"}, {"name": "低筋面粉", "amount": "145克"}, {"name": "白砂糖", "amount": "90克"}, {"name": "玉米淀粉（可不加）", "amount": "10克"}, {"name": "柠檬汁", "amount": "5克"}, {"name": "可可粉", "amount": "2克"}]'::jsonb, '["（蛋清蛋黄分离，蛋清放冷冻到有冰渣）\n\n低筋面粉过筛放入盆中，油加热到70-80℃，倒入面粉中，快速搅匀\n\n用烫面法做出来的古早蛋糕更加柔软轻盈！", "倒入牛奶，搅匀\n\n➕蛋黄，继续搅匀，提起打蛋器是这种状态", "开始打发蛋白，挤入柠檬汁\n\n先开高速打至有鱼泡眼，➕1/3糖\n继续打到有小气泡，➕1/3糖\n中速打至有纹路，➕剩下的糖\n\n开低速整理纹路，用刮刀刮一下盆壁，打至有小尖尖！干性打发（我试过打到足够发，不会回缩塌陷）", "取1/3蛋白放入蛋黄糊中翻拌均匀，倒入剩余蛋白中，混合均匀 倒入模具中！\n\n25克面糊➕可可粉混合均匀，倒入裱花袋，剪一个小口子！\n\n裱花袋口子不要贴面糊太近，倾斜45度，拉长条", "拿根筷子垂直方向，划出千叶纹路", "烤箱提前预热，145℃，60分钟\n放中下层，最后10分钟，➕10℃开热风\n\n⚠️密封性好的烤箱，夹锡纸棒", "出炉，震出热气\n我没有用油纸，倒扣晾凉至手温，脱模，晾凉切块\n\n如果是垫了油纸，出炉直接拿出来放在晾网上晾凉再撕开油补", "切块，完美！密封冷藏保存", "比戚风蛋糕绵密湿润"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/99f43ef7dd464dbfb5d4b0a9447e2643_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蓝莓吐司面包（免手揉版）', '烘焙甜品饮料', '面包', '', '[{"name": "高筋面粉", "amount": "280g"}, {"name": "牛奶", "amount": "165g"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "白糖", "amount": "25g"}, {"name": "酵母", "amount": "3g"}, {"name": "奶粉", "amount": "10g"}, {"name": "黄油", "amount": "25g"}, {"name": "盐", "amount": "3g"}, {"name": "紫薯粉", "amount": "3g"}, {"name": "适量蓝莓酱", "amount": "适量"}]'::jsonb, '["牛奶165g+鸡蛋1个+白糖25g+酵母3g（夏天一定要用冰牛奶）", "搅拌均匀", "再让入高筋面粉280g+奶粉10g（我第一次做没有放奶粉，口感也影响不大）", "混合到没有干粉时，再加黄油25g+盐3g（带pvc手套，不然太粘手了，先可以用抓的方式把黄油抓紧面团里）", "分成2个面团，白色面团揉成团后，就用保鲜膜盖住放冰箱冷藏", "另外一个加入紫薯粉团（紫薯粉3g用一点点水混合成团）", "甩打到颜色均匀就行了，同样也是用保鲜膜盖住放冰箱冷藏（30分钟）", "时间到了拿出来看看，是不是有薄膜了，然后2个面团再开始室温（夏天）发酵至2倍大", "发酵好后，撒上少量高筋面粉，再用手掌给两个面团排气", "再把两个面团杆成差不多一个大的长方形（我这步做得有点粗糙，嘿嘿）", "白色面团放蓝莓酱（蓝莓酱是我自己熬的）", "再把紫色面团盖上去", "切成6条，顶部要预留一些", "再像扭麻花一样全部扭起来", "再整下型，", "从上往下卷", "全部卷好", "放进吐司烤盘", "再次发酵到7分满，进烤箱，180度25分钟（中途上色了就用锡箔纸盖上）", "包装完成"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/b9b0c0265f9046199a0a9a3872b65307_1280w_1707h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('满屋飘香的爱心椰蓉面包！椰蓉面包yyds！', '烘焙甜品饮料', '面包', '', '[{"name": "面团部分：", "amount": "适量"}, {"name": "高筋面粉", "amount": "310克"}, {"name": "牛奶", "amount": "185克"}, {"name": "全蛋液", "amount": "35克"}, {"name": "鲜酵母", "amount": "10克"}, {"name": "细砂糖", "amount": "35克"}, {"name": "盐", "amount": "4克"}, {"name": "奶粉", "amount": "10克"}, {"name": "黄油", "amount": "30克"}, {"name": "椰蓉馅：", "amount": "适量"}, {"name": "蛋黄液", "amount": "60克"}, {"name": "细砂糖", "amount": "45克"}, {"name": "奶粉", "amount": "15克"}, {"name": "椰蓉", "amount": "75克"}, {"name": "黄油", "amount": "45克"}]'::jsonb, '["首先准备好所需食材\n厨师机桶中倒入面团材料（除了黄油和盐以外）", "慢速搅拌成团后转中高速揉面", "揉至可以拉出厚膜", "加入软化的黄油和盐慢速搅拌至吸收，转中高速揉面", "揉至可以拉出薄膜即可", "面团送入发酵箱发酵至2倍大小", "将面团分割成9个揉圆盖保鲜膜松弛15分钟", "制作椰蓉馅，蛋黄液加入细砂糖和奶粉搅拌均匀", "倒入椰蓉拌匀", "倒入软化的黄油拌匀", "将椰蓉分成9个，送入冰箱冷藏", "面团松弛完毕，拍扁后包入椰蓉馅", "取一个面团擀开，尽量擀大一点", "翻面对折", "再次对折", "用锋利的刀切口", "将面团往两边翻开", "全部同样的操作，放入烤盘中，送入发酵箱36度发酵", "发酵至2倍大小，表面刷一层蛋液", "送入提前预热好的烤箱，上火190度下火180度烘烤15分钟左右，每个人的烤箱不同，烘烤时间温度仅作为参考！", "出炉后轻震烤盘，放凉即可食用！"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/245592b4599e4fbcb80cd724fe2526c3_1701w_1361h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('青柠乳酪面包口感清新酸甜｜超级适合夏天', '烘焙甜品饮料', '面包', '酸', '[{"name": "高筋面粉", "amount": "250克"}, {"name": "抹茶粉", "amount": "5克"}, {"name": "鸡蛋液", "amount": "50克"}, {"name": "140-155克牛奶", "amount": "适量"}, {"name": "细砂糖", "amount": "25克"}, {"name": "鲜酵母/或高糖干酵母3克", "amount": "7克"}, {"name": "盐", "amount": "3克"}, {"name": "黄油", "amount": "25克"}, {"name": "奶油奶酪", "amount": "250克"}, {"name": "糖粉", "amount": "20克"}, {"name": "柠檬汁", "amount": "2克"}, {"name": "青柠檬皮屑", "amount": "5克"}, {"name": "适量柠檬皮屑", "amount": "适量"}, {"name": "柠檬片", "amount": "4片"}]'::jsonb, '["塔希提青柠檬，用盐搓洗干净后，用刨丝器擦出柠檬皮屑，不要白瓤，会苦，只要绿色的皮。", "奶酪软化后，加入糖粉，刮刀拌匀", "挤入柠檬汁，加入柠檬皮屑", "刮刀拌匀", "装入裱花袋，冷藏备用。", "除去盐、酵母、黄油，其他食材全部加入海氏M6厨师机。", "机器定时7-8分钟，\n2档打10秒，\n转3档打10秒，\n转4档打10秒，\n转5档打30秒，此时面团成团无干粉，\n转6档打6-7分钟，打到7-8成筋，破洞锯齿的粗膜状态", "⚠️⚠️夏天打面一定要控制面温，刚才咱们没提控温，是因为没放酵母，这一步测温，温度一定是超过24度了，面团拿出来平铺在金属保鲜盒里，密封好，拿去冷冻降温到面团15度再打。\n\n降温后放入厨师机，加入盐、黄油、酵母（酵母包裹进面团，不直接接触黄油和盐）", "定时5-6分钟。\n直接4档打1分钟，\n转5档打1分钟，食材基本全部吸收，\n转6档3-4分钟，打到9-10成筋，破洞光滑的手套膜状态", "出缸收圆，面温控制在24-26度之间最好，不超过26度。\n我这个中途冷冻时间久，冷冻到10度了，打好面温有点低，问题不大，可以延长发酵时间。", "放入28度环境进行一发（夏天室温就够了，太热的开空调）\n面团发酵至体积2倍大，筛干粉防粘，戳洞缓慢回缩就是发好了", "发酵完成移到操作台上，不破坏光滑面。\n切割成8等份，63克左右/份", "筛一层干粉防粘，轻拍排气，全部收圆", "放入26-28度环境松弛20分左右", "松弛后的面团表面撒点干粉防粘（台面不要撒，会打滑，擀不开）", "擀面杖擀成圆形", "翻面，挤入30克奶酪\n（馅料不全部用完哦，留一点点入炉前装饰用）", "上下捏合，像捏饺子一样，多捏2遍，防止爆开。", "翻面，两头轻轻搓一下，整理成橄榄状，如果沾手就撒点手粉", "全部做好，留出空隙，摆入烤盘。\n密封好，放入30-35度环境中，进行二次发酵。", "发酵至体积", "8倍大，不用发太大，容易空心", "表面筛一层面粉装饰，用锋利的刀片从面团中间割一条，别割太浅，稍微有点深度，但是不露出馅料。把剩下的奶酪馅挤在中间。", "放入预热好的烤箱，卡士750S，不垫蓄热板，三能1314烤盘，中下层，上火130，下火190（原装烤盘用下火180），烤15-20分钟\n\n⚠️其它家用烤箱参考，上火150-170，下火180，烤15-20分\n\n⚠️这款面包要保持绿色不变色更好看，可以入炉时就盖锡纸，全程盖着。也可以入炉5分钟后盖锡纸（如图，锡纸放在上层烤网上，不会破坏面包表面，也不影响观察）", "特写镜头", "出炉后立刻震盘，冷却。\n入炉前挤的装饰奶酪不会自己摊开，出炉后用小抹刀在两侧抹匀。表面再擦点柠檬皮屑装饰，摆上半片柠檬装饰。", "这是一款非常清新酸甜的面包，面包体很松软，中间夹着细腻丝滑的青柠乳酪馅，柠檬味清香扑鼻，吃一口太清爽了，口感很惊艳，舌尖瞬间被这抹酸甜俘获！酸甜正合适！\n这是属于夏天的独特味道！为夏天而生的面包！吃一口忘不掉，回味无穷，太好吃了！快来安排吧", "⚠️⚠️保存方法：\n装袋密封起来，放入冰箱-18°C冷冻保存。\n不能冷藏，冷藏吐司老化快，容易变硬。\n吃之前室温解冻后直接吃，非常柔软。\n微波炉中火叮30-50秒，整体都更软更好吃！", "好吃又好做，快来跟做吧，记得来交作业，帮我点个“好极了”\n感谢大家，祝大家暴富，发财，多吃不长胖！\n其它好吃的面包，关注我主页，顶部搜索栏搜：面包", "٩(˃̶͈̀௰˂̶͈́)و", "(˶‾᷄ ⁻̫ ‾᷅˵)"]'::jsonb, 30, 155, '困难', 3, 'https://i2.chuimg.com/498409d8e4024320ba52a30269e7a548_1707w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('双重巧克力口感---爆浆可可小面包，好像也叫黑眼豆豆', '烘焙甜品饮料', '面包', '', '[{"name": "---种面---", "amount": "适量"}, {"name": "水", "amount": "50克"}, {"name": "高筋面粉", "amount": "50克"}, {"name": "（0.5克）鲜酵母（干酵母）", "amount": "1.5克"}, {"name": "---可可面团---", "amount": "适量"}, {"name": "牛奶", "amount": "100克"}, {"name": "（3克）鲜酵母（干酵母）", "amount": "9克"}, {"name": "高筋面粉", "amount": "150克"}, {"name": "可可粉", "amount": "9克"}, {"name": "白砂糖", "amount": "25克"}, {"name": "盐", "amount": "1克"}, {"name": "所有种面", "amount": "适量"}, {"name": "黄油", "amount": "15克"}, {"name": "25- 30克耐高温可可豆", "amount": "适量"}, {"name": "适量70%巧克力", "amount": "适量"}]'::jsonb, '["种面部分材料全部混合均匀，室温发酵至2-3倍大，或者提前一晚做，种面混合后直接冷藏发酵一夜", "这是我在阳台上大概32度发酵2小时后的样子", "拨开有密密麻麻的气孔", "除黄油，可可豆和巧克力以外，可可面团材料中加入种面", "3档低速混合，5档揉出粗膜", "加入黄油，3档混合，5档揉出薄膜", "加入巧克力豆，揉匀，室温发酵", "发酵至两倍大", "发酵好的面团取出排气，平均分割成8份，每一份大约", "9克，盖保鲜膜松弛15分钟", "取出面团，手按压扁，翻面，中间包入巧克力，收口", "团圆，发酵至", "表面可以刷蛋液，我不想浪费一颗鸡蛋，就刷了牛奶~~", "180度预热烤箱，然后上下火180度烤10分钟，出炉后趁热再刷一层牛奶", "来张美照~肉眼可见的柔软", "给你们感受下~~~", "咬一口~真的超浓郁~~~~~快去做~"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/c507e820dc644eb08f0d0989a11726bb_1280w_917h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('一次发酵！越吃越香的奶盐罗宋面包！', '烘焙甜品饮料', '面包', '', '[{"name": "高筋面粉", "amount": "330克"}, {"name": "细砂糖", "amount": "30克"}, {"name": "奶粉", "amount": "12克"}, {"name": "鲜酵母", "amount": "10克"}, {"name": "全蛋液", "amount": "30克"}, {"name": "冰牛奶", "amount": "108克"}, {"name": "冰水", "amount": "28克"}, {"name": "炼乳", "amount": "60克"}, {"name": "盐", "amount": "4.5克"}, {"name": "黄油", "amount": "30克"}, {"name": "有盐黄油适量其它配料：", "amount": "适量"}]'::jsonb, '["首先准备好所需食材\n桶中倒入面团材料（除了黄油和盐以外）", "厨师机慢速搅拌成团后转中高速揉面", "揉至可以拉出厚膜", "加入室温软化的黄油和盐，开慢速搅拌至黄油吸收，转中高速揉面", "揉至可以拉出薄膜即可", "揉好的面团直接分成8个", "直接将其擀开", "翻面两边往中间折叠", "两端再捏起来", "稍微搓成锥型即可", "全部同样步骤，盖上保鲜膜松弛15分钟", "将面团擀开，擀长", "卷起来即可", "全部同样操作，送入发酵箱33度醒发60分钟左右", "发酵至2倍大小", "用锋利的刀切开，挤上有盐黄油", "送入提前预热好的烤箱，上火195下火185度烘烤15分钟左右，每个人的烤箱不同，烘烤时间温度仅作为参考！", "面包表面稍微上色后取出，刷上一层有盐黄油", "继续送入烤箱烘烤1-2分钟即可", "出炉后轻震烤盘，放凉即可食用！"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/612c963caee04f04b794bcc4fff47bdb_1701w_1361h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鸡蛋小饼干', '烘焙甜品饮料', '饼干', '', '[{"name": "鸡蛋", "amount": "1个"}, {"name": "蛋黄", "amount": "2个"}, {"name": "细砂糖", "amount": "50g"}, {"name": "低筋面粉", "amount": "80g"}]'::jsonb, '["将蛋黄、全蛋、细砂糖都倒入盆里。然后用打蛋器高速打发", "打发至有明显纹路。然后转最低速整理气泡。这一步很重要。小饼干细不细腻就看这里了", "整理好气泡的面糊非常细腻 面糊滴落后也不易消失。但是还是有流动性的哦", "加入过筛后的低筋面粉。用翻拌的手法兜底拌匀", "翻拌好以后面糊 没有干粉 很细腻 有一定的黏稠度。一定不是稀稀的那种", "拌匀的面糊装入裱花袋 用刮刀往前推面糊。排出空气", "在烤盘里垫上油布或者油纸。方便烤好以后脱模。请勿偷懒。不然你会后悔的\n\n而且。每个小饼干不要挤太大。1-2厘米的直径就好了。烤的时候是会膨胀的。要有一定的间隔。如果挤太大就成大饼子了   还是小小一个更可爱", "150度中层 30分钟。就可以享用啦～", "最近有新用海氏C45烤箱做这款小饼干，电子温控，整体温差正负5度的样子，设置150度中下层烤了25分钟的样子刚刚好，所以大家都要根据自己的烤箱做出调整，灵活运用", "17更新】\n这里我用到的是厨师机，做了配方的三倍量，打蛋盆里不能有油有水，不然是打发不起来的", "同样是一次性加入所有的细砂糖，我并没有减糖，对于全蛋打发来说，糖是很好的稳定剂", "然后将打蛋盆坐在一盆60度左右的热水上，用打蛋器搅散鸡蛋，注意水温不能太高，不然会把蛋液给烫熟，一边搅拌一边等到蛋液温度达到36度\n\nTIPS：这个非常重要！不要用冷藏鸡蛋去打发，全蛋液在36-40度之间是最好打发的！", "蛋液温度达到以后，装好打蛋头，开最高速打发", "打发到体积膨胀，颜色变浅，并且蛋液可以留下纹路", "然后转最低速整理蛋液到没有气泡，非常细腻的状态", "这里继续一段小视频，这个是整理好气泡以后的全蛋液，大家一定要打发到这个状态呀！这个很关键", "然后我是分三次过筛加入低筋面粉，翻拌手法见小视频。\n\n一定要非常温柔的对待你的全蛋液，因为此时是充盈了细腻均匀的小气泡的，要尽量避免消泡过度", "接上一条小视频\n\n翻拌到大致无干粉的时候可以边转盆边兜底翻拌，然后就可以加入剩下的低筋面粉了，手法要同样轻柔", "最后翻拌均匀的面糊是细腻的，略带流动性的，但是肉眼可见面糊是黏稠的，并不是稀得和水一样", "然后就可以装入裱花袋，裱花袋里套了一个圆形的花嘴", "均匀的挤在烤盘上，要留有空隙", "很多人问我要一次性多烤一些怎么办，说真的 除了用风炉多层同烤真的没有其他办法\n我一次性烤了四层\n参考温度为130度30分钟", "低温烘烤出来的小饼干表面光滑，上色均匀，并且口感是酥脆的哦。"]'::jsonb, 30, 115, '困难', 3, 'https://i2.chuimg.com/5a8ace493fda4d658883ffbc92f3e911_2304w_1536h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('黄油曲奇', '烘焙甜品饮料', '饼干', '', '[{"name": "开始做之前请一定认真看看小贴士，成败在此一举，在我这个方子里，特别特别重要的是黄油软化的程度，太软花纹不成型，太硬挤到手抽筋。", "amount": "适量"}, {"name": "【温馨提示：曲奇烤的时候会比你原来挤的体积稍微大一点，所以，挤的时候不要挤太大哦，变大一点很正常，不可能烤完后还跟挤出的大小一样】", "amount": "适量"}, {"name": "❣️❣️❣️糖粉可以根据自己口味适当增减，其他可以变动的地方上面都写了，没写的要么就是不能变动，要么就是我没尝试过，要换这换那的，自己尝试一下哈，但改完后的口感我由于没尝试过，自然是不知道的，你们自己做实验吧！！！", "amount": "适量"}, {"name": "黄油", "amount": "130克"}, {"name": "（不喜欢甜的可以减少几克）糖粉", "amount": "60克"}, {"name": "盐", "amount": "1.5克"}, {"name": "蛋清", "amount": "30克"}, {"name": "低筋面粉", "amount": "90克"}, {"name": "高筋面粉", "amount": "70克"}, {"name": "杏仁粉", "amount": "25克"}, {"name": "黄油", "amount": "130克"}, {"name": "（不喜欢甜的可以减少几克）糖粉", "amount": "60克"}, {"name": "盐", "amount": "1.5克"}, {"name": "蛋清", "amount": "30克"}, {"name": "低筋面粉", "amount": "85克"}, {"name": "高筋面粉", "amount": "70克"}, {"name": "杏仁粉", "amount": "25克"}, {"name": "抹茶粉", "amount": "10克"}, {"name": "黄油", "amount": "130克"}, {"name": "（不喜欢甜的可以减少几克）糖粉", "amount": "60克"}, {"name": "盐", "amount": "1.5克"}, {"name": "蛋清", "amount": "30克"}, {"name": "低筋面粉", "amount": "80克"}, {"name": "高筋面粉", "amount": "70克"}, {"name": "可可粉", "amount": "15克"}, {"name": "杏仁粉", "amount": "25克"}, {"name": "温馨提示：步骤里的图我是用的三倍的量", "amount": "适量"}]'::jsonb, '["这里先借百度的图片说下原材料里的杏仁粉，好多人都搞不清楚，我们这个方子里要用的是上图右边的杏仁磨的粉，左边的严格意义上应该叫巴旦木，还有称之为美国大杏仁的，也叫扁桃仁，它不是杏仁，做马卡龙用的是左边的（扁桃仁粉），我们方子里要用右边的（杏仁粉）哈～", "跪求大家一定要仔细看完方子再开始做🙏🏻🙏🏻🙏🏻", "开始吧，提前准备好所有原材料，以免手忙脚乱；", "黄油提前室温软化，最好是提前一天从冷冻拿到冷藏里放着；\n\n夏天直接室温软化，冬天的时候可以隔热水、烤箱低温，或者用吹风机热风吹一下进行软化，但这个吹风机最好是一个新的哈，不要用吹过头发的来吹，哈哈，有暖气的地方还可以放暖气片上软化；", "再用小视频说说黄油的软化程度，在此教程里，这是非常重要的一步，把这一步控制好了，百分百成功；\n\n夏天的时候，黄油软化到上面视频里的程度，就是用硅胶刮刀按压下去会有一点阻力；", "冬天要比夏天的时候软一点，而且冬天做曲奇速度要快，因为气温低会导致黄油凝固，就会使面糊特别难挤，手挤抽筋了都挤不出来；", "加入糖粉，先用硅胶刮刀把糖粉和软化的黄油搅拌均匀，以免后面打发的时候，糖粉到处飞，当然，如果你喜欢烟雾缭绕的感觉或者赶时间，也可以不拌，直接打发；😬", "打发黄油；", "侧面的记得也打发一下；", "打发至黄油颜色变浅发白，体积也变膨胀；", "然后把蛋清倒进去，如果你是新手的话，蛋清最好分三次加进去，每次彻底搅拌均匀后再加入下一次，蛋清也尽量用常温的，这样可以降低油水分离的风险；", "加入蛋白后，你可能一开始碰到这种情况，别担心，继续打，这个是蛋清还没跟黄油完全融合；", "打到这种状态才行；", "然后把盐放进去；", "搅拌均匀；", "再放个面粉筛在容器上面，把低筋面粉、高筋面粉、杏仁粉全部倒面粉筛里；", "过筛进去，杏仁粉颗粒会比面粉粗一些，如果不好过筛的话，可以用硅胶刮刀按压下去；", "粉都过筛进去后，搅拌均匀，尽量避免转圈圈搅拌，防止起筋，可以用硅胶刮刀按压着搅拌；", "搅拌至细腻顺滑，看不见面粉颗粒为止；", "来个视频看看拌好的面糊软硬度，更直观；", "这里我用的是8齿的裱花嘴，杂牌的，也找不到购买记录了，所以说不出型号，但是跟SN7092号裱花嘴有点像，只是小一点，下面口子的直径是2厘米，高度是", "8厘米；", "把裱花嘴放裱花袋里，然后剪个合适的口子，口子不要剪太大里，因为后面挤的时候，向前还会有很大推力，剪太大了裱花嘴会冲出去，哈哈，剪完后把裱花嘴从口子里伸出来；", "然后把裱花袋套在左手上，大拇指和食指呈C形将裱花袋撑开一个口子；", "然后把面糊从那个口子灌进去，面糊宁少勿多，太多了不好挤；", "把边缘的面糊刮到前面去；", "把裱花袋的尾部在右手食指上绕一圈；", "然后扭一扭，相当于把上面封口了，这样是为了好用力，也防止挤的时候，曲奇面糊从后面冒出来；", "挤出自己喜欢的花纹，我这里挤的是传统玫瑰花形；", "方法是先挤一点；", "然后紧挨着那个点转一圈，但这两步不要停顿，连贯性的挤完，不然中间有断点，不好看；", "再来个视频教你怎么挤出这种花型，这是以前拍的；\n\n挤的时候，烤箱可以提前预热，温度设置为上下管170摄氏度左右，至少预热10分钟，因为曲奇需要高温定型；\n\n一般烤箱打开前几分钟温度比较低，要预热10-15分钟左右才能达到需要的温度；\n\n当然，方子里给的温度也只是参考，烤箱不同，温差也不同，所以，你必须摸清楚自己烤箱的温度；", "依次把烤盘挤满，但是每朵之间不要间隔太近了，因为曲奇烤的时候，体积还会膨胀变大一点，挨太近了怕粘连到一起了；", "如果你有硅胶垫的话，强烈建议垫一个硅胶垫，可以有效的降低曲奇变形的风险；", "挤完的曲奇，美美哒；", "放入预热好的烤箱；", "烤箱温度设置为上管165度，下管150度，中层，烤20-25分钟左右；\n\n温馨提示：烤箱不同，温差也不同，这个温度只是做个参考，你得摸清自己烤箱的脾气，我烤东西一般不按照固定时间，我会随时观察烤箱，烤熟了的可以先拿出来，烤饼干时，烤箱中间可以打开没关系的；\n\n这里有些图片是不同时期拍的，有些是手机拍的，有些事相机拍的，有些是从视频里截图的，所以会有些色差；", "家用烤箱的温度大部分都不太均匀，我的也是，烤的时候，随时观察烤箱里的情况，熟了的可以先拿出来，没熟的继续烤，只要曲奇定型后（约8-10分钟左右可以完全定型），烤箱可以随时打开看看；", "纹路很立体，实际颜色比这个深一点黄一点；", "这个是相机拍的；", "接下来做可可味儿的，配方跟原味儿基本一样，就是低粉减少10可，多加15克可可粉，其他的都一样，做法也一模一样；", "前面打发黄油的过程就不演示了，这里就是把可可粉和低筋面粉、高筋面粉，还有杏仁粉一起过筛到打发好的黄油里；", "然后搅拌均匀；", "知道细腻顺滑，看不见面粉颗粒为止；", "然后装入裱花袋；", "挤出花型，记得挤花之前先把烤箱打开预热；\n\n视频更直观，温馨提示：挤花的时候，裱花嘴和烤盘应该是垂直的，因为我一只手拍视频，一只手挤花，又为了让大家更好的看到挤花的手法，所以倾斜了一些，两只手一起挤更省力；", "放入烤箱，上管165度，下管150度，烤20-25分钟左右；\n\n再啰嗦一遍😂，烤箱不同，温差也不同，这个温度只是做个参考，你得摸清自己烤箱的脾气，我烤东西一般不按照固定时间，我会随时观察烤箱，烤熟了的可以先拿出来；", "烤完就可以拿出来了，我烤的时候是先熟的先拿出来了，这里拍视频教程嘛，所以，你懂的，都摆一起好看一些，哈哈；", "成品美图，这个是相机拍的；", "最后是抹茶味儿的，配方也基本一样，就是低筋面粉减少5克，多加10克抹茶粉，其他的都跟原味儿一样，做法也一样；", "黄油打发的过程这里也不演示里，就是把抹茶粉跟低筋面粉、高筋面粉、杏仁粉都倒一起；", "过筛到打发好的黄油里；", "搅拌至面糊细腻顺滑，看不见面粉颗粒为止；", "装入裱花袋；", "同样的挤法挤出花型，记得挤花之前先把烤箱打开预热；", "再来个挤花小视频；", "放入预热好的烤箱，上管设置为155度，下管设置为140度，先烤8分钟左右定型；\n\n这个温度仅供参考，不同的烤箱，温差也不同，请根据自己烤箱的实际温度作调整；", "烤抹茶曲奇值得注意的是，烤8-10分钟左右定型后，要盖上锡纸，不然曲奇表面很容易上色；\n\n盖锡纸后，抹茶曲奇需要再烤20分钟，同样的，中间随时打开烤箱揭开锡纸查看下，摸一下曲奇的底部，稍微有点硬了就可以出炉了，如果还是软的就接着再烤；\n\n我的时间是根据我的烤箱和实际温度来定的，只做个参考，你一定要摸清楚自己烤箱的脾气哈；", "再啰嗦一遍，抹茶的一定要盖锡纸，不然上色了很难看；\n\n我的是烤8-10分钟左右定型后盖的锡纸，然后再烤20分钟左右，不同的烤箱，温差也不同，有些人可能盖锡纸后15分钟就烤好了，有些可能要20多分钟甚至半个多小时；\n\n所以，要随时观察曲奇的状态，摸着底部有一点点硬，记住，一点点硬就可以拿出来了，使劲按的话，可能还会有点软，没关系，冷却后就硬了；", "这一步对抹茶曲奇很重要，请认真看完，超级感谢；\n\n你们如果实在不会判断抹茶的熟没熟，就看底部，底部颜色变成这种就差不多了，再用手摸一下，稍微有一点硬就可以了，使劲按可能还有一丁点软，冷却后会变硬的，记住，烤抹茶的一定要盖锡纸；🙏🙏🙏\n\n我一般是烤8-10钟，看着基本定型后就盖锡纸，其实烤5分钟开始就可以盖锡纸，你只要确保锡纸不会压歪你的曲奇就可以开始盖了，越早越好；\n\n一开始烤的时候，曲奇不是亮亮的泛油光吗？等到油光差不多消失后，基本就定型了，就可以开始盖锡纸了，但是，盖的越早，烤的时间就要适当加长些，方子里的时间只是参考；\n\n具体的，你们还要随时拿出来看看底部的颜色，然后摸一下，关于中间还有一点湿软的，我觉得没关系，冷却后，吃起来就是酥的感觉，如果你想完完全全烤透，那就盖锡纸后，把下管温度起码调低20度，然后加长烤的时间，起码要再烤30-40分钟，低温慢烤，既可以烤透，也可以保证不会上色；", "成品美图", "再来个黄油曲奇家族的合影照，花纹很立体吧😬", "我不知道你们注意到一个细节没，我挤的花有两种状态，一种是左边这样的，纹路顶端比较薄比较尖锐，另外一种是右边这样的，纹路顶端比较圆滑，想知道怎么做的，看下图👇🏻", "如果想得到左边那种纹路顶端比较薄比较尖锐的，裱花袋就剪到完全离开裱花嘴的齿", "如果想得到右边那种纹路顶端比较圆滑的花纹，裱花袋的口就不要剪太大，把裱花嘴的齿遮住一点点，这样挤出来哦花纹顶端就会比较圆滑，顶端也就不会那么容易碎", "关于锯齿边，因为我这个方子做出来花纹比较立体，口感偏脆，所以面糊会比那种酥到掉渣的方子的面糊会干一点，挤出来的曲奇多多少少会有一点锯齿边，我做的太多了就没太纠结这个问题，如果你不能接受一丁点的锯齿边，那么就按照我上面的方法，裱花袋遮住一点花齿，挤出来的花边就会很顺滑，但同样，花纹可能就没有那么深了，会浅一点", "增加一种花型的挤法——菊花形状，用的惠尔通8B裱花嘴，挤花的时候裱花嘴跟烤盘应该是垂直的，我拍出来为了看清楚点，所以斜着挤，先离开烤盘1厘米的地方挤出面糊，面糊到达烤盘时再挤一点，然后一边慢慢慢慢的挤，一边把裱花嘴往下面压，我的面糊比较干，所以断开的时候要转着断开", "惠尔通8B裱花嘴挤出的曲奇成品图", "再放一张🤓"]'::jsonb, 30, 345, '困难', 3, 'https://i2.chuimg.com/ee349457cccb4fd1b57dc641219da3bb_1242w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蔓越莓饼干 新手也不怕', '烘焙甜品饮料', '饼干', '', '[{"name": "黄油", "amount": "120克"}, {"name": "糖粉", "amount": "70克"}, {"name": "（约1个小鸡蛋）全蛋液", "amount": "50克"}, {"name": "蔓越莓", "amount": "60克"}, {"name": "低筋面粉", "amount": "230克"}]'::jsonb, '["欢迎一起学习", "准备好材料，蔓越莓切碎", "120克黄油软化到按压就能按开，加入70克糖粉，用手动打蛋器搅拌均匀", "50克全蛋液分三次加入，每次加入用手动打蛋器搅匀", "分次筛入230克低筋面粉，用刮刀压拌至无干粉状态，必要时可以带一次性手套用手抓捏均匀（也不能过度搅拌，会导致起筋，就不酥脆）", "倒入60克碎蔓越莓压拌均匀", "把面团整形成长条形，这里我用的U型模具，更方便，包个保鲜膜，方便脱模出来。", "放冰箱冷冻1小时后，取出来切片，厚度大概", "切好了，摆到烤盘上，每块饼干要保持一定距离，烤的时候饼干会胀大（我的烤箱38升烤盘要烤2盘）", "烤箱一定要预热，预热好后放入烤箱中层，上下火170度，15分钟（每个烤箱温度有差异，时间不一定一样，看到表面微金黄就可以出炉）", "上色后出炉", "放到网架上晾凉", "口感不错"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/db35c057cfe04887987a2f9cd9b54510_1430w_1144h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('入口即化的珍妮曲奇', '烘焙甜品饮料', '饼干', '', '[{"name": "无盐黄油", "amount": "200克"}, {"name": "糖粉", "amount": "53克"}, {"name": "低筋面粉", "amount": "124克"}, {"name": "奶粉", "amount": "5克"}, {"name": "玉米淀粉", "amount": "65克"}, {"name": "盐", "amount": "1.5克"}, {"name": "高筋粉", "amount": "65克"}]'::jsonb, '["软化好的黄油加入盐", "低速打几圈至盐融化加入糖粉", "继续打至黄油发白体积膨胀", "一次性加入所有粉类（不用过筛）用刮刀搅拌一下", "在用打蛋器低速打至看不见干粉", "取出面糊放在案板上搓～直到面糊顺滑不粘手就可以了", "裱花嘴装入裱花袋，这是8齿的珍妮曲奇花嘴，你可以根据自己喜欢挑选", "挤出花型～带孩子太久太久没挤花了！", "挤好后放入预热好的烤箱150度30～40分钟，具体看曲奇上色情况来调整。", "这是出炉的样子，顶部稍微有点上色，但是纹路是清晰的～", "拍照时掰开一个看看，这个还不是很酥，因为还没凉，凉了以后更酥！", "口感真的一级棒！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/233596543fb74efa9648faad40b2d3a8_4032w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小朋友们超爱的卡通小饼干', '烘焙甜品饮料', '饼干', '', '[{"name": "无盐黄油", "amount": "60克"}, {"name": "糖粉", "amount": "30克"}, {"name": "低筋面粉", "amount": "105克"}, {"name": "鸡蛋液", "amount": "20克"}, {"name": "奶粉", "amount": "20克"}, {"name": "1套卡通饼干模具", "amount": "适量"}]'::jsonb, '["黄油切小块软化（用手指轻轻能按出一个小坑的状态）。然后筛入糖粉。", "先用刮刀压拌一下，防止搅打的时候糖粉飞溅。", "搅打均匀，手动与电动打蛋器都可以。注意不要过度打发，搅匀就可以了。", "分两次加入蛋液。（即先加一半搅匀融合后再加剩下的）", "低筋粉与奶粉混合，筛入黄油中", "用刮刀翻拌至无干粉状态", "带手套，轻轻拢成团（如果面团太软，可以放冰箱冷藏一下）", "上下各垫油纸，将面团擀开，约", "3厘米厚。（别擀太薄了，太薄烤好后容易变形）", "擀好后放冰箱冷冻至刚好变硬（大约20分钟左右）。冷藏也可以，但所需时间较长。", "压模（模具上可以先刷少许粉防粘）。剩下的边角料用手轻轻揉成团，再次擀开，冻硬，压模。直至将面团做完。", "放入烤盘中，烤箱上下火预热160度（大约需10分钟）", "烤箱预热好后，将饼干放入烤箱中层，烤约10~15分钟，至边缘开始出现轻微焦黄时取出。（烘烤的时间与温度仅做参考，要根据自己烤箱的实际情况作出调整。烤的时候注意观察，别烤焦了）", "饼干刚烤好时是软的，等晾凉后就变硬了，放入密封罐中保存。"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/f951402cae784e7091b284468ce0f309_1011w_1151h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('披萨', '烘焙甜品饮料', '披萨', '', '[{"name": "高筋面粉【面饼】", "amount": "140克"}, {"name": "低筋面粉【面饼】", "amount": "60克"}, {"name": "（面粉吸水性不同，可选择100-110的范围添加）水【面饼】", "amount": "110克"}, {"name": "橄榄油【面饼】", "amount": "14克"}, {"name": "细砂糖【面饼】", "amount": "10克"}, {"name": "耐高糖酵母【面饼】", "amount": "2克"}, {"name": "盐【面饼】", "amount": "1克"}, {"name": "番茄【红酱】", "amount": "2个"}, {"name": "洋葱【红酱】", "amount": "1个"}, {"name": "1头大蒜【红酱】", "amount": "适量"}, {"name": "月桂叶【红酱】【它就是香叶】", "amount": "3片"}, {"name": "适量黑胡椒粉【红酱】", "amount": "适量"}, {"name": "适量盐【红酱】", "amount": "适量"}, {"name": "适量糖【红酱】", "amount": "适量"}, {"name": "肉糜【红酱】", "amount": "200克"}, {"name": "熟虾仁", "amount": "8个"}, {"name": "适量青椒丝", "amount": "适量"}, {"name": "适量红椒丝", "amount": "适量"}, {"name": "适量口蘑片", "amount": "适量"}, {"name": "适量玉米粒、豌豆粒", "amount": "适量"}, {"name": "适量肉片【种类按自己喜好】", "amount": "适量"}, {"name": "适量马苏里拉芝士碎", "amount": "适量"}, {"name": "适量番茄酱【红酱】", "amount": "适量"}]'::jsonb, '["将方子里的面饼材料混合均匀揉成面团，到出膜阶段即可。放入发酵箱或者温暖处发酵至两倍大，基本上在28℃左右的温度环境即可。下面等待发酵的时间可以准备披萨的其他材料。", "【红酱做法】准备200克肉糜，肥瘦2:8左右即可。", "洋葱一个，切末备用。", "蒜一头，切末备用。", "西红柿2个，先放滚水中20秒，然后去皮做成番茄泥。", "锅中放油，油热后放入洋葱末、蒜末炒香。", "洋葱末、蒜末炒香以后，放入肉糜，迅速划散。", "等肉糜泛白以后倒入番茄泥、适量番茄酱、黑胡椒粉等翻拌均匀。", "加入月桂叶继续煮至汤汁浓稠，成酱的状态，加入盐、糖等调味出锅备用。【方子中的量做出的酱料做一个披萨用不完，可以放冰箱冷冻，以后可以拌肉酱意面，但是披萨的红酱相对于意大利肉i将要更稠，所以用来拌面的时候可以少加一点点水把酱煮开再拌】", "【准备披萨材料】准备肉片（加黑胡椒炒制的鸡肉片、牛肉片、超市的冷冻火腿反正自己喜欢的各种肉类都可以，切薄片，大小适中），青椒红椒切丝，玉米粒豌豆粒准备好，适量口蘑，8个熟的虾仁。！！！！！！！注意，披萨上的蔬菜总量不要太多，不然做好以后会很水，我习惯在制作之前把蔬菜材料们放在烤盘上，烤箱预热150度，烘干到水分蒸发一些，这样出的水少，菜也能多放些。", "面团排气后擀成适当大小，周边稍厚的面饼，【我用三能28*28的金色不沾烤盘，一般擀成差不多放下的圆型】，用叉子在面饼上扎一些小孔，然后静置20分钟。在静置好的面饼上刷一层做好的红酱，撒一层马苏里拉芝士碎。，", "放一层肉片，撒一层芝士碎，撒上青椒红椒口蘑，撒上一层芝士碎，再均匀摆上熟虾仁，撒上玉米粒、豌豆粒，撒上一层芝士碎。【怕豌豆粒玉米粒不熟的可以先焯水】", "烤箱预热210度，烤制15分钟，出炉趁热食用喔⊙ω⊙，发酵过程完美的饼皮才会好吃，所以记得控制好发酵的温度和时间哦"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/97d6b2d488b211e6a9a10242ac110002_800w_693h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('披萨', '烘焙甜品饮料', '披萨', '', '[{"name": "马苏里拉芝士", "amount": "适量"}, {"name": "高筋面粉", "amount": "110g"}, {"name": "盐", "amount": "1.5g"}, {"name": "糖", "amount": "2.5g"}, {"name": "酵母粉", "amount": "2.5g"}, {"name": "橄榄油或者玉米油", "amount": "10g"}, {"name": "视情况而定水", "amount": "65g"}]'::jsonb, '["将面粉，盐，糖，酵母粉放进盆里搅拌，再将油和水一点一点往盆里倒，边倒边搅拌。揉至表面光滑，尽可能的多揉一会，十几二十分钟差不多。（水不一定要加完，不同牌子的面粉吸水情况不同）", "然后将面团放到盆子里，表面粘点水，保鲜膜封住，放到微波炉里，旁边再放一碗热水，不需要开微波炉，只需要给面团制造一个温暖湿润的环境(烤箱如果有发酵功能，可以直接用烤箱发酵)", "切菜，我一般放  青红椒  口菇  洋葱  (胡萝卜不推荐）", "把肉切好，腌制，然后可以烤，可以微波炉打，总之弄熟。(培根一定要完全解冻，用厨房纸吸干水分)", "面发酵到差不多两倍大后，拿出来再揉一揉，排气。", "然后擀成烤盘大小。先给烤盘刷油，然后将披萨底放进去，再给披萨表面刷油，可以用手调整大小，外边一圈比里面厚。", "擀面团的时候就可以先把烤箱预热，220度，15分钟。", "撒料顺序：先均匀涂抹披萨酱，披萨酱太稀的话就少抹点，再撒一层马苏里拉芝士，然后开始先放肉，后放菜，还可以放点菠萝玉米粒披萨草辣椒面之类的，看个人喜好。然后再撒一层马苏里拉（表面铺满即可）。然后就可以烤了。烤箱中层，15分钟至金黄色，基本上颜色好了就可以出了。(芝士拉丝的关键就是不要把芝士烤干)", "烤好之后，有荷兰芹的话，可以把荷兰芹放到微波炉里打干，捏碎，稍微撒点装饰。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/de64c32289b511e6a9a10242ac110002_1948w_1742h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('意式披萨', '烘焙甜品饮料', '披萨', '', '[{"name": "面粉", "amount": "400克"}, {"name": "干酵母", "amount": "4克"}, {"name": "水", "amount": "230克"}, {"name": "植物油", "amount": "10克"}, {"name": "糖", "amount": "5克"}, {"name": "盐", "amount": "3克"}, {"name": "适量披萨酱", "amount": "适量"}, {"name": "适量马苏里拉奶酪", "amount": "适量"}, {"name": "适量香肠（或培根）", "amount": "适量"}, {"name": "适量甜玉米粒", "amount": "适量"}, {"name": "适量豌豆", "amount": "适量"}, {"name": "适量胡萝卜丁", "amount": "适量"}]'::jsonb, '["首先在搅拌盆中加入分别称好面粉，酵母，水，植物油，糖和盐", "使用kitchenAid厨师机的二档加到三档开始揉面", "面团仅需要几分钟揉就可以了，因为不必揉太久！", "再把面团揉光滑，放入盆中盖上保鲜膜发酵，约半小时左右", "发酵好的面团的面团大约是原面团的1倍多大小", "提起面团会出现蜂窝组织，再将面团揉光滑", "揉好的面团，用电子秤称重平均分成4个面团，约160多克一个可做9寸的披萨4个！", "取其中一个面团放在披萨烤盘上，然后用手将面团向烤盘的四周按压做饼底", "最好按压出来的饼底平整薄厚一样，这样烤出来才好吃", "用餐叉在饼底均匀的扎上一排排的小孔", "先均匀的涂抹一层披萨酱，再撒一层马苏里拉奶酪", "将切好的香肠或是培根，玉米粒，豌豆，胡萝卜丁，也可以放自己喜欢的虾仁或是其他蔬菜都可以", "最后在上面再撒一层马苏里拉奶酪，如果喜欢可以多撒一些，将海氏C45烤箱上下火预热200度，放入中层烤12分钟左右即可！", "烤好的披萨出炉了！", "披萨的饼底厚度可以自行掌握，如果喜欢饼底厚一些，可以用的面团稍微多一些！"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/1ff8c5c88b4a11e6b87c0242ac110003_1616w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制意面酱、披萨酱', '烘焙甜品饮料', '披萨', '', '[{"name": "两个西红柿", "amount": "适量"}, {"name": "四分之一洋葱", "amount": "适量"}, {"name": "五瓣大蒜", "amount": "适量"}, {"name": "一小块黄油", "amount": "适量"}, {"name": "一小勺黑胡椒碎", "amount": "适量"}, {"name": "一小勺（没有可不放）披萨草", "amount": "适量"}, {"name": "1/2小勺（没有可不放）罗勒", "amount": "适量"}, {"name": "一小勺（尝味道增减）盐", "amount": "适量"}, {"name": "一大勺糖", "amount": "适量"}, {"name": "适量番茄沙司", "amount": "适量"}]'::jsonb, '["如果称重的话，具体用量参照图片", "洋葱和蒜末切碎备用，我用料理机打的，有点出汤了", "西红柿去皮切碎，我也用了料理机。", "锅里放一块黄油加热至融化（也可以换成植物油）", "黄油炒香蒜末", "放入洋葱继续炒香", "放入西红柿碎，翻炒一会儿，加入盐、糖、黑胡椒碎、披萨草、罗勒叶。最小火焖煮二十分钟左右。加适量番茄沙司。（中途看锅搅拌，防止干锅）", "做意面酱使用的话，到这个浓稠度就可以了", "做披萨酱要收汁到这个程度", "意大利面煮至没有硬心。配上番茄意面酱。", "自制杏鲍菇鸡肉披萨", "披萨成品，比卖的好吃😋"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/1806f9ba7ad94db98c100c04a9163181_750w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('儿子说比BSK好吃的披萨（含披萨酱、饼底做法）', '烘焙甜品饮料', '披萨', '', '[{"name": "低筋粉（饼底）", "amount": "40克"}, {"name": "高筋粉（饼底）", "amount": "160克"}, {"name": "水（饼底）", "amount": "110克"}, {"name": "白糖（饼底）", "amount": "10克"}, {"name": "盐（饼底）", "amount": "1克"}, {"name": "酵母（饼底）", "amount": "4克"}, {"name": "橄榄油（饼底）", "amount": "15克"}, {"name": "（4肥6瘦）猪肉碎（披萨酱）", "amount": "500g"}, {"name": "（偏小）洋葱（披萨酱）", "amount": "2个"}, {"name": "（偏小）番茄（披萨酱）", "amount": "4个"}, {"name": "适量番茄酱（披萨酱）", "amount": "适量"}, {"name": "大蒜（披萨酱）", "amount": "2个"}, {"name": "少量黑胡椒粉（披萨酱）", "amount": "适量"}, {"name": "桂皮（披萨酱）", "amount": "3块"}, {"name": "适量盐（披萨酱）", "amount": "适量"}, {"name": "根据自己喜好放多或者少马苏里拉芝士碎", "amount": "适量"}, {"name": "培根", "amount": "3片"}, {"name": "左右虾仁", "amount": "12个"}, {"name": "适量豌豆、胡萝卜粒 、玉米粒", "amount": "适量"}]'::jsonb, '["大蒜、洋葱和肉搅碎备用", "番茄🍅搅碎备用", "不粘锅内倒入少许玉米油，蒜碎炒香，倒入洋葱碎翻炒", "洋葱炒香后加入肉碎继续翻炒", "待肉发白倒入打碎的番茄碎", "加入适量番茄酱（提色），加入桂皮和月桂叶、胡椒粉翻炒", "中火慢熬，待汤汁收干加入适量盐，披萨酱就做好啦。PS：酱一定要炒干水分！！！", "把面饼的材料依次（水、糖、盐、油、面粉）放入面包机，在面粉里掏个小坑埋入酵母，面包机一个发面程序就好了。", "取一个10寸的披萨盘，面皮慢慢碾开，用叉子叉满小孔，发酵一会儿。", "铺上自制披萨酱", "铺一层芝士碎，铺一层培根，再摆好虾仁🍤", "摆好虾仁后再铺一层芝士碎，加点蔬菜（豌豆、胡萝卜粒、水果玉米粒，提前煮好，挤干水分哦），再根据自己喜好撒上一层芝士碎。", "烤箱210度预热后放入披萨，15分钟就可以啰！", "自己做的饼底真的超好吃😋", "您学会了吗？等您上传您的作品哟……"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/840b82372e1f43818e1861524e1fe835_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('苹果派（超快手）菠萝派、香蕉派、红豆派', '烘焙甜品饮料', '派', '', '[{"name": "新鲜菠萝", "amount": "130克"}, {"name": "黄油", "amount": "10克"}, {"name": "冰糖", "amount": "10克"}, {"name": "水", "amount": "100克"}, {"name": "蛋挞皮", "amount": "6个"}]'::jsonb, '["菠萝切丁", "10克黄油和10克冰糖准备好", "热锅加入黄油，注意一定要小火", "倒入菠萝和冰糖，转中火开始炒", "炒一会就倒入100克水", "继续翻炒", "收干水分就行了", "蛋挞皮直接从冰箱拿出来，把锡纸去掉，记得拿出来就去掉锡纸，不然一会就不好去了。", "这是六个的量，锡纸去掉以后，解冻大概两分钟，稍微有一点软就行了", "把炒好的菠萝果肉放进去", "蛋挞皮对折，对折的位置不需要使劲捏紧", "用锋利的刀划两道", "刷上全蛋液两遍，撒上黑芝麻", "进烤箱180度，20分钟左右。香喷喷的菠萝派出炉了，每个烤箱的脾性不同，注意观察。上色比较深的就差不多了。"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/1e006d24e8ca4940bbbcb68153643eac_810w_810h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小山进的苹果派', '烘焙甜品饮料', '派', '', '[{"name": "法式油酥面团", "amount": "200克"}, {"name": "2/3个苹果", "amount": "适量"}, {"name": "适量鲜奶油", "amount": "适量"}, {"name": "适量细砂糖", "amount": "适量"}, {"name": "黄油", "amount": "20克"}]'::jsonb, '["去油酥面团200克，擀成超过20cm的圆形，厚度3mm；", "用20cm的慕斯膜切成完整的圆形，边上2cm处折起来；", "苹果切薄片螺旋型摆放好；", "均匀刷上鲜奶油；", "撒上细砂糖；", "黄油切成小块，均匀放置在苹果片上；", "190度烤40分钟。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/5f57d24782c7458eb9c1e45f04c40634_2725w_4096h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香蕉派（0失败）', '烘焙甜品饮料', '派', '', '[{"name": "香蕉", "amount": "1根"}, {"name": "蛋挞皮", "amount": "8个"}]'::jsonb, '["香蕉切碎，取8个蛋挞皮解冻后放入香蕉碎，撕掉锡纸（我这个忘记了，后面撕掉了😂）对折捏紧封口。每个蛋挞皮上面划三刀并且刷上全蛋液两次，撒少许黑芝麻点缀，欧克啦😌", "送入烤箱，烤箱温度180度 时间15分钟"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/d7dc26a172ca4a18aa5ee4ada5f4eb8b_1906w_1427h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香酥苹果派', '烘焙甜品饮料', '派', '', '[{"name": "苹果", "amount": "2个"}, {"name": "2张手抓饼", "amount": "适量"}, {"name": "个鸡蛋", "amount": "1个"}, {"name": "适量黑芝麻", "amount": "适量"}, {"name": "克糖", "amount": "5克"}, {"name": "玉米淀粉", "amount": "10克"}, {"name": "盐", "amount": "1克"}]'::jsonb, '["具体看图二介绍", "具体做法", "酥脆可口", "好吃到停不下来"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/0a1f38cf468a4372b2310ff60f5b33a5_620w_826h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('经典蓝莓派Classic Blueberry pie', '烘焙甜品饮料', '派', '', '[{"name": "派皮：", "amount": "适量"}, {"name": "通用面粉", "amount": "300克"}, {"name": "砂糖（可选）", "amount": "50克"}, {"name": "海盐", "amount": "1克"}, {"name": "无盐黄油", "amount": "226克"}, {"name": "冰水", "amount": "45ml"}, {"name": "伏特加（或者替换成冰水）", "amount": "30ml"}, {"name": "蓝莓馅", "amount": "适量"}, {"name": "（5 cups蓝莓", "amount": "500克"}, {"name": "（3tbsp柠檬汁", "amount": "45ml"}, {"name": "1tbsp柠檬皮屑（可选", "amount": "适量"}, {"name": "通用面粉", "amount": "30g"}, {"name": "砂糖", "amount": "50克"}, {"name": "一撮盐", "amount": "适量"}, {"name": "1tsp肉桂粉", "amount": "适量"}, {"name": "增加色泽", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "适量奶油", "amount": "适量"}]'::jsonb, '["先来制作派皮，将黄油🧈切成小块和面粉盐糖混合揉搓直至呈砂粒状。\n加入水和伏特加（也可替换成水）揉成面团，放冰箱冷藏。", "制作蓝莓馅🫐：将所有材料混合", "根据干湿程度自行加柠檬汁或者面粉", "从冰箱拿出来备用的面团，分成两份。案板上撒面粉面团上也撒一点防粘，把其中一份擀成大饼，放在模具上，用叉子在底部叉洞，倒入馅料。", "另一份面团也擀成饼，切成条条，编花篮。", "编花篮示意图", "切掉边缘多余的面皮，捏紧边缘", "烤箱提前预热200度20分钟转170度30-40分钟或者直至派皮金黄蓝莓爆开。 在烤的时候如果发现派的边缘上色太快可以围一圈锡纸防止烤糊。", "对了，烤之前别忘了刷蛋液，我刷的是奶油哈哈", "放凉后配上冰激凌🍦享用吧💗", "拥有甜食的一天才算完整啊嘿嘿🍬🍬(*¯︶¯*)", "再来一张图嘿嘿，美味❤️"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/31dc64a6d7494b2aae0f89e235634feb_1280w_1228h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级好吃的咸味司康Savoury Scones', '烘焙甜品饮料', '司康', '', '[{"name": "普通面粉（低粉中粉都行的）", "amount": "250g"}, {"name": "黄油（切成小块）", "amount": "60g"}, {"name": "培根", "amount": "160g"}, {"name": "葱末", "amount": "35g"}, {"name": "奶酪碎", "amount": "100g"}, {"name": "一小撮盐", "amount": "适量"}, {"name": "泡打粉", "amount": "7g"}, {"name": "糖", "amount": "20g"}, {"name": "奶油", "amount": "100g"}, {"name": "2颗鸡蛋", "amount": "适量"}]'::jsonb, '["160g培根切成小方块，放在一个锅里，锅里不用放油，然后中火煎，直到四周开始变得焦黄~", "差不多这个样子就可以了，然后放一边，放凉~", "在一个空盆里放入250g低筋面粉，和切成小块的60g黄油。", "用手搓，或者用搅拌器搅拌，黄油被面粉包裹，但依然有小颗粒的黄油的时候就可以接下来的步骤啦~", "往黄油和面粉的盆里放入：已经凉了的培根，葱末35g，奶酪碎100g，盐一小撮，泡打粉7g，糖20g，奶油100g，鸡蛋两颗~", "搅拌~搅拌~搅拌~\n用刮刀搅拌或者用搅拌机，当然，你也可以选择用手~等混合的差不多了就停，如果过度搅拌最后的成品就不酥松啦~这时候的面团应该是比较粘的。", "在干净的桌上铺上一张保鲜膜，然后撒一点干粉，再把刚才的混合物倒在上面。隔着保鲜膜或者用手把面团弄成一个圆形，稍微按扁一点。注意：用手碰面团之前稍微抹一点干粉喔，不然会黏手哒~", "就是这个样子~", "然后用保鲜膜包好，放冰箱冷藏十五分钟，让面团松弛一下，同时让各种味道更好的融合一下~\n*你要是超级有耐心的话，放几个小时，或者放冰箱过夜，第二天再烤更好！！！", "十五分钟到！拿出来，切成6大块~", "移到烤盘上", "刷点牛奶", "放入提前预热好的烤箱，200度烤20分钟左右~\n\n烤的时候好香好香好香", "拍张照片，交作业\n然后就可以享用啦~\n不要问我为什么少了一块，我也不！知！道！"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/f2fa1ecfdccb4fd6800f5e40dcc8681a_2202w_1652h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蔓越莓司康', '烘焙甜品饮料', '司康', '', '[{"name": "低筋面粉", "amount": "250克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "泡打粉", "amount": "6克"}, {"name": "细砂糖", "amount": "40克"}, {"name": "黄油", "amount": "50克"}, {"name": "-60ml淡奶油", "amount": "50ml"}, {"name": "蔓越莓", "amount": "70克"}, {"name": "盐", "amount": "2克"}, {"name": "少许比利时黑巧克力豆", "amount": "适量"}]'::jsonb, '["低筋面粉也可以换成普通的中筋面粉，黄油室温软化，蔓越莓不用再切小粒。", "淡奶油和鸡蛋液混合，搅拌均匀。", "低筋面粉，泡打粉，细砂糖，盐，在一个大点的容器中混合均匀。", "一定要搅拌均匀，因为司康不需要过度揉面，所以这里尽量让材料混合均匀，那样口感才会更好。", "软化的黄油加到混合好的面粉里。", "用手揉搓黄油和粉，形成粗粗的颗粒状，这样烘烤时黄油可以融化，使司康更松软。", "放入蔓越莓搅拌均匀，用手松散的抓匀，不要硬压。", "倒入蛋液和淡奶油的混合液。", "轻轻的揉成面团，一定要尽量减少揉面的次数，防止面粉产生筋度，筋度产生的越少，司康烤出来的口感更松软。", "为了方便整形，我放到一个六寸的派盘中，派盘的厚度刚刚好，表面可以装饰一点蔓越莓和黑巧克力豆，我用的是比利时嘉利宝的。", "派盘是活底的，很容易顶出来切成六块，司康的形状传统是三角形，也可以用模具压成圆形等各种你喜爱的形状。", "之前的黄油和面粉混合的油酥粒可以稍微留一点出来，我选了两个上面撒的油酥粒，另外四个刷了一层薄薄的蛋液。", "烤箱200度预热，放入中层，烤20分钟。", "一会就能看到司康已经蓬松高了许多，所以用派盘整形我觉得特别适合，不用用手过度压揉，放进去稍微一按就行。", "当当当，出炉了，右边是两个撒了油酥粒的，左边四个是刷了蛋液的，看个人喜好了。", "司康外形看着朴素粗糙，但口感却棒棒哒！", "里边的组织蓬松，刚出炉热的口感还有点软，稍微晾凉就是酥软的口感。", "配一杯红茶或咖啡，都是下午茶极好的搭配。"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/39d02cdf656d452ea59af50b12ba9437_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('完胜星巴克的超美味酥脆司康 super easy crunched scone', '烘焙甜品饮料', '司康', '', '[{"name": "面粉", "amount": "150克"}, {"name": "泡打粉", "amount": "4克"}, {"name": "盐", "amount": "2克"}, {"name": "糖", "amount": "30克"}, {"name": "奶粉", "amount": "10克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "淡奶油", "amount": "10克"}, {"name": "适量蔓越莓", "amount": "适量"}, {"name": "黄油", "amount": "60克"}, {"name": "适量杏仁", "amount": "适量"}]'::jsonb, '["所有粉类干性材料混合均匀", "蔓越莓或者蓝莓干浸在水中泡开（放巧克力忽略这步），奶油倒入鸡蛋打散，黄油切小块", "黄油先放入粉类混合物中，搓揉进面粉", "加入蛋液混合物、蔓越莓（蓝莓干、巧克力豆）杏仁，揉成面团（揉至成型即可，切勿过度）用保鲜膜包裹，放进冰箱冷藏1小时后取出，切成六块", "烤箱预热至180度，每块面团涂抹牛奶或者蛋液，放入烤箱烤20分钟", "噹！趁热或者放凉都超好吃，比外面售卖的黄油味更突出，不仅酥脆且有坚果香。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/86fc0aa7ba85482e943a229c1c64ace6_1616w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('减脂｜比瑞幸司康好吃的快手巧克力司康', '烘焙甜品饮料', '司康', '', '[{"name": "鸡蛋", "amount": "1个"}, {"name": "可可粉", "amount": "10克"}, {"name": "低筋面粉", "amount": "160克"}, {"name": "黄油", "amount": "10克"}, {"name": "泡打粉", "amount": "3克"}, {"name": "盐", "amount": "1克"}, {"name": "奶油（怕热量高牛奶也可以）", "amount": "50g"}, {"name": "奶粉（可不加）", "amount": "10g"}, {"name": "巧克力豆（可不加）", "amount": "20克"}, {"name": "20～40g，可加至60g代糖", "amount": "适量"}]'::jsonb, '["10g黄油和代糖，手温融化揉搓在一起。这一步能让司康口感更细腻。建议增加（代糖的最好选择赤藓糖醇，控制量在20g到40g，喜欢甜的可以多加，但是60g以上就会很甜了）", "加入160g低筋面粉，10g可可粉。1g盐，3g泡打粉，10g奶粉。20g巧克力豆。加入鸡蛋液和奶油。混合。不同面粉的吸水量不一样，我试过5次这个水分做出来的面团刚好，不会太湿也不会太干，你先把干粉混合到一起，不出意外是没问题的，如果你觉得太干，可以在5g，5g的加水。", "不揉，一点一点压制成团，避免起面筋", "两层油纸，赶成1cm后的平铺图，像叠被子一样叠起来。", "叠三折。重复这个步骤6次。能让做出来的司康更有层次感。", "最后揉成3cm的厚片，切8块。冰箱冷藏20分钟左右，这样会让黄油更好的分离，为了更好的口感。", "记得刷蛋液。190度烤20到25分钟（如果怕烤的太干尽量从18分钟观察一下，毕竟每个烤箱都不一样。）", "成品图。比瑞幸的更有层次感。很酥脆。搭配拿铁绝配。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/e7b08a2940b640a58811baa5750cc63a_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('满屋飘香，口口都是满足——酥松香甜的蔓越莓蜜豆司康', '烘焙甜品饮料', '司康', '甜', '[{"name": "低筋面粉", "amount": "250克"}, {"name": "（这个糖量不是很甜，喜甜的可以加量哦）细砂糖", "amount": "35克"}, {"name": "盐", "amount": "2克"}, {"name": "泡打粉", "amount": "6克"}, {"name": "无盐黄油", "amount": "70克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "牛奶", "amount": "60克"}, {"name": "适量蔓越莓", "amount": "适量"}, {"name": "适量红蜜豆", "amount": "适量"}]'::jsonb, '["准备好材料。蔓越莓切碎，无盐黄油软化（是软化，不是融化哦），鸡蛋打散。", "将低筋面粉、细砂糖、盐、泡打粉混合均匀，加入软化的黄油，用手抓松抓匀，抓到小小的絮状就行了。", "加入打散的鸡蛋液（鸡蛋液留一点最后的时候刷表面用），继续抓匀抓松。留一小把抓好的粉出来备用，最后做酥顶用。", "往面粉盆里加入牛奶，揉匀，揉好的状态应该是没有干粉，可以成团。别太干，太干了整形会裂开，烤完口感会很干；也别太烂，太烂了粘手没法整形。（不同牌子的面粉吸水量不同，建议加牛奶时候最后留一点看面团情况进行调节。）", "将揉好的面团分成两份，分别用手按扁按圆，厚度大概", "5cm就好了。在其中一份按扁的面团上均匀铺上红蜜豆。铺好了轻轻按压一下，让蜜豆和面团贴合。", "将另一块按扁按圆的面团覆盖在上面，上下两块面团边缘接口处捏紧。", "刷上预留的鸡蛋液。铺上蔓越莓干，用手轻轻按一下，使蔓越莓干和面团贴合，防止烤的时候脱落。撒上之前预留的酥顶。", "将饼切成若干块。", "烤盘铺上油纸，把切好的饼分别放到油纸上，各块之间留点空隙，别挨太紧。烤箱预热190度。", "放烤箱中层，上下火190度，15分钟。（各家烤箱脾气不同，具体大家可以自己摸索哈，最后两分钟留意一下上色）", "噔噔噔噔~松脆可口，摸索摸索可以把蔓越莓蜜豆换成葡萄干啊、巧克力豆啊、蓝莓啊……各种配料做成花式松饼。", "把蔓越莓换成杏仁片也是很好吃哒～"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/b49513509c044f73a6dfa1d4dd59b641_2448w_1957h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('墨西哥肉酱塔可', '烘焙甜品饮料', '塔', '辣', '[{"name": "少许亨氏小清纯沙拉酱", "amount": "适量"}, {"name": "3-5个墨西哥玉米饼", "amount": "适量"}, {"name": "牛肉糜", "amount": "150g"}, {"name": "2-3个番茄", "amount": "适量"}, {"name": "1/5个洋葱", "amount": "适量"}, {"name": "一小把根香菜", "amount": "适量"}, {"name": "半个柠檬", "amount": "适量"}, {"name": "一把沙拉菜", "amount": "适量"}, {"name": "牛油果", "amount": "1个"}, {"name": "少许海盐", "amount": "适量"}, {"name": "少许现磨黑胡椒", "amount": "适量"}]'::jsonb, '["准备好全部的食材，酸甜开胃的肉酱塔可，let's go！", "牛肉末用姜丝，一勺蚝油、一勺生抽、少许盐、半勺料酒、白糖、黑胡椒粉腌渍一刻钟以上。", "取少许洋葱爆香，加入腌渍好的牛肉末炒好，加一点辣椒粉、胡椒粉调味，可以尝一下咸淡再酌情加盐。", "番茄用盐搓洗表面，去番茄籽切小丁，洋葱切小丁，一瓣大蒜切蒜末，香菜洗净切碎。", "制作爽口的番茄莎莎酱，将食材一起倒入碗里，挤入柠檬汁，洒上海盐和黑胡椒碎搅拌均匀，做好了可以放冰箱冷藏。", "牛油果捣碎，挤入亨氏小清纯沙拉酱。", "这个沙拉酱自带花嘴，挤出来是跟裱花奶油一样很可爱的纹路，可以直接装饰。", "用叉子将沙拉酱和牛油果泥搅拌均匀就做好了。", "所有的准备工作就绪，玉米饼可以放烤箱烤脆。预热烤箱，180度烤3-5分钟。", "将炒好的牛肉末和最好的番茄salsa搅拌均匀。", "先在玉米饼底铺上沙拉菜叶", "舀入肉末莎莎酱，放上一勺小清新的牛油果沙拉酱。清爽开胃的肉酱莎莎酱塔可就大功告成啦！\n放在清新的木托盘大理石桌子的背景里，来一张美美的定妆照，就开吃吧！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/104f4c0b018545c2b551bd010b8ff33d_1958w_1306h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('柠檬塔', '烘焙甜品饮料', '塔', '', '[{"name": "1/2个黄柠檬皮屑", "amount": "适量"}, {"name": "1/4个青柠檬皮屑", "amount": "适量"}, {"name": "黄柠檬汁", "amount": "30g"}, {"name": "青柠檬汁（可用黄柠檬汁代替）", "amount": "20g"}, {"name": "百香果汁（用果茸更好）", "amount": "10g"}, {"name": "细砂糖", "amount": "60g"}, {"name": "全蛋液", "amount": "112g"}, {"name": "玉米淀粉", "amount": "3.7g"}, {"name": "吉利丁片（未泡水净重）", "amount": "2.5g"}, {"name": "黑朗姆酒", "amount": "5g"}, {"name": "少许香草精", "amount": "适量"}, {"name": "少许食盐", "amount": "适量"}, {"name": "无盐黄油", "amount": "42g"}, {"name": "1/4个黄柠檬皮屑", "amount": "适量"}, {"name": "1/4个青柠檬皮屑", "amount": "适量"}, {"name": "镜面果胶", "amount": "20g"}, {"name": "1/2张金箔", "amount": "适量"}, {"name": "少许清水（可用柠檬汁代替）", "amount": "适量"}, {"name": "低筋面粉", "amount": "100g"}, {"name": "无盐黄油", "amount": "60g"}, {"name": "少许食盐", "amount": "适量"}, {"name": "糖粉", "amount": "35g"}, {"name": "杏仁粉", "amount": "12g"}, {"name": "全蛋液", "amount": "25g"}, {"name": "全蛋液", "amount": "25g"}, {"name": "淡奶油", "amount": "30g"}, {"name": "无盐黄油", "amount": "12g"}, {"name": "细砂糖", "amount": "12g"}, {"name": "椰蓉", "amount": "12g"}, {"name": "玉米淀粉", "amount": "12g"}, {"name": "朗姆酒", "amount": "5g"}]'::jsonb, '["一、首先制作柠檬果胶部分：先将柠檬洗净，用食盐揉搓表皮去除果蜡，洗净擦干后用柠檬挫皮刀搓出皮屑（只取黄/绿部分，不取白色部分），将镜面果胶与柠檬皮屑、金箔、少许清水（不用太多）混合拌匀，搅拌至金箔成为金箔碎，保鲜膜封面冷藏备用", "二、接下来制作柠檬馅部分：首先将柠檬皮屑与柠檬汁、百香果汁、砂糖、食盐混合倒入复合平底锅中，中火将混合物煮至略微沸腾的状态", "将蛋液分次加入到玉米淀粉中拌匀，搅拌至没有粉类颗粒的状态，加入香草精拌匀，将步骤2中煮好的混合物趁热冲入，用蛋抽快速拌匀", "将步骤3所得混合物重新倒回复合平底锅中，以120-140℃火力回火混合物并不停搅拌，避免蛋液受热凝固，搅拌至浓稠状后调至100℃，继续持续熬煮约30s（还是要快速搅拌），煮至卡仕达酱质地后离火过筛入干净的盆中，降温至45-50℃时加入用冷水泡软的吉利丁片、软化黄油和朗姆酒拌匀，保鲜膜贴面封好，冷藏至少12小时后使用", "三、接下来制作甜酥塔皮部分：首先取一小块冷冻或冷藏的无盐黄油（配方份额外），捏在指尖位置，在塔圈内壁均匀地抹上一层薄薄的无盐黄油（最好用透气的冲孔塔圈，做出的塔皮平整好看），送入冰箱冷藏备用", "甜酥塔皮配方中的无盐黄油室温软化成膏状，依次加入糖粉、食盐、杏仁粉混合拌匀，将蛋液打散，分2-3次加入黄油中拌匀（避免出现水油分离的状态）", "低粉过筛，加入到步骤6的黄油中拌匀至没有粉类颗粒感的状态，保鲜膜封好压扁至1cm左右厚度，冷藏至少30min使面团变硬一些", "在油纸上撒上少许低粉防粘（配方份额外），将冷藏好的塔皮面团取出，面团表面撒少许手粉，盖油纸擀成厚约3mm的面片（擀开过程中面团容易出油粘住油纸，可以再撒一些手粉，不要太多），送入冰箱冷冻使其变硬", "将冷藏的冲孔塔圈取出，裁出若干差不多大小的油纸片垫在塔圈下，用塔圈压在冷冻好的面片上，取下面片（如图所示），送入冰箱冷藏备用", "将剩下的塔皮再次搓匀，冷藏后擀开成3mm厚的面片（参考步骤8），冷冻变硬后切成若干条比塔圈略微长一点儿的长条面片（别太硬，太硬会切碎面皮）", "将步骤10中冷冻的面片放入冰箱冷藏使其略微回软，取出塔圈（操作一个拿出一个，剩下的塔圈最好放冷藏，夏天室温太热，塔底变软很难操作），用小毛刷（毛笔最好）蘸少量清水刷在塔底紧挨塔圈的位置，浸润塔皮，将长条的塔皮拿出贴在塔圈侧边并捏紧收口（刷水可以粘合塔底和侧边，避免出现烘烤时二者脱节的现象）。操作完送回冰箱冷藏", "为所有的塔皮嵌模，冷藏至少20min后取出，用小刀削去超出塔圈高度的塔皮，继续送回冰箱冷藏过夜。第二天将塔皮取出，揭去底部油纸，直接放在铺有透气烤垫的烤盘中，用叉子在塔底戳洞，避免烘烤中底部鼓起。如果使用冲孔塔圈+透气烤垫，就不用在塔皮内垫烘焙石子或大米，如果用油纸或油布烘烤塔皮，建议将比塔皮大一号的油纸揉搓软后，压石子垫在塔皮里一起烘烤，避免底部鼓起。烤箱预热上下火170℃，热风模式，烤箱中层烘烤塔皮约18min，取出后常温放凉", "四、接下来制作椰子奶馅部分：首先将椰蓉倒入铺有油纸或油布的烤盘中，上下火100-120℃将椰蓉烤箱，使其略微上色（约10-12min）；无盐黄油室温软化；将蛋液分次加入到玉米淀粉中，搅拌至没有粉类颗粒感的状态，分次加入软化黄油中拌匀，加入烤好放凉的椰蓉拌匀", "将冷藏的淡奶油加糖、朗姆酒混合打发，与步骤14的混合物拌匀，填入装有平口6号嘴的裱花袋中（", "6cm裱花嘴），裱花嘴贴近塔底表面，挤上厚约3mm的椰子奶馅，烤箱预热上下火150℃，热风模式回火烘烤塔皮约15min，取出后常温放凉", "脱模后用柠檬挫皮刀或细筛网磨平塔皮侧面。图中左为普通塔圈（高度不是缩的，就是比冲孔的矮），右为冲孔塔圈，可以明显感受到冲孔塔圈制作的塔皮表面更匀称平整", "将冷藏好的柠檬馅取出，用蛋抽搅打均匀，用裱花袋挤在塔中，并用小号抹刀抹平柠檬馅", "将抹平柠檬馅儿的塔送回冰箱冷冻至少15min，使柠檬馅略微变硬，将柠檬果胶取出，用小号抹刀抹在柠檬塔表面，即可完成"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/50a12e67c8c0410a9b0a5d39723bdbad_1620w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('外酥里嫩～好吃到停不下来的德式布丁塔', '烘焙甜品饮料', '塔', '', '[{"name": "低筋面粉", "amount": "145克"}, {"name": "糖粉", "amount": "60克"}, {"name": "鸡蛋液", "amount": "35克"}, {"name": "黄油", "amount": "45克"}, {"name": "鸡蛋黄", "amount": "2个"}, {"name": "炼奶", "amount": "20克"}, {"name": "淡奶油", "amount": "155克"}]'::jsonb, '["室温软化的黄油➕过筛糖粉拌均匀，分次加入鸡蛋液拌均匀、倒入过筛的低筋面粉、拌到无颗粒状态面团、分成5份、搓圆放入纸杯中捏成杯形", "淡奶油➕鸡蛋黄➕炼奶混合搅拌均匀过筛一遍、倒入纸杯中8分满、\n放入170度预热的烤箱中、中层烤25分钟即可", "满屋飘香的德式布丁塔出炉啦！", "外酥里嫩的"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a7beca8cf570411185c34b24c22dc6a0_3024w_4030h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('德式布丁塔', '烘焙甜品饮料', '塔', '', '[{"name": "鸡蛋小约40克", "amount": "1个"}, {"name": "黄油", "amount": "45克"}, {"name": "低筋面粉", "amount": "150克"}, {"name": "糖粉", "amount": "60克"}, {"name": "蛋黄", "amount": "2个"}, {"name": "淡奶油", "amount": "200克"}, {"name": "炼乳", "amount": "45克"}]'::jsonb, '["准备材料", "室温软化的黄油加入糖粉，拌至无干粉状。", "分次加入鸡蛋液搅拌均匀。", "筛入低筋面粉，用压拌法拌匀至无干粉状。", "把拌好的面团分成6份搓圆放进纸杯，将面团捏在纸杯里。", "将淡奶油，蛋黄，炼乳混合均匀，过筛后倒入纸杯中8分满。", "烤箱上下火180度预热10分钟，烤25-28分钟即可。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/52921e4b6d674e49aaf8a3ce6265769a_1618w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('跟做有奖2种口味酥香坚果塔｜（蜂）枫糖味｜麻辣味｜好吃好做｜无需塔模具｜新年必备', '烘焙甜品饮料', '塔', '辣', '[{"name": "⬇️❤️塔皮：", "amount": "适量"}, {"name": "低筋面粉", "amount": "200克"}, {"name": "黄油", "amount": "90克"}, {"name": "糖粉", "amount": "45克"}, {"name": "蛋液", "amount": "25克"}, {"name": "盐", "amount": "1克"}, {"name": "⬇️❤️枫糖味坚果：", "amount": "适量"}, {"name": "枫糖（蜂蜜）", "amount": "25克"}, {"name": "黄油", "amount": "25克"}, {"name": "砂糖（可减）", "amount": "15克"}, {"name": "综合果仁", "amount": "220克"}, {"name": "盐", "amount": "0.25克"}, {"name": "⬇️❤️麻辣味坚果：", "amount": "适量"}, {"name": "蜂蜜", "amount": "25克"}, {"name": "黄油", "amount": "25克"}, {"name": "砂糖（可减）", "amount": "15克"}, {"name": "综合果仁", "amount": "220克"}, {"name": "盐", "amount": "0.25克"}, {"name": "辣椒碎", "amount": "2克"}, {"name": "花椒碎", "amount": "1克"}]'::jsonb, '["坚果提前准备好～\n\n这个综合果仁我是自己搭配的，随意搭配了一些巴旦木，南瓜籽，核桃仁，夏威夷果，蔓越莓～就是家里刚好有的东西就好了～\n\n总量220克一种口味即可～你们随意啦，喜欢就好～\n\n蔓越莓和南瓜籽还是建议放，这两个有颜色上的搭配毕竟", "除蔓越莓之外的果仁全部倒入烤盘中～", "130度30-40分钟，中途可以稍微翻动一次～坚果可以提前一天烤熟～备用", "黄油提前软化，天冷可以使用烤箱发酵功能软化，也可以使用发酵箱，吹风机等等～", "黄油软化至手指可以轻松戳洞即可～开发酵软化很快的～二十来分钟就好了，又不会像做热水或者微波炉那样不均匀～", "料理机中加入：软化黄油，低筋面粉，蛋液，糖粉，盐～\n\n这一步，绞肉机厨师机也可以的～绞肉机没有的就上手吧～直接揉", "打成这样的细沙状～即可～", "倒在台面上～他不干不干不干～天气冷而已～往下看", "用手来回搓～借助你的手温～这样面团更均匀～家里太冷会搓的时间长～可以开小太阳来照耀一下你的手～", "成一个光滑的团子～", "上下各一张烘焙油纸～", "擀面杖来回擀～", "杆成厚薄均匀约3毫米的面片～", "拿出一个叉子～\n\n扎好之后送去冰箱平躺冷冻15-20分钟", "扎洞是为了烘烤膨胀不变形～", "我的12连模底宽", "5～\n\n有磨具的直接用磨具吧，我反正不想买～\n\n这个也没有的话，往下看，自己做～我写了～\n\n蛋挞模抠来用一下也可以哈哈哈哈哈哈哈～\n\n办法总比困难多～姐妹", "所以我找一个约", "5宽的圈圈～\n\n🌟就是说，你的圈，比你的托大2-3厘米就够了～\n\n你可以用矿泉水瓶，玻璃杯等东西来刻这个圈圈～", "没有磨具的怎么办～自制～用完还能回收做纸杯蛋糕～哈哈哈哈哈～真是个奇奇怪怪的博主～", "冰箱取出，刻圈～", "当然，如果你有这种花边的圈圈会更好看～我不想买了～哈哈哈哈哈～", "尽量放在正中间～", "全部弄好～没看错，就是12连蛋糕磨具，倒扣过来的样子哈哈哈哈", "边角料～重新擀开，扎洞，冷冻，刻圈～重复以上动作～\n\n\n后面实在太少了就算了～直接搓圆烤了吃掉或者留着下次用吧～", "不管做啥，都要提前预热烤箱，好习惯要保持\n\n预热的时候开热风，温度上来的更快更均匀～\n\n送入提前预热好的烤箱～175度15分钟～", "放两分钟不那么烫手了，手轻轻一推就脱模啦～不会粘～趁热去弄容易碎～\n\n我连续烤了两盘～一共24个～", "侧面看一下～不放在正中间的话，就会不平，一边高一边低～所以你们要耐心点哦～乖", "枫糖（蜂蜜），黄油，砂糖，盐～加入锅中～", "25克盐就是：1小撮盐，什么是一小撮，两根手指头抓一丢丢丢～", "小火煮至焦糖色，出现密集的小泡泡～", "倒入提前准备好的坚果～快速翻拌均匀，让每一颗坚果都裹上糖浆～", "另起一锅：枫糖（蜂蜜），黄油，砂糖，盐～加入锅中～", "25克盐就是：1小撮盐，什么是一小撮，两根手指头抓一丢丢丢～", "辣椒碎2克，花椒碎1克～", "加入糖浆里面去～看到辣椒了吗？", "搅拌均匀～", "戴手套，把坚果放在塔皮上面～用勺子也行～", "两种口味都弄好了～", "150度5-8分钟～热风～坚果和塔壳都熟的～这一步只是为了加热一下，使坚果和塔壳亲密结合一下～所以，两层也没关系～热风可以加速空气循环🔄", "翻出两月饼包装袋～密封一下～", "麻辣味～你一定要试试～", "枫糖味～你更喜欢哪个味儿？"]'::jsonb, 30, 215, '困难', 3, 'https://i2.chuimg.com/37157383b61b43c296351658c7e28c14_1616w_1077h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酥皮泡芙甜点', '烘焙甜品饮料', '泡芙', '甜', '[{"name": "酥皮", "amount": "适量"}, {"name": "80G黄油", "amount": "适量"}, {"name": "55G糖粉", "amount": "适量"}, {"name": "100G低筋面粉（过筛）", "amount": "适量"}, {"name": "泡芙", "amount": "适量"}, {"name": "170G牛奶", "amount": "适量"}, {"name": "75G无盐黄油", "amount": "适量"}, {"name": "1G白砂糖", "amount": "适量"}, {"name": "105G低筋面粉（过筛）", "amount": "适量"}, {"name": "（根据鸡蛋大小会不一样哦）鸡蛋", "amount": "3个"}]'::jsonb, '["（先制作酥皮）黄油软化混合糖粉", "黄油和糖粉拌至细腻", "将低筋面粉加入2中，由底部向上翻，下压，拌至均匀没有粉即可", "用保鲜袋整形，根据你制作的泡芙的大小整形成圆柱形，放冰箱冷藏让他结实点，方便切，太硬也不行哦", "（现在开始做泡芙，开始预热烤箱哦）牛奶、黄油和糖混合", "加热至沸腾，沸腾1分钟之后", "加入过筛的低筋面粉，快速搅拌至至无颗粒，再熄火", "鸡蛋先全部打入碗里，一个个的加入面糊，每加入一个都快速搅拌均匀，加第3个时候要分适量加入，观察面糊粘稠程度，提起成倒三角即可，最后拌至面糊光泽柔顺即可", "装入裱花布袋", "在烤盘均匀挤出，垂直向上提的挤出，下饱满上细（如果烤盘是不防粘的要铺油纸哦）", "酥皮冷藏之后稍微结实，方便切取使用，如果切起来很碎，可以先放一下回温", "在挤好的泡芙上盖上酥皮", "放入预热好的烤箱，上火200度、下火160度烤10分钟，转上火180度，下火160度烤15分钟，第一个10分钟内不要打开烤箱（如果没有分上下火的，上下火均180度，25-30分钟，最后五分钟要看咯，因为每个烤箱温度不一样，不要上色太过咯）", "一种是有酥皮的，一种是没有酥皮的，这是配方全部的份量，可以减半。", "又酥皮，无馅都很好吃", "泡芙里面的馅；卡仕达酱（具体做法不想写了，你们百度一下哦）或者淡奶油和糖粉打发的馅也很轻盈，很赞"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/12cdc3de880d11e6b87c0242ac110003_2448w_3264h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('奶油泡芙', '烘焙甜品饮料', '泡芙', '', '[{"name": "低筋面粉", "amount": "100g"}, {"name": "淡奶油", "amount": "200g"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "水", "amount": "160g"}, {"name": "黄油", "amount": "80g"}, {"name": "白糖（泡芙皮）", "amount": "1小勺"}, {"name": "白糖（淡奶油）", "amount": "20g"}, {"name": "1/2小勺盐", "amount": "适量"}]'::jsonb, '["按照配方将黄油、水、白糖和盐称量好，准备一口小锅，将黄油、水、白糖和盐倒入锅中。", "这时用小火慢慢的给锅加热，同时轻轻搅拌，黄油会一点点的在水里溶化（不要用大火，以免黄油还没化而水却先沸腾了）。", "加热过程中将面粉称量好并过筛。", "待黄油完全溶化，水开始沸腾的时候，我们将面粉一次性倒入锅中。", "同时用打蛋器快速的搅拌，使面粉与水充分的混合均匀（如图，将面粉烫熟），此时可以将炉火关闭。", "继续搅拌面糊，同时将已经打散的鸡蛋液分多次倒入面糊，每次倒一点点，搅拌到与面糊充分混合后再倒入下一次。", "就这样边搅拌边倒入蛋液，直到面糊变得细腻幼滑，用打蛋器提起会拉起来一段比较长的拖尾，这个状态面糊就算制作成功了。（因为只能用手动，所以搅拌的时间会比较长，做好心理准备～）", "把制作好的面糊转移到裱花袋中，用菊花型裱花嘴垂直烤盘挤出一个个小小的泡芙坯。(注意间距要大一些，泡芙膨胀很厉害的~)然后用手指沾点水把头上的尖尖按瘪，这样烤出来比较好看。", "时间设置25分钟，温度调至190度，放入烤箱开始烘焙，随着时间的推移，泡芙会慢慢长大，20分钟过后观察表面如果已经上色，基本就可以取出来了，以免烤糊。这样泡芙皮就算制作完成了～", "在烘烤过程中，我们就可以制作奶油馅料了。将淡奶油倒入打单盆里，加入适量的白砂糖。", "用电动打蛋器快速搅打，奶油会由稀慢慢变得浓稠，最后至表面有清晰的纹路，且能稳定住形状即可。", "将奶油转移至裱花袋中，在下端剪开一个小口，将打好的奶油挤入泡芙自然形成的裂缝中（或自己捅开一个小洞），这样一份香浓可口的奶油泡芙就完成啦～"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/8a87ad40883011e6a9a10242ac110002_600w_400h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香草泡芙', '烘焙甜品饮料', '泡芙', '', '[{"name": "无盐黄油", "amount": "80克"}, {"name": "（5~6个）鸡蛋", "amount": "250克"}, {"name": "低筋面粉", "amount": "120克"}, {"name": "水", "amount": "150克"}, {"name": "盐", "amount": "2克"}, {"name": "（4个）蛋黄", "amount": "80克"}, {"name": "纯牛奶", "amount": "300克"}, {"name": "细砂糖", "amount": "75克"}, {"name": "低筋面粉", "amount": "15克"}, {"name": "玉米淀粉", "amount": "15克"}, {"name": "1/2条香草豆荚", "amount": "适量"}]'::jsonb, '["⭐️关注我们公众号：甜悦家烘焙，获取更多的教学视频&amp;烘焙工具，材料的优惠信息。\n\n淘宝店：甜悦家\n\n如果在制作过程中有什么疑问，可以扫码添加我的小助理的微信，她会给你详细解答哦，还可以加入甜悦家的烘焙交流群，还会有淘宝优惠哦~", "认真先看完视频哇，有许多要注意的小细节~~注意视频中的小贴士", "【香草馅】", "先把香草豆荚的籽给取出来", "然后把牛奶和香草豆荚都放进锅里煮沸", "牛奶在煮的时候我们把细砂糖和蛋黄混合均匀，不需要打发", "然后把低筋面粉和玉米淀粉过筛加入蛋黄里搅拌均匀", "必须把所有干粉都搅拌均匀了，完成之后的状态如图，看不清可以看视频中的状态", "蛋黄糊做好之后，牛奶也差不多沸腾了，这个时候把沸腾的牛奶慢慢加入蛋黄糊里搅拌均匀，注意一开始别倒太快，否则蛋黄很容易烫熟，具体操作请看视频。", "牛奶和蛋黄糊混合均匀之后，再倒回锅子里，然后回炉子上小火加热，一边加热一边搅拌，中途一刻不能停，一停底部就会结块，香草馅就没办法顺滑了，具体操作请看视频。", "香草馅如果在做的时候控制不了火，那底部结块太快的时候，可以离火在桌子上用打蛋器把香草馅搅拌均匀，最后要搅拌如图中的状态才算是完成，具体操作请看视频。", "煮好的香草馅把它倒入盘子中铺平", "然后盖上保鲜膜，方法请看视频，盖上保鲜膜之后放入冰箱冷藏，让它迅速降温，那香草馅就算做好了。", "【泡芙】", "首先把盐，水和黄油放入锅中煮沸", "油水在煮的时候我们把低筋面粉过筛备用，等下再过筛，就迟了", "再把鸡蛋打散", "油水煮沸之后，要在水还是沸腾的状态下，一次性把过筛好的面粉全部加进去", "然后用打蛋器迅速搅拌均匀，进行糊化，温度不够高，面粉的糊化做不好，会影响泡芙成型", "打蛋器搅拌均匀之后就要转刮刀进行操作了，刮刀用按压的手法来检查这个面团有没有拌匀的时候，就是看看还有没有干粉，这个过程其实也是在挥发面团过多的水分，检查搅拌到没有干粉就可以了。", "然后加入蛋液混匀，泡芙面糊第一次添加的蛋液，是所有蛋液一半的量，因为面糊的温度较高，为了避免温度高使蛋液凝固，所以我们一开始要加入较多的蛋液来降低面糊的热度。", "剩余的蛋液我们要分数次加进去泡芙面糊里，每次加入都搅拌均匀再加第二次，具体操作，和每一次加入蛋液后的状态，请看视频。\n小贴士【鸡蛋对泡芙的品质有很大的影响，当我们煮沸水分加入面粉搅拌的时候，因为火力和时间的不一样，水分的挥发也不一样，不同面粉的吸水性也不一样，因此也影响到鸡蛋的使用量。相同分量的鸡蛋，到了每个人手里，制作出来的面糊干湿程度可能会不一样，所以要视情况添加，使面糊达到最佳的状态，倒三角就可以了】", "面糊搅拌完之后烤箱190度上下火预热", "然后把泡芙面糊挤入烤盘中，每个大概是5厘米，如果要做大泡芙就挤大一点，面糊一定要有硬度，否则是烤不了大泡芙的", "泡芙挤出来之后会有一个小尖勾，我们用剩余的蛋液抹平一下就可以了", "中层 上下火190度 烤20分钟\n马上转 中层 上下火170度 再烤20分钟\n全程大概40分钟左右", "泡芙烤完之后，我们把香草馅从冰箱拿出来，检查一下是不是成功的，好吃的香草馅是不粘盘和保鲜膜的", "检查完之后把香草馅按压顺滑，然后装入裱花袋里", "泡芙我们用筷子在底部戳一个小洞", "然后把馅料挤进去泡芙，这个泡芙就做好啦~~【后面会一些要注意的事项和小贴士，请大家认真看哦】", "希望做大家都能做出棒棒的泡芙哦~~做出来记得交作业哦~~~"]'::jsonb, 30, 155, '困难', 3, 'https://i2.chuimg.com/f906e84a888e11e6a9a10242ac110002_578w_420h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酥皮奶油泡芙', '烘焙甜品饮料', '泡芙', '', '[{"name": "黄油", "amount": "30g"}, {"name": "糖粉", "amount": "12g"}, {"name": "低筋面粉", "amount": "37g"}, {"name": "黄油", "amount": "40g"}, {"name": "糖", "amount": "2g"}, {"name": "盐", "amount": "1g"}, {"name": "水", "amount": "100g"}, {"name": "低筋面粉", "amount": "60g"}, {"name": "左右鸡蛋", "amount": "2个"}, {"name": "淡奶油(我用的是植物性奶油）", "amount": "100g"}]'::jsonb, '["酥皮：30g黄油切成小块常温软化", "筛入糖粉12g、低粉37g，搓成粗玉米面状态。", "捏成面团，再整理成长条形，包上油纸或保鲜膜放冰箱冷藏1-2小时。注意不要过度揉捏，成型即可。", "泡芙：黄油40g、糖2g、盐1g、水100g混合，加热至黄油全部融化，出现小泡泡转小火。", "低粉过筛后一次性全部倒入。", "拌匀至无干粉，成光滑柔软的面团后离火。", "面团晾凉，温度到60度左右的时候，分多次加入打散的鸡蛋，每加一次搅拌均匀后，看下状态再加", "搅拌到把刮刀抬起来出现如图一样（倒三角），证明已经可以了，面糊过稀或过稠都会影响泡芙最后膨起来的程度。", "烤箱提前预热，把面糊装进裱花袋里，挤成大小均匀的颗粒，每颗之间保持有2厘米左右的距离（可以不用裱花嘴）", "从冰箱取出冷藏好的酥皮，切成厚度", "3厘米左右的薄片。（酥皮不能提前拿出来切，因为黄油会融化）", "将酥皮片盖在烤盘里挤好的泡芙面团上，每个面团放上一片酥皮。", "烤箱预热后放入泡芙，180度20分钟左右，待泡芙膨胀定型后转160度30分钟左右。（表面有点发黄即可。泡芙在膨胀过程中不要开烤箱，以免遇凉收缩。）", "淡奶油提前打到七八分发，取一个泡芙，在底部戳一个小洞。", "挤入奶油。（要等泡芙冷却后再挤入奶油哦，否则奶油遇热会很快溶化的），喜欢水果的，可以加入。", "欢迎加烘焙群：473667999\n或者用手机扫右边的二维码→"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/79cd7ace88ea11e6a9a10242ac110002_1046w_852h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酥皮泡芙', '烘焙甜品饮料', '泡芙', '', '[{"name": "酥皮材料", "amount": "适量"}, {"name": "低筋面粉", "amount": "41克"}, {"name": "黄油", "amount": "41克"}, {"name": "糖粉", "amount": "33克"}, {"name": "泡芙材料", "amount": "适量"}, {"name": "低筋面粉", "amount": "64克"}, {"name": "鸡蛋", "amount": "105克"}, {"name": "黄油", "amount": "45克"}, {"name": "砂糖", "amount": "1克"}, {"name": "牛奶", "amount": "107克"}, {"name": "盐", "amount": "1克"}, {"name": "泡芙馅材料", "amount": "适量"}, {"name": "抹茶粉（宇治御金香）", "amount": "7克"}, {"name": "淡奶油", "amount": "300克"}, {"name": "（可选）砂糖", "amount": "10克"}, {"name": "白巧克力", "amount": "40克"}]'::jsonb, '["制作酥皮\n将室温软化的黄油和糖粉拌至完全融合。", "筛入低粉面粉，翻拌至均匀无干粉", "将混合后的面团放在两张油纸中间，再用擀面杖擀成长28厘米，宽14厘米，厚2-3mm的薄片，放入冰箱里面冷冻10分钟，再用模具压出17至18个左右圆形（压酥皮的圈最好选大于挤泡芙糊的圈）。将压好的酥皮材料放入冰箱冷藏，边角料可再擀平再压圆片，也可以放入冰箱冷冻之后再用\n（方中成品在17至18个左右)", "制作泡芙\n黄油、盐、糖、牛奶放到锅中开中小火加热不停轻轻搅拌至微沸腾。", "将过筛后的低筋面粉倒入快速搅拌至无颗粒，约40秒后，待锅底沾上一层薄膜离火。面团要烫熟、烫透，但不要出现糊底的现象。（面粉要过筛，以免出现面疙瘩）\n\n低筋面粉加入锅内后注意别加热过度，如果加热过度，就会导致分离现象的产生。火候太大，也可能会造成结块。", "将烫面糊取出转移到另一个打蛋盆，锅底膜不需要刮出，为了不让锅内余热继续加热面糊。分多次加入蛋液，继续搅拌，让蛋液与面糊充分融合，每次加入鸡蛋后，面糊必须拌匀上劲，", "注意观察面糊状态，用塑料刮刀舀起面糊在刮刀上呈倒三角状态即可。", "烤盘垫入油布，切件器粘面粉印出18个左右痕迹。\n\n将混合好的面糊装入裱花袋，用直径约1cm的裱花嘴挤出圆形。 挤好的泡芙上面会有个小尖，手摸一下湿布把尖角按下去，这样烤出来泡芙不容易歪。泡芙之间要留有一定的距离，以防烘烤后粘连在一起。\n\n制作好的面糊必须马上制作，面糊如果冷掉了，糊化的面糊会变质。所以务必要趁热进行操作", "将事先做好的酥皮取出，盖在挤好的泡芙面糊上。", "烤箱提前进行预热230度，中下层，泡芙进烤箱后调置在220度，一担面糊膨胀起来，就将烤温调降至180度（面糊大概在12分钟左右膨起），共烘烤时间在30分钟左右。\n\n掌握好烘烤温度，是迈向成功的第一步，摸透自家烤箱脾气这很重要。方中的烤温只适合我家烤箱。仅供参考。\n\n烤箱的温度一定要适当，炉温过高，表面上色深而内部不熟，炉温过低，制品不易起发，而且不易上色。\n\n烤制过程中千万不要打开烤箱，如果打开烤箱，由于泡芙面糊里还残留着水分，就会缩小下陷。", "烤好后烤箱开一条缝散热25分钟后出炉。", "制作泡芙馅料\n选厚底奶锅，将白巧克力、抹茶粉、淡奶油倒入锅中加热烧开搅拌均匀离火，待凉用料理棒打匀。倒入打蛋盆盖好保鲜膜入冰箱冷藏5小时后打发", "将冷藏后的抹茶奶油用打蛋器中速打至8分发左右可裱花状态即可。", "将圆形泡芙底部扎一圆孔，将馅料从孔内挤入", "切开的泡芙。\n好吃的不得了。", "喜欢巧克力味的可把白巧换成黑巧，抹茶换成可可。\n\n可可粉7克\n黑巧克力40克\n淡奶油300克\n砂糖10克（可选）", "也可选最简单的奶油馅。\n淡奶油300克\n糖粉24克", "方中能做12厘米大的两只花环泡芙。\n建议比酥皮泡芙多烤5分钟。", "两个花环泡芙馅用了\n250毫升安佳淡奶油\n4克抹茶粉\n25克糖粉\n打发做的泡芙夹馅", "掌握好烘烤温度，是迈向成功的第一步，摸透自家烤箱脾气这很重要。方中的烤温只适合我家烤箱。仅供参考。\n家宝徳烤箱"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/9d6a7624241411e7bc9d0242ac110002_1836w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单的奶油霜刺绣花朵', '烘焙甜品饮料', '奶油霜', '', '[{"name": "奶油霜", "amount": "适量"}, {"name": "小毛笔", "amount": "适量"}]'::jsonb, '["调好4种颜色的奶油霜，白色 黄色 深粉色 浅粉色", "因为是做到一半才想起来拍菜谱的，所以这之前的步骤我口述下，请大家自行脑补，找一张你喜欢的花花图片，用半透明的糯米纸转印下来，我用的是食用铅笔，用剪子沿边缘剪下来，在蛋糕上贴平，用黄色的奶油霜先勾边", "把三色奶油霜依次挤好，注意以下两点", "奶油霜要软一些", "一次挤1个花瓣最好", "拿起你的小毛笔，从深粉色巷白色刷刷", "完成biubiubiu"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/5c7f6ee40c8611e7947d0242ac110002_1280w_856h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('奶酪奶油霜-cupcake 杯子蛋糕奶油霜首選', '烘焙甜品饮料', '奶油霜', '', '[{"name": "奶油奶酪", "amount": "200克"}, {"name": "動物性淡奶油", "amount": "250克"}, {"name": "糖粉", "amount": "50克"}, {"name": "10mL利口酒(喜歡才加)", "amount": "适量"}]'::jsonb, '["奶油奶酪提前拿出冰箱室溫軟化", "把奶油奶酪隔熱攪至順滑無顆粒\n要加利口酒就這時加\n和奶油奶酪一起攪拌至融合", "淡奶油一次性加入糖粉\n打發至八分發", "把步驟2 加入 步驟3\n一起打發到融合\n不要打發過了哈\n會油水分離的\n建議這步用手動打蛋器", "把打發好的奶酪鮮奶油包上保鮮紙放入冰箱冷藏2小時\n做這步的目的是讓鮮奶油變硬\n裱花的時候花形更立體漂亮\n如果個不是完美主意者可以立即用啦", "我是把奶油直接裝袋放入冰箱的", "來做一個奶酪鮮奶油草莓搭😋"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a6865465fc8740e8b0a91adfc8177649_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('快手淡奶油奶油霜( 超白)', '烘焙甜品饮料', '奶油霜', '', '[{"name": "铁塔淡奶油", "amount": "300g"}, {"name": "阿尔卑黄油或伊利白油", "amount": "200g"}, {"name": "白糖或砂糖", "amount": "30g"}, {"name": "适量柠檬汁", "amount": "适量"}]'::jsonb, '["200g黄油室温软化，伊利白油和阿尔卑发酵黄油是目前市场上性价比较高，颜色偏白适合裱花用的黄油(如果想做出白白的奶油霜不建议选用其他品牌黄油)", "打发黄油直至发白", "取100g铁塔淡奶油+30g糖，微波炉加热或隔水加热至糖融化(铁塔奶油在常用的几个牌子里是成色较白的，建议不要替换其他牌子，除非比铁塔白)", "加入冷藏的200g淡奶油(加热后的淡奶油会变黄，所以这里我们只取少量淡奶油加热融化糖，热奶油加冷藏的奶油刚好达到室温，做奶油霜温度正合适)", "淡奶油中加少许柠檬汁调味，并混合均匀", "分数次把淡奶油倒入黄油中并打发", "打到光滑，我们就得到了超白的奶油霜"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/939230bb70c24de8b17d60f7f96e77f5_2048w_3072h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('别的小朋友都会做韩式裱花奶油霜啦！你什么时候来学', '烘焙甜品饮料', '奶油霜', '', '[{"name": "A", "amount": "适量"}, {"name": "细砂糖", "amount": "120g"}, {"name": "水", "amount": "55g"}, {"name": "B", "amount": "适量"}, {"name": "蛋清", "amount": "153g"}, {"name": "细砂糖", "amount": "20g"}, {"name": "柠檬汁", "amount": "3ml"}, {"name": "C", "amount": "适量"}, {"name": "1/4tsb盐", "amount": "适量"}, {"name": "黄油", "amount": "500克"}]'::jsonb, '["小奶锅内放入a中的细砂糖和水，大火煮开后调中小火继续煮", "然后把b中的原料放入厨师机，开始高速打发蛋白，待蛋白出现羽毛状，提起打蛋头，蛋白呈弯钩状即打发完成，厨师机调至中档。", "此时糖水也正好煮至118度，离火，缓缓倒入打发蛋白中，打发均匀（即完成意式蛋白霜）；中速继续搅拌至常温。", "待3中搅拌至常温，将软化至室温的黄油切小块加入", "同时加1/4tsb盐，再继续加入黄油，每次加一小块，打蛋器混合均匀后再加下一块。", "黄油全部加入，继续搅拌至均匀，最后高速打发30秒，完美的奶油霜就完成啦"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/9a1111a7504a4832afe0568e2c8a6465_1100w_733h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('十七种常用淡奶油/奶油霜调味，让你的蛋糕丰富起来', '烘焙甜品饮料', '奶油霜', '辣', '[{"name": "见下方正文奶油", "amount": "适量"}, {"name": "见下方正文各辅料", "amount": "适量"}]'::jsonb, '["一、巧克力奶油\n\n这个算是比较常用的奶油，黑森林蛋糕必备款。\n\n黑巧克力20g   淡奶油100g   细砂糖5g  稳定酱适量（可选，可不加）  细砂糖视巧克力口味增减\n\n⒈\n①黑巧20g，淡奶油100g隔水加热融化，不要超过60度，加入砂糖融化均匀。\n②冷藏隔夜降温至2-6度，隔冰水打发。\n⒉\n①黑巧20g，淡奶油20g隔水加热融化，不要超过60度，冷藏2小时至凝固。\n②凝固的巧克力奶油加适量淡奶油稳定酱打散，加入30g淡奶油打均匀，加入50g淡奶油打发。\n\n★★★这里包括下面的隔夜不是必须的，冷藏4小时以后就可以用了，但是很多时候隔夜的效果更好。这里的隔冰水也不是必须的，隔冰更好打发。加稳定酱的奶油，看稳定酱状态分次加奶油打均匀后打发。", "二、抹茶奶油（椰子/酸奶/可可味）\n\n抹茶粉3g  淡奶油30g  淡奶油100g  淡奶油稳定酱适量（可选） 白巧克力20g（可选）  细砂糖视巧克力口味增加\n\n⒈\n①抹茶粉3g淡奶油30g隔水加热混合均匀，成为无颗粒无团的抹茶酱。\n②冷藏隔夜降温至2-6度，取出加入100g奶油打发。\n⒉\n①抹茶3g淡奶油30g隔水加热混合均匀，加入白巧克力20g融化搅拌均匀。慢慢加入100g奶油使混合物温度升高，不要超过60度，并搅拌均匀。\n②冷藏隔夜至2-6度，隔冰水打发。\n\n★慢慢加入100g奶油，一次性加进去会使前面的混合物凝固。\n★如需加入稳定酱，先在抹茶奶油酱里加入稳定酱打散，在分次加入奶油打均匀后打发。\n★★★抹茶的储存，低温避光密封防潮，请入冰箱\n★★★这里很多人问过我为什么要加热，第一因为抹茶稍微加热后香味会更浓郁，第二是因为这种操作打出来抹茶不会结团起小疙瘩\n★抹茶酱+冰块打碎就是抹茶冰沙啊，加个奶油顶就是星冰乐\n\n★★★抹茶粉换成椰子粉可可粉酸奶粉按口味适量增加后，与奶油煮开，隔夜冷藏即可\n★椰子粉是叶子饮料，不是椰子面粉\n★酸奶粉是酸奶饮料，不是带菌的发酵粉。酸奶不能用", "三、乳酪口味奶油\n\n奶油奶酪30g  淡奶油20g  糖10g  淡奶油200g  淡奶油稳定酱适量（可选，可不加）细砂糖视自己口味增加\n\n①奶油奶酪隔水软化至糊糊状\n②淡奶油20g糖粉10g隔水加热至融化，加入糊糊状的奶油奶酪搅拌均匀，成为奶油奶酪酱\n③冷藏降温至2-6度，加入200g奶油打发\n\n★比例大概为30g奶酪酱100g奶油。\n★如需加入稳定酱，先把奶油奶酪酱与稳定酱混合打匀，再分次加入奶油打均匀后打发。", "四、伯爵红茶味奶油/奶茶味奶油\n\n一包红茶粉/5g红茶粉   淡奶油50g   细砂糖5g  淡奶油100g  稳定酱适量（可选）  细砂糖视自己口味增加\n\n①取一个红茶包，大概5g红茶粉，拆掉纸包只留茶粉，加入淡奶油50g和砂糖5g，开小火煮，不断搅拌，煮出红茶的颜色咖啡色和浓郁茶香关火。\n②将煮好的红茶奶油过筛，去掉茶粉。冷藏隔夜降温至2-6度备用。\n③取出冷藏好的红茶奶油酱，加入100g奶油打发。\n\n★建议翻倍做，量太少容易煮干，可以烧开以后离火焖\n★可以用红茶茶叶，多加点奶油煮或者离火焖都可以。红茶酱+牛奶就是奶茶啊👀\n★如需加稳定酱，将红茶奶油酱与稳定酱一起打散开，再分次加奶油打均匀后打发。", "五、咖啡味奶油\n\n现磨咖啡豆粉7g/速溶黑咖啡粉1-2g  淡奶油100g  吉利丁片", "5～1g  细砂糖10g  淡奶油稳定酱适量（可选，可不加）  细砂糖是自己口味增加\n\n①吉利丁片冷水泡软备用\n②黑咖啡粉与淡奶油混合，加入加糖小火熬煮出颜色及香味。煮好的咖啡奶油过筛，去掉咖啡粉。\n③保持咖啡奶油温度50-60度左右，放入泡好的吉利丁，搅拌融化。入冰箱隔夜冷藏，降温至2-6度。隔冰打发。\n\n★如需加入稳定酱，先将稳定酱打散，分次加入咖啡奶油打均匀后打发。\n★咖啡酱+热牛奶就是拿铁啊", "六、奥利奥奶油\n\n甜咸两口味，需要那种用哪种。\n\n淡奶油100g  奥利奥饼干沫10g  细砂糖10g  盐一撮  淡奶油稳定酱适量（可选，如抹面建议加）\n\n①奥利奥碾细末备用\n②淡奶油加糖（如需咸口此时加入盐一撮），打至七成发。\n②加入奥利奥沫，翻扮两三下，再打两三圈就好。\n\n★如需加入稳定酱，先把稳定酱打散一下，再分次加入奶油打均匀后打发。", "七、黑芝麻/核桃/杏仁口味淡奶油\n\n黑芝麻糊/核桃糊/杏仁糊粉（超市有售，比如南方黑芝麻糊）15g   淡奶油30g   淡奶油100g   淡奶油稳定酱适量（可选） 细砂糖视自己口味增加\n\n①各种糊的粉15g混合淡奶油30g，加热煮成糊状，这个必须加热一下才会香，都知道糊糊用凉水是冲不开的哈。冷藏降温至2-6度。\n②取出做好的糊糊，加入100g淡奶油打发。\n\n★这里的味道会比较淡一点，因为糊糊的粉里添加了其他辅料。如果需要味道浓郁可以下拉使用坚果酱调味\n★如需加入稳定酱，先与糊糊打均匀，再分次加入淡奶油打均匀后打发", "八、焦糖奶油/太妃奶油\n\n选这张图的时候，我就想到一句话，海盐焦糖巧克力，完美的搭配。\n\n细砂糖20g  奶油25g  黄油5g  海盐一撮  淡奶油200g  淡奶油稳定酱适量（可选）\n\n①加热25g奶油备用，不能太凉\n②取小号平底不沾锅，放入砂糖，翻炒至融化。加入加热过的奶油，熬煮至焦糖色，放入黄油，海盐，煮至浓稠，入冰箱冷藏降温至2-6度。既为海盐焦糖酱。\n（★焦糖酱如果大量制作起来保存，可以把熬煮淡奶油含量增加至50-75g，打发的时候适量减少就可以了。）\n③冷藏好的海盐焦糖酱，加入200g奶油打发。\n\n★比例大概为100g奶油20g焦糖酱。\n★如需加入稳定酱，先与焦糖酱混合打均匀，再分次加入奶油打均匀后打发。\n★海盐焦糖酱可以翻倍做，干净无水的玻璃瓶保存，调味蘸酱都很好吃。\n★焦糖酱水份会炒干一些，大概成品40g左右。量少不太好做，建议至少翻倍。不翻倍就注意经常离火不要让水份都蒸发没了，那就成一块太妃糖了……\n★★量少不好控制的话，熬的酱凉了以后会成为太妃糖😂😂建议①酱晾凉到40–50度左右，把200g奶油加热到40-50度。把奶油倒进焦糖酱拌匀，冰箱冷藏一夜直接打发。②同第一种办法加入50g温热奶油并冷藏，用的时候再加150g奶油打发。\n★焦糖酱+咖啡就是焦糖玛奇朵啊", "九、柠檬味奶油/百香果奶油\n（糖渍橙皮和柚子皮也适合加入奶油，但不适合做凝乳，做果酱更好一些）\n\n柠檬奶油制作稍微麻烦一些，状态也不太好掌控，多做几次熟练就好了。柠檬奶油要先做柠檬凝乳，也可以说是柠檬酱。不管是慕斯还是奶油还是其他奶制品，都是用柠檬凝乳去调味，而不是直接加柠檬。直接加柠檬汁奶油会变简易马斯卡彭。\n\n蛋黄1颗   细砂糖30g  新鲜柠檬汁25g  黄油15g  柠檬皮屑适量  淡奶油100g  淡奶油稳定酱适量（建议使用）\n\n①蛋黄细砂糖新鲜柠檬汁柠檬皮入小不锈钢盆，搅拌均匀不需打发。加入切小丁的软化的黄油。\n②烧一盆水，隔水加热①，慢慢搅拌，不要让蛋黄凝固，稍微粘稠就可以离火了。状态是用勺子背沾取酱，中间画一道，有明显痕迹即可。\n③这时候可以直接放冰水降温，没有冰水冷藏降温到2-6度。即成为柠檬凝乳。\n④20g柠檬凝乳混合100g奶油打发，撒适量柠檬皮装饰。\n\n★建议加入淡奶油稳定酱，这个奶油状态软一些。先把凝乳与稳定酱打均匀，再分次加入奶油打均匀后打发。\n★这里只写了蛋黄版柠檬凝乳，全蛋版也可以用，全蛋版下厨房加州厨房有写，自行搜一下哈。\n★百香果凝乳做法同柠檬凝乳，柠汁换去籽百香果汁，可以多加5-10g，去掉柠檬皮即可～", "十、果蔬口味奶油\n\n适用于任何有冻干粉的果蔬，用水果的时候多一些，但南瓜紫薯这类蔬菜也可以搭配出很好吃的口味，比如焦糖巧克力南瓜味，莓果芝士紫薯味。这里只能使用冻干粉，烘干研磨的不行不行不行不行不行。\n\n果蔬冻干粉5-15g（果蔬味道有浓有淡，根据自己果蔬情况去调节）  淡奶油30g  淡奶油100g   果粒适量（可选）  淡奶油稳定酱适量（可选） 细砂糖视自己口味添加\n\n①取适量冻干粉混合30g淡奶油，小火加热至冻干粉融化，冷藏降温至2-6度。\n②果蔬奶油酱，加入100g奶油打发。\n③如果用来夹心，可加适量鲜果粒或果干果粒，增加口感。\n\n★紫薯南瓜这些，选熟的粉调色用。不要加热的太热，会成为紫薯泥南瓜泥……\n★如需加入稳定酱，果蔬奶油酱与稳定酱混合打散，分次加入奶油打均匀后打发。", "十一、罗勒味/薄荷味奶油\n\n罗勒作为香料来说，咸口比较容易被人接受。清甜口带清香气息也还不错。但是毕竟是进口来的调料，国人还是接受程度差一些。但是用来辅佐正宗欧包和特殊口味甜品还是很好吃的，搭配柠檬或者松子就别有风味。也可以搭配各种粗粮及坚果。\n\n薄荷呢是接受程度比较高的一款香草，口味清新为主，适合搭配柑橘类口味，青柠柚子甜橙都很好吃，很是清爽。\n\n新鲜罗勒/薄荷叶子适量  清水几滴  淡奶油100g  吉利丁片1g  细砂糖10g/海盐", "5g  淡奶油稳定酱适量（可选）  柠檬皮碎沫适量（可选）\n\n⒈\n①吉利丁片冷水泡软备用\n②新鲜香草叶子切细碎，取2/3放入容器，加一点水捣出汁，取一小勺用就够了。剩余1/3切的细细碎碎的，考验刀功的时候到了。\n③过筛香草泥，取汁，加入100g淡奶油小火煮沸并搅拌大概半分钟一分钟的，蒸发一下水份，关火。（这一步吃咸口加盐，吃甜口加糖融化，或者此时不加，打发时在加）\n④降温至60度左右，加入泡好的吉利丁，搅拌融化。继续降温至30度以下，放入1/3切细碎的香草沫沫，翻扮几下就行了。\n⑤入冰箱冷藏隔夜降温至2-6度，取出打发。（这一步没调味的进行调味，可以加入一点柠檬皮碎末提一下清香味道，不要加多掩盖香草香味）\n⒉\n★因为这里增加的香草汁水份并不多（没有超过5g），所以直接打发也可以\n①同上面第二步\n②过筛香草泥，取汁，加入100g奶油打发。\n③加入香草碎末翻扮均匀。可以加入一点柠檬皮碎末提味。\n\n★如需加入稳定酱，分次加入奶油打均匀后打发。\n★量大可以直接搅拌机或者均质机打成香草泥来用不用过筛，因为本身细腻。也可以粗略过掉大纤维", "十二、麦片奶油（更建议做奶油霜）\n\n这个奶油是看人家做学来的，只因为很好看😂😂只是在做好的奶油里加了宝氏的彩色麦片，但是因为麦片的特性，所以更建议做奶油霜。\n\npost宝氏水果味彩色麦片适量  任意口味淡奶油  建议加一点稳定酱\n\n①彩色麦片碾碾碎备用\n②准备打发好的奶油，麦片加进去拌匀", "十三、天然色素奶油，植物本身味道，不能做太深的上色哈\n\n蝶豆花茶（蓝紫色）/山栀子（黄色）/甜菜切片（红色）适量   奶油   细砂糖  稳定酱适量（可选，建议加）\n\n天然色素帖子已经单独更新，查看新帖使用\n\n★如需加入稳定酱，先将稳定酱打散，分次将冷藏好的奶油加入稳定酱打均匀后打发。\n★黑枸杞，藏红花理论上也适用于这个方法给奶油调色，不过价格太贵了！请土豪尝试。\n★班兰叶（香兰叶）打汁过滤后直接加入也可以，加热会变色", "十四、坚果类奶油\n\n这一类是可以买到坚果酱，来调制奶油。有榛子酱，腰果酱，夏威夷果酱，杏仁酱，开心果酱，核桃酱，还有经常吃的花生酱和芝麻酱。对，芝麻酱就是麻汁…这里推荐入手的是开心果酱，颜色碧绿，口感香醇，虽然原料贵，但是成品确实特别好吃。用来做慕斯马卡龙或者夹心都不错。坚果适合搭配巧克力，黑白巧都好吃。\n\n增加口感用的坚果碎，芝麻这一种，要碾一下，直接放芝麻粒不好吃。就是北方常用芝麻盐里那种碾碎的。\n\n这里要提一下栗子泥，栗子泥也属于坚果，但并不适合用在这里。上面提到的都是油性的坚果酱，栗子泥是水性的。用栗子泥来装饰蛋糕，是栗子泥加黄油打顺滑，加奶油调节一下软硬度就可以。详细方法查阅蒙布朗配方。\n\n坚果酱5-20g  淡奶油100g  淡奶油稳定酱适量（可选，建议用） 同类坚果碎适量（可选）细砂糖视自己口味增加\n\n①奶油打发到有点粘稠的时候，加入坚果酱继续打发。\n②打发后的奶油可以视情况加入适量坚果碎增加口感。\n③建议加入淡奶油稳定酱，坚果酱先与稳定酱打均匀再分次加入奶油打发。\n\n★坚果酱和糖浆一样都要适量加，加太多了会造成奶油过于软。\n★这里用的是可流动性的坚果酱，超市里有种花生酱没有流动性，干干的膏状，那个适合做饼干，不适合打发。", "十五、利用果茸与果酱调味\n\n常见的果茸有安德鲁果茸、宝茸果茸。果茸即新鲜的水果浓缩，法式甜点里经常用到，调味或者制作镜面都很不错。我个人喜欢树莓和椰子，这两种都属于水果不好储备的。果酱就不说了，可以是自己熬的果酱，这个要求稠一点，也可以是售卖的果酱。不建议用新鲜水果，水份太多。\n\n果茸或果酱10-20g  淡奶油100g  细砂糖适量  淡奶油稳定酱适量（可选，建议用）\n\n①淡奶油100g，打发至粘稠，加入果茸或果酱，继续打发。\n②果茸和自制果酱含水多一些，市售果酱内有胶质。所以用果茸和自制果酱建议加入稳定酱，先把稳定酱与果茸打均匀，再分次加入淡奶油打均匀后打发。", "十六、调味糖浆奶油\n\n调味糖浆因为口味太多就不一一写了，可以某宝搜一下。常用的是莫林糖浆、达芬奇糖浆、法布芮糖浆、特朗尼糖浆。口味方面个人觉得枫糖、薄荷、玫瑰味是一定要入手的，其他的就看自己喜好了，比如我自己就格外喜欢樱桃和桃花口味。如果你不确定喜欢哪个口味，可以先去喝杯鸡尾酒🍸，调酒师那里糖浆比较齐活。口味方面每个人都不一样，但是调味糖浆却是增加甜品风味的好搭档，不止可以用在奶油里，比如我就会在情人节推出桃花口味甜点，在七夕推出玫瑰风味甜点。\n\n调味糖浆5-20g  淡奶油100g  淡奶油稳定酱适量（可选，建议用）  细砂糖视自己口味添加\n\n①奶油打发到稍微有点粘稠的时候，加入糖浆继续打发。\n②建议加入淡奶油稳定酱，糖浆先与稳定酱打均匀再分次加入奶油打发。\n\n★加入糖浆的奶油质地会软一丢丢，看糖浆添加量。如果加太多糖浆很有可能奶油软趴趴，所以不要加多，根据情况适量加。所以这里建议加少量稳定酱。\n★有些糖浆会带有颜色使奶油上色，如果觉得不好看可以适量增加色素。", "十七、花式酒味奶油\n\n终于更最后一个了，写到这就觉得浑身轻松精神爽。烘焙中常用的酒有咖啡力娇酒、黑白金朗姆酒、君度力娇酒、樱桃白兰地力娇酒等等。再简单一点，力娇酒都适合提风味，芭菲力娇各种水果力娇口感都甜甜的。甚至还包括伏特加龙舌兰白兰地，只要搭配得好，对于甜点来说都是一种特色。\n\n做法也相当简单，奶油打到9成发状态，加适量调味酒打匀就好了。\n\n适量的意思是你自己看着办，调你自己需要的味道，别来问加几克了，这个不固定！建议加一点稳定酱。\n\n★先打发再加酒避免了奶油打不发和泄的过快"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/f1f129246a1711e7bc9d0242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('法式焦糖布丁', '烘焙甜品饮料', '布丁', '', '[{"name": "蛋黄", "amount": "3个"}, {"name": "淡奶油", "amount": "225g"}, {"name": "牛奶", "amount": "75g"}, {"name": "砂糖", "amount": "20g"}]'::jsonb, '["液体1 将淡奶油、牛奶、砂糖放入奶锅中，小火加热，直至砂糖完全融化。关火晾凉待用。", "液体2  三个蛋黄搅拌均匀，晾凉后的液体1缓慢加入蛋黄中，拌匀。", "液体2过筛，去出气泡和蛋黄固体，烤出的布丁更嫩滑。", "烤箱预热，将过筛后的液体2倒入容器中，放烤盘上。烤盘加半寸深的水，这个水量就是刚好没过烤盘的底部就可以，千万不要多了！入烤箱。\n170～180度烤25—30分钟，观察布丁表面出现焦糖色即可。\n每个烤箱温度都不一样，一定根据自己烤箱温度来调整时间。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/263e671888b511e6a9a10242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('新手零失败的超简单牛奶布丁-无淡奶油版奶冻', '烘焙甜品饮料', '布丁', '', '[{"name": "牛奶", "amount": "250克"}, {"name": "细砂糖", "amount": "15克"}, {"name": "（一片半）（或7克吉利丁粉）吉利丁片（或吉利丁粉）", "amount": "7.5克"}]'::jsonb, '["吉利丁片放入凉水中浸泡备用，注意一定要用凉水。大概十几分钟就会泡软。", "家里的普通袋装牛奶一包，剪开放入小奶锅，加糖，开小火边加热边用手动打蛋器搅拌至白糖融化。待牛奶微微沸腾后关火。", "牛奶晾至温热不烫手。将泡好的吉利丁片放入牛奶中，轻轻搅拌至融化。注意不要用力搅拌以免产生过多气泡。（对腥味敏感的朋友可以加几滴柠檬汁）", "这里注意啦！我有让牛奶布丁变得超可爱的小窍门啦！拿出秘密武器—装蛋黄酥的小圆盒！将小圆盖放在小盆里使其固定不倒，把牛奶混合液轻轻倒进去吧！做完大概是三个的量！\n当然如果你放在任何你喜欢的容器里都是可以哒！只是这个圆圆滚滚白白胖胖实在可爱！", "端着小盆放进冰箱冷藏，大概", "5小时就会成型。时间久点效果会更好哦！", "取出布丁，倒扣在盘中脱模，按照自己的想法装饰一下吧！我放的玫瑰花酱，香香甜甜的，放水果丁也很棒，清凉爽口哦！\n脱模小妙招：1手轻轻按着布丁向内侧稍微用力，布丁和模具时间会出现小缝隙，沿着缝隙倒一点点的牛奶或者蜂蜜，过一会液体渗入就能轻易倒扣脱模啦！2可以用吹风机在模具四周吹几圈热风。3用热毛机裹住模具四周和底部。\n另外如果用蛋黄酥模具，可以剪掉多余的、没装满布丁液的一圈塑料壳，脱模会更容易！", "看，餐桌上的焦点，超级简单，做来试试吧！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/23676bd91c1c4a338496e3323a751810_1836w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛奶布丁', '烘焙甜品饮料', '布丁', '', '[{"name": "本鸡蛋", "amount": "3个"}, {"name": "糖", "amount": "40克"}, {"name": "牛奶", "amount": "200克"}, {"name": "淡奶油", "amount": "120克"}]'::jsonb, '["打蛋盆中打入3个鸡蛋，加入40克糖打至糖融化", "加入牛奶和淡奶油搅拌均匀", "过筛3-4次后，布丁液最好静置15-20分钟，这样布丁液里面的小气泡会消失，烤出的布丁会很细腻", "烤箱预热，中层160度50到60分钟，根据自家烤箱火力🔥设置", "静置后的布丁液均匀的分到布丁碗中，用锡纸封住碗口以防蒸汽", "烤盘中倒入热水，水深没过布丁碗一半即可", "中层160度，50-60分钟，看自己烤箱的脾气决定，冷却后冷藏食用最佳"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/df9f930f0e744abda7a727ef815946b1_1124w_1174h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单的焦糖布丁', '烘焙甜品饮料', '布丁', '', '[{"name": "鸡蛋", "amount": "3个"}, {"name": "白砂糖", "amount": "25克"}, {"name": "淡奶油", "amount": "200克"}, {"name": "牛奶", "amount": "100克"}]'::jsonb, '["准备食材，以上是布丁液的用料；底部的焦糖水另外准备30g白糖和少量热水即可，焦糖底会有一点苦，不喜欢的同学可以不做。", "先将牛奶、淡奶油和25g的砂糖倒进奶锅，小火加热，搅拌至砂糖融化。", "糖融化后就可以关火，放凉。", "三个鸡蛋打成蛋液。", "然后将温度降下来的牛奶液缓缓倒入鸡蛋液，搅拌均匀。", "搅拌好的牛奶鸡蛋液颜色很漂亮；", "然后过筛，这样做出的布丁口感会更细腻。", "附加题（可选做）：准备最底层的焦糖水，30g左右白糖，中大火加热，融化为棕色糖水糊后换小火；", "倒入30g左右热水稀释，搅拌，变成均匀的焦糖水后关火；", "将焦糖水倒入布丁杯，每个杯子一勺即可。          —————————选做分界线—————（不喜欢焦糖的可以直接跳过）", "将刚才做好的牛奶鸡蛋液（也就是布丁液）倒入布丁杯。", "烤盘倒入一半的冷水，需要隔水加热！       烤箱200度预热10分钟，然后将布丁端入烤箱中层，180度，上下火，30分钟。", "烤好的布丁表面略微焦黄，很漂亮；", "底部加了焦糖水，布丁吃到最后会有微苦微甜的焦糖水混入，口感更丰富～               （冷藏后口味更佳）"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/326c0d3a1b774d1881072e930b9518b8_1500w_1124h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛奶布丁（五分钟搞定）', '烘焙甜品饮料', '布丁', '', '[{"name": "牛奶", "amount": "450ml"}, {"name": "淡奶油", "amount": "250克"}, {"name": "一勺白砂糖", "amount": "适量"}, {"name": "吉利丁片", "amount": "2片"}]'::jsonb, '["食材全部备好，吉利丁片用凉水泡上。", "锅里小火倒入牛奶，微微有温度的时候缓缓倒入淡奶油和白糖（按自己喜好放置，喜欢甜就多放不喜欢就少放）不停搅拌至牛奶热但是不开，关火。（锅里照片忘记照了）", "牛奶70℃左右的时候，将泡好的吉利丁片捞出放入碗中，碗上铺好纱布，将牛奶用纱布过滤一下倒入盛有软吉利丁片的碗中，搅拌至吉利丁片完全融化。", "将液体倒入容器中，放入冰箱保鲜层（冷藏放新鲜蔬菜的那层）静置3-4小时。", "秒杀外面一切牛奶布丁。开动！！！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/fdd8f5ee334a4cefa929f39dbd07ca88_750w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('比维他更低成本更好喝的夏日必备柠檬茶！', '烘焙甜品饮料', '冷饮', '', '[{"name": "柠檬", "amount": "1个"}, {"name": "130—180克白砂糖", "amount": "适量"}, {"name": "—1.7L水", "amount": "1.3L"}, {"name": "10—15克红茶叶", "amount": "适量"}]'::jsonb, '["准备好材料，柠檬搓盐洗干净切片去核。一定要去核不然会苦，不是柠檬的那种涩，是苦！", "熬柠檬糖浆\n\n水要末过白砂糖，大概大半碗水左右。开中小火搅拌助融化，沸腾之后放入3片柠檬（怕维生素c高温不可的可以现在就盛出等降温了一点再放柠檬）我想要熬出的是柠檬的香甜所以就直接放了，拿铲子压一下更出味，大概4分钟后即可盛出晾凉。", "可与此同时煮红茶，想喝浓的就沸腾之后8的分钟左右，反之就4分钟即可。注意最好是开中小火，大火蒸发快会造成比例不对，也可以用铲子压茶叶出味。", "等所有上面的放凉了之后同剩下的柠檬挤汁全部搅拌一起就可以了！留一到两片没有煮过的柠檬浮在上面好看点，煮过的会沉入底部。放冰箱想喝的时候喝，我们一家子基本留不了过夜，不过我发现过夜的会更加甜。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/e6dcb7b5826f400b91ee5d6b09e07b50_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('少女控桃桃养乐多', '烘焙甜品饮料', '冷饮', '', '[{"name": "桃子", "amount": "3个"}, {"name": "1瓶养乐多", "amount": "适量"}, {"name": "冰糖", "amount": "15克"}, {"name": "适量冰块", "amount": "适量"}]'::jsonb, '["先来熬一个桃子酱【桃子酱可以放在冰箱冷藏，随时拿出来用】2个桃子洗净 去皮，切成小块，放入瓶子里加冰糖15克至融化。然后倒入锅子里加热至粘稠，重新放入瓶子中冷藏。", "这是我熬好的桃子酱。可以抹面包，也可以做饮品。", "杯子中放入桃子酱适量，加入冰块适量。", "我选择了白桃味和原味的乳酸菌饮品。", "用乳酸菌饮品倒满，然后加桃子片和薄荷装饰。好喝的桃桃养乐多就做好啦～"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/8523b80e990c4a4f8554b05325a740f2_3109w_2486h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('网红金桔柠檬茶', '烘焙甜品饮料', '冷饮', '', '[{"name": "金桔柠檬绿茶", "amount": "适量"}, {"name": "水", "amount": "300克"}, {"name": "绿茶", "amount": "10克"}, {"name": "冰块（第一次加）", "amount": "100克"}, {"name": "柠檬", "amount": "1个"}, {"name": "青柠檬", "amount": "2片"}, {"name": "金桔", "amount": "4个"}, {"name": "（冰糖和水1:1熬煮而成）果糖", "amount": "50克"}, {"name": "冰块（第二次加）", "amount": "250克"}]'::jsonb, '["煮开的纯净水（80度左右）倒入茉莉绿茶中，闷泡几分钟", "过滤掉茶叶，加入冰块，这样能减少茶的苦涩味。", "摇摇杯里面挤入柠檬汁，再放入柠檬片和小金桔，加入绿茶水，冰块，还有果糖，摇晃均匀。", "水桶杯里加入一片柠檬片，一片青柠檬，几颗金桔，倒入调好的绿茶水。", "金桔柠檬绿茶就完成哈", "还可以加入百香果汁，再把绿茶底换成红茶水，就变成另一款网红饮品——百香果柠檬红茶。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/92bfb0b2d786421ba5d1c40589d366bc_1460w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Lemonade（快乐柠檬水）', '烘焙甜品饮料', '冷饮', '', '[{"name": "柠檬", "amount": "5个"}, {"name": "白砂糖", "amount": "250克"}, {"name": "250毫升纯净水", "amount": "适量"}, {"name": "1400毫升冰冻纯净水", "amount": "适量"}]'::jsonb, '["制作糖水：白砂糖250克", "纯净水250毫升", "倒入锅中，上灶大火融化。", "融化过程中，不停搅拌，直至白砂糖完全融化，不需要将糖水煮沸。", "糖水制作完成，放凉，备用。", "挤柠檬汁：5个柠檬洗干净，对半切开，准备开挤。（温馨提示这可是体力活啊）", "记得切两片柠檬片，去籽，备用。", "挤好的柠檬汁及果肉", "将之前切好，去籽的柠檬片放入壶中。使用过滤网，过滤出柠檬汁。", "用小勺压一压，不能浪费。", "过滤好的柠檬汁", "加入放凉的糖水", "加入冰冻纯净水，我用的是农夫山泉550ml装的，用了", "又加了2片薄荷和冰块，真是太好喝了。", "媳妇拍的，好看啊。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/dccd6636c90d4bb78b8ee91ea68f4364_3024w_2419h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制夏日神仙饮品西瓜柠檬雪碧饮', '烘焙甜品饮料', '冷饮', '', '[{"name": "一小块西瓜", "amount": "适量"}, {"name": "青柠檬", "amount": "2片"}, {"name": "小金桔", "amount": "2个"}, {"name": "适量冰块", "amount": "适量"}, {"name": "一瓶雪碧", "amount": "适量"}]'::jsonb, '["准备好食材", "西瓜切成小块放入杯中", "挤入一个小金桔汁", "放入冰块", "放入青柠檬片和小金桔", "倒入雪碧即可", "好看好喝", "赶快试试吧～"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/883852facb5645308e35eab9e7894622_1534w_2046h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制苹果酱', '烘焙甜品饮料', '果酱', '', '[{"name": "苹果", "amount": "2个"}, {"name": "半个柠檬", "amount": "适量"}, {"name": "（根据自己苹果甜度）白糖", "amount": "40g"}, {"name": "适量水", "amount": "适量"}]'::jsonb, '["苹果已经，去皮。", "切成小块，放盐水浸泡一会儿，避免氧化。", "捞出苹果块，放入锅里。", "放适量冰糖或者白糖，根据自己口味的量而定。", "加入苹果1/3的清水煮制苹果变色变软。", "倒入料理机打碎。", "再倒入锅中。", "挤入柠檬汁。", "熬制变粘稠。", "放凉装入容器中。", "抹面包很不错哦。"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/7c7db930ce5c4f83abdba74d8aed7b43_750w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级好吃酸甜可口苹果酱', '烘焙甜品饮料', '果酱', '酸', '[{"name": "两个苹果", "amount": "适量"}, {"name": "一个（大）柠檬", "amount": "适量"}, {"name": "冰糖", "amount": "350克"}, {"name": "适量水", "amount": "适量"}]'::jsonb, '["一个柠檬取汁去籽备用", "苹果去皮切小丁+半个柠檬汁+半个切碎的柠檬皮 （尽量不要柠檬皮白色的部分，不然会苦）柠檬皮是给果酱增香的，柠檬的香气是来自柠檬皮不是柠檬汁 ，这是苹果酱好吃的秘诀之一，一定要加柠檬皮。", "冰糖 砂糖 绵白糖都可以，我用的是黄冰糖，做果酱一定要糖量大，糖量大才能出果胶，这一步不能减糖，不然酱会稀", "开始制作 苹果丁柠檬皮柠檬汁都放好后加适量的水，水刚刚末果苹果就可以了", "水千万不要多  苹果会出一部分水，开火", "大火煮开转中火煮到苹果变软，大概5分钟左右", "加入糖 （不用怕糖多会太甜，后面的步骤会放剩下的半个柠檬汁去调整口味）", "中火一直煮，这是刚加入糖又开锅的状态", "变这样稍微粘稠一点的时候加剩下的半个柠檬汁，尝一下味道，喜欢在酸一点可以在加柠檬汁，按自己的口味调整酸甜度。", "一直中火 煮到用铲子翻动可以看见锅底的状态就可以关火了，这样的状态做出来果酱的黏稠度刚刚好。", "放到无水无油的容器中 常温后放冰箱过夜 ，这一步是为了让果酱粘稠定型，不可以省略。"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/748f6a27bd374d95b9c8344547d7788c_2048w_1536h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制草莓酱（4月正当季，不做后悔，简单到你不敢想象）', '烘焙甜品饮料', '果酱', '', '[{"name": "草莓", "amount": "700克"}, {"name": "柠檬", "amount": "1个"}, {"name": "180-200克白砂糖", "amount": "适量"}]'::jsonb, '["新鲜草莓洗干净，控干水份", "切成小块", "加入白砂糖", "搅拌均匀", "放入冰箱冷藏24小时", "倒入无油锅中", "大火翻炒至草莓变软，炒的时候用锅铲不停的捣碎草莓", "转中火熬出胶，继续捣碎草莓", "出胶，果肉也变细腻了", "关火倒入柠檬汁", "搅拌均匀", "先来一口尝尝😊😊，酸酸甜甜", "待冷却后，装入密封罐，放冰箱可保存两三个月。", "配上吐司面包，太好吃啦😋", "视频图示"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/25434306cd184bcb8c53cdec8d4ec290_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('初夏黄杏酱', '烘焙甜品饮料', '果酱', '', '[{"name": "杏", "amount": "600克"}, {"name": "冰糖", "amount": "300克"}]'::jsonb, '["杏洗净切小块加冰糖进冰箱腌制1-2h，此处有强迫症的朋友可以把杏子去皮，但是懒癌晚期的我选择直接切", "果肉连水一起倒入锅中，全程小火，勤翻动防止糊锅，煮软后用铲子把果肉压一压", "容器用开水烫一烫，保证无水无油，倒入果酱，撕张保鲜膜贴在表面，冷却后放进冰箱冷藏保存", "来一勺果酱兑冷萃红茶，酸甜清香", "涂面包也是超级好吃"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/be52671f916843409a3e1c9444c4d7cf_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蓝莓果酱不用买，我来教你在家做', '烘焙甜品饮料', '果酱', '', '[{"name": "蓝莓", "amount": "600克"}, {"name": "黄冰糖（冰糖、白砂糖）", "amount": "240克"}, {"name": "柠檬", "amount": "1个"}]'::jsonb, '["蓝莓600克，我用的是大兴安岭的野生蓝莓是小小颗的，这种蓝莓酸甜可口，特别适合做果酱，如果你没有也可以用市售的蓝莓。", "黄冰糖240克，也可以换成冰糖，或者是白砂糖。", "把称好重的蓝莓和黄冰糖一起放到锅里，熬果酱最好用玻璃锅或者是不锈钢锅，不要用铁锅。", "开中小火，慢慢的把冰糖熬融化，继续熬煮20分钟，熬的时候要一直不停的搅拌以免糊锅底。", "挤一个柠檬的柠檬汁。", "20分钟后把挤好的柠檬汁倒进锅里，继续熬煮10分钟，什么状态是果酱熬好了呢？准备一碗清水，用筷子滴一滴果酱到清水里，它可以凝固，就说明熬好了。", "密封瓶事先要做好消毒准备，洗干净放在水里煮20分钟，或者是放在消毒碗柜里消毒，密封瓶是干燥的，没有水就可以使用了。", "熬好的蓝莓果酱，趁热装在消毒好的瓶子里，马上盖上盖子倒扣，使其产生密封的效果，放凉后放入冰箱冷藏，这样做的蓝莓果酱可以放一个月哦，密封瓶最好选用小的，这样的话一次两次就可以吃完，不要用大瓶子，一两次吃不完，来回开盖接触空气、这样会缩短保质期还容易变质。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/ad966e0360f8415c852c8bc87b912833_2174w_2899h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制三色芋圆1⃣（附上窍门详细比例）', '烘焙甜品饮料', '糖水', '', '[{"name": "（去皮净重）六鳌红薯🍠", "amount": "300克"}, {"name": "木薯粉", "amount": "227克"}, {"name": "————————-", "amount": "适量"}, {"name": "（去皮净重）紫薯🍠", "amount": "300克"}, {"name": "木薯粉", "amount": "108克"}, {"name": "————————-", "amount": "适量"}, {"name": "（去皮净重）土豆🥔", "amount": "300克"}, {"name": "木薯粉", "amount": "197克"}, {"name": "—————————", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["今天做的是三色芋圆，所以就用三种，粗粮去皮洗干净切块放锅里蒸熟，筷子能扎透就熟了，今天买不到好的芋头，就用这三种！", "准备三个碗，各装上木薯粉备用！", "粗粮取出三个颜色各拿一个盆子装上，趁热用铲子压泥，喜欢甜的就是这个时候加点白糖。然后加一勺木薯粉拌，要是湿还可以加一勺，⚠️⚠️紫薯比较干先加一勺。", "大概加图中的状态。", "各取一部分煮熟团，今天材料300克，捏这么大煮熟团就够了，⚠️紫薯比较干，要是觉得松散熟团可以多煮一点点，用手捏长，无论多难捏你尽量捏这样，揪成小剂子扔滚水里煮，煮芋圆一样。", "煮熟浮起来（我比较懒三种一起煮）煮好捞起倒主面团里，也可以一种一种煮", "煮好分别倒主面团里，用铲子拌均", "倒入一勺木薯粉拌均,倒出桌面手搓揉，用点巧劲加蛮力推揉，揉几下加粉继续揉（粉不能一下子加太多，加多干了还得用水补救那样就不好吃了）就这样揉啊揉揉成一个软度适中的光滑面团", "揉面手法图中演示，土豆芋圆（娃爸拍的）", "紫薯比较干，松散，刚开始你们会怀疑失败了，想加水，哈哈哈哈😂⚠️⚠️（喜欢糯的不需要加一滴水。喜欢Ｑ的就加一点点刚才煮熟团的水）只要有耐心揉几分钟弹性会越来越好。", "看看紫薯的弹性，真的太好了！我这里没有加一滴水！🤪⚠️如果还是有点松散熟团再煮一点点补救就行了，毕竟紫薯比较干！", "变这样就揉的差不多了，再用力揉一会儿OK！紫薯加的粉实在少，所以是最好吃的😋", "三个依次揉好的面团，（我粉没有称，做好才称出准备比例，不要问我粉剩的问题了🤣）", "用保鲜膜包下防止干了，有空就马上做，没空的亲包起来空了做，不是醒面⚠️也可以分开包，防止串色。这个时候带娃的妈妈就可以先去哄宝宝睡觉了，去两小时没问题，我都是分两次做，等会儿做的时候再揉揉依然是柔软的面团。", "撒少许干粉搓。很轻松就能搓条，娃帮我拍一个揉面视频。", "补一个芋圆搓条", "好漂亮的说，撒一些干粉均匀摸下", "揉好直接切，切好撒干粉防粘！", "美美哒，不需要整形，再撒一些干粉防粘", "三色混合", "煮一点尝尝，水烧开把芋圆仍进去煮膨胀浮起捞出。", "冲冷水想吃Q的这部很重要，冲下倒糖水里。", "我今天加的是牛奶😋，为了方便就加这个。⚠️⚠️甜汤可以加冰镇的奶茶、椰汁，椰浆、牛奶、喜多多、红豆汤，燕窝，银耳汤，然后上面铺一些蜜豆、仙草、珍珠、椰果、坚果、水果、可以吃的很丰富营养，尽情发挥想象😄", "芋圆煮好冲凉倒一杯一点点奶茶好吃😋", "🤩🤩🤩这份是牛奶蜜豆仙草芋圆", "这里金黄的就是小小的板栗🎃南瓜做的，很软糯😋", "上次还搓小小的当珍珠给小朋友吃❤️", "我喜欢像煮面一样吃，哈哈哈哈😂", "冷冻后的芋圆。后期还会继续发一些更详细的图，比如差不多比例😄", "晒晒😄😄", "一斤斤打包好的👌", "有问题留言，附上图片问问题，失败了找我帮你补救!一有时间我就回复，谢谢🙏不卖芋圆！"]'::jsonb, 30, 160, '困难', 3, 'https://i2.chuimg.com/b0b08d155a6446de9f0164f16e728a75_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制超嫩豆腐脑（豆腐花）', '烘焙甜品饮料', '糖水', '辣', '[{"name": "干黄豆", "amount": "150克"}, {"name": "清水", "amount": "1500克"}, {"name": "内脂", "amount": "3克"}]'::jsonb, '["干黄豆清洗干净，加入适量清水浸泡8小时左右 ，夏季要放冰箱冷藏，我一般前一晚浸泡，第二天起来就可以做了。", "准备1500克清水。", "泡好的黄豆沥干水份，加入准备好的1500克清水打成生豆浆（可以分2次打），我用的是破壁机，用一次果蔬功能一次破壁功能，打出来的豆浆非常浓。如果是用普通的豆浆机，请用三次果汁功能，保证出浆率，出浆率是成功制做豆腐脑的前提。这里需要注意的是，这里打的是生豆浆，不是煮熟的豆浆。", "打好的生豆浆倒入过滤袋子里，挤出豆浆，第一次我用的是这种过滤袋，做出来的豆腐脑上半层非常嫩，下半层比较粗，原因是这种袋子不够密。", "第二次用的是这种过滤袋，做出来的豆腐脑从上至下都是非常嫩的，过滤的时候尽量挤干豆浆，保证出浆率。（某宝搜“奶茶过滤网”）", "用网勺把浮沫撇干净。", "过滤好的生豆浆开火煮熟（第一次煮开是假沸状态），煮开后中火再煮7分钟，保证豆浆煮熟，煮豆浆很容易溢出来和糊锅，需要不停地搅拌，以免糊底了，有浮沫就撇掉，越煮浮沫越少，煮好的豆浆会有一层豆皮，把豆皮夹出来。", "煮好的豆浆过滤一遍，可以拿这种过滤网，很快捷的，一倒就可以了。", "我用的是这个牌子的内脂，3克一包，用一小勺温开水化开（约10克温开水），不要放太多水化内脂，水多做出来的豆腐脑出水也多，化好的内脂倒入电饭锅或保温瓶里待用。（这种内脂上说明1200克的豆浆用一包，但我第一次1200克豆浆用一包做出来有酸味，第二次1300克豆浆做出来也有酸味，第三次1500克清水打出了的豆浆煮好，用一包刚刚好，没有酸味）", "过滤好的豆浆沿着电饭锅壁倒入化好的内脂里，速度需要快点，大概几秒完成了，盖上盖子约15分钟左右就好了，冬天电饭锅可以开保温，夏天就不用开了。夏天10分钟就凝固了，凝固就可以吃了，非常嫩的，焖得时间久，豆腐脑就会老点。（关于这时豆浆的温度，85度是最好的，如果有食物温度计可以量一下，如果没有温度计，不过滤的话就晾2分钟再倒入（夏天5分钟）。", "焖了10分钟，凝结了，开吃咯，装了一碗才想起来要拍照，哈哈😜。", "我喜欢吃甜的，所以煮了红糖水。", "加入红糖水，非常好吃哦！享受制作过程带来的快乐！"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/0f3014ebbd7a40b581ffeccdb5703931_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏日地摊卖得超火爆的解暑糖水，今天一次性教你四种口味！', '烘焙甜品饮料', '糖水', '', '[{"name": "白凉粉", "amount": "10克"}, {"name": "水", "amount": "500克"}, {"name": "花生米，山楂碎，芒果\n芋圆，酒酿，葡萄干，红糖汁01.红糖原味冰粉", "amount": "适量"}, {"name": "燕麦脆，西柚，芒果，芒果汁，西米，草莓，小汤圆，椰汁02.杨枝甘露冰粉", "amount": "适量"}, {"name": "芋圆，紫米，酒酿，小汤圆，珍珠，燕麦脆脆，葡萄干，牛奶03.奶香紫米冰粉", "amount": "适量"}, {"name": "金桔，百香果，话梅，苏打水04.百香果汽水冰粉", "amount": "适量"}]'::jsonb, '["10g白凉粉加500g的沸水，在锅里充分搅拌至融化后，倒入碗里放凉，再放入冰箱冷藏1小时左右。", "冷藏后的冰粉用小刀切成一块块的，也可以用勺子挖成不规则形的。", "冰粉可以按自己喜好搭配，是减脂又美味的夏日甜品，赶快get起来呀！\n下面给大家介绍4种不一样的口味参考吧！", "红糖原味冰粉配料：\n花生米，山楂碎，芒果，\n芋圆，酒酿，葡萄干，红糖汁", "将冰粉铺底，依次将材料摆上，可以撒些芝麻点缀，最后把红糖汁倒入", "经典原味红糖冰粉就做好啦，这款原味红糖会比较偏甜，但酒酿和酸甜葡萄的搭配恰好平衡了它的甜腻，", "杨枝甘露冰粉配料：\n燕麦脆，西柚，芒果，芒果汁，\n西米，草莓，小汤圆，椰汁", "倒入的汤底是椰汁，也可以用杨枝甘露汁：用芒果+牛奶+椰汁打成芒果酱，这个味道偏水果口味，有香甜的水果香，女孩子会比较喜欢哟~", "椰汁味道夹杂在芒果，西柚和草莓之间，一口下去还有西米和冰粉的滑嫩！", "奶香紫米冰粉配料：\n芋圆，紫米，酒酿，小汤圆，\n珍珠，燕麦脆脆，葡萄干，牛奶", "这款汤底是牛奶味哟，有浓浓的奶香，材料口感是偏软糯的，搭配着奶香更美味 !", "紫米搭配牛奶简直太美好了，不喜欢酒酿的可以不放进去，会更加浓郁。", "百香果汽水冰粉配料：\n金桔，百香果，话梅，苏打水", "这款真的超级夏天！简直美白又减脂，不过不放糖会有一点酸哟，可以在里面放些蜂蜜，甚至还可以把苏打水换成雪碧。", "如果炎炎夏日来一碗冒着泡泡的汽水冰粉，简直就是满口的夏日惊喜，一碗就可以赶走你所有的夏日炎热。", "好啦，这四种冰粉get到了吗，赶快点赞收藏起来吧，嘿嘿～学会了摆地摊去！"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/80390297669b4b3ab3b0ecd2bf747a31_830w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('喝了后不想再去店里喝的杨枝甘露（红柚替代版）', '烘焙甜品饮料', '糖水', '', '[{"name": "两大个芒果", "amount": "适量"}, {"name": "椰浆", "amount": "100g"}, {"name": "牛奶", "amount": "100g"}, {"name": "10-15g（10g最佳）糖", "amount": "适量"}, {"name": "2-3瓣红柚", "amount": "适量"}, {"name": "适量西米", "amount": "适量"}]'::jsonb, '["先来煮西米。我用的平底锅，多放水，大火烧开，放入西米，烧15分钟，盖锅焖10分钟。然后过冷水。再重新烧水，冷水下锅继续烧15分钟，盖锅焖10分钟，最后过流动的冷水，捞起来备用。\n\n看了一些方子是大火煮15分钟焖20分钟，或者大火煮5分钟焖30分钟，都尝试了，还是觉得分别煮15分钟焖10分钟做好，煮出来的西米透亮的。\n\n可能因为煮的西米不多，加的水很多，在煮的过程没有进行搅拌，最后煮出来也是挺好的。", "这是大火煮15分钟，焖20分钟，白色的点还是太多了，根本不熟，也不知道哪里出错了……", "分别煮15分钟再焖10分钟的效果", "在煮西米的时候准备好其他东西", "芒果切好，红柚子掰开。1/3的芒果留出来待会打汁", "我用的搅拌机，如果有其他工具能达到同样的效果，也是可以用的。倒入糖，芒果，牛奶，椰浆，若干冰块（现做现喝，喜欢喝冰点的）", "洗干净杯子，依次放入芒果，西米，红柚，然后再倒入刚才打好的芒果汁", "最后成品大概能做4-5小杯，料真的超级足的。喝的时候搅拌下就好啦！\n\n最后祝大家早安午安晚安，天天好心情！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/685a5466cb56465e9a93f6a3825512af_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('绿豆糖水冰沙绿豆汤（免浸泡速出沙）', '烘焙甜品饮料', '糖水', '', '[{"name": "200—300克绿豆", "amount": "适量"}, {"name": "2.5瓶矿泉水", "amount": "适量"}, {"name": "适量老冰糖", "amount": "适量"}]'::jsonb, '["倒入两瓶矿泉水，大火煮开", "倒入洗净的绿豆继续大火煮", "绿豆水煮开，倒入半瓶矿泉水“冷砸”绿豆，让其开花，转中小火🔥进行二次煮开", "煮开后，持续熬煮5～10分钟，方便出沙", "按口味甜淡准备老冰糖", "绿豆出沙后，放入老冰糖，迅速搅匀，小火熬煮3分钟", "待老冰糖块融化后，即可出锅盛起", "出沙成品，君幸饮！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/90c769e53b0b4b89b08a60a353ecfff1_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('手工冰淇淋', '烘焙甜品饮料', '冰淇淋', '', '[{"name": "鸡蛋", "amount": "4个"}, {"name": "淡奶油", "amount": "200g"}, {"name": "（甜度可根据自己嗜好增减）炼乳", "amount": "150g"}, {"name": "+10g细砂糖", "amount": "30g"}, {"name": "适量（可不用）柠檬汁", "amount": "适量"}]'::jsonb, '["鸡蛋用分离器分离蛋黄蛋白，装蛋白的盆不能有任何杂质。", "蛋白中加几滴柠檬汁（没有可不加，我就没加），把30g细砂糖分两次加入蛋白，用电动打蛋器将蛋白打至干性发泡（加糖容易打发一点），打好的蛋白可以先放入冰箱冷藏待用。", "淡奶油提前放冰箱冷藏，倒入容器用电动打蛋器打至8、9成发（最好把容器也先放冰箱冰一会），自己看看差不多就行。", "把10g糖加到蛋黄中，用打蛋器将蛋黄打散成蛋黄液。", "将蛋黄液分次加入到打发的淡奶油中，加一次，用刮刀拌匀一次，直到全部混合均匀。", "然后再分次加入炼乳，也是加一次，都要拌匀一次，不能偷懒，一定要慢慢拌匀。", "从冰箱取出打发的蛋白，分3、4次加入到搅拌好的淡奶油中，加一次拌匀一次，直至全部拌匀即可。", "将搅拌好的冰淇淋液倒入密封盒中，加果酱或坚果的就可以加了，自己觉得如果加坚果的话最好冻个一个半小时再加入拌匀。我加了自制的草莓酱和融化的巧克力。", "放入冰箱冷冻四个小时以上，冻不硬的，可以放心，从冰箱拿出来，用专用的挖球器，直接就可以吃，也可以稍微放置几分钟，我是直接吃的，哈哈，太美味了，绝对不输给哈根达斯！", "我的全部材料：淡奶油用的紫风车，味道香醇；炼乳用的雀巢..."]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/4df86752883011e6b87c0242ac110003_1536w_1147h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('根达斯冰淇淋', '烘焙甜品饮料', '冰淇淋', '', '[{"name": "淡奶油", "amount": "200g"}, {"name": "兰皇鸡蛋", "amount": "4个"}, {"name": "炼乳", "amount": "120g"}, {"name": "细砂糖", "amount": "30g"}]'::jsonb, '["可生食的兰皇鸡蛋～", "将鸡蛋的蛋白和蛋黄分离，蛋白放入无水无油的盆内", "蛋白分3次加入细砂糖，用打蛋器打至硬性发泡，打发好的蛋白放入冰箱冷藏备用", "淡奶油从冷藏室取出，打蛋器不用洗，用打蛋器打到出现纹路时加入练乳，高速打发一分钟", "加入蛋黄，（可加15g可可粉及适量牛奶在蛋黄里搅拌一下再加入，这样做出来就是巧克力味）", "用打蛋器打散，然后用刮刀切拌均匀～", "加入三分之一打发好的蛋白，翻拌均匀再加下一次，分3次全部翻拌均匀", "将搅拌好的冰淇淋糊倒入保鲜盒，入冰箱冷冻一晚。也可加入各种果酱或巧克力", "用冰淇淋勺挖出球形，淋上草莓汁即可。", "做我的方子有任何问题欢迎加微博或微信咨询，加入时验证码请写上您的下厨房昵称，方便对号入座哦。\n\n 欢迎关注微博：http://weibo.com/u/5586961638\n\n微信号：yjyhcf1206"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/4db12a3e894a11e6b87c0242ac110003_750w_728h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制冰淇淋（懒人版无需搅拌的冰淇淋）', '烘焙甜品饮料', '冰淇淋', '', '[{"name": "淡奶油", "amount": "200ml"}, {"name": "（只要蛋黄）鸡蛋", "amount": "2个"}, {"name": "纯牛奶", "amount": "50ml"}, {"name": "白糖", "amount": "50克"}, {"name": "少许盐", "amount": "适量"}, {"name": "几滴柠檬汁／醋", "amount": "适量"}]'::jsonb, '["将两个鸡蛋的蛋白和蛋黄分离，只需要蛋黄部分。把50克白糖放入蛋黄里，加入几滴柠檬汁或者醋，用电动打蛋器搅拌均匀，直到蛋黄液颜色变浅黄色即可。", "把50克纯牛奶倒入小奶锅加热，小火微微加热，直到牛奶热到表面冒泡泡即可关火。趁热，把热牛奶慢慢倒入打好的蛋黄液，一边倒入一边快速搅拌，（注意，不能让蛋黄结块，结块就变成鸡蛋花了，影响口感）。", "然后再把这个蛋黄液倒回小奶锅，加入一点点盐。开小火微微加热，一边加热一边用筷子快速搅拌（注意，火越小越好，避免糊锅），直到液体微微煮开，即可关火。放凉待用。", "接下来，打发淡奶油，淡奶油打发到9分发，即提起打蛋器能出现垂直的尖尖角即可。", "把打发好的淡奶油倒入放凉的淡奶液里，搅拌均匀，就是冰淇淋液咯，（如果想吃巧克力味，蔓越莓味，抹茶味或者各种水果口味的，这一步就可以添加进去，一起搅拌均匀，今天这款是加了蔓越莓口味的，味道非常赞。）然后把混合好的冰淇淋液倒入一个干净带盖子的容器里，放入冰箱冷冻室，冷冻三个小时以上就可以吃了，冰凉爽口又美味，快快动手做吧！", "这是冻了一个晚上第二天拿出来吃的冰淇淋，奶香味十足，非常美味！", "放了蔓越莓，味道棒棒哒！", "蔓越莓口味的冰淇淋。喜欢吃榴莲口味的，可以加榴莲，味道也是超级好吃噢！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/54b303b94ea24e72848d902784a3fa21_1080w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秒杀哈根达斯无冰渣冰激凌', '烘焙甜品饮料', '冰淇淋', '', '[{"name": "淡奶油", "amount": "200克"}, {"name": "蛋黄", "amount": "2个"}, {"name": "糖", "amount": "40克"}, {"name": "牛奶", "amount": "50克"}, {"name": "盐", "amount": "0.5克"}, {"name": "几滴柠檬汁去腥", "amount": "适量"}]'::jsonb, '["蛋黄加20克糖和几滴柠檬汁搅拌至颜色变浅体检增大，牛奶倒入锅中小火加热至微微冒小泡关火，放入蛋黄液加", "5克盐快速搅拌均匀，开最小火熬，边熬边不停搅拌至浓稠状后盛出晾凉备用", "以上就是完成了蛋黄高温杀菌，从生变成了熟", "淡奶油加糖和几滴柠檬汁打发至有纹路，将蛋黄液与打发的淡奶油混合翻拌均匀", "这个时候你可以加可可粉、草莓粉、巧克力酱，喜欢什么加什么，然后再用打蛋器打发至有纹路的状态\n✅加其他果肉的在这一步加上，可可粉累我觉得3克左右就好啦，最终还是要看你自己喜欢的程度", "最后倒入容器放冰箱冷冻一晚上就可以随时随地开吃啦", "口感细腻，毫无冰渣"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f7ee4cb431f5454788c6b8c761020008_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('比哈根达斯还好吃的冰激凌（蛋黄是熟的，可以放心吃）', '烘焙甜品饮料', '冰淇淋', '', '[{"name": "纯牛奶", "amount": "50克"}, {"name": "（不爱吃甜的，这里可以只放10克）白砂糖1", "amount": "20克"}, {"name": "（只要蛋黄，多余的蛋白可以做鸡蛋干）鸡蛋黄", "amount": "2个"}, {"name": "盐", "amount": "0.5克"}, {"name": "淡奶油", "amount": "200克"}, {"name": "几滴柠檬汁", "amount": "适量"}, {"name": "（有人反应还是有点甜，不喜甜的这里加5克）白砂糖2", "amount": "10克"}, {"name": "一点点蔓越莓干", "amount": "适量"}]'::jsonb, '["准备材料", "准备两个蛋黄，蛋白不要哦，多余蛋白可以做鸡蛋干。", "加20克砂糖，四五滴柠檬汁（不爱甜的加10克）", "用打蛋器打发", "打成颜色变淡，体积变大就可以。放一旁备用。", "准备50克牛奶", "把牛奶倒入锅里小火加热", "牛奶加热至微微小泡（千万不要煮沸，不然蛋黄成蛋花)，关火，加入刚刚放一旁备用的蛋黄液，", "5克盐，不断搅拌。然后开小火，搅拌（重点：牛奶不要煮沸，关火再倒入蛋黄，搅拌均匀，再开小火加热）", "小火搅拌至糊状，关火，放一旁晾凉，备用。（蛋黄糊一定要彻底凉透，等下加入到打发的淡奶油里，不然热的蛋黄糊加入到冷淡奶油里，奶油都要化了）", "200淡奶油加10克砂糖，（不喜欢甜这几可以加5克糖)，再加三滴柠檬汁。", "打发至有纹路状态，切记不要打发过了，等下蛋黄糊加进去，还要再打发的。打发过了，就水油分离了，变豆腐渣样了。", "加入刚刚放一旁备用的蛋黄糊，翻拌", "继续用打蛋器打发", "打发至顺滑有纹路，这样，可以了。（想吃其他味道的，可以这里可以加几克抹茶粉或者可可粉搅拌)。这里是冰激凌后面有没有冰渣，口感好不好的关键，奶油不能打过了。不然就水油分离了。", "装入容器", "我上面撒上一些蔓越莓干，可以添加自己喜欢的配料。放冰箱冷冻。", "超浓郁的奶味。无冰渣。", "这是巧克力的，被我冻了一个星期，快吃完了，才想到拍个照。"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/b4e84c82b03b4b5d95f79e6075855fdb_1836w_1468h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('芒果牛奶布丁', '烘焙甜品饮料', '果冻', '', '[{"name": "芒果", "amount": "1个"}, {"name": "250毫升牛奶", "amount": "适量"}, {"name": "白砂糖", "amount": "10克"}, {"name": "吉利丁粉", "amount": "15克"}]'::jsonb, '["芒果切丁", "把吉利丁粉、白糖倒入牛奶，小火加热融化", "把融化的液体倒入盛放芒果的容器里，搅拌均匀", "待冷却后放入冰箱冷藏2小时以上", "取出，脱模，切块"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6df33692691011e7947d0242ac110002_500w_596h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制水果果冻 | 假期熊孩子们的最爱', '烘焙甜品饮料', '果冻', '', '[{"name": "白凉粉", "amount": "16克"}, {"name": "沸水", "amount": "400克"}, {"name": "（按个人口味增减）细砂糖", "amount": "15克"}, {"name": "随意各种水果", "amount": "适量"}]'::jsonb, '["准备材料", "水果切开。", "放入碗中。", "锅中放入白凉粉和细砂糖拌匀。", "开大火，沸水慢慢倒入锅中，边倒边搅拌。", "煮沸关火。", "倒入碗中。", "冷却后放冰箱冷藏风味更佳。", "清甜Q弹的水果冻做好了，一起来品尝吧～"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/f7deae47852d4ea2aefa5c15c7f21be9_1124w_1500h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('火龙果果冻', '烘焙甜品饮料', '果冻', '', '[{"name": "饮用水", "amount": "200克"}, {"name": "火龙果果肉", "amount": "50克"}, {"name": "白凉粉", "amount": "20克"}, {"name": "糖", "amount": "20克"}]'::jsonb, '["红心火龙果去皮，切小块", "锅中倒入水", "倒入白凉粉和白糖", "开火，不停搅拌", "水开后直接倒入事先准备好的容器中", "把切好的火龙果倒入其中", "拌匀，晾凉", "等晾凉后，就可以切成合适的大小开吃了", "想要晾凉速度快点的话，可以直接放入冰箱冷藏"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/5f01c5d83b9342388418869aeb146d38_1620w_1215h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('茉莉菊花冻~白凉粉版', '烘焙甜品饮料', '果冻', '', '[{"name": "水", "amount": "400克"}, {"name": "糖", "amount": "40克"}, {"name": "白凉粉", "amount": "16克"}, {"name": "5-6朵茉莉花", "amount": "适量"}, {"name": "5-6朵菊花", "amount": "适量"}]'::jsonb, '["准备好茉莉花菊花，放入泡茶器", "加入400克开水，盖上盖子泡几分钟。\n\n（其实你也可以直接在锅里把菊花、茉莉花、白凉粉、糖全准备好了然后搅拌均匀）", "称40克白砂糖，16克白凉粉。", "这是我在某宝上买的白凉粉，2包才8块钱还包邮，超级划算。\n\n一克粉比25克水/液体。所以做之前先算好多少水要放多少粉就可以了。", "将茶汤、白砂糖、白凉粉都放入锅中，搅拌均匀，直到砂糖融化。然后煮开", "起锅晾凉，常温放凉后可以放冰箱冷藏，味道更佳哦。\n\n超级晶莹剔透，要不是它是热的，我都觉得可以拿来做蛋糕的镜面了😜（脑洞太清奇）", "脱模，切块就能吃了，完美！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f2dfdb45e9b54a98b5e33f2536ca2d34_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('芒果奶冻（白凉粉版）', '烘焙甜品饮料', '果冻', '', '[{"name": "芒果", "amount": "1个"}, {"name": "牛奶", "amount": "500ml"}, {"name": "35-40克白凉粉", "amount": "适量"}, {"name": "白砂糖", "amount": "25克"}]'::jsonb, '["中等芒果一个去皮切丁，或者大的半个。建议不要切太大块，影响凝固。", "容器内倒入500ml牛奶，加糖、白凉粉搅拌均匀，中小火煮至起泡微开（牛奶煮全开会降低其营养），边煮边搅拌，防止糊底。担心不凝固的小伙伴可以自行增加白凉粉用量。", "倒入切好的芒果丁中，轻轻搅拌下让芒果丁浮上来。或者倒入容器再加芒果丁。去除大的气泡。", "常温冷却就可以凝固。温度高或者着急吃的话放冰箱凝固。然后拿出来用小刀划开四周，倒扣脱模，切块即可。", "滑嫩爽口，营养丰富。1-2小时食用较佳。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/0ee57181c73e433fbff02b51fda770e1_1080w_810h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('手打咖啡（网红400次泡沫咖啡）', '烘焙甜品饮料', '咖啡', '', '[{"name": "1尖汤匙（勺子能装的最大份量）速溶咖啡", "amount": "适量"}, {"name": "1尖汤匙糖", "amount": "适量"}, {"name": "1平汤匙（表面与边缘平齐）热水", "amount": "适量"}, {"name": "牛奶或淡奶", "amount": "适量"}]'::jsonb, '["将1尖匙咖啡（小包的直接一包进）、1尖匙糖、1平匙开水依次放入杯中，用汤匙拌匀，大概是图中这个样子。", "左手手掌整个握住杯子下部，右手拿汤匙快速划圈搅拌杯中的混合物，搅拌大概几百次（官方说法是400次），到最后变成了浓稠的浅色的花生酱状。（和上图不是同一次做的）", "倒入开水搅匀，根据咖啡的种类和自己的口味加入淡奶、牛奶或者省略，即可享用。", "将咖啡酱舀到牛奶上，就出现分层的效果啦！如果能打至不流动了效果更好（但是喝还是要搅匀了喝唷）", "再发个动图。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6072fbe15dd545f494aadf786a80274f_909w_918h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('泡沫咖啡', '烘焙甜品饮料', '咖啡', '', '[{"name": "速溶黑咖啡", "amount": "2勺"}, {"name": "糖", "amount": "2勺"}, {"name": "热水", "amount": "2勺"}, {"name": "牛奶", "amount": "1杯"}]'::jsonb, '["材料很简单就是速溶黑咖啡，牛奶，糖和一点水。有很多厨友问是不是一定要速溶咖啡，我还是在前面再提醒一下吧，因为现磨咖啡和挂耳的话是没办法完全溶解的所以打不到这样子的质地哦，雀巢那种二合一带植脂末也打不发，最后面我有试过可以看一下👇🏻", "咖啡粉两勺", "细砂糖两勺（糖可减量可换代糖最好不要不加，不加糖打的效果看最后面有更新）", "热水两勺。量的多少取决于你要做多少而已，咖啡粉和糖和水的比例是1：1：1就可以了，我这边给的量差不多是刚好够一杯", "用蛋抽搅拌溶解均匀。", "一般博主的话是用手打发的，保守估计也要7到10分钟，我没有麒麟臂于是决定上电动打蛋器，（或者有打奶泡器也是可以的）效率简直翻倍👌🏻", "低速打一会儿咖啡就开始变色变粘稠了", "再打一会变成类似于奶油的质地就可以了", "咖啡真的可以打发到这种扣碗不掉的程度好神奇的！", "牛奶倒入杯中，不要倒太满啦，冰的热的牛奶都可以的", "打发好的咖啡盛到牛奶上面，泡沫咖啡get👌🏻", "喝之前要搅和搅和和牛奶混均匀", "口感真的很不错，上层有种类似奶泡的感觉，我觉得比普通的拿铁好喝👍🏻", "静置一会儿的话会出现泡沫分层，像拉花一样好好看哈哈", "看到很多厨友打发不成功或者有问一般的二合一速溶咖啡可以吗，我就拿了一条雀巢试了下结果证明是不行的🙅🏻‍♀️如果是雀巢黑咖啡是可以的哦就是二合一不行", "首先少量的水的话没办法完全溶解除除咖啡粉之外的植脂末。", "打蛋器打了五分钟之后还是这样的状态，没有办法打到稳定的泡沫状，所以雀巢二合一那种是不行啦。如果用的二合一咖啡里面是粗粒的黑咖啡，那种的是可以把植脂末过滤掉用就行了👌🏻", "到底不加糖能不能打发呢？因为问的人太多我又来更新了，试了一下，完全不加糖的话打发也是可以的但是时间上是加糖打发的两倍，打发效果上也没有加了糖那么绵密有明显的小气泡而且消泡会快一些，如果实在不爱糖也能接受这个效果，那就不加吧😂", "还有问得最多的问题就是能存放多久，于是我又来做实验了，打了一份试试，分了两半放常温室内和冰箱", "三个小时之后的室内的一份，放半个小时就出现了小白点，而且气泡变得密集，但整体状态没有改变", "冰箱的也是一样，出现了小白点，这可能涉及到什么化学反应我就解释不来了，气泡也一样变多了", "室温的放了一夜，表面看起来和昨天一样，但是内部已经变硬变的很黏应该是没法吃了吧", "冰箱放一夜的内部还好，但是也明显消泡了，有少许咖啡液析出。建议大家还是当天打当天喝吧，我做一杯五分钟就搞定了也很方便啦", "啊今天一个朋友说打不发，然后我也试了下发现用这个打奶油的四线头打发效果很差哦可能只能打出泡泡，底部和咖啡液的接触面小且线太少了，建议还是用蛋抽头打哦"]'::jsonb, 30, 120, '困难', 3, 'https://i2.chuimg.com/f7c448bb9ed04299a7d1d96c943679dd_2820w_2255h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('冰酿抹茶拿铁ICED MATCHA LATTE', '烘焙甜品饮料', '咖啡', '', '[{"name": "【抹茶拿铁】", "amount": "适量"}, {"name": "2茶勺抹茶粉", "amount": "适量"}, {"name": "1到2大勺热水", "amount": "适量"}, {"name": "1cup温水", "amount": "适量"}, {"name": "适量冰", "amount": "适量"}, {"name": "加了冰块后几乎1咖啡杯的3/4满你喜欢的牛奶（原方是杏仁奶）", "amount": "适量"}]'::jsonb, '["抹茶粉中加入一到2大勺热水，搅拌至无粉，会有一点黏黏的。", "倒入剩下的1cup水混合，放入冰箱冷藏或冷冻室，冷藏15分钟。", "两个杯子装满冰，加入你喜欢的牛奶", "喜欢甜的话，可以加入糖浆。然后加入冰镇抹茶", "冷粹抹茶拿铁完成！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/01b95c2711e147b9a63c1f06b0d526a3_912w_730h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('每天一杯冰拿铁#超级详细#', '烘焙甜品饮料', '咖啡', '', '[{"name": "酌量速溶咖啡", "amount": "适量"}, {"name": "酌量白糖", "amount": "适量"}, {"name": "少许矿泉水", "amount": "适量"}, {"name": "250毫升纯牛奶", "amount": "适量"}]'::jsonb, '["320ml的玻璃杯一个，打蛋器，黑咖啡，纯牛奶，白糖，矿泉水", "先放糖，甜度根据自己的喜好放", "放入速溶咖啡，追求品质的，就买最好的速溶咖啡，品质好坏口感区别很大。\n雀巢的速溶咖啡同一种包装，原产国有好几个，价格也不同，我这个原产国是法国，我试过很多品牌的速溶咖啡，最喜欢这个香味，就一直喝这款，放入的量也是可以根据自己的喜好放，咖啡味重一点还是牛奶味重一点，随意调整", "倒入矿泉水，可以常温，也可以先放冰箱冷藏过，冷开水也可以，就地取材", "矿泉水的量需要控制一下", "就是比泡湿多一点", "用打蛋器打发至膨胀发白成坨，以上步骤是引用了韩国咖啡的制作方法", "跟韩国咖啡的区别在这个步骤，也就是咖啡泡倒入牛奶和牛奶倒入咖啡泡的区别。\n此处敲重点，我这里是把冷藏的牛奶倒入咖啡泡里，这个大小的杯子正好可以盛下250ml的牛奶，最好是边倒边搅拌，这样咖啡泡就能很好的融进牛奶里，喝起来的口感要比韩国咖啡好很多很多", "这是没搅拌拍的图", "用打蛋器随便拉了一下，有花纹出来", "这是边倒边搅拌好的，完美的奶泡就浮出，比奶泡机打出来的奶泡要绵密很多，口感超棒", "泡速溶冰咖啡没那么多讲究，简单又快速，只要材料齐全，步骤不出错，手残党也是可以分分钟就做出一杯口感超棒的冰咖啡。\n好了，开始享用吧，希望这方法你也喜欢☕️"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/503ddba5af2349868bd33dff837fa78d_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('毫无难度！一分钟做生椰乳Dirty', '烘焙甜品饮料', '咖啡', '', '[{"name": "厚椰乳", "amount": "100g"}, {"name": "适量浓缩", "amount": "适量"}, {"name": "一只容量为120ml的玻璃杯", "amount": "适量"}]'::jsonb, '["已经养成习惯，喝完就把杯子洗净重新放回冷冻室。\n杯子的温度对dirty是否够污起到很重要的作用喔！", "100g 菲诺厚椰乳，这款味道真的不错，价格也便宜，1L也就二十来块，唯一一点就是这个包装实在不好储存", "直接将浓缩萃进椰乳里\n让萃取嘴尽可能靠近液面，也可以用勺子🥄的背面进行一个引流\n\n要快快喝哦！\n第一口可以喝到热咖啡和浓郁的椰奶味\n越往下喝融合的越好！\n好好享用吧～\n\n如果没有现成的生椰乳可以用100ml牛奶🥛➕70g的椰浆 搅拌均匀，可以喝到差不多的味道哦"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/254ebe5feff94e41a048decd6fdd2614_854w_854h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香浓KFC豆浆（料理机版）', '烘焙甜品饮料', '豆浆', '', '[{"name": "农家黄豆", "amount": "50克"}, {"name": "纯净水", "amount": "400ml"}]'::jsonb, '["黄豆用纯净水泡发，放入料理杯，我全程用的小瓶矿泉水。", "加大概300ml水，剩100ml留着打第二遍的。如果是做豆浆水多一点少一点都没有关系，做豆腐脑要严格按比例来。", "按压搅打，我这个机子是按压的", "打完以后倒入茶漏袋里面过滤到锅里，挤干净生豆浆。用这种布的过滤会比滤网更干净，目数小于80的滤网建议过滤两三遍。", "然后把挤干净的豆渣重新放回料理杯，加入剩下的100ml水，继续搅打。", "然后重复步骤4的过滤，这次搅打豆渣明显细腻了很多。两次豆浆混合在一起就可以了。", "然后把生豆浆煮开，滤去浮沫，一定要煮开，因为豆浆会假沸，一般闻到豆香，没有生豆子的味道就好了，煮好的豆浆豆香浓郁，不加糖喝都有淡淡的清甜。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/2572e863f5d64f92b84ea25fd92661f2_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('破壁机打出没有豆腥味的豆浆（免泡豆）', '烘焙甜品饮料', '豆浆', '', '[{"name": "每60克（三人份）黄豆", "amount": "适量"}, {"name": "/每60g热水", "amount": "750克"}, {"name": "酌情红枣、糖", "amount": "适量"}]'::jsonb, '["我买的是这款“朴实”的料理机", "①黄豆（我打了4天的量）在干燥无油的热锅里，小火炒1分钟", "②准备蒸盘，铺上油纸，倒入炒过的黄豆（这步如果没有蒸箱，可以用锅）", "③放入蒸箱，100℃25分钟（温度提升需要时间）\n注：没有蒸箱，等水沸腾后锅中放入黄豆蒸煮至少20分钟", "④取1份（60g）黄豆+热水750ml（只要是熟的热水都可以），果蔬键打两遍\n（不到2分钟）\n如果加红枣花生等其他辅料，黄豆可以酌情减量。", "剩余蒸熟的豆子分几份装保鲜盒内放【冷冻】，每次拿出60g的黄豆可以和其他食材混合打，两三分钟时间。", "这是打好的豆浆，没有一点豆腥味。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/48a584b04fdc4cfa88e1c3a74b45f5b8_1200w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('黄金比例香浓豆浆', '烘焙甜品饮料', '豆浆', '', '[{"name": "-60g黄豆", "amount": "50克"}, {"name": "水", "amount": "700ml"}]'::jsonb, '["黄豆洗干净泡水 一个晚上，大概8-9小时", "加水700ML", "破壁机做出来的豆浆，非常细腻。\n小伙伴们快试试看吧！"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/7fa7eefbc33349fc898ce06c91a20fa3_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('破壁机营养食谱12款超好喝的豆浆米糊搭配', '烘焙甜品饮料', '豆浆', '', '[{"name": "南瓜", "amount": "150克"}, {"name": "糯米", "amount": "15克"}, {"name": "小米", "amount": "20克"}, {"name": "3颗红枣", "amount": "适量"}, {"name": "5/1朵银耳", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "500毫升水", "amount": "适量"}]'::jsonb, '["✅南瓜小米银耳露👉香甜顺滑\n\n1⃣️南瓜150克，糯米15克，小米20克，红枣3颗，银耳5/1朵，冰糖适量，水500毫升\n2⃣️所有食材装入破壁机里选择米糊模式即可\n\n晶莹水润，补水润嗓", "✅紫薯莲子银耳羹\n\n1⃣️紫薯40克，莲子20克，银耳半朵泡发1小时，撕成小块，水500毫升\n\n2⃣️所有食材放入破壁机，选择米糊模式", "✅宫廷花生酪\n\n1⃣️去皮花生100克，冰糖30克，糯米20克，大米20克，水600毫升\n\n✅香芋红豆沙\n\n1⃣️芋頭200克，牛奶100克，冰糖30克，紅豆60克，水400毫升\n\n❗️做法都是把所有食材放入破壁機裡，選擇米糊模式即可。", "✅浓香美龄羹\n\n👉山药50克，黄豆30克，大米10克，糯米20克，枸杞3克，冰糖适量，水500毫升\n\n✅红豆薏米燕麦糊\n\n👉红豆30克，薏米25克，红枣4颗，燕麦30克，水500毫升，选择五谷模式。", "✅山药紫薯芋泥羹\n\n👉芋头60克，紫薯40克，糯米20克，山药30克，冰糖适量，水600毫升\n\n✅香浓黑芝麻糊\n\n👉黑芝麻60克，花生15克，红枣4颗，冰糖适量，糯米20克，水500毫升", "✅韩式南瓜粥\n\n👉南瓜250克，糯米50克，牛奶250克，冰糖适量，水400毫升，选择米糊模式\n\n✅香浓玉米汁\n\n👉玉米120克，小米15克，大米20克，冰糖适量，水600毫升，选择玉米汁模式", "✅香蕉可可燕麦奶\n\n👉可可粉5克，香蕉1根，核桃20克，即食燕麦50克，水500毫升，选择奶昔模式！健康低脂，香甜好喝\n\n✅山药黑豆红枣糊\n\n👉山药100克，黑豆30克，红枣3颗，核桃15克，冰糖适量，水600毫升，选择五谷模式！健脾胃，养生美味"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a76ec0d490674d45b5f3ff9d8587c5fa_1125w_1485h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('这是一款经典香浓豆浆', '烘焙甜品饮料', '豆浆', '', '[{"name": "黄豆", "amount": "20g"}]'::jsonb, '["黄豆20g\n大米15g\n小米15g\n花生5g\n冰糖3块", "加入破壁机\n600ml水\n豆浆模式", "香浓出锅", "还有其他产品的制作", "这是花胶做成的花胶糕，下期教制作", "还有这些馄饨的制作", "因为爱好开了【一家小店】，专业做纯手工滋bu品，一干就是七年，yang生膏！yangsheng丸！养sheng茶🍵！鲜炖系列燕窝花胶100多个品种。有想做私房和开店的可以来实体店或者线上系统学习，食材选择，制作，辩证搭配，如何引流销售等等....", "还有烤梨！热饮制作"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/181de15cdbbb4fc6978b8a7ac42408e4_1280w_1703h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('奶茶', '烘焙甜品饮料', '奶茶', '', '[{"name": "茶叶（红茶）", "amount": "8克"}, {"name": "水", "amount": "80ml"}, {"name": "牛奶", "amount": "220ml"}]'::jsonb, '["茶叶和水的比例为1:10", "水煮开，沸腾，关火。倒入茶叶，焖三分钟左右。", "喜欢浓点的可以焖久一点。", "倒入牛奶，加热，周围起一圈小气泡即可，关火。", "加蜂蜜或者糖搅拌，过滤。", "喜欢喝浓奶茶的盆友，可以多放茶叶。根据个人口味。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/4b6f69f888e011e6a9a10242ac110002_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('不要点外卖啦，自制奶茶，超简单', '烘焙甜品饮料', '奶茶', '', '[{"name": "水", "amount": "300克"}, {"name": "牛奶", "amount": "1000克"}, {"name": "红茶", "amount": "25克"}, {"name": "（30克）糖（木糖醇）", "amount": "40克"}]'::jsonb, '["茶叶称重25g，多点少点可以自己调节，没有厨房秤的朋友抓个4下差不多。", "选择全脂牛奶，味道会比较浓", "水开后煮茶，小火焖一会，时间越久茶味越浓。", "大约3-5分钟后加入牛奶，加牛奶是最喜欢的步骤，因为颜色很好看哦。\n大火煮开，转小火煮一会，这个步骤最好人在边上看着，牛奶容易溢出来，因为在健身，所以我们不加糖，需要加入糖的可以自行加入，加木糖醇糖尿病人也可以喝。上面有量，比较淡，喜欢甜的就多加点。", "煮完的亚子，香香的，用滤网滤出就好啦", "上班来不及了，装好一杯下午喝，买的小袋子，带给小伙伴喝也很奈斯。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/14fc2e766e634a62b83dfaa320fb2140_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('花钱学习的自制私房奶茶，超级简单', '烘焙甜品饮料', '奶茶', '', '[{"name": "牛奶", "amount": "200克"}, {"name": "水", "amount": "100克"}, {"name": "根据喜好来添加约15g左右绵白糖", "amount": "适量"}, {"name": "更多也行红茶包（茶叶）", "amount": "5g"}, {"name": "老师的配比在步骤3⃣️，奶味浓郁偏甜上面配方我改良的比较清爽不加奶油⬆️⬆️", "amount": "适量"}]'::jsonb, '["所有原料秤好全部放入锅中", "加热至沸腾，转小火煮约5-10分钟，煮出茶香味儿、茶色即可！", "主图是按照老师的配比煮出来的成品图！两份量", "改良版：简单粗暴一点儿，比较适合我，低脂版本，无奶油，少糖。牛奶和水、红茶随意加！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/4dc1998490b1460484261505f7253e09_1350w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级好喝的珍珠奶茶', '烘焙甜品饮料', '奶茶', '', '[{"name": "煮茶用水", "amount": "1000克"}, {"name": "适量珍珠", "amount": "适量"}, {"name": "纯牛奶", "amount": "2000克"}, {"name": "左右糖", "amount": "400克"}, {"name": "伯爵红茶", "amount": "25克"}]'::jsonb, '["锅中烧开水后，把珍珠倒进去，小火煮25分钟后关火焖30分钟，记得勤搅拌，不然会粘锅，建议水稍微多点", "准备好的1000克水烧开后关火，把25克红茶倒进去，搅匀后盖上盖子焖20分钟左右", "红茶焖好后用滤网把茶叶滤出来，茶水备用", "珍珠焖好后滤出来，用凉水过两遍", "过好的珍珠用糖拌匀，这里可以用白糖或者红糖", "纯牛奶加热", "杯子里放入红茶水和纯牛奶，然后加糖，比例的话根据个人口味，我觉得两勺奶和两勺茶有点苦，所以加了三勺奶", "应该先放珍珠然后再把茶和奶倒进去，忘了😂", "超级好喝的珍珠奶茶就做好啦，真的和外面卖的没差，外面卖的很多都是用奶粉或者植脂末奶精做的，所以还是在家做最安全，无添加😃😃"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/f12ec13dcb114c89afda634b6b15f488_810w_805h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('自制奶茶', '烘焙甜品饮料', '奶茶', '', '[{"name": "英红九号茶叶", "amount": "18克"}, {"name": "纯牛奶", "amount": "500克"}, {"name": "水", "amount": "400克"}, {"name": "糖", "amount": "10克"}]'::jsonb, '["英红九号红茶", "先将红茶叶冲洗一下，水滚后加入红茶，关火燜一分钟", "然后加入纯牛奶，我用了全脂的欧德宝纯牛奶，感觉不错，再加糖，煮开后，小火煮3分钟左右，煮到显茶色比较深时隔茶渣，奶茶就煮好了，非常简单"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/80d05982046a4d1082fbea29084197ce_754w_1008h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超解压莫吉托 | mojito带来的快乐，与酒精无关', '烘焙甜品饮料', '酒', '', '[{"name": "8~10片薄荷叶", "amount": "适量"}, {"name": "1/2个青柠", "amount": "适量"}, {"name": "粗糖", "amount": "1茶匙"}, {"name": "适量碎冰+大块冰块", "amount": "适量"}, {"name": "白朗姆酒", "amount": "50ml"}, {"name": "适量苏打水", "amount": "适量"}, {"name": "8~10片薄荷叶", "amount": "适量"}, {"name": "1/2个青柠", "amount": "适量"}, {"name": "粗糖", "amount": "1茶匙"}, {"name": "适量碎冰+大块冰块", "amount": "适量"}, {"name": "适量雪碧", "amount": "适量"}]'::jsonb, '["材料根据口味准备好，粗糖半勺也可以，根据口味自己调整。", "青柠事先滚一滚，切去2头，再对半切，最后十字下刀切成4小块，剔去柠檬籽，放进杯子。", "新鲜的薄荷叶提前泡在冰水里回复活力，吃之前摘取新鲜的茎和叶子，用手稍微拍打出香味放进杯子。", "然后放一勺粗砂糖，用擀面杖把杯子里的青柠+薄荷+砂糖碾压出汁液。", "放50ml或者你喜欢数量的朗姆酒进来，（无酒精的不用加），再加入3/4杯碎冰。（具体碎冰操作见视频）", "最后，倒进适量的苏打水（有酒精）和雪碧（无酒精）就可以啦~"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/77717a36049942b3bb350643e2948fc3_1353w_762h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五分钟可以搞定的下酒菜——酒蒸蛤蜊', '烘焙甜品饮料', '酒', '', '[{"name": "五瓣切碎蒜", "amount": "适量"}, {"name": "黄油", "amount": "20克"}, {"name": "蛤蜊", "amount": "400克"}, {"name": "日本清酒", "amount": "2大勺"}, {"name": "（熟透加）黄油", "amount": "10克"}, {"name": "少许黑胡椒", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["锅烧热➕黄油至融化", "加大蒜末，炒香，黄油和大蒜的味道最配哦", "加入两勺清酒", "盖好锅盖进行焖煮，不用加一滴水哦", "两分钟左右蛤蜊开口啦", "加剩下的黄油，黑胡椒，盐", "我还加了一点点西芹碎，也可以不加", "等黄油融化就可以出锅啦！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/34164338f2564a288af0b268aa0494f8_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏天别喝奶茶了，不增肥的冰饮莫吉托（无酒精版）', '烘焙甜品饮料', '酒', '', '[{"name": "薄荷", "amount": "20片"}, {"name": "青柠", "amount": "1个"}, {"name": "大量冰块", "amount": "适量"}, {"name": "糖浆", "amount": "10ml"}, {"name": "苏打水", "amount": "100ml"}]'::jsonb, '["在做至少一个小时先把薄荷放在冷水里浸泡，可以使得香气更好释放。", "摘一些薄荷叶，只要摘下面的，上面的就出来做装饰。", "这是留出来的顶端的叶子。", "青柠切掉两端，再一切为二。", "其中一半不用动，另一半六等分。把一半加上三个小角挤到薄荷叶中。", "再倒上糖浆。", "用擀面杖敲一些碎冰。", "将碎冰倒进杯中，放上另外三个青柠角。倒上气泡水。", "神秘动作原来是！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/2ce8337187754c078b14b5a305f4febd_1622w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('樱桃酒（不加酒）', '烘焙甜品饮料', '酒', '', '[{"name": "樱桃", "amount": "10斤"}, {"name": "冰糖", "amount": "2斤"}]'::jsonb, '["漂亮的樱桃", "新鲜樱桃洗净", "晾干，去核", "一层冰糖、一层樱桃，最上部放冰糖，随着冰糖逐渐化开，樱桃汁增多，气泡增多，开始每天搅拌放气，搅拌一周，后放在阴凉处，被冰糖浸过的樱桃非常好吃，过半个月过滤果肉后密封，血糖不高的可以当腌渍蜜饯吃。樱桃酒需要等待，最好是六个月，着急的可一个月以上就可以品尝了。", "用酵素桶的滤网过滤出樱桃肉，酸酸甜甜的，非常好吃，留出适量直接吃，部分放冰箱冷冻，能吃很长时间", "部分可以用烤箱或空气炸锅烤成果脯，当干果吃，也是不错的小零食", "烤好了的样子", "共过滤出大半桶樱桃汁，为安全起见，需要按酵素的标准，放置6个月，静待冬日暖阳时品尝[呲牙]", "这是去年夏天做的黄桃酒，今年开始喝。夜晚来临的时候，小酌一杯果酒，微醺（感觉有酒精度）时怡情养性，应比白酒对身体好吧。", "三个月了", "5个月了，尝一尝，酸酸甜甜的，挺好喝", "7个月了，好喝，真是值得！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/ff73de6f0df74aba952af03b147aea84_599w_1064h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('盐水鸡胗 | B级下酒菜，不费力只费酒', '烘焙甜品饮料', '酒', '', '[{"name": "鸡胗", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "白酒/黄酒/料酒", "amount": "适量"}, {"name": "食盐", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "朝天椒", "amount": "适量"}, {"name": "老姜片", "amount": "适量"}, {"name": "葱段", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "八角", "amount": "适量"}, {"name": "香叶", "amount": "适量"}, {"name": "干辣椒", "amount": "适量"}, {"name": "桂皮", "amount": "适量"}]'::jsonb, '["鸡胗用力搓洗数遍，加入白酒和盐继续干搓一会，用流动的水搓洗干净鸡胗的腥臭味，这一步是非常重要的，盐水鸡胗好吃不好吃全靠洗得是否干净彻底。", "沥干水分的鸡胗倒入腌料抓匀，在冰箱冷藏腌制一晚。", "我选择放在保鲜袋里，让食材和调味料充分接触。", "把腌制一宿的鸡胗挑拣出来，把腌料和煮料一起塞进无纺布包，煮鸡胗的时候一起放进来。", "鸡胗先焯一遍水，换一盆干净的冷水，放入盐、料酒和料包，大火煮开后转小火焖煮，计时30分钟。", "煮好的鸡胗泡在水里冷藏一晚是最好吃的，吃不完继续泡着冷藏，随吃随取。", "切成厚厚的薄片是很干净的味道，还可以加点佐料凉拌，丰俭由人。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/575b96a04ce2449ab7977d3be911ebac_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('37款鲜榨果汁配方大公开', '烘焙甜品饮料', '果汁', '', '[{"name": "水果", "amount": "适量"}, {"name": "蔬菜", "amount": "适量"}]'::jsonb, '["芦笋果菜汁\n　　\n材料：芦笋80g、荷兰芹80g、苹果1个、柠檬半个\n　　\n做法：\n    （1）芦笋与荷兰芹洗净切小段，加入少许冷开水放入果汁机打汁。\n　　（2）苹果，柠檬去皮切小块，放入如上的菜汁中一起打成果汁。\n　　\n　　功效：这种饮料富含丰富维他命B1与B2，能强化心脏功能。", "综合健康果菜汁\n　　\n材料：苹果1个、青椒80g、苦瓜110g、荷兰芹120g、大黄瓜150g\n　　\n做法：\n　　（1）将青椒，苦瓜，荷兰芹洗净切小块，加些冷开水一起放入果汁机打汁。\n　　\n　　（2）苹果，大黄瓜洗净去皮，切小块放入如上菜汁一起打成果菜汁即可。\n\n功效：可增强抵抗力，降血压，整肠及减肥，美容养颜等功效。", "柳橙牛乳汁\n　　\n材料：柳橙1/2个、牛乳140cc、绿豌豆60~70g、蜂蜜适量\n　　\n做法：柳橙切小块与牛乳，绿豌豆，蜂蜜一起打汁即可。\n　　\n功效：此果汁含丰富的维生素与钙质，是运动后的好饮料。", "西瓜汁\n　　\n材料：西瓜200g、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n做法：西瓜切皮去籽后切成小块，柠檬去皮也切成小块与蜂蜜和冰块一起打成西瓜汁。\n　　\n功效：有沙除浮肿，利尿等作用。也是炎夏消暑的好饮料。", "哈蜜瓜毛豆汁\n　　\n材料：毛豆（煮熟后去壳）50g、哈蜜瓜200g、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n做法：哈蜜瓜，柠檬切皮去籽后切成小块，与其他材料一起放入果汁机打汁即可。\n　　\n功效：此果汁含有维生素C，是营养非常丰富的果汁", "马铃薯苹果汁\n　　\n材料：马铃薯（土豆）2个、苹果1个、蜂蜜适量\n　　\n做法：马铃薯和苹果洗净去皮切小块，加些冷开水与蜂蜜放入果汁机打汁即可。\n　　\n功效：预防高血压，中风，动脉硬化，纾解精神压力。", "奇异果水梨汁\n　　\n材料：奇异果（弥猴桃）2个、水梨1个、柠檬1/4个、冰块适量\n　　\n做法：奇异果去皮切小块，梨子去皮及果核切小块，连同柠檬汁与冰块榨汁即可。\n　　\n功效：含丰富维生素C，有养颜，美容及利尿等作用。", "苹果芥菜汁\n　　\n材料：苹果1个、柠檬1个、芹菜60g、芥蓝菜80g、蜂蜜与冰块适量\n　　\n做法：\n　　\n（1）青菜类洗净切小段，加少许冷开水放入果汁机中打汁\n　　\n（2）苹果去皮去核切小块，连同冰块与柠檬汁放入如上的菜汁中一起打成果汁，最后加蜂蜜适量。\n　　\n功效：预防高血压，感冒，增强抵抗力，促进血液循环。", "蕃茄小黄瓜汁\n　　\n材料：蕃茄1个、小黄瓜3条、蜂蜜适量\n　　\n做法：\n　　\n（1）小黄瓜洗净切小块，加入少许冷开水，放入果汁机打汁。\n　　\n（2）蕃茄洗净切成小块与蜂蜜放入如上的黄瓜汁一起打成果汁。\n\n功效：含维生素A，B1，B2及维生素C，对身体虚肿有利尿作用，能净血，调节身体机能，是夏天美容保健圣品。", "苹果青江菜汁（青江菜即为普通白菜）\n　　\n材料：苹果1个、青江菜150g、柠檬1/4个、蜂蜜适量\n　　\n做法：\n　　\n（1）青江菜洗净切小块，加少许冷开水放入果汁机打汁。\n　　\n（2）苹果削皮切成小块，柠檬去皮切成小块，全部材料放入如上的菜汁中一起打汁。\n　　\n功效：青江菜含有丰富的维他命C及钙质和红萝卜素。对高血压，动脉硬化及便秘均有预防的效果。", "奇异果高丽菜汁（奇异果即弥猴桃；高丽菜即包心菜）\n　　\n　　材料：奇异果1个、高丽菜200g、柠檬1/6个、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶分别洗净切小块，加入少许冷开水放入果汁机打汁。\n　　\n　　（2）奇异果去皮切成小块，柠檬去皮切成小块。连同蜂蜜及冰块放入如上的菜汁中打成果汁。\n　　\n　　功效：可促进肠胃蠕动，帮助消化。高血压，皮肤粗糙及糖尿病者适用。", "苹果荷兰芹汁\n　　\n　　材料：苹果1个、荷兰芹120g、油菜（即小芥菜）100g、柑橘（橙子）1/2个\n　　\n　　做法：\n　　\n　　（1）油菜洗净切小块，荷兰芹洗净切小段，加少许冷开水放入果汁机打汁。\n　　\n　　（2）苹果削皮切成小块，柑橘去皮切成小块，全部材料放入如上的菜汁中一起打成果汁。\n　　\n　　功效：此果汁含丰富维生素C，胡萝卜素及钙质，可增强抵抗力，预防感冒，适合糖尿病及高血压患者。", "胡萝卜苹果汁\n　　\n　　材料：胡萝卜1条、苹果1个、柠檬1/4个、冰块适量\n　　\n　　做法：\n　　\n　　（1）糊萝卜削皮洗净切小块，加适量冷开水放入果汁机中打汁，\n　　\n　　（2）苹果削皮切成小块，柠檬去皮切成小块，全部材料放入如上果汁中一起打汁。\n　　\n　　功效：此果菜汁可增强抵抗力，消除疲劳。是对高血压及肝病患者有益的饮料。", "凤梨高丽菜汁（凤梨即菠萝，高丽菜即包心菜）\n　　\n　　材料：凤梨200g、高丽菜150g、柠檬1/6个、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶洗净切小块，加入少许冷开水放入果汁机打汁\n　　\n　　（2）凤梨削皮切成小块，连同柠檬汁，冰块放入如上的菜汁中打成果汁。\n　　\n　　功效：凤梨含有大量纤维可帮助消化，预防便秘。胃溃疡及皮肤粗糙者适用。", "苹果白萝卜汁\n　　\n　　材料：苹果1个、白萝卜50g、高丽菜叶80g、芦荟20g、柠檬1/6个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶，芦荟洗净切成小块，加入少许冷开水放入果汁机中打汁。\n　　\n　　（2）白萝卜，苹果，柠檬均去皮切成小块，全部放入如上菜汁中一起打成果汁。\n　　\n　　功效：对高血压，消化不良及胃溃疡有帮助，并有整肠及美容的作用。", "苹果水芹汁（水芹即日常炒菜用的普通芹菜）\n　　\n　　材料：苹果1/4个、葡萄柚1/4个、水芹120g、生菜叶子100g、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）水芹和生菜叶子先洗净切小块，加少许冷开水放入果汁机打汁。\n　　\n　　（2）葡萄柚剥除内层薄膜切成小块，苹果削皮切成小块，全部放入如上菜汁一起打成果汁。\n　　\n　　功效：此果菜汁有清血作用，有益高血压及心脏者患者饮用。", "哈蜜瓜高丽菜汁\n　　\n　　材料：哈蜜瓜1/3个、高丽菜（包心菜）120g、柠檬汁1/6个份、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）包心菜叶分别洗净切小块，加少许冷开水放入果汁机中打汁。\n　　\n　　（2）哈蜜瓜去皮去籽切小块，连同柠檬汁，蜂蜜及冰块一块放入如上的菜汁中一起打成果汁。\n　　\n　　功效：此果汁可预防胃溃疡，牙龈出血及高血压，并可以帮助消化。", "青椒苹果汁\n　　\n　　材料：苹果1个、大青椒1个、蕃茄半个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）青椒洗净切小块，加些许冷开水放入果汁机中打汁。\n　　\n　　（2）苹果洗净去皮，蕃茄洗净一起切小块与蜂蜜一起加入如上青椒汁，搅拌打成果汁即可。\n　　\n　　功效：预防高血压，强化心脏功能。", "蕃茄哈蜜瓜汁\n　　\n　　材料：水芹（普通芹菜）70g、蕃茄1个、蛋白1个、哈密瓜1/2个、柠檬1/4个\n　　\n　　做法：\n　　\n　　（1）水芹洗净切小段，加少许冷开水放入果汁机打汁。\n　　\n　　（2）蕃茄，哈蜜瓜削皮切成小块，柠檬剥除内层薄膜切成小块，放入如上汁中一起打成汁。\n　　\n　　（3）最后将蛋白慢慢倒入打好的果汁中拌匀。\n　　\n　　功效：增强体力，消除疲劳。适合运动后饮用。", "苹果枇杷汁\n　　\n　　材料：苹果1个、枇杷5个、红萝卜1/3条、柠檬汁1/6个份、冰块适量\n　　\n　　做法：\n　　\n　　（1）红萝卜去皮洗净切小块，加适量冷开水放入果汁机打汁\n　　\n　　（2）苹果削皮切成小块，枇杷去皮去籽洗净切块，连同柠檬汁，冰块全部放入如上一起打汁。\n　　\n　　功效：此果汁红萝卜素，锌铜含量丰富。是贫血，便秘症状者最佳果汁。", "芒果汁\n　　\n　　材料：芒果1个、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n　　做法：芒果去皮去籽后切成小块，和柠檬汁，蜂蜜及冰块一起放入果汁机打汁。\n　　\n　　功效：芒果中含有很高的维生素C，可帮助食欲，消除疲劳。", "枇杷汁\n　　\n　　材料：枇杷8个、柠檬1/4个、蜂蜜适量、冰块适量\n　　\n　　做法：枇杷剥皮去籽切小块，与柠檬汁，蜂蜜及冰块一起放入果汁机打汁。\n　　\n　　功效：此果汁有镇咳去痰及消除肠胃不适的疗效。", "香蕉牛奶汁\n　　\n　　材料：香蕉1条、柠檬1/4个、牛奶200cc、蜂蜜适量、冰块适量\n　　\n　　做法：香蕉剥皮切小块，与牛奶，柠檬，蜂蜜及冰块一起放入果汁机中打汁。\n　　\n　　功效：促进食欲，帮助消化。对便秘有很好的疗效。", "牛蒡葡萄柚汁\n　　\n　　材料：牛蒡150g、葡萄柚1个、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）牛蒡彻底洗净后切小段，加少许冷开水放入果汁机中打汁\n　　\n　　（2）柠檬去皮切小块，葡萄柚去皮去籽切小块，连同冰块一起放入如上牛蒡汁中打成果汁。\n　　\n　　功效：牛蒡含丰富钙质，对高血压，便秘，肝病，晒伤，肩膀酸痛，褐斑，雀斑，贫血等有效。", "哈蜜瓜果汁\n　　\n　　材料：哈蜜瓜400g、柠檬1/4个、蜂蜜适量、冰块适量\n　　\n　　做法：哈蜜瓜去皮去籽切小块，柠檬去皮切成小块，放入果汁机打汁。喜甜味者可加入蜂蜜调味。\n　　\n　　功效：哈蜜瓜含丰富维生素C，有美容及利尿作用。", "柠檬柳橙汁\n　　\n　　材料：柠檬1个、柳橙1个半、蜂蜜适量、冰块适量\n　　\n　　做法：柳橙和柠檬去皮切成小块，加入蜂蜜放入果汁机中打成果汁。\n　　\n　　功效：可预防高血压，皮肤粗糙和晒伤过敏。并有利尿作用。", "葡萄柚菠萝汁\n　　\n　　材料：葡萄柚1/2个、菠萝150g、蜂蜜适量、冰块适量\n　　\n　　做法：菠萝削皮切成小块，葡萄柚去皮切成小块，连同蜂蜜及冰块放入果汁机中打成果汁。\n　　\n　　功效：菠萝含有促进肉类消化的酵素，可以整肠促进食欲，防止高血压和皮肤粗糙。", "菠萝柠檬芹汁\n　　\n　　材料：菠萝200g、柠檬1个、西洋芹100g、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）荷兰芹洗净切成小块，加适量冷开水放入果汁机中打汁\n　　\n　　（2）菠萝，柠檬去皮切成小块与其他材料放入如上的荷兰芹汁中一起打汁即可。\n　　\n　　功效：高血压，糖尿病，增强体力，消除疲劳者适用。", "蕃茄红萝卜汁\n　　\n　　材料：蕃茄1个、红萝卜1条、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）红萝卜洗净切小块，加适量冷开水放入果汁机中打汁\n　　\n　　（2）蕃茄，柠檬去皮切成小块，全部材料放入如上的红萝卜汁中一起打成果汁。\n　　\n　　功效：此果汁含丰富维生素。适合高血压，消化不良，便秘，容易感冒者饮用。", "土豆红萝卜汁\n　　\n　　材料：土豆1个、红萝卜1条、苹果1个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）土豆与红萝卜洗净去皮切小块，加少许冷开水，放入果汁机中打汁。\n　　\n　　（2）苹果洗净去皮切小块与蜂蜜一起放入如上的菜汁中一起打成汁即可。\n　　\n　　功效：含有丰富维生素B1，维生素C，矿物质，蛋白质，可预防高血压，中风，肝硬化，防止老化，强化体内免疫系统。", "菠萝柠檬汁\n　　\n　　材料：菠萝350g、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：菠萝，柠檬洗净切小块，与其他材料一起放入果汁机中打汁即可。\n　　\n　　功效：能帮助消化，有提神及健胃等功效。", "柳橙红萝卜汁\n　　\n　　材料：柳橙2个、芦笋150g、红萝卜120g、柠檬1/4个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）芦笋，红萝卜洗净切小块，加些冷开水放入果汁机中打汁。\n　　\n　　（2）柳橙，柠檬洗净去皮切小块与蜂蜜一起放入如上打汁即可。\n　　\n　　功效：柳橙含丰富维生素C，维生素P，能增进抵抗力，降低胆固醇。芦笋能清热降火。", "葡萄柚菠菜汁\n　　\n　　材料：葡萄柚1个、菠菜150g、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）菠菜洗净切小段，加少许冷开水放入果汁机中打汁。\n　　\n　　（2）葡萄柚去皮去籽切成小块，柠檬去皮切成小块。连同蜂蜜冰块放入菠菜汁中一起打成果汁。\n　　\n　　功效：此果汁适用于贫血，高血压，便秘，皮肤粗糙者饮用。", "胡萝卜牛奶汁\n　　\n　　材料：胡萝卜1条、牛奶150cc、蜂蜜适量\n　　\n　　做法：胡萝卜削皮洗净切成小块放入果汁机，再将牛奶和蜂蜜一起倒入打汁即可。\n　　\n　　功效：可预防感冒，肌肤干裂。对减肥者也有帮助。", "蕃茄柠檬汁\n　　\n　　材料：蕃茄2个、柠檬半个、蜂蜜适量\n　　\n　　做法：蕃茄，柠檬洗净切小块，与蜂蜜一起放入果汁机中打汁即可。\n　　\n　　功效：蕃茄含丰富胡萝卜素与维生素C，维生素P等，可预防细胞老化。是养颜美容的好饮料。", "苹果芥菜汁\n材料：苹果1个柠檬1个芹菜60g芥蓝菜80g蜂蜜与冰块适量\n\n作法：（1）青菜类洗净切小段，加少许冷开水放入果汁机中打汁（2）苹果去皮去核切小块，连同冰块与柠檬汁放入如上的菜汁中一起打成果汁，最后加蜂蜜适量。"]'::jsonb, 30, 180, '困难', 3, 'https://i2.chuimg.com/aa5c9f9e891711e6b87c0242ac110003_500w_330h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鲜榨果汁的4+1种有爱喝法厨娘物语', '烘焙甜品饮料', '果汁', '', '[{"name": "香浓香蕉燕麦牛奶", "amount": "适量"}, {"name": "香蕉", "amount": "2根"}, {"name": "燕麦", "amount": "30g"}, {"name": "牛奶", "amount": "300ml"}, {"name": "美颜火龙果草莓奶", "amount": "适量"}, {"name": "火龙果", "amount": "1个"}, {"name": "草莓", "amount": "4个"}, {"name": "酸奶", "amount": "100ml"}, {"name": "甜蜜胡萝卜橙子汁", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "橙子", "amount": "1个"}, {"name": "蜂蜜", "amount": "5g"}, {"name": "饮用水", "amount": "100ml"}, {"name": "清新奇异果黄果汁", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "奇异果", "amount": "1个"}, {"name": "梨", "amount": "1个"}, {"name": "饮用水", "amount": "50ml"}, {"name": "维C凤梨芒果汁", "amount": "适量"}, {"name": "凤梨", "amount": "1个"}, {"name": "芒果", "amount": "1个"}, {"name": "半个百香果", "amount": "适量"}, {"name": "饮用水", "amount": "50ml"}]'::jsonb, '["香浓香蕉燕麦牛奶：\n2根香蕉去皮切小块。", "榨汁机内放入香蕉块、30g燕麦。", "倒入300ml牛奶，打至顺滑。", "倒入杯中，撒上燕麦，放入吸管。", "香浓香蕉燕麦牛奶就完成啦，开喝吧~", "美颜火龙果草莓奶：\n1个火龙果对半切开，去皮切成小块。", "4个草莓去蒂对半切开。", "将草莓、火龙果块放入榨汁机中，倒入100ml酸奶。", "打至顺滑，倒入杯中。", "美颜火龙果草莓奶就做好啦，开喝吧~", "甜蜜胡萝卜橙子汁：\n1根胡萝卜去皮切成小块。", "1个橙子去皮，去筋切出果肉。", "榨汁机内放入胡萝卜、橙子，加入5g蜂蜜，100ml饮用水。", "打至顺滑。", "倒入杯中，放入吸管。", "甜蜜胡萝卜橙子汁就完成啦，开喝吧~", "清新奇异果黄果汁：\n1根黄瓜切块。", "1个奇异果去皮切块。", "1个梨去皮切小块。", "切好的果肉放入榨汁机中，倒入50ml饮用水。", "打至顺滑倒入杯中，放入吸管。", "清新奇异果黄瓜汁就做好啦，开喝吧~", "维C凤梨芒果汁：\n半个凤梨，切条切成小块。", "1个芒果对半切开，沿杯口用力按出果肉。", "把锅内放入榨汁机内，倒入50ml饮用水。打至顺滑。", "倒入杯中，放入半个百香果，放入吸管。", "维C凤梨芒果汁就做好啦，开喝吧~"]'::jsonb, 30, 135, '困难', 3, 'https://i2.chuimg.com/34cd53f4469a11e7bc9d0242ac110002_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鲜榨果汁搭配大全', '烘焙甜品饮料', '果汁', '', '[{"name": "新鲜水果加牛奶加酸奶", "amount": "适量"}]'::jsonb, '["🍊橙子味养乐多：\n新鲜橙子一个，养乐多两瓶，打成汁即可\n口感：酸酸甜甜，这就是现实版的橙子味养乐多啊，超好喝，大家都知道橙子直接用榨汁机榨出来是会发苦的，加了养乐多，口感超级好，你们一定要试试", "🔥火龙果牛奶加酸奶\n火龙果一小块约70克，加入250毫升牛奶，加半盒酸奶（杯装100克那种酸奶），打成汁即可\n口感：火龙果味酸奶的感觉[赞R]，女儿不吃火龙果，但是经常大便干燥，不得不想办法，火龙果加了牛奶和酸奶打成汁后她可以喝满满一杯，说明很好喝", "苹果胡萝卜汁🔥熟饮\n\n🍎苹果跟胡萝卜各半根，放锅中蒸熟，加入一杯凉白开打成汁即可\n口感：这个口感简直就是逆天了，不仅颜值高，而且超级好喝，不爱吃胡萝卜的宝宝一定试试，营养丰富哦，一点胡萝卜那种异味都没有的", "纯正葡萄汁\n🍇葡萄去皮，加入两勺白糖打成汁即可\n口感：酸酸甜甜，我是很喜欢喝的，我记得怀孕的时候有人说多吃葡萄，生的孩子眼睛大，然后我又吃不完那么多葡萄，就天天打葡萄汁喝啦，然而然而娃的眼睛还是遗传了她爸爸", "木瓜牛奶加酸奶\n木瓜一小块，加入250毫升牛奶，加半杯酸奶，打成汁即可\n口感：浓郁的木瓜味，带着酸奶的酸甜，比直接打木瓜牛奶好喝多了，据说丰胸，不知道真假\n纯正哈密瓜汁", "黑芝麻牛奶加酸奶\n黑芝麻炒熟，约小半碗，加入250毫升牛奶，加入半杯酸奶打成汁即可\n口感：浓郁的芝麻香味带着牛奶的丝滑，乌黑亮发全指望它了，如果喜欢浓稠的状态，可以少加牛奶，或者多加黑芝麻，另外还可以加点糖一起打，然后放入雪糕磨具里做黑芝麻糊雪糕", "芒果牛奶\n小台芒果一个半，加入250毫升牛奶打成汁即可\n口感：浓浓的芒果味，夹杂着牛奶的甘甜，超好喝的，芒果不要放多，多了就成芒果奶昔了", "🍌香蕉牛奶\n香蕉半根，如果大香蕉就三分之一根，加入250毫升牛奶打成汁即可\n口感：我不喜欢喝奶昔，这个量打出来的香蕉牛奶特别丝滑细腻，好好喝", "哈密瓜半个，去皮去籽打成汁即可\n口感：哈密瓜用榨汁机打出来的果汁我感觉比纯汁机榨的好喝太多了，能感觉到果肉的口感，超好喝", "都是新鲜果汁哦，这个果汁机可以抽真空，平时去幼儿园接宝宝，我都会榨一杯新鲜果汁带去给女儿喝", "来个一周大合集", "水果榨出来颜色好美啊", "你们也快试试吧，都超好喝的"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/c031087eab304604af7ba0baba0f0835_1242w_2208h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('苹果汁（不氧化）', '烘焙甜品饮料', '果汁', '', '[{"name": "（整个约387克，去皮去核后约243克）苹果", "amount": "1个"}, {"name": "水", "amount": "650克"}, {"name": "（如果榨的汁本身就挺甜了，糖就少放点，反之，多点）糖", "amount": "15克"}, {"name": "苹果甜度不一样，加了糖也不一样；喜欢甜的，糖多放点，喜欢淡的，糖少放点", "amount": "适量"}, {"name": "榨汁后边放糖，边搅拌，同时可以尝一下味道，再看糖用不用多加，或少放", "amount": "适量"}]'::jsonb, '["苹果去皮切块", "削皮去核之后，约243克", "倒入清水，煮沸", "把煮好的苹果和水，倒入破壁机/果汁机/豆浆机榨汁，果蔬模式/自定义榨汁模式（不需要加热了）", "放入糖搅拌\n放糖之前先尝一下味道，感觉是淡的，再放糖\n边放边搅拌，同时要尝一下味道"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/c700a01ee04a41acae9ef8abe35102c2_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('破壁机菜谱丝滑醇香南瓜汁喝过最好喝的南瓜汁', '烘焙甜品饮料', '果汁', '', '[{"name": "约600克南瓜", "amount": "适量"}, {"name": "约22克大米", "amount": "适量"}, {"name": "约20克黄豆", "amount": "适量"}, {"name": "约16克小米", "amount": "适量"}, {"name": "6-8颗冰糖", "amount": "适量"}, {"name": "破壁机最后加到1400ml水", "amount": "适量"}]'::jsonb, '["南瓜去皮去籽，切成小块备用", "准备好大米，小米，黄豆和冰糖，黄豆是最后醇香的关键", "材料如图", "放入破壁机，加水到1400ml水位线，选择破壁机-杂粮糊，点击启动，做的过程中，整个客厅都能闻见香气✨", "最后的成品，特别丝滑香甜", "一大杯热气腾腾的，丝滑醇香的南瓜汁就做好啦"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/6c2df2dff7a34dec96552a1dca77cec6_4096w_2730h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('水果茶', '烘焙甜品饮料', '花草茶', '', '[{"name": "苹果", "amount": "适量"}, {"name": "菠萝", "amount": "适量"}, {"name": "柠檬", "amount": "适量"}, {"name": "红茶包", "amount": "适量"}, {"name": "薄荷叶（可略）", "amount": "适量"}]'::jsonb, '["苹果切丁，菠萝切小块，柠檬切片", "锅里烧开水，将苹果菠萝放入煮3--5分钟，然后将红茶包放入浸出颜色后取出", "将锅中煮好的水果红茶倒入杯子中，加上新鲜的薄荷叶和柠檬片即可"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/7e676098873911e6b87c0242ac110003_450w_598h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超懒冻柠茶', '烘焙甜品饮料', '花草茶', '', '[{"name": "红茶", "amount": "适量"}, {"name": "柠檬", "amount": "适量"}, {"name": "或冰糖蜂蜜", "amount": "适量"}, {"name": "适量冰块", "amount": "适量"}]'::jsonb, '["用开水冲泡红茶包（立顿茶包可以，茶粉过滤、茶叶沏泡当然更可以啦），30秒后将茶包拎出，不要长时间浸泡，以免茶汤变涩", "放凉茶汤的同时清洗柠檬。柠檬表面撒上适量盐，用手揉搓，可以去除皮上可能存在的果蜡。柠檬洗净后切片备用", "茶汤冷却至室温后加入柠檬片、适量蜂蜜/冰糖搅拌调味，加入冰块直接饮用，或放进冰箱冷藏"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/9fdbe59540da4067aeda0bc9c47debe7_3456w_5184h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('夏日冰爽蜜桃冰茶', '烘焙甜品饮料', '花草茶', '', '[{"name": "，洗净，切片成熟的桃子（油桃，毛桃，水蜜桃）", "amount": "3个"}, {"name": "一杯清水", "amount": "适量"}, {"name": "大半杯（糖量根据自己口味调节吧）冰糖或白砂糖", "amount": "适量"}, {"name": "半个柠檬汁", "amount": "适量"}, {"name": "一升清水", "amount": "适量"}, {"name": "一汤勺或2个茶包红茶或茶包（绿茶也行）", "amount": "适量"}]'::jsonb, '["将糖、水和桃子在一个小锅里煮沸。用木勺搅拌，让桃子的味道释放出来。小火煮5分钟至砂糖溶解后，熄火盖上锅盖，浸泡25 - 30分钟。最后加入柠檬汁。", "开始煮茶。大锅里倒入一升水和茶叶或茶包。沸腾后小火煮4-5分钟。过滤出茶叶，放置冷却。（喜欢茶味重就多放点茶叶，要茶味淡就少放点）", "桃子糖水放凉后倒入瓶子或容器里，过滤掉桃子肉。（桃子肉可以留着吃，别浪费~~~）", "混合桃子糖水和红茶。饮用时加入冰块和新鲜桃子切片。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a512a9e8885e11e6a9a10242ac110002_3471w_2327h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('桂圆枸杞红枣茶', '烘焙甜品饮料', '花草茶', '', '[{"name": "灯笼桂圆肉", "amount": "适量"}, {"name": "贡果枸杞", "amount": "适量"}, {"name": "新疆红枣片", "amount": "适量"}]'::jsonb, '["开水冲泡就可以喝，可不断加水，优哉游哉喝上半天"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/f54795c888cb11e6a9a10242ac110002_620w_380h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('苹果肉桂茶', '烘焙甜品饮料', '花草茶', '', '[{"name": "一个苹果", "amount": "适量"}, {"name": "一到两根肉桂", "amount": "适量"}, {"name": "大容量（1L）水杯", "amount": "适量"}]'::jsonb, '["苹果和肉桂分别洗净，苹果可以用一点点盐揉搓表面起到杀菌和消毒的功效", "苹果去芯，不用削果皮，直接切成小片。越薄越好", "往水杯中放入肉桂和1个苹果分量的苹果片，冷藏8-12个小时", "肉桂和桂皮很像哦 不要买错了肉桂是入药的 药店都有卖\n肉桂是里面，桂皮是外面的皮"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/41642af6b16311e6947d0242ac110002_961w_721h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧肉炖土豆（丝毫不腻）', '肉类', '猪肉', '', '[{"name": "带皮五花肉1.5斤", "amount": "适量"}, {"name": "土豆一个切块", "amount": "适量"}, {"name": "冰糖6个", "amount": "适量"}, {"name": "适量葱姜蒜、八角两个、香叶两片、桂皮一小块", "amount": "适量"}, {"name": "（孩子吃饭用的小勺）老抽一勺、生抽两勺", "amount": "适量"}]'::jsonb, '["葱姜蒜、八角、香叶、桂皮", "冰糖六颗（这是一斤半的用量，各位可以根据肉多少适量增减冰糖用量）", "带皮五花肉，凉水下锅放三片姜，适量料酒，烧开过凉水冲洗干净控干水。然后干锅什么都不放下入五花肉煎出油后盛出待用。注：这一步很重要，我试过不用这一步，做出来的太腻。", "锅内放油，凉油下入六颗冰糖小火熬至枣红色。", "冰糖熬至枣红色后下入五花肉翻炒挂色，然后下入备好的葱、姜、蒜、八角、香叶、桂皮，翻炒几下后倒入老抽、生抽再翻炒至均匀。", "（重要的事说三遍：开水、开水、开水）老抽、生抽翻炒均匀后倒入适量开水，大火烧滚后盖上锅盖中小火炖40分钟。因为炖的时间长，开水多加点，炖的时候多看着点，水少的时候加水（必须开水）。（说明一下，开水是做好后肉软糯的关键一步，放凉水的话做好后肉会略紧，一定放开水哦！）", "炖四十分钟后用筷子夹出香叶、桂皮、八角，加入适量盐、味精，下入土豆块，添加适量开水盖锅盖继续中小火炖十分钟。", "放土豆块炖十分钟后出锅！好吃点个赞哦！好吃的话记得收藏，不然小心找不到了。", "配米饭女儿能吃一大碗！", "第一次发帖，本人做饭照镇楼！好吃记得点赞收藏哦，给点动力以后再发几道拿手菜！"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/790de2c46c574f809bd4797ad2c19370_864w_1152h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单的家常下饭菜猪肉末辣炒豆角', '肉类', '猪肉', '辣', '[{"name": "豇豆角", "amount": "600克"}, {"name": "猪肉（半肥瘦）", "amount": "300克"}, {"name": "生抽", "amount": "3勺"}, {"name": "料酒", "amount": "3勺"}, {"name": "半勺糖", "amount": "适量"}, {"name": "半勺蚝油", "amount": "适量"}, {"name": "一勺老抽", "amount": "适量"}, {"name": "小米椒", "amount": "5个"}, {"name": "6瓣蒜头", "amount": "适量"}, {"name": "一勺淀粉", "amount": "适量"}]'::jsonb, '["半肥瘦的猪肉末。加一勺料酒一勺生抽半勺蚝油半勺糖一勺淀粉腌制10几分钟。（也可以不腌，后续调味加重）", "加油炒香肉末炒出一些油取出肉末备用", "肉末炒出的油再加点油加入小米椒和蒜末炒香后，加入洗干净切粒的豆角大火爆炒，两勺料酒两勺酱油锅边淋入炝锅，水分干了即时补2-3勺水，大概全程大火翻炒五分钟左右，这五分钟内看情况补水", "加入炒好的肉末一起翻炒2-3分钟左右，加入小半勺老抽调色，一茶匙盐调味，出锅"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/f6aa3b2c097743c79f7a91cbdc9190df_2654w_2122h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉末嫩豆腐｜嫩滑口感爽口！这道快手菜超级下饭！！（减脂少油版）', '肉类', '猪肉', '', '[{"name": "1盒嫩豆腐", "amount": "适量"}, {"name": "肉末", "amount": "80克"}, {"name": "1朵（浸泡）干香菇", "amount": "适量"}, {"name": "小米辣", "amount": "1根"}, {"name": "葱花", "amount": "1把"}, {"name": "少许水淀粉", "amount": "适量"}, {"name": "海天酱油", "amount": "1.5勺"}, {"name": "少许盐", "amount": "适量"}, {"name": "适量食用油", "amount": "适量"}]'::jsonb, '["提前将香菇泡开泡软（香菇水留着），切丁备用。", "猪肉末里分别放入香菇丁/蒜末/少许盐/酱油/半勺食用油，搅拌均匀。", "炒锅中放入少许油(减脂选用橄榄油～），7成热时后放入肉末煸熟，放入蒜末和朝天椒翻炒一下后，再加入半碗香菇水至烧开。", "嫩豆腐切块（约2*2cm），轻轻倒入锅中。", "加入2勺酱油、少许白胡椒粉。倒入水淀粉（2勺生粉+1/3碗水），转中火不用盖锅盖。", "待酱汁烧开后，别把酱汁烧的太干，留一点拌饭吃超下饭！！！😏我家的已经把盘子都给舔干净了！！盛出后撒上葱花～"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/de5502b3309d4388a885900139021a49_4032w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蒜苔炒肉末，三碗米饭都不够吃', '肉类', '猪肉', '', '[{"name": "蒜苔", "amount": "1斤"}, {"name": "肉末", "amount": "200克"}, {"name": "3/4根小米辣", "amount": "适量"}, {"name": "根葱", "amount": "2根"}, {"name": "半个瓣蒜瓣", "amount": "适量"}]'::jsonb, '["洗净的蒜苔切丁，肉末用搅肉机搅碎一下，不要太碎，有点颗粒感好吃，2勺生抽，1勺老抽，1勺蚝油", "少许盐白糖，1勺淀粉，加适量清水搅匀备用", "葱姜蒜末一起炒香来", "倒入肉末翻炒至肉末变色，稍微多炒一会儿，炒出焦香味", "淋上调好的料汁", "煮至浓稠即可盛出", "另起锅倒入蒜苔炒至1/2分钟，喜欢吃烂了点稍微多炒一会儿，（看个人喜好，我喜欢脆的😁", "加点小米辣提鲜增点辣味，（不喜欢吃辣的可以不放）", "最后翻炒至浓稠即可出锅", "每次做这个菜，孩子都要吃2碗米饭🫣，太费米饭🍚了，记得多煮点哦（有些孩子吃不了辣，也可以不放，也一样好吃）"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/ccb439fb9d0b4c699650e3e9bd179c3d_1125w_1470h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('破防了红烧肉这样做味道真的绝了', '肉类', '猪肉', '', '[{"name": "五花肉", "amount": "300克"}, {"name": "鹌鹑蛋", "amount": "20个"}, {"name": "适量姜蒜葱", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "八角", "amount": "3个"}, {"name": "香叶", "amount": "4片"}]'::jsonb, '["好吃不腻", "五花肉切块，鹌鹑蛋煮熟剥壳备用\n五花肉冷水下锅，加入一勺料酒，葱段煮出浮沫捞出\n锅里不放油，小火将五花肉放进去煎至两面微微金黄盛出，倒出多余的油\n放入冰糖炒出焦糖色，将五花肉倒入翻炒上色，倒入两碗开水", "加入一勺料酒+3勺生抽+1勺老抽+1勺蚝油，加入适量八角桂皮香叶，葱结，姜蒜头，焖煮30分钟\n再倒入鹌鹑蛋中小火焖煮20分钟，最后大火收汁就可以出锅啦！"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/ed788b55f35e4ab9857d43991bec7216_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨好吃的红烧排骨炖土豆懒人版轻松做拿手菜', '肉类', '排骨', '', '[{"name": "排骨", "amount": "500克"}, {"name": "土豆", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "八角", "amount": "3个"}, {"name": "桂皮", "amount": "1块"}, {"name": "6粒冰糖", "amount": "适量"}]'::jsonb, '["排骨洗净剁小块，凉水下排骨，加适量料酒、葱姜焯水，捞出冲洗干净，沥干水分。\n起锅小火放适量油和冰糖，炒到冰糖完全融化，下入排骨翻炒均匀\n放入葱姜片、香叶、八角、桂皮炒香➕一勺生抽➕一勺老抽➕一勺蚝油，翻炒均匀", "加入没过排骨的热水，水开转小火盖盖煮25分钟", "➕适量盐，加入切块的土豆（正好有半根胡萝卜，也一起放了）继续炖15分钟左右", "炖至土豆熟透，大火收汁即可。", "超级香的排骨土豆就做好了", "土豆软糯入味 好吃"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/2cf481dd07a44f04b4b9d4639d1abe52_1254w_1003h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('糖醋排骨', '肉类', '排骨', '', '[{"name": "仔排", "amount": "500g"}, {"name": "约15~20g冰糖①", "amount": "适量"}, {"name": "料酒", "amount": "1汤匙"}, {"name": "生抽", "amount": "2汤匙"}, {"name": "(约45g)冰糖②", "amount": "3汤匙"}, {"name": "白醋", "amount": "4汤匙"}, {"name": "老抽", "amount": "1茶匙"}, {"name": "1粒八角", "amount": "适量"}, {"name": "2小片香叶", "amount": "适量"}, {"name": "1结小香葱", "amount": "适量"}, {"name": "生姜", "amount": "3片"}]'::jsonb, '["2025年啦，我来更新个简朴的制作视频！", "排骨洗净～", "锅中倒入冷水，放排骨煮开后捞出，温水洗净沥干备用。", "锅内倒入适量的油和冰糖①", "中火加热至变成焦糖色，转小火。千万不要炒过头，不然发黑发苦。（换锅子不为啥，就是铁锅操作的时候，忘记拍照片了。过程和做法是一样，展示一下而已。）", "倒入排骨快速翻炒上色。（此步骤为炒糖色儿，为了上色更好看。）倒入排骨的时候，可以用锅盖挡一挡，防止油迸到身上。", "转中大火，依次倒入料酒，生抽，老抽，冰糖②，白醋 和生姜片翻炒出香气。    \n\n       \n很多人问醋呢？醋在这一步啊！！\n醋在这里！醋在这里！醋在这里啊！！\n\n还看不到吗？醋在这里！\n\n这下应该看到了吧？！醋在这里！！\n\n麻烦仔细看步骤啊！！！", "准备好八角香叶 （你要是不想放，那就不放。看个人喜好，真不用太纠结。家里做菜灵活操作嘛(๑°⌓°๑)不用照搬，也没人逼你。）", "倒入适量的热水没过排骨，放入八角香叶和香葱结，煮开后转小火焖30分钟。", "半小时后，大火收汁。", "收汁完成，色泽美美哒。", "香喷喷哒。根据个人喜好收汁，有人喜欢干一点的，有人喜欢汤汁多点的。\n\n再尝下咸淡，毕竟品牌不同，生抽啊酱油啊什么的含盐量不一样，淡了就加盐。随意点，不用照搬。\n\n加不加盐，盐，盐，看这里！这里！！\n\n❗再说一遍：每个品牌的生抽、酱油之类的含盐量不同，淡了就加盐！！菜做好前，自己尝尝就知道了。根据自家情况调整！", "出炉后撒炒熟的白芝麻和葱花点缀。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/1ebd8d06f15140e3a8eed3d792066a45_2784w_1856h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱香排骨', '肉类', '排骨', '', '[{"name": "适量干葱姜蒜", "amount": "适量"}, {"name": "4粒冰糖", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "八角", "amount": "2个"}, {"name": "料酒", "amount": "2勺"}, {"name": "黄豆酱", "amount": "2勺"}, {"name": "排骨", "amount": "1000克"}, {"name": "15粒花椒", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}]'::jsonb, '["准备好葱姜蒜，喜欢吃姜可以多放，不喜欢可以少放", "可以根据个人口味添减，", "排骨清水洗干净", "焯水后备用（焯水加点姜片料酒去腥味）", "热锅放油先放姜片（这样炒出的姜片好吃不辣，炒其他肉类的时候也可以先煸炒姜片）炒出香味加入葱蒜炒香，加入排骨炒料酒继续翻炒，再加入黄豆酱、冰糖、老抽、生抽，八角花椒（喜欢辣可以加入干辣椒或者收汁的时候加入小米辣青红辣椒）翻炒均匀，炒出香味加入清水，一勺白醋最好没过排骨大火烧开5分钟左右转中小火炖煮40到60分钟（根据个人喜好筋道的就时间短些，喜欢软烂就炖久点）", "最后大火收汁（也可以根据个人喜好加入少量的土豆或者冬瓜）留点汤汁拌饭或者拌面条都是很美味的。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/d0e1fa0043e9448d9dde08729725537c_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('土豆排骨（超好吃）', '肉类', '排骨', '', '[{"name": "排骨", "amount": "200克"}, {"name": "土豆", "amount": "2个"}, {"name": "青椒", "amount": "2个"}, {"name": "4瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "2片"}, {"name": "小葱", "amount": "2根"}, {"name": "桂皮", "amount": "1块"}, {"name": "香叶", "amount": "3片"}, {"name": "1罐啤酒", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "料酒", "amount": "2勺"}, {"name": "油", "amount": "30克"}, {"name": "盐", "amount": "5克"}, {"name": "生抽", "amount": "3勺"}, {"name": "老抽", "amount": "2勺"}]'::jsonb, '["排骨洗净，冷水下锅，放入姜片料酒，煮出浮沫，捞出洗干净备用。", "焯水后的排骨。", "土豆2个，切成小块。锅内放油，小火煎至微焦，盛出备用。", "准备葱、姜、蒜、干辣椒、桂皮、香叶。", "锅内少油，放入除辣椒以外的调料炒香，放入排骨；\n\n再放老抽，生抽，翻炒均匀，倒入一罐啤酒没过排骨，或者加入开水，大火烧开，转小火，炖15分钟（如果喜欢很软糯的，可以炖久一点的），放入土豆和辣椒，再煮5分钟，出锅。\n\n出锅前尝一下味道，如果淡了就放点盐。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/7b5db1c2178544fda947fab84baee4ae_2107w_1703h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('硬菜代表--排骨炖豆角土豆（豆角焖面胚子）', '肉类', '排骨', '', '[{"name": "排骨", "amount": "400克"}, {"name": "豆角", "amount": "300克"}, {"name": "土豆", "amount": "1个"}, {"name": "1捏花椒（或粉）", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "半勺盐", "amount": "适量"}, {"name": "适量料（白）酒", "amount": "适量"}, {"name": "4瓣大蒜", "amount": "适量"}, {"name": "半根葱", "amount": "适量"}, {"name": "姜", "amount": "4片"}, {"name": "1圈东古黄豆酱油（老式塑料瓶比较便宜那种）", "amount": "适量"}, {"name": "半圈东古一品鲜酱油", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}, {"name": "干辣椒", "amount": "2个"}]'::jsonb, '["食材处理：", "排骨凉水浸泡2小时以上（急就不泡）", "摘豆角，掰不掰断随意。关于土豆在下一步。", "姜切片，葱切葱花，蒜拍扁，大概切两下。花椒八角干辣椒备用。", "几种酱油和料酒备好，免的炒时候慌乱。", "如图↑如果不是焖面用，土豆平时我还是用刀别（锛）成块或者切滚刀块。（玉米、倭瓜炖进去都好吃，很好吃的那种好吃！和土豆一块下锅就行）", "不焯水直接爆炒 肉香味绝对更浓郁（冻的久的话还是先焯一下），热！锅凉油下排骨，要不然粘锅粘的你怀疑人生。", "花椒八角干辣椒可以先扔进去，中小火多煸一会儿炒干水分，转大火锅边烹一圈料（白）酒（一定炒的水分够干再烹料酒，即刻颠勺绝对出火苗↑像这样），放姜蒜，酒和姜蒜水分炒干后重复上述操作，再放葱花。", "锅边淋入半圈一品鲜，一圈老酱油，一点老抽，炒出酱香味，转小火加热水没过排骨。", "中小火，水开后炖15-20分钟下豆角土豆，适量加盐。再炖15分钟左右。出锅前撒蒜末盛出。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/710054dc2be3431d857d46c7e9e3732a_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('虎皮青椒/青椒塞肉', '肉类', '猪肉末', '', '[{"name": "适量肉末", "amount": "适量"}, {"name": "青椒", "amount": "3个"}, {"name": "3朵香菇", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "生抽", "amount": "3勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "耗油", "amount": "1勺"}, {"name": "醋", "amount": "1勺"}, {"name": "少许糖", "amount": "适量"}, {"name": "黄豆酱", "amount": "1勺"}]'::jsonb, '["将胡萝卜香菇切碎，放肉馅中，加盐，生抽2勺，老抽，耗油拌匀", "尖椒切段，我的尖椒比较长，我分成了三段，将拌好的肉馅塞进尖椒里", "锅里加油，油热放入尖椒.，煎至两面出虎皮即可，大约煎6-7分钟，全部煎完后锅中加入少许水，盐一丢丢，生抽1勺，糖，醋，黄豆酱，水开后2分钟就好了", "出锅啦，开动"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/3ce4350edcd04cc08d0087d9658f6707_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃哭了的万能肉沫酱', '肉类', '猪肉末', '', '[{"name": "少许盐", "amount": "适量"}, {"name": "肉沫", "amount": "300克"}, {"name": "适量生姜", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "（小）洋葱", "amount": "1个"}, {"name": "线椒", "amount": "2个"}, {"name": "小米辣", "amount": "2个"}, {"name": "生抽", "amount": "1勺"}, {"name": "耗油", "amount": "1勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "黄豆酱", "amount": "2勺"}, {"name": "料酒", "amount": "2勺"}, {"name": "适量油", "amount": "适量"}]'::jsonb, '["准备食材，肉沫放点料酒、盐腌半小时", "葱、姜、线椒、小米辣切小段，洋葱切碎备用", "玉米淀粉2勺备用", "生抽、老抽、耗油、料酒、黄豆酱混合均匀而成的调料汁", "油锅烧热，放入葱姜煸炒香", "放入肉沫翻炒至变色，再加入线椒、小米椒炒2分钟", "加入洋葱碎，加入调料汁翻炒3分钟", "玉米淀粉加少许水混匀倒入锅中，继续翻炒2分钟，收汁即可关火\n不香吗？自己动手试试吧。哈。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/5e9416233d3348108b99ef21b3b98e50_912w_684h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('毛豆米炒肉沫', '肉类', '猪肉末', '', '[{"name": "毛豆", "amount": "适量"}, {"name": "肉末", "amount": "适量"}, {"name": "蒜末 生抽 老抽 耗油 白糖 淀粉 小米辣", "amount": "适量"}]'::jsonb, '["调料 放一旁备用"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/1ed5c79c899e4188b6cf647670427659_788w_1051h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉沫青椒', '肉类', '猪肉末', '', '[{"name": "青杭椒", "amount": "适量"}, {"name": "肉末", "amount": "适量"}, {"name": "蒜末", "amount": "适量"}, {"name": "葱花", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "白糖", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺鸡精", "amount": "适量"}, {"name": "半勺花椒粉", "amount": "适量"}, {"name": "清水", "amount": "适量"}, {"name": "淀粉", "amount": "适量"}]'::jsonb, '["准备材料", "调酱汁：碗中加入2勺生抽，1勺蚝油，1勺料酒，1勺老抽，少许白糖，半勺鸡精和花椒粉，半碗清水，搅拌均匀。", "电炒锅倒油，放入肉末炒熟，加入葱蒜炒香，倒入酱汁炒匀，加入青椒圈翻炒几分钟至熟。", "淋上半碗淀粉水焖至汤汁浓稠，盛出浇在米饭上，拌匀开吃吧！！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/f3cefe098283485ab3eccc3d8656d4b2_1080w_1332h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉末四季豆', '肉类', '猪肉末', '', '[{"name": "四季豆", "amount": "500克"}, {"name": "肉末", "amount": "200克"}, {"name": "生抽", "amount": "1大勺"}, {"name": "老抽", "amount": "1小勺"}, {"name": "糖", "amount": "5克"}, {"name": "少量料酒（拌肉末）", "amount": "适量"}, {"name": "少量盐", "amount": "适量"}]'::jsonb, '["肉末大约200克的样子，用盐，料酒，拌一下，备用。", "四季豆去头尾，切成小丁，起油锅翻炒。", "这步要有点耐心慢慢翻炒，可以用大火，但是别停下翻炒。把四季豆里的水全部炒干，如果感觉太干了，加一点生抽一方面调味一方面加点水分。", "炒到这个程度就差不多了，大概需要6-8分钟。盛出备用。", "起油锅放入肉末翻炒至变色。", "加入一勺老抽调色。", "放入四季豆末一起翻炒。放一勺生抽，一勺糖。", "如果觉得太干可以放一点水炖一会。", "起锅开吃，配上大米饭特别好吃！娃们还能添饭。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/214d8f6685bf4450bf34c7fc847fbcc6_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五花肉干煸土豆片', '肉类', '五花肉', '', '[{"name": "两颗土豆", "amount": "适量"}, {"name": "五花肉", "amount": "200克"}, {"name": "或麻辣香锅调料郫县豆瓣酱", "amount": "适量"}, {"name": "一个菜椒红色菜椒或者干辣椒", "amount": "适量"}, {"name": "5～10克盐", "amount": "适量"}, {"name": "三片姜", "amount": "适量"}, {"name": "一个青椒", "amount": "适量"}, {"name": "四五颗蒜瓣量蒜末", "amount": "适量"}]'::jsonb, '["土豆切片，不用太薄，适当就行\n土豆如果比较大就对半切片，怎么切无所谓了", "葱姜蒜切片，青红椒切段\n除了炒菜的蒜，还要四五瓣蒜剁成细一点蒜末备用", "五花肉选肥瘦相间，切薄片，如果不好切片，先冻一下再切就比较好切了。\n我的五花肉让卖家去皮了", "土豆片切的薄可以省略这一步💋\n土豆片入开水煮到八分熟，大概就是咬上去不是脆脆的口感，可以凉拌的那个程度，咬一口就知道了哈哈", "先不开火凉锅凉油下入五花肉翻拌一下让肉片散开都粘上油（这样可以有效防止粘锅）\n然后才开火慢慢煸炒五花肉到有一点焦黄和油脂出来", "加入葱姜蒜和郫县豆瓣酱一勺翻炒出红油\n，有时候我也会用麻辣香锅调料", "下入煮好的土豆片和青红椒继续翻炒，让五花肉的油脂煸一会土豆片，关火加入蒜末即可出锅。\n想适当滴一滴老抽上色也未尝不可😂\n\n加了郫县豆瓣酱基本就不在加盐了，我喜欢最后出锅前烹点醋"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/92f33f6c685411e7947d0242ac110002_1250w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧五花肉', '肉类', '五花肉', '', '[{"name": "五花肉", "amount": "500克"}, {"name": "6到8颗（甜度视个人而定）冰糖", "amount": "适量"}, {"name": "老抽", "amount": "2勺"}, {"name": "适量姜", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "一小勺生抽", "amount": "适量"}, {"name": "1到2片香叶", "amount": "适量"}, {"name": "4到5个（看个人）干辣椒", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "小段葱", "amount": "适量"}, {"name": "3到4个蒜", "amount": "适量"}]'::jsonb, '["肉切小块焯水（直接把切好的肉放冷水里，不盖盖子烧开后再稍微煮一会就好）\n前面的步骤忘记拍了，从炒糖色开始吧，锅里倒入适量油，大火加热转小火，把冰糖放锅里炒，用铲刀一个个拍碎，完全溶化后不停的翻炒，有细腻泡沫出来的时候把五花肉倒入锅内，翻炒两分钟左右，翻炒后上色均匀。", "翻炒均匀后，上色如图（千万不要翻炒时间太长，不然会有微微的苦味）", "把配料入锅继续翻炒，转中火，炒出配料的香味，倒入生抽，料酒，待料酒收干后加入提前准备好的温水（冷水会使肉煮出来有点柴）。", "水没过肉即可。然后加入准备好的老抽，喜欢甜的话再加点白糖。大火烧开，转中小火继续煮。", "煮到水差不多的时候，大火收汁。如果喜欢肉烂一点的话加水的时候可以多加点，时间煮长一点。", "香喷喷的五花肉出锅啦，最后撒上葱花，个人觉得挺好吃😋"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/d92721dde0d24ea8bd7bbfe3d9bcf41b_1836w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五花肉干煎土豆', '肉类', '五花肉', '', '[{"name": "五花肉", "amount": "250克"}, {"name": "土豆", "amount": "1个"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "小半勺老抽", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "小半勺白糖+盐", "amount": "适量"}, {"name": "各一个青红辣椒", "amount": "适量"}]'::jsonb, '["☑土豆五花肉切薄片，辣椒去蒂去籽切滚刀块；\n☑热锅放油放入土豆片中小火煎至表面焦黄盛出备用，放入五花肉干煎至两面焦黄，把五花肉拔到一边，放入大蒜和辣椒炒至断生，加入土豆片翻炒均匀，然后加入糖、盐、蚝油、生抽、老抽翻炒均匀后即可出锅；", "香酥五花肉", "怎么也吃不腻的土豆片", "米饭杀手，真的太好吃啦～"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/3d26a50e61c442ceba50b6fa92a81eb0_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级下饭米饭扒光光——葱爆五花肉片', '肉类', '五花肉', '', '[{"name": "五花肉", "amount": "250克"}, {"name": "大葱", "amount": "1根"}, {"name": "小米椒", "amount": "2个"}, {"name": "杭椒", "amount": "3个"}, {"name": "3-4瓣大蒜", "amount": "适量"}, {"name": "姜片", "amount": "3片"}, {"name": "少许淀粉", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "郫县豆瓣酱", "amount": "2勺"}, {"name": "糖", "amount": "1勺"}, {"name": "小半碗清水", "amount": "适量"}]'::jsonb, '["五花肉片250克可以炒一盘子，看家里人份量决定。五花肉片切成合适大小后倒入碗里加3勺料酒2勺生抽和少许淀粉抓匀腌制20分钟。", "准备好姜，蒜、小米椒、杭椒和一根大葱。", "切片完毕。", "热锅热油，五花肉翻炒。", "炒到微微焦色后盛出。喜欢口感硬实点的可以多煸炒一会儿到五花肉片焦色发硬，个人喜欢微软一些的口感。", "锅里加入姜片和蒜片炒出香味。", "加入椒和大葱片炒软。", "葱姜撇到一边，加入2勺郫县豆瓣酱炒出红油。", "姜蒜葱等和豆瓣酱炒匀。", "加入五花肉，一起翻炒2分钟后，加入小半碗水继续炒。", "豆瓣酱本身挺咸的，不加盐，加一勺白糖提鲜，炒匀。", "出锅盛盘。", "咸鲜入味，大口吃完这一碗葱蒜味🧄十足的五花肉片，才叫爽快。\n真❗️\n的❗️\n香❗️"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/419b0355fc2d42058023479b43612541_3024w_2821h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('下饭神器回锅肉，不爱吃肥肉的我都超喜欢！', '肉类', '五花肉', '', '[{"name": "五花肉", "amount": "500克"}, {"name": "青椒", "amount": "1个"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "盐", "amount": "10克"}, {"name": "鸡精", "amount": "1勺"}, {"name": "白糖", "amount": "8克"}, {"name": "若干姜蒜", "amount": "适量"}]'::jsonb, '["烧肉皮，去腥，烧锅的肉皮更好吃。锅烧热，将皮与锅紧贴，也可以直接在煤气灶上用火烧，注意不要烧到自己了。", "烧成这样就可以了", "冷水下锅煮至七分熟，凭感觉就好了，全熟也可以，味道差不多。", "煮好捞起来切薄片，我喜欢薄一点，不腻。肉像图中这样摆放切，可以切的更薄。", "青椒切块备用。洋葱切丝。", "锅中倒入一点点油，五花肉可以炒出很多油。", "炒至肉皮卷起，肥肉中的油被炒出。我喜欢炒久一点，不会那么腻。", "加入姜蒜，豆瓣酱，白糖，生抽上色", "倒入青椒和洋葱，也可以不放洋葱，我个人是非常喜欢洋葱回锅肉。翻炒一分钟，青椒和洋葱熟了加盐和鸡精。", "只放青椒的", "加了洋葱的", "白糖是关键，一定要放，加了白糖特别香。没有豆瓣酱的可以用豆豉代替。也好吃。"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/8b92b69edd6b4f9381350c562ba37551_3072w_4095h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秘制猪蹄', '肉类', '猪蹄', '', '[{"name": "姜", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "适量桂皮", "amount": "适量"}, {"name": "干辣椒", "amount": "1个"}, {"name": "冰糖", "amount": "适量"}, {"name": "猪蹄", "amount": "500g"}, {"name": "酱油", "amount": "适量"}, {"name": "味精", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "冰糖", "amount": "适量"}, {"name": "香叶", "amount": "适量"}, {"name": "香菜", "amount": "适量"}]'::jsonb, '["桂皮八角 香叶 辣椒 蒜姜改刀备用。葱打个结", "切小块 洗干净", "将猪蹄切成小块 \n锅中加水烧开加入猪蹄烧2分钟 倒出备用", "锅中放油 入冰糖小火熬至变色，放入猪蹄 桂皮八角姜片葱 蒜翻炒 放入酱油 炒至上色加入料酒 水", "然后倒入高压锅中放入葱结 加入一勺味精 几克盐大火烧开盖上保险盖直到沏关小火沏10—15分钟", "等高压锅冷却倒入锅中大火 烧至粘稠 撒上葱花 出锅摆盘", "味道非常好"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/095c7a1fcb534c42ab35538125311fdf_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧猪蹄', '肉类', '猪蹄', '', '[{"name": "猪蹄", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "八角", "amount": "适量"}, {"name": "香叶", "amount": "适量"}, {"name": "桂皮", "amount": "适量"}, {"name": "干红辣椒", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "冰糖", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "老抽", "amount": "适量"}]'::jsonb, '["猪蹄洗净先焯水：猪蹄入冷水下锅煮开后再煮几分钟，捞起用温水冲洗干净，沥干备用；", "葱头、姜、蒜洗净备用；", "八角、香叶、桂皮、干辣椒、花椒洗净备用；", "锅里放油，下入葱姜蒜爆香；", "再放入八角、香叶、桂皮、干辣椒、花椒翻炒出香味；", "炒香的调料捞起备用，锅里的油不用捞起留在锅中；", "抓一小把冰糖放入锅里（不用另外放油，就用刚炒调料用的油），中小火煮至冰糖全部溶化 ；", "倒入猪蹄，翻炒至均匀上色；", "加入料酒、生抽、老抽翻炒均匀；", "加入炒香的调料翻炒下；", "加入没过猪蹄的热水，大火烧开后盖好锅盖转小火煮70－80分钟左右；", "70－80分钟左右可以时可以试下咸味够不够，不够可以加点酱油（不建议加盐），最后用中大火收汁即可。", "捞出装盘。美味的猪蹄多吃更美丽哦！"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/7ab19900896411e6b87c0242ac110003_1239w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('堂妈金牌冰糖猪蹄', '肉类', '猪蹄', '', '[{"name": "猪蹄", "amount": "3只"}, {"name": "大料", "amount": "2个"}, {"name": "两片香叶", "amount": "适量"}, {"name": "适量食用油", "amount": "适量"}, {"name": "李锦记红烧汁", "amount": "4勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "十个左右冰糖", "amount": "适量"}, {"name": "适量食盐", "amount": "适量"}, {"name": "两勺白酒", "amount": "适量"}, {"name": "几片生姜", "amount": "适量"}, {"name": "适量葱段", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}]'::jsonb, '["准备材料", "配料细节图", "一个猪蹄用砍刀剁成四块，别剁的太碎", "锅里添凉水加入猪蹄，加入两汤匙白酒", "再加入生姜两片", "烧开煮一会去除血水和浮沫子", "用捞网捞出猪蹄", "猪蹄用温水清洗干净，控干水份备用", "锅热加食用油，油热后加入冰糖、八角和香叶", "待冰糖充分融化变黄", "加入葱段姜片翻炒出香味", "加入控水的猪蹄翻炒", "再加入生抽和红烧汁继续翻炒均匀", "把料汁炒匀，小心别幅度太大，容易烫着手", "加入适量的温水，水不必漫过猪蹄，持平就好，猪蹄炖得太烂就不好吃了", "加入食盐和鸡精", "猪蹄倒入高压锅", "加热喷气后扣气压阀", "中火２０分钟，关火焖10分钟", "放气后打开高压锅", "打开气阀，猪蹄倒入炒锅收汁浓稠", "这一部很关键，收汁好的猪蹄色泽红亮，即可享用", "来一块，太香了！", "年夜饭必吃菜～～～～堂妈的冰糖猪蹄！"]'::jsonb, 30, 120, '困难', 3, 'https://i2.chuimg.com/52c5c5eccf7d11e6bc9d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('老成都蹄花儿饭（海带猪蹄汤 美容养颜 媲美老妈蹄花儿）', '肉类', '猪蹄', '', '[{"name": "猪蹄", "amount": "2只"}, {"name": "2张干海带", "amount": "适量"}, {"name": "多一点姜", "amount": "适量"}, {"name": "适量大葱", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "比老抽多一些生抽", "amount": "适量"}, {"name": "适量糖", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}, {"name": "适量小葱", "amount": "适量"}, {"name": "适量蒜泥", "amount": "适量"}, {"name": "适量醋", "amount": "适量"}, {"name": "适量红油", "amount": "适量"}, {"name": "适量米饭", "amount": "适量"}]'::jsonb, '["准备干海带两张 海带和猪蹄真的很配 去腥又增香", "凉水下锅至煮开 这样可以缩短泡海带的时间", "捞出切成长条备用", "猪蹄我是前天买的 回家就放进了冷冻 不用解冻 凉水放入锅中（我直接用的焯海带的水）多放点姜去腥", "煮至沸腾 水开后再煮一分钟", "用筷子将猪蹄一个个捞出 只要猪蹄不要姜 不要带出浮沫", "锅洗干净 重新倒入冷水 放入猪蹄 大葱 姜 海带 大火煮开", "锅两边放上筷子 锅盖放在筷子上 避免扑锅", "一直大火 熬煮至汤白", "大概15分钟 已经很白了 蛋白质充分溶解在汤里面了", "汤白后就可以捞出猪蹄和姜（只要猪蹄和姜 不要海带 海带已经软了 不需要再压 再压就烂了）重新加入清水 刚没过猪蹄就行 接下来要用到电压力锅", "电压力锅 选择豆/蹄筋一类 软烂程度选最高的 时间40多分钟 个人觉得电压力锅比普通的压力锅好用的多 没有可怕的声音 而且好了之后还有排气按钮可以直接排气 软烂程度也可以自行选择 非常方便", "压好后的猪蹄 可以看到已经很软烂了", "重新倒回锅中 与刚才的汤一起 大火煮开 加入适量盐和鸡精调味 关火撒入葱花", "汤白 葱绿 蹄花烂 滋补又美容 接下来要打蘸碟了 没有蘸碟的蹄花汤不是四川的蹄花汤", "数一数 一共有11种调料 从上往下从左到右依次是花椒、生抽、老抽、醋、盐、糖、鸡精、红油、蒜泥、葱和小米辣 川味可能精致就在这 调料往往不是一般的多", "所有调料就位 只等红油 红油也是川菜精髓", "蘸碟完成 蒜香 葱香 辣油香 芝麻香 麻辣咸鲜酸甜可口 非常解腻又提味", "蹄花软糯 晶莹剔透", "一点都不腥 海带真是蹄花的好朋友 这碗蘸碟都可以多下两碗饭", "巴适得板 老成都蹄花儿饭😌 你来不来一碗😋"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/f59ae87777564c04bae176fd61cb3d55_2448w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨香烤猪蹄', '肉类', '猪蹄', '', '[{"name": "猪蹄", "amount": "1只"}, {"name": "料酒", "amount": "2勺"}, {"name": "八角", "amount": "1个"}, {"name": "1小把冰糖", "amount": "适量"}, {"name": "1/2勺老抽", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "盐", "amount": "2克"}, {"name": "三根干辣椒", "amount": "适量"}, {"name": "适量姜片", "amount": "适量"}, {"name": "一小包卤料", "amount": "适量"}, {"name": "一个（油纸）烤箱", "amount": "适量"}, {"name": "少许孜然粉辣椒粉", "amount": "适量"}]'::jsonb, '["猪蹄是肉店给烧好毛剁好的，冷水入锅，加一勺料酒，炒菜的勺，姜片适量，煮个七八分钟吧", "就这个料酒", "热锅，冷油，小火，油热以后放一把冰糖，炒糖色，下猪蹄的时候把之前焯水的水控干，小心别被油溅到，不然真的巨疼🙄", "然后后面我就没拍照了，俩手忙不过来，口述吧", "糖色炒的差不多（差不多就是你觉得还挺喜欢的颜色）加入之前准备好的一颗八角，三颗干辣椒，一勺生抽，半勺老抽，一勺料酒，继续翻炒。", "觉得隐约闻到好闻的味道的时候，就加一壶水，（烧开的水，一整壶），这时候把卤料加进去，中火煮15分钟，转到高压锅，上汽以后煮15分钟。", "煮好了就把猪蹄捞出来滤干卤汁，哦对，之前煮的时候我看家里有豆腐干，就加了几块一起进去了", "这时候就可以预热烤箱了，预热10分钟", "趁烤箱自己热自己的时候，把猪蹄放在铺了油纸的烤盘上，撒上辣椒面和孜然，看自己口味酌量撒。", "放进烤箱，上下火，220度，20-30分钟，也是看你喜欢的酥脆程度来定时间。", "时间到了，巨香烤猪蹄就好啦！外面是略有点焦香的，里面是嫩的，巨好吃！我建议大家做起来！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/be9c27f8312b42438c727098732c1d1c_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('瘦肉丸(超级详细，不断改善中……)', '肉类', '瘦肉', '', '[{"name": "猪瘦肉", "amount": "250g"}, {"name": "马铃薯淀粉(或红薯淀粉)", "amount": "175g"}, {"name": "细味精", "amount": "10g"}, {"name": "精盐", "amount": "9g"}, {"name": "香甜泡打粉", "amount": "6g"}, {"name": "高弹素（可略，自己吃别放！！！）", "amount": "5g"}, {"name": "嫩肉粉（可略，自己吃别放！！！）", "amount": "5g"}, {"name": "鸡精", "amount": "5g"}, {"name": "白砂糖", "amount": "5g"}, {"name": "黄料酒", "amount": "3g"}, {"name": "食用碱", "amount": "1g"}, {"name": "猪肉粉精(可略，自己吃别放！！！)", "amount": "1g"}, {"name": "适量佐料(葱、姜、芹菜、香菜、紫菜、虾皮、榨菜、醋、香油、胡椒粉)", "amount": "适量"}, {"name": "水", "amount": "150g"}]'::jsonb, '["到菜市场购买半斤瘦肉(250g),要全瘦肉，不要带肥，最好是猪腿肉或里脊肉，以保证瘦肉丸的口感细腻而不柴。", "把瘦肉和葱姜末放入绞肉机，直到绞成肉泥为止。或者用菜刀刀背，擀面杖之类的慢慢敲成肉泥。", "把绞好的瘦肉放在一个盆子里，将高弹素，嫩肉粉，猪肉粉精，黄酒，味精，鸡精，食用碱，添加到肉里，用力揉搓10分钟，要用手掌揉，直到肉富有弹性为止。", "倒入马铃薯淀粉，初步将肉与淀粉混合。", "将泡打粉，白砂糖，盐，放入之前称好的150g水中，用筷子搅拌，使之溶于水中。然后分两次倒入之前的肉中，用手揉搓或者用筷子朝同一个方向搅拌使淀粉完全和肉混合均匀，看上去只有肉色为止。", "按照自己的口味，将葱，芹菜，紫菜，虾皮，榨菜，盐，放入一个空碗中。", "把锅中的水烧开，水一定要是开的，这样煮出来的瘦肉丸的汤会是清的，不然，汤就会变得混浊。", "把肉用刀片之类的工具刮成一小长条一小长条地放入烧开了的水里，盖上锅盖，煮一两分钟。", "当看到锅中的瘦肉丸全都浮起来时，用勺子舀些汤放入已准备好的佐料碗里，烫下佐料。", "将煮熟的瘦肉丸捞起放入碗中，然后再放入胡椒粉，醋，香菜，香油，用一个小勺子搅拌一下。\n此时美味的瘦肉丸才算大功告成。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/0f40fbea24ff45aa813f3cb30b6573e6_470w_284h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级下饭鱼香肉丝（不辣版）', '肉类', '瘦肉', '辣', '[{"name": "肉丝", "amount": "250克"}, {"name": "黑木耳", "amount": "1把"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "青椒", "amount": "2个"}, {"name": "葱（大葱）姜蒜末", "amount": "适量"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "腌肉材料如下：", "amount": "适量"}, {"name": "小半勺（一点点）白胡椒粉", "amount": "适量"}, {"name": "料酒", "amount": "2勺"}, {"name": "淀粉", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "酱汁材料43221如下：", "amount": "适量"}, {"name": "香醋", "amount": "4勺"}, {"name": "白砂糖", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "清水", "amount": "2勺"}, {"name": "淀粉", "amount": "1勺"}, {"name": "以上“勺”是指家家都有的陶瓷汤勺", "amount": "适量"}]'::jsonb, '["说明：不知道“勺”是多大的小伙伴，特别为你们补了个图。想来家家都有，基本通用的陶瓷勺，才能成为量具吧。稍微相差一点也没有关系，试过就知道了。", "干木耳泡发。想快点可以用温水泡。\n瘦肉切丝，用腌肉材料抓匀，腌制20分钟。", "如果是大木耳要切成丝，小木耳就省了。\n胡萝卜、青椒切丝。", "葱姜蒜切末。（我喜欢姜末直接揉入生肉中，就是为了挑不出来，因为我和娃都有点体寒，吃姜对身体好。）\n调好酱汁，准备好豆瓣酱。", "不粘锅多下些油，肉丝倒入，快速划散，变白铲出备用，油留下。", "先下胡萝卜炒，再下豆瓣酱炒香。", "下葱蒜末，木耳青椒一起炒熟。", "下肉丝翻炒均匀。", "沿锅边倒入酱汁，大火快速炒匀收汁出锅。", "鲜香美味！拿饭来！"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/8459d9aa87384f08830d3bf084f49506_810w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('下饭神器-豆瓣酱蒸瘦肉', '肉类', '瘦肉', '', '[{"name": "瘦肉", "amount": "250克"}, {"name": "豆瓣酱", "amount": "2勺"}, {"name": "油", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "适量盐、鸡粉", "amount": "适量"}]'::jsonb, '["先准备好材料", "切好肉之后把以上配料腌20分钟", "蒸15分钟"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/b6b6b3ad39564065b031c83997ff07e8_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级下饭•鱼香肉丝', '肉类', '瘦肉', '', '[{"name": "猪肉（里脊肉）", "amount": "300g"}, {"name": "15朵木耳", "amount": "适量"}, {"name": "1小根胡萝卜", "amount": "适量"}, {"name": "1-2个（看大小）青椒", "amount": "适量"}, {"name": "大葱", "amount": "1根"}, {"name": "适量姜丝", "amount": "适量"}, {"name": "2瓣大蒜", "amount": "适量"}, {"name": "郫县豆瓣酱", "amount": "1大勺"}, {"name": "淀粉", "amount": "2勺"}, {"name": "香醋", "amount": "3勺"}, {"name": "白砂糖", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "（可不放）盐", "amount": "1小勺"}, {"name": "清水", "amount": "4勺"}]'::jsonb, '["腌肉：猪肉切丝，依次加入少许料酒、盐、胡椒粉、淀粉、植物油，抓匀腌制10分钟。", "备料：木耳提前泡软切小或切丝，胡萝卜、青椒切丝，姜、葱切丝，蒜切瓣，备用。", "调汁：调制鱼香汁是这道菜的关键，盐、生抽、醋、糖、淀粉、水的比例是，1：2：3：3：2：4。", "炒肉：锅内热油，倒入腌制的肉丝翻炒至变色后盛出，备用。", "炒料：锅内热油，倒入葱、姜、蒜炒香后，加入1勺豆瓣酱，翻炒出汁。", "炒菜：依次加入胡萝卜丝、木耳、青椒丝，炒至七成熟后，加入肉丝，翻炒片刻，倒入调好的鱼香汁，翻炒均匀。", "收汁：翻炒均匀、等待收汁，即可出锅。", "盛盘：即可食用。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/c3ffdb79ee6042a190052659c21a4ce3_1024w_807h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧肉炖土豆～肥肉不腻，瘦肉不柴的下饭神器', '肉类', '瘦肉', '', '[{"name": "五花肉", "amount": "400克"}, {"name": "(个头很小)土豆", "amount": "4个"}, {"name": "(大概七八块)冰糖", "amount": "15克"}, {"name": "1-2勺酱油", "amount": "适量"}, {"name": "1-2勺料酒", "amount": "适量"}, {"name": "半勺多盐", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "一小块桂皮", "amount": "适量"}, {"name": "适量葱姜", "amount": "适量"}]'::jsonb, '["肉切块，两三厘米宽就行，别太小。\n\n肉炖炖会缩一点。我用的五花和后臀尖，掺着来的。家里有人一口肥肉都不吃，只吃瘦的..", "大葱切段，姜切片。备好八角，冰糖，桂皮。", "锅烧热，倒少许油，五六成热放五花肉，小火慢煸，把五花肉的肥油煸出来。\n\n瘦肉多的话可以适当增加一点油量～", "煸差不多了，把肉推倒锅的一边，放冰糖，小火慢炒。\n\n糖，炒不完全化掉没事，不影响后面步骤，炒太久怕苦了。(冰糖边炒边敲碎，敲不碎也没事)", "炒差不多了，放八角，桂皮，葱姜，炒匀。再放料酒和酱油，炒匀。", "加热水没过五花肉，大火烧开转小火慢炖四十分钟到一小时。", "炖的时候切土豆，切多大块，去不去皮都随意～但别太小喽，怕炖碎就只剩沫沫了😂", "肉差不多了放土豆，放盐。这时候要是水不多了可以再加点热水。", "十五分钟土豆差不多好了，尝下咸淡，不咸再加点盐。有同学提问‘‘那咸了呢？’’.....也有办法😂把汤倒出去些，再加点热水！\n\n大火收汁。喜欢拌饭的话汤汁多留点～", "成品上桌！饿死了！一盘子直接被吃光！\nヾ(@^▽^@)ノ"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/9e59d63c82b44114b7b8985dbf60dcb3_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('糖醋里脊-糖醋汁版', '肉类', '里脊', '', '[{"name": "猪里脊", "amount": "300克"}, {"name": "1丢丢白胡椒粉", "amount": "适量"}, {"name": "1丢丢椒盐粉", "amount": "适量"}, {"name": "1丢丢洋葱粉", "amount": "适量"}, {"name": "1丢丢生姜粉", "amount": "适量"}, {"name": "1丢丢糖", "amount": "适量"}, {"name": "盐", "amount": "1小勺"}, {"name": "1汤勺啤酒", "amount": "适量"}, {"name": "1汤勺油", "amount": "适量"}, {"name": "面粉", "amount": "50克"}, {"name": "红薯淀粉", "amount": "50克"}, {"name": "泡打粉", "amount": "1克"}, {"name": "一汤勺油", "amount": "适量"}, {"name": "100-110克水", "amount": "适量"}, {"name": "3汤勺糖", "amount": "适量"}, {"name": "1.5汤勺香醋", "amount": "适量"}, {"name": "半汤勺柠檬汁", "amount": "适量"}, {"name": "1汤勺李锦记红烧汁", "amount": "适量"}, {"name": "半汤勺红薯淀粉", "amount": "适量"}, {"name": "少许油", "amount": "适量"}]'::jsonb, '["里脊肉去掉外面的筋膜.\n切成厚一些的片.\n再切成条.\n\n不建议切太粗了的.\n成品会很大块.\n\n切细一点比较好入味.\n然后....\n主要是份量也显多呀.(˶‾᷄ ⁻̫ ‾᷅˵)", "放入：\n白胡椒粉.生姜粉.洋葱粉.盐.糖.\n搅拌均匀放一会儿.\n然后放啤酒搅拌至完全吸收后.\n再放10分钟以上..\n\n没有生姜粉.洋葱粉的.\n可以把新鲜的剁成茸挤汁用..\n\n啤酒最好不要换其它酒.\n如果介意的.\n可以放凉水.\n\n成品是无酒味的..)^o^(", "面粉和红薯粉.泡打粉混合均匀.\n\n红薯粉一般在超市都能买到.\n和淀粉.盐.鸡精这些做邻居.\n\n如果实在没有的.\n就用玉米淀粉吧.吧.吧...！\n\n面粉如果有低筋粉的.\n可以用低筋的.\n没有就用普通的面粉就好.\n\n（真够随便的..ಠ_ಠ...）", "慢慢加水.\n一直到如图状态..\n\n大概100-110克左右..", "把肉放下去搅拌均匀.", "再放一汤勺食用油下去搅拌均匀.", "小锅里面放油..\n最好是口径小一些的.\n深一些的..！\n\n油热至6成.\n大概就是筷子放下去能冒泡的那种.\n\n小火.\n把肉一条条放下去.\n不要动.\n炸一会后一般会自动浮起来.\n如果不浮.（锅不好.ಠ_ಠ ）\n那就炸一会再拨动..", "炸至微黄后捞出..\n\n把所有的都炸好后.\n放一旁备用.", "把酱汁材料里的香醋.糖.红烧汁.柠檬汁.\n再加二汤勺左右的水.\n（多点少点无所谓.）\n混合均匀备用...", "再次把油烧热.\n中大火.\n把炸好的里脊肉放下去炸一遍.\n可以分几次炸..", "炸至如图金黄色捞出.\n大概也就10多秒的时间.\n动作要快.姿势要帅.\n很容易就炸过头的.\n\n這时候吃都非常的爽...！( ´▽｀)", "另用一个锅.\n倒入混合好的酱汁.\n小火加热至酱汁浓稠一些.", "把淀粉放入碗中.\n加小半碗水混合均匀.\n倒入锅中..\n\n用锅铲一直铲动混合均匀..！\n变成透明.浓稠的酱汁后关火.\n放少许炸里脊肉的食用油下去搅拌均匀.\n成品会比较通透发亮.\n不想放的也可以不放哈.！", "装入小碗中.\n撒上一些熟白芝麻..\n\n娃可以就光吃這酱汁.\n吃一碗饭下去.\n是不是傻...╮(￣▽￣\"\")╭", "吃的时候.\n蘸着酱汁吃就好.\n這样可以避免放久了..\n里脊肉会变软的问题..\n\n强烈推荐這种吃法..", "当然.\n伱要不接受推荐的话.\n也可以在步骤13的时候.\n把里脊放下去迅速翻炒均匀.\n装盘撒白芝麻呀.."]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/6f29fef678d84a99a1c8d4750d1803f6_1578w_1182h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('网红里脊肉', '肉类', '里脊', '', '[{"name": "猪里脊", "amount": "300克"}, {"name": "小汤勺1勺盐", "amount": "适量"}, {"name": "糖", "amount": "2勺"}, {"name": "1/3勺鸡精", "amount": "适量"}, {"name": "少许白胡椒粉", "amount": "适量"}, {"name": "适量孜然粉", "amount": "适量"}, {"name": "适量（加不加，可根据自己所需）辣椒粉", "amount": "适量"}, {"name": "适量（加不加，可根据自己所需）椒盐", "amount": "适量"}, {"name": "食用油", "amount": "适量"}]'::jsonb, '["将里脊肉洗净，我买的是肉心更嫩，做起来更好吃。", "肉切薄大片，别切太厚,薄薄的就行，稍拍松一下。", "肉放入碗中，加入2勺糖。", "1勺盐。", "1/3勺的鸡精。", "少量的白胡椒粉。", "我是用这种小汤勺量的，中餐调料用的量没固定，可根据买的量和自家的口味下调料，因为有的人吃得比较淡，有的吃得比较咸，众口难调，我的仅供参考。", "加少许食用油抓匀，也可加少许料酒,但我没加，一样好吃不膻。有时料酒下多了反而破坏肉原有的香味。", "手沾水弄少许水在肉片上反复3次把肉抓匀至起粘稠感。", "取少许的地瓜粉加水调成稠糊状抓勻，只要薄薄一层就行了，不用太多。商家大多数都会加嫩肉粉，自己吃就不需要，若你喜欢也可以加就是了😂", "用油炸建议用这种深的小锅或奶锅，省油，还自带个网勺，很好用。", "油炸到肉变白，即可捞起，若炸到肉变黄，就老了，不好吃。", "捞出沥油。", "再把肉装入盘中，撒上孜然粉、辣椒粉、椒盐等，看你喜欢什么加什么。忘了加点沙茶粉，加入味更赞。若没有不加也行，味道一样好吃😋。", "自己在家整盘吃比用竹签串起来吃更过瘾、不串竹签炸的时候更方便，若你喜欢用竹签的话也Ok，客人来了摆盘会好看些。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/3bacfcd8662942ba98fe2edf475afc76_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱爆小里脊（鲜嫩多汁）', '肉类', '里脊', '', '[{"name": "（500g）猪小里脊", "amount": "1条"}, {"name": "1小撮白胡椒粉", "amount": "适量"}, {"name": "1/2小匙盐", "amount": "适量"}, {"name": "鸡蛋清", "amount": "1个"}, {"name": "2大匙生抽", "amount": "适量"}, {"name": "1小匙生粉", "amount": "适量"}, {"name": "1大匙（没有也行）everything bagel（各种芝麻混合物）没有就用芝麻", "amount": "适量"}, {"name": "大葱", "amount": "1根"}]'::jsonb, '["小里脊一条，先把有筋膜的地方修掉。", "小里脊切片+白胡椒+盐+2大匙生抽+鸡蛋清抓匀，放置5分钟后加1大匙生粉+2大匙水拌匀，再加1大匙油拌匀备用，一根大葱葱白切丝备用", "热锅加1大匙油，150度左右就可以放肉下去划开，由于我家是电磁炉，火力不太猛，要炒2分钟才能肉呈白色，此时下大葱翻炒1-2分钟，下1大匙everything bagel，没有就撒白芝麻，然后盐调味就可以装盘了", "口味鲜、嫩，但不是重口味哦，喜欢辣口的请忽略", "临时组局和朋友吃个便饭，有了这道葱爆小里脊顿时提高了便饭档次"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/64b7a3f8feed4fa79507fd024f4b01ed_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常做法糖醋里脊百吃不厌~', '肉类', '里脊', '', '[{"name": "醋", "amount": "1勺"}, {"name": "猪里脊", "amount": "300克"}, {"name": "糖", "amount": "1勺"}, {"name": "番茄酱", "amount": "3勺"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "适量淀粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "半勺生抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "半勺蚝油", "amount": "适量"}]'::jsonb, '["腌肉：将猪里脊肉先切厚片，用刀背拍一拍，把肉拍松一点。切成一个手指头粗的条，加料酒，生抽，蚝油，一点点盐，白胡椒粉，一个鸡蛋（或蛋清），将肉用手抓匀，腌制20分钟以上。", "调酱：3勺番茄酱+1勺白醋+1勺白糖++一勺淀粉+半碗（饭碗）清水，搅拌至糖融化，放在一边备用。", "裹粉：一般老手是边裹粉边下锅油炸，新手建议先把粉全部裹好再来炸，这样在炸的时候就不会手忙脚乱。准备一个大碗，里面放干淀粉，玉米淀粉，红薯淀粉，土豆淀粉都可以。把每一根肉条都满满裹上干淀粉。", "炸制：油温160度左右下里脊，可以拿一个干筷子放在油里面试一下，周围冒小泡就可以下锅。炸到表面微黄可以捞出，全程中火。然后等几分钟，油温升高到200度左右，把里脊倒进去复炸一次，只需40秒，表皮就会很脆，马上捞出。", "裹酱：另外拿一个锅，锅里放一点点底油，把调好的酱汁倒进去，煮到冒大泡，把炸好的里脊放进去，翻炒，让每一根都裹上酱汁。", "出品：出锅啦！撒上万能装饰：黑芝麻+葱花（如果有白芝麻更好）。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/35a8bcd0f0dd4a48a36e23e0f9d9f4b3_912w_684h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牙签肉（里脊肉版）', '肉类', '里脊', '', '[{"name": "一条里脊", "amount": "适量"}, {"name": "适量料酒、生粉", "amount": "适量"}, {"name": "适量糖、盐、醋、姜", "amount": "适量"}, {"name": "适量辣椒粉、胡椒粉", "amount": "适量"}, {"name": "适量花椒粉、生抽", "amount": "适量"}, {"name": "适量蚝油、孜然粉", "amount": "适量"}, {"name": "调味料不齐也没事的", "amount": "适量"}]'::jsonb, '["一条里脊肉洗净，切成小块！", "准备好所有调料，每种放适量。", "放入调味料，搅拌均匀！", "盖保鲜膜腌制2⃣️小时，我一般放冰箱冷藏腌制一晚，这样更入味！", "准备油炸之前，用牙签串上！这一步牙签不能少，这就是传说中的灵魂！当然，没有牙签直接油炸，也不影响口感！", "油多放一些，加热到微微冒烟（可以先盖上锅盖），下油锅炸至如图的颜色，捞出沥油，装盘，撒上一把（熟）白芝麻！像样！颜值与美味共存！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/885b2a1139fa4ed9a3d3dc476cdd1e8c_3072w_4096h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('嫩炒猪肝', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "200克"}, {"name": "淀粉", "amount": "2勺"}, {"name": "料酒", "amount": "2勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量糖", "amount": "适量"}, {"name": "姜", "amount": "5片"}, {"name": "3瓣蒜头", "amount": "适量"}, {"name": "四分之一个青椒", "amount": "适量"}, {"name": "四分之一个红椒", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "青蒜叶", "amount": "1根"}]'::jsonb, '["猪肝买来在水中泡半小时", "剪去白色筋，切成薄片(一定要薄一点)。", "将切好的猪肝放碗里，加一勺盐(平时炒菜的两倍量)、少许糖、2勺(小汤勺)料酒、2勺(小汤勺)淀粉，生姜3片、蒜头1瓣", "用手捏一下，腌制15分钟", "准备一锅水，烧开，水要多点，完全没过猪肝", "放入腌好的猪肝，只要等猪肝变粉红色时(不要变全白，全白就老了)立刻捞出冲洗干净(焯水时间一定要短，放入猪肝翻拌一下就可关火，不用等水开了)。", "将焯好水的猪肝沥干水份(图片上的猪肝有点焯过头了)", "准备半个洋葱，四分之一个青椒，四分之一个红椒", "锅内放油，油温7成热时放洋葱炒出香味", "接着放青椒红椒，煸炒至断生", "倒入沥干水的猪肝，加一勺生抽，几滴老抽(几滴就行，倒多了会发黑)，少许白糖，少许料酒，2个干辣椒，一根青蒜苗，翻炒均匀(翻炒动作必须快，不然容易炒老)，淋一点水淀粉，关火"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/c251bf922b0311e7bc9d0242ac110002_1944w_2576h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鲜嫩的猪肝汤', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "50克"}, {"name": "两颗菠菜", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "若干姜丝", "amount": "适量"}, {"name": "干淀粉", "amount": "1勺"}, {"name": "若干勺白胡椒粉", "amount": "适量"}, {"name": "盐", "amount": "2克"}, {"name": "若干香油", "amount": "适量"}]'::jsonb, '["把猪肝尽量切薄，练刀工啊！这是嫩滑的关键。鲜姜切细丝，菠菜洗净切两段。", "反复清洗，然后泡十五分钟", "攥干水份，放盐、白胡椒粉、料酒，调匀，再放干淀粉调匀。腌15分钟入味。", "把菠菜和猪肝分别焯水，去掉菠菜的草酸、猪肝的腥味。", "再次坐锅，放入适量清水、姜丝。\n做汤的时候放些姜丝提味，就不用放鸡精了。\n水开后放猪肝，转小火，是鲜嫩的关键。\n猪肝尽管焯过水，此时还会出沫子，用汤勺撇掉。煮一分钟左右，看猪肝颜色转白就熟了。", "放入焯过的菠菜，点几滴香油，OK！\n腌猪肝的时候盐一次加足了，出锅时可不再放盐。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/067d88cdd9f64b5d860b25f92c291430_1304w_1002h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“小炒猪肝”的家常做法，味道干香很赞，先收藏起来', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "350克"}, {"name": "几颗大蒜", "amount": "适量"}, {"name": "约15克生姜", "amount": "适量"}, {"name": "小米辣", "amount": "30克"}, {"name": "大红椒", "amount": "1个"}, {"name": "蒜苗", "amount": "3根"}, {"name": "适量植物油", "amount": "适量"}, {"name": "小半勺食用盐", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "少许白糖", "amount": "适量"}, {"name": "蚝油", "amount": "5克"}, {"name": "生抽酱油", "amount": "2克"}]'::jsonb, '["首先我们准备新鲜的猪肝350克\n加入清水清洗干净之后备用\n此做法属于干香类菜需要提前清洗", "清洗干净之后将猪肝切成3毫米左右的厚片\n同学们可以适当的切厚一些这样更方便新手操作", "猪肝切好之后下一步开始腌制\n碗中加入食用盐1小半勺（约", "5克）\n加入胡椒粉", "5克\n加入老抽3克调底色\n调好味之后抓拌均匀备用", "最后加入少许的食用油搅拌均匀\n这一步的目的是防止猪肝下锅黏成一团", "下一步开始准备辅料\n准备大蒜几颗切成小粒备用（约30克）", "准备生姜1小块切成小粒备用（约15克）", "准备小米辣30克切碎备用\n不能吃辣的同学可以不加", "准备大红椒1个切成小颗粒备用", "准备蒜苗3根轻轻拍散之后切碎备用", "下一步开始制作\n首先我们把锅烧热\n锅烧热之后加入适量的油滑锅\n滑好锅之后将热油倒出\n然后加入适量的冷油", "再将腌制好的猪肝下锅滑10秒钟\n这一步的目的是将猪肝炒至定型（此时约5成熟）", "然后将切好的姜蒜粒和辣椒粒下锅翻炒30秒\n这一步的目的是将料头炒香\n同学们家庭小灶则需要2分钟左右", "翻炒30秒钟之后开始调味\n锅中加入胡椒粉", "5克\n加入少许白糖提鲜\n加入蚝油5克\n加入生抽酱油2克\n最后加入老抽2克翻炒几下", "翻炒均匀之后再加入切好的蒜苗粒\n开中小火翻炒至断生即可出锅装盘", "一道干香下饭的小炒猪肝就制作完成"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/b8e30b7580b741c297305d2c746b067e_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒猪肝家庭做法', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "1块"}, {"name": "胡萝卜", "amount": "1段"}, {"name": "尖椒", "amount": "1个"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "（不喜欢可以少放）姜", "amount": "7片"}, {"name": "淀粉", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺陈醋", "amount": "适量"}, {"name": "糖", "amount": "1小勺"}, {"name": "盐", "amount": "1小勺"}, {"name": "适量食用油", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}]'::jsonb, '["猪肝浸泡一小时，洗净切片。（可以放姜片浸泡去腥）", "放淀粉料酒腌制一会。", "胡萝卜、洋葱、尖椒、姜切片。", "调酱汁：生抽一勺，老抽半勺，蚝油一勺，陈醋半勺，盐、糖比例1:1用筷子搅匀。", "锅里水开倒入猪肝煮至变色立刻捞出。", "捞出备用。", "锅里油热炒香姜片。", "倒入洋葱翻炒。", "倒入胡萝卜、尖椒炒一会。", "倒入调好的酱汁翻炒匀。", "倒入猪肝大火翻炒均匀。", "装盘即可，非常好吃呦。"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/8021d6bc119b40519b1a728ef5cc8ba2_2160w_2880h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('洋葱爆炒猪肝（简单易学，色香味俱全）', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "200克"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "姜丝", "amount": "1片"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "淀粉", "amount": "1小勺"}, {"name": "少许料酒", "amount": "适量"}, {"name": "少许老抽", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "少许糖", "amount": "适量"}, {"name": "少许耗油", "amount": "适量"}, {"name": "几滴香油", "amount": "适量"}]'::jsonb, '["新鲜猪肝切片，刀工很重要，可以让卖家切好，清水浸泡1小时，冲洗干净，用少许料酒，姜丝，淀粉腌制20分钟（腌制时间越长越好，猪肝一点腥味都没有），我一般是头一天加料酒，姜丝腌制，放冰箱，第二天炒", "洋葱切成小块备用", "关于刀工的问题，我要交代下，因为看见厨友们的刀工，实在是不敢恭维😂😂，1、洋葱切一半，倒扣，横一刀，竖三刀搞定，2、辣椒也是先切段，再对半切开，刀工影响口感跟视觉，😇😇，3、猪肝最好找商家切好，如果自己切，一定要薄片哈", "青椒，红椒，蒜片，姜丝切好备用", "5勺，，少许老抽，几滴香醋，少许耗油，少许糖，调成汁", "锅中热油，油稍微多些，倒入猪肝快速爆炒6成熟，盛出备用", "另起锅，少许油，姜蒜小火炒香", "倒入洋葱，中火翻炒10秒", "倒入青红椒，中火炒10秒", "倒入猪肝，翻炒均匀", "盖上锅盖，大火", "5分钟左右", "倒入淀粉水（15 克水），大火翻炒三十秒，淋几滴香油", "出锅装盘", "甜甜的洋葱+嫩嫩的猪肝，配上青红椒，，是不是更有食欲"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/ba87356b31f643bd94d2116916e9d151_2731w_2185h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('煎猪扒', '肉类', '猪排', '', '[{"name": "以下调味以200克的肉为基础猪扒（厚薄随个人喜好，厚一点没有那么容易煎干）", "amount": "适量"}, {"name": "生粉（玉米淀粉、凌粉等都可以）", "amount": "1茶匙"}, {"name": "糖", "amount": "1茶匙"}, {"name": "酱油", "amount": "2茶匙"}, {"name": "水", "amount": "2茶匙"}, {"name": "油（腌猪扒）", "amount": "1茶匙"}, {"name": "适量油（煎猪扒）", "amount": "适量"}]'::jsonb, '["能够买到如图略带雪花的大排是最好的，但不要奢望雪花会像肥牛一样，那只是幻想。所以曾经有留言说我胡说八道。", "猪扒先拍松。用菜刀背剁或用特别剁肉的榔头都可以。", "调腌肉的酱汁。生粉、糖、酱油加水调匀。把猪扒放入。再放油。腌最少半小时。酱汁可以盖过猪扒。这样猪扒更入味，而且很湿润。", "猪扒放入大火烧热的锅里煎。", "煎好有一点焦的效果最好", "可以变成甜酸番茄洋葱猪扒", "这是台式炸猪扒和鸡扒。另外有食谱。https://www.xiachufang.com/recipe/102925298/", "非油炸日式吉列厚切猪扒。另外有食谱。https://www.xiachufang.com/recipe/102292577/", "不用醬油，改用鱼露。风味不同。", "洋蔥黑椒汁豬扒"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/8dc6ae1c88a711e6a9a10242ac110002_1920w_1920h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香煎猪排', '肉类', '猪排', '', '[{"name": "猪大排", "amount": "8块"}, {"name": "适量小香葱、老姜", "amount": "适量"}, {"name": "半料酒", "amount": "1勺"}, {"name": "盐", "amount": "2克"}, {"name": "咖哩粉", "amount": "10克"}, {"name": "生抽", "amount": "10克"}, {"name": "生粉", "amount": "50克"}, {"name": "黑胡椒粉", "amount": "2克"}, {"name": "花椒", "amount": "2克"}, {"name": "鸡蛋", "amount": "1只"}]'::jsonb, '["猪排拍松洗净沥干水份待用", "香葱切小段，老姜切片", "用乐扣乐扣的料理盒加入料酒，生抽，盐，香葱段，老姜片，生粉，咖喱粉，鸡蛋然后一股脑拌匀", "将大排两面都蘸上料腌制2小时以上，冰箱隔夜更入味", "平㡳煎锅加适量油，等油温70度左右就可以下锅煎了，两面煎至微黄就行了"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/1ced18d288cc11e6a9a10242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级简单-改良简易炸猪排', '肉类', '猪排', '辣', '[{"name": "猪瘦肉（里脊肉）", "amount": "适量"}, {"name": "鸡蛋", "amount": "适量"}, {"name": "面粉", "amount": "适量"}, {"name": "面包糠", "amount": "适量"}, {"name": "辣椒面（自选）", "amount": "适量"}, {"name": "黑胡椒", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "酱油", "amount": "适量"}]'::jsonb, '["先把猪肉切成1厘米左右的薄片，用刀背敲断经络（十字纹的方法敲）。", "把敲好的猪肉用黑胡椒、盐、料酒、酱油腌制10分钟以上", "鸡蛋和面粉放在一个碗中调成面糊，小美忘记量他们的比例了。面糊要稍微粘稠一点，这样好裹在猪排上，把腌制好的猪排放入面糊中。", "准备一个大的容器，里面倒入面包糠，把猪排从面糊中取出放在面包糠上，用手轻轻的压猪排，使面包糠完全覆盖在猪排上。", "热锅多油（要保证猪排能完全浸在油里，PS：小美为了节约，所以油放得少了点），油温升高以后放入猪排，然后转中火，直到炸熟为止，一面炸成型了，需要翻面哦。", "小编的个人公众号，上面很多菜谱，每天也都会更新最新的菜谱，搜索公众号“meishi0123”或者扫这个二维码添加。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/af911bfc891711e6b87c0242ac110003_1000w_663h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('中式猪扒', '肉类', '猪排', '辣', '[{"name": "带骨猪里脊", "amount": "3块"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "一汤匙半生抽", "amount": "适量"}, {"name": "一汤匙米酒", "amount": "适量"}, {"name": "适量白胡椒", "amount": "适量"}, {"name": "一汤匙蚝油", "amount": "适量"}, {"name": "半汤匙玉米淀粉", "amount": "适量"}, {"name": "适量普通面粉", "amount": "适量"}, {"name": "适量面包糠", "amount": "适量"}]'::jsonb, '["猪里脊切成一指厚的猪排", "猪排用刀背把肉打松。用松肉锤当然很好，但是有时候做传统菜，就是喜欢一把菜刀搞定一切~~", "料理碗中依次加入一个鸡蛋、适量的白胡椒", "一勺半的生抽", "一勺米酒", "一勺蚝油", "适量的玉米淀粉", "调料和猪大排用手揉匀，", "腌制半小时左右", "腌制好的猪排先拍一层面粉（普通面粉，低筋面粉都可以）", "再裹一层蛋液（食谱原料里的第二只鸡蛋）", "最后拍上面包糠。这时候，要用力把面包糠按进肉里（如果买来的面包糠是粗粒的，请先装入保鲜袋用擀面杖碾碎些）", "起油锅，锅中倒入足量的油，加热到八成热。（检验的办法是：撒一点面包糠或者面粉进油锅，瞬间浮起并散开，表示油温合适了。）这时候转中火，放入猪排，两面炸至金黄就可出锅。（猪排熟得很快，不用炸很久的。我一般翻面只翻一次的。但油炸东西是个技术活，还是要自己练着找感觉的）", "出锅以后用吸油纸吸掉表面的油。可以直接一人块抓着啃，斯文点的话，切成细条，供客人食用。一定记得配上一碟辣酱油！", "感谢支持本次「厨Studio」课程的小伙伴们\n场地提供方：欧美佳电\n生鲜食材提供方：易果生鲜\n餐厨用品提供方：优集品"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/9901cd708a0011e6b87c0242ac110003_2592w_1728h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常快手菜 日式炸猪排（自调酱汁）', '肉类', '猪排', '辣', '[{"name": "四块猪排", "amount": "适量"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "或60克淀粉", "amount": "3大勺"}, {"name": "80-100克面包糠", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "料酒", "amount": "1小勺"}, {"name": "适量色拉油（炸猪排用）", "amount": "适量"}]'::jsonb, '["猪排用刀背一刀刀地轻轻敲打松弛。", "敲打松弛后的猪排逐个用手抹上盐和白胡椒粉，放一点点料酒，入味30分钟后，准备2个鸡蛋（打散）、3大勺淀粉、80-100克左右面包糠。这几个盘子建议都用敞口大的，后面好操作。", "猪排两面首先裹一层薄薄的淀粉。", "然后从蛋液里过一下。", "最后在面包糠里打个滚。", "好了，乖乖在油布或油纸上等着被炸吧😓", "将适量的色拉油用中大火烧热到160度左右。筷子插进去有小泡泡从筷子底部慢慢往上升就差不多了。或者丢一点面包糠进去，面包糠马上浮起来也表示油温差不多了。                                            （***油温不宜过高，不然猪排放进去马上就颜色很深了，容易导致表面已炸老里面还没熟）", "油温差不多以后，马上将火转为中小火，放入猪排，一边观察颜色一边两面翻翻，炸至金黄色捞出，大概炸2，3分钟左右吧。", "猪排捞出来放在油纸上晾一会儿。诱人😍", "配的酱汁来了！下厨房厨友那里学来的配方：生抽3小勺白糖3小勺番茄酱2小勺蚝油2小勺水1小勺，拌匀即可！", "切片摆盘～", "淋上自己调的酱汁，看着不错😋"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/a5090ec1759e4fbab3b22e1ff478256a_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('四神猪肚汤', '肉类', '猪肚', '', '[{"name": "一只猪肚", "amount": "适量"}, {"name": "山药", "amount": "200克"}, {"name": "茯苓", "amount": "20克"}, {"name": "莲子", "amount": "30克"}, {"name": "芡实", "amount": "20克"}, {"name": "少许生姜", "amount": "适量"}]'::jsonb, '["准备这些食材洗净备用", "猪肚用盐醋搓洗干净", "猪肚放入砂锅，加姜片和料酒，煮5分钟至猪肚缩成一团后捞出", "猪肚切片后将所有的食材：山药茯苓芡实莲子猪肚一起倒入沙锅，煮1小时左右，用高压锅压20分钟也可以，最后加盐", "煮好咯，这是最佳养胃食疗方，一周吃两三次可以调理胃炎胃溃疡、太瘦想增肥也可以常吃"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6ef6cf9289c111e6b87c0242ac110003_2048w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('张姐-白切猪肚', '肉类', '猪肚', '', '[{"name": "猪肚", "amount": "1只"}, {"name": "一大块生姜", "amount": "适量"}, {"name": "小米辣", "amount": "1只"}, {"name": "1瓣蒜头", "amount": "适量"}, {"name": "小葱", "amount": "2根"}, {"name": "适量黄酒", "amount": "适量"}, {"name": "少许麻油", "amount": "适量"}, {"name": "适量海鲜酱油（或蒸鱼豉油）", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "少许白胡椒粉", "amount": "适量"}, {"name": "", "amount": "适量"}]'::jsonb, '["锅里放水先把猪肚焯水后捞出，小图中间有一层白色的用刨子刨去，再次冲水清洗干净备用。", "锅里放水放入猪肚，加入小量黄酒，切片的生姜，切段的葱白，盖盖子大火煮开后改小火焖，煮80分钟左右捞出，中间翻几次身，可根据自己的喜好调整时间，晾凉后切片装盘，\n蘸酱碟放入海鲜酱油百分之三十（或蒸鱼豉油），海天特级生抽百分之七十，葱末、切丁的小米辣、蒜末、小磨香油，胡椒粉，一盘香喷喷的白切猪肚就做好了，很简单吧。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/d3982a008b9111e6a9a10242ac110002_1080w_1097h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最牛的处理猪肚方法', '肉类', '猪肚', '', '[{"name": "猪肚", "amount": "适量"}, {"name": "适量面粉", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}]'::jsonb, '["先倒料酒搓洗一遍，把洗下的脏东西倒掉", "不要用清水冲洗，直接倒入面粉，慢慢搓揉", "很干净了吧？猪肚上的粘液全部被面粉粘下来后用清水冲洗干净", "锅内加水和料煮开，把一个盘子塞到猪肚里面，如果口太大用牙签连接，把用盘子撑着的猪肚放锅里过水", "取下盘子猪肚一点也没有回缩", "再来一张，真的不回缩"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/013962c4e3ff11e6bc9d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('养胃山药猪肚汤、猪肚鸡汤（含猪肚清洗方法）', '肉类', '猪肚', '', '[{"name": "猪肚", "amount": "1个"}, {"name": "15粒白胡椒粒", "amount": "适量"}, {"name": "姜", "amount": "1块"}, {"name": "铁棍山药", "amount": "1根"}, {"name": "10粒枸杞", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["猪肚汤要味道正跟肥肠一样，功夫关键要用在洗上面，洗的方法跟洗猪大肠一样， 买来的猪肚内面在外，猪肚放入盆里用清火冲洗掉表面污物，加入面粉（不放水）搓洗猪肚，各种抓，揉，捏，搓，抓久一点然后放清水继续搓洗，把面粉洗干净后，再放盐（不放水）继续搓洗，洗15-20分钟左右冲水洗净，接着放入醋重复前面的动作（抓，揉，捏，搓洗），搓洗15-20分钟左右冲水洗净，再放入料酒（不放水）继续搓洗15-20分钟左右冲水洗净，再切姜丝放进去搓洗15-20分钟左右，清水洗净，一直洗到猪肚清爽无异味，水清澈见底就大功告成了。", "翻面用剪刀清理掉上面的肥油，再用料酒搓洗一遍。", "锅里放一勺料酒和几片生姜水烧开放入猪肚煮两三分钟", "焯水可以这样套个大盘子，这样做猪肚不会缩小", "捞出沥干水，用小刀刮掉如图部位的白膜", "这是刮洗干净后的样子", "清水洗一遍", "如果是煲猪肚鸡，可以如图剪开，将焯过水洗净的鸡肉塞入猪肚用线捆绑好再煲汤", "我是煲山药猪肚汤，所以直接切条", "一个也要洗那么久，几个也是洗，所以我一次性买了三个，将处理干净的猪肚全部切条，平均分成6份，保鲜袋分装入冰箱冷冻，什么时候想煲汤直接取一份就行", "猪肚一份，生姜一块用刀拍碎，再加入胡椒粒，清水半锅，大火烧开", "铁棍山药一根洗净", "刮去外皮切段", "将山药下入砂锅大火烧开", "改小火煲2个小时以上，直到肚条软烂，加入枸杞和盐再煮10分钟左右即可盛出洒上葱花开喝", "一次有葱花没枸杞，味道真的很鲜", "一次有枸杞没葱花", "好鲜好鲜的汤"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/fdf19240491b4468b2f09c5ac82913cd_1836w_3264h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('〈胡椒猪肚鸡汤〉，我超级喜欢的味道，欣小厨', '肉类', '猪肚', '', '[{"name": "猪肚", "amount": "1个"}, {"name": "鸡腿", "amount": "1只"}, {"name": "姜片", "amount": "3片"}, {"name": "看自己口味白胡椒粒", "amount": "适量"}, {"name": "一小把枸杞", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一点点味精", "amount": "适量"}, {"name": "半斤牛奶（不放也行）", "amount": "适量"}]'::jsonb, '["新鲜猪肚，买回来，洗干净，然后用盐搓一遍，洗净，用醋搓一遍，洗净，用淀粉搓一遍，洗净。之后，在锅里煮", "3分钟捞出。", "猪肚切条。", "鸡腿切块。", "放入热水，煮", "3分钟。", "清水，放入猪肚，姜片，白胡椒粒。炖1-2小时，把猪肚炖到能咬动，也可以用高压锅压。高压锅5-7分钟就可以。", "我买的白胡椒粒，捣碎的。", "把煮好的猪肚和汤倒入砂锅，然后放入煮好的鸡腿，加入白胡椒碎。", "倒入一瓶牛奶，（牛奶可加可不加）加盐，鸡精。炖10分钟左右。", "小火炖，炖的时候尝尝味道，缺什么加点。", "加入枸杞子，再炖5分钟左右。尝了一口，味道好极了。", "很入味。", "一锅都喝掉了。"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/6b1f8b0c45234a31821c1e5f97e2c522_810w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌猪皮', '肉类', '猪皮', '', '[{"name": "熟花生米", "amount": "10g"}, {"name": "猪皮", "amount": "250g"}, {"name": "一小勺花椒面", "amount": "适量"}, {"name": "一下把葱花", "amount": "适量"}, {"name": "3瓣大蒜", "amount": "适量"}, {"name": "二勺制过辣椒酱", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "少许醋，酱油，味精", "amount": "适量"}]'::jsonb, '["首先把买好的猪皮煮熟，要吃糯点的就煮30分钟，煮熟后捞起来放凉等下好切。", "把猪皮切成一条条的形状放在碗里备用", "用一个小碗把辣椒酱，花椒面，大蒜，醋，酱油，白糖，味精，花生米，盐，葱花调好后倒在切好的猪皮上吃的时候拌匀就可以了"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/416732e8885811e6a9a10242ac110002_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('辣炒猪皮（两吃）', '肉类', '猪皮', '辣', '[{"name": "处理好的猪皮", "amount": "300克"}, {"name": "干红辣椒", "amount": "5根"}, {"name": "青尖椒或青蒜", "amount": "1根"}, {"name": "适量多些大葱", "amount": "适量"}, {"name": "酱油", "amount": "2勺"}, {"name": "糖", "amount": "1勺"}, {"name": "料酒", "amount": "4勺"}, {"name": "醋", "amount": "0.5勺"}]'::jsonb, '["猪皮在放了料酒的开水里煮5分钟，然后捞出，把皮下白色的脂肪都刮干净，然后切丝重新下入新的一锅开水加料酒、姜片、盐和少许酱油，煮半个小时左右，水别放的太多。煮好后，猪皮捞出备用，可以留一点在汤里，冷却后就是肉皮冻了，放在冷藏室，吃时沾蒜醋汁很美味。（我一般一次做2斤左右的猪皮，一次处理好后，分成四袋左右冷冻起来）", "干红辣椒在热水里泡软，斜剪成丝，青尖椒切丝，葱丝切多些备用。", "先用几滴油将青尖椒丝煸炒几下断生后盛出备用，不要炒老炒软了。另起锅宽油煸香红辣椒丝和葱丝，然后倒入猪皮丝，4勺料酒、2勺酱油、1勺糖翻炒均匀，最后放入青椒丝，在热锅边滴几滴米醋，翻炒几下马上出锅。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/b139a1c088d311e6a9a10242ac110002_1080w_810h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('泡椒水晶猪皮', '肉类', '猪皮', '辣', '[{"name": "猪皮", "amount": "750g"}, {"name": "小米椒", "amount": "750g"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白醋", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "少量高度白酒", "amount": "适量"}, {"name": "少量白糖", "amount": "适量"}, {"name": "十几粒花椒", "amount": "适量"}, {"name": "适量姜片", "amount": "适量"}, {"name": "几段葱白", "amount": "适量"}, {"name": "适量干红辣椒", "amount": "适量"}, {"name": "桂皮", "amount": "1片"}, {"name": "八角", "amount": "1个"}]'::jsonb, '["左手戴上一次性胶皮手套，右手拿镊子开始拔猪毛！有技巧，猪皮要湿润一些，不然拔起来很费劲。如果有点干，拔毛前放冰箱冻起来再解冻就可以了。拔毛的时候拿出一块猪皮之后记得把袋子系上，猪皮直接暴露在空气中很容易变干的。买来的猪皮基本都用刀刮过，看起来干净，其实毛囊里残留了好多小毛茬。用手指把猪皮顶起来，逆着光就能找到毛茬了，用镊子夹住顺着猪毛生长方向很容易拔出来，你会看到肉皮里残留的猪毛也挺粗挺长的。", "刚拔出来的猪毛底部有油脂，顺手直接粘在左手戴的胶皮手套上，接着拔猪毛，差不多了，油脂也干了，直接对着垃圾桶用镊子一拨弄就全下去了，不用担心弄得到处都是。看，像不像手套长毛了？这都是肉皮里面残留的，镊子拔得最干净。火烧也只能烧掉表面的。", "烧一锅水，水开之后把猪皮过一下水，2分钟左右拿出，快速过一下凉水，用刀刮去残留的肥肉，手法和去猪皮一样用刀压住一拉就掉了。然后清洗干净，洗到水清亮干净无油脂漂浮即可。一定洗干净，这是水晶猪皮的关键所在。", "处理好的猪皮应该像这样，只有胶皮没有肥肉块。然后根据自己喜好切成小块或切丝都行。个人觉得切丝更容易入味儿～", "烧一锅水，放入猪皮，盐，白醋少许，料酒少许，姜片，葱白几段，花椒十几粒，八角一个（掰碎），桂皮一小块儿，干红辣椒随意，我的小米辣不是很辣所以加入红辣椒增添辣味儿。煮12分钟左右用筷子能扎穿就可以了，猪皮捞出迅速放进加了冰块儿的水里过水，这样比过自来水Q弹得多，还不会成胶冻。", "猪皮捞出放容器里，把小米椒和泡小米椒的水一起到进入，水要刚好没过猪皮，不够可添加凉白开，再加盐，高度白酒，糖，鸡精。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/fc5540d2897e11e6b87c0242ac110003_4160w_2336h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('卤猪皮', '肉类', '猪皮', '', '[{"name": "猪皮", "amount": "500克"}, {"name": "适量水", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["先解冻卤水。\n（卤水的制作，详见：http://www.xiachufang.com/recipe/101682233/）", "用刀把肉皮下的肥肉和油去掉，将肉皮上的残毛处理干净。", "捞起来后用清水洗干净。", "卤水烧开后，放入猪皮。", "加少许老抽、盐和水（水淹没猪皮即可），水开后转小火，煮30分钟。", "关火，捞出猪皮，切成自己喜欢的形状即可。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/55fc3e988a5511e6a9a10242ac110002_600w_600h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧猪皮', '肉类', '猪皮', '', '[{"name": "半斤猪皮", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "生抽", "amount": "3勺"}, {"name": "料酒", "amount": "2勺"}, {"name": "姜", "amount": "4片"}, {"name": "糖", "amount": "1勺"}]'::jsonb, '["猪皮去干净多余的肥肉和毛，凉水下锅煮至水开，5分钟后，捞出，并洗去污物。", "猪皮切成麻将块，锅中放油，放入姜片炒香后，将肉皮入锅并加入老抽，酱油，料酒，盐，糖炒至上色，加入开水，没过猪皮。", "水开后，放入电饭锅（蹄筋键）或高压锅上汽中火煮大约20分钟左右，（嫌麻烦的也可以在锅中煮至软烂），用筷子插入很轻松穿过。", "倒回锅中，开大火，煮到收下汁即可。（收汁可收可不收，为了好看可以多做一步）"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/7a9085b5eebc41e3bba9c63c1f6703a2_640w_359h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('非常简单又美味的大骨头汤', '肉类', '猪骨', '', '[{"name": "一斤半左右猪骨", "amount": "适量"}, {"name": "左右纯净水", "amount": "3升"}, {"name": "4～5片姜片", "amount": "适量"}, {"name": "4～5段大葱段(3厘米左右的)", "amount": "适量"}, {"name": "八角", "amount": "2个"}]'::jsonb, '["猪骨头买回来先飞水，煮出血水，冲洗干净", "把洗净的猪骨，水，葱，姜，八角一起放入高压锅里，大火上气后调小火压40～50分钟左右（由于你我使用的高压锅品牌不一样，时间可根据自家的功能而设定）。", "压好的骨头汤。把葱姜八角捞出来倒掉，如果直接做汤，可以换炒锅加热调味（也可以直接用高压锅加热调味），如果做菜备用，先放凉分装好冷冻保存。", "直接做汤：换个炒锅继续加热，加盐，胡椒粉，生抽少许(不喜欢有颜色可不加)，鸡精少许，香菜，香葱调味。关火后加几滴香油即可。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/8e193cb88a8211e6b87c0242ac110003_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('人生中学会煲的第一道汤—玉米胡萝卜马蹄煲猪骨', '肉类', '猪骨', '', '[{"name": "猪骨", "amount": "300克"}, {"name": "半根玉米", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "6～8个马蹄（荸荠）", "amount": "适量"}, {"name": "两片+一块姜", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["猪骨在水龙头下冲洗干净后，放入锅内，入清水，加两片姜，两勺料酒，大火烧开，撇去浮沫，再开盖滚多两、三分钟，关火捞出后用温水再次冲洗干净备用。", "洗净的猪骨置于砂煲内，加足量清水、一块拍松的生姜，一点点陈醋（以利于猪骨中的钙质溶解于汤内），大火开煲。", "同时准备其他食材，玉米撕去包衣切成小段（我一般切段后会再分两半），胡萝卜去皮后切滚刀块，马蹄洗净削皮切两半。", "砂煲中加入洗净切好的的玉米、胡萝卜、马蹄，大火烧开后转中小火煲", "5～2个小时，加少许盐，关火出锅。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6a89cdb406154ba2a424eacdde4142a2_1106w_1091h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('猪骨低脂蔬菜煲', '肉类', '猪骨', '', '[{"name": "家乐猪骨浓汤宝", "amount": "1块"}, {"name": "1小块嫩豆腐", "amount": "适量"}, {"name": "1小把白玉菇", "amount": "适量"}, {"name": "3朵香菇", "amount": "适量"}, {"name": "胡萝卜", "amount": "10片"}, {"name": "3朵西兰花", "amount": "适量"}, {"name": "1小把蟹味菇", "amount": "适量"}, {"name": "1小把玉米粒", "amount": "适量"}, {"name": "1盒魔芋结", "amount": "适量"}, {"name": "少许姜丝", "amount": "适量"}, {"name": "少许香葱", "amount": "适量"}]'::jsonb, '["准备好全部食材，这道菜的秘诀就是家乐猪骨口味浓汤宝了。", "将各种蔬菜洗净备用。", "在砂锅中放半锅水，水开后放入家乐猪骨口味浓汤宝搅拌均匀，浓浓的骨香扑面而来，勾人胃口。", "将家乐猪骨浓汤宝煮化，一锅浓郁又鲜香的汤底就制作完成啦。", "依次放入白玉菇、蟹味菇，接着放入其他自己喜欢的蔬菜。", "煮几分钟，鲜美的猪骨浓汤蔬菜煲就做好了！", "鲜掉眉毛，让我们围坐一起，享受低脂带来的健康生活！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/04b1687714b14ddda36efdea07d70db2_1050w_788h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('淮山玉米萝卜猪骨汤3月北鼎电磁炉食谱', '肉类', '猪骨', '', '[{"name": "猪筒骨", "amount": "600克"}, {"name": "淮山", "amount": "325克"}, {"name": "一根玉米", "amount": "适量"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["食材准备；", "猪骨洗净冷水下锅煮沸焯去血水，捞出用凉水冲几遍洗干净，沥干水备用；", "淮山、胡萝卜去皮切小块，玉米也切小块，淮山切好后可以用清水泡着以免氧化变色；", "锅里加入1600克清水，先加入猪骨和玉米；", "珐琅锅盖上盖子，电磁锅选择“排骨汤”功能，口感选择“适中口感”；", "煮到程序还剩下30分钟的时候再加入淮山和胡萝卜，继续煮到程序完成就可以了；", "最后加少许盐调味即可。", "营养又美味~"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/b3c6303c411f419e987cc80ebe878453_5472w_3648h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('五指毛桃茯苓薏米~猪骨祛湿汤', '肉类', '猪骨', '', '[{"name": "适量猪骨", "amount": "适量"}, {"name": "茯苓", "amount": "20克"}, {"name": "薏米", "amount": "50克"}, {"name": "五指毛桃", "amount": "50克"}, {"name": "陈皮", "amount": "1片"}, {"name": "少许盐", "amount": "适量"}, {"name": "2000毫升清水", "amount": "适量"}]'::jsonb, '["材料清洗干净，清水泡30分钟，再次洗干净就可以。", "猪骨焯水，也可以用鸡肉，焯水后洗干净。", "把洗好的材料都放在一起，加入清水，一次加够水。", "大约煮一个半小时，如果明火煮，煮开了，就改小火慢慢熬。", "煮好放少许盐，其它不用放。", "五指毛桃茯苓薏米猪骨汤"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/6bcdb712310649a190764b6f38b58b83_763w_1017h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('火爆肥肠', '肉类', '肥肠', '辣', '[{"name": "半斤肥肠一根", "amount": "适量"}, {"name": "少许青花椒", "amount": "适量"}, {"name": "四根青椒", "amount": "适量"}, {"name": "蒜瓣", "amount": "适量"}, {"name": "几片老姜", "amount": "适量"}, {"name": "大葱", "amount": "适量"}, {"name": "白酒", "amount": "适量"}, {"name": "适量糖", "amount": "适量"}, {"name": "酱油", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}, {"name": "孜然", "amount": "适量"}, {"name": "干辣椒", "amount": "适量"}]'::jsonb, '["锅中盛满清水，水中放入适量白酒和酱油和少许青花椒，将肥肠放入水中煮半个小时，直到用一根筷子可以戳穿肥肠为止。", "煮好的肥肠切成一圈一圈的小段，补充两个作料：孜然粉和干辣椒。", "锅中热油，放入青花椒、豆瓣酱、蒜片、姜片、大葱炒香。", "放入肥肠，大火爆炒直至肥肠呈金黄色，在爆炒的过程中放入少许白糖和酱油。", "调至小火，放入适量孜然粉和干辣椒继续翻炒 ，直至肥肠表皮有些许焦脆感，香味扑鼻。", "放入青椒段，再翻炒片刻即可。", "欢迎各位厨友扫码或在微信中查找关注苹果耗子的公众号：好吃至欢。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/1f73ccee87fb11e6b87c0242ac110003_431w_583h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧肥肠（超详细，零失败制作）', '肉类', '肥肠', '', '[{"name": "肥肠", "amount": "1500克"}, {"name": "适量盐，老姜，郫县豆瓣，生抽，三奈，八角，花椒粒", "amount": "适量"}, {"name": "适量味精，料酒，白糖，葱花，香菜", "amount": "适量"}, {"name": "适量面粉，泡黄豆，草果，醋", "amount": "适量"}]'::jsonb, '["把肥肠洗净，可能大家都觉得洗肥肠很麻烦，其实主要掌握了方法，就很容易了。\n1,把肥肠稍微用水冲一下 ，沥一下水，把500克左右面粉 全部撒在肥肠上。下一步就是使劲揉搓，五分钟后用水冲洗干净。\n2，用同样的方法，把另一面翻过来也这样洗，洗好后，撕掉多余的油。\n3，洗好后，再倒100克左右的醋揉搓几分钟。清洗干净就0K了。", "冷水下锅，把洗净的肥肠放进去，放点姜片，花椒，葱结和料酒去腥，水开后，再煮五分钟出锅冷却。", "冷却后把肥肠切成小节备用。", "先把肥肠倒入锅里炒一炒（这时炒的时候不要倒油，主要是炒干水汽），起锅备用。然后锅内倒油，放入老姜，郫县豆瓣，花椒粒，老抽，草果，三奈，八角，冰糖炒香，注意这时火不能太大，火大的话佐料容易炒糊。佐料炒好后，把肥肠倒入翻炒，开大火，翻匀后倒入料酒，再炒2分钟，倒入热水烧开，（最好没过肥肠2厘米左右），把烧开后的肥肠转入高压锅，压15分钟，焖10分钟就可以了。\n如果时间压得太久的话，肥肠没有嚼劲，时间压少了的话，又会嚼不动。这个度一定要掌握好。", "把泡好的黄豆放入肥肠内烧十分钟，放入味精，出锅放葱花，撒香菜就可上桌了。\n没放黄豆的肥肠，第2天早上还可以用来下肥肠面或者是肥肠米线，都很不错。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/635aa37967994467beaa4aacbf5f76d6_1440w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('溜肥肠', '肉类', '肥肠', '', '[{"name": "一根熟肥肠", "amount": "适量"}, {"name": "葱姜蒜", "amount": "适量"}, {"name": "尖椒", "amount": "适量"}, {"name": "料酒，生抽，耗油", "amount": "适量"}, {"name": "盐，白胡椒粉，孜然", "amount": "适量"}]'::jsonb, '["熟肥肠回来清洗干净，也可以在加料酒姜片煮一会去味道。切段儿", "准备好配菜", "油六成热下葱姜蒜炒出香味，大火下肥肠，加些酱油，料酒，炒到变黄，最好炒面微脆", "下尖椒，加盐，耗油，孜然再翻炒一会。加淀粉水勾芡，即可出锅。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/aff2fa2a5dfe4322b1da492caf66d947_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('干锅肥肠', '肉类', '肥肠', '', '[{"name": "肥肠", "amount": "500克"}, {"name": "洋葱", "amount": "50克"}, {"name": "青椒", "amount": "50克"}, {"name": "蒜", "amount": "20克"}, {"name": "香菜", "amount": "10克"}, {"name": "红辣椒", "amount": "5克"}, {"name": "适量芝麻", "amount": "适量"}, {"name": "油", "amount": "0.5勺"}, {"name": "一品鲜酱油", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "糖", "amount": "1勺"}, {"name": "1匙盐", "amount": "适量"}, {"name": "0.2匙味精", "amount": "适量"}, {"name": "花椒", "amount": "3克"}, {"name": "大料", "amount": "3克"}]'::jsonb, '["猪大肠买的是已经煮熟的回来清洗干净焯水后冷水冲洗沥干水份备用", "猪大肠切除小段", "锅中倒入油烧热放入花椒、大料、糖、蒜爆香", "锅中放入猪大肠翻炒", "倒入蚝油、一品鲜酱油味道棒极了", "放入调味料翻炒使每个猪大肠都能裹上鲜味", "放入圆葱和青椒", "放入红辣椒、盐、味精翻炒均匀入味", "最后撒上香菜提鲜即可出锅享用", "香香哒干锅肥肠装入盘中", "肥肠是我家人的最爱", "撒上白芝麻更加提高干锅肥肠的颜值哦", "干锅肥肠绝对是宴客必备的拿手菜", "肥肠入口汁浓香嫩唇齿留香回味无穷", "来瓶啤酒搭配幸福到爆棚"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/885eb7a9f9ab48008457c60a08444035_1440w_1078h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒肥肠', '肉类', '肥肠', '', '[{"name": "200—250g煮熟的肥肠", "amount": "适量"}, {"name": "青椒", "amount": "1个"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "三分之一根（1个）胡萝卜或者红椒", "amount": "适量"}, {"name": "蚝油", "amount": "3勺"}, {"name": "生抽", "amount": "3勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "红糖", "amount": "2勺"}, {"name": "大半听啤酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "少许鸡精", "amount": "适量"}]'::jsonb, '["请用煮熟的肥肠！！煮熟的！这是爆炒的菜谱，火力大时间短，因此需要把肥肠煮好，嚼不烂就是没煮好！-_-！1⃣️取200—250g煮熟的肥肠切段（这边已经用煮过的肥肠省去处理肥肠的步骤，注意⚠️挑选处理干净的肥肠不要有异味的！！）2⃣️洋葱洗净切好3⃣️青红椒洗干净切片（没有红椒可以用半根胡萝卜切片，主要是为了点缀颜色）", "锅里放油（锅内要无水）烧热，下肥肠翻炒一会儿，加少许啤酒（量大约如图所示），加入蚝油、生抽、老抽、红糖翻炒（⚠️有人问一勺是多大，大概就是那种一个人喝汤的勺子那么大，去饭店吃饭常配的那种，注意⚠️调味料的多少很难书面传授，菜谱只能大约一个量，如果是刚学做菜不要太过刻板，及时品尝咸淡！）翻炒一会儿加入剩下的啤酒，盖盖子焖一会儿", "啤酒快收干的时候，加入洋葱、青椒、胡萝卜（红椒）继续翻炒一会儿，翻炒均匀", "炒熟后，撒上盐，鸡精翻炒均匀即可出锅"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/eda7adfaa7564246a19c14e23d872c0e_1472w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最简单的熬猪油方法', '肉类', '猪油', '', '[{"name": "猪油", "amount": "1000g"}, {"name": "冷水（我用的纯净水）", "amount": "100g"}]'::jsonb, '["卖猪肉的地方就有卖猪油，买回来之后，切成小块", "这是切好的小块", "将切好的小块猪油全部放入锅里", "然后放入一小碗冷水", "盖上锅盖中火焖一会儿", "打开锅盖 不停地用勺翻，以防糊锅底", "继续不停的翻", "到此程序就可以边翻，边往瓶子里面撇油了。", "瓶子上面放个漏勺", "这样一点一点的就不出油了，可以关火。带有冷却后就可以了。", "这是炼制好了的猪油，我的这个方法练出来的油是白色的，方法不对的话炼出来的猪油发灰色 味道也不好。", "这是熬油剩的油渣，可以做很多用途，一会儿看小贴士", "把油炸放碗里盖上保鲜膜放入冰箱冷藏。不建议装入塑料盒。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/3fccf78ddcc4483e9f2e32b2119ea94f_400w_320h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('轻松熬出又白又滑土猪油', '肉类', '猪油', '', '[{"name": "适量猪板油", "amount": "适量"}]'::jsonb, '["买回来的猪板油用热水器热水冲洗几遍，把板油上的脏东西洗干净\n猪板油不是肥猪肉哦\n具体问猪肉档老板就知道啦", "洗干净的板油放入锅中\n大火把水收干。这个时候很多人会问水是哪里来的？\n我们洗好的板油上面会残留一些洗板油的水", "见到没有水份后会慢慢出油\n这时候转小火慢熬\n然后可以做别的事啦\n基本上不太用管它 时不时看看就好", "准备一个装猪油的容器\n一个网筛\n一个勺子", "一直小火熬到图中的状态比较清澈", "一勺一勺舀出来过筛\n后面的继续熬继续舀出来", "直到结束\n一碗清澈的猪油就成功啦\n等待它凝固就可以用啦\n凝固后呈雪白色", "白白滑滑的猪油熬好啦"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/b44b4cf4571f11e7bc9d0242ac110002_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小技巧如何熬制猪油', '肉类', '猪油', '', '[{"name": "猪肥油 或 猪板油", "amount": "适量"}, {"name": "水", "amount": "适量"}, {"name": "筛网", "amount": "适量"}, {"name": "耐高温器皿（不锈钢碗）", "amount": "适量"}]'::jsonb, '["⭐️关注我们公众号：甜悦家烘焙，获取更多的教学视频&amp;烘焙工具，材料的优惠信息。\n\n淘宝店：甜悦家\n\n如果在制作过程中有什么疑问，可以扫码添加我的小助理的微信，她会给你详细解答哦，还可以加入甜悦家的烘焙交流群，还会有淘宝优惠哦~", "猪肥油：\n猪肥油是猪身上的肥肉，买来表面带有一层猪皮，熬猪油一般会把猪皮去掉。\n猪肥油用手指压下去是结实的，横切面整齐。内侧会连带一些瘦肉，熬制猪油的时候瘦肉容易焦掉，会影响猪油的味道和颜色，因此要把比较大块的瘦肉去掉。\n猪肥油熬出来的杂质比较少，但出油率比较小，没有猪板油那么香。", "猪板油：\n猪板油是猪肚子上的肥油，买回来是一大板、形状不规则的，有一层薄膜包裹着里面的肥膏，内侧有一层更厚的膜。在熬猪油的时候这些膜可以包裹住里面细碎的油脂块，以防猪油渣散掉，因此都不需要去掉。\n猪板油的出油率比较高，熬出来的油也比较香。", "猪板油清洗干净，尽量切成大小手指一半长度的均匀的小方块，避免熬制过程中受热不均匀。", "切好的猪板油放入锅中，总量不要超过锅子高度的二分之一，方便翻动猪油。", "加入少量水。\n水没有固定的量，水多一点就熬久一些，并没有任何影响。", "开大火加热，不停翻动猪油，让猪油受热均匀，直到水沸腾。", "熬出雪白猪油的小技巧：\n水的加入能让水和生猪油同时加热，防止猪油的边缘焦化，进而影响猪油的颜色。", "持续开大火，直到水分差不多熬干，猪油开始慢慢出油，就可以把火调到中小火或小火。", "开盖让猪油慢慢熬煮，不时翻动让猪油受热均匀，但不需要一直搅拌。", "猪油渣体积变小，变成金黄色，油也开始慢慢变成金黄色，就可以先把猪油渣捞出来，防止猪油渣煮焦，影响猪油的颜色和味道。", "猪油渣全部捞出来之后，猪油继续小火熬煮多几分钟，这样做出来的猪油更香。\n但也不能把猪油煮太久煮到冒烟，否则会有焦味，对身体也不好。", "炸好的猪油要马上倒出来，用筛网过滤，把剩余的杂质滤出来。", "刚炸好的猪油油温很高，需要用耐高温的器皿盛装，例如不锈钢碗。", "猪肥油的熬制和猪板油差不多。但猪肥油需要切成片状熬煮。", "猪肥油和猪板油的猪油渣可以密封冷藏保存，炒青菜的时候放几颗可以增加香味。", "猪油在室温下冷却之后就会凝固，变成白色。如果颜色不干净，一般是因为猪油里面的杂质焦化变色而影响的。", "完全冷却之后，可以盖上保鲜膜放在阴凉干燥的地方保存。", "在夏天或是室温较高的情况下，猪油容易酸败变质，需要放在冰箱保存，冷藏可以保存3个月左右，冷冻可以保存6个月左右。"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/5faa2de224a246f393e73bfddb7e1a7f_700w_382h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('熬大白猪油‖色白不腥', '肉类', '猪油', '', '[{"name": "猪板油", "amount": "750克"}, {"name": "水", "amount": "350克"}, {"name": "四片姜", "amount": "适量"}, {"name": "黄酒", "amount": "10ml"}, {"name": "盐", "amount": "2克"}]'::jsonb, '["猪板油切厚片", "锅里放水和姜片少许黄酒煮至微开", "下入板油煮三分钟", "捞出 透明感", "锅内放350ml清水。倒入焯过水的板油片", "大火煮开", "水少时 把火力调至小火", "随着油量增加水汽成大泡", "水汽少之又少的时候关火", "把油篦出。在油脂中加入盐2克", "放凉一小时后的油脂", "放至三小时后的油脂"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/18758a9c5b8f466ca2024f998a81fb65_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('用最简单的方法熬最白的猪油', '肉类', '猪油', '', '[{"name": "猪板油", "amount": "3斤"}, {"name": "清水", "amount": "120克"}]'::jsonb, '["一定要买猪板油哈，这个位置的出油率最高；", "切小块，我都是随意切的，有大有小；", "倒入锅里，这个锅没讲究，我用不粘锅熬过，也用不锈钢锅熬过，还有铁锅也熬过，都很白；", "加入适量的清水，水没讲究，我加的冷的自来水，水的用量也不是固定的，我是每次随意加；\n\n但如果你非要问用量的话，我只能说个大概的，3斤板油，我大概放了120左右的水；", "小火慢慢熬，中间不停的翻拌按压，油就慢慢熬出来了，熬出来的油及时捞出来；", "油渣过滤下；", "快熬完的板油，被榨干了，哈哈；\n\n一般情况下，最后快完的油，我是单独放的，因为最后这一点颜色会深一些，凝固后的油就比前面的稍微偏黄一点；", "猪油渣不要丢了，留着炒青菜，我们这儿有道菜叫油渣小白菜，特别好吃；\n\n或者加点盐（有些地方加糖）拌一下，直接吃，\n香酥脆...", "清澈见底的猪油，不怕麻烦的可以用最细的那种筛网多过滤几遍；", "特别清亮；", "凝固后的猪油，雪白雪白的..."]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/33e127f547fb47e7a43b436e85df21da_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('青椒炒猪腰', '肉类', '猪腰', '', '[{"name": "猪腰", "amount": "1个"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "青椒", "amount": "3个"}, {"name": "少许姜", "amount": "适量"}, {"name": "少许蒜苗", "amount": "适量"}, {"name": "各少许油,酱油,盐,胡椒粉,醋,淀粉", "amount": "适量"}]'::jsonb, '["先把猪腰清理干净,把里面的经络都切除,这样就不会有异味,然后切片...", "为了去除猪腰的异味,把切成片的猪腰加少许淀粉和醋先腌十几分钟,然后用水冲洗干净,再加少许淀粉和胡椒粉抓匀...", "姜,青椒,胡萝卜,蒜苗,切成丝和段...为了颜色搭配好看所以用了胡萝卜和青椒,这些食材都可以随意搭配,选红椒也可以,如果没有蒜苗用葱或大蒜也可以...", "因为猪腰炒久了容易老,所以时间在掌握好,食材不能一起炒,先在锅里下点油稍微煸炒一下胡萝卜和青椒,然后再在锅里下油爆姜丝,然后炒猪腰到变色加入炒过的青椒和胡萝卜,然后调少许酱油和盐翻炒几分钟,就可以出锅了..."]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/b322bc9487ff11e6a9a10242ac110002_4000w_3000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鲜嫩猪腰汤', '肉类', '猪腰', '', '[{"name": "猪腰", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "花生油", "amount": "适量"}]'::jsonb, '["油下锅热油", "姜爆香，闻到香味加入适当开水，水开了放入猪腰，下锅十秒关火"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/ffb5e7de89d011e6a9a10242ac110002_2048w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('我妈拿手好菜 猪腰汤', '肉类', '猪腰', '', '[{"name": "猪腰", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "热开水", "amount": "适量"}]'::jsonb, '["猪腰切花；姜切片，或拍开；烧开水，备用。", "白锅，即不放油，开火热锅至昌白烟。白锅落姜爆炒", "猪腰转色，攒酒", "落热开水没过猪腰", "汤滚开，放盐，关火。", "超级赞！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/65dc02908b4411e6b87c0242ac110003_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒猪腰子', '肉类', '猪腰', '', '[{"name": "一根大葱", "amount": "适量"}, {"name": "喜欢多放 不喜欢则少放洋葱", "amount": "适量"}, {"name": "一对猪腰子", "amount": "适量"}, {"name": "一只手的量淀粉", "amount": "适量"}, {"name": "可放可不放青椒或红辣椒", "amount": "适量"}]'::jsonb, '["将猪腰洗净，对半切开，把里头的白色部分全切掉，扔掉；\n\n在把猪腰子的表面先横着拿刀划，再竖着划，最后切成自己想要的长短，别切太大，腰花的形状就出来啦！\n\n大葱切段，洋葱就一条一条的，辣椒三角类型的都行（反正就随意发挥）", "盐、酱油、淀粉 腌制，最好是提前腌制，（比如你晚上吃，中午或早晨就给腌制了）", "炒腰子前拿过滤的东西把腌制腰花里的水全沥干（因为里面有血水），放另一个干净的碗再拿一点（切记是一点）淀粉抓一下", "锅里放油，烧热，把腰花放进去，变色就捞出，一定不能太长时间！！！（我这淀粉放多了）", "把油倒了，重新放干净的油\n\n把洋葱，大葱，青椒进去炒，酱油，蚝油（这里我没放盐，咸淡你们尝尝在考虑放不放）炒会在把猪腰子倒下去，翻滚两下就出锅了！", "出锅啦。超嫩超好吃"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/c7d827e4fb4c11e6947d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒猪腰', '肉类', '猪腰', '', '[{"name": "", "amount": "适量"}, {"name": "猪腰", "amount": "2个"}, {"name": "几瓣大蒜", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "青蒜", "amount": "1根"}, {"name": "适量辣椒", "amount": "适量"}, {"name": "少量生抽", "amount": "适量"}, {"name": "少量老抽", "amount": "适量"}, {"name": "适量味精", "amount": "适量"}]'::jsonb, '["猪腰买回来需要切开挖去白色东西，然后切开泡盐水，时间随意，猪腰凉水入锅煮开，姜片一起放。水一沸腾就把猪腰捞出放凉切薄片，如图，凉水浸泡。", "切好配料备用", "热锅冷油爆炒配件，然后倒入猪腰爆炒，加入调料焖一会装碗，好吃又不腥的猪腰就上桌了。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/a18a513e2cf211e7947d0242ac110002_2448w_3264h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('卤猪耳', '肉类', '猪耳朵', '', '[{"name": "一只新鲜猪耳朵", "amount": "适量"}, {"name": "适量大料", "amount": "适量"}, {"name": "适量姜，蒜", "amount": "适量"}, {"name": "适量花椒，十三香，盐", "amount": "适量"}, {"name": "适量独家秘方加入红茶", "amount": "适量"}, {"name": "适量老抽，生抽", "amount": "适量"}]'::jsonb, '["将猪耳洗干净，放入沸腾水中吊水。", "将水煮沸加入老抽，生抽和大料，花椒等。再将吊水后的猪耳放入水中。小火40分钟。", "为了能让猪耳更加入味，将煮好的猪耳浸泡在卤水中4个小时后食用。棒棒哒！", "切片猪耳朵时，刀锋一定要斜向下45度。这样切出的卤猪耳有木有很专业呢～"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/6e416b52889011e6b87c0242ac110003_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌猪耳朵', '肉类', '猪耳朵', '', '[{"name": "一个熟猪耳朵", "amount": "适量"}, {"name": "两段葱白", "amount": "适量"}, {"name": "一根黄瓜", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "香醋", "amount": "适量"}, {"name": "辣椒油", "amount": "适量"}, {"name": "香油", "amount": "适量"}, {"name": "一品鲜酱油", "amount": "适量"}, {"name": "白糖", "amount": "适量"}]'::jsonb, '["熟食店买来的猪耳朵切丝备用", "葱白切细丝，泡在装水的碗中", "黄瓜切丝备用", "猪耳朵，葱丝，黄瓜，少许盐，一勺香醋半勺一品鲜一勺白糖，拌匀之后上面根据自己洗好放少许辣椒粉", "热锅倒入辣椒油，加入两个干红辣椒，油热后浇在拌好辣椒粉上，用一次性手套与猪耳朵拌匀"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/74c84eac892e11e6b87c0242ac110003_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('卤猪耳朵', '肉类', '猪耳朵', '', '[{"name": "猪耳朵", "amount": "2只"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量黄酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一块桂皮", "amount": "适量"}, {"name": "两三个八角", "amount": "适量"}, {"name": "两棵带葱白的小葱葱结", "amount": "适量"}, {"name": "一块老姜", "amount": "适量"}, {"name": "几枚辣椒干", "amount": "适量"}, {"name": "适量山楂干片", "amount": "适量"}]'::jsonb, '["把耳朵清理干净，焯水冲洗干净，入锅，加足清水，所有的食材一并放入，煮，不要盖，滚起有浮末撇去，撇干净盖上锅盖，改最小火！", "煮至用筷子可以戳穿耳朵最厚实的部位就是煮好了，不用再煮，把火关了，焖上十几二十分钟！如果时间可以允许焖久一点更入味更好吃哦", "焖好用筷子捞出来，晾凉！", "卤好的猪耳朵，随你白切、烹炒、凉拌都可以，我今天就做了最喜欢的炒猪耳，冬笋、青椒、蒜苗、猪耳一起烹炒，非常值得推荐！", "这就是一盘青椒冬笋炒猪耳，非常下饭哦"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/299675ce8a1111e6b87c0242ac110003_1811w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌猪耳朵', '肉类', '猪耳朵', '', '[{"name": "一个猪耳朵", "amount": "适量"}, {"name": "半根黄瓜", "amount": "适量"}, {"name": "适量熟花生米", "amount": "适量"}, {"name": "适量香菜", "amount": "适量"}, {"name": "几个小米椒", "amount": "适量"}, {"name": "几个蒜瓣", "amount": "适量"}, {"name": "一小片生姜", "amount": "适量"}, {"name": "少许油", "amount": "适量"}, {"name": "一汤勺生抽", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "一小勺白胡椒粉", "amount": "适量"}, {"name": "小半碗啤酒", "amount": "适量"}, {"name": "少许老抽", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许芝麻油", "amount": "适量"}, {"name": "少许熟白芝麻", "amount": "适量"}, {"name": "少许鸡精", "amount": "适量"}]'::jsonb, '["煮熟了的猪耳朵切丝.\n黄瓜去皮切薄片.\n熟花生米.\n香菜洗净切碎.\n小米椒.大蒜瓣.生姜切碎...！\n\n猪耳朵可以直接买熟的回来.\n\n如果买生的话要清洗干净.\n放冷水锅煮开后.\n再煮几分钟后捞出.\n放凉水中浸泡透.\n再锅里放开水.\n一些大料.生姜.老抽等.\n把猪耳朵放下去煮15分钟左右捞出.\n放凉透后切薄片凉拌.", "锅里放少许油..\n\n放入小米椒.大蒜.生姜碎..\n\n我家因为熟的白芝麻木有了.\n\n我提前放了一些生的下去.\n如果是用熟的.\n可以最后放..\n\n额...\n我随意起来真的挺那啥...", "放入生抽.老抽.白胡椒粉.\n白糖.盐.啤酒.....\n\n加热出香味...", "微微收干了一些汁后...\n\n关火.\n\n放芝麻油.鸡精\n我家亲戚说喜欢辣.\n我不客气的又放了一勺辣椒油.", "放凉之后..\n\n把猪耳朵.黄瓜.花生米放入.\n\n充分搅拌均匀！\n\n伱也可以倒入盘子里面搅拌.\n我觉得不太方便.\n没锅里来的痛快..", "再放入香菜.\n搅拌均匀....", "装盘...！\n\n动手吧..."]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/bbaf427ee17311e6bc9d0242ac110002_1280w_856h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常拌猪耳朵', '肉类', '猪耳朵', '', '[{"name": "一块猪耳朵", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "适量醋", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量酱油", "amount": "适量"}, {"name": "一大勺老干妈辣酱", "amount": "适量"}]'::jsonb, '["把猪耳朵切丝、黄瓜拍成块、蒜、香菜、切末。", "用一个小碗调料，放入酱油、醋、盐、白糖、蒜末、老干妈。", "把黄瓜、猪耳朵、香菜末放入调料碗拌匀完成。", "黄瓜提前放冰箱口感更好"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/510afda6535f11e7947d0242ac110002_3264w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱爆猪心', '肉类', '猪心', '', '[{"name": "新鲜猪心", "amount": "1个"}, {"name": "青椒", "amount": "1个"}, {"name": "红椒", "amount": "1个"}, {"name": "少许淀粉", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "少许酱油", "amount": "适量"}, {"name": "少许蚝油", "amount": "适量"}, {"name": "少许料酒", "amount": "适量"}, {"name": "少许醋", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许糖", "amount": "适量"}]'::jsonb, '["将猪心切片，用料酒，酱油，淀粉，醋，糖，盐腌制十分钟。", "青椒，红椒切片，姜切丝。", "锅中放热油，放入腌制好的猪心炒匀盛出。重新热一个锅，放入少许油，再放入青红椒，姜丝爆炒香味，再放入刚才炒好的猪心，最后调点豆瓣酱和蚝油。快速炒匀盛出。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/6da88b20885511e6b87c0242ac110003_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒猪心', '肉类', '猪心', '', '[{"name": "一个猪心", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}, {"name": "五瓣蒜瓣", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "湖南青辣椒", "amount": "200克"}]'::jsonb, '["先将猪心洗干净切成薄片。放入盘中装好，撒入适量盐，鸡精，生抽，胡椒粉，料酒进行腌制。大约十五分钟。", "锅中放入适量花生油烧热。把腌制好的猪心倒入锅中爆炒，变色即盛盘装出。", "再放适量花生油烧热，放入切碎的蒜瓣爆香，再将切好的湖南辣椒爆炒，辣椒稍稍变软时倒入猪心翻遍片刻，撒入适量鸡精粉，即可出锅。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/7315394e886111e6b87c0242ac110003_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌猪心', '肉类', '猪心', '辣', '[{"name": "一只猪心", "amount": "适量"}, {"name": "八角，桂皮，茴香，生姜，葱，大蒜，盐，料酒，白糖，花椒油，酱油，醋，鸡精，蚝油，辣椒油，小米辣，芝麻", "amount": "适量"}]'::jsonb, '["锅里放猪心加水放八角，桂皮，茴香，生姜，料酒，盐，花椒煮熟", "猪心煮熟后捞出晾凉，切葱丝垫底，蒜蓉，小米辣备用", "蒜蓉兑凉开水放适量的盐，鸡精，白糖，蚝油，酱油，醋，花椒油，辣酱油，芝麻，全部搅拌均匀浇在猪心上放几粒小米辣装饰即可", "这道菜以麻辣为主，香辣可口"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/03b9e7128ba811e6b87c0242ac110003_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('安神猪心汤', '肉类', '猪心', '', '[{"name": "半个（2人份）猪心", "amount": "适量"}, {"name": "3-5克（1人份）枸杞", "amount": "适量"}, {"name": "两三颗（1人份）红枣", "amount": "适量"}, {"name": "四五颗（1人份）桂圆", "amount": "适量"}, {"name": "3-5克茯苓", "amount": "适量"}, {"name": "3-5克酸枣仁", "amount": "适量"}, {"name": "（以上药材均为一人份）", "amount": "适量"}]'::jsonb, '["猪心洗干净血水血块，切成小块。", "药材洗干净浸泡一会。", "切好的猪心下锅放冷水加几滴料酒煮沸，撇掉浮沫，清水冲干净猪心。这样煮出来的汤会清澈没有肉沫。", "我是用电炖锅煮的，包了锡纸，炖两个小时。如果上煤气炉炖，一个半小时应该够了的，看水吧。猪心是比较不容易炖烂的肉，这是它独特的口感。", "睡前两个小时喝，晚上睡得香😄"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/403df530189c11e7bc9d0242ac110002_700w_467h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('卤猪心、猪肝（卤心肝）', '肉类', '猪心', '', '[{"name": "（约300克）猪心", "amount": "1个"}, {"name": "（约200克）猪肝", "amount": "1块"}, {"name": "姜", "amount": "6片"}, {"name": "小葱", "amount": "3根"}, {"name": "5瓣蒜", "amount": "适量"}, {"name": "2粒八角", "amount": "适量"}, {"name": "10粒花椒", "amount": "适量"}, {"name": "香叶", "amount": "3片"}, {"name": "干辣椒", "amount": "2条"}, {"name": "料酒", "amount": "2汤匙"}, {"name": "生抽", "amount": "5汤匙"}, {"name": "3小粒冰糖", "amount": "适量"}, {"name": "1/2茶匙盐", "amount": "适量"}, {"name": "老抽", "amount": "1茶匙"}, {"name": "食用油", "amount": "1汤匙"}]'::jsonb, '["猪心对半切开，清理掉内部的血块，猪肝去掉血管，一同用清水泡30分钟。姜切片、葱切段、蒜用刀拍破。", "锅里注入冷水放入1汤匙料酒和猪心、猪肝。开火煮制水滚，捞去浮沫，取出猪心和猪肝备用。", "另取一个锅子，加入食用油，爆香姜片、蒜和葱。加入清水约600ml，放入料酒、生抽、老抽、盐、冰糖、八角、香叶、花椒、干辣椒，煮滚后放入烫好的猪心和猪肝。再次煮滚后调小火（最小的火力）盖上盖子，煮8-10分钟左右将猪肝捞出，用牙签穿透猪肝看没有血水溢出即是熟了。猪心则继续用小火煮20分钟。", "煮好后关火，猪心不必捞出，一直用卤汁泡着。待卤汁完全冷透后再放入刚才捞出的猪肝一同浸泡2小时以上，直到完全入味。", "吃之前，将卤好的猪心猪肝切片，淋上卤汁即可。喜欢重口味可以用一点蒜末+生抽+醋+香油+一点点糖，调成蘸汁蘸食。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/27a97b8ecc3b4e53aa8d256f951d356d_1620w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('麻辣猪血烧豆腐', '肉类', '猪血', '辣', '[{"name": "猪血", "amount": "适量"}, {"name": "老豆腐", "amount": "适量"}, {"name": "老抽", "amount": "适量"}, {"name": "辣椒粉", "amount": "适量"}, {"name": "花椒粉", "amount": "适量"}, {"name": "姜蒜", "amount": "适量"}, {"name": "葱花", "amount": "适量"}, {"name": "芝麻", "amount": "适量"}, {"name": "淀粉", "amount": "适量"}]'::jsonb, '["豆腐、猪血切块装盘备用。", "姜蒜切丝。", "锅放油烧热放入切好的姜蒜，盐、辣椒粉、花椒粉、老抽，煎一分钟左右，在放水煮待水开时倒入切好的猪血豆腐，慢火煮，待豆腐猪血入味就可以放入调好的水淀粉勾芡，即可起锅装盘。洒入芝麻和葱花装饰即可。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/4ac475b087e211e6a9a10242ac110002_600w_800h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常韭菜炒猪血', '肉类', '猪血', '', '[{"name": "猪血", "amount": "适量"}, {"name": "韭菜", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "花生油", "amount": "适量"}, {"name": "盐", "amount": "适量"}]'::jsonb, '["把猪血切成片，过一下水捞出待用。", "用蒜爆锅后放入猪血翻炒。", "把韭菜放入后加适量盐，搅拌均匀后出锅。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/47c49b2c895b11e6a9a10242ac110002_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧猪血', '肉类', '猪血', '', '[{"name": "克500猪血", "amount": "适量"}, {"name": "适量酱油", "amount": "适量"}, {"name": "几片蒜头", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量豆瓣酱", "amount": "适量"}, {"name": "适量酸辣椒", "amount": "适量"}, {"name": "一小块酸萝卜", "amount": "适量"}, {"name": "一根大蒜", "amount": "适量"}]'::jsonb, '["猪血切片，水烧开煮3分钟", "姜切碎，小米椒切段，酸辣椒切碎，大蒜子切碎，酸萝卜切碎，大蒜根切薄片，大蒜叶子切段", "放油，把姜蒜根小米椒酸萝卜酸辣椒大蒜沫爆香，再加一勺豆瓣酱和适量酱油炒出红油加入猪血", "翻炒半分钟把大蒜叶子放进去加适量的盐和鸡精再翻炒一下出锅"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a77598e8414111e7947d0242ac110002_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“酸菜烧猪血”的家常做法，非常开胃下饭', '肉类', '猪血', '酸', '[{"name": "克猪血", "amount": "适量"}]'::jsonb, '["厨师长教你：“酸菜烧猪血”的家常做法，非常开胃下饭"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/72f510f35c01475c9582754592eeea49_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香辣蒜苗炒猪血', '肉类', '猪血', '辣', '[{"name": "一把蒜苗", "amount": "适量"}, {"name": "一块猪血", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量蒜", "amount": "适量"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "适量淀粉", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量食盐", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}]'::jsonb, '["准备食材。", "葱，姜，蒜，干辣椒切沫备用。", "猪血切成大约一厘米厚的片。", "蒜苗切段。", "炒锅烧热，加入适量植物油。", "放入葱，姜，蒜，干辣椒爆香。", "放入猪血煸炒至微焦，看着微焦但并不是糊了，这样的猪血吃着特别香。", "放入适量料酒，翻炒均匀。", "加入蒜苗翻炒均匀。", "加入适量食盐翻炒均匀。", "倒入勾兑好的淀粉，翻炒均匀。", "加入适量鸡精翻炒均匀，关火。", "香喷喷的香辣蒜苗炒猪血就可以出锅装盘啦！"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/604faba9d8164f52b655265e0d274f38_1024w_768h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('雪梨猪肺汤', '肉类', '猪肺', '', '[{"name": "猪肺", "amount": "1个"}, {"name": "猪骨", "amount": "500g"}, {"name": "雪梨", "amount": "2个"}, {"name": "姜", "amount": "2片"}, {"name": "酒", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "味精", "amount": "适量"}]'::jsonb, '["猪肺放在水龙头往里灌水，整个猪肺发涨，然后让肺里的水流出，再灌水、再流、这样重复10一15次，", "直到猪肺变白。", "把猪肺切成小块，锅内放凉水，把猪肺放进锅内，大火煮开，猪肺受热收缩，会有大量的浮沫挤出，水开后煮1分钟左右，将猪肺沥干水，再倒进盆冲洗干净浮沬，这样处理过的猪肺非常干净，就可以放心吃了。", "锅内放少许的油、油热放姜、再放沥干水的猪肺、放几滴酒翻炒到水份干出锅待用。\n锅里放水、水沸后放料酒、把猪排骨在沸水里面过水后、倒出用冷水冲干净待用。\n雪梨去芯切小块。\n砂锅注入清水、把所有的材料放进锅里、大火烧开后小火煲3小时、放盐调味即可食用。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/fb17d588888711e6a9a10242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒肺片', '肉类', '猪肺', '辣', '[{"name": "半只猪肺子", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "一小段葱", "amount": "适量"}, {"name": "姜", "amount": "2片"}, {"name": "少许十三香", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["肺子切片，葱姜切丝，辣椒切段。", "待油热，葱、姜、辣椒、十三香爆锅，肺片入锅爆炒。加适量盐。待熟出锅。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/0847fa9088d211e6b87c0242ac110003_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('尖椒煸猪肺', '肉类', '猪肺', '', '[{"name": "适量猪肺", "amount": "适量"}, {"name": "适量尖椒", "amount": "适量"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "2片"}]'::jsonb, '["猪肺洗净切片，在用水把肺洗干净，沥干水", "锅里倒入油，可以多一点（肺很吃油的），烧热油下姜蒜接着倒入肺煸，煸久一点。煸到油快干了，就倒入尖椒，加适量的盐，炒到尖椒熟即可，放点鸡精起锅。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/c751dc02894611e6a9a10242ac110002_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('麻辣猪肺', '肉类', '猪肺', '辣', '[{"name": "1副猪肺", "amount": "适量"}, {"name": "食用油", "amount": "50ml"}, {"name": "老抽", "amount": "10ml"}, {"name": "生抽", "amount": "20ml"}, {"name": "料酒", "amount": "50ml"}, {"name": "蚝油", "amount": "10ml"}, {"name": "少许鸡精", "amount": "适量"}, {"name": "3粒冰糖", "amount": "适量"}, {"name": "桂皮", "amount": "1片"}, {"name": "3粒八角", "amount": "适量"}, {"name": "香叶", "amount": "5片"}, {"name": "生姜", "amount": "15片"}, {"name": "6瓣大蒜", "amount": "适量"}, {"name": "十几个（根据能吃辣的程度放）干辣椒", "amount": "适量"}, {"name": "辣椒粉", "amount": "50g"}, {"name": "花椒（或花椒粉）", "amount": "30g"}, {"name": "孜然（或孜然粉）", "amount": "10g"}, {"name": "十三香", "amount": "20g"}, {"name": "胡椒粉", "amount": "20g"}, {"name": "根据自己口味盐", "amount": "适量"}]'::jsonb, '["猪肺冷水下锅，水开后再煮20分钟。捞起，用剪刀把猪肺上每根肺管都剪开（一定要剪开冲洗，肺管里会有血水，剪开才能洗得到）冲洗干净后切成片", "锅里放油，油热后放入八角，桂皮，生姜，花椒炒出香味后倒入辣椒粉炒匀。然后放入大蒜，干辣椒，稍微炒至出辣油", "倒入切好的猪肺，翻炒均匀。然后把剩下的所有材料全倒进去。翻炒后加水没过猪肺一毫升左右，大火煮开再关中小火加盖焖煮一个小时左右。（煮好后不用收汁，有辣水泡着更好吃哦）"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/27fd98ce8b0011e6a9a10242ac110002_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('菜干煲猪肺（汤）', '肉类', '猪肺', '', '[{"name": "一个猪肺", "amount": "适量"}, {"name": "适量菜干", "amount": "适量"}, {"name": "少许南北杏", "amount": "适量"}, {"name": "一个蜜枣", "amount": "适量"}, {"name": "半斤猪骨或猪肉", "amount": "适量"}, {"name": "几片姜片", "amount": "适量"}]'::jsonb, '["菜干提前用水浸泡", "4个钟，洗凈，切段", "我用的是白菜干，亲戚自种自晒的。没有可外面买", "猪肺对住水龙头入水", "用个喉口对住入", "入水后猪肺会涨大成10倍，用手抓压，会有血水从喉口流出来，抓到血水流干为止，再次入水再次抓压，如些五、六次", "落锅干煮，会出水，越煮越多水", "倒出冲洗", "第二次煮（放少少水）", "再洗，可以用盐抓几下", "反复洗干净就ok", "猪肉猪骨过一次水", "全部材料入锅，加适量水，定时3个钟", "调味，倒小碟生抽放桌面，饮汤食菜😊"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/301443bcd68911e6bc9d0242ac110002_2104w_1184h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('肉沫豆角', '肉类', '肉末', '', '[{"name": "豆角", "amount": "500克"}, {"name": "猪肉碎", "amount": "200克"}, {"name": "（不吃辣可不放）小米椒", "amount": "5克"}, {"name": "适量大葱 大蒜", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "糖", "amount": "1勺"}, {"name": "适量老抽", "amount": "适量"}, {"name": "淀粉", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}]'::jsonb, '["1勺料酒 1勺糖 1勺淀粉 1勺生抽 抓匀 先把肉碎腌制10分钟", "豆角切成丁", "葱 蒜 小米椒 切成丁", "锅底放适量植物油 油低温的时候就把肉沫放进去煸炒  加少许老抽调色", "然后乘出备用", "锅底放少量植物油  把切好的葱、蒜、小米椒 放入锅中 炒出香味", "把豆角放入锅里翻炒  边炒边加入 少量的清水，一定要一点一点的放 一定要少量多次加入， 这样可以使豆角更容易熟 而且颜色是翠绿的 。", "豆角成熟之后 加入之前超好的肉沫 加适量的盐  翻炒均匀", "出锅之前可加少许鸡精"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/746b5b3e87d011e6a9a10242ac110002_3420w_2592h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蚂蚁上树(肉末炒粉丝)超下饭‼十分钟搞定', '肉类', '肉末', '', '[{"name": "红薯粉丝", "amount": "80g"}, {"name": "肉末(猪肉糜)", "amount": "30g"}, {"name": "少许葱花", "amount": "适量"}, {"name": "少许姜片", "amount": "适量"}, {"name": "盐", "amount": "2g"}, {"name": "料酒", "amount": "1勺"}, {"name": "酱油", "amount": "1勺"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "少许糖", "amount": "适量"}, {"name": "少许油", "amount": "适量"}]'::jsonb, '["红薯粉丝剪成段，用温水浸泡20分钟泡软备用。", "泡软后的粉丝沥干水分。", "葱切成末，姜切片。", "锅内倒入少许油，烧热后倒入葱末姜片爆香，加1勺豆瓣酱翻炒均匀后下猪肉糜(肉末)炒散。倒1勺料酒、1勺酱油、糖、盐调味炒均匀，加入小碗冷水，煮沸。", "汤煮沸后倒入沥干水分的红薯粉，入锅一起翻炒几下后小火焖煮5分钟。", "大火翻炒收汁出锅。此菜要速炒，时间长了粉条容易粘连，影响菜肴口感！", "出锅的肉末炒粉丝色泽油亮。", "装盘后可以撒少许葱花和白芝麻，美味诱人！", "粉丝油亮，柔软滑嫩，肉末香嫩！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/7ea02eee3d4744c6b97563f3e907c3f2_3072w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('比布丁还要嫩！巨好吃又营养的肉末水蒸蛋', '肉类', '肉末', '', '[{"name": "鸡蛋", "amount": "3个"}, {"name": "少许盐", "amount": "适量"}, {"name": "温水", "amount": "250克"}, {"name": "肉末", "amount": "50克"}, {"name": "葱", "amount": "1根"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺生抽", "amount": "适量"}, {"name": "白糖", "amount": "10克"}, {"name": "玉米淀粉", "amount": "10克"}]'::jsonb, '["碗中打入三个鸡蛋", "加少许盐，搅拌均匀", "加入温水，搅打均匀", "过筛一次！盖上保鲜膜，扎几个小孔！水开上锅蒸10分钟", "起锅热油炒肉末，炒至肉末变色", "加入一勺蚝油", "半勺生抽", "半勺白糖，翻炒均匀", "玉米淀粉加入半碗水调匀，淋入肉末中，煮至浓稠", "撒上葱花", "把炒好的肉末放入蒸好的鸡蛋羹上就可以啦！\n⚠"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/fa0cbf1c19704b6080598856031adf6f_3024w_4030h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱汁浓郁！超级下饭的家常菜肉末香菇', '肉类', '肉末', '辣', '[{"name": "香菇", "amount": "300克"}, {"name": "肉末", "amount": "200克"}, {"name": "葱", "amount": "1根"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "小米辣", "amount": "2个"}, {"name": "生抽", "amount": "2勺"}, {"name": "糖", "amount": "5克"}, {"name": "蚝油", "amount": "1勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "淀粉", "amount": "1勺"}, {"name": "盐", "amount": "5克"}]'::jsonb, '["调个酱汁：碗中加入两勺生抽+一勺老抽+一勺蚝油+适量盐和糖+一勺淀粉，加入半碗清水拌匀", "香菇切片，锅中水开，焯水一分钟捞出备用，起锅倒入适量油，油热放入肉末，炒至变色，加入葱，蒜，小米辣翻炒出香味，倒入香菇翻炒均匀，倒入酱汁，翻炒至汤汁浓稠，出锅撒上葱花即可！", "太下饭了，我儿子吃了两碗饭"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/c7cf449ff6884728a7c9f875d42fe321_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级下饭的肉沫炒土豆！', '肉类', '肉末', '', '[{"name": "土豆", "amount": "2个"}, {"name": "肉沫", "amount": "200克"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "葱", "amount": "1根"}, {"name": "小米辣", "amount": "2个"}, {"name": "生抽", "amount": "2勺"}, {"name": "盐", "amount": "5克"}, {"name": "老抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "糖", "amount": "5克"}, {"name": "淀粉", "amount": "1勺"}]'::jsonb, '["家常菜，推荐", "调个酱汁：碗中加入两勺生抽+一勺老抽+一勺蚝油+适量盐和白糖+一勺淀粉+适量清水，搅拌均匀", "土豆去皮切块，多洗几次，洗掉淀粉，油热下锅，把土豆煎至微黄，盛出备用\n锅中倒入适量油，放入肉沫，炒至变色，加入葱，蒜小米辣翻炒出香味\n放入土豆翻炒均匀，倒入酱汁，翻炒至汤汁浓郁，最后撒上葱花即可！", "✨✨✨是不是超级简单，一定要多备些米饭哦！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/44cbe2d704f14ae197a65f1fe22a4d82_1921w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('可乐鸡翅', '肉类', '鸡翅', '', '[{"name": "鸡翅", "amount": "12个"}, {"name": "少许油", "amount": "适量"}, {"name": "1罐可口可乐", "amount": "适量"}, {"name": "姜", "amount": "3片"}, {"name": "左右盐", "amount": "1克"}, {"name": "2汤勺啤酒", "amount": "适量"}, {"name": "1汤勺生抽", "amount": "适量"}, {"name": "小半汤勺老抽", "amount": "适量"}, {"name": "少许熟白芝麻", "amount": "适量"}]'::jsonb, '["鸡翅洗净背面划二刀..\n\n方便入味.\n伱要真懒.\n也可以不划..(−_−＃)", "锅里放冷水.鸡翅..\n放入二片姜...\n\n煮开..", "准备一罐可乐.\n另一片姜切丝.", "水开后煮二分钟左右..\n\n捞出洗净备用.", "锅里放少许油.\n把洗净控干水分的鸡翅放下去煎香.", "翻面..", "二面都煎好后放入生姜丝和啤酒.\n炒出香味..\n啤酒汁略微收干了.\n\n木有啤酒的可以用一勺料酒代替.\n不过我还是喜欢啤酒的！", "放入一汤勺的生抽.\n嗯.\n就平时喝汤的勺..", "小半汤勺的老抽.", "翻炒均匀上色.", "倒入可乐.\n烧开后转中火.\n盖上锅盖焖.", "焖至一半汁时.\n加入盐.\n开大火收汁.", "收到自己喜欢的程度就好..", "装盘.撒上熟白芝麻.\n\n我这是全部收干了的.\n一定要不停的搅拌.\n很容易糊."]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/86d43f14f05a11e6947d0242ac110002_1280w_856h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('外婆教我的红烧鸡翅连汤汁都狠好吃！！！', '肉类', '鸡翅', '', '[{"name": "鸡翅中", "amount": "8个"}, {"name": "2粒冰糖", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "半个辣椒", "amount": "适量"}]'::jsonb, '["准备阶段：", "鸡翅正反面各划两刀➕料酒3勺➕生抽2勺➕蒜末、姜片➕生粉半勺➡️放入盘中腌制20分钟", "生姜切6片、大蒜切末、葱切成丝、辣椒半个切丝备用", "半勺生抽、半勺老抽、一勺蚝油、2颗冰糖备用", "热锅冷油➡️油热后加入葱、姜、蒜、辣椒➡️炒出香味\n\n⚠️注意：我这里放的前一天熬出来的猪油，猪油会更香，没有的话普通的油也是可以的", "加入腌制后鸡翅➡️煎至两面金黄", "加入热水沒过鸡翅➡️倒入之前准备好的半勺生抽、半勺老抽、一勺蚝油、2颗冰糖➡️加入一根完整的打成结的小葱➡️热水煮开后关成小火煮15分钟\n\n⚠️注意：要放热水，冷水会使肉收缩，从而影响口感；同时要放一根完整的小葱，这样汤汁会更香哦😜", "大火收汁装盘➡️撒上葱花\n\n鸡翅肉质鲜嫩｜汤汁浓稠\n\n真的超级好吃，快来试下吧❤️"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/1136c60f7ae3439ea67e8ddcc7208991_2700w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('懒人版红烧鸡翅', '肉类', '鸡翅', '', '[{"name": "鸡翅", "amount": "400g"}, {"name": "冰糖", "amount": "10g"}, {"name": "老抽", "amount": "8g"}, {"name": "生抽", "amount": "10g"}, {"name": "盐", "amount": "3g"}, {"name": "少许姜", "amount": "适量"}, {"name": "蒜", "amount": "1个"}, {"name": "小米辣", "amount": "1个"}, {"name": "少许白胡椒", "amount": "适量"}, {"name": "少许白芝麻装饰", "amount": "适量"}]'::jsonb, '["（有人留言说焯水，这个问题自行选择，我没焯水，浸泡1小时左右，中间换过水）鸡翅洗干净放锅里，所有料放锅里，用手捏，多按摩一会儿，腌制半小时，中间记得翻身", "锅里热油，中🔥把鸡翅放入锅里煎", "两面煎微黄", "把前面料倒入锅中加入热水没过鸡翅", "大火烧开后转最小火炖", "我煮半小时，时间无所谓，快要开饭时候打开锅盖大火烧，收汁即可", "这样就好了", "是不是很想吃，那就快试试吧", "最后装盘撒上芝麻点缀", "烘焙美食交流群，广告勿扰！谢谢！"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/c77c0b55ead74eff9fa3328129cda6c1_2160w_2880h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('妈妈家的味道，吃了停不下来的红烧鸡翅', '肉类', '鸡翅', '', '[{"name": "8-10个鸡中翅", "amount": "适量"}, {"name": "葱", "amount": "2根"}, {"name": "姜", "amount": "5片"}, {"name": "4瓣蒜", "amount": "适量"}, {"name": "5颗冰糖", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "1/2勺蚝油", "amount": "适量"}, {"name": "1/2勺老抽", "amount": "适量"}, {"name": "1/2勺淀粉", "amount": "适量"}]'::jsonb, '["将鸡中翅洗净，两面各划两刀", "将姜切丝、切片，京葱切片，蒜切成蒜末备用。左边的姜丝蒜米用来腌渍鸡翅，右边的用来炒菜。", "准备5粒冰糖、小葱打结备用", "将3勺料酒、2勺生抽、1/2勺生粉、姜蒜倒入鸡翅中腌制15-20分钟", "这是腌渍20分钟的鸡翅", "将腌渍好的鸡翅放入不粘锅两面煎制金黄", "起锅烧油，放入葱姜蒜爆香", "鸡翅放入锅中翻炒几下，加入沒过鸡翅的热水，大火烧开后加入葱结、冰糖、蚝油、1/2勺老抽、1/2勺生抽，转小火炖煮15分钟，然后取出葱结姜片，大火收汁。", "出锅撒芝麻葱花，开吃吧！真的好吃的停不下来～"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/36ce5c0bc6c0454caec5ce2cdb52fb90_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('可乐鸡翅（超级成功案例）
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香煎鸡胸肉', '肉类', '鸡胸', '', '[{"name": "—250g左右鸡胸肉", "amount": "200g"}, {"name": "1/8 teaspoon盐", "amount": "适量"}, {"name": "1/8 teaspoon黑胡椒粉", "amount": "适量"}, {"name": "2—3瓣大蒜", "amount": "适量"}, {"name": "1 tablespoon蜂蜜", "amount": "适量"}, {"name": "1/8 cup橄榄油", "amount": "适量"}, {"name": "少许橄榄油", "amount": "适量"}, {"name": "（づ￣3￣）づ╭❤～答应我好好看tips好嘛", "amount": "适量"}]'::jsonb, '["将盐和黑胡椒粉撒至鸡胸肉双面，轻微按摩片刻，静置15分钟左右。（盐和胡椒粉的分量也可以根据自己的感觉随！便！撒！\n\n以下tips：\n鸡胸肉不易取太大块，尽量控制在200g—250g之间，太大不易入味。太厚可以切两片~鸡大胸比鸡小胸更好吃。\n\n【不要切太薄，容易柴】\n有部分妹纸反应鸡胸肉不太吃盐，如果是重口味，可以适量多撒点盐哈~如果你是正常口味不要猛撒，会齁咸（认真脸", "鸡胸肉腌制的时候就开始准备酱料。大蒜剁碎成蒜末，加入一勺蜂蜜，加入橄榄油。\n\n以下tips：\n如果没有量勺，用平时喝汤的这种勺子，1勺蜂蜜，2-3勺橄榄油。如果鸡肉多的话，酱汁要多一点噢，酱汁要足才能完美的裹住鸡胸", "【没有橄榄油的朋友请看这边】\n\n很多小伙伴留言问没有橄榄油咋办~实践出真知，特地用了花生油试了，味道也是极好的~不过还是推荐一定用橄榄油，更嫩！ 如果实在是没有橄榄油，请用味道轻的植物油，不要用黄油、香油、猪油！", "用勺子搅拌均匀，因为蜂蜜比较黏稠所以要多搅拌片刻，让蜂蜜和油完美的混合。", "将鸡胸肉铺在保鲜膜上，将酱料均匀涂抹在双面。\n\n以下tips：\n保鲜膜才能紧密的裹紧酱汁，退而求其次可以选保鲜袋。酱汁要足够的多，能裹住双面，这样鸡胸肉才足够嫩。", "密封起来，冷藏一晚上。\n冷藏是保鲜层，平时放鸡蛋牛奶的那一层。", "【记得用不粘锅，不然就哭泣吧- - 】\n\n锅里加入少许橄榄油（其实可以不加油了）将鸡胸肉连同酱汁一起倒入锅子里，煎至深棕色后翻面煎，开小火盖盖子焖煎。全程大约10分钟左右，请根据鸡肉实际情况操作\n\n\n以下tips：\n【全！程！小！火！盖！盖！子】\n\n不要为了追求焦脆的颜色延长时间，煎久了就不嫩了~（如图左下角金黄色即可）\n\n【要！小！火】因为酱汁含有蜂蜜和蒜蓉，所以特别容易煎焦了糊锅…\n\n糊了的蒜末什么的就不！要！吃！了！乖~\n如果煎好了切片发现里面肉是红色的请再煎一会儿，一定要煎熟了再吃，乖啦~", "【以下碎碎念，跟制作步骤无关可忽略】\n\n我喜欢焦一点香脆，所以煎的比较丧心病狂，火力有点over了。【请！不！要！轻！易！模！仿】\n\n大家根据自己健！康！习！惯！煎，不需要也煎出焦脆的感觉，只要金灿灿熟了就能吃了。", "如果煎的成功，切开的时候鸡肉会微微渗出汁水，完美（祖蓝脸\n反正只要自己觉得好吃炸就够了，管他什么标准呢~ \n\n口感真的就是外脆里嫩，又多汁！稍微切厚点吃口感更棒！切好的鸡胸肉可以蘸酱汁吃~ 非常入味香脆！\n\n说到这里本宝宝要啰嗦一句，如果你手抖盐多了，那配沙拉菜或者夹三明治吃，实在不行就白粥吃啊啊啊；如果太淡了就蘸酱吃！什么番茄酱、泰式甜辣椒等等。", "切片夹三明治吃超级好吃！\n做饭这件事情嘛，不爱吃甜的少一点蜂蜜，口味重的多点盐，一定要足够的时间腌制入味才会好吃哟~"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/0a4eb5b689ab11e6b87c0242ac110003_1600w_2407h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('健身厨男版：香煎滑嫩鸡胸肉，全网最流行的鸡胸吃法！', '肉类', '鸡胸', '', '[{"name": "500鸡胸", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量淀粉", "amount": "适量"}, {"name": "适量酱油", "amount": "适量"}]'::jsonb, '["把肉片薄是关键\n以前做的时候整块鸡胸下去 \n影响整体效果", "放入盐、黑胡椒、生抽、淀粉\n用手抓捏均用后 腌制15分钟\n我一般都是冰箱里腌一宿，因为上班比较早尽量为早上节约时间", "大火将平底锅烧热，刷一层薄油\n鸡肉下锅\n咦，厨男用的居然是柳宗理，无奈我只有宜家8寸锅。", "马上盖上锅盖，形成烘烤的气氛。转中火，两面各煎2分钟", "成品当当", "盖上锅盖"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e54200208ab811e6a9a10242ac110002_457w_511h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('减脂鸡胸肉饼', '肉类', '鸡胸', '', '[{"name": "鸡胸肉", "amount": "500克"}, {"name": "西兰花", "amount": "100克"}, {"name": "玉米粒", "amount": "100克"}, {"name": "胡萝卜", "amount": "100克"}, {"name": "生抽", "amount": "2勺"}, {"name": "小半勺盐", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}, {"name": "生粉", "amount": "2勺"}]'::jsonb, '["鸡胸肉剁成肉泥，玉米粒煮熟，西兰花和胡萝卜切碎", "鸡胸肉里加入生抽", "加入黑胡椒", "加入生粉", "搅拌均匀腌制一会儿", "加入蔬菜拌匀", "弄成肉饼状", "不粘锅小火两面煎熟", "做好啦！", "营养低脂"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/6af9f5c430bd4e17abc0e29116deec7b_1864w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('嫩煎鸡胸肉', '肉类', '鸡胸', '', '[{"name": "一块鸡胸肉", "amount": "适量"}, {"name": "半勺盐", "amount": "适量"}, {"name": "黑胡椒粉", "amount": "1勺"}, {"name": "料酒", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "蒜末", "amount": "2勺"}, {"name": "淀粉", "amount": "1勺"}, {"name": "橄榄油", "amount": "5g"}, {"name": "清水", "amount": "50ml"}]'::jsonb, '["一块鸡胸肉对半横切成平均的两片，再用刀背轻轻拍松让其更松软更容易入味。", "鸡胸肉中加入半勺盐、1勺黑胡椒粉、3勺料酒、2勺生抽、2勺蒜末、1勺淀粉（淀粉是为了让肉更嫩，如果你是严格控可不加）搅拌均匀，腌制30分钟使其充分吸收。", "鸡胸肉弹嫩的关键：锅中倒入5g橄榄油中火烧热20秒，下腌好的鸡胸肉，两面各煎15秒左右使表面略微变色。", "接着倒入50ml清水，盖上盖子小火焖个2分钟左右至水分收干，转中火，两面各煎个20秒，至其表面呈金黄色。\n*用水汽焖熟鸡胸肉，肉质更嫩，鸡胸肉充分吸收水分而更加多汁。", "嫩煎鸡胸肉完成！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/52b19d3c6c9f4899ba05958dac7c6649_7952w_5304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超嫩的小炒鸡胸肉', '肉类', '鸡胸', '', '[{"name": "鸡胸肉", "amount": "1块"}, {"name": "4～5根杭椒", "amount": "适量"}, {"name": "姜", "amount": "1片"}, {"name": "3瓣大蒜", "amount": "适量"}, {"name": "料酒", "amount": "2勺"}, {"name": "淀粉", "amount": "1勺"}, {"name": "黑胡椒粉", "amount": "1小勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "小半勺盐", "amount": "适量"}, {"name": "适量花生油", "amount": "适量"}]'::jsonb, '["把鸡胸肉去膜切丁，加入小半勺盐，1小勺黑胡椒粉，加入2勺料酒，1勺生抽，1勺淀粉。拌匀，腌制10分钟左右。", "杭椒切丁，姜切丝，蒜切末。", "不粘锅里加入少量油（铁锅可以油适量多一点），热锅后放入腌制的鸡胸肉中火炒到刚断生，颜色变白就可以。成出来备用。", "重新放油热锅，加入姜丝和蒜末爆香，放入杭椒丁炒到断生，加入炒好的鸡胸肉进行翻炒，再加入一勺生抽，一勺蚝油，炒匀出锅。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/478256e6e6dd40c7b0b682dee68171dd_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('懒人版大鸡腿￨做法超级简单', '肉类', '鸡腿', '', '[{"name": "鸡腿", "amount": "5个"}, {"name": "葱", "amount": "15g"}, {"name": "姜", "amount": "15g"}, {"name": "蒜", "amount": "15g"}, {"name": "（2勺）生抽", "amount": "30ml"}, {"name": "（2小勺）老抽", "amount": "10ml"}, {"name": "（2勺）蚝油", "amount": "30g"}, {"name": "干辣椒", "amount": "6个"}, {"name": "花椒", "amount": "3g"}, {"name": "冰糖", "amount": "20g"}, {"name": "（2勺）料酒", "amount": "30ml"}, {"name": "水", "amount": "100ml"}]'::jsonb, '["鸡腿洗净，在鸡腿上划几刀，放入电饭锅中", "把所有的调料以此放入锅中", "再倒入100ml水（大概半碗），开启煮饭模式", "出锅，完成"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/f7d082977325401487c4e9491ec23ea4_1280w_853h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('照烧鸡腿饭', '肉类', '鸡腿', '', '[{"name": "鸡腿", "amount": "2只"}, {"name": "料酒", "amount": "1勺"}, {"name": "酱油", "amount": "2勺"}, {"name": "蜂蜜", "amount": "1勺"}, {"name": "各一勺黑椒碎黑椒粉", "amount": "适量"}, {"name": "盐小半勺", "amount": "适量"}, {"name": "西蓝花胡萝卜少许", "amount": "适量"}, {"name": "大半勺老抽", "amount": "适量"}, {"name": "大蒜生姜几片", "amount": "适量"}, {"name": "2～5勺清水", "amount": "适量"}]'::jsonb, '["鸡腿去骨加入黑胡椒粉胡椒碎盐姜片腌制五分钟", "碗里加入1勺料酒2勺生抽1勺蜂蜜大半勺老抽2～5勺清水拌匀", "蔬菜焯水煮熟捞起，热火放油放入大蒜爆香，放入鸡腿中小火煎至两面金黄，加入调好的酱汁，盖好盖子中小火焖十分钟左右熟透即可", "切件，和蔬菜一起摆在饭面，淋入煎鸡腿的酱汁就可以慢慢享用啦", "香味浓郁的黑椒酱汁+嫩滑的鸡肉，越吃越过瘾", "好好吃哇", "给块鸡肉你尝尝😄"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/6d20fcbee0d54677a634e0c80560a45b_1027w_822h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到飙泪的秘汁多汁蒜香鸡腿，鲜嫩到流口水。', '肉类', '鸡腿', '', '[{"name": "琵琶腿", "amount": "5个"}, {"name": "小葱", "amount": "2根"}, {"name": "适量蒜末", "amount": "适量"}]'::jsonb, '["1️⃣鸡腿洗净，正反面各划两刀方便入味。\r\n2️⃣腌制蒜香鸡腿👉🏻2勺蒜末➕ 小葱➕2勺料酒➕ 2勺生抽➕1勺老抽➕少许盐➕ 1勺蜂蜜➕适量黑胡椒➕1勺蚝油抓拌均匀腌制半小时。", "3️⃣油热鸡腿煎至两面金黄，淋入腌制剩余的料汁➕半碗开水没过鸡腿，大火煮开小火焖熟，收汁出锅。", "好吃不腻", "超级过瘾"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/57124c8992cb498fb7b7891024534a92_1242w_1654h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆好吃的卤鸡腿 卤蛋电饭煲 炒锅都可以做~', '肉类', '鸡腿', '辣', '[{"name": "鸡腿🍗", "amount": "4个"}, {"name": "鸡翅根", "amount": "2个"}, {"name": "水煮蛋", "amount": "4个"}]'::jsonb, '["操作如图", "操作如图", "操作如图", "操作如图", "汤汁泡一宿好好吃！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/74f807f20e7e41b4b544fb87505476ec_3024w_2417h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('手撕鸡腿', '肉类', '鸡腿', '', '[{"name": "鸡腿", "amount": "1只"}, {"name": "料酒", "amount": "1勺"}, {"name": "姜", "amount": "3片"}, {"name": "生抽", "amount": "3勺"}, {"name": "醋", "amount": "3勺"}, {"name": "5瓣蒜末", "amount": "适量"}, {"name": "香菜", "amount": "6根"}, {"name": "香油", "amount": "1勺"}, {"name": "糖", "amount": "1小勺"}, {"name": "葱", "amount": "3根"}, {"name": "半个柠檬", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}]'::jsonb, '["水里加料酒姜片 鸡腿过水煮熟。大概要20多分钟。", "碗里加调料。3勺生抽 3勺醋 一勺白糖 洋葱丁 蒜末 香菜 葱花", "鸡腿熟了要泡冰水里 凉了后就可以上手撕了", "撕好放入碗中  加入去了籽的半个柠檬 加1勺香油  吃辣的朋友可以加小米椒", "最后拌一拌就OK啦。好吃"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/5bb7bea8341c4dd2927f71c8c07344b2_828w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香辣烧鸡爪', '肉类', '鸡爪', '辣', '[{"name": "鸡爪", "amount": "500克"}, {"name": "适量小米椒", "amount": "适量"}, {"name": "各一个八角和桂皮", "amount": "适量"}, {"name": "一小块姜", "amount": "适量"}, {"name": "一至两勺酒酿汁", "amount": "适量"}, {"name": "一块冰糖", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "少许陈醋", "amount": "适量"}, {"name": "少许鸡精（可不放）", "amount": "适量"}, {"name": "适量葱花", "amount": "适量"}]'::jsonb, '["鸡爪洗净.剪掉指甲！", "如图每一个放案板上.刀放鸡爪中间部位上.最好是把它爪心朝上.因为这有肉..然后割一下.这样就不会打滑了.然后按着刀背往下压.鸡爪剁开了！伱要提起刀来剁..估计剁稀巴烂还剁不准.还蹦一身脏", "锅里放水.冷水把鸡爪放下去.再把八角和桂皮放入.姜块里面切二片放入.开火煮.", "煮沸后..继续煮5分钟左右.只有焯水透了.才能把鸡爪里面的异味去掉", "煮鸡爪时.把小米椒切段.生姜切丝.葱花切碎备用！（葱花我放另外菜板切了.不能和生东西同菜板）", "煮好的鸡爪..捞出.凉水彻底清洗干净..", "锅里放油.放入冰糖.烧至冰糖全部融化.", "变色冒小泡泡时.放入鸡爪翻炒上色..", "上色后..放入小米椒.姜丝翻炒..", "然后把酒酿汁放入（根据自己口味放.不要一次加太多.后面可以尝味道的.不够再加！）如果没有酒酿.就直接用一罐啤酒烧.也好吃的", "再放生抽.陈醋（不用超过一勺就行）白胡椒粉下去翻炒！", "然后放开水下去.煮沸后转中小火..（如果没有酒酿用啤酒的.这里可以把开水换成啤酒.我这个图片里面的就是放了半罐啤酒代替水的）", "收汁到一半时候.放盐..然后开大火收汁（这一步关键到成品色泽好看不好看）最后一分钟能看见颜色越来越深..越来越亮！", "收汁到自己想要的程度.关火.放鸡精（可不放）搅拌均匀..", "撒上葱花就可以吃了！！"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/b4cfc1124ac411e7bc9d0242ac110002_1616w_1081h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('柠檬凤爪', '肉类', '鸡爪', '辣', '[{"name": "一斤鸡爪", "amount": "适量"}, {"name": "两勺香油", "amount": "适量"}, {"name": "姜", "amount": "5片"}, {"name": "适量小米椒", "amount": "适量"}, {"name": "200毫升米醋", "amount": "适量"}, {"name": "少许料酒", "amount": "适量"}, {"name": "柠檬", "amount": "1个"}, {"name": "两瓣蒜", "amount": "适量"}, {"name": "200毫升生抽", "amount": "适量"}, {"name": "一颗香菜", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["1、生鸡爪洗净剪掉指甲，切成小块方便入味（我是把每个鸡爪切成三块），小米椒切碎，蒜切块，柠檬切片，香菜切段备用。", "2、锅内冷水加入鸡爪，料酒，姜片，开锅后煮7～8分钟，捞出放入冰水中冷却，这样会让鸡爪有脆脆的口感", "3、取一个大碗放入米醋200毫升，陈醋少许，生抽（味达美）200毫升，白糖根据口味添加，香油，加入蒜，倒入少量料酒或白酒", "4、待鸡爪全部冷却后，控干水分，放入调制好的酱料中，加入切好的小米椒，柠檬片（去皮），香菜段，包上保鲜膜放入冰箱，五六个小时就可以全部入味，就可以食用，每次吃完再用保鲜膜封起来放入冰箱。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/e322e3497ac7418f9c3f49263d33fa58_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('柠檬酸辣鸡爪自制超级无敌美味的网红鸡爪', '肉类', '鸡爪', '辣', '[{"name": "鸡爪", "amount": "12只"}, {"name": "柠檬", "amount": "1个"}, {"name": "小米椒", "amount": "6个"}, {"name": "细青椒", "amount": "2个"}, {"name": "洋葱", "amount": "0.5个"}, {"name": "姜", "amount": "5片"}, {"name": "6瓣蒜", "amount": "适量"}, {"name": "香葱", "amount": "1根"}, {"name": "生抽", "amount": "8勺"}, {"name": "醋", "amount": "6勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "芝麻油", "amount": "2勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "糖", "amount": "1小勺"}, {"name": "料酒", "amount": "2勺"}]'::jsonb, '["鸡爪剪掉指甲（可以让卖鸡老板帮忙剪掉）材料如图备齐", "鸡爪一分为三或四", "冷水入锅，下入鸡爪，放1小勺盐，两勺料酒，一颗葱，几片姜片去腥。大火烧开沸腾后煮12分钟，", "焯水期间，把葱姜蒜辣椒切碎，洋葱切丝，柠檬切片去籽。", "捞出冷水冲洗干净，放在凉白开中浸泡（我加了冰块，口感会更有嚼劲）", "取一个大碗生抽8勺，蚝油1勺，香醋6勺，芝麻香油2勺，1小勺盐，", "加1小勺糖，放在大碗里混合均匀备用", "冷却后的鸡爪放在调料汁的碗里翻拌均匀", "放入所有的葱 姜 蒜 柠檬片  洋葱 辣椒搅拌均匀，包上保鲜膜放冰箱冷藏至少两个小时，期间翻动几次，以便更入味。", "完成，开吃，一个人一盘根本不够好吗？😄"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/67fa71291fcd4fefb1cbf244e465cc67_1124w_1500h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“销魂”卤鸡爪', '肉类', '鸡爪', '', '[{"name": "鸡爪", "amount": "500g"}, {"name": "6瓣大蒜", "amount": "适量"}, {"name": "生姜", "amount": "2块"}, {"name": "辣椒", "amount": "2个"}, {"name": "料酒", "amount": "5勺"}, {"name": "红烧汁", "amount": "3勺"}, {"name": "冰糖", "amount": "1块"}, {"name": "少许盐", "amount": "适量"}, {"name": "米醋", "amount": "5勺"}, {"name": "生抽", "amount": "5勺"}, {"name": "2-3勺蚝油", "amount": "适量"}]'::jsonb, '["鸡爪剪去指甲洗净备用。", "冷水锅放入姜片和少许盐加入料酒焯水约6分钟。", "过冷水二次清洗。", "配料：带皮大蒜、姜块、辣椒。", "锅里倒入少许油下生姜大蒜炒香。", "下鸡爪和辣椒（辣椒被掩盖了）过油表层微微起皱。这里敲重点：鸡爪一定用厨房纸巾拭干水分，锅里中小火低温翻炒（预防油溅）。一旦无法避免的发生油溅事故（厨房如战场），请及时勇敢的拿起锅盖当盾牌，保护好自己嗷！", "下蚝油、生抽、红烧汁炒出酱香味。左上角可看到辣椒的“身影”。", "下料酒去腥入味。", "加入适量清水下一块冰糖。大火煮沸转小火焖煮约35-40分钟。", "慢慢收汁后加入“米醋”灵魂深处的一抹酸爽，绝对提味。", "边看电视边吃爪爪一盆立马消灭殆尽！！无敌我胃！带皮大蒜也是灵魂所在嗷，吸饱了精华酱汁软糯嫩滑，轻轻一吸，回味无穷啊！", "太多朋友留言问我红烧汁了，干脆拍张图片给大家做个参考吧😘，一般各大超市都有售，家里没有红烧汁可以用老抽替代。", "太多厨友询问勺子大小，就家常普通的瓢羹，从自己其他菜谱借用一下，请忽略图片背景与鸡爪不符，哈哈哈😄…大家参考吧！", "还有厨友们留言问我家的锅子，“臻三环”铸铁双耳锅，厚底薄边34cm。好用的土式老锅，纯属个人实用分享，不打广告！哈哈哈😄…", "一直习惯叫米醋，因为是大米小麦天然发酵的，今天应厨友要求拍照片才发现，名字叫“同康香醋”，尴尬了😅！这是我们台州本土品牌，台州人惯用的。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/a2ca37e9088a43e4b83ecc0abc9a6881_814w_748h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('绝对不会后悔的酸辣鸡爪', '肉类', '鸡爪', '辣', '[{"name": "鸡爪", "amount": "10只"}, {"name": "生姜", "amount": "3片"}, {"name": "料酒", "amount": "2勺"}, {"name": "1颗🧄大蒜", "amount": "适量"}, {"name": "🌶️辣椒", "amount": "10个"}, {"name": "盐", "amount": "1大勺"}, {"name": "🍋柠檬", "amount": "1个"}, {"name": "冰糖", "amount": "1把"}, {"name": "半碗生抽", "amount": "适量"}, {"name": "蚝油", "amount": "2勺"}, {"name": "米醋", "amount": "2勺"}, {"name": "陈醋", "amount": "5勺"}, {"name": "白糖", "amount": "1勺"}, {"name": "芝麻香油", "amount": "2滴"}]'::jsonb, '["鸡爪泡出血水，对半切开。然后凉水上锅，加入料酒，生姜，水开后盖上盖子大火煮8到10分钟。（觉得没熟透的，可以中火煮20分钟，自己觉得怎么好怎么来，菜谱只是参考）PS: 鸡爪煮太久容易煮烂，没嚼劲。", "将鸡爪倒出过冷水，反复冲洗几次，把鸡爪的胶质洗干净，直到水变得干净清澈。 （这步讲究的人，建议用烧开晾凉的凉白开或者矿泉水） 不要再吐槽了！ 还是觉得不卫生，那大可以不吃了呗…… 想特别请问一下，你们平时吃水果蔬菜也是用凉白开清洗的嘛？", "然后泡点水，放冰箱冷藏2小时。", "大蒜和辣椒放入搅拌机，快速搅打几下成大颗粒状。", "辣椒蒜蓉里面挤入柠檬汁，加一大勺盐，1把冰糖，搅拌至冰糖稍微融化，然后静置腌制2小时。（柠檬🍋柠檬🍋柠檬🍋在这里使用的！别再跟我说看了几遍没看见柠檬到底在哪里！）", "这是腌制2小时的状态，冰糖差不多融化完了，辣椒酱出味儿，现在闻着就很下饭了！", "辣椒酱里倒入小半碗生抽，2勺蚝油，少许白醋，适量陈醋，2滴芝麻香油，搅拌均匀。", "冰箱里的鸡爪，取出，滤水。 然后倒入辣椒酱，充分搅拌均匀，放入冰箱继续冷藏24小时。如果着急吃，冷藏2小时也是可以的……只要你觉得鸡爪够味儿了！", "超开胃！一个人没事的时候绝对不要做这个，会吃到没完没了，停不下来的！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/d5464cd3cbfa4e91ac7eaa4459fc119c_2592w_1728h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最简单的鸡肉做法——家常生炒鸡', '肉类', '鸡肉', '辣', '[{"name": "几根葱", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "3-5瓣蒜", "amount": "适量"}, {"name": "少许（可忽略）甜椒", "amount": "适量"}, {"name": "半只鸡", "amount": "适量"}, {"name": "一勺料酒", "amount": "适量"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "半勺盐", "amount": "适量"}, {"name": "特级生抽", "amount": "2勺"}, {"name": "一勺耗油", "amount": "适量"}]'::jsonb, '["鸡肉切块洗干净控干水分（不控干水分炒出来不好吃）。蒜姜切块，我喜欢蒜的味道，所以弄多一倍的量，葱最好用小葱切断，我这是大葱所以切丝。甜椒是点缀颜色好看，切颗粒（没有就算了）。如果你喜欢吃辣可以换成小米椒，切小段。", "油热下蒜姜颗粒炒香，然后下鸡肉翻炒。", "炒到鸡肉变色了，加入料酒（沿锅边下），炒到酒精挥发以后，加入生抽，耗油，胡椒粉继续翻炒", "炒一会以后加入一小碗水（大概如图的量，别多了），加盖小火15分钟。中途开盖翻炒一下。", "开盖大火收汁，加入少许盐（因为加了生抽和耗油了，盐适量），点缀的红椒（或小米椒），翻炒2下，最后加入葱。搞定。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/46b9ce442d0545149dcc9c69cea93867_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧鸡块没朋友版，超级下饭', '肉类', '鸡肉', '', '[{"name": "鸡腿", "amount": "8只"}, {"name": "干辣椒", "amount": "3个"}, {"name": "八角", "amount": "2个"}, {"name": "15粒花椒", "amount": "适量"}, {"name": "姜", "amount": "3片"}, {"name": "半根大葱", "amount": "适量"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "半勺蚝油", "amount": "适量"}, {"name": "冰糖", "amount": "20克"}]'::jsonb, '["大葱切斜段，干辣椒切段，生姜切片，蒜切块。", "1勺豆瓣酱。", "鸡腿切块，开水锅中过一下。", "热锅倒油，七成热放入葱、姜、蒜、干辣椒。", "放入一勺豆瓣酱，小火炒香。", "炒至颜色均匀。", "倒入鸡块，沿锅边调入生抽、老抽。", "炒匀，放入2个八角，15粒花椒。", "加入冰糖，半勺蚝油。", "稍微炒一下，倒入开水，淹过鸡块。小火炖半个小时。根据口味加入适量盐，搅匀，大火收汁出锅。", "撒一点葱花，装盘。"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/5a08b3f9149b41dfa27dcca5d0ac6205_3368w_2695h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('鸡腿炖土豆 上桌秒空盘 汤都喝干了！', '肉类', '鸡肉', '', '[{"name": "鸡腿", "amount": "1只"}, {"name": "土豆", "amount": "1个"}, {"name": "姜", "amount": "5片"}, {"name": "生抽", "amount": "5勺"}, {"name": "若干葱", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "干辣椒", "amount": "3个"}, {"name": "两勺糖", "amount": "适量"}, {"name": "一个八角", "amount": "适量"}, {"name": "没有可不放香叶", "amount": "适量"}]'::jsonb, '["鸡腿一只，如果家里人多可以两只。\n切块，加入料酒三勺姜五片腌制十分钟左右去腥。", "凉水下锅，煮开即可捞出，这一步是去血水和浮沫。", "煮的时候姜片也丢进去，煮开马上捞出来，否则鸡肉太柴，煮出的有浮沫水倒掉。", "炒糖色。中火，油五成热，倒入两勺糖，炒到有点冒烟，放入鸡腿。\n\nPS：刚才捞出的鸡腿控干水分，如果没控干，倒锅里的时候注意迸溅。", "这个是炒糖色的过程，一定要不停翻炒，以免糊锅。", "炒到这个程度基本差不多了。", "接着倒入葱段和干辣椒一起再炒一分钟。", "加入开水和土豆块。没过鸡腿。\n\nPS：一定是热水，不要凉水，否则热的鸡腿遇到凉水，马上收缩，最后吃起来肉很紧很柴。", "+五勺生抽\n+一个八角\n+香叶两片【没有可不放】", "大火烧开，撇去浮沫，转中火炖15分钟。", "尝尝咸淡，淡了用盐调整，咸了少加一丢丢水。\n\n大火收汁，留一小碗汤汁为最佳，水太多像泡着一样，影响口感。", "开始享用吧！土豆软糯，鸡腿Q弹，汤汁浓郁，不好吃你来找我！"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/b9a0036514ec4b05a39120c061a99560_1024w_768h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小鸡炖蘑菇(注意一步操作就香气沁人)', '肉类', '鸡肉', '', '[{"name": "鸡肉：1000克", "amount": "适量"}, {"name": "干香菇：50克", "amount": "适量"}, {"name": "八角：3克", "amount": "适量"}, {"name": "干红辣椒：6个", "amount": "适量"}, {"name": "大葱：20克", "amount": "适量"}, {"name": "生姜：20克(分两次用)", "amount": "适量"}, {"name": "盐：13克左右", "amount": "适量"}, {"name": "生抽：20克", "amount": "适量"}, {"name": "老抽：5克", "amount": "适量"}, {"name": "耗油：10克", "amount": "适量"}, {"name": "食用油：适量", "amount": "适量"}, {"name": "料酒：20克(分两次用)", "amount": "适量"}, {"name": "白糖：17克", "amount": "适量"}]'::jsonb, '["我这次的是从京东生鲜上买的一家知名品牌冷冻土香鸡(其他鸡也可以)，提前从冰箱里拿出来自然解冻，解冻后清洗干净，剁掉鸡屁股和鸡脚指备用。", "把干香菇清洗干净，用1300毫升的凉水提前3个小时泡上", "把清洗干净的鸡剁成小块，放入锅内，倒入凉水，再加入12克姜片和10克料酒，大火烧开后，打开锅盖，撇去浮沫，开着锅盖焯水1分钟捞出控干水分（开着锅盖焯水有利于腥味散出）。", "这是水开后的状态，还是会有很多浮沫的，把浮沫撇去。", "这是撇去浮沫后是不是就好多了呢！", "鸡肉焯水后捞出控水备用（上图焯过水的鸡肉）。", "1、把泡好的香菇捞出控水备用。\n2、把泡香菇的水烧开，撇去水里浮沫备用（泡香菇的水图片省略了）。", "炒锅里加入适量食用油，把葱段、八角、干红辣椒段和8克姜片倒入锅内炒出香味。", "倒入鸡块先翻炒片刻，再沿着锅边转圈倒入10克料酒(利用料酒遇热锅底蒸发去腥味提鲜)，翻炒几下，然后再倒入老抽、生抽、耗油、白糖、盐继续翻炒两分钟左右。", "上图是倒入所有调味料翻炒片刻后的状态", "加入1000毫升左右泡香菇的热开水(水的多少如图状态淹没过鸡肉就行，这个加水量只是参考），再加入香菇，盖好锅盖就开始炖了，大火烧开后转小火炖，只要锅内始终保持沸腾状态就可以了。\n\n注：如果加粉条的话，就需要多加水，粉条提前用凉水泡软，最后5分钟加入炖入味即可！加粉条的话，配方中的各种调味品都需要相应再增加用量。", "上图是炖了35分钟打开锅盖沸腾中的状态，可以收汤汁也可以不收汤汁(这只鸡肉嫩，只炖了35分钟鸡块就完全熟了，如果是真正的土鸡需要炖1个半小时左右才可以，也就需要往锅里相应多加些水了，注意一次要把水加够，中途不加水)。\n        出锅前加入适量鸡精、淋入适量的芝麻香油、撒上适量小香葱搅拌即可出锅装盘了！菌香四溢，肉香味鲜，属于香而不腻的一道美味！", "最后锅里汤汁留多少根据喜好定，有时汤汁留的多，有时留汤汁留的少，随喜好来（应该撒小香葱更好卖相也会更漂亮，可惜家里没有小香葱就只好切了片大葱叶子来点缀一下了）。\n          出锅前品尝一下咸淡，淡了就加盐，咸了汤汁就多留些。终于记录完了，写菜谱真的是好费眼睛啊！\n       (拍照技术太拙，菜谱封面对不起味道，口感是王道，理解万岁)。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/e9d57ca13e2544fd8836576c69600d4e_1280w_959h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常黄焖鸡', '肉类', '鸡肉', '', '[{"name": "鸡腿", "amount": "4只"}, {"name": "土豆", "amount": "1个"}, {"name": "8-10朵香菇", "amount": "适量"}, {"name": "各1个青红椒", "amount": "适量"}, {"name": "10瓣大蒜", "amount": "适量"}, {"name": "姜", "amount": "1块"}, {"name": "适量料酒", "amount": "适量"}, {"name": "冰糖", "amount": "10克"}, {"name": "适量蚝油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量黄豆酱", "amount": "适量"}, {"name": "适量花椒", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "香叶", "amount": "1片"}]'::jsonb, '["鸡腿洗净切块 \n香菇切块\n土豆去皮切丁\n青红椒切片，姜蒜切片", "鸡腿肉冷水下锅，放料酒，姜片焯水", "煮出血沫后捞出控干水分，放一旁备用", "锅中放适量油放入冰糖", "待冰糖慢慢溶化后 小火炒至枣红色", "放入鸡腿肉翻炒，把姜蒜也放进来，花椒八角香叶也放进来，喜欢辣的可以放几片干辣椒", "放入生抽蚝油，两勺黄豆酱 翻炒", "然后把香菇土豆丁放进来，再放入少许盐，翻炒均匀", "倒入砂锅，兑入没过食材的开水", "煮开后盖上盖子，中小火闷煮10分钟左右（期间可打开盖子，翻动翻动，以免糊底）", "看看土豆熟了，鸡肉也就熟了，起锅前放入青红椒", "哇哦！好吃的不得了，最后连汤汁都舍不得倒掉，用来泡米饭又是一顿，其他的菜都省了"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/36ed1b59702645668564b083e1d89770_716w_615h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('姜爆乌鸡', '肉类', '乌鸡', '', '[{"name": "乌骨鸡", "amount": "1只"}, {"name": "麻油", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "生姜", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "白芝麻", "amount": "适量"}]'::jsonb, '["乌骨鸡洗净，斩块，斩完的鸡肉块不能太大，爆完的鸡的残缺小肉末肉块最香了，内脏可根据个人喜好决定放不放，爆了的内脏也超香", "姜切丝，要大量，基本能铺满锅底的程度", "热锅，入麻油，切记这里不能用别的油，否则味道会大打折扣，麻油量较多，基本可以铺满锅底的程度", "大火热油，五成热时就可以放入姜丝爆香", "姜丝爆香到金黄逐渐微焦的时候，下鸡块，迅速翻炒", "将鸡块翻炒到变色表面微焦六七成熟的时候，如果鸡肉渗水出来，将水倒掉，并再倒入适量麻油，如果几乎没有渗水，倒入大量料酒，不用没过所有鸡块，但要没过四分之三的程度，翻炒几下", "加入适量生抽和盐，不要加老抽，本来就是乌鸡了…………大火收汁，收的过程中自己尝下咸淡，口味比较重的可以酌情再加入生抽或盐", "四分之三的料酒收到只剩四分之一的程度时，要开始不停翻炒，这道菜需要把汁收得很干，不经常翻炒的话很容易粘锅烧焦", "收汁翻炒到几乎没有时，以鸡肉爆炒到肉质收缩金黄微焦为佳，关火起锅摆盘", "最后在鸡肉上撒点白芝麻，开吃，爆炒过的内脏鸡肉末和生姜超香"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/510050c2a6da11e6947d0242ac110002_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('山药红枣乌鸡汤', '肉类', '乌鸡', '', '[{"name": "乌鸡", "amount": "1只"}, {"name": "半根山药", "amount": "适量"}, {"name": "8颗红枣", "amount": "适量"}, {"name": "姜", "amount": "5片"}, {"name": "葱", "amount": "2根"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["乌鸡洗净斩成大块，红枣浸泡，葱姜切好。", "乌鸡凉水下锅开锅焯水5分钟。", "焯水后用热水洗净乌鸡的浮沫，沥干。", "开水下锅，入乌鸡、葱姜、料酒、红枣，大火烧沸10分钟，转小火慢炖。", "山药去皮洗净，切成滚刀块。当汤炖至1个小时后加入山药，继续文火慢炖1个小时加盐调味即可。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/fdc1cf0a440211e7bc9d0242ac110002_909w_975h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('乌鸡双菇汤（儿童也能喝的元气汤）', '肉类', '乌鸡', '', '[{"name": "半只乌鸡", "amount": "适量"}, {"name": "6朵鲜香菇", "amount": "适量"}, {"name": "适量白玉菇（可换成其他新鲜菇）", "amount": "适量"}, {"name": "姜（晚上少放）", "amount": "3片"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "半根大蒜叶或葱（可不加）", "amount": "适量"}, {"name": "盐", "amount": "1克"}]'::jsonb, '["沙煲放一点油，放入洗净的乌鸡，大火翻炒至肉熟，加姜", "加水（水量可以多一点，因为是明火和需要撇血沫），加胡萝卜（最好撇血沫后加），加盖，大火烧开", "撇血沫前", "撇干净后，加盖，中火烧15分钟，期间，去整理菇类", "菇类洗净切好", "此时水量正好降低了", "加入菇，大火烧开后，小火煲25分钟（则烧开后一共煲了40分钟）", "关火，加盐，汤好！（不想要绿色的，可跳过下一步）", "加大蒜叶或者葱（加不加随意哦亲）", "迫不及待吃起来，小心烫哦", "骨髓都吃了", "再来一碗，满足"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/b72c75922b4d4c6cb991ea71bfd4aedc_4002w_3002h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('调经补气血-乌鸡汤四物汤', '肉类', '乌鸡', '', '[{"name": "半只乌鸡", "amount": "适量"}, {"name": "当归", "amount": "10g"}, {"name": "川芎", "amount": "10g"}, {"name": "熟地", "amount": "10g"}, {"name": "白芍", "amount": "10g"}, {"name": "红枣", "amount": "10g"}, {"name": "枸杞", "amount": "10g"}]'::jsonb, '["先把鸡肉洗好备用（药材我是去药店买，说要半只鸡的量，药剂师会看着给配的，四物汤-或者按照我上面写的买也可以）", "准备好食材，接下来就是焯水\n炖汤我都习惯把肉放锅里焯水后再炖汤", "冷水下锅后放入鸡肉、药材，开大火炖，煮开了之后转小火慢炖，炖个2小时的样子，药效差不多可以炖出来", "起锅时我会放一点点盐巴（放一点冰糖改善一下口感）很简单的养生汤，空了可以自己动手做一做"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/5a4702e969f6496bb5e4eb2ae49b7b15_828w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('三杯鲍鱼乌鸡', '肉类', '乌鸡', '', '[{"name": "乐扣乐扣baum麦饭石色不粘锅", "amount": "1只"}, {"name": "半只乌鸡（肉多的哦）", "amount": "适量"}, {"name": "8-10只鲍鱼", "amount": "适量"}, {"name": "九层塔", "amount": "1把"}, {"name": "8瓣大蒜", "amount": "适量"}, {"name": "姜", "amount": "8片"}, {"name": "30毫升黑麻油（芝麻油、香油）", "amount": "适量"}, {"name": "30毫升台湾米酒（或料酒）", "amount": "适量"}, {"name": "（约15毫升）生抽", "amount": "4勺"}, {"name": "（约8毫升）老抽", "amount": "2勺"}, {"name": "约5-8克冰糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "3-5个干辣椒（可无）", "amount": "适量"}, {"name": "适量料酒（腌制鸡肉和鲍鱼用）", "amount": "适量"}]'::jsonb, '["准备好所有的食材，乌鸡选肉多一点的更好吃哦。黑麻油和九层塔一定少不了啦～当然还要有一口不粘性能极强的炒锅～我用的是乐扣乐扣baum麦饭石色不粘锅。", "大蒜轻拍，姜切大片，鲍鱼切花刀备用。", "乌鸡切快，鲍鱼准备好，加适量料酒和姜片冷藏腌制15-20分钟，我喜欢放入乐扣乐扣保鲜盒中冷藏，密封效果好，存放味道大的东西也不会串味，玻璃材质用着也更放心。然后将乌鸡焯水，捞出沥干备用。", "锅中放入黑麻油，用芝麻油也行，开小火，放入姜片，煸炒到香气四溢，稍干，边缘稍金黄。", "加入蒜瓣和葱段翻炒，如果喜欢辣味，也可以加一些干辣椒一起翻炒。", "加入沥干水分的鸡块开中大火翻炒到3分钟左右。", "然后加入米酒、生抽老抽和冰糖继续翻炒3分钟左右。", "然后加入一小碗水，盖上锅盖，中小火焖煮10分钟，让鸡肉入味。", "再加入鲍鱼继续小火盖上锅盖焖煮10分钟，这样鸡肉更入味，鲍鱼也不会煮过头而口感变老。", "炖煮结束后开盖，开中大火收汁，将汤汁收浓，这个过程可以适当加盐调味，一点点盐就足够啦。最后汤汁收浓变得粘稠，在乐扣乐扣不粘炒锅里也翻动自如哦，完全不用担心糊锅的问题。", "收汁快OK的时候加入一把九层塔，快速翻炒即可出锅，香喷喷呢～一起开动吧！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/8891f73906a74dc79abb1ec0867c0f7d_2000w_1333h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小米椒爆鸡胗', '肉类', '鸡胗', '辣', '[{"name": "小米椒", "amount": "适量"}, {"name": "鸡胗", "amount": "适量"}, {"name": "大蒜", "amount": "适量"}, {"name": "盐，生抽，黄酒", "amount": "适量"}]'::jsonb, '["鸡胗冷水下锅，煮变色了捞起切片。第一次做我看网上都说要尽可能切薄，结果做出来我发现太薄了爽口的口感都快出不来了，突然明白为何在外吃到的鸡胗要切花——一来好看，二来容易熟又保持了爽口感。如图介绍两种切法。", "切好的鸡胗加盐加黄酒加生抽腌制半小时以上。", "大蒜切成蒜蓉，小米椒切小段备用。", "炒锅下油，然后放入蒜蓉和小米椒中火热香，下鸡胗炒，因为腌制过，就不用再放调料啦。一直炒到鸡胗熟透了，就可以上菜啦！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/620f8db687f311e6b87c0242ac110003_915w_606h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒鸡胗', '肉类', '鸡胗', '辣', '[{"name": "适量鸡胗", "amount": "适量"}, {"name": "10瓣蒜", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量线辣椒", "amount": "适量"}, {"name": "三粒八角", "amount": "适量"}]'::jsonb, '["鸡胗、八角、干红辣椒清洗干净，蒜切成蒜粒，线辣椒（泡椒）切好备用。", "鸡胗，八角，干红辣椒放在凉水锅里煮，煮到鸡胗变色后，再煮五分钟捞出。", "鸡胗切成小片，（炒的时候容易入味）放料酒，生抽，适量盐，腌够三十分钟，中间搅拌一次。", "热锅凉油，等油热了，放入切好的蒜粒，线辣椒（泡椒），进行爆炒，香味出来后，放入鸡胗，继续爆炒，最后根据味道，加一点盐，出锅。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/f41ff452548a11e7947d0242ac110002_1504w_2000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('巨好吃的青椒炒鸡胗', '肉类', '鸡胗', '', '[{"name": "鸡胗", "amount": "6个"}, {"name": "青椒", "amount": "3个"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "料酒", "amount": "2勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "适量油，盐，蚝油，胡椒粉", "amount": "适量"}]'::jsonb, '["材料如图所示，用了两个红辣椒，吃辣的可以增加数量", "鸡胗洗净，冷水入锅，加入料酒姜片，煮开后捞出鸡胗洗净，冷却后切薄片备用", "青椒洗净去籽切条备用，葱姜蒜切好备用", "锅内倒入适量油，油热加入葱姜蒜炒香，加入鸡胗，1勺生抽，一勺蚝油一起翻炒均匀，刚入锅的鸡胗还是有点粉色的。", "翻炒至鸡胗变色加入青椒一起翻炒至青椒断生", "这时候就可以调味出锅啦", "好了，装盘！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/5c1451935b4d46b69e2bd09803a26c43_752w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('烧烤鸡胗', '肉类', '鸡胗', '', '[{"name": "鸡胗", "amount": "500克"}, {"name": "葱", "amount": "1根"}, {"name": "姜", "amount": "3片"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "半勺盐", "amount": "适量"}, {"name": "糖", "amount": "1勺"}, {"name": "烧烤料", "amount": "2勺"}, {"name": "辣椒粉", "amount": "1勺"}, {"name": "适量白芝麻", "amount": "适量"}]'::jsonb, '["鸡胗洗净如图对半切开", "热油放改好的刀的鸡胗", "中火炸到金黄色捞出控油备用", "另起一锅放油，放葱姜蒜炒香", "倒入鸡胗，加料酒翻炒均匀", "加入半勺盐，1勺糖提鲜，2勺烧烤料，1勺 辣椒粉", "继续翻炒出香味", "关火，撒白芝麻，小葱花", "翻拌均匀盛出~", "非常好吃的烧烤味的鸡胗就做好了~"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/357631121cae4eb98493145a35139749_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('下饭菜•爆炒鸡胗花', '肉类', '鸡胗', '辣', '[{"name": "匙酱油       2", "amount": "适量"}, {"name": "瓣蒜     6", "amount": "适量"}, {"name": "小片姜片     6", "amount": "适量"}, {"name": "根香芹      4", "amount": "适量"}, {"name": "匙料酒  1", "amount": "适量"}, {"name": "只鸡肾       10", "amount": "适量"}, {"name": "勺盐      1", "amount": "适量"}, {"name": "个红青椒    5", "amount": "适量"}, {"name": "块沙姜     2", "amount": "适量"}]'::jsonb, '["主配料齐全", "炒鸡什配菜：香芹切段，红椒青椒切片，香葱切段。", "切什花的确适合技术活，所以直接拍视频算了。", "把切好的鸡肾花，倒入少许米酒和盐拌匀十分钟，等锅里水开倒入绰水，鸡肾变色立马捞起，时间千万不要久了，太久老了炒出来不好吃", "绰过水的鸡什花，漂亮！", "鸡什花花调味：加入料酒，蚝油，生抽，香油，胡椒粉拌匀入味30分钟", "拌好入味的什花", "炒鸡什我一般都用菜籽油，去腥炒出来更香，油热放几颗白胡椒，倒进鸡什大火爆炒两分钟，家里有酒糟的话倒两匙酒糟水（或米酒或料酒），把配菜倒入翻炒两分钟，欠汁倒入收汁起锅。", "这道菜真的让人食欲满满！今晚忍不住想要添饭！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/667cc22249854caf8b8160e11c5dddaa_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小巷深处的美味—徐州小土鸡', '肉类', '土鸡', '辣', '[{"name": "半只肉鸡", "amount": "适量"}, {"name": "一把小米椒", "amount": "适量"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "适量葱姜蒜、香菜", "amount": "适量"}, {"name": "一个八角", "amount": "适量"}, {"name": "适量料酒、老抽", "amount": "适量"}, {"name": "适量油、盐、糖", "amount": "适量"}]'::jsonb, '["鸡剁块，并用温水清洗干净，不用焯水（这样鸡的味道比较香），彻底沥干水分备用。", "小米辣切丝，干辣椒剪碎，葱姜蒜、香菜切好备用。", "锅烧热后下油，直接倒干辣椒、葱姜和八角以及一半的蒜、煸香（一定要煸出香味来），再倒入鸡块不停煸炒。", "等到鸡肉煸炒至发白发紧，倒入料酒继续煸炒，把鸡肉的腥气炒出来。我家做菜喜欢用这种土绍酒或白酒代替料酒，土法酿制比较醇香。", "加入老抽继续翻炒，再加入盐、糖继续翻炒，再盖上锅盖中火焖5分钟左右。", "开盖继续翻炒，再加入剩下的一半大蒜、小米辣丝、香菜丝一起继续翻炒。", "等到这些蔬菜熟了就可以出锅享用了"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/e32b0e5689de11e6b87c0242ac110003_1080w_1616h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('铁锅土鸡炖榛蘑', '肉类', '土鸡', '', '[{"name": "土鸡", "amount": "1只"}, {"name": "榛蘑", "amount": "300克"}, {"name": "3-4个八角", "amount": "适量"}, {"name": "适量花椒", "amount": "适量"}, {"name": "适量葱姜蒜末", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一小勺高度白酒", "amount": "适量"}, {"name": "一小勺醋", "amount": "适量"}]'::jsonb, '["榛蘑提前两小时用凉水泡开", "剪干净干部杂质", "洗干净，我洗了四次", "撕成大块备用", "土鸡剁适当大小块，开水过一遍，捞出备用。\n锅内加油100毫升，油热后倒入鸡块，开始大火炒，约十分钟，加入葱姜蒜末，酱油，白酒，醋，大料，花椒，炒匀，加水炖，水要加足，没过鸡块十厘米，盐适量加入，喜欢吃辣的朋友，可以放些干辣椒一起炖，放入备好的榛蘑，中火一个半小时，收汤，出锅。", "榛蘑吸油，这样炖出来的鸡肉不油腻，肉香而烂，蘑菇非常好吃，胜过肉的味道。\n这个菜不怕剩，分装好每次热一盘，和新做的一样。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/640f0982ed354d9380b4a0e3eb674de0_640w_512h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('茶树菇土鸡汤', '肉类', '土鸡', '', '[{"name": "茶树菇", "amount": "500克"}, {"name": "半只土鸡", "amount": "适量"}, {"name": "4颗红枣", "amount": "适量"}, {"name": "葱", "amount": "1根"}, {"name": "姜", "amount": "5片"}, {"name": "10粒枸杞", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许花椒", "amount": "适量"}]'::jsonb, '["准备买新鲜的茶树菇 太晚了没买到 用了干茶树菇 用开水泡一个小时 去掉根部 准备半只土鸡 一根葱 5片姜片", "先用热锅 放少许油 加入姜片 香味之后 放入鸡块 爆炒 鸡块表面黄色之后 关火 加入砂锅 放入茶水菇 红枣几颗 放入姜片和花椒 ➕水（根据人多人少放水，千万不要中途加水）", "大火加入40分钟 烧开之后转入小火一个小时左右 收汁加葱花放枸杞加少许盐", "新鲜美味的鸡汤出来了 两个人全喝光了 连鸡块都吃完了 朋友说好喝！！哈哈哈 开心"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/5e73bbcdfd6e48c2bd68b50ceee825a3_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('厨师长教你：“爆炒土鸡”的家常做法，只需油盐酱醋，味道非常赞', '肉类', '土鸡', '', '[{"name": "半只黑皮土公鸡", "amount": "适量"}, {"name": "大蒜", "amount": "40克"}, {"name": "几根二荆条", "amount": "适量"}, {"name": "小米辣", "amount": "40克"}, {"name": "大葱", "amount": "2根"}, {"name": "1小块仔姜", "amount": "适量"}, {"name": "适量熟菜籽油", "amount": "适量"}, {"name": "适量食用盐", "amount": "适量"}, {"name": "老抽", "amount": "2克"}, {"name": "生抽酱油", "amount": "10克"}, {"name": "少许白糖", "amount": "适量"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "少许晒醋", "amount": "适量"}]'::jsonb, '["首先我们准备黑皮土公鸡半只\n将土鸡剁成几大块之后再剁掉鸡屁股", "然后去掉指甲之后将鸡肉剁成小块备用\n同学们最好剁小块一些这样更容易爆炒和入味", "最后我们在处理鸡脖子的时候将鸡皮扯下来", "然后将吸附在鸡皮表面的淋巴清除干净\n鸡脖上面的淋巴不分家养或者养殖都会有\n所以我们在处理鸡脖子的时候必须认真仔细检查一遍", "将鸡头剁好之后下一步开始准备辅料", "准备大蒜40克切成小粒备用\n同学们爆炒土鸡可以适量的多加一些大蒜这样更香", "准备几个二荆条去蒂之后切成小粒备用\n同学们也可以用魔芋或者小土豆代替二荆条", "准备小米辣40克切成小粒备用\n不能吃辣的同学可以不加", "准备大葱2根切成小粒备用", "最后准备仔姜1小块切成小粒备用\n建议川外的同学加生姜更好，因为出川后的仔姜味道会发苦\n温馨提示：此菜为家常小炒一锅成菜，无宽油", "下一步开始制作\n首先我们在锅中加入适量的清水\n然后将剁好的鸡头下锅焯水\n因为鸡头比较大块所以焯水之后更容易熟透\n鸡头焯熟之后倒出备用", "然后我们把锅烧热\n锅烧热之后再加入适量的熟菜籽油\n将油温烧至6成热", "油温6成热之后在锅中加入食用盐1勺（约3克）", "然后将剁好的鸡块下锅开中小火爆炒5分钟\n油中加盐的目的是让鸡肉更加的干香和入味", "当鸡肉炒至水份略干的时候再加入切好的大蒜和辣椒", "料头下锅之后翻炒几下将大蒜炒香", "大蒜炒香之后再加入老抽2克转小火将鸡肉翻炒至上色\n此菜不能加豆瓣酱所以加少许老抽上色", "鸡肉上色之后加入10克生抽酱油从锅边淋入炒香", "最后再加入切好的大葱粒，仔姜粒和辣椒粒", "然后开始调味\n锅中加入少许白糖中和辣味和提鲜\n再加入少许胡椒粉\n然后翻炒几下将辅料炒至断生", "再加入少许的晒醋从锅边淋入开大火翻炒均匀\n没有晒醋的同学可以用香醋或者陈醋代替\n最后大火翻炒几下炒出锅气即可出锅装盘", "一道非常美味的爆炒土鸡就制作完成"]'::jsonb, 30, 110, '困难', 3, 'https://i2.chuimg.com/659b0e55f6544040847dc25ff5443511_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('原汁原味土鸡汤', '肉类', '土鸡', '', '[{"name": "半只土鸡", "amount": "适量"}, {"name": "适量葱白，姜片，蒜瓣", "amount": "适量"}]'::jsonb, '["活鸡半只，洗净切块备用！去除鸡油～", "热锅，加少油，下葱姜蒜爆香，倒入鸡块翻炒！让鸡肉弹嫩关键点一定要先炒再炖！直接煲出来的肉很柴～", "翻炒一分钟，加水！水要多，至少要没过鸡肉！后面炖汤收汤会少很多。", "煮沸后，捞掉里面的葱姜蒜配料和浮油！这点很重要！因为这些配料煲汤时容易煮烂串味！", "倒入锅内压15分钟，开盖，鸡汤已经变得黄澄澄了！继续开盖小火炖15分钟！（我喜欢用高压锅，因为省时间！讲究的话就用砂锅炖，中小火炖40分钟）", "汤已经去了鸡油和爆炒的少量油咯，所以这个汤的颜色就是鸡肉里的，不要怕，绝对不会油腻～出锅前加一小勺盐即可！", "鸡肉超嫩，鸡汤原汁原味！超好喝！        来，干了这碗鸡汤！！！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/5c487e63458f4240af1aa696dfffd08b_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('辣子鸡（丁）', '肉类', '仔鸡', '辣', '[{"name": "一碗干辣椒", "amount": "适量"}, {"name": "两勺花椒", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "两勺料酒", "amount": "适量"}, {"name": "三片姜", "amount": "适量"}, {"name": "一勺白芝麻", "amount": "适量"}, {"name": "两勺生抽", "amount": "适量"}, {"name": "一勺蚝油", "amount": "适量"}, {"name": "半勺十三香", "amount": "适量"}, {"name": "半勺胡椒粉", "amount": "适量"}, {"name": "半勺花椒油", "amount": "适量"}, {"name": "三勺淀粉", "amount": "适量"}, {"name": "鸡腿", "amount": "4只"}]'::jsonb, '["先把干辣椒剪好，鸡腿肉去骨切成小块", "切好的小块放入料酒、生抽、十三香、胡椒粉、蚝油、白糖、盐、花椒油、淀粉、以上调料适量，研制15分钟左右", "起锅烧油，筷子放里面至可以起泡，放入切好的鸡块炸，第一遍先炸透。捞出", "等油热了再放进去复炸至熟（如果想吃有嚼劲一点的就多炸一会）", "锅中放油，放入葱、姜、花椒、辣椒小火清炒一会，直至炒干、炒出香味并放入炸好的鸡块转入中火，放入半勺糖炒一会，再放入鸡精、孜然粉、熟芝麻（只是为了装饰用，放不放都可以），翻炒几下就可以了"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/90e1dd52cd2042dfb64b8a232b6b0e6b_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒香辣鱿鱼', '肉类', '仔鸡', '辣', '[{"name": "鱿鱼", "amount": "2只"}, {"name": "杭椒", "amount": "2根"}, {"name": "小米椒", "amount": "4个"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "4瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "4片"}, {"name": "20粒花椒", "amount": "适量"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "糖", "amount": "20克"}]'::jsonb, '["鱿鱼洗净切条", "切小米椒", "水开鱿鱼焯20秒", "热锅放姜蒜翻炒", "加花椒豆瓣酱", "放洋葱继续翻炒", "倒入鱿鱼继续翻炒", "加蚝油，生抽，老抽", "大火爆炒30秒", "香喷喷的香辣鱿鱼做好啦"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/d63756342bed4cd5be0050cf4a0e8cf2_577w_761h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家常红烧小鸡翅根', '肉类', '仔鸡', '', '[{"name": "鸡翅根", "amount": "6个"}, {"name": "半根葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "八角", "amount": "1个"}, {"name": "冰糖", "amount": "5个"}, {"name": "桂皮", "amount": "1根"}, {"name": "香叶", "amount": "2片"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["鸡翅根改刀，冷水下锅，加入葱姜料酒和八角，大火烧开", "撇去浮沫捞出，凉水冲洗干净", "起锅烧油，下入适量冰糖，小火炒糖色，炒制枣红色", "下去鸡腿炒上色，加入葱姜八角桂皮，香叶干辣椒，中火炒香，加少许生抽，一点老抽上色，加入一碗清水", "大火烧开转小火炖30分钟，加少许盐调味", "大火收汁，出锅"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e0fc91f13f534705b3625c65621624ff_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('独家绝活！红烧仔鸡', '肉类', '仔鸡', '', '[{"name": "仔鸡", "amount": "1只"}, {"name": "适量五花肉或者前腿肉", "amount": "适量"}, {"name": "适量生姜", "amount": "适量"}, {"name": "适量勺生抽", "amount": "适量"}, {"name": "适量勺老抽", "amount": "适量"}, {"name": "适量勺料酒", "amount": "适量"}, {"name": "适量瓣大蒜", "amount": "适量"}]'::jsonb, '["适量前腿肉", "清洗干净仔鸡", "适量一点点食用油，（我这个昨天买的肥肉丝，我怕浪费了，就炼点油，用一点点食用油，就是为了更好的逼出肥肉里的油）", "翻炒均匀，油炼的差不多把渣子捞出来丢了，影响卖相", "放入买的肉，肥的多点，放锅里煸炒出油", "倒入鸡，使劲炒，炒到表皮焦黄，水分炒掉", "炒到这个程度，放入料酒，生抽，老抽翻炒均匀，", "加入开水，跟鸡齐平多点点，盖盖闷煮", "烧到水还有三分之二的时候，放入大蒜，加入适量盐，适量糖提鲜，翻炒几下，接住闷煮", "水还有三分之一的适合，尝尝咸淡，差不多就可以大火收汁，出锅！\n\n这个方法推荐你们试试，真的很好吃，土豆烧仔鸡，板栗烧仔鸡，毛豆烧仔鸡等等，都可以这么做，很好吃"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/fd5c4d0e435f451d917b292417e2dc78_864w_1152h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('不加一滴水皮脆肉嫩鸡腿肉', '肉类', '仔鸡', '', '[{"name": "鸡腿", "amount": "4只"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "几片蒜片", "amount": "适量"}]'::jsonb, '["鸡腿去骨、横切几刀方便入味、加入蒜片、料酒1勺、生抽2勺、蚝油1勺、老抽半勺抓匀腌制20分钟", "把腌好的鸡腿用厨房纸巾吸干水份、带皮那面放入平底锅、盖上锡纸、上面放一个装半盆水的盆子压着（这样能让肉质更紧实更嫩滑）小火煎5分钟翻面再煎5分钟、", "切块装盘、撒上欧芹碎", "忍不住偷吃一块"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/9177d445b9d94c2e8fc61c9b814e4350_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('电饭锅焖三黄鸡', '肉类', '三黄鸡', '', '[{"name": "l只三黄鸡", "amount": "适量"}, {"name": "味极鲜酱油", "amount": "1勺"}, {"name": "海鲜酱", "amount": "1勺"}, {"name": "蚝油", "amount": "1小勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许冰糖粉", "amount": "适量"}, {"name": "香菇", "amount": "3个"}, {"name": "小葱白", "amount": "2根"}, {"name": "老姜", "amount": "3片"}]'::jsonb, '["三黄鸡清除内脏洗净后沥干水分，葱切成小段，姜、香菇切丝备用。", "用1小碗将上述用料全部倒入碗內拌匀后均匀地涂抹在鸡肚子里，再将葱姜香菇丝塞进鸡肚子里", "将剩下的料涂抹在鸡的外皮上，要每个地方都涂到，然后腌制1小时左右。", "电饭煲的锅底部均匀地抹上花生油，然后把腌制好的三黄鸡放入电饭煲，接通电源按下煮饭档。", "十分钟后电饭煲自动跳到保温档，不要打开锅盖，继续保温5分钟。", "然后开锅将鸡翻面继续按煮饭档重复第5步即可"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/66199f5c882311e6b87c0242ac110003_602w_602h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('三黄鸡汤', '肉类', '三黄鸡', '', '[{"name": "上海本地三黄鸡", "amount": "适量"}, {"name": "葱姜料酒若干", "amount": "适量"}]'::jsonb, '["把整鸡洗干净滤干水分", "入锅，加满冷水", "大火烧开慢慢的撇去血沫", "血沫撇干净，加葱姜加料酒，大火烧开，调小火慢炖，直到冒香气用筷子插入肉厚的地方，口感按个人喜好，一年的老母鸡肉质有点老，1/2小时为宜。出锅前加适量盐吊鲜！", "醇香的鸡油熬制：\n锅里放一点点油起锅，\n把滤干的鸡油放进去熬，\n鸡油熬好加点盐或者白糖，\n盛出来放玻璃器皿冷却\n吃面条馄饨舀一点鸡油\n喷喷香", "鸡汤馄饨", "鸡汤火腿面", "海参鸡汤"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/bf42f35ed3db11e6947d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('清炖三黄鸡（热菜）', '肉类', '三黄鸡', '辣', '[{"name": "三黄鸡", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "白胡椒粒", "amount": "适量"}, {"name": "干辣椒", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "大料", "amount": "适量"}, {"name": "香叶", "amount": "适量"}, {"name": "红枣", "amount": "适量"}, {"name": "桂圆", "amount": "适量"}, {"name": "枸杞", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "香菜", "amount": "适量"}]'::jsonb, '["三黄整鸡解冻，去内脏，鸡头，鸡爪，臀尖，放凉水锅里焯水，煮开后捞出用热水清洗干净，控水晾凉待用", "锅里放焯过水的整鸡，放入凉水，淹住三黄鸡，加料酒，姜片，葱段，白胡椒粒，干辣椒，花椒，大料，香叶，红枣，桂圆，枸杞等调味料，大火煮开，去除浮末，盖锅盖转小火焖炖1小时后，加盐再炖15分钟，出锅放香菜就行了"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/c19512f2e92711e6bc9d0242ac110002_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧三黄鸡家常版(黄焖鸡)', '肉类', '三黄鸡', '', '[{"name": "三黄鸡", "amount": "1只"}, {"name": "半个土豆", "amount": "适量"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "半个青辣椒", "amount": "适量"}, {"name": "鲜香菇", "amount": "3个"}, {"name": "半个洋葱头", "amount": "适量"}, {"name": "5瓣大蒜", "amount": "适量"}, {"name": "两片姜", "amount": "适量"}, {"name": "半个八角", "amount": "适量"}, {"name": "适量白醋、生抽、老抽、耗油", "amount": "适量"}, {"name": "半瓶啤酒", "amount": "适量"}, {"name": "适量盐、白糖、鸡精", "amount": "适量"}, {"name": "（可不放）干辣椒", "amount": "2个"}]'::jsonb, '["上好的三黄鸡一只（我在超市买的带包装冷冻的）", "改刀切成小块", "辅料切成喜欢的形状", "爆香料切好备用", "热锅凉油将洋葱、生蒜、姜片、八角、干辣椒翻炒爆香。", "下入鸡肉块煸炒，将肉块炒制变色变干。（肉块炒成白色）", "点上少许白醋（肉会更加鲜嫩）", "放生抽适量（后补的图）", "放老抽适量上色", "放适量耗油提鲜", "啤酒半听（我用的是大听的，品牌随意，没有也可以放料酒）", "加入适量清水，（没过鸡肉便可）", "大火烧开放入食用盐、白糖、鸡精转小火，盖上锅盖炖15—20分钟，（时间以鸡肉熟烂为准）", "倒入配菜，土豆和香菇先行入锅，大火收汁，出锅前两分钟在放胡萝卜和青椒。", "摆好桌子、椅子、筷子、勺子，上菜上大米饭，开造。", "孩子吃的很开心"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/3bf3d8f9ef4b4e338501db7048f0cc78_1728w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('白斩鸡', '肉类', '三黄鸡', '', '[{"name": "三黄鸡", "amount": "1只"}, {"name": "姜", "amount": "2片"}, {"name": "大葱", "amount": "2段"}, {"name": "八角", "amount": "2个"}, {"name": "白芷", "amount": "4片"}, {"name": "小半碗啤酒", "amount": "适量"}, {"name": "适量香油", "amount": "适量"}, {"name": "少许生姜", "amount": "适量"}, {"name": "适量大蒜", "amount": "适量"}, {"name": "适量香菜梗", "amount": "适量"}, {"name": "适量蒸鱼豉油", "amount": "适量"}]'::jsonb, '["嫩鸡一只..\n\n我一般都把头剁掉丢弃.\n用厨房剪把屁股剪掉丢弃.\n\n再把肚子里面的东西全部掏出来.\n可以把肝肠這些收拾干净炒鸡杂吃..！\n脚也会剪下来.\n剪掉指甲剁小放鸡杂里一块炒...！\n\n鸡杂实在太好吃了..！(˶‾᷄ ⁻̫ ‾᷅˵)", "一口大锅.烧水.\n水量要完全能盖过鸡.\n放入大葱.姜.八角.白芷.啤酒..！\n如果没有啤酒的就放一些料酒..\n\n如果没有大锅.\n就把鸡分成二半.\n這样就好煮了. ！\n\n反正就是：\n有困难就解决困难.\n没困难就制造困难...！(￣∇￣)", "水开后.拎起鸡.\n放入锅中烫一下就提起.\n\n重复三次...！\n重复三次...！", "计时器准备好.\n\n把鸡整个都放入锅中.\n煮一分钟...！\n\n真的就一分钟..！", "一分钟后.\n捞出放入冷水中浸泡凉后捞出.", "再次放入锅中煮4分钟..！", "四分钟后.\n盖上锅盖煮一分钟后关火.\n\n关火后不要打开锅盖.\n根据鸡的大小焖40-50分钟..！", "焖好后捞出.\n放入提前准备好的冰水中.\n要浸泡10分钟左右.\n\n让它冷静冷静..！\n\n建议就是用矿泉水瓶.\n装纯净水丢冰箱冰着用.\n\n用生自来水的话.\n吃坏肚子了.\n我是不会负责的.( ´▽｀)", "10分钟后捞出.\n用厨房纸吸干水分.\n戴上手套.\n淋香油.\n把鸡全身都涂抹一遍.\n静置几分钟.\n\n香油淋上去的地方.\n明显一下就比较黄呀.(˶‾᷄ ⁻̫ ‾᷅˵)", "把大蒜.生姜.香菜梗.切碎..\n\n吃的时候再倒蒸鱼豉油下去就好.！", "把鸡切块摆盘.\n蘸料里倒入蒸鱼豉油.\n\n如果覚得淡了.\n可以放少许盐.\n根据自己的口味调整..！"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/ca32c7d7f67d42519c95abfa2aa12123_1616w_1081h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒鸡肝', '肉类', '鸡肝', '', '[{"name": "鸡肝", "amount": "350克"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "各1个青红辣椒", "amount": "适量"}, {"name": "油", "amount": "3汤匙"}, {"name": "料酒", "amount": "1汤匙"}, {"name": "花椒粒", "amount": "3克"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "淀粉", "amount": "2茶匙"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "生抽", "amount": "2茶匙"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量香油", "amount": "适量"}]'::jsonb, '["鸡肝洗净，切成片后，用料酒、盐、淀粉抓匀，再加少许油拌匀，腌制10分钟左右。", "洋葱洗净切片，青红辣椒洗净、去子、切块备用。", "取一小碗，加入料酒、生抽、盐、糖、花椒粉调匀，兑成调味汁。", "锅内加较多的油，烧至六成热时，放入鸡肝滑炒至变色后，关火捞出沥油。", "锅中留少许底油烧热，下葱、姜、蒜片炒香。", "放入洋葱和辣椒，继续大火翻炒至断生后，将滑好的鸡肝倒入锅中翻炒均匀。", "迅速将兑好的调味汁倒入锅中，炒匀关火。", "最后淋入几滴香油，即可出锅。香油只是点缀的香气，切忌多放。", "成品大图，看看吧~~", "本菜谱选自萨巴厨房出品的《米饭爱小炒》。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/f938c19488f711e6a9a10242ac110002_886w_576h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小花妈妈秘制鸡肝', '肉类', '鸡肝', '', '[{"name": "一斤半鸡肝", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "八角（大料）", "amount": "1个"}, {"name": "（如图）花椒面", "amount": "1小勺"}, {"name": "（如图）盐", "amount": "1小勺"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "各2勺（如图）酱油（生抽和老抽）", "amount": "适量"}, {"name": "（如图）料酒", "amount": "1勺"}]'::jsonb, '["第一步：先将鸡肝切成块；将葱切段、姜切片（适量即可）", "第二步：将鸡肝放入热水中焯至半熟（爱吃嫩的就少烫一会儿）。", "第三步：焯水后捞出待用。", "第四步：在大勺中倒入适量的油和糖，熬至琥玻色。", "第五步：待糖化开精辟将鸡肝倒入锅中，目的为了上色。", "第六步：翻炒几下后，放入适量花椒面。", "第七步：再将切好的葱姜放入锅中，再翻炒几下。", "第八步：倒入酱油（生抽、老抽）", "第九步：倒入料酒", "第十步：添水，水不要添的过多，刚刚没过鸡肝即可。", "第十一步：放入一个八角。  （PS：那个小圆片叫什么来着？！ (⊙o⊙)…）", "第十二步：放入适量的盐。（根据自己的口味即可）", "第十三步：盖盖开煮即可，中途揭开盖子拍个照", "第十四步：出锅！   噹噹噹噹~~"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/6a5100988ae311e6b87c0242ac110003_553w_369h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('白水嫩鸡肝｜卡卡爸', '肉类', '鸡肝', '', '[{"name": "4、5个鸡肝", "amount": "适量"}, {"name": "姜片", "amount": "2片"}, {"name": "两勺适量盐", "amount": "适量"}, {"name": "5、6粒（喜欢可以多放）花椒", "amount": "适量"}, {"name": "可有可无牛奶", "amount": "适量"}]'::jsonb, '["新买的新鲜鸡肝要先泡去血水，（水里可以加一点点盐和牛奶）至少10分钟，然后用清水淘洗两次，至水清，注意下手轻柔，不要碰破了鲜嫩的鸡肝。", "事先准备一个大碗，或者是耐100℃高温的保鲜盒，撒入花椒粒和盐，喜欢花椒就多放一些，我就是随手一抓。", "泡好洗净的鸡肝冷水下锅焯水，水量淹没鸡肝就够，放几个姜片去腥，中小火，把水慢慢烧开后，立即捞出鸡肝。\n\n（请注意：不要放任何黄酒、料酒、白酒……\n虽然这也是去除腥味的传统方法，但是，不适合用作动物肝脏，不信的话，您就试试看。）", "水开后立即捞出的鸡肝，趁热放在之前准备好的碗里，鸡肝带着温度焖在花椒粒上面，很能激发出香味儿。\n\n      此时鸡肝已经八成熟，可能还会带有些许血丝，不要担心，只差最后一步。", "再次烧开一些开水，倒入大碗，淹没碗中的鸡肝，尝尝盐味儿，不够就再加一些食盐调整咸淡，就这么泡着，直到自然冷却。\n\n\n      有做过的朋友说，鸡肝较大，可能不能熟透。我有两个方法来解决：\n      其一、上一步水开以后，小火再煮1分钟，肯定熟了；\n      其二、用更大的容器浸泡，更多的开水带来更长的保温时间，也能保证熟透。\n\n根据巴氏消毒法，食物内部温度达到68℃以上，半个小时以内就可以杀死所有细菌，我们这个做法，基本上也就达到了理想的环境。", "泡上十分钟以后，就算入味了，鸡肝的鲜嫩程度刚刚好，血丝已经消失，可以像白灼虾那样连汤一起上桌了。\n\n      也可以提前准备好，就这么泡着，凉了拿出来还是鲜嫩的，连汤装保鲜盒一起放冰箱，两三天内随时享用。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/214e5b520e4111e7bc9d0242ac110002_1296w_1729h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒鸡肝', '肉类', '鸡肝', '辣', '[{"name": "五块鸡肝", "amount": "适量"}, {"name": "两个青椒/尖椒", "amount": "适量"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "两瓣蒜切", "amount": "适量"}, {"name": "适量盐，鸡精", "amount": "适量"}, {"name": "两勺酱油", "amount": "适量"}, {"name": "两勺生抽", "amount": "适量"}, {"name": "两勺料酒", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}]'::jsonb, '["把肝切片。蒜切片，干辣椒青椒切好备用", "做锅，多放点油！蒜片干辣椒炒香下入肝片翻炒（炒到肝变成白色）加入料酒酱油生抽白糖胡椒粉继续翻炒，出锅前加入青椒盐鸡精即可"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/cecb50541d9711e7bc9d0242ac110002_1279w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('姜煮鸡肝', '肉类', '鸡肝', '', '[{"name": "鸡肝", "amount": "300克"}, {"name": "姜丝", "amount": "15克"}, {"name": "200毫升料酒", "amount": "适量"}, {"name": "糖", "amount": "20克"}, {"name": "生抽", "amount": "2.5大勺"}, {"name": "老抽", "amount": "0.5大勺"}]'::jsonb, '["做处理：去除鸡肝上附着的脂肪和血块；把鸡肝倒进网勺里，再用热水成流水状浇注在鸡肝上，慢慢地浇，不要“哗啦\"一下子地倒。热水还剩一半时，把鸡肝翻个个儿，继续浇注热水；这样可以给鸡肝去掉一部分的腥味。切成一口大小，再冲洗几下，沥干水分。", "鸡肝入锅，倒料酒进去。开大火。不一会儿，表面上就会出现血沫，用勺子撇掉这些血沫，撇得越干净越好。", "放入姜丝和糖。生抽老抽打圈状淋入锅中。5，6分后夹取一块鸡肝试吃，如果中间没有血水就是已经好了，立马熄火，连汤汁带鸡肝盛出。如果中间还有血水，再煮1分钟。", "让鸡肝在汤汁中浸泡30分钟即可。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/097de2417a4242b2b3cd1b49b4108163_1353w_900h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('老母鸡汤', '肉类', '老母鸡', '', '[{"name": "土鸡", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "盐", "amount": "适量"}]'::jsonb, '["土鸡洗干净，入凉水，葱结，生姜，大火烧开", "大火烧开后，转小火，保持微沸状态，炖3小时", "最后加入山药，或者冬瓜片，炖开，调入盐，就可以趁热享用啦"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/cbd29954883f11e6a9a10242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧土鸡', '肉类', '老母鸡', '', '[{"name": "一只土鸡（新鸡，不是老母鸡）", "amount": "适量"}, {"name": "适量桂皮、八角、花椒、香叶、青红椒、姜、蒜瓣、香葱。", "amount": "适量"}, {"name": "适量盐、生抽、醋、豆瓣酱", "amount": "适量"}]'::jsonb, '["洗净土鸡，斩件沥干水分。", "锅中油烧至7～8成热，下姜片、蒜瓣、葱结爆香，放入八角、桂皮、花椒、加一勺豆瓣酱炒香。", "下鸡块翻炒，加入香叶，适量生抽、香醋翻炒至鸡皮略出油。", "加入适量清水或高汤，水量略高于鸡块，大火烧开再转小火煲约1小时20分钟。", "揭盖放入靑红椒略煮透，加入香葱、适量盐翻炒均匀即可。", "香喷喷的红烧土鸡。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/8d72b83e894211e6b87c0242ac110003_748w_728h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('煲靓汤 老母鸡汤', '肉类', '老母鸡', '', '[{"name": "土鸡", "amount": "1只"}, {"name": "干香菇", "amount": "6个"}, {"name": "生姜", "amount": "1个"}, {"name": "3瓣大蒜", "amount": "适量"}, {"name": "料酒", "amount": "2汤匙"}, {"name": "小葱", "amount": "3根"}, {"name": "枸杞", "amount": "1汤匙"}, {"name": "净重为鸡的2倍用来煲汤的矿泉水", "amount": "适量"}, {"name": "板栗肉", "amount": "1把"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["香菇提前泡水。要用干香菇比较好吃，新鲜的 没有发生美拉德反应，不香der！\n\n不超过10只香菇的话，鸡汤是不可能变成蘑菇汤的！不用担心香菇会掩盖鸡汤的味道啊。放的数量正确，只会提鲜而已。\n\n生姜切片，大蒜剥好，老母鸡洗净切好备用。\n\ntips： \n\n新鲜宰杀 处理干净 的鸡要在 【半 小 时 内】下锅。如果不能及时下锅，得拿保鲜膜包起来放入冰箱（4摄氏度左右）24小时，待肉熟化后再煲汤。\n\n老母鸡不能刚杀完 过几小时 才煮汤哦！ 因为 动物 死之后会慢慢释放毒素，肉比较难吃，也不健康。\n\n\n\n\n动物在（屠宰）死后有一个僵直过程，从小看柯南长大的你们应该不陌生。肉类的宰后熟化过程就是等待僵直期完成的过程。排酸肉是在低温条件下通过宰后熟化的肉，较之没有经过熟化的肉口感会更软嫩。但是就营养成分来说，排酸肉和普通肉不会有明显区别。\n参考：排酸肉概念分析，翟美茹等，兽医分析\n成熟排酸肉的结构蛋白变化，李兰会等，肉类工业\n补充：很多人问低温冷藏就低温冷藏呗，为什么叫排酸呢？\n（其实我也没查到这个名字的来源，我推测的：p）因为，动物死后，组织开始缺氧，进行无氧代谢，在肌肉组织中就会积累乳酸（跟人进行无氧运动之后会觉得肌肉酸痛的原理差不多）而当肉放置一段时间后，乳酸分解。所以这种低温冷藏的肉叫做排酸肉。\n尸僵一般在死后30分钟到两小时内开始。处于僵直期的肉保水性降低，硬度升高，可能会不太好吃。而经过一段时间的储藏后，在组织酶等作用下，经过一系列生化作用，僵直解除，肉质回软，弹性和保水性都有一定成都的回升。”\n\n“这一情形深层次的机理是：肌肉的收缩和舒张都需要消耗能量，而这股能量最直接的来源是肌肉细胞中的一种不稳定的高能化合物：三磷酸腺苷，也就是我们熟悉的ATP。”\n\n牛生前，肌肉中的糖元不断分解产生ATP，肌肉受到神经系统指令后，肌浆网(肌肉中钙的主要储存处)释放Ca离子，于是细胞外的Ca离子进入细胞内使细胞液中的钙的浓度升高并最终导致肌肉收缩。而后，在钙泵作用下细胞内的Ca离子被排出产生肌肉舒张，整个过程是可逆的。\n\n牛死后，机体的代谢环境发生改变，肌浆网自体崩解，ATP的含量也不断降低，大量Ca离子溢出后进入细胞内使肌肉持续收缩，这时ATP又逐渐消耗殆尽，肌肉无法再舒张，于是便处于持久的僵硬状态。如果宰杀时牛过度惊恐和挣扎就会消耗更多的ATP，还会使得僵直状态提前。", "鸡拿去沸水中飞水2分钟，捞起。\n\n（若不是清理完 半小时就煮。 有时间也特别讲究的话，可以在飞水前把熟化过的鸡放在清水中浸泡1小时，这样可以去腥和血水。）", "热锅内放1勺油，烧热后 放入 姜片、蒜瓣炒香。再放入鸡块 、料酒翻炒5分钟。\n\n高温油 炒过的鸡，煲汤 会更加香浓哦～  \n\n\n美拉德反应！\n\n\n避免直接下水煮，那样汤头容易寡淡，不鲜美。\n\n如果较喜欢直接煮，请尽量整只鸡下锅 比较香。勿切。\n\n锅选用【不跑气】的汤锅。砂锅最佳。\n\n【不跑气意思是： 砂锅盖的周围一圈闭合紧密，不跑水气。 】 \n\n质量次的砂锅，锅盖一圈的密封性不佳。和有没有出气孔没关系。", "把炒过的食材倒入汤锅中，加入常温下的净水、香菇、板栗和小葱。\n\n（不推荐未过滤的自来水。差水质会影响汤的口感。）\n\n煮沸后转小火，煲90-180分钟，一般90分钟就够，看急不急。期间若常揭盖漏气就不香了。可以偶尔查看1-2次。\n\n（小时候最喜欢吃鸡汤里的板栗^^ ）\n\n最后15分钟 转大火放入枸杞、盐。盐推荐 苦味较淡的 喜马拉雅岩盐。放盐别搅，会有生盐味哒！撒葱花。\n\n\n超靓的鲜鸡汤出锅咯! \n\n拿去泡米饭吧～"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/a449a6f04eb111e7947d0242ac110002_526w_381h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('猴头菇煲老母鸡汤', '肉类', '老母鸡', '', '[{"name": "猴头菇", "amount": "2个"}, {"name": "半只老母鸡", "amount": "适量"}, {"name": "姜", "amount": "3片"}, {"name": "20粒枸杞", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "1葱结", "amount": "适量"}]'::jsonb, '["如果是半只鸡两个大点的猴头菇就够了。", "头天晚上开始泡猴头菇，根部朝下最好给它用个盘子扣着 不然猴头菇会浮起来。", "第二天早上用剪刀把根部剪掉，留着会很苦。然后用手像挤海绵一样在水里反复过几遍水，把黄水都挤干净就可以用了！", "如果猴头菇个头大就用刀切几片，据说用手撕不破坏营养呢😄！", "老母鸡砂锅里放足量的水，加姜片，葱结大火烧开，撇去浮沫再加入猴头菇一起炖开后，转小火炖两个小时！这个时间要看你的鸡的大小和老嫩了！筷子能戳动就可以了！我这只是农村正宗老母鸡炖了四个小时还是肉质紧紧的可香啦！", "快好的时候可以加几颗枸杞，撒点小葱花！特别美味和营养！\n本菜谱中猴头菇是我们群团购的无硫特级猴头菇。品质超好！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/134960521a31422588a91db703258936_888w_887h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('不会破皮且肉质筋道的滋补人参老母鸡汤', '肉类', '老母鸡', '', '[{"name": "半只老母鸡", "amount": "适量"}, {"name": "若干姜", "amount": "适量"}, {"name": "一小把枸杞", "amount": "适量"}, {"name": "若干大葱", "amount": "适量"}, {"name": "适量人参", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "3颗红枣", "amount": "适量"}]'::jsonb, '["老母鸡洗择干净，用盐把鸡身体擦一遍，放到冰箱冷藏20分钟。", "老母鸡从冰箱取出来，再洗一遍，把外层的盐洗掉，放入砂锅，加入葱段、姜片、料酒、人参。", "砂锅加水到水位线那里，大火烧开，转小火慢炖。", "小火炖一个小时后加入红枣，红枣最好开一个小口，让营养更好扩散。", "加入红枣后再炖45-60分钟（按照鸡肉大小来看），放入枸杞，再小火炖3分钟左右。", "一锅营养滋补的人参老母鸡汤就做好啦，因为之前鸡身用盐擦过，出锅前就可以不放盐了。", "油亮亮的美味人参鸡汤，看起来就好补的感觉，我习惯连鸡油一起喝，怕胖的宝宝可以用吸油纸把油吸掉。", "我的公众号，会经常分享菜谱、小故事和vlog，期待关注。", "我的微博，期待交流。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/b47a6f1110dc4e90b175ed192430d5d4_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒鸡心', '肉类', '鸡心', '', '[{"name": "鸡心", "amount": "适量"}, {"name": "青椒", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "孜然", "amount": "适量"}, {"name": "孜然粉", "amount": "适量"}]'::jsonb, '["鸡心洗净，弄干净后，放入料酒，生抽腌制15分钟。", "青椒细丝备用。适量孜然粉和孜然粒混合备用。", "油锅烧热后，放入鸡心爆炒，鸡心变色以后，开始榨干鸡心的水分。", "等水分大部分榨干时，放入青椒丝，喷入少许生抽，加入孜然混合物（孜然量依照个人口味加入，ps如果味道不够可以加入少许盐）即可出锅啦。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/aec9ce3e87ce11e6b87c0242ac110003_2816w_1584h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒鸡心', '肉类', '鸡心', '', '[{"name": "鸡心", "amount": "500g"}, {"name": "尖椒", "amount": "2个"}, {"name": "红小米椒", "amount": "5个"}, {"name": "大葱", "amount": "3g"}, {"name": "姜片", "amount": "2g"}, {"name": "酱油", "amount": "3g"}, {"name": "蚝油", "amount": "10g"}, {"name": "盐", "amount": "4g"}, {"name": "糖", "amount": "3g"}, {"name": "油", "amount": "3g"}]'::jsonb, '["把鸡心浸泡、洗净 竖着中间切一刀，切成两瓣儿，如果嫌太大，也可切成四瓣！青椒切成滚刀块！红小米椒切成小段！", "鸡心切好后入凉水锅 煮一下 水开即可捞出", "热锅倒入凉油 下葱花和姜片 煸出香味 倒入红小米椒 煸炒 倒入煮熟的鸡心 大火爆炒 倒入酱油、蚝油，盐，颜色渐深之后倒入尖椒，继续爆炒！之后放入糖，翻炒两下关火！", "噔噔噔噔…闪亮出锅！拌饭特别香！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/563126d4da1f11e6947d0242ac110002_960w_722h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('辣炒鸡心', '肉类', '鸡心', '辣', '[{"name": "一斤鸡心", "amount": "适量"}, {"name": "小辣椒", "amount": "2个"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "孜然", "amount": "8克"}, {"name": "干辣椒", "amount": "3个"}, {"name": "两勺蒜蓉辣酱", "amount": "适量"}, {"name": "白芝麻", "amount": "5克"}, {"name": "一段葱", "amount": "适量"}, {"name": "四片姜", "amount": "适量"}, {"name": "7瓣蒜", "amount": "适量"}, {"name": "少许生抽", "amount": "适量"}, {"name": "盐", "amount": "2克"}, {"name": "一勺料酒", "amount": "适量"}, {"name": "半勺酱油", "amount": "适量"}, {"name": "白糖", "amount": "3克"}, {"name": "少许十三香或花椒面", "amount": "适量"}]'::jsonb, '["鸡心一斤，焯水，凉水下锅，水开一分钟左右捞出", "洗净的鸡心切除心管部位，去油，去膜（个别鸡心有一层膜）从中间切开，好入味\n再次洗净，用适量料酒，十三香，盐腌制十分钟", "附料备好，（如图）辣椒切滚刀片，胡萝卜切片，葱姜蒜切好", "热锅凉油，放入红辣椒，孜然", "放入蒜蓉辣酱炒香，葱姜蒜，胡萝卜", "白糖，生抽，酱油少许", "放入鸡心", "放入辣椒，白芝麻", "炒好装盘"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/bf1dd97e58bb11e7bc9d0242ac110002_1080w_810h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孜然鸡心', '肉类', '鸡心', '', '[{"name": "一袋鸡心", "amount": "适量"}, {"name": "适量孜然或孜然粉", "amount": "适量"}, {"name": "生抽或者一品鲜", "amount": "2勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "姜", "amount": "2片"}, {"name": "料酒", "amount": "1勺"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "一个八角", "amount": "适量"}, {"name": "少许白糖", "amount": "适量"}, {"name": "少许十三香", "amount": "适量"}, {"name": "少许耗油", "amount": "适量"}, {"name": "一点/上色就行了奥老抽", "amount": "适量"}, {"name": "少许芝麻", "amount": "适量"}, {"name": "可不放辣椒面", "amount": "适量"}]'::jsonb, '["选择干净新鲜的鸡心，解冻处理，划几刀，或者对半切开，洗干净里边的脏血，然后冷水下锅进行焯水，放入葱姜，料酒，去腥。焯出血沫，水开以后关火，盛出鸡心。用自来水冲洗，冲去粘在鸡心上边的脏东西，鸡心里头也要好好清洗。(备用)", "锅里放油，放入葱姜蒜、下鸡心，八角放里爆香，爱吃辣椒也可以放两个红辣椒奥，放入酱油或生抽，翻炒上色，少许糖和耗油提鲜，放入盐、鸡精，十三香调味，然后放少许水，炖一会（有的人说被坑了，我也很纳闷，仔细看一遍，上色就是酱油或者生抽，没有生抽和酱油。一点点老抽也行，这没有规定奥，）我只是把我的菜无偿分享，喷子绕行", "等汤汁收的差不多就可以放入辣椒面孜然芝麻了，不要等一点汤收干，要留少许汤汁，不然就不好吃了", "成品图，吃饭"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/0f8d5cda61494d0ab83e9a5ea8019588_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孜然鸡心', '肉类', '鸡心', '辣', '[{"name": "鸡心", "amount": "1斤"}, {"name": "料酒", "amount": "1勺"}, {"name": "孜然", "amount": "2勺"}, {"name": "生抽", "amount": "1小勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "干辣椒", "amount": "4个"}, {"name": "姜", "amount": "2片"}]'::jsonb, '["处理鸡心。切掉鸡心表面的油脂，然后对半切开，洗干净藏在里面的血块。加入料酒腌制10分钟。", "准备辅料，姜片、青红辣椒。", "炒制。油烧热，先放入辅料炒香，然后倒入鸡心大火翻炒，鸡心水分较多，把水分炒干，然后撒入孜然粉、盐，少量生抽，翻炒均匀即可出锅。我爱吃辣，所以还加了辣椒粉，非常好吃，很下饭。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/2976df3ae801479891fab416d12186e8_750w_946h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('不用焯水，超简单的炖柴鸡', '肉类', '柴鸡', '', '[{"name": "一只柴鸡", "amount": "适量"}, {"name": "少许油", "amount": "适量"}, {"name": "少许冰糖", "amount": "适量"}, {"name": "没过鸡肉开水", "amount": "适量"}, {"name": "适量老抽，生抽，料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量葱段，姜片，蒜瓣", "amount": "适量"}, {"name": "适量花椒大料", "amount": "适量"}]'::jsonb, '["锅开小火，放少量油，适量冰糖", "冰糖熬成浅棕色，放切好洗净的鸡块翻炒、段生，上色", "鸡肉变色后，放入葱段，姜片，蒜瓣，生抽，老抽，料酒翻炒", "翻炒两分钟后，放开水没过鸡肉，同时放入花椒，大料包，小火炖2小时", "放适量盐，中火30分钟"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/f1dd91de885e11e6a9a10242ac110002_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小笨鸡炖土豆（红烧家庭做法）', '肉类', '柴鸡', '', '[{"name": "小笨鸡", "amount": "1只"}, {"name": "土豆", "amount": "3个"}, {"name": "食用盐", "amount": "2小勺"}, {"name": "老抽", "amount": "5小勺"}, {"name": "白糖", "amount": "2小勺"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量葱花", "amount": "适量"}, {"name": "半小勺十三香", "amount": "适量"}, {"name": "大豆油", "amount": "2大勺"}, {"name": "少许味精", "amount": "适量"}]'::jsonb, '["把整只笨鸡切块用高压锅压一下，时间大概30分钟左右\n.（笨鸡肉比较硬，所以一定要压一下）准备好备用。", "把所有配料放在一起备用。一起放进锅里味道比逐一放进去要好。", "锅里热油", "油热后把鸡块沥干水分倒进锅里翻炒。", "倒入配料继续翻炒。", "加入鸡汤大火炖10分钟左右。", "加入土豆块  继续炖。", "加入土豆块后再炖十分钟左右。", "关火，加入少许味精。", "出锅，放点香菜末点缀。有点拍虚了☺"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/458e4b6e89f611e6b87c0242ac110003_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('柴鸡蛋炒奶白菜', '肉类', '柴鸡', '', '[{"name": "鸡蛋", "amount": "3只"}, {"name": "奶白菜", "amount": "1把"}, {"name": "2颗大蒜", "amount": "适量"}]'::jsonb, '["奶白菜洗净，切段。", "鸡蛋打散，加入适量的料酒和盐，大蒜切碎。", "热油，鸡蛋炒熟盛出。再热油，蒜蓉香锅，白菜下锅翻炒，稍软把鸡蛋加入一起炒，出锅前加入适量的盐和鸡精调味即可。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/5eb2eec68b8911e6b87c0242ac110003_1815w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('东北正宗小鸡炖土豆', '肉类', '柴鸡', '', '[{"name": "适量鸡肉", "amount": "适量"}, {"name": "几个土豆", "amount": "适量"}, {"name": "一根葱", "amount": "适量"}, {"name": "4～6片姜", "amount": "适量"}, {"name": "3~4个干辣椒", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "五分之一的酱油量老抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量花椒面", "amount": "适量"}, {"name": "1~2个八角", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "油", "amount": "适量"}, {"name": "一壶烧开的水", "amount": "适量"}, {"name": "一小把葱花", "amount": "适量"}]'::jsonb, '["把葱切成段，姜切成片。", "将生抽，老抽，料酒，八角，花椒面，白糖，蚝油两段葱段以及一片姜片放入小碗中提前调好后（以防做起来手忙脚乱，pou主先大概拌好，之后加汤尝味道，咸淡拿盐调，颜色用酱油调）。", "在锅里加适量的水，烧开。水开放入鸡肉，直至鸡肉变色，用漏勺捞出放入另一盆准备好的凉水中，把沫子洗干净，水倒干净，放一旁备用（放入凉水中是为了让鸡肉更紧实，口感更好）。", "锅擦干，倒油，一层油大约没过锅底。开火，油烧热，放入鸡肉，大火炒至金黄，倒入葱段，姜片，干辣椒，酱料，继续翻炒一下，倒入烧开的水，没过鸡肉即可，转中小火盖好锅盖炖！注意⚠️炒的过程中要一直翻炒！千万别糊了！", "鸡肉小火炖制过程中将土豆切成滚刀块。鸡肉炖烂，汤少一点后将土豆放入锅中，翻下锅，盖好锅盖，继续小火炖。炖5分钟左右，开盖尝一尝味道咸淡，以及看颜色，味道淡➕盐，颜色浅➕老抽。想喝汤的再加开水，在调味道，尝着加调料。想炖的干巴的，就不用加水了。盖锅盖炖。", "炖一会，土豆熟了之后，像我们家一样的爱吃干一点味道重一点不要太多糖的，在剩不多的汤的时候，开大火收汤。吃汤多得土豆熟了就可以关火了。", "装盘，撒一层葱花。完成！\n\n忙忙活活，没来得及照照片，下次做补上！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/98391cf4f99011e6947d0242ac110002_600w_400h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香菜炒笨鸡蛋', '肉类', '柴鸡', '', '[{"name": "适量香菜", "amount": "适量"}, {"name": "两个鸡蛋", "amount": "适量"}, {"name": "适量凤球唛生抽", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["鸡蛋，新鲜的香菜洗净 切成小段.", "鸡蛋洗净 打到容器里，油热 下鸡蛋翻炒。", "在放入香菜，快速翻炒，加点生抽，盐。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/6b0144528d174345816475e06725ee99_690w_390h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('小鸡炖蘑菇', '肉类', '童子鸡', '', '[{"name": "适量东北榛蘑", "amount": "适量"}, {"name": "一只鸡肉", "amount": "适量"}, {"name": "适量（手握一把）土豆粉条", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量蒜", "amount": "适量"}, {"name": "两颗八角", "amount": "适量"}, {"name": "适量酱油（生抽，老抽混合汁）", "amount": "适量"}, {"name": "两勺料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "少量糖", "amount": "适量"}, {"name": "少量香菜（备选）", "amount": "适量"}]'::jsonb, '["榛蘑去根泡发2小时左右，中途换2次水，顺一个方向搅拌甩掉泥沙杂物，备用。（蘑菇泡发后不要用手挤水）", "土豆粉条可以先用水泡1小时左右，这样比较爱熟，比较省火，做菜时间上也比较好掌握，未泡的土豆粉条大约要30分钟左右熟，泡过的土豆粉条10分钟左右就可以熟。", "准备好鸡肉，葱姜蒜，酱油（生抽和老抽混合汁），盐，糖，八角。", "鸡肉斩块，葱姜蒜切大块。", "热油，加入葱，姜，蒜，八角，最好选用大豆油。", "加入生鸡肉爆炒，炒到基本没有多余水份，鸡肉有焦香味为止。", "倒入料酒翻炒。", "倒入酱油混合汁和少量白糖翻炒。", "持续大火，炒到上色均匀。（以上5,6,7,8,9步骤大约10分钟之内完成）", "倒入热水。（尽量不要倒凉水，因为凉水会使鸡肉发紧，口感不好。）", "汤汁沸腾后调中小火炖鸡。（整个过程根据鸡肉的品种而定，东北笨鸡一般要1个多小时才会熟，三黄鸡20分钟就可以熟。炖到鸡肉熟透，汤味浓郁就可以了）", "鸡肉炖好后加入泡发好的榛蘑，土豆粉条，加盖炖10分钟左右，然后开盖调大火再炖10分钟左右，根据自己口味加适量盐调味后就可以出锅了。", "做好的菜依照个人口味加入适量的香菜或者葱花调味。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/508641a889cd11e6b87c0242ac110003_620w_380h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('无水葱油童子鸡（珐琅锅版）', '肉类', '童子鸡', '', '[{"name": "童子鸡", "amount": "1000克"}, {"name": "12颗葱", "amount": "适量"}, {"name": "2大块姜", "amount": "适量"}, {"name": "红辣椒", "amount": "1个"}, {"name": "料酒或（花雕酒）", "amount": "5勺"}, {"name": "香油", "amount": "1勺"}, {"name": "适量生抽或（蒸鱼豉油）", "amount": "适量"}, {"name": "适量黑胡椒粉", "amount": "适量"}, {"name": "花椒油", "amount": "1勺"}, {"name": "适量色拉油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["童子鸡洗净控干水份、少许盐和胡椒粉里外抹匀后腌制半小时", "珐琅锅、锅里抹一层薄薄的油、姜2大块切片、、一把葱洗净切大段、均匀铺在锅底、最好把锅底铺满", "把腌制好的鸡放入锅中、淋上料酒", "盖上锅盖中火开始煮、有蒸汽出来后、改小火20分钟后关火、可以用筷子戳一下、看是不是可以轻松戳透肉、如果是那就说明鸡煮好了", "趁热在鸡上淋入生抽，或（蒸鱼豉油）也可，在撒上葱花和香菜、红辣椒。然后另取一口小锅、倒入适量色拉油、1勺花椒油、1勺香油烧至滚汤冒烟后关火、直接淋在鸡身上即可、大功告成、开吃吧！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/0dabdc8bd0e94faeafd6bfe94612a834_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('清蒸童子鸡', '肉类', '童子鸡', '', '[{"name": "童子鸡", "amount": "1 只"}, {"name": "适量花雕酒", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["童子鸡洗净，沥干水分", "斩四大块，调入葱、姜、花雕酒\n盐、腌制 2 小时", "蒸锅上气后，大火蒸40分钟即可"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/dae7ce43695e40ee80620f3ee5779704_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('青椒童子鸡', '肉类', '童子鸡', '', '[{"name": "半只（约900克）童子鸡", "amount": "适量"}, {"name": "少许花椒", "amount": "适量"}, {"name": "3—4个青椒", "amount": "适量"}, {"name": "红尖椒", "amount": "10个"}, {"name": "10多个泡野山椒", "amount": "适量"}, {"name": "适量姜片", "amount": "适量"}, {"name": "适量蒜瓣", "amount": "适量"}, {"name": "少许葱段", "amount": "适量"}, {"name": "少许蒜苗", "amount": "适量"}, {"name": "1匙料酒", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许胡椒面", "amount": "适量"}, {"name": "2匙生抽", "amount": "适量"}, {"name": "1匙老抽", "amount": "适量"}, {"name": "1匙蚝油", "amount": "适量"}, {"name": "1匙郫县豆瓣", "amount": "适量"}, {"name": "少许白糖", "amount": "适量"}, {"name": "少许橄榄油", "amount": "适量"}, {"name": "少许菜籽油", "amount": "适量"}]'::jsonb, '["将鸡洗净，宰成小块，沥干水分。用花椒、姜片、料酒、盐、胡椒粉、生抽（1匙）、橄榄油腌制30分钟。", "准备配料。", "锅内倒入菜籽油，中大火烧至6成热。锅内放入花椒、姜片、蒜瓣爆香，倒入腌制好的鸡肉炒。", "鸡肉炒的时间要长些，直到把鸡肉的水分炒干，鸡肉焦黄，这是获得香糯口感的关键（这时锅内的水分已干，只剩下油而没有水）。", "加入红尖椒、泡野山椒、郫县豆瓣、蚝油、生抽（1匙）、老抽炒匀。", "炒几分钟后加入青椒翻炒。", "最后加入白糖、葱段、蒜苗炒一下。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/44c239f317da4a5abc083ccdb8f22604_810w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('清蒸童子鸡-感觉身体被掏空？三伏天吃个童子鸡补一补！', '肉类', '童子鸡', '', '[{"name": "半只新鲜童子鸡", "amount": "适量"}, {"name": "盐", "amount": "5克"}, {"name": "生姜", "amount": "3片"}, {"name": "小葱", "amount": "5根"}]'::jsonb, '["把童子鸡洗净，用盐把里外都均匀抹上盐，腌制片刻。", "在童子鸡肚子里塞入生姜和小葱。", "锅里烧水，水开后，把装有童子鸡的碗放入锅里，大火蒸30分钟即可。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/94d3823d42ad4538a50722772bd26e40_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香菜牛肉', '肉类', '牛肉', '辣', '[{"name": "牛肉", "amount": "200克"}, {"name": "若干根香菜", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "红辣椒", "amount": "适量"}, {"name": "淀粉", "amount": "2勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "2～3勺生抽", "amount": "适量"}, {"name": "酱油", "amount": "1勺"}, {"name": "黑胡椒", "amount": "适量"}, {"name": "糖", "amount": "适量"}, {"name": "花椒粉", "amount": "适量"}, {"name": "孜然粉", "amount": "适量"}]'::jsonb, '["牛肉切条或者切丝，加入生抽，酱油，糖一小撮，黑胡椒碎，孜然粉，花椒粉，淀粉，一点油拌匀腌制一会", "姜切丝，辣椒蒜切末备用", "香菜洗净切段", "锅中热油，可以放点花椒爆香，再捞出丢掉，先放入姜丝，辣椒蒜末爆香。", "喜欢的还可以加点孜然爆香，再滑入牛肉，快速翻炒变色，加点料酒增香", "牛肉全部变色后加入香菜，鸡精，快速翻炒几秒即可。", "出锅装盘～"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/8857624cbeb441d4b7f9a68d48408d78_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('青椒炒牛肉', '肉类', '牛肉', '', '[{"name": "牛肉", "amount": "6两"}, {"name": "青椒", "amount": "2个"}, {"name": "适量蒜头", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "朝天椒", "amount": "2条"}, {"name": "葱", "amount": "1根"}, {"name": "蚝油", "amount": "3勺"}, {"name": "酱油", "amount": "1勺"}, {"name": "白糖", "amount": "0.5勺"}, {"name": "1点点鸡精", "amount": "适量"}, {"name": "淀粉", "amount": "0.5勺"}]'::jsonb, '["牛肉切薄片，姜葱蒜辣椒切好备用", "把姜葱蒜辣椒倒入牛肉一起，再加入两勺蚝油，一勺酱油，白糖，鸡精，少许淀粉和适量食用油", "搅拌均匀，腌制至少十分钟", "青椒切块，烧一锅开水倒入一点盐一点食用油，把青椒倒入进去焯水，一分钟左右", "烧热油锅，把腌制好的牛肉倒下去大火翻炒，炒至变色把焯过水的青椒倒入，加入1勺蚝油，翻炒均匀即可（青椒倒入后炒几下就可以，不用炒太久）", "青椒炒牛肉完成✅"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/0e66aa5052234665a079148417d393ee_3024w_2420h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('又香又嫩的小炒牛肉（巨好吃，手残党也能做）', '肉类', '牛肉', '', '[{"name": "牛肉（牛里脊更好）", "amount": "350克"}, {"name": "一小勺（约1.5克）小苏打", "amount": "适量"}, {"name": "一勺（喝汤勺）老抽", "amount": "适量"}, {"name": "二勺生抽", "amount": "适量"}, {"name": "一勺蚝油", "amount": "适量"}, {"name": "一勺花椒油", "amount": "适量"}, {"name": "一勺半（辣味的）烧烤料", "amount": "适量"}, {"name": "半勺孜然粉", "amount": "适量"}, {"name": "二勺熟芝麻", "amount": "适量"}, {"name": "少许蒜末、葱花", "amount": "适量"}, {"name": "三勺食用油", "amount": "适量"}]'::jsonb, '["牛肉洗净备用。", "调料表（可点开看大图）", "横切牛羊竖切猪。切牛肉时找到牛肉的纹理走向，横着下刀，切断纤维组织与筋膜，炒熟的肉口感才会鲜嫩。", "如图所示。", "肉片尽量尽量切薄一点，好熟，切好的肉片放入碗中。", "加入步骤2⃣️中除食用油和芝麻之外的所有调料。\n\n注意⚠️ 上面的调料放完一定不要放盐！另外加盐肯定会咸！而且，腌牛肉不放盐也是炒制时不出水的关键！", "抓匀，多抓一会儿，一定要把所有调味料都抓均匀。", "倒入食用油。", "用食用油把牛肉封住，不使水份流失，腌制半小时以上（可隔夜冷藏。腌制二天左右再炒，口感是最好的！！！）", "炒牛肉。锅烧热放油，爆香蒜末。", "开大火，倒入牛肉煸炒。", "大火将牛肉快速翻炒1～2分钟（肉片薄而少最多一分钟，多而厚二分钟。别炒久，肉会老。一定大火！！）\n\n有厨友说炒牛肉会出水，三个关键：一，腌制时不放盐！即使腌料盐不够，也在出锅之前加盐为好；二，炒时油多一点，油多才能封住肉汁；三，大火快炒。记住这三点，一定能炒出好吃的牛肉！", "关火撒芝麻。", "出锅撒葱花。", "另一次做的。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/c41a99034121487991dd80c88b6df261_3780w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱香浓郁的葱爆牛肉', '肉类', '牛肉', '', '[{"name": "牛肉", "amount": "200克"}, {"name": "（约200g）大葱", "amount": "1根"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "一汤匙蚝油", "amount": "适量"}, {"name": "一汤匙生抽", "amount": "适量"}, {"name": "半茶匙白糖", "amount": "适量"}, {"name": "半汤匙老抽", "amount": "适量"}]'::jsonb, '["1 葱白滚刀切，按压几下，使其松散点；", "2 蒜瓣切厚片；", "3 牛肉顶刀切薄片；", "牛肉上浆：牛肉中加入一茶匙研磨好的黑胡椒和粗盐、小半汤匙生抽、小半汤匙老抽、半汤匙蚝油，顺着一个方向搅拌，最好多搅拌一会儿。打上劲后依次加入适量葱姜水，直至牛肉不吸水为止，最后倒入香油抓散肉片，进行油封，放置一旁备用。", "酱汁：半茶匙白糖、半茶匙鸡粉、一茶匙香油、一汤匙生抽、一汤匙蚝油、半汤匙米酒、半汤匙米醋，搅拌均匀。", "起锅热油，油温六七成热，倒入牛肉煎一小会定型，然后再滑散，待牛肉两面变色后捞出备用。", "锅内留底油（有条件可以补点牛油），倒入蒜片葱白爆香，加入小半茶匙盐，翻炒大约一分钟，此时葱白会出现焦边。", "倒入牛肉翻炒均匀，接着加入酱汁，爆炒大约30-60s，即可出锅。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/a0a4c8384c404f84b4d71ea0d41d7946_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('滑蛋番茄牛肉', '肉类', '牛肉', '', '[{"name": "牛肉", "amount": "400克"}, {"name": "（3-4个）番茄", "amount": "300克"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "TBSP牛奶", "amount": "1大勺"}, {"name": "葱", "amount": "1根"}, {"name": "TBSP番茄泥(tomato purée)", "amount": "1大勺"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量鸡粉(可有可无)", "amount": "适量"}, {"name": "【腌肉料】", "amount": "适量"}, {"name": "TBSP生抽", "amount": "1大勺"}, {"name": "TSP老抽", "amount": "1小勺"}, {"name": "TBSP蚝油", "amount": "1大勺"}, {"name": "TBSP麻油", "amount": "1大勺"}, {"name": "TSP生粉", "amount": "1小勺"}, {"name": "半小勺TSP小苏打", "amount": "适量"}]'::jsonb, '["牛肉切薄片提前一晚用生抽，老抽，蚝油，麻油，生粉和小苏打腌制。还有一种腌法不用过夜，用两勺小苏打把肉抓捏均匀腌15-20分钟，清水洗干净小苏打，用老抽，生抽，蚝油，麻油和少许生粉拌匀再腌15-20分钟。\n不喜欢小苏打味道的可以用蛋清腌肉，方法参照这里：https://www.xiachufang.com/recipe/107043768/", "番茄用开水滚1-2分钟，浸冷水，剥皮，切滚刀块，喜欢连皮吃的忽略剥皮直接切块。", "鸡蛋打散，加一大勺牛奶，这一步很重要❗️，能使鸡蛋松嫩。", "起油锅，把牛肉炒至变色断生盛出待用。", "洗干净锅，热油倒入鸡蛋，稍微凝固后用锅铲把蛋从锅边往中间推，反复推几次，让鸡蛋蓬松立体。没有流动的液体后粗略炒散盛出待用。", "少许油炒软番茄，加适量水，加入番茄泥，炖几分钟。水量看你想要多少汁拌饭来决定。", "倒入牛肉和鸡蛋，根据个人口味加盐，糖，生抽，和鸡粉调味。最后勾芡撒葱花。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/6f8ba18a7fb245869cd8c81babac5cc9_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('西红柿牛腩', '肉类', '牛腩', '', '[{"name": "牛腩        500克", "amount": "适量"}, {"name": "西红柿     3-4个", "amount": "适量"}, {"name": "葱            1颗", "amount": "适量"}, {"name": "姜            少许", "amount": "适量"}, {"name": "蒜            三瓣", "amount": "适量"}, {"name": "花椒        10颗", "amount": "适量"}, {"name": "八角         1颗", "amount": "适量"}, {"name": "生抽        2勺", "amount": "适量"}, {"name": "料酒         1勺", "amount": "适量"}, {"name": "冰糖         6粒", "amount": "适量"}, {"name": "干红辣椒  2个", "amount": "适量"}]'::jsonb, '["把牛腩切块，放冷水中浸泡30分钟左右，拔除血水", "葱切段，姜、蒜切片", "西红柿放入盆中，倒入开水，烫掉外皮（这样吃的时候会很方便哦），然后切块或者用手撕碎", "把泡好的牛腩冷水下锅，开锅后撇去浮沫，捞出沥干水分", "锅里放油，油热后放入葱、姜、蒜、花椒、大料、干辣椒爆香", "然后倒入牛腩，加料酒、生抽翻炒均匀", "牛腩变色后，加开水（开水要没过牛腩多些哟），开小火炖50分钟左右", "另起锅炒西红柿，炒出红油后，加半碗水烧开后，倒入牛腩锅中", "加入冰糖，盐调味，继续炖30分钟，直到牛腩炖熟。（要留一些汤汁哦，泡饭、拌面都超级好吃的）", "最后把成品倒入心爱的碗碗，哈哈，已经迫不及待了"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/58b24f0287f711e6b87c0242ac110003_678w_905h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('番茄土豆炖牛腩', '肉类', '牛腩', '', '[{"name": "2枚西红柿", "amount": "适量"}, {"name": "1颗土豆", "amount": "适量"}, {"name": "半只洋葱", "amount": "适量"}, {"name": "牛腩肉", "amount": "500克"}, {"name": "香葱", "amount": "6根"}, {"name": "冰糖", "amount": "10克"}, {"name": "盐", "amount": "5克"}, {"name": "白胡椒粉", "amount": "3克"}, {"name": "15毫升生抽", "amount": "适量"}, {"name": "15毫升油", "amount": "适量"}, {"name": "老姜片", "amount": "2片"}, {"name": "少许香葱粒", "amount": "适量"}]'::jsonb, '["将牛腩肉洗净并沥干水分，切成 2~3厘米见方的方块。西红柿（约400克）洗净后放入开水中汆烫一下，撕去表皮，去蒂，切成3~5厘米见方的大块。土豆（约150克）削皮，切成小块，浸泡在水中防止氧化。洋葱（约150克）剥去外皮，切成小片。", "牛腩肉放入煮锅中，加入足够的冷水，移至大火上，烧开后继续汆烫5~8分钟，倒掉汤汁，捞出牛腩肉块，用热的流动水冲去杂质。", "大火加热炒锅中的油，放入香葱结（或大葱1根，切成大段）、老姜片和洋葱炒出香气。", "然后放入西红柿炒软。", "把锅中的香葱结和姜片挑出，加入牛腩块煸炒至表面收紧，加入切好的土豆块。", "调入生抽，倒入可以没过锅中食材的热水（大约2400毫升），调入盐和冰糖，改大火煮沸后转小火煮2小时。", "出锅前撒白胡椒粉，改大火煮沸2分钟，至肉烂汁浓即可。上桌时可以点缀香葱或香菜、青蒜等。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/2e9d76ceedc311e6bc9d0242ac110002_1200w_1200h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('番茄炖牛腩（浓香型）', '肉类', '牛腩', '', '[{"name": "适量牛腩", "amount": "适量"}, {"name": "多点西红柿", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "土豆", "amount": "1个"}, {"name": "小葱", "amount": "1把"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "姜", "amount": "4片"}, {"name": "桂皮", "amount": "1块"}, {"name": "香叶", "amount": "4片"}]'::jsonb, '["所有原材料", "番茄表面划十字，放入沸水中烫一下去皮，因为炖牛腩的时间很久，番茄切大块就可以。", "牛腩切块（宽约2cm）\n买回来就是块状的就不用再切了（例如我）", "放入冷水中煮沸，去血水后捞出备用。", "胡萝卜和土豆切成滚刀块\n滚刀块就是让食材边滚动边切块\n适合长时间烹饪\n入味且不宜散", "小葱系一下打成结，这样看起来比较专业，不需要的时候更容易捞出来。", "锅里放少量食用油，烧热后把香料爆香。", "接着放入切好的番茄，中火慢慢熬出汁，并放入冰糖、生抽和老抽，老抽一定要少，不然颜色会变黑，冰糖是为了综合番茄的酸味，也可用白糖代替。", "牛腩、胡萝卜和小葱一起放入（土豆更好熟，等牛腩炖的差不多了后放）。", "同时往锅里倒入适量的热水。", "盖上锅盖小火炖了差不多一个小时。", "把不吃的香料捞出扔掉。", "如果汤汁快烧干了，可以再倒一些热水，尝下味道后放适量的盐，同时把切好的土豆放进去。炖肉的盐一定不能放太早，放早了肉不容易熟（理论知识满分的爸比亲口告诉我的￣▽￣\"）", "半个小时后土豆也完全入味就算完成啦！！！", "按照这个做法\n番茄到最后几乎看不到\n全部化到汤汁里了\n如果喜欢吃块状的番茄\n可以在加土豆的时候再放一些番茄进去"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/958fdb1ac0e4430b96ce3e0120034ded_1280w_851h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧牛腩煲', '肉类', '牛腩', '', '[{"name": "约800克牛腩", "amount": "适量"}, {"name": "一小块姜", "amount": "适量"}, {"name": "适量牛腩炖料(八角丁香草果胡椒粒桂皮陈皮等等)", "amount": "适量"}, {"name": "约3汤匙生抽", "amount": "适量"}, {"name": "约2汤匙老抽", "amount": "适量"}, {"name": "约2汤匙耗油", "amount": "适量"}, {"name": "约一小抓冰糖", "amount": "适量"}, {"name": "约2汤匙料酒", "amount": "适量"}, {"name": "适量水", "amount": "适量"}, {"name": "少许淀粉水", "amount": "适量"}]'::jsonb, '["牛腩切块，我切的大约4厘米乘4厘米大小。冷水加切好的牛腩加热直到水开。关火，倒掉水，冲洗一遍，沥干。", "可以买这种牛肉汤料，因为里面什么都有 ，不需要买五六七八包八角桂皮丁香什么的 然后一包用一点，剩下的摆满柜子😂\n\n或者家里已经有基本香料的也可以有什么用什么，大概四五种也可以了。", "我用的有八角四颗，草果两个(刀背稍微敲一下，比较出味)，桂皮两片，胡椒粒约1茶匙，丁香约半茶匙，花椒粒约半茶匙。\n放碗里稍微洗一下，捞起来放高压锅", "继续加入冰糖约十颗小的，姜块一块，陈皮两片(没有的话可以像我这样用新鲜的橘子皮)，有香叶可以加四张，我没有所以没加\n\n我喜欢稍甜口，所以加这么多糖，而且有冰糖煮出来的牛肉汤才会清甜。不喜欢甜的，可以少放，但是最好不要不放，口感会有差别。", "继续加入料酒", "约一茶匙五香粉", "生抽，老抽，耗油一起加入", "加入水漫过牛腩表面再多一些，高压锅大火煮上汽，调中火煮25分钟。关火，让它自己慢慢冷却到气差不多散了，再打开", "这个时候已经很好吃了，但是汤汁还比较稀，我们要稍微加工一下，才能有饭店那种浓稠的汤汁。\n\n牛腩和汤一起倒入炒菜锅，把里面的香料陈皮尽量捞出扔掉。汤不用太多，大约和牛腩表面相平再稍微少一点点就可以了", "倒多余的汤出来，煮面可以加点这个汤，很香甜。", "大火煮牛腩，尝一下味道，根据自己口味稍微调节一下，可以加点老抽调颜色。\n\n汤汁翻滚后，加入一汤匙淀粉和少许水调的淀粉水，继续大火煮一分钟，不时拌一下，变浓稠就可以关火了", "装入瓦煲，撒上葱花，来一碗白饭，就着汤汁，满足☺"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/7ebd5f56cd5e4fb2b12ae047b201763e_810w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('可以吃一辈子的红烧牛腩', '肉类', '牛腩', '辣', '[{"name": "牛腩", "amount": "1500克"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "八角", "amount": "2个"}, {"name": "桂皮", "amount": "1块"}, {"name": "30粒花椒", "amount": "适量"}, {"name": "生姜", "amount": "1块"}, {"name": "1/2个洋葱", "amount": "适量"}, {"name": "6瓣大蒜", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "黄酒", "amount": "20克"}, {"name": "老抽", "amount": "5ml"}, {"name": "生抽", "amount": "50ml"}, {"name": "冰糖", "amount": "20克"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["纯肉的诱惑", "牛腩浸泡半小时以上，多换水，最后挤干净血水切块，牛腩煮熟后会缩水，切大块点，三立方厘米左右，不然吃的时候不过瘾。", "肉块放大锅中，再冲洗一下血水，加没过肉块的足量冷水，大火开始煮。", "水沸后撇去血沫，边煮边撇，持续约一到二分钟，直到基本干净，略有白色的沫子没关系。", "将牛腩捞出沥干，撇干净的话基本不会有脏东西了，如果肉上沾的沫子多，可以用温水洗净。焯水的汤放一边静置备用。", "另起炒锅，下少许油，小火先放洋葱、生姜（拍松）、大蒜炒出香味，再下八角、桂皮、干辣椒、冰糖和豆瓣酱（如果用郫县豆瓣酱最好先剁细，容易出红油），全程小火，炒出酱香味。", "转中火，下牛肉块翻炒，炒至肉块边缘带焦黄色。", "烹入黄酒，加老抽和生抽炒匀。", "转大火，加焯水的汤，底部沉淀的渣不要倒入，如果像我一样，用高压锅炖，水量以刚刚没过肉块为宜，炖出来特别香浓。水加太多，香味会没有那么浓郁，如果用普通锅，自己酌情加水。", "转高压锅，加盐调味，大火上汽后转小火约15分钟。纯牛腩当然很过瘾，但我更喜欢再加一些蔬菜，比如炖胡萝卜土豆，最好把蔬菜先炒一下，洋葱、胡萝卜切小块，土豆适中，用少许油，下洋葱炒出香味，再依次下胡萝卜和土豆块，炒的稍稍有一点焦边，到入牛腩锅中，搅匀，再压约10分钟就好了。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/665a851db5f9468ba2a8ab54b862bb8e_2208w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('顶级牛排', '肉类', '牛排', '', '[{"name": "牛排", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "黑胡椒粉", "amount": "适量"}, {"name": "油", "amount": "适量"}, {"name": "可选黄油", "amount": "适量"}, {"name": "可选红酒", "amount": "适量"}]'::jsonb, '["超市里买好一点的牛排，注意不要买腿肉或腱子。我推荐眼肉，肥一点的好吃。初学者也不要买T骨之类带骨头的，不容易做。不需要太贵的，美国这边5刀一磅的已经很好了，10刀的可以熟练后再买。贵一点的确实好吃", "拿刀背把牛肉断筋。随便敲就好了，这步不是重点，敲薄了容易熟，而且感觉更大啊哈哈", "腌制：牛排上洒盐、黑胡椒粉、抹上油，腌制一小时或以上", "腌制后的牛排，表面油光发亮，可以入锅了", "平底锅烧热，直接入牛排", "一面煎完换一面，翻一次就够了，不用翻来翻去。时间要自己把握了，大火1分钟左右，或者表面有焦黑了就可以翻。\n（也有大师说每15秒翻一次，来回翻直到内部熟。这种事总有不同做法，看各人喜好吧。）", "关火，趁着锅里的余温加最后的调料：一小勺红酒，或者一小块黄油，倒一点点生抽也可以。这里可以自由发挥了。\n\n重要：静置5分钟享用。", "补充：很多人提到了“铸铁条纹锅”。经常做牛排的话确实可以入手一个，你值得拥有。不过这玩意儿除了牛排也没别的用了。。。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/889991bc875211e6b87c0242ac110003_1936w_2592h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛排腌制方法', '肉类', '牛排', '', '[{"name": "眼肉", "amount": "2块"}, {"name": "适量玫瑰海盐", "amount": "适量"}, {"name": "适量研磨黑胡椒", "amount": "适量"}, {"name": "黄油", "amount": "适量"}]'::jsonb, '["准备食材 用厨房纸把牛排的水分擦干净 一定要擦干净", "先撒一层研磨过的黑胡椒 再撒一次研磨过的玫瑰海盐 双面都要撒匀 包上保鲜膜放入冰箱保鲜层两个小时-四个小时", "然后拿出来用黄油煎 一定要用黄油 多一点黄油没关系 也不要怕表面煎焦 要的就是这种外焦里嫩的感觉 煎2分钟再换面 一共煎5分钟即可 全程中火煎 再搭配喜欢的蔬菜开吃吧"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/75038766fa634994a9f869f55ec598ce_2016w_1512h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('黑椒牛排（配酱汁做法）', '肉类', '牛排', '', '[{"name": "牛排", "amount": "2块"}, {"name": "少许黑胡椒（给牛排做马杀鸡）", "amount": "适量"}, {"name": "少许盐（给牛排做马杀鸡）", "amount": "适量"}, {"name": "少许食用油/橄榄油（给牛排做马杀鸡）", "amount": "适量"}, {"name": "半头紫色洋葱（酱汁）", "amount": "适量"}, {"name": "一个番茄（酱汁）", "amount": "适量"}, {"name": "1汤勺生抽（酱汁）", "amount": "适量"}, {"name": "少许老抽（酱汁）", "amount": "适量"}, {"name": "少许蚝油（酱汁）", "amount": "适量"}, {"name": "少许盐（酱汁）", "amount": "适量"}, {"name": "少许糖（酱汁，看个人口味）", "amount": "适量"}, {"name": "3-4瓣儿蒜（酱汁）", "amount": "适量"}, {"name": "土豆（配菜）", "amount": "1个"}, {"name": "水果胡萝卜（配菜）", "amount": "2根"}, {"name": "芦笋（配菜）", "amount": "3根"}, {"name": "半颗柠檬（配菜）", "amount": "适量"}]'::jsonb, '["先给两个牛排做个马杀鸡，双面撒盐、黑胡椒（胡椒碎更好，但我用的黑胡椒粉），再上个油儿，两面都按摩一下，弄的锃亮锃亮的就放在一边让他们自己呆着就行", "接下来准备酱汁\n先把洋葱，番茄和蒜切越碎越好", "放一点点底油，洋葱和蒜下锅炒香", "加入番茄，翻炒均匀", "之后依次加入一点点蚝油，一汤勺生抽\n加一小碗水，看口味加一些盐和黑胡椒，老抽我是主要用来调色的，糖就完全看个人口味了\n然后就放小火让它在锅里自生自灭就好，没事儿多搅拌搅拌，防止粘锅\n临出锅可以稍微勾下欠，能让酱汁更浓稠", "左边👈就是酱汁啦\n右边👉是在熬酱汁过程中煎好的配菜\n水果胡萝卜和芦笋直接煎就好，锅里放一点黄油，胡萝卜，芦笋下锅，煎到稍稍变色就可以出锅啦\n土豆先用清水加盐煮熟，然后直接用刚刚的油煎一下，看到表面有点儿焦焦的就好啦，记得加一些黑胡椒", "接下来煎牛排，做好马杀鸡的牛排直接下锅，不用再放油啦\n每面煎两分钟左右就好了，时间长了就老啦", "出锅锅摆盘盘吃饭饭，耶！\n摆盘拍照应该是整个过程最费时间的了..."]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/9cfcc3e2f2e84bfe8fd79d9ad25fcbc3_3072w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('这些煎牛排的小技巧你们都会吗？', '肉类', '牛排', '', '[{"name": "纽约客西冷牛排", "amount": "200克"}, {"name": "黄油", "amount": "50克"}, {"name": "迷迭香", "amount": "20克"}, {"name": "大蒜", "amount": "20克"}, {"name": "少许黑胡椒", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["煎牛排前将牛排用海盐和鲜碾磨的黑胡椒腌制一分钟。", "先倒入植物油，中火将油温烧至七成热，将牛排放入。切忌：不可直接用黄油煎。", "一面煎至金黄时翻面，切忌只需翻一次面。", "最后加入黄油、迷迭香和大蒜提味，用勺子将黄油浇在牛排表面，让牛排裹满带着香料味的黄油。", "牛排厚度不一样，需要煎的时间也不一样。所以最好的方法是通过触摸牛肉，感受牛排的软硬程度来看成熟度。", "大拇指放在不同的手指上，用另一只手触摸大拇指下部的肌肉，这个触感和牛肉的触感差不多。", "大家平时就可以先试一试，感受一下。", "中国人不放心牛肉品质，很多人喜欢吃全熟的牛排。虽然可以理解，但我们一般喜欢做六成熟。", "煎至想要的成熟度后，将牛排放到60度烤箱，或保温的地方静置五分钟后就可以开吃了。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/01b3c2f9837f408face809c871340edf_398w_265h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家庭自制绝对安全的牛排  简单  简单  简单', '肉类', '牛排', '', '[{"name": "牛肉", "amount": "729克"}, {"name": "适量黑胡椒", "amount": "适量"}, {"name": "橄榄油", "amount": "3勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "耗油：可选", "amount": "3勺"}, {"name": "鸡蛋清：可选", "amount": "1只"}, {"name": "红酒：可选", "amount": "3勺"}, {"name": "适量勺，或两指捻苏打淀粉：可选", "amount": "适量"}]'::jsonb, '["第一步  菜市场买牛里脊，最好这种带经带肥油的", "回家切片，大概1cm厚度。洗净，厨房纸擦干，刀工不好的厚薄随意，我也是属于刀功稀烂系列。给牛排一片片的马杀鸡，就是用牛排锤松肉，轻锤啊，不要作死的锤，锤的稀巴烂就不好吃了。", "找个大碗，要比牛排大的。里面放入所有调味料拌匀。", "把牛排一片片裹上调味料，轻轻按摩一下（牛排的幸福时光）！码入保鲜盒中，每一片单独撒些黑胡椒，盖盒腌制48小时以后就可以吃了！", "48小时候取出，酱料水分会吸收一些，变成凝胶状态，肉质变深色。选择黄油煎，奶香更浓。选择橄榄油煎，肉质更清新。选择植物油会有一点锅味，就是菜味。我个人喜欢橄榄油！", "小火慢煎不然容易糊", "快手黑椒酱：\nA不分\n黄油  10g\n洋葱  1/4颗打碎\n黑胡椒  大概量1茶勺，太多会辣\n耗油    1汤勺\nB部分\n水         小半碗 \n淀粉     1汤匙\n黄油融化，加入a部分其他混合物，加热拌匀，加入b部分水淀粉加热到半浓稠即可。\n\n说明：黑椒酱是淋酱，牛排煎熟放在盘子里，把黑椒酱淋上去。可以煮一点意面，煎个蛋组合，跟外面买的差不多"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/719f8cdae9674443b6ccacd221cbce84_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秒杀吉野家的照烧肥牛', '肉类', '肥牛', '', '[{"name": "肥牛", "amount": "300g"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "少许蒜片", "amount": "适量"}, {"name": "白糖", "amount": "1勺"}, {"name": "生抽", "amount": "4勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺淀粉", "amount": "适量"}, {"name": "半勺黑椒粒", "amount": "适量"}]'::jsonb, '["烧水加入姜片", "冰冻的肥牛解冻，我买的是冰冻牛展，比较有嚼劲，超市就有，如果买不到买肥牛也可以的。焯水，到变色马上捞起，不能煮过头，牛肉会失去鲜味", "捞起备用", "调个酱汁，4勺酱油", "1勺蚝油", "一勺白糖", "半勺淀粉，再加入几勺清水", "加入半勺黑椒粒，黑椒粉也可以", "锅下油，加入蒜蓉和切好的洋葱", "洋葱炒出香味后加入胡萝卜，其实可以一起下的", "洋葱胡萝卜炒至有些软加入焯过水的肥牛片", "炒半分钟后加入调好的酱汁，翻炒1分钟出锅", "超级香的照烧汁肥牛就做好咯", "超级有嚼劲的牛展～"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/ca4dad60fc8341299a78c8ac7a230838_1256w_1005h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('番茄肥牛汤', '肉类', '肥牛', '', '[{"name": "适量肥牛卷", "amount": "适量"}, {"name": "西红柿", "amount": "1个"}, {"name": "盐", "amount": "3克"}, {"name": "1瓣蒜", "amount": "适量"}, {"name": "姜", "amount": "2片"}, {"name": "葱", "amount": "1根"}, {"name": "白胡椒粉", "amount": "1小勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "蚝油", "amount": "1勺"}]'::jsonb, '["吃一口就会爱上", "1⃣️肥牛卷用开水烫一下捞起备用，番茄去皮切丁备用，姜葱蒜切好备用", "2⃣️锅中适量油放入姜蒜爆香，倒入番茄丁炒出汤汁，加入一勺蚝油两勺生抽翻炒均匀，加入一大碗清水煮沸，倒入肥牛卷再次煮沸，加入适量盐，一勺白胡椒粉调味，撒上葱花即可开吃啦。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/38648726ddb94d30a0ccef9cbebc8675_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到舔碗底的土豆肥牛拌饭', '肉类', '肥牛', '', '[{"name": "肥牛", "amount": "150克"}, {"name": "土豆", "amount": "1个"}, {"name": "一碗米饭", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "一勺生抽", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺黑胡椒", "amount": "适量"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "适量盐，鸡精", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}]'::jsonb, '["制作步骤：\r\n将洋葱、土豆去皮切丁备用，肥牛卷焯水去除血沫， 捞起备用，用电饭煲提前煮好米饭备用；", "调酱汁，小碗中加入生抽、蚝油，黑胡椒、老抽、 料酒、食盐，搅拌均匀备用；\r\n热锅烧油，加入土豆丁炒软加洋葱炒香，倒入一碗 清水没过洋葱和土豆，大火烧开后转中小火焖煮10分 钟，煮到土豆变烂；\r\n接着加入焯过水的肥牛卷和调好的黑椒酱汁翻炒均匀后，大火收汁即可；\r\n将煮好的米饭装碗，再淋上黑椒土豆肥牛，拌匀就可 以开吃啦！", "超级超级好吃，你们一定要试试"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/11f88f29dbc74ff1b0000a9e08712d1f_1536w_2046h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到舔盘的秘制洋葱炒肥牛卷！拌饭巨香', '肉类', '肥牛', '', '[{"name": "肥牛卷", "amount": "200克"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "半勺黑胡椒粉", "amount": "适量"}, {"name": "淀粉", "amount": "1勺"}, {"name": "小半碗清水", "amount": "适量"}]'::jsonb, '["先调一个酱汁:碗中加入生抽+老抽+蚝油+胡\r\n椒粉+料酒+淀粉+半碗清水搅拌均匀。", "肥牛卷放入开水中,焯30秒变色捞出备用,洋\r\n葱切丝。", "锅热入油,放入洋葱丝翻炒变软", "放入肥牛卷炒匀~", "淋入调好的酱汁,翻炒均匀煮至粘稠即可。最后可加入一点葱花点缀~", "直接淋在米饭上变成肥牛盖浇饭！开吃🍚！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/fd151acc0045493f98a378eddc68e1c9_1125w_759h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超下饭的酸汤肥牛', '肉类', '肥牛', '酸', '[{"name": "肥牛", "amount": "300克"}, {"name": "一把金针菇", "amount": "适量"}, {"name": "番茄", "amount": "3个"}, {"name": "黄泡椒", "amount": "1个"}, {"name": "红泡椒", "amount": "1个"}, {"name": "适量青椒、朝天椒", "amount": "适量"}, {"name": "葱", "amount": "1根"}, {"name": "姜", "amount": "2片"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "按自己口味。生抽、盐、蚝油", "amount": "适量"}]'::jsonb, '["先把配料切好，泡椒剁碎、青椒和小米椒切圈。 再烧水，烫一下番茄去皮然后切小块，金针菇焯水，肥牛放姜片、料酒焯水，变色后捞起。", "起锅热油，放入姜、蒜、泡椒爆香。", "爆香加入切块的番茄炒出汁，倒大概500ml的清水大火烧开，然后加入适量的盐、生抽、蚝油、料酒。", "加入焯水过的金针菇、肥牛煮开。", "煮开后倒入大碗（我煮的量比较多，碗装不下，用一个火锅装的），撒上青椒、朝天椒、白芝麻、葱花，热油浇下去。", "接下来就是拍照", "拍照时间", "一大锅汤都喝光，锅差点都留不住了。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/ebeb140004794f0da4f47532c64e98a5_3024w_2419h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('黑椒牛柳', '肉类', '牛里脊', '', '[{"name": "牛肉", "amount": "500g"}, {"name": "半个青甜椒", "amount": "适量"}, {"name": "1/3瓶李锦记黑椒酱", "amount": "适量"}, {"name": "半个红甜椒", "amount": "适量"}, {"name": "一个洋葱", "amount": "适量"}, {"name": "黑胡椒碎", "amount": "适量"}, {"name": "黑胡椒粉", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "淀粉", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "糖", "amount": "适量"}]'::jsonb, '["牛肉切条状，放料酒，黑胡椒粉，少许盐，淀粉抓匀至水分都吸收进肉里，腌制半小时", "洋葱切块，青红椒切成菱形", "大火入牛柳过油，6成熟时迅速捞起", "锅内留底油，下洋葱，中火炒到洋葱透明，散出甜味", "大火下牛柳，与洋葱均匀翻炒", "倒入1/3瓶的李锦记黑椒酱。翻炒均匀，加点糖提鲜，按个人口味调试，淡了加点盐", "最后加入青红椒，翻炒出香味后，出锅装盘", "装盘后，在黑椒牛柳表面撒上黑胡椒碎。完成"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/84011234875611e6a9a10242ac110002_600w_450h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('杭椒牛柳黑椒牛柳 终于找到炒出嫩牛肉的办法了 肉片肉丝都适用', '肉类', '牛里脊', '', '[{"name": "牛肉（里脊肉）", "amount": "200g"}, {"name": "青椒", "amount": "1根"}, {"name": "生抽", "amount": "1勺"}, {"name": "盐", "amount": "0.5勺"}, {"name": "糖", "amount": "0.5勺"}, {"name": "老抽", "amount": "0.5勺"}, {"name": "蛋清", "amount": "20g"}, {"name": "1/3勺小苏打", "amount": "适量"}, {"name": "姜水", "amount": "0.5勺"}, {"name": "水淀粉", "amount": "1勺"}, {"name": "生油", "amount": "25g"}, {"name": "蚝油", "amount": "1勺"}, {"name": "生抽", "amount": "0.5勺"}, {"name": "清水", "amount": "2勺"}, {"name": "适量黑胡椒粉", "amount": "适量"}]'::jsonb, '["牛里脊肉200g切成宽厚5-7mm，长约6-7cm的条状，做牛柳时候适当粗点嚼起来口感更好。切好后用清水漂下血水，捞出控水。", "将腌制用的料放入控水后的牛肉，姜水可以切两三片姜，用手在一个碗中揉碎，把揉出的汁水倒入碗中就行了", "抓1分钟，抓匀，感觉肉条变粘上浆后腌制15分钟。", "这是最重要的一步，腌15分钟后向碗内倒入生油约25g，目的是用生油把牛柳给封起来，浸渍两小时。饭店里都是一下子封上好多斤备用。", "热锅凉油，四五成热的时候放入牛柳滑炒到变色捞出。", "调制碗汁，黑胡椒粉我是现磨的，粉的粗细可以自由调节，多少可以根据自己的口味灵活掌握。", "青椒下锅翻炒断生，倒入碗汁，倒入滑炒好的牛柳翻炒均匀就可以出锅了，蚝油也有勾芡的作用，炒出来色泽非常好看。", "看看细节是不是很有胃口，吃起来也是又嫩又滑，和饭店里炒出来的一个感觉。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/9de8a865cc2245c697f31bd8018576a5_3560w_2848h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛里脊不硬的窍门', '肉类', '牛里脊', '', '[{"name": "料酒", "amount": "适量"}, {"name": "勺", "amount": "适量"}, {"name": "克牛里脊", "amount": "适量"}, {"name": "克盐", "amount": "适量"}, {"name": "克胡椒粉", "amount": "适量"}, {"name": "勺料酒", "amount": "适量"}, {"name": "老抽，生抽", "amount": "适量"}]'::jsonb, '["把牛里脊切片，横切牛羊竖切猪。", "把切好的牛里脊放在碗里加入适量小苏打抓匀，一般不到一斤的牛肉放一小勺就可以了。盖好盖子或者保鲜膜扔进冰箱冷藏。", "一般晚上吃中午腌制，如果时间不够最少也要两个小时。吃的时候从冰箱拿出来用水把小苏打洗净，多洗几次。我一般都是洗到没有血水为止。然后再用胡椒粉，生抽，糖，盐，淀粉，油抓匀炒制。这样做完得牛里脊很嫩。", "加入蚝油就是蚝油牛肉。加入牛奶就是油爆里脊。我一般加点孜然，和土豆片。孩子很喜欢。很下饭。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/76b363ef06cf4a6794f36d94df607d32_1080w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('绝对不会炒老的尖椒牛柳', '肉类', '牛里脊', '', '[{"name": "牛里脊", "amount": "200克"}, {"name": "尖椒", "amount": "1把"}, {"name": "适量淀粉", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "1-2大勺酱油", "amount": "适量"}]'::jsonb, '["牛肉切丝，或切条，或切块，随心所欲些。\n把牛肉洗净，挤干水分，水分要尽量挤干，然后开始腌制牛肉。\n用盐先均匀的洒在牛肉上，用手使劲抓到发粘，加一两勺料酒，再加一点酱油着色，我喜欢加生抽，更鲜，加生抽的话前面的盐要略微少一点点防止肉过咸，继续抓抓抓，捏捏捏至发粘，加生粉，注意不是水淀粉哦，是直接把生粉洒在肉上，抓捏至生粉完全包裹住牛肉，如果觉得太黏抓捏不匀，可以加一点点水，抓捏至肉色透亮如上图，再浇一点点油，拌匀", "不辣的尖椒，洗净，剥开去籽（去籽目的是保持菜品清洁，要不然一粒粒炒黑的籽影响美观），偷懒的话洗净沥干就行，不剥开直接炒也没关系。", "油锅冒烟后倒入沥干的尖椒翻炒，加点盐，稍微有点瘪了就盛出，颜色还是翠绿的，不用太熟，等下还要回锅再炒过的。", "最最关键的步骤来咯！ 起油锅，锅子烧热后倒油，冷油，冷油，冷油把牛肉下锅，刚放下去的时候不用炒，让它稍微在油里煎熬一会会儿时间，大概10秒后再开始翻炒。牛肉要嫩，最关键的步骤就在这里啦，再次强调，必须要热锅冷油下牛肉。牛肉划开，翻炒至差不多断生的状态，把尖椒一并倒入，开大火不停翻炒，如果觉得锅里很干，可以加一点点热水继续翻炒，等尖椒和牛柳都熟了，有点点黏黏的状态，就可以出锅啦！", "诱人的尖椒牛柳出锅啦！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/b2adf007e7bc4d3b9a3b747b9928c4c7_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单的杭椒牛柳，米饭杀手！家常开胃菜哦～', '肉类', '牛里脊', '辣', '[{"name": "牛里脊", "amount": "200克"}, {"name": "杭椒", "amount": "4个"}, {"name": "红圆椒", "amount": "1个"}, {"name": "盐", "amount": "2克"}, {"name": "生抽", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "豆腐乳", "amount": "1块"}, {"name": "白糖", "amount": "5克"}, {"name": "淀粉", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}]'::jsonb, '["准备好所有食材。", "牛肉切成粗条，加入盐、酱油、豆腐乳、料酒、胡椒粉、蚝油、白糖、干淀粉，抓匀腌制一刻钟。", "杭椒切长段，蒜切末。", "热锅凉油，倒入腌制好的牛肉，炒至断生，盛出备用。", "下蒜末炒出香味，倒入杭椒炒出辣味，加入牛柳和少许盐迅速翻炒均匀即可。", "可以开吃啦～"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/063c02f5f2724cf999ef313ca90b8967_1633w_1086h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('C记卤牛腱（可能是最简单的卤制法）', '肉类', '牛腱', '', '[{"name": "牛腱", "amount": "2斤"}, {"name": "随意桂皮", "amount": "适量"}, {"name": "随意八角", "amount": "适量"}, {"name": "随意香叶", "amount": "适量"}, {"name": "随意草果", "amount": "适量"}, {"name": "随意肉豆蔻", "amount": "适量"}, {"name": "随意小茴香", "amount": "适量"}, {"name": "随意丁香", "amount": "适量"}, {"name": "随意花椒", "amount": "适量"}, {"name": "随意干辣椒", "amount": "适量"}, {"name": "随意姜片", "amount": "适量"}, {"name": "随意大蒜", "amount": "适量"}, {"name": "随意大葱葱白", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一小口！白酒", "amount": "适量"}, {"name": "一小块！冰糖", "amount": "适量"}]'::jsonb, '["首先要挑选一块好的牛腱，首选筋膜丰富的腱芯（又称：金钱腱），不论筋纹还是口感，都是最棒的。当然腱芯的价格也会比一般的腱子肉贵一些。", "第1个“一小时”：不汆水，用浸的！\n把牛腱分割成大小合适的条状，横截面就差不多是切片的大小，牛肉煮后会缩水，留点余量不要切太细了。切好的牛腱浸在水中去血水，期间多换水多翻动翻动，尽可能多洗去一些，土豪可以用流动水。看图片一小时下来是不是也白白的了~~", "第2个“一小时”：倒掉水，把牛腱放入冰箱冷冻，是冷冻，冷冻！\n此做法可保切片不散，肉质也更紧致！\n完全无事可干的一小时，赶时间的可以去掉这个步骤。", "香料准备工作：把你家的香料全都拿出来，每个都放一点，随意就好，缺几样也无所谓的。新鲜的姜蒜葱也一样，不强求，有就放。喜欢蒜味的朋友们，推荐你们把一整头大蒜放进去，不要剥开，不要去皮，冲一冲就可以了。如果香料实在不多，那么加一包五香粉吧，但口感不怎么好，总有点粉粉的。", "第3个“一小时”：汤锅中加入所有香料、调料、水（不要加太多，不够可以补），大火煮开。接着把冰冻了一小时的牛腱直接加入沸锅中，汤汁要没过牛腱，不够再加热水，大火再煮沸。", "因为没有汆过水，多少还有些血沫的，刚开始容易噗锅，盖子开一些并且注意观察。前10分钟大火滚煮，人不要离开。中程改中火，厚底汤锅可改小火，保持滚就行了。期间看望几次，顺便翻翻身尝尝味，缺啥补啥。咸味可以略重一些，这样肉中间是刚好的。\n最后这个一小时是大致时间，具体看火力和肉的大小决定，筷子能插入即可关火，喜欢吃有嚼劲些的，差不多是稍用力能插入的程度。", "浸泡6小时以上或者过夜，过夜的话要放冰箱。吃的时候再切片。撒上椒圈，开瓶啤酒，看看美剧，吹吹空调，我就问你爽不爽！！！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/0cae1296897111e6b87c0242ac110003_1000w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱牛腱子（前腱）', '肉类', '牛腱', '', '[{"name": "一个牛前腱子", "amount": "适量"}, {"name": "两根葱", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "两头（别包皮洗净后拉几个口）蒜", "amount": "适量"}, {"name": "半袋（500一袋）甜面酱", "amount": "适量"}, {"name": "适量黄豆酱油", "amount": "适量"}, {"name": "适量红烧酱油（找色用）", "amount": "适量"}, {"name": "桂皮一块，大料（八角）5一6个花椒3一40粒，丁香3一4个，草果两个，豆冦两个，白芷3一4个，（香叶，甘草，干桔皮，小茴香各适量）", "amount": "适量"}, {"name": "5一6个冰糖", "amount": "适量"}, {"name": "适量二盐（比绿豆小的那种）", "amount": "适量"}]'::jsonb, '["第一步：先将牛腱子洗净，然后凉干水份（可以切个4一5块）\n第二步：把除了＂红烧酱油和盐＂以外的各种调料放进凉水锅中（水得多放，得把肉末过）\n第三步：大火把水烧开后把肉全放进去，等水再开时，然后红烧酱油找色（深酱红色）放盐找口味（汤得咸点）改小火炖半小时（中间别开锅盖）到点后关火，焖一个小时，再开火小火炖一个小时，（筷子能插进肉里有一点费劲，但能把肉还能提起来时正好）然后关火焖到自然凉了捞出即可，但不能马上切（会切碎的）放进冷藏室至少2，3小时后再切。（我相信您一定吃的停不下来，就是香）"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/3f2bdc528b9311e6a9a10242ac110002_960w_716h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧牛腱子肉', '肉类', '牛腱', '', '[{"name": "三条牛腱", "amount": "适量"}, {"name": "三个八角", "amount": "适量"}, {"name": "四小段大葱", "amount": "适量"}, {"name": "四片姜", "amount": "适量"}, {"name": "六粒丁香", "amount": "适量"}, {"name": "两个辣椒", "amount": "适量"}, {"name": "两个橙皮", "amount": "适量"}, {"name": "十来粒花椒", "amount": "适量"}, {"name": "一个草果", "amount": "适量"}, {"name": "一勺豆瓣酱", "amount": "适量"}, {"name": "各适量生抽,老抽,冰糖", "amount": "适量"}]'::jsonb, '["红烧牛腱子", "步骤一\n洗净的牛腱子肉", "步骤二\n将牛腱子肉切厚片备用", "步骤三\n备调料\n大葱,生姜片,干辣椒,橙皮,草果,八角,丁香,花椒,豆瓣酱", "步骤四\n将牛腱子肉焯水后备\n起锅热油\n下入姜片大葱和豆瓣酱炒香\n再把所有香料倒入锅里炒出香味\n下入焯了水的牛腱子肉翻炒\n加入料酒,生抽,老抽,冰糖炒入味\n倒入开水\n水要没过牛腱子肉\n先用大火煮十分钟\n调小火炖煮60分钟即可\n\n注：（焯牛肉时,放少许陈醋去肉腥味）", "牛腱子肉酥烂入味\n香喷喷"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e73246c6446a11e7947d0242ac110002_1620w_1215h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('零失败的牛腱子', '肉类', '牛腱', '', '[{"name": "牛腱", "amount": "900克"}, {"name": "老抽", "amount": "3勺"}, {"name": "香叶", "amount": "5片"}, {"name": "糖", "amount": "5g"}, {"name": "生抽", "amount": "2勺"}, {"name": "盐", "amount": "8克"}, {"name": "姜", "amount": "6片"}, {"name": "1/4根葱", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "桂皮", "amount": "1根"}]'::jsonb, '["牛腱子解冻后清水洗净切成如图小块，锅内加清水煮沸加入牛腱子，一直大火煮7-8分钟，把血水煮出来。", "那些白色泡沫就是血沫，取出牛腱子时用大火煮开，避开这些血沫。", "同时准备另一只锅加清水、葱、姜，香叶，桂皮，煮开。\n煮开后，把牛腱子块从前面的锅里捞出来放入这个锅内。\n使用冷水会把牛腱子的肉收紧，不容易煮熟，口感还太硬。\n调至中火，炖40分钟。", "加入盐，糖，老抽，生抽，把握不好咸度盐，老抽逐步加，尝汤的味道，比自己想要的咸度略咸一点。\n继续炖，到用筷子能轻松戳进肉内，开锅盖，大火收汁，一定要盯着，不然就前功尽弃了。\n汤和肉一起倒出来，晾凉同时浸泡入味，放一夜，第二天就有美味的早餐啦。", "我家用的老抽是我妈做红烧类菜品时专用，确实上色味道更胜一筹。好味道的秘密分享给大家。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/088f0336e24647ae866a6d3c37e887af_1000w_777h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('这绝对会是你吃过最好吃的卤牛腱！更新糖心蛋做法', '肉类', '牛腱', '', '[{"name": "两整块金钱腱", "amount": "适量"}, {"name": "（半瓶差不多）生抽", "amount": "300克"}, {"name": "花椒一把，八角3颗，桂皮1条，草果1颗，香叶3片香辛料：", "amount": "适量"}, {"name": "干陈皮1块（增加风味，实在没有就算了...）干辣椒4根", "amount": "适量"}, {"name": "白腐乳", "amount": "3块"}, {"name": "1大瓷勺甜面酱", "amount": "适量"}]'::jsonb, '["牛腱子肉放水里浸泡一小时，拿出洗干净，倒入生抽，生抽要淹没牛肉，隔夜腌制。", "牛肉和生抽倒入铸铁锅，加凉水淹没牛肉，大火煮开，撇去浮沫。", "加入所有干香料、甜面酱和腐乳，最小火炖2小时。", "拿出牛腱子肉放凉，隔夜冷藏（或者冷藏四个小时以上），第二天拿出切薄片。", "冷藏过的牛肉紧实了很多，很好切薄片。不用怕老或者柴，肉质很嫩，越嚼越香！", "有一次我急着吃，没过夜就切了，肉还很软切不了薄片。", "但厚厚的肉吃着很带感（扭～）喜欢薄片的冷藏过夜再切哦！", "这里开始说一下糖心蛋和卤蛋的做法。选一根粗一点的针，如图。还要选优质的鸡蛋，虽然鸡蛋里的沙门氏菌超过78度就不会作妖了，但糖心蛋最好还是选日本鸡蛋，能生食的那种比较安全。", "对着鸡蛋大的一头（屁股那头）扎下去，扎不动可以把针屁股对着桌上，针尖垂直向上，鸡蛋放针尖上，往下轻轻地慢慢敲，敲几下就扎进去了。", "只要扎两个小洞透气就行，可别把针全扎进去😱", "水烧开以后，把鸡蛋放进沸水，保持水沸的状态煮6分钟。就6分钟！！！", "时间到了立即关火，把鸡蛋轻轻放进凉水里静置15分钟，方便脱壳。", "剥蛋壳要小心点，轻一点，里面的鸡蛋黄还很嫩，拍了个小视频给大家看一下糖心蛋弹软的状态😊", "把鸡蛋放入凉透的卤汤里，冷藏一夜，第二天就可以吃了。", "这个是卤了4个小时的糖心蛋，里面还不够入味，第二天蛋白和蛋黄的颜色都会深一些。这里只是切开来给大家看一下糖心蛋的蛋黄状态。如果不喜欢吃糖心蛋，就把鸡蛋煮15分钟，煮熟煮透再卤，程序是一样的。祝大家好胃口😊"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/b48f7feeb0c5401da5eb3ebed5e67431_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛尾炖白萝卜汤', '肉类', '牛尾', '', '[{"name": "左右牛尾", "amount": "500克"}, {"name": "半根白萝卜", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "白胡椒粉", "amount": "适量"}]'::jsonb, '["请摊贩将牛尾破成一节一节的。回家后如果有时间，用凉水浸泡3小时左右。然后入冷水锅，开大火，等水开后再煮上2分钟，焯出血沫，然后捞出备用，注意不要粘上血沫", "将白萝卜去皮后切成滚刀块备用，葱切段，姜切片", "将焯好的牛尾放入炖锅中，加入葱姜和20ML的料酒，然后添滚开的开水，至八分满即可。大火将水烧开，然后转小火，炖2-3小时", "加入白萝卜块、少量的盐，大火将水烧开，然后再转小火炖半小时左右至萝卜块熟透即可", "喝汤时可以根据自己的口味加盐和白胡椒粉调味，吃牛尾上的肉需要准备蘸料，我通常用吃火锅时的芝麻酱调料，具体的你可以根据自己的口味来挑一个蘸料，或者只是生抽加一点点醋也可以"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/e2688bb687f311e6a9a10242ac110002_850w_566h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('法式红烩牛尾', '肉类', '牛尾', '', '[{"name": "10节牛尾", "amount": "适量"}, {"name": "一个紫洋葱", "amount": "适量"}, {"name": "两根西芹", "amount": "适量"}, {"name": "两根胡萝卜", "amount": "适量"}, {"name": "五瓣大蒜", "amount": "适量"}, {"name": "各一些色拉油、黄油", "amount": "适量"}, {"name": "三大勺番茄膏", "amount": "适量"}, {"name": "两枝百里香", "amount": "适量"}, {"name": "150毫升红酒", "amount": "适量"}, {"name": "面粉", "amount": "15克"}]'::jsonb, '["牛尾解冻完全，这样容易入味，方便烹饪，顺带一提好的肉最好的解冻方法是室温自然解冻。", "如图处理好你的蔬菜，以及其他原料，我喜欢吃土豆所以我加了一个土豆，这个随意～", "加入色拉油、黄油，锅烧热，放入大蒜，牛尾煎到金黄微棕，喷一些红酒（可以不喷）然后肉和汁水一起倒入炖锅中加入一大锅冷水，大火等水开转小火。", "用煎肉的锅放油，把所有蔬菜原料炒到软，加入番茄膏转小火，倒入炖锅。（不喜欢蔬菜太软，可以晚点加进去）", "总共炖煮三小时，炖煮半个小时后把百里香用纱布包好放进去，加一部分红酒。继续炖煮。出锅前半小时加剩下的红酒然后黑胡椒和盐调味。出锅再撒一点黑胡椒荷兰芹碎也行。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/cd4def5564f741c0bff86d3d4aabab4d_853w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('韩式清炖牛尾汤', '肉类', '牛尾', '', '[{"name": "半根左右牛尾", "amount": "适量"}, {"name": "2-3小勺（平常吃饭的小汤匙就行）料酒", "amount": "适量"}, {"name": "2—3片姜片", "amount": "适量"}, {"name": "3头大蒜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量香葱末", "amount": "适量"}]'::jsonb, '["牛尾提前一天泡在冷水里，中间换2到3次水，泡出部分血沫，姜切片，大蒜剥好", "把泡好的牛尾放入砂锅里，砂锅里倒入足量的冷水，放入料酒和姜片，开大火，等水快开，血沫已经涌上来的时候，把火捻小，用干净的大勺子把血沫撇出来，然后再把火捻大，第二批血沫涌上来的时候把火捻小，撇出血沫，重复以上步骤，直到把血沫完全撇除干净（砂锅里一定要倒入足够的水，因为撇除血沫的同时肯定也会把水带出，一会煲汤的时候是不能再添加生水进去的，所以水一定要够用）（如果嫌这样子麻烦，也可以用另一个锅焯水，冷水下锅，水开后撇出血沫，把牛尾拿出用温水冲净，再放入已经烧开水的砂锅里，我喜欢上一种焯水的方法，觉得煲出来的汤更香）", "把姜片捞出不用，把大蒜倒入砂锅里，（不要嫌多，把蒜都用上）开大火，水沸腾把火捻小，开始煲汤，最好煲够3个小时，最起码也要2个半小时（中间不要频繁的掀锅盖，更不能添加生水，我的这个做法是不放葱和任何香料的，大蒜的味道和牛尾很搭，放心，绝对不会有膻味的）", "汤煲好后按个人喜好添加盐调味，盐一定要最后再加，碗里放入适量香葱末，盛上汤，就可以享用了。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/b665f62e890c11e6b87c0242ac110003_638w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧牛尾', '肉类', '牛尾', '', '[{"name": "一根牛尾", "amount": "适量"}, {"name": "10小段葱段", "amount": "适量"}, {"name": "姜", "amount": "8片"}, {"name": "3瓣切片蒜", "amount": "适量"}, {"name": "40颗左右花椒", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "两片香叶", "amount": "适量"}, {"name": "三个八角", "amount": "适量"}, {"name": "三个干辣椒", "amount": "适量"}, {"name": "两勺味极鲜酱油（生抽）", "amount": "适量"}, {"name": "一勺老抽", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "两勺料酒", "amount": "适量"}, {"name": "一勺醋", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "少许鸡精", "amount": "适量"}, {"name": "剩下的葱，姜，花椒第三步骤的时候放。以上材料都是看牛尾的用量调整，第2步骤中的葱姜花椒用一半。", "amount": "适量"}, {"name": "其实我觉得做饭就差不多这加点那加点，用心做就会很好吃😋之前我都是随心所欲加，都写的适量，应大家要求，差不多就这么多就OK。", "amount": "适量"}]'::jsonb, '["牛尾放入冷水中浸泡三小时。中间换水三次。我买的牛尾一块差不多两指厚", "将生牛尾冷水下锅，漂去血沫捞出备用。", "压力锅里倒入开水，放入牛尾，将葱、姜、花椒、桂皮、香叶、八角包好放入高压锅中，加少许醋，上汽后中小火压25分钟左右。高压锅放汽结束后捞出备用。（如果块很薄就20分钟，块厚又粗就30分钟，此图是30分钟后成果）", "做锅热油，将葱，姜，蒜，花椒、干辣椒炒香，倒入牛尾翻炒，加料酒，适量味极鲜酱油调味，少量老抽上色，少许白糖翻炒均匀，倒入牛尾清汤（没过牛尾），大火烧开，中火炖15～25分钟入味，转大火收汁成粘稠状，加入适量盐，（味道合适可以不加）加点鸡精翻炒均匀出锅即可。", "成品！开吃！超下饭！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/fbeb517e895411e6a9a10242ac110002_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛尾汤', '肉类', '牛尾', '', '[{"name": "一根牛尾", "amount": "适量"}, {"name": "两个西红柿", "amount": "适量"}, {"name": "两个土豆", "amount": "适量"}, {"name": "一根胡萝卜", "amount": "适量"}, {"name": "一个洋葱", "amount": "适量"}, {"name": "半棵圆白菜", "amount": "适量"}, {"name": "一定不是沙司番茄酱", "amount": "适量"}]'::jsonb, '["牛尾凉水下锅，焯一下，水倒掉，然后重新做一锅水把焯好的牛尾放在里面，加葱，姜，香叶，炖两个小时，两小时后也先不要关火，一直小火炖着", "所有蔬菜切丁", "西红柿去皮然后切丁", "炒锅加油，小火将番茄酱炒出红油，再加西红柿继续炒到西红柿烂烂的，然后把炒好的西红柿倒到炖着牛尾的锅里，牛尾继续炖哈，别停火！", "炒锅加油，把土豆丁和胡萝卜丁炒一下", "然后把洋葱也放在锅里一起炒，稍微炒一下就行，然后把这些菜也倒在炖牛尾的锅里。", "小火继续炖大概半小时，加盐调味，注意搅拌，不然土豆很容易粘在锅底", "加圆白菜，再炖半小时，炖到汤汁浓稠，尝一下味道，如果不够咸就再加一些盐，就可以了！", "炖好的牛尾汤可以配米饭也可以配意面，看个人爱好吧！味道都很不错！！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/b7b86dd4899f11e6b87c0242ac110003_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('芹菜牛肉末', '肉类', '牛肉末', '', '[{"name": "牛肉", "amount": "500g"}, {"name": "芹菜", "amount": "300g"}, {"name": "干辣椒", "amount": "4个"}, {"name": "2瓣大蒜", "amount": "适量"}, {"name": "小米椒", "amount": "2个"}, {"name": "盐", "amount": "适量"}, {"name": "味精（可不加）", "amount": "适量"}, {"name": "酱油", "amount": "适量"}]'::jsonb, '["牛肉洗净，用水稍稍浸泡去掉血水，沥干水后剁成牛肉末，剁好的牛肉末放碗中沥干备用。", "芹菜去掉叶子，洗净，也切成碎末。大蒜切片，干辣椒去籽切段，小米椒切碎。", "开中火，炒锅中放入少许油，倒入切好的牛肉末，加一小点酱油迅速翻炒。炒至断生再接着翻炒片刻后盛出备用。", "锅中剩油放入大蒜、干辣椒煸出香味，然后放入芹菜末和小米椒碎，转中高火，翻炒2-3分钟。", "再放入炒好的牛肉末翻炒2分钟，出锅前加入适量盐、味精和酱油，搅拌均匀后出锅即可。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/736a894a880111e6b87c0242ac110003_2304w_1536h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('15分钟快手菜牛肉末炒杂蔬', '肉类', '牛肉末', '', '[{"name": "牛肉馅", "amount": "300克"}, {"name": "冷冻蔬菜粒", "amount": "500g"}, {"name": "各一勺（15ml）牛肉馅腌制材料（料酒，生粉，生抽，蚝油，花椒油，橄榄油）", "amount": "适量"}]'::jsonb, '["牛肉馅加腌制材料，拌匀腌制2小时以上", "蔬菜粒开水中焯一下至蔬菜粒浮起，滤干备用。", "热锅加如油，油热后倒入腌制好的肉末爆炒至变色。", "加入蔬菜粒，加一勺生抽提鲜炒匀。", "可与出锅啦～～"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/3ce74d3e5a3840349024956024cc4b46_1868w_1240h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('千层牛肉馅饼', '肉类', '牛肉末', '', '[{"name": "面皮：", "amount": "适量"}, {"name": "面粉", "amount": "250克"}, {"name": "温水", "amount": "140克"}, {"name": "盐", "amount": "2克"}, {"name": "牛肉馅：", "amount": "适量"}, {"name": "牛肉", "amount": "400克"}, {"name": "姜", "amount": "4片"}, {"name": "葱", "amount": "50克"}, {"name": "蚝油", "amount": "2勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "香油", "amount": "1勺"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "2瓣大蒜", "amount": "适量"}]'::jsonb, '["250克面粉里加入140克温水，搅拌均匀，用筷子搅拌可以，戴上厨房手套用手搅拌也可以。", "搅拌均匀的面絮揉成团，揉不光滑没关系，静置醒面1小时，再来揉就会挺光滑了。", "称好400克牛肉米。", "半颗洋葱切碎", "牛肉糜中加入3克盐、2勺生抽、半勺老抽、2勺蚝油、1勺香油慢慢搅拌均匀，分多次加入60克葱姜水，用筷子朝一个方向搅拌至完全吸收，这样作出的肉馅有汁，不会又干又硬。葱姜水可以这样制作：取出一个容器，加入50克葱碎，4片姜用压蒜器挤出姜末，然后倒入65克水泡10分钟左右，用筛网过滤出渣子，也可以用手挤压出渣子，剩下的葱姜水就可以分次加入馅料了。加入调料的肉馅腌制30分钟，最后再加入蒜泥和洋葱碎拌匀。勺子是用来喝汤的陶瓷调羹。", "取出60克面团，揉圆。", "用擀面杖擀成直径约26厘米的面片。", "面片从中间用刀划出一道切口，把肉馅铺满面片的四分之三，留出约1厘米边边不要放肉馅，没有放馅的四分之一部分往上折。", "折好的一面继续上翻。", "最后折出一个扇形，用手把边边捏一下封口。在案板上撒少量面粉，放上做好的饼胚，轻轻按压。", "做好三个饼胚在煎锅中倒入适量油，中小火煎的两面金黄，记得火不要太大，火大里面会夹生。", "煎好从中间切开，放入盘中，我已经忍不住要咬一口了。", "外焦里嫩，还有特殊的牛肉香，快来吃吧：）如果想做早餐，也可以前一天拌好馅料，做好面团，放进冰箱，早上起来再做饼胚，节省时间，可以很快做好。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/6c7a9b76151e43eea9136ad9e82b5aa8_1500w_1124h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('米饭杀手｜芹菜粒炒牛肉末', '肉类', '牛肉末', '', '[{"name": "左右牛肉", "amount": "125克"}, {"name": "一把芹菜", "amount": "适量"}, {"name": "青椒", "amount": "1根"}, {"name": "适量花生油", "amount": "适量"}, {"name": "4瓣大蒜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量白砂糖", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "酱油", "amount": "1勺"}]'::jsonb, '["牛肉洗净（我只用了这个份量的一半，因为拍照的时候忘记切了=͟͟͞͞(꒪⌓꒪*)）", "任意切成大块，然后搅成肉末", "肉末放一旁待用（如果下锅炒之前肉末出血水了，血水要去掉）", "芹菜去掉叶子然后洗净", "切成粒放一旁", "青椒也切成粒放一旁", "大蒜切成片，调料备好放一旁", "热锅下油（油放多一点），稍微冒烟就下大蒜爆香", "然后把牛肉末放进去⚠️快速⚠️翻炒，铲铲铲，得把肉末给弄散开（要不然就成芹菜粒炒肉饼了🌚）", "牛肉末会炒出不少水，保持大火，快速翻炒把ta炒干", "可以适当添点油，把肉末翻炒到像是这样👆🏻干干的、焦香焦香的，而且有一些已经粘在锅上面了🌚", "放入芹菜粒", "放入青椒粒一起翻炒至断生", "放入调味料一起翻炒，保持大火，要炒到食材都变得干燥，没有水分才可以出锅", "牛肉焦香焦香的，又有嚼头！配上芹菜的香味还有些许辣味，真的超级下饭的ヾ( ･`⌓´･)ﾉﾞ", "开动！(/ω＼)"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/a69908506ba8406cafa7fa035d93298a_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('下饭神器-辣椒炒牛肉末', '肉类', '牛肉末', '辣', '[{"name": "牛肉", "amount": "100克"}, {"name": "杭椒", "amount": "50克"}, {"name": "小米辣", "amount": "50克"}, {"name": "生抽", "amount": "10ml"}, {"name": "白糖", "amount": "10g"}, {"name": "2头蒜头", "amount": "适量"}, {"name": "生姜", "amount": "3片"}]'::jsonb, '["还好在家里屯了好多的牛肉，这一块当时超市28块钱一斤买的，现在看来好划算，切一小块下来做今天的下饭菜。", "牛肉切成小丁", "这些肉需要有一些味道更好入味，加入一点酱油，一点糖，先腌制一下。", "要下锅前，在放入水和淀粉，搅拌匀。", "然后加入一点食用油润滑，这样下锅炒的时候肉和肉之间不会容易粘连。", "起锅热油，放入牛肉末翻炒。", "等到肉都变了颜色就可以捞出备用了。", "今天的辣椒要两种，一种是小米辣，提供辣味，另一种是小杭椒，提供清香味。", "将这两种辣椒切成小小的，备用。", "起锅热油，放入蒜末和姜末爆香。", "加入辣椒末，辣椒末多炒一会儿，让辣椒的香气和辣味出来。", "接着就是放入我们炒好的牛肉末啦～ 快速翻炒一会儿，加入一圈生抽，一些白糖，翻炒30秒钟就可以出锅啦～", "一份超级无敌下饭的辣椒炒牛肉末就完成了。", "搭配上两个简简单单的素菜，就是很棒的一餐啦·", "来，看看，搭配上米饭是不是很有胃口～"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/eadf2c7a23524a50a32d413e1a258440_1616w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('蕃茄炖牛筋（快速法）', '肉类', '牛筋', '', '[{"name": "牛筋", "amount": "500g"}, {"name": "洋葱", "amount": "1个"}, {"name": "番茄", "amount": "1个"}, {"name": "1小块姜", "amount": "适量"}, {"name": "1颗八角", "amount": "适量"}, {"name": "料酒", "amount": "2汤匙"}, {"name": "老抽", "amount": "1汤匙"}, {"name": "味极鲜", "amount": "2汤匙"}, {"name": "适量（根据个人口味）盐", "amount": "适量"}, {"name": "白糖", "amount": "1汤匙"}, {"name": "适量葱", "amount": "适量"}]'::jsonb, '["锅内水烧开，牛筋洗净切块，放入锅中煮一分钟左右去血，捞出。", "将牛筋倒入高压锅内，加入姜老抽、味极鲜酱油、料酒、糖、盐，加开水没过牛筋，盖上高压锅盖。", "大火煮，高压锅冒气之后调小火煮半小时，时间到后关火，洋葱番茄切块加入锅中，大火煮15分钟收汁（无需盖锅盖），最后加入葱段即可。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/9cb91fa4898d11e6b87c0242ac110003_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('炖牛筋', '肉类', '牛筋', '', '[{"name": "牛筋", "amount": "1kg"}, {"name": "葱段", "amount": "30g"}, {"name": "姜片", "amount": "15g"}, {"name": "2粒八角", "amount": "适量"}, {"name": "10粒花椒", "amount": "适量"}, {"name": "红烧酱油", "amount": "50ml"}, {"name": "料酒", "amount": "30ml"}, {"name": "冰糖", "amount": "10g"}, {"name": "适量盐", "amount": "适量"}, {"name": "胡椒粉", "amount": "1g"}, {"name": "食用油", "amount": "10g"}]'::jsonb, '["牛筋洗净，放入沸水中汆烫至收缩，大约煮5-10分钟。烫好后捞出来过凉水，修剪去附着的脂肪和碎肉，切成适合的大小。我喜欢长条形，所以切长一点。", "炒锅烧热，加入10g（约一汤匙）的食用油。放入姜片小火煸至微微发黄，再放入葱段和八角炒香。此时倒入红烧酱油，让酱油在锅里稍微烹一下，这样炖好的牛筋会有酱香味。之后倒入切好的牛筋，翻炒几下，就可以加水了。如用高压锅，水量要刚好没过牛筋。如用普通炖煮的方式则要更多一些。加入料酒，冰糖，胡椒粉和花椒粒。大火烧开后倒入高压锅，炖约45分钟。待压力没有时开盖，捞出要吃的分量和汤汁，放入炒锅中加入烫好的豆皮或其他搭配食材，这时才放盐。焖煮至豆皮或其他食材熟透，汤汁也变得浓稠时即可出锅装盘。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/18e907fe060411e7947d0242ac110002_1604w_1069h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌牛筋', '肉类', '牛筋', '', '[{"name": "牛筋", "amount": "1500克"}, {"name": "两个八角", "amount": "适量"}, {"name": "一块桂皮", "amount": "适量"}, {"name": "一块生姜", "amount": "适量"}, {"name": "20粒花椒", "amount": "适量"}, {"name": "半个或一块橙皮或陈皮", "amount": "适量"}, {"name": "一个白萝卜", "amount": "适量"}, {"name": "适量小米椒", "amount": "适量"}, {"name": "适量大蒜", "amount": "适量"}, {"name": "适量香菜", "amount": "适量"}, {"name": "适量花生米", "amount": "适量"}, {"name": "一汤勺油", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "一小勺白胡椒粉", "amount": "适量"}, {"name": "一汤勺生抽", "amount": "适量"}, {"name": "适量陈醋", "amount": "适量"}, {"name": "适量辣椒油或花椒油", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "二汤勺啤酒", "amount": "适量"}, {"name": "适量熟白芝麻", "amount": "适量"}]'::jsonb, '["牛筋洗净.\n放入冷水锅中.\n煮开后再煮5分钟左右.\n捞出洗净备用..\n\n我这大概有4斤左右牛筋吧～\n为嘛要一次煮这么多？\n\n炫.富.啊....(˶‾᷄ ⁻̫ ‾᷅˵)", "高压锅里放入牛筋.\n\n再放入花椒.八角.桂皮.生姜.橙皮.切片的白萝卜.\n\n白萝卜可以不用去皮.洗净就好！", "再放入水...\n最起码要能盖过牛筋..", "盖上高压锅盖.\n上汽后转中小火压30分钟..\n\n泄气后可以用筷子试试牛筋是不是伱喜欢的烂度.\n\n如果不是.\n再压一会儿啊～\n\n捞出沥干水分放凉时.\n尽量分开放.\n不然有热度的话.\n牛筋会臭不要脸的粘一起.\n放凉后可以装一起.\n\n吃多少取多少.\n其它的可以分装冷冻保存.\n平时随吃随取..", "取一块牛筋切片..\n\n装入碗里！", "大蒜.小米椒切碎.\n\n香菜切碎..", "锅里放油..\n放入大蒜和小米椒爆香～", "放入生抽.白糖.白胡椒粉～\n\n炒出香味.", "放入啤酒～", "放入辣椒油或花椒油.陈醋.盐..\n\n炒出香味后.\n关火.\n让调料汁放凉！", "放凉后的..倒入牛筋里.\n放上熟白芝麻.芝麻油（香油）\n\n搅拌均匀！", "放入香菜.花生米.\n搅拌均匀～!", "尝尝味道就可以吃啦！"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/a26b6bf4302811e7947d0242ac110002_1616w_1081h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧牛蹄筋（家常版）', '肉类', '牛筋', '', '[{"name": "牛筋", "amount": "500克"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "姜", "amount": "6片"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "干红辣椒", "amount": "2个"}, {"name": "适量盐", "amount": "适量"}, {"name": "生抽", "amount": "2勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}, {"name": "适量香菜", "amount": "适量"}, {"name": "八角", "amount": "3个"}]'::jsonb, '["将牛蹄筋清洗干净，放入高压锅，加入刚刚没过牛蹄筋的水，加几片姜和八角，高压锅压45分钟，这个软硬程度我家比较喜欢，如果喜欢软烂的，可以延长时间！", "压好的牛蹄筋捞出放凉，切成大小合适的小段，胡萝卜切片，姜蒜切片，辣椒切小段", "锅中加适量油，不需要太多，油热放入姜蒜辣椒爆香", "加入牛蹄筋和胡萝卜翻炒均匀", "加入盐，老抽，生抽，糖和适量清水，盖锅盖中火稍炖一会", "汤汁收的差不多就可以盛出装盘了", "撒点香菜装饰一下，诱人吧！😍😍😍"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/1c8fe9db523145cfaae5fa13fee3067a_1500w_1500h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧板栗牛筋', '肉类', '牛筋', '', '[{"name": "牛筋", "amount": "500克"}, {"name": "板栗", "amount": "300克"}, {"name": "1汤勺老抽", "amount": "适量"}, {"name": "姜", "amount": "2片"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "花椒", "amount": "2克"}, {"name": "糖", "amount": "10克"}, {"name": "干辣椒", "amount": "3个"}, {"name": "八角", "amount": "2个"}, {"name": "料酒", "amount": "1勺"}, {"name": "盐", "amount": "2克"}, {"name": "一勺蚝油", "amount": "适量"}, {"name": "适量花生油", "amount": "适量"}]'::jsonb, '["准备所需的材料：牛筋、板栗、老抽、生抽、大蒜、生姜、八角、花椒、干辣椒、白糖、盐、料酒。", "牛筋洗净放锅中焯水烫一下，再放入煲锅中煲2小时（有高压锅的只要压30分钟），同时在快煲好牛筋的时，把板栗放入开水中烫一下剥皮备用。", "将牛筋捞出稍凉切成3厘米的段", "热锅冷油放入锅中爆香葱姜片、蒜、干辣椒、八角、花椒，再倒入生抽、老抽、耗油、料酒。", "放入牛筋和剥好的板栗，翻炒片刻加入适量的开水，盖好锅盖开中小火煮约半小时左右。", "把花椒、生姜片、八角捡出来加盐和糖调味，最后开大火收汁即可装盘食用"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/fa8bf5ddc40d477e85540e990b8c19d6_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱油牛百叶', '肉类', '牛百叶', '', '[{"name": "美味鲜", "amount": "适量"}, {"name": "熟牛百叶", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "干辣椒", "amount": "适量"}, {"name": "色拉油", "amount": "适量"}]'::jsonb, '["把牛百叶在滚水里焯一下，迅速捞出并过一遍凉水。这样牛百叶口感会很脆。", "把沥干水的牛百叶均匀的铺在盘子上。", "把葱洗净切成碎末，把葱末均匀的撒在牛百叶上。在撒点干辣椒。淋两勺的美味鲜。", "在锅里把油烧热，淋上即可。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/2ad0918e881f11e6b87c0242ac110003_597w_445h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('水煮牛百叶', '肉类', '牛百叶', '辣', '[{"name": "牛百叶", "amount": "适量"}, {"name": "白菜", "amount": "适量"}, {"name": "葱姜蒜", "amount": "适量"}, {"name": "辣椒，花椒", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}, {"name": "豆豉", "amount": "适量"}, {"name": "糖", "amount": "适量"}]'::jsonb, '["牛百叶洗净后切成宽条。", "白菜切好，用红辣椒在锅中翻炒一下，七八成熟即可，用少许的盐调味。炒好后摆在盘底。", "炒锅中加油，用干辣椒和花椒爆锅，炒切碎的豆豉和豆瓣酱，炒出红油后加开水，不要太多。将牛百叶放到水中，开到最大火，烫煮2,3分钟。期间用盐和糖调味，牛百叶熟透后立刻装盘。", "用适量的油把葱花，蒜末，辣椒，花椒爆香后，把热油浇在刚刚入盘的牛百叶上。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/e0a029ae882211e6a9a10242ac110002_1500w_1004h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('凉拌牛百叶', '肉类', '牛百叶', '', '[{"name": "牛百叶", "amount": "300g"}, {"name": "三片生姜", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "两瓣大蒜头", "amount": "适量"}, {"name": "半个鲜红辣椒", "amount": "适量"}, {"name": "适量麻油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量醋", "amount": "适量"}, {"name": "适量小葱", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}, {"name": "适量鸡精", "amount": "适量"}, {"name": "适量味精", "amount": "适量"}]'::jsonb, '["锅里倒入清水，大火烧开，牛百叶洗净切条加生姜倒入烧开的清水里", "牛百叶烧开后加料酒，继续烧2分钟，捞起，过冷水后备用", "把鲜红辣椒和大蒜头剁成碎末，加入麻油、醋、生抽、白糖、鸡精、味精后搅拌均匀", "把上一步调好的酱料浇在牛百叶上，再把小葱切段撒在上面，最后拌匀就可以端上桌吃了。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/dcc1f44a887011e6b87c0242ac110003_650w_650h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超级简单又Q弹的爆炒牛肚', '肉类', '牛百叶', '', '[{"name": "牛肚", "amount": "适量"}, {"name": "青尖椒", "amount": "适量"}, {"name": "红尖椒", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}, {"name": "白糖", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "非必需辣椒油", "amount": "适量"}]'::jsonb, '["补充一步处理牛肚的方法：牛肚买回来先整块下锅加葱姜料酒焯水，放点醋容易熟，烧开后转小火半个小时左右、煮到能用筷子戳进去就可以了，然后拿出来洗干净切条", "准备食材，尖椒（尖尖的就叫这个名字吧，具体叫啥，大家看我图片，青的比较长，红的比较短）切段，葱切段，姜切条，蒜切片；\n重点在牛肚，刚买回的牛肚是整片的，需要清洗干净，然后放锅里水煮，煮到半熟，注意千万别煮烂了，烂了没口感，煮好后切成条状备用。", "油，姜，蒜，葱依次下锅，炒香后加入少许白糖，再加适量（半勺即可）豆瓣酱，翻炒；\n倒入牛肚，加生抽，料酒，辣椒油（喜欢吃辣可以多放），炒匀", "加青红椒，大火翻炒，出锅装盘（不需要放盐）", "手写菜谱，字丑见谅", "手写菜谱2，加入可视化图形，帮助您理解这道菜的精髓"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/104d282f4a784b08931b0721877ec044_677w_751h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香辣红油牛百叶（在家也可以轻松做出川菜馆子的感觉）', '肉类', '牛百叶', '辣', '[{"name": "牛百叶", "amount": "220克"}, {"name": "四汤匙料酒", "amount": "适量"}, {"name": "合计3g葱/姜/蒜", "amount": "适量"}, {"name": "油辣子", "amount": "3g"}, {"name": "花椒油", "amount": "3g"}, {"name": "辣椒油", "amount": "12g"}, {"name": "花生米", "amount": "2g"}, {"name": "盐", "amount": "2克"}, {"name": "不多于1克白糖", "amount": "适量"}, {"name": "极少量食用碱", "amount": "适量"}, {"name": "两汤匙味极鲜生抽", "amount": "适量"}]'::jsonb, '["商家盒装售卖的百叶一般是预制过的，直接冲洗干净。", "挤干水份，+料酒，稍稍腌制5分钟", "接下来煮制作m有两种处理方式：#1、锅内放水+料酒烧开，放入百叶，涮一下马上捞出来，水开再放入，重复四次；#2、如果动作慢，担心把握不好，就放沸水10秒左右马上捞出。新手建议用第2种处理办法。", "碗底+葱白+姜+蒜+油辣子+白糖+醋四五滴+味极鲜生抽", "+花椒油+红油，把碗里底料充分拌匀", "放入百叶，码上花生末+葱花。", "吃时搅拌均匀即可，脆嫩爽口，麻辣鲜香，连料头都特别特别好吃，真的不骗你们😆"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/1d5b0fbf26354b70bcea5b545ee301c4_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('韩式牛骨汤 Korean Beef Bone Soup', '肉类', '牛骨', '', '[{"name": "2磅牛骨", "amount": "适量"}, {"name": "（1磅以内即可）牛胸肉Beef Brisket", "amount": "1块"}, {"name": "水", "amount": "6升"}, {"name": "细挂面", "amount": "100g"}, {"name": "1-2根香葱", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量胡椒", "amount": "适量"}]'::jsonb, '["先将牛骨用冷水冲净，然后泡在冷水中，大约2-3小时。第二张图可以看得很明显，2-3小时之后所有的血水、大部分油脂以及其他脏东西都泡出来了。这步很重要，可以保证你的汤出来时颜色是乳白色的。", "在大锅中用水没过所有的牛骨，然后将牛肉也放到锅中（其实我们后来骨头是分了两个锅煮，不要被第一张图骗了，没有那么满的哈）。中火慢炖，这个过程撇去浮沫。", "煮大约1个小时后，牛肉已经煮软时拿出来切成片备用。具体的煮牛肉时间还取决于你的水的多少、牛肉大小等等，请依据实际情况调整。", "这一步非常重要！切完牛肉之后，汤大概再煮3-4小时，直至汤减少了一半的时候，放凉，然后放入冰箱冷藏2小时以上，直至汤表面所有的油脂都结成硬块，然后用小勺全部刮下。这样就可以保证基本所有的油脂都被撇走了。", "当你撇完所有的硬块时，如果你的汤看上去像我们上图这样完全变成果冻状，你大概再煮20-30分钟至牛汤全都热透就可以了。但是如果你的牛骨汤撇完硬块状的油脂，下面依然是水水的，那还需要至少炖煮1小时左右。你最后的牛骨汤的质地是半透明的，有点像牛奶的，不会过稠或者过稀的。", "将细挂面煮熟之后过一遍冷水。滤去水分之后放入碗中。", "将切好的牛肉、葱花都摆在面上面，然后趁热倒入牛骨汤。", "任何多余的调味料都不需要，只要盐、现磨黑胡椒即可！牛骨汤要趁热喝哦！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/405b928888ba11e6a9a10242ac110002_700w_460h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单懒人酱牛骨（牛蝎子.羊蝎子）酱牛肉', '肉类', '牛骨', '', '[{"name": "牛蝎子", "amount": "1000g"}, {"name": "都可以的其他骨头", "amount": "适量"}, {"name": "调味", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "可有可无生黄豆一把", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "几粒花椒", "amount": "适量"}, {"name": "稍微多点（替盐）生抽", "amount": "适量"}, {"name": "适量（上色）老抽", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}]'::jsonb, '["凉水泡牛骨，多换几次水，去血水\n凉水入锅，开锅转小火，煮几分钟去浮沫\n\n骨头捞出来，凉水冲去浮沫杂质\n放进干净的锅里，放姜片八角（必要的）\n干辣椒花椒（次要的）淋上生抽老抽糖\n抓把黄豆，喜欢花生米的可以放点花生米（出来可以干吃也能当下酒菜）\n\n添水，没过骨头就行\n启动电压力锅，肉，骨，蹄筋的按钮都可以\n\n\n现在，你可以等着闻味道了😄", "想卤蛋的现在煮几个白水蛋，剥皮等着\n\n压力锅程序完成\n找个大的容器把骨头干捞出来\n晾凉，骨肉表面稍微风干（超级好吃）\n（比热吃更好吃，更好吃，更好吃啊，可以吃出西北酱牛肉的味道🐯）", "黄豆花生捞出来就可以吃了\n汤不要倒，把之前的水煮蛋放进去\n喜欢吃豆腐皮，金针菇，海带，豆干的朋友们。。。。。\n一切都可以泡进去，煮熟就可以吃了\n（提前泡进去，或者煮好再多泡着腌制一会会更入味好吃）\n不过加了太多菜的，要适当加盐奥", "来吧，不计热量，嗨起来"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/6e3d4de9ee8742249387d37c24a2dfa1_620w_621h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('美味牛骨养生汤', '肉类', '牛骨', '', '[{"name": "2-3块牛骨", "amount": "适量"}, {"name": "玉米", "amount": "1根"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "1节莲藕", "amount": "适量"}]'::jsonb, '["牛骨解冻冷水泡一个小时，把血水泡出来。然后烧开水焯牛骨2-3分钟，去除血水和沫子。", "砂锅冷水放入姜片，葱段，红枣5颗，一把枸杞，烧开。烧开后放入抄好的牛骨，烧开以后转小火。煲一个小时。", "加入玉米 莲藕 胡萝卜 大火烧开，转小火，煲两个小时。加盐撒把香菜，出锅享用～"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/4a5aae5abf5a11e6bc9d0242ac110002_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('暖身补钙牛骨萝卜汤', '肉类', '牛骨', '', '[{"name": "👇约3～4人份", "amount": "适量"}, {"name": "约800克牛骨", "amount": "适量"}, {"name": "约牛骨4倍量清水", "amount": "适量"}, {"name": "白萝卜（中大）", "amount": "1根"}, {"name": "白胡椒粒（现研磨）", "amount": "1克"}, {"name": "约20克料酒", "amount": "适量"}, {"name": "1～2个葱结", "amount": "适量"}, {"name": "2大块（约30克）姜（分2次用）", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量葱花（必备·提味）", "amount": "适量"}]'::jsonb, '["准备好所需食材·白萝卜削皮切成滚刀块", "牛骨提前一小时用清水浸泡，去除骨内血水、多余油脂。", "锅内加入适量清水，把牛骨冷水下锅，加入姜块、葱结、料酒", "中大火煮沸，再煮5分钟，中途撇去浮沫", "绰好的牛骨用清水多清洗几遍，直至水不再浑浊。", "锅内加入牛骨、胡椒、姜块、牛骨4倍左右的水量，水尽可能一次加够·大火煮30分钟「转」小火慢熬", "5小时（1小时左右加入白萝卜继续煮）", "如果锅内有汤溢出，盖子开个小缝即可。", "大约一小时左右加入白萝卜、少许盐，大火煮沸转小火慢熬半小时，至萝卜熟透，最后调味即可。", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "熬好的牛骨萝卜汤再撒点葱花提味，完美～", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/58df54bb313f4a5188db1bf141a738d5_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酱烧牛骨', '肉类', '牛骨', '辣', '[{"name": "牛骨", "amount": "1根"}, {"name": "姜", "amount": "7片"}, {"name": "适量盐", "amount": "适量"}, {"name": "葱", "amount": "1根"}, {"name": "1头蒜", "amount": "适量"}, {"name": "大料", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "桂皮", "amount": "1块"}, {"name": "干辣椒", "amount": "2个"}, {"name": "三分之一袋辣酱", "amount": "适量"}, {"name": "三分之一袋黄豆瓣酱", "amount": "适量"}, {"name": "酱油", "amount": "4勺"}, {"name": "老抽", "amount": "1勺"}, {"name": "耗油", "amount": "1勺"}, {"name": "十三香", "amount": "1勺"}, {"name": "10粒花椒", "amount": "适量"}]'::jsonb, '["牛骨凉水浸泡泡出血水，建议泡一下午换三次水", "牛骨凉水下锅，加两片姜，四勺料酒，水开后煮五分钟，撇去浮沫捞出", "热锅倒入两大勺豆油，放几粒冰糖小火熬化后放入牛骨两面煎一下不用时间过长，之后放入料酒，葱姜蒜桂皮香叶八角干辣椒花椒粒，加人四勺酱油，两勺老抽，1勺耗油，放入开水抹过牛骨，加人十三香，辣酱和豆瓣酱，盖盖小火炖煮一个小时", "我用的铸铁锅，普通铁锅适当延长时间，快熟的时候可以根据自己的口味适量加少许盐，因为已经加入辣酱和豆瓣酱了", "不喜欢辣的可以不放辣酱，根据自己的口味随意就可以了"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/7845a78793544a3a9147c94a6718f3b2_1124w_1314h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('堂妈教你做牛肉馅饼', '肉类', '牛肉馅', '', '[{"name": "牛肉，洋葱，葱，姜，食盐，鸡精，生抽，老抽，香油，葱，食用油，白糖", "amount": "适量"}]'::jsonb, '["鸡腿一根，洗净焯水去血水", "换水加葱段姜片高压锅炖出一大碗高汤", "好香啊～～～～", "高汤凉透用勺子舀去上面油脂，备用。", "一斤面粉加六两温水", "一点一点的倒入温水", "一边倒一边用筷子搅，把面都搅成图中的絮状。然后加入一勺食用油，这勺油会使做好的馅饼皮脆脆的。", "面絮揉成面团，可能有点粘手，但也不要加干面，面团越软，馅饼皮口感越棒。", "面团盖上保鲜膜或者锅盖，醒发至少半个小时。", "葱切段放温油里慢炸呈焦黄色，滤出葱油凉透。以前堂妈都用花椒水，这次选择葱油感觉更好吃，更能突出牛肉的香气。", "牛肉要选择特别嫩没有筋的部位", "葱姜切末", "牛肉要选择特别嫩没有筋的部位，如果肉中有筋膜和韧带，一定要剔除，牛肉先切粒，后剁成末，稍有粗粒也没关系，更有口感。但别用家庭用的小时绞肉机，肉纤维比较粗容易被卡住。", "牛肉末置盆中，用四根筷子顺一个方向搅拌均匀，高汤一点点顺时针打入肉馅中使其完全吸收", "一斤牛肉打进四五两高汤是最完美的。", "肉馅润润的，但太废胳膊，尽自己的能力吧", "牛肉馅里加葱姜末", "准备好调料", "肉馅中再依加入料酒、糖少许、生抽、老抽、盐、葱油、鸡精，最后再加入芝麻油和葱花姜末拌匀。", "白洋葱切末，一定是白洋葱哦，加入调好味道的牛肉馅中，静置一会。", "洋葱和肉馅的比例是1:1", "洋葱末加入牛肉馅里", "所有材料和匀", "醒发好的面团揉匀，再醒发十五分钟", "面团揉成长条", "分割成约70克一份的小剂子", "取一个剂子压扁用擀面杖檊成薄厚适中的面皮儿", "然后像包包子一样，包上牛肉馅", "把面皮的尾巴收起，压在饼子的底面。", "牛肉饼胚做好", "电饼铛预热，加一些食用油，放入馅饼胚子", "六七分钟双面焦黄即可", "金灿灿的牛肉馅饼做好了", "也可以平底锅里倒少许油，把馅饼收口朝下放入锅中，中小火慢慢煎，煎至金黄后翻面，两面都金黄色即可。记得要小火慢慢煎，不然面饼立马金黄了，馅还是生的。", "瞧瞧这馅饼的馅料，鲜嫩多汁，太好吃了", "多汁的牛肉馅饼才是好馅饼"]'::jsonb, 30, 180, '困难', 3, 'https://i2.chuimg.com/988c54766e9511e7947d0242ac110002_1280w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('好吃到爆的牛肉馅饼', '肉类', '牛肉馅', '', '[{"name": "牛肉", "amount": "1250克"}, {"name": "（大的）洋葱", "amount": "5个"}, {"name": "姜", "amount": "40g"}, {"name": "葱", "amount": "1根"}, {"name": "2汤勺(吃饭用的就可以)老抽", "amount": "适量"}, {"name": "2汤勺(吃饭用的就可以)生抽", "amount": "适量"}, {"name": "少许花椒粉", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "少许盐", "amount": "适量"}, {"name": "2汤勺(吃饭用的就可以)蚝油", "amount": "适量"}, {"name": "少许香油", "amount": "适量"}, {"name": "少许鸡精", "amount": "适量"}, {"name": "2汤勺(吃饭用的就可以)料酒", "amount": "适量"}, {"name": "两三斤 自己酌情面粉", "amount": "适量"}]'::jsonb, '["和面！面要软一些！水用温水，分次放入避免水倒多了！", "面感受下软硬，揉好就好了！面要软一些像烙饼一样就行！", "面成这样就可以了！盖上盖子醒面，一小时时间就可以！", "准备洋葱！剥皮！准备盆清水！会辣眼睛！", "可以稍微切一下放到搅碎机里！这样更快！不会太辣眼！", "用这种机子就可以！拿刀切也行！", "切成这样就可以！然后放点盐沉淀下！为了把洋葱的汁杀出来！", "拿个蒸包子的屉布把洋葱的汁儿攥出来！直到没有汁儿！", "洋葱挤完汁儿这样就可以了！", "先在肉馅里放姜葱，再放料酒，放一点水，洋葱的汁虽然都挤出去了，但还会再出汤汁，所以不用放太多水，顺势搅拌！然后放其他剩余的佐料，生抽、老抽、耗油、香油、盐、鸡精、花椒粉！搅拌！再把生鸡蛋放里，最后放洋葱！每放一次东西都要搅拌一下！朝一个方向使劲搅拌！ 我写的量是按两斤半肉馅写的，大家可以根据肉的多少，调整佐料的多少！肉和面的多少，自己调整，我家的这个量是一大家子吃，能做几十个呢！色泽达到这样味道基本上就没问题了！", "擀面皮，开始包馅饼了！就像包包子一样！", "面皮这么大就可以！薄一点好吃！不过注意也别太薄！要不会破！照的有点显大，其实没那么大！比包子皮大一些！薄一些就好！", "放这么多馅儿就可以！包出来的馅饼就很大了！像包包子一样，最后把馅饼反着放就可以！老妈是左手包的，大家自己脑补右手吧！", "电饼铛预热一下！饼铛里放油！把馅饼放进去！合上电饼铛！", "三四分钟的样子就差不多熟了！电饼铛都是双面热的！有的有指示灯的灯灭了就差不多了，没灯的自己掌握时间就好！中间可以打开看下，色泽金黄了就可以了！电饼铛不太一样，自己掌握差不多了就好！", "掌握好火候，馅饼熟了！因为面比较薄，汤汁出来了，看着有点糊！其实没糊，大家可以自己掌握，皮的薄厚，薄的好吃，可以适当薄一些！再配上一碗粥！慢慢享用吧！", "味道好记得晒图呦"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/d75fd77105cb486aa4817c18fdffb45f_854w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛肉馅饺子', '肉类', '牛肉馅', '', '[{"name": "牛肉馅", "amount": "500g"}, {"name": "（350g）胡萝卜", "amount": "3根"}, {"name": "香菜", "amount": "160g"}, {"name": "洋葱", "amount": "120g"}, {"name": "姜末", "amount": "15g"}, {"name": "五香粉", "amount": "2勺"}, {"name": "生抽", "amount": "5勺"}, {"name": "香油", "amount": "3勺"}, {"name": "适量盐（炒胡萝卜）", "amount": "适量"}, {"name": "适量食用油（炒胡萝卜）", "amount": "适量"}, {"name": "若干饺子皮", "amount": "适量"}]'::jsonb, '["牛肉馅中放生抽和五香粉顺时针拌五至十分钟，打上劲儿哈。", "洋葱和姜切末，放入香油搅拌均匀备用。", "胡萝卜擦丝，锅中放底油将胡萝卜炒熟，过程中加入跟平常炒菜时一样的盐，炒好晾凉备用。", "香菜切末备用。", "等待胡萝卜晾凉的时候，将洋葱末放入牛肉馅中继续顺时针拌匀，然后再将晾凉的胡萝卜和香菜放入馅中顺时针拌匀，过程中尝咸淡，根据自己口味可适当加盐。 其实很简单，味道超级香！", "我包的😁", "老公包的😁"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/538c3f65435a49e8ac48a4f9903ec126_1242w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('多汁麻辣牛肉末烧土豆-15分钟搞定的下饭菜', '肉类', '牛肉馅', '辣', '[{"name": "土豆", "amount": "1斤"}, {"name": "普通瓷勺4勺（当然你可以多放）牛肉馅", "amount": "适量"}, {"name": "半根螺丝椒", "amount": "适量"}, {"name": "两根香芹", "amount": "适量"}, {"name": "1瓷勺花椒粉", "amount": "适量"}, {"name": "1瓷勺（最好选香辣味的）辣椒粉", "amount": "适量"}, {"name": "3瓷勺鲜味酱油", "amount": "适量"}, {"name": "1瓷勺料酒", "amount": "适量"}, {"name": "1瓷勺蚝油", "amount": "适量"}, {"name": "半勺白糖", "amount": "适量"}]'::jsonb, '["准备好食材，提示：如果你的食材比我的多，按比例增减调味料即可。", "处理食材：肉馅加1勺料酒，1勺鲜味酱油拌匀腌制，如果你用的肉馅多就按比例增加。", "芹菜切丁，螺丝椒切丁。", "一斤土豆，先切片，再切条，最后切成四方小丁。", "锅内入瓷勺2勺油，大火，入土豆丁。", "煎到表面出现黄色焦壳，取出沥油，如图，大家可以参考。", "煎土豆剩下的底油，中火，入牛肉馅，炒至全部变白。", "入瓷勺一勺辣椒粉，一勺花椒粉，翻炒出香味。", "入土豆丁。", "入2勺鲜味酱油，1勺蚝油，半勺糖。", "如果有辣椒油可以放一勺。加水，没过土豆。盖上锅盖，大火烧5分钟。", "5分钟后，开盖，撒入芹菜碎和螺丝椒碎，关火装盘。", "一定要有些汁水才香，不需要加盐，味道足够好了。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/6ba6e39b3fc54abe8ab01f89af91f24d_960w_562h.gif', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('牛肉馅的几个要点', '肉类', '牛肉馅', '', '[{"name": "一斤半牛肉", "amount": "适量"}, {"name": "大半个洋葱", "amount": "适量"}, {"name": "一大勺花椒油", "amount": "适量"}, {"name": "两片姜", "amount": "适量"}, {"name": "一勺生抽", "amount": "适量"}, {"name": "一勺老抽", "amount": "适量"}, {"name": "一个鸡蛋", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "五大勺花椒水", "amount": "适量"}, {"name": "适量黑胡椒粉", "amount": "适量"}]'::jsonb, '["要点一，新鲜牛肉肥瘦相间，加入鸡蛋，鸡蛋的作用是让牛肉嫩滑，增加口感。同方向搅拌。", "要点二，(不要放太多)花椒水，将花椒放入热水中煮三分钟，泡半小时。花椒水分次打入牛肉馅中，用力同方向搅拌，目的很明确，1让牛肉汤汁饱满。2去腥提鲜，3搅拌为了让牛肉上劲，更有嚼头。加个顺口溜，一斤牛肉一两水，加个鸡蛋才完美。😄😄", "要点三，先放盐，同方向搅拌，为了锁住牛肉和汤汁的鲜味。加入生抽老抽，提鲜上色，继续同方向搅拌。", "要点四，加入洋葱碎姜沫，洋葱和牛肉是绝配，是灵魂，是伴侣。姜末一定要足够碎，主要是为了去腥提鲜，吃的时候吃不出来姜味。黑胡椒粉配牛肉，增加肉馅味道的多样性可使香味更加浓郁。", "要点五，灵魂伴侣，花椒油。作用是使牛肉馅鲜香顺滑，花椒油炸好后去掉花椒，直接浇在洋葱上炸出葱油。", "同方向继续搅拌，一气呵成！看着要很腻乎那种，蒸出来才有汤汁。", "好好吃啊，咬一口满口的肉香，直流汤。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/def64ed80fdb4c069c59c96feda430e6_750w_600h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('羊肉焖饭', '肉类', '羊肉', '', '[{"name": "羊肉", "amount": "适量"}, {"name": "1胡萝卜", "amount": "适量"}, {"name": "1土豆", "amount": "适量"}, {"name": "1/2洋葱", "amount": "适量"}, {"name": "食盐", "amount": "适量"}, {"name": "一勺蚝油", "amount": "适量"}, {"name": "半勺红烧酱油（生抽）", "amount": "适量"}, {"name": "少许姜丝", "amount": "适量"}, {"name": "小半勺料酒", "amount": "适量"}, {"name": "盘锦大米", "amount": "适量"}]'::jsonb, '["羊肉用清水浸泡，多换几次水，直至水是清澈的，没有血水。\n多次浸泡羊肉可去除血水减少羊肉膻味。", "羊肉切拇指大小的小块。\n生姜切条，加生抽，食盐，一点料酒腌制半小时以上。\n\n如果还是怕膻味也可以选择焯水~冷水加羊肉丁和姜片，煮出脏沫后关火冲干净。", "锅里少许油，倒入羊肉块翻炒。", "羊肉变色后加少许盐，红烧酱油或者生抽进行翻炒，收干汁关火盛出来。", "另起锅热油爆炒洋葱丝。", "土豆和胡萝卜切小块。\n\n洋葱丝炒软之后，剥开到一边，加点油放土豆胡萝卜翻炒。", "混合翻炒~", "倒入之前的羊肉，加一大勺蚝油,加点盐，生抽混合翻炒~\n\n如果你是土豪你有孜然粉或者孜然，然后你又不讨厌的话就加一把~~", "盘锦大米用清水淘洗干净，放入适量的清水，将炒好的食材连同汤汁一起倒入大米上，放入几朵洗干净的干香菇，按下煮饭键即可。（不用泡发，这个是外婆教我的小技巧，这样做出来的香菇比较香！）\n\n\n*经过大家反馈，比平时煮饭少一点水煮出来更好吃，我是按照平时的水量煮好了之后不拔插头继续再煮会儿就可以干干的出锅巴了，大家随意。\n\n①平时煮饭的水量，跳闸后别拔插头，焖干一点，喜欢锅巴的可以多煮一会儿出锅巴\n\n②比平时煮饭少点水，干一点比较好吃\n\n③如果最后煮出来比较湿，可以无油无水的锅子煸炒下", "煮出来的米饭油光发亮的特别诱惑！\n胡萝卜是甜甜的，土豆是绵绵的~\n撒一把葱花搅拌开动了~"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/cde5d33c88a311e6b87c0242ac110003_1800w_1196h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孜然羊肉', '肉类', '羊肉', '', '[{"name": "300羊肉", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量五香粉", "amount": "适量"}, {"name": "适量葱", "amount": "适量"}, {"name": "三片姜", "amount": "适量"}, {"name": "两瓣蒜", "amount": "适量"}, {"name": "适量酱油", "amount": "适量"}, {"name": "一小勺盐", "amount": "适量"}, {"name": "一小勺糖", "amount": "适量"}, {"name": "十粒花椒粒", "amount": "适量"}, {"name": "一瓣大料", "amount": "适量"}, {"name": "五棵香菜", "amount": "适量"}, {"name": "一小把孜然粒", "amount": "适量"}, {"name": "一小把辣椒面", "amount": "适量"}, {"name": "一小把芝麻", "amount": "适量"}]'::jsonb, '["将肉切片，放入少量五香粉，料酒，腌一会儿", "将材料备齐", "热油，加入花椒大料粒，出香味后捞出扔掉", "放入姜丝，葱花，炒香", "加入淹好的羊肉，翻炒到变色", "加糖适量", "酱油，适量", "白酒适量", "在锅里还有汤的时候加入孜然，为了更好入味", "加辣椒面", "汤没有时，加一小勺盐", "加入蒜片", "关火，加香菜"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/dd490530897311e6a9a10242ac110002_1620w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最简单的清汤羊肉', '肉类', '羊肉', '', '[{"name": "左右羊肉", "amount": "1000克"}, {"name": "姜片", "amount": "5.6片"}, {"name": "葱段", "amount": "3.4段"}, {"name": "1小把花椒", "amount": "适量"}, {"name": "左右盐", "amount": "12克"}, {"name": "半根白萝卜", "amount": "适量"}, {"name": "10粒左右白胡椒粒", "amount": "适量"}]'::jsonb, '["将羊肉切成大块浸泡在水中2小时，中间换两次水，我用的是羊腿肉，羊腿要剁开露出骨髓", "将羊肉放入锅中，放入冷水，水要淹没羊肉，最好多放一些，煮的时间久的话水会变少，大概淹没后再多加一指长度的水量", "大火将水煮开，撇去浮沫", "不再煮出血沫后加入葱姜和花椒胡椒，加入适量盐，中途尝尝味道，根据自己的口味调整，觉得咸可以再加水", "大火煮开后转小火炖3小时左右，也可以用高压锅25分钟，喜欢吃烂一点30分钟也可以", "将白萝卜切片放入煮15分钟左右，直到萝卜变软入味", "出锅前加入蒜苗香菜（可以多一些，提味儿），喜欢粉丝也可以煮熟放入，开吃就行啦！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a077e8e92b214191947c5df8dbf0492f_551w_368h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱爆孜然羊肉', '肉类', '羊肉', '', '[{"name": "羊肉片", "amount": "250克"}, {"name": "大葱", "amount": "1根"}, {"name": "孜然粉", "amount": "3勺"}, {"name": "芝麻", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "五香粉", "amount": "适量"}, {"name": "味精", "amount": "适量"}, {"name": "盐", "amount": "适量"}]'::jsonb, '["羊肉片水开下锅，轻微焯一下，这样炒出来的羊肉不水！控干水分备用！", "大葱切大斜刀备用！", "起锅，烧油，比平时炒菜油多一点，大葱下锅爆香！", "倒入羊肉，加料酒，五香粉，味精，盐，生抽快速翻炒！", "翻炒均匀后再加入孜然，芝麻翻炒均匀！", "出锅装盘，鲜嫩羊肉配上孜然芝麻，味道棒极了！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/5be1141da8fb48079ed7f4557e9cd61e_918w_1224h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧羊肉', '肉类', '羊肉', '', '[{"name": "羊肉", "amount": "1000克"}, {"name": "姜", "amount": "8片"}, {"name": "香叶", "amount": "6片"}, {"name": "八角", "amount": "4个"}, {"name": "适量花椒", "amount": "适量"}, {"name": "大葱", "amount": "1根"}, {"name": "2小块桂皮", "amount": "适量"}, {"name": "6瓣大蒜", "amount": "适量"}, {"name": "花雕酒", "amount": "20克"}, {"name": "豆瓣酱（葱伴侣）", "amount": "20克"}, {"name": "生抽", "amount": "25克"}, {"name": "老抽", "amount": "8克"}, {"name": "白糖", "amount": "6克"}, {"name": "适量香菜", "amount": "适量"}]'::jsonb, '["山羊肉切大块。", "清洗一下。", "冷水下锅。", "煮开，去浮沫。", "捞出，清洗一下。", "控一下水。", "大葱切段，姜切片，大蒜去皮拍一下。", "锅里放入适量的油。", "放入准备好的大料。", "炒出香味。加入羊肉。", "加入花雕酒。", "加入生抽。", "加入老抽。", "加入糖，加入豆瓣酱，翻炒一下，最后加入适量的水。", "水根据肉的多少来。可以持平，也可以高出羊肉。", "大火煮开。", "然后转小火慢慢炖，一般1个小时左右就可以大火收汁了。", "我都炖2个小时左右，大涵涵喜欢吃软烂一些的，所以大家根据自己的喜好来控制好时间，中间可以加水的。", "最后大火收汁，放入香菜就可以开吃啦。"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/8c5912ac0cd6403b83b3ae8ea18090cc_1126w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孜然烤羊排', '肉类', '羊排', '辣', '[{"name": "适量羊排", "amount": "适量"}, {"name": "适量孜然粉", "amount": "适量"}, {"name": "适量辣椒粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "三片姜", "amount": "适量"}, {"name": "一片桂皮", "amount": "适量"}, {"name": "一个八角", "amount": "适量"}, {"name": "一小戳花椒", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "两张锡纸", "amount": "适量"}]'::jsonb, '["羊排选外层有一层油皮的比较好，洗净放入高压锅，放入桂皮、花椒、八角、盐、姜、水，水没过羊排即可，大火上汽后转中小火20分钟。", "将羊肉捞出沥干，晾凉", "将盐均匀的摸遍羊排，再抹孜然粉、辣椒粉，再抹一边油，用量根据个人口味，抹好放置半小时", "用一张锡纸垫在烤盘上，另一张将羊排包好，烤箱200度上下火，烤20分钟，用锡纸包的目的是为了防止羊肉水分流失口感发柴", "20分钟后，烤箱转上火，把锡纸打开，羊排有一层油脂那面朝上，继续烤8～10分钟，目的是上色和将外皮烤脆", "外皮烤得焦黄后，出炉。用菜刀顺着排骨一根根切开，开动吧！！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/e94b5f2a885311e6b87c0242ac110003_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧羊排', '肉类', '羊排', '', '[{"name": "羊排", "amount": "500克"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "六片姜", "amount": "适量"}, {"name": "3小块冰糖", "amount": "适量"}, {"name": "小半勺老抽", "amount": "适量"}, {"name": "酒", "amount": "6勺"}, {"name": "生抽", "amount": "3勺"}, {"name": "八角", "amount": "1个"}, {"name": "香叶", "amount": "2片"}, {"name": "1大片陈皮", "amount": "适量"}, {"name": "很小一块（没有也没问题）桂皮", "amount": "适量"}, {"name": "蒜苗", "amount": "1根"}, {"name": "蒜", "amount": "5片"}, {"name": "1小把孜然粒", "amount": "适量"}]'::jsonb, '["提前五六个小时解冻羊肉（如果是新鲜羊肉就直接浸泡），把羊肉放入冷水中浸泡，隔一两个小时换水，直至没有血水。胡萝卜切块，姜切片，蒜切小块待用。", "在锅中放两片姜，放入羊肉，开大火，把羊肉飞水（把沫撇掉）。飞水好的羊肉用冷水冲洗一遍放在旁边待用。", "热锅，放入少量花生油，待油热后放入姜蒜爆香。", "放入羊肉翻炒，翻炒至边缘焦黄。", "倒入生抽，老抽和酒，翻炒均匀。", "放入八角，桂皮，香叶，陈皮，孜然粒和冰糖，翻炒至均匀。", "放入胡萝卜，翻炒至均匀后，倒入适量酒。这道菜不放水，就放酒，煮至酒干后更加香。", "将翻炒至均匀的羊肉连肉带汁倒入砂锅，大火烧开，小火焖四十分钟后，放入蒜苗翻炒，大火收汁。", "就可以吃了，香。"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/80bb60971b524957be880ca006358be8_3029w_2286h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('酥而不腻的红烧羊排', '肉类', '羊排', '', '[{"name": "羊排", "amount": "500克"}, {"name": "5粒花椒", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "三片姜", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "一小片陈皮", "amount": "适量"}, {"name": "五粒冰糖", "amount": "适量"}, {"name": "各一勺蚝油老抽生抽", "amount": "适量"}, {"name": "一根胡萝卜", "amount": "适量"}, {"name": "小半跟白萝卜", "amount": "适量"}, {"name": "两根点缀增香新鲜大蒜", "amount": "适量"}, {"name": "料酒", "amount": "20克"}, {"name": "浸过羊排水", "amount": "适量"}]'::jsonb, '["羊排解冻、洗净、水烧开，放入羊排，这一步是需要焯水，水开后把羊排倒入冷水冲洗干净。", "羊排上有些许些油，我把它切下来，锅烧开，放入洋油炒出油，放入生姜，大蒜，八角，花椒等炒香，把羊排放入锅中一起炒，炒出香味后放入冰糖继续翻炒。", "倒入料酒、蚝油、生抽老抽、盐少许，加入冷水大火烧开转小火，喜欢酥一点就炖1个小时左右，喜欢有嚼劲就40分钟左右。", "锅里还剩三分之一的汤汁可以把辅料红萝卜白萝卜放入，大火烧开转小火大概十到十五分钟左右。最后收汁开大火。", "收汁起锅前放入新鲜大蒜叶点缀增香。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/efdca225b3584490b026210ae4d5d47b_1152w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧土豆羊排', '肉类', '羊排', '', '[{"name": "一盆的量羊排", "amount": "适量"}, {"name": "约两颗吧土豆", "amount": "适量"}, {"name": "若干冰糖", "amount": "适量"}, {"name": "若干花椒、辣椒、香叶、八角、蒜片、大葱（京葱）、小细葱", "amount": "适量"}, {"name": "若干生抽、老抽、蚝油", "amount": "适量"}, {"name": "若干料酒", "amount": "适量"}]'::jsonb, '["羊排沿骨头一根根切开，绰水。起油锅，半热时转小火放花椒爆香，后捞出弃之，再放蒜片大葱辣椒转中火爆香，放冰糖小炒一会，下羊排，点料酒，放三片香叶两颗八角，喷生抽老抽蚝油，炒匀。入水起码半锅，大火开后转中火煮25分钟，放土豆块，大火开后中小火约20分钟。汁收干就成。起锅，剪葱花装饰。是的，全程不放盐。", "找了另一个图，羊排切到如图状态（这生姜当归羊肉汤是上次舌尖第二天的后遗症。这汤焯水后，放料酒生姜当归小火一起煮啊煮啊，放一点盐，喝的就是汤）"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/22d90f5eefcc4826926d294b247fe8a2_725w_543h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('最简单的家庭版烤羊排', '肉类', '羊排', '', '[{"name": "羊排", "amount": "2斤"}, {"name": "适量孜然粉", "amount": "适量"}, {"name": "适量辣椒粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}]'::jsonb, '["抓适量的盐均匀抹在羊排上", "烤架放在中层，下层烤盘垫上锡纸接油，180度烤20分钟", "然后拿出烤架和烤盘，烤盘中的油倒掉，把羊排转移到烤盘中，开始撒调料，我撒了很厚一层呐~烤盘放在中间180度烤20分钟", "之后把烤盘放到最上面位置，烤箱调到上层火，210度再烤10分钟。让外面一层皮更焦", "大功告成", "两个人没有吃了，太划算了！"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/ae9890948cf8498fb5d2f75bfbdb0051_1500w_1124h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧羊腿肉', '肉类', '羊腿', '', '[{"name": "没称重羊腿肉", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "八角", "amount": "2个"}, {"name": "香叶", "amount": "1片"}, {"name": "若干大葱段", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "适量酱油", "amount": "适量"}, {"name": "适量姜片", "amount": "适量"}, {"name": "可有可无啤酒", "amount": "适量"}]'::jsonb, '["羊腿肉挑带一些肥肉的部分，切成小块备用，多换几次水，洗净血水", "冷水，扔几片姜片，烧开，下羊肉块，再次烧开，俗称的抄水，能去净羊膻味和血沫子，大概滚开2-3分钟就可以，冲净控干水备用", "准备辅助材料 有冰糖可以准备一小块 色泽会非常好看，没有也没关系", "热锅凉油，油不需要多，下姜片，八角，桂皮，小火烘炒出香味，下羊肉转中大火炒3分钟左右，倒入料酒，继续翻炒", "料酒挥发掉之后，倒入酱油，酱油里面有焦糖，所以翻炒要勤，不要糊锅了，翻炒至酱油的味道散去，肉都挂上颜色，锅底都是油的那种感觉，下葱段，冰糖，翻炒几下葱变色，马上加入开水", "开水没过羊腿肉，放干辣椒和香叶，加一小勺十三香可以提味，再加一些啤酒更好，没有也没关系，反复炒的过程中，羊膻味基本没有了。大火烧，再次挥发羊膻味，倒入高压锅，20分钟，比较省事，也可以用砂锅，小火慢炖，味道很特别呢！", "我这次用的高压锅，出锅加盐，又收了一下汤汁，撒上香菜段，就可以开吃啦！这是给老公做的午饭，饭盒装的，开盖之后满屋飘香～很简单很方便"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/efbaa36ec4d711e6bc9d0242ac110002_960w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('胡萝卜炖羊腿', '肉类', '羊腿', '', '[{"name": "羊腿", "amount": "2斤"}, {"name": "胡萝卜", "amount": "2根"}, {"name": "香菇", "amount": "10个"}, {"name": "腐竹", "amount": "3根"}, {"name": "姜", "amount": "1块"}, {"name": "红枣", "amount": "2个"}, {"name": "八角", "amount": "1个"}, {"name": "香叶", "amount": "1片"}, {"name": "桂皮", "amount": "1个"}, {"name": "干辣椒", "amount": "1个"}, {"name": "冰糖", "amount": "1块"}, {"name": "半碗料酒", "amount": "适量"}, {"name": "4汤勺生抽", "amount": "适量"}, {"name": "2汤勺老抽", "amount": "适量"}, {"name": "1汤勺蚝油", "amount": "适量"}]'::jsonb, '["准备材料", "胡萝卜滚刀切块，腐竹切段后放碗中加冷水泡发，香菇冲洗一下放碗中泡发。", "羊腿带着包装放入冷水中，等待其解冻。\n\n» 化冻不要去掉包装，不然肉容易泡烂。如果是新鲜的羊肉就不用化冻啦。", "化冻好的羊腿，拆掉包装，用流水冲去表面血水。", "锅中加冷水没过羊腿，放姜片，不盖盖子，等水开后再煮三四分钟。\n\n» 焯水可去除肉中的杂质，但也会损失一部分鲜味。如果想保持更多鲜味，就不建议焯水啦。", "焯好的羊腿，用温水冲一下，放一旁备用。", "热锅冷油，丢入一块冰糖，不断翻炒至冰糖融化。", "这块冰糖有点大，最好挑几块小块的。全程小火炒糖，不然容易焦。", "放入姜片、蒜粒、干辣椒爆香。", "倒入前面处理好的羊腿，中火翻炒。", "表面裹上糖色后，加入半碗料酒。", "放入1片香叶、1块桂皮、1个八角、2个红枣。然后倒入没过羊腿的热水。大火煮开后转中小火炖1个半小时。\n\n» 这里没有放盐、生抽这些咸味的调料，因为先放会使肉质收紧不易煮烂。汤的颜色来自糖色。水最好一次家族，如果中间水快要烧干了，加水记得加热水哦。", "炖羊腿的这会，另起一锅处理配菜，胡萝卜先入锅煎。\n\n» 胡萝卜煎过之后，不易炖烂。", "腿炖了1个半小时后，锅中放入胡萝卜和香菇，加一些热水。等到胡萝卜煮软后放入腐竹。\n\n» 腐竹很容易熟，所以不用太早放。", "最后加4汤勺生抽，2汤勺老抽，1汤勺蚝油，煮10分钟左右关火焖。", "一锅超级软烂的羊肉就做好啦！"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/53cd20cc179d44db8ffc1abd6a219853_720w_480h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('羊腿汤', '肉类', '羊腿', '', '[{"name": "羊小腿", "amount": "1只"}, {"name": "半根大葱", "amount": "适量"}, {"name": "少许姜", "amount": "适量"}, {"name": "少许花椒", "amount": "适量"}, {"name": "少许茴香籽", "amount": "适量"}, {"name": "干辣椒", "amount": "2只"}, {"name": "适量萝卜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量香菜", "amount": "适量"}]'::jsonb, '["羊小腿洗干净放入高压锅，放入大葱、生姜、花椒、茴香籽、干辣椒，加水没过羊小腿，等上汽了中火压25分钟（如果是滩羊就省去这一步）", "取出羊小腿，放入汤锅。汤过滤，去掉香料放入汤锅", "萝卜切块放入汤锅，一起炖煮。等萝卜能轻易戳穿加入盐，尝尝咸淡，稍微偏淡些就好，再煮十分钟左右。撒香菜沫出锅"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/139efcf7ad054411b937fd0cc51077fa_911w_1620h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('生烤羊腿家庭烤箱版', '肉类', '羊腿', '', '[{"name": "羊腿", "amount": "1只"}, {"name": "盐", "amount": "20克"}, {"name": "辣椒粉", "amount": "1勺"}, {"name": "姜", "amount": "5片"}, {"name": "孜然", "amount": "5勺"}, {"name": "20粒花椒", "amount": "适量"}, {"name": "洋葱", "amount": "1个"}, {"name": "小茴香", "amount": "1勺"}, {"name": "适量花生碎", "amount": "适量"}, {"name": "适量白芝麻", "amount": "适量"}]'::jsonb, '["买羊前腿1只，前腿薄，在家里烤比较容易熟。", "用叉子在羊腿上扎几下，再划几刀，这样腌制方便入味，把准备好的料:盐，洋葱，姜丝，小茴香铺在羊腿上，进行按摩。腌制1小时左右。", "烤之前把腌制好的羊腿上面的料抖落下去，放入烤箱，上下200度，烤40分钟，取出，把花生碎，芝麻碎，孜然，洒在羊腿两面，再放入烤箱，正反面各烤20分钟。取出，美味的羊腿就烤好了。赶紧享受吧！"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/7c830c4c73834f6ab04080a6f8e00702_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('烤羊腿', '肉类', '羊腿', '', '[{"name": "孜然粉", "amount": "2勺"}, {"name": "2個洋葱", "amount": "适量"}, {"name": "黑胡椒", "amount": "2勺"}, {"name": "海盐🧂", "amount": "20克"}, {"name": "2條胡蘿蔔🥕", "amount": "适量"}, {"name": "豌豆", "amount": "400克"}, {"name": "羊後腿", "amount": "1只"}, {"name": "2個蕃茄", "amount": "适量"}, {"name": "2頭蒜", "amount": "适量"}, {"name": "橄欖油", "amount": "100克"}, {"name": "迷迭香", "amount": "2根"}, {"name": "2/3勺牛至", "amount": "适量"}, {"name": "嫩肉粉", "amount": "3勺"}]'::jsonb, '["第一☝️要煨肉（孜然粉、黑胡椒、迷迭香、牛至、海鹽、嫩肉粉）反覆挫肉正/反面，让調料均勻塗抹然後靜置一會兒。", "待羊油脂潤濕調料如圖後，用刀在肉身上划幾個十字口，把蒜和剩下的迷迭香添入十字口中。", "把烤盤中的調料繼續抹勻在肉上，正反兩面都要。再次靜置一會兒⋯⋯", "羊脂完全潤濕調料如圖⋯⋯", "用油紙包好，不能留封兒⋯⋯腿底用锡纸包裹好⋯⋯", "第一次放入冰箱冷藏煨肉「時間越久越好」⋯⋯", "20多個小時後取出來的樣子⋯⋯", "然後配置底料：胡蘿卜切段兒、洋蔥切塊兒、豌豆、蕃茄打成泥，倒上少許橄欖油+海鹽攪拌⋯⋯", "攪拌均勻如圖所見", "把羊腿放上", "最後推薦翡麗百端特初榨橄欖油抹上⋯⋯", "再放入冰箱冷藏煨制一天。", "開始烤制200度3⃣️D風預熱10分鐘。把羊腿放置在烤箱下二層200度三小時40分鐘", "期間翻轉兩次，最後一次用刷子沾烤盤上湯汁刷勻全身，升溫烤箱溫度至220度最好20分鐘烤色⋯⋯不要馬上取出羊腿兒，十分鐘後在開箱取肉。", "開始享受美食吧⋯⋯", "根據個人囗味，在肉上撒鹽及胡椒调味……", "沾上烤盤上的湯汁⋯⋯", "沾上烤盤上的湯汁⋯⋯", "沾上烤盤上的湯汁⋯⋯", "沾上烤盤上的湯汁⋯⋯", "真是美味可口啊⋯⋯"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/07fa2872107c4207b2b2c9cf8ab33047_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香菜爆炒羊肉片', '肉类', '羊肉片', '', '[{"name": "香菜", "amount": "2两"}, {"name": "羊肉", "amount": "3两"}, {"name": "姜丝", "amount": "15克"}, {"name": "蒜蓉", "amount": "10克"}, {"name": "孜然粒", "amount": "5克"}, {"name": "指天红椒", "amount": "3个"}]'::jsonb, '["羊前腿肉切片，用盐，鸡粉，食粉，生粉水，生抽，料酒腌制15分钟。", "香菜洗净切段，辣椒，蒜蓉，姜丝，孜然粒洗后备用。", "油锅下油在油温5~6成热的时候下羊肉滑一下，肉变白色即可捞起！注意油温不要太高，否则羊肉易老！", "锅热下油，姜蒜蓉辣椒爆香，下孜然粒的时候转小火炒出孜然味，将过好油的羊肉放入大火快速翻炒30秒，最后下香菜炒至断生，给点生抽，生粉水打一点芡 ，起锅再放点油放一点即可！"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/81c165d688ce11e6b87c0242ac110003_1094w_926h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('爆炒肥羊片', '肉类', '羊肉片', '', '[{"name": "1盒盒装肥羊片", "amount": "适量"}, {"name": "青红二荆条", "amount": "4个"}, {"name": "1/4个洋葱", "amount": "适量"}, {"name": "香葱", "amount": "1根"}, {"name": "少许白糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "适量孜然粉", "amount": "适量"}, {"name": "适量清水", "amount": "适量"}, {"name": "少许白酒", "amount": "适量"}, {"name": "独蒜", "amount": "1个"}, {"name": "1芽姜", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "1撮干花椒粒", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "少量淀粉", "amount": "适量"}, {"name": "适量油", "amount": "适量"}]'::jsonb, '["盒装肥羊片去掉包装，常温放置在漏盆中解冻，沥干解冻析出的血水，千万不要浸泡在水中解冻；", "青红二荆条斜切，洋葱切块，香葱取葱白切段，蒜粒切片，姜切较窄的片，干辣椒剪成短节，准备好少许干花椒粒；", "料酒、生抽、白糖、盐、胡椒粉、孜然粉加适量清水调匀成味汁；", "炒锅烧油少许，倒入青红二荆条片和洋葱翻炒断生，调盐少许，铲出备用；", "炒锅洗净，热油适量，倒入干辣椒节和花椒粒炝锅后放入蒜片和姜片爆香；", "倒入肥羊片快速翻炒并沿锅边烹入少许白酒；", "倒入事先炒好的辣椒和洋葱片，快速铲匀后烹入味汁翻炒均匀，勾一层薄芡，撒香葱颠匀起锅。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/c3607e628b5511e6a9a10242ac110002_1080w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('孜然羊肉片', '肉类', '羊肉片', '', '[{"name": "羊肉片", "amount": "250g"}, {"name": "孜然", "amount": "2勺"}, {"name": "少许白糖", "amount": "适量"}, {"name": "姜", "amount": "2g"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "2滴"}, {"name": "料酒", "amount": "2滴"}, {"name": "鸡精", "amount": "1勺"}, {"name": "盐", "amount": "5g"}, {"name": "五香粉", "amount": "1勺"}, {"name": "油", "amount": "10g"}]'::jsonb, '["羊肉片入锅用热水焯一下，这里注意不宜焯的时间太久，否则羊肉肉质会变老。", "如图：备孜然、五香粉、鸡精、盐、生抽、姜、蒜、料酒、蚝油、白糖。", "如图：备孜然、五香粉、鸡精、盐、生抽、姜、蒜、料酒、蚝油、白糖。", "如图：备孜然、五香粉、鸡精、盐、生抽、姜、蒜、料酒、蚝油、白糖。", "油锅烧热，放入适量油。", "姜、蒜入锅，过油爆香。", "焯过的羊肉入锅，快速翻动。", "放入少许盐、鸡精、五香粉，快速翻炒均匀。", "加入生抽、料酒、蚝油继续翻炒。", "临出锅前放入少许白糖提鲜，撒入孜然翻炒均匀，即可出锅了。", "香喷喷的孜然羊肉可以开吃啦！这样做出来的羊肉会稍微有一点点焦香，配上孜然的特殊香味，一点也不觉得腻，如果你喜欢吃香菜，也可以在临出锅前撒入香菜。"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/a92b3282bb7d11e6947d0242ac110002_640w_426h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('羊肉片汆萝卜', '肉类', '羊肉片', '', '[{"name": "羊肉片", "amount": "250克"}, {"name": "白萝卜", "amount": "1根"}, {"name": "（根据个人口味调整放）盐", "amount": "适量"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "2-3根青蒜苗", "amount": "适量"}]'::jsonb, '["白萝卜洗净去皮，青蒜洗净，羊肉片就买涮羊肉用的就行，羊肉片要买偏瘦点的。", "白萝卜滚刀切成中等块，青蒜苗切碎。", "萝卜下锅，放上足够多的水，大火烧开，转小火炖到萝卜软烂。", "此时另起锅水烧开，焯一下羊肉片（半分钟即可，此步忘拍照了，为了撇去浮沫，汤才会清亮），迅速捞入白萝卜锅内。此时调味，放入盐和白胡椒粉，要吃鸡精的也可放点。最后撒入切好的青蒜苗。", "羊肉鲜嫩，萝卜软烂，汤清味美，喝完暖乎乎，最适合大寒时节。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/8392a1a7594c49dfa9771b61760013d4_1215w_1620h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('葱香爆炒羊肉片', '肉类', '羊肉片', '', '[{"name": "羊肉片", "amount": "200克"}, {"name": "葱", "amount": "2根"}, {"name": "盐", "amount": "2克"}, {"name": "白糖", "amount": "1克"}, {"name": "适量孜然粉", "amount": "适量"}, {"name": "少许酱油", "amount": "适量"}, {"name": "少许豆油", "amount": "适量"}]'::jsonb, '["新鲜羊肉片放入碗中，冲洗浸出水份备用。🌴☘️", "羊肉片的碗中放入酱油，盐，白糖，孜然粉。搅拌均匀。🎋🌴", "洗净的香葱切碎备用。（各人感觉这里多放点葱白比较好吃）🌴🎋", "这是搅拌好的羊肉片。🌴🎋☘️", "锅中热油。🎋🌴", "将羊肉片倒是锅中翻炒至肉片变色半熟状态。🎋🌴", "再倒入香葱碎翻炒直肉片与葱碎熟透即可。🌴☘️", "看！香喷喷的葱香爆炒羊肉片就做好了，哈哈😄很简单吧！学会的朋友们上传作品哦~么么哒！🌴🎋☘️"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/5cc6db2a8e4444228f4399c13499c3f9_2016w_1134h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧羊蝎子', '肉类', '羊蝎子', '', '[{"name": "羊蝎子", "amount": "500克"}, {"name": "八角", "amount": "2个"}, {"name": "2-3片香叶", "amount": "适量"}, {"name": "10粒花椒", "amount": "适量"}, {"name": "小米椒", "amount": "4个"}, {"name": "少许葱 姜 蒜", "amount": "适量"}, {"name": "盐", "amount": "1小勺"}, {"name": "白糖", "amount": "1小勺"}, {"name": "生抽", "amount": "2小勺"}, {"name": "老抽", "amount": "1小勺"}, {"name": "豆瓣酱", "amount": "1大勺"}]'::jsonb, '["葱、姜、蒜等配料洗净，切好备用；羊蝎子焯水（一定要凉水下锅），撇去浮沫后洗净备用。", "锅里倒油、油八分热，放葱、葱、姜、蒜、辣椒炒香。", "加入郫县豆瓣酱。", "放入羊蝎子，翻炒至羊蝎子表面微焦。", "倒入适量的生抽和老抽，生抽和老抽的比例大概在2:1，翻炒均匀，使羊蝎子均匀上色。", "加入一勺白糖（红糖或者冰糖都可以），再加入足量的清水，大火烧开后转中小火炖制45-60分钟。", "出锅前依个人口味轻重加盐调味，转大火收汁。", "羊蝎子软烂，香味四溢后即可关火出锅。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/6a9d3f4a8a1511e6a9a10242ac110002_800w_533h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('羊蝎子火锅', '肉类', '羊蝎子', '', '[{"name": "羊蝎子", "amount": "适量"}, {"name": "葱、姜", "amount": "适量"}, {"name": "生抽、老抽、料酒", "amount": "适量"}, {"name": "郫县豆瓣酱、甜面酱", "amount": "适量"}, {"name": "辣椒、花椒、香叶、桂皮、茴香、草果", "amount": "适量"}, {"name": "羊肉卷、火锅丸、鹌鹑蛋", "amount": "适量"}, {"name": "金针菇、香菇", "amount": "适量"}, {"name": "豆芽、千张、青菜、香菜", "amount": "适量"}]'::jsonb, '["羊蝎子冷水浸泡半天，中途多换几次水。", "冷水下锅煮开5分钟，温水冲去浮沫", "换一个干净的深一点的锅放入冲洗干净的羊蝎子。放葱、姜、生抽、老抽、料酒、郫县豆瓣酱、甜面酱、辣椒、花椒、香叶、桂皮、茴香、草果。", "加足量的水，烧开后撇去浮沫。炖一个半小时，可以尝一下，肉烂了就可以了。", "加适量的盐调味连汤一起倒入火锅里，放点香菜", "涮菜准备好。吃完羊蝎子锅里加点水，不够咸再加点盐，用锅底继续涮。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/662fcb9a8a9111e6a9a10242ac110002_3456w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('秘制酱香羊蝎子(详细超多图)', '肉类', '羊蝎子', '', '[{"name": "羊蝎子", "amount": "6斤"}, {"name": "一根葱", "amount": "适量"}, {"name": "八片姜", "amount": "适量"}, {"name": "一头蒜", "amount": "适量"}, {"name": "60粒小茴香", "amount": "适量"}, {"name": "80粒花椒", "amount": "适量"}, {"name": "各四颗草果、豆蔻、肉蔻、草寇、丁香、", "amount": "适量"}, {"name": "各两块良姜、桂皮", "amount": "适量"}, {"name": "五片香叶", "amount": "适量"}, {"name": "六颗（泡两颗，四颗炖肉）大料", "amount": "适量"}, {"name": "四个干辣椒", "amount": "适量"}, {"name": "适量，实在没法数孜然", "amount": "适量"}, {"name": "两根荜拨", "amount": "适量"}, {"name": "两颗白扣", "amount": "适量"}, {"name": "适量辛夷", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量红糖", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量甜面酱", "amount": "适量"}, {"name": "十二根香菜", "amount": "适量"}, {"name": "一个，比拳头大点的洋葱", "amount": "适量"}, {"name": "两包注意注意！！没有上面香料的，可以直接用牛羊肉炖肉料包，料包也没有的，直接用花椒，大料，桂皮，香叶家里有什么放什么也行！", "amount": "适量"}]'::jsonb, '["羊蝎子肉多的吃着过瘾，买的时候让店家切小块，放适量的花椒大料泡四个小时左右，中间换三四次水，把血水泡出来", "经过几次换水和长时间侵泡，干净了很多", "泡好的羊蝎子冷水下锅，水多放点，加花椒，大料，料酒，葱，姜，焯水", "煮出血沫子，撇出", "撇到汤渐渐变清，汤留着一会炖蝎子", "盛出焯好的羊蝎子", "温水冲洗掉羊蝎子上的血沫子", "准备香料，因为六斤比较多，分两锅炒，所以准备两份", "炒锅倒油，油温不要太高时倒入香菜和洋葱丝炒香", "炒出香味的洋葱和香菜盛出，待用", "重新起锅，把香料和葱姜蒜爆香，放入一半焯好的羊蝎子，翻炒两分钟，倒入刚才留的汤锅中，不喜欢焯肉汤水的，用清水也可以（一定要是开水哦）", "翻炒好的羊蝎子和料一起倒入汤锅", "加入炒香的洋葱和香菜", "冰糖，红糖，盐，生抽，老抽，料酒，白胡椒粉，甜面酱混合，倒入锅中", "大火烧开，转小火慢炖2小时，出锅前过滤掉汤中的香料和煮烂的洋葱香菜", "放入适量枸杞和香菜，点上电磁炉，上桌开撮吧，吃完肉蝎子，还可以用汤涮喜欢的青菜，豆腐，特别推荐用汤涮烙饼！巨好吃！", "满屋飘香啊，肉软烂入味，老爸没牙都可以吃", "烙饼就是这样的，葱花饼，发面饼，乌冬面，拉面，只要是自己喜欢的都可以，万物皆可涮哈。"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/a221eb109d0b11e6947d0242ac110002_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('香辣羊蝎子', '肉类', '羊蝎子', '辣', '[{"name": "羊蝎子！", "amount": "1000克"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "一小块生姜", "amount": "适量"}, {"name": "一段大葱", "amount": "适量"}, {"name": "适量大料（见步骤里）", "amount": "适量"}, {"name": "少许红茶叶", "amount": "适量"}, {"name": "二汤勺黄豆酱", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}, {"name": "适量泡椒", "amount": "适量"}, {"name": "二汤勺冰糖", "amount": "适量"}, {"name": "几根小芹菜", "amount": "适量"}, {"name": "适量油", "amount": "适量"}, {"name": "一汤勺白酒", "amount": "适量"}, {"name": "一汤勺陈醋", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}, {"name": "适量孜然粒", "amount": "适量"}]'::jsonb, '["羊蝎子最好让卖的给剁好..\n我的收到时候木有剁的.\n\n还好我家有砍骨刀.～\n\n（卖家是不是感应到了我是真汉纸才不剁的..（≧∇≦）.）", "剁成一段段的～\n\n讲真..快剁好时.\n我的菜板给剁碎了.\n是真的碎了..凸^-^凸\n\n我发图给送我羊蝎子的看.\n她笑疯了吧..！╮(╯▽╰)╭", "放入水中浸泡出血水～\n\n这个其实也不需要泡太久！", "捞出..\n\n放入冷水锅中..丢几片姜！", "煮开后..\n\n再煮5分钟以上..\n\n\n捞出洗净沥干水备用～", "洋葱.生姜.大葱.小米椒.泡椒.小芹菜分别切好..\n\n泡椒水装碗里备用...！\n\n大料我用了：八角二个.桂皮一段.香叶二个.草果一个.甘草几个.花椒20个左右\n（花椒用纱袋装着了.煮好捞出丢弃的.不想大快朵颐吃的时候咬到.不介意的可以直接放）\n这些如果家里没有.就在超市买一个卤料包.里面基本都有！", "锅里放油..\n放冰糖..", "小火加热至变色.冒泡～\n\n如果不会炒糖色的可以忽略这一步.\n后面直接把冰糖放下去..\n不过冰糖量要减一点..～", "把洋葱.生姜.大葱.大料放下去爆香～", "然后把羊蝎子放入翻炒上色～\n\n把白酒淋上盖上锅盖焖10秒～\n再把陈醋淋上盖上锅盖焖10秒～\n\n（这一步必须要的）", "羊蝎子往四边拨开.\n锅中间底油上放上黄豆酱！", "翻炒均匀....", "把泡椒水放入...", "翻炒至煮开..\n\n加开水炖..水量要高过羊蝎子！\n\n（我不能说我倒了一罐啤酒下去）", "我换了珐琅锅炖..\n这锅炖的比一般锅时间要少一半.\n炖出来的也香.\n而且水分不太会流失...(｡-_-｡)\n\n我一下忘记了.放多了水.\n后面开大火收汁了！", "再说一个这一步需要放东西..\n红茶叶.\n是我以前在电视里看见的.\n\n但是.我木有红茶.\n我放了一点下厨房一个妹纸奶奶种的茶叶..", "盖上锅盖..小火慢炖.\n\n外面看..\n那么安静....\n不漏气...", "快炖好前5分钟.\n放泡椒和小米椒.孜然粒下去..\n再尝味道放盐...\n\n盖上锅盖炖5分钟...", "关火前放小芹菜..", "开吃开吃～\n\n别抢..！(￣∇￣)"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/bbb4c0faa32511e6bc9d0242ac110002_1280w_856h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('白汤羊蝎子火锅', '肉类', '羊蝎子', '', '[{"name": "羊蝎子", "amount": "适量"}, {"name": "洋葱", "amount": "适量"}, {"name": "大枣", "amount": "适量"}, {"name": "枸杞", "amount": "适量"}, {"name": "姜片", "amount": "适量"}, {"name": "茶叶", "amount": "适量"}, {"name": "食盐", "amount": "适量"}, {"name": "白胡椒粉", "amount": "适量"}, {"name": "料包丁香、砂仁、桂皮、白芷、甘草", "amount": "适量"}]'::jsonb, '["羊蝎子一盆", "绿茶抓一小把放进碗里", "泡一大碗绿茶，茶水倒出", "再加热水浸泡一碗，一共泡好两大碗茶水。", "羊蝎子成段洗净，放在盆里，加足量水浸泡羊蝎子，鲜羊蝎子浸泡时间为一个半小时，冻的羊蝎子要浸泡三个小时", "用茶水兑一些凉水，倒进锅里，加入羊蝎子，用茶水焯羊蝎子去腥是第一个妙招", "焯水的羊蝎子会出很多的血沫子，慢慢撇除，继续焯水", "直到血沫子变成白色", "捞出羊蝎子", "放进温水里洗净", "锅里添足够的温水，加入羊蝎子，放入姜片和洋葱片，加洋葱是白汤羊蝎子的第二个妙招", "丁香、砂仁、桂皮、白芷、甘草、大枣、枸杞", "装进纱布包", "加入大枣和枸杞", "装入纱布包放入汤锅内", "大火炖开，小火慢炖至少需要约一个半小时。", "如果用高压锅四十分钟就好", "炖好的羊蝎子再加入鸡精、白胡椒粉和食盐调味即可。喜欢香菜可以放一些也是不错的。"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/7e041dfad74b11e6947d0242ac110002_1280w_960h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('上海酱鸭腿', '肉类', '鸭腿', '', '[{"name": "四只约两斤鸭腿", "amount": "适量"}, {"name": "老抽", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "姜块", "amount": "适量"}, {"name": "八角", "amount": "适量"}, {"name": "桂皮", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "红糖或冰糖或白糖", "amount": "适量"}]'::jsonb, '["鸭腿四个，洗净，冷水入锅，水大约没过鸭腿，大火开煮。", "快要煮沸时捞去浮沫，完全沸腾后加料酒，拍松的姜块，生抽，老抽，各种香料。我的图中桂皮太小了，因为家里正好用完了，同学们可以放一块再大点的。", "改成小火，盖上盖子，保持微沸而又不溢出的状态，烧一个半小时左右，直到筷子可以轻松插入。", "加入红糖或冰糖或白糖，开盖，转大火🔥开始收汁，这时人就不要离开灶台了，不时将淋在鸭腿上，直到汤汁收干，浓油赤酱。", "若要斩件，一定要冷透，否则切出来味道不变，颜值就悲剧了。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/b261b86e8ad911e6a9a10242ac110002_1215w_1215h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧酱鸭腿', '肉类', '鸭腿', '', '[{"name": "鸭腿", "amount": "3只"}, {"name": "一把小葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "克糖", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量桂皮", "amount": "适量"}]'::jsonb, '["腌制，这一步忘了拍照，具体如下：\n鸭腿用大量食盐抓匀，也可以用大粒泡菜盐，目的是杀出腥气，至少一个小时，看到有大量水析出就对了，不要怕太咸，因为鸭肉难以入味儿，也可以出门上班前少放点儿盐腌制，下班回来做。实在怕咸就在鸭腿下垫上两根筷子，可以避免泡在盐水中。\n还有一种做法就是，用盐和花椒抓匀以后，放在通风处，晾上半个小时。", "腌好的鸭腿洗净、擦干。\n炒锅大量油，比炒菜多一倍，下姜片，下小葱结、花椒、八角爆香，皮朝下鸭腿下锅，煎两分钟，至出油。", "翻面，继续煎1分钟。", "下冰糖或或者白糖，下酱油、花雕酒，热水加至淹没鸭腿，大火烧开，转中小火，保持微微沸腾状态，加锅盖焖。", "焖烧大概二三十分钟，过程中翻面两次，糖、水、油已经乳化。", "挑出已经稀烂的小葱，出锅、收汁、装盘。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/a2b2413c090e11e7bc9d0242ac110002_1488w_1488h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('红烧鸭腿土豆块', '肉类', '鸭腿', '', '[{"name": "鸭腿", "amount": "2只"}, {"name": "土豆（中等大小）", "amount": "2个"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "2汤勺花雕酒", "amount": "适量"}, {"name": "3汤勺生抽", "amount": "适量"}, {"name": "1汤勺老抽", "amount": "适量"}, {"name": "1汤勺黄豆酱（或其他豆瓣酱）", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "白糖", "amount": "2克"}]'::jsonb, '["起油锅，油略冒烟是爆香葱姜蒜。放鸭腿块，煸炒略变色后加入花雕酒翻炒1分钟。再加入生抽、老抽、黄豆酱（为了增加鸭肉的肉香气，也可以加入你喜欢的任何酱料）、白糖，翻炒均匀。", "加开水（一定要开水）刚好没过鸭块。大火烧开后改小火20分钟。盖盖。", "放入土豆块，调味，加入适量盐。大火开后转小火15-20分钟。", "最后汤汁要是多，开盖大火收汁。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/ed8a37ef98534c38b80faa7686b5b389_1836w_1836h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('家庭版香酥鸭腿', '肉类', '鸭腿', '', '[{"name": "一大勺酱油", "amount": "适量"}, {"name": "一大块姜", "amount": "适量"}, {"name": "啤酒一罐或者黄酒一小杯或者白酒一勺啤酒或者黄酒或者白酒", "amount": "适量"}, {"name": "八角", "amount": "5个"}, {"name": "香叶", "amount": "5片"}, {"name": "适量葱", "amount": "适量"}, {"name": "一大勺蚝油", "amount": "适量"}, {"name": "一小勺白糖", "amount": "适量"}, {"name": "鸭腿", "amount": "5只"}]'::jsonb, '["所有材料混合腌制，密封好放进冰箱过夜.", "冷水上锅蒸熟，大约40分钟.所有腌料都要放进去一起蒸.", "蒸熟后沥干水分，把香料都抹干净备用.", "油锅烧热就下鸭腿炸，油要没过鸭腿.", "炸至表皮金黄捞出即可.", "厨房纸吸一吸表皮的油.", "斩件装盘即可."]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/bbc57a2c4ef64b17ac76325c0b5b16b2_1242w_1656h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('超简单卤鸭腿', '肉类', '鸭腿', '', '[{"name": "鸭边腿", "amount": "2只"}, {"name": "花椒", "amount": "5克"}, {"name": "1小块桂皮", "amount": "适量"}, {"name": "八角", "amount": "4个"}, {"name": "香叶", "amount": "4片"}, {"name": "1/3根大葱", "amount": "适量"}, {"name": "3～4片姜", "amount": "适量"}, {"name": "4～5瓣大蒜", "amount": "适量"}, {"name": "糖", "amount": "15克"}, {"name": "盐", "amount": "5克"}, {"name": "2茶勺醋/白醋", "amount": "适量"}, {"name": "1汤勺料酒", "amount": "适量"}, {"name": "2汤勺生抽", "amount": "适量"}, {"name": "7～10粒可以不加枸杞", "amount": "适量"}, {"name": "可以不加西洋参", "amount": "1克"}, {"name": "水", "amount": "1200克"}]'::jsonb, '["所有材料备齐", "腿子肉冷水入锅烧开，这一步主要是想把鸭腿的血水煮出来，烧开后煮1分钟就好了，拿出来沥干备用", "换平底锅煎出鸭皮里面的肥油，这一步不要放油哈，鸭皮下面很肥所以完全可以用鸭腿本身的脂肪代替油脂。此时好多鸭油可以煎出来，表皮煎得差不多的时候就可以了", "放上准备好的香料们，葱姜蒜，八角桂皮香叶和白糖。", "炒啊炒啊炒，煎啊煎啊煎，炒出糖色和香味儿以后放上香醋，料酒，生抽再炒啊炒啊炒，煎啊煎啊煎，差不多1分半钟（不要煎糊啦），可以放上水啦！", "大功告成！哈哈开玩笑啦！我最喜欢这一步，水放上之后大火烧开放上盐，转小火就可以盖上锅盖想干嘛干嘛去了，期间可以翻个面，让鸭腿均匀上个色，等待45～60分钟以后关火，齐活！", "捞出来，蒸个米饭呐，煮个面条啦～直接盖在上面，然后浇上汤汁儿，放点青菜蔬菜什么的就问你馋不馋？\n卤完的卤子还可以留一些下次卤点鸡蛋啊花干啊排骨啊猪蹄啊鸡腿啊…只要你想吃的都可以用这个方法噢！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/86cebb0d79ec4fe783468fc5a49716ff_912w_684h.jpg', true, true);
